/* motorcycle-data.js — Motorcycle permit practice (based on the MSF/NHTSA Motorcycle Operator Manual).
   window.MOTO = { cats:[{id,name,blurb}], q:[{cat,a,q,o,e}] } — all 6 languages. */
window.MOTO = {"cats":[{"id":"controls","name":{"en":"Controls & Operation","es":"Controles y operación","ru":"Органы управления","tr":"Kumandalar ve Kullanım","hi":"नियंत्रण और संचालन","ar":"أدوات التحكم والتشغيل"},"blurb":{"en":"Hand and foot controls, the friction zone, shifting, starting and stopping.","es":"Controles de mano y pie, la zona de fricción, los cambios, arrancar y detenerse.","ru":"Ручные и ножные органы управления, зона сцепления, переключение, старт и остановка.","tr":"El ve ayak kumandaları, friksiyon bölgesi, vites, kalkış ve durma.","hi":"हाथ-पैर के नियंत्रण, फ्रिक्शन ज़ोन, गियर, शुरू करना और रोकना।","ar":"أدوات التحكم اليدوية والقدمية، ومنطقة الاحتكاك، والتبديل، والانطلاق والتوقف."}},{"id":"gear","name":{"en":"Protective Gear","es":"Equipo de protección","ru":"Защитная экипировка","tr":"Koruyucu Ekipman","hi":"सुरक्षात्मक गियर","ar":"معدات الحماية"},"blurb":{"en":"Helmets, eye and face protection, jackets, gloves, boots and being seen.","es":"Cascos, protección de ojos y cara, chaquetas, guantes, botas y ser visible.","ru":"Шлемы, защита глаз и лица, куртки, перчатки, ботинки и заметность.","tr":"Kasklar, göz ve yüz koruması, montlar, eldivenler, botlar ve görünürlük.","hi":"हेलमेट, आँख-चेहरे की सुरक्षा, जैकेट, दस्ताने, बूट और दिखना।","ar":"الخوذات، وحماية العينين والوجه، والسترات، والقفازات، والأحذية، والظهور."}},{"id":"braking","name":{"en":"Braking & Stopping","es":"Frenado y detención","ru":"Торможение и остановка","tr":"Frenleme ve Durma","hi":"ब्रेकिंग और रुकना","ar":"الكبح والتوقف"},"blurb":{"en":"Using both brakes, quick stops, swerving and following distance.","es":"Usar ambos frenos, frenadas rápidas, esquivar y distancia de seguimiento.","ru":"Оба тормоза, экстренная остановка, объезд и дистанция.","tr":"Her iki fren, hızlı duruş, manevra ve takip mesafesi.","hi":"दोनों ब्रेक, तेज़ रुकाव, स्वर्व और फॉलोइंग दूरी।","ar":"استخدام الفرملتين، والتوقف السريع، والمراوغة، ومسافة المتابعة."}},{"id":"cornering","name":{"en":"Turning & Lane Position","es":"Giros y posición en el carril","ru":"Повороты и положение в полосе","tr":"Dönüş ve Şerit Konumu","hi":"मोड़ और लेन स्थिति","ar":"الانعطاف وموضع المسار"},"blurb":{"en":"Slow-Look-Press-Roll, countersteering, leaning and lane positioning.","es":"Reduce-Mira-Presiona-Acelera, contramanillar, inclinarse y posición en el carril.","ru":"Замедлись-Смотри-Нажми-Газуй, контрруление, наклон и положение в полосе.","tr":"Yavaşla-Bak-Bastır-Gazla, ters direksiyon, yatma ve şerit konumu.","hi":"धीमा-देखो-दबाओ-बढ़ाओ, काउंटरस्टीयरिंग, झुकाव और लेन स्थिति।","ar":"أبطئ-انظر-اضغط-سرّع، والتوجيه العكسي، والميل، وموضع المسار."}},{"id":"visibility","name":{"en":"Being Seen & SEE","es":"Ser visible y SEE","ru":"Заметность и SEE","tr":"Görünürlük ve SEE","hi":"दिखना और SEE","ar":"الظهور و SEE"},"blurb":{"en":"The SEE strategy, conspicuity, intersections, signaling and blind spots.","es":"La estrategia SEE, visibilidad, intersecciones, señalización y puntos ciegos.","ru":"Стратегия SEE, заметность, перекрёстки, сигналы и слепые зоны.","tr":"SEE stratejisi, görünürlük, kavşaklar, sinyal ve kör noktalar.","hi":"SEE रणनीति, दृश्यता, चौराहे, सिग्नल और ब्लाइंड स्पॉट।","ar":"استراتيجية SEE، والظهور، والتقاطعات، والإشارة، والنقاط العمياء."}},{"id":"hazards","name":{"en":"Hazards & Surfaces","es":"Peligros y superficies","ru":"Опасности и покрытие","tr":"Tehlikeler ve Yüzeyler","hi":"खतरे और सतहें","ar":"المخاطر والأسطح"},"blurb":{"en":"Slippery roads, railroad tracks, obstacles, night riding, wind and animals.","es":"Caminos resbalosos, vías férreas, obstáculos, conducción nocturna, viento y animales.","ru":"Скользкие дороги, ж/д пути, препятствия, ночь, ветер и животные.","tr":"Kaygan yollar, demir yolu, engeller, gece sürüşü, rüzgâr ve hayvanlar.","hi":"फिसलन सड़कें, रेल पटरी, बाधाएँ, रात की सवारी, हवा और जानवर।","ar":"الطرق الزلقة، وسكك الحديد، والعوائق، والقيادة الليلية، والرياح، والحيوانات."}},{"id":"passenger","name":{"en":"Passengers, Cargo & Groups","es":"Pasajeros, carga y grupos","ru":"Пассажиры, груз и группы","tr":"Yolcu, Yük ve Grup","hi":"सवारी, सामान और समूह","ar":"الركاب والحمولة والمجموعات"},"blurb":{"en":"Carrying a passenger, loading cargo, and group-riding formation.","es":"Llevar pasajero, cargar y la formación de grupo.","ru":"Перевозка пассажира, груз и групповое построение.","tr":"Yolcu taşıma, yük ve grup düzeni.","hi":"सवारी ले जाना, सामान लादना और समूह संरचना।","ar":"حمل راكب، وتحميل البضائع، وتشكيل القيادة الجماعية."}},{"id":"impairment","name":{"en":"Alcohol, Fatigue & Sharing the Road","es":"Alcohol, fatiga y compartir la vía","ru":"Алкоголь, усталость и дорога","tr":"Alkol, Yorgunluk ve Yolu Paylaşma","hi":"शराब, थकान और सड़क साझा करना","ar":"الكحول والتعب ومشاركة الطريق"},"blurb":{"en":"Impairment, the full lane, lane sharing, and riding near traffic.","es":"Deterioro, el carril completo, compartir carril y circular junto al tráfico.","ru":"Опьянение, полная полоса, совместное использование полосы и движение в потоке.","tr":"Bozulma, tam şerit, şerit paylaşımı ve trafik yakınında sürüş.","hi":"क्षीणता, पूरी लेन, लेन साझा करना और ट्रैफ़िक के पास सवारी।","ar":"الإعاقة، والمسار الكامل، ومشاركة المسار، والقيادة قرب المرور."}}],"q":[{"cat":"controls","a":0,"q":{"en":"Which control is operated by your right hand to increase engine speed?","es":"¿Cuál control se opera con la mano derecha para aumentar la velocidad del motor?","ru":"Какой орган управления приводится в действие правой рукой для увеличения оборотов двигателя?","tr":"Motor devrini artırmak için sağ elinizle hangi kumanda kullanılır?","hi":"इंजन की गति बढ़ाने के लिए आपके दाहिने हाथ से कौन सा कंट्रोल चलाया जाता है?","ar":"أي عنصر تحكم يتم تشغيله بيدك اليمنى لزيادة سرعة المحرك؟"},"o":[{"en":"The throttle","es":"El acelerador","ru":"Ручка газа","tr":"Gaz kolu","hi":"थ्रॉटल","ar":"دواسة الوقود (الخانق)"},{"en":"The clutch lever","es":"La palanca del embrague","ru":"Рычаг сцепления","tr":"Debriyaj kolu","hi":"क्लच लीवर","ar":"ذراع القابض"},{"en":"The gear-shift lever","es":"La palanca de cambios","ru":"Рычаг переключения передач","tr":"Vites değiştirme kolu","hi":"गियर-शिफ्ट लीवर","ar":"ذراع تغيير السرعات"},{"en":"The rear brake pedal","es":"El pedal del freno trasero","ru":"Педаль заднего тормоза","tr":"Arka fren pedalı","hi":"रियर ब्रेक पेडल","ar":"دواسة الفرامل الخلفية"}],"e":{"en":"The throttle is the twist grip on the right handgrip and is rolled on to increase engine speed. The Motorcycle Operator Manual lists the throttle among the right-hand controls.","es":"El acelerador es el puño giratorio en la manija derecha y se gira hacia adentro para aumentar la velocidad del motor. El Manual del Operador de Motocicletas incluye el acelerador entre los controles de la mano derecha.","ru":"Ручка газа — это поворотная рукоятка на правой ручке руля, которую проворачивают для увеличения оборотов двигателя. Руководство мотоциклиста (Motorcycle Operator Manual) относит ручку газа к органам управления правой руки.","tr":"Gaz kolu, sağ gidonun üzerindeki döner kabzadır ve motor devrini artırmak için içe doğru çevrilir. Motosiklet Kullanıcı Kılavuzu, gaz kolunu sağ el kumandaları arasında sıralar.","hi":"थ्रॉटल दाहिनी हैंडग्रिप पर मौजूद ट्विस्ट ग्रिप है और इंजन की गति बढ़ाने के लिए इसे रोल किया जाता है। Motorcycle Operator Manual थ्रॉटल को दाहिने हाथ के कंट्रोल में सूचीबद्ध करता है।","ar":"دواسة الوقود (الخانق) هي المقبض الدوار على المقبض الأيمن، ويتم لفها لزيادة سرعة المحرك. يُدرج دليل مشغّل الدراجة النارية الخانق ضمن عناصر التحكم باليد اليمنى."}},{"cat":"controls","a":1,"q":{"en":"Where is the front brake lever located on a motorcycle?","es":"¿Dónde se ubica la palanca del freno delantero en una motocicleta?","ru":"Где расположен рычаг переднего тормоза на мотоцикле?","tr":"Motosiklette ön fren kolu nerede bulunur?","hi":"मोटरसाइकिल पर फ्रंट ब्रेक लीवर कहाँ स्थित होता है?","ar":"أين يقع ذراع الفرامل الأمامية في الدراجة النارية؟"},"o":[{"en":"On the left handlebar, near the clutch","es":"En el manillar izquierdo, cerca del embrague","ru":"На левой рукоятке руля, рядом со сцеплением","tr":"Sol gidonda, debriyajın yanında","hi":"बाएं हैंडलबार पर, क्लच के पास","ar":"على المقود الأيسر، بالقرب من القابض"},{"en":"In front of the right handgrip, operated by the right hand","es":"Frente a la manija derecha, operada por la mano derecha","ru":"Перед правой ручкой руля, приводится в действие правой рукой","tr":"Sağ gidon kabzasının önünde, sağ elle kullanılır","hi":"दाहिनी हैंडग्रिप के सामने, दाहिने हाथ से चलाया जाता है","ar":"أمام المقبض الأيمن، ويُشغَّل باليد اليمنى"},{"en":"On the left footrest, operated by the left foot","es":"En el estribo izquierdo, operada por el pie izquierdo","ru":"На левой подножке, приводится в действие левой ногой","tr":"Sol ayak basamağında, sol ayakla kullanılır","hi":"बाएं फुटरेस्ट पर, बाएं पैर से चलाया जाता है","ar":"على مسند القدم الأيسر، ويُشغَّل بالقدم اليسرى"},{"en":"In front of the right footrest, operated by the right foot","es":"Frente al estribo derecho, operada por el pie derecho","ru":"Перед правой подножкой, приводится в действие правой ногой","tr":"Sağ ayak basamağının önünde, sağ ayakla kullanılır","hi":"दाहिने फुटरेस्ट के सामने, दाहिने पैर से चलाया जाता है","ar":"أمام مسند القدم الأيمن، ويُشغَّل بالقدم اليمنى"}],"e":{"en":"The front brake lever is squeezed by the right hand in front of the right handgrip. The Motorcycle Operator Manual identifies the front brake lever as a right-hand control.","es":"La palanca del freno delantero se aprieta con la mano derecha frente a la manija derecha. El Manual del Operador de Motocicletas identifica la palanca del freno delantero como un control de la mano derecha.","ru":"Рычаг переднего тормоза сжимают правой рукой, он расположен перед правой ручкой руля. Руководство мотоциклиста относит рычаг переднего тормоза к органам управления правой руки.","tr":"Ön fren kolu, sağ gidon kabzasının önünde sağ elle sıkılır. Motosiklet Kullanıcı Kılavuzu, ön fren kolunu sağ el kumandası olarak tanımlar.","hi":"फ्रंट ब्रेक लीवर को दाहिनी हैंडग्रिप के सामने दाहिने हाथ से दबाया जाता है। Motorcycle Operator Manual फ्रंट ब्रेक लीवर को दाहिने हाथ के कंट्रोल के रूप में पहचानता है।","ar":"يتم الضغط على ذراع الفرامل الأمامية باليد اليمنى أمام المقبض الأيمن. يحدد دليل مشغّل الدراجة النارية ذراع الفرامل الأمامية كعنصر تحكم باليد اليمنى."}},{"cat":"controls","a":3,"q":{"en":"Which hand operates the clutch lever?","es":"¿Con qué mano se opera la palanca del embrague?","ru":"Какой рукой приводится в действие рычаг сцепления?","tr":"Debriyaj kolunu hangi el kullanır?","hi":"क्लच लीवर को कौन सा हाथ चलाता है?","ar":"أي يد تشغّل ذراع القابض؟"},"o":[{"en":"The right hand","es":"La mano derecha","ru":"Правой рукой","tr":"Sağ el","hi":"दाहिना हाथ","ar":"اليد اليمنى"},{"en":"Either hand, depending on the model","es":"Cualquiera de las dos manos, según el modelo","ru":"Любой рукой, в зависимости от модели","tr":"Modele bağlı olarak her iki el de","hi":"कोई भी हाथ, मॉडल के अनुसार","ar":"أي يد، حسب الطراز"},{"en":"Neither; the clutch is foot-operated","es":"Ninguna; el embrague se opera con el pie","ru":"Никакой; сцепление приводится в действие ногой","tr":"Hiçbiri; debriyaj ayakla kullanılır","hi":"कोई नहीं; क्लच पैर से चलाया जाता है","ar":"لا يد؛ فالقابض يُشغَّل بالقدم"},{"en":"The left hand","es":"La mano izquierda","ru":"Левой рукой","tr":"Sol el","hi":"बायां हाथ","ar":"اليد اليسرى"}],"e":{"en":"The clutch lever is squeezed by the left hand. The Motorcycle Operator Manual lists the clutch lever as a left-hand control on the handlebar.","es":"La palanca del embrague se aprieta con la mano izquierda. El Manual del Operador de Motocicletas incluye la palanca del embrague como un control de la mano izquierda en el manillar.","ru":"Рычаг сцепления сжимают левой рукой. Руководство мотоциклиста относит рычаг сцепления к органам управления левой руки на руле.","tr":"Debriyaj kolu sol elle sıkılır. Motosiklet Kullanıcı Kılavuzu, debriyaj kolunu gidon üzerindeki sol el kumandası olarak sıralar.","hi":"क्लच लीवर को बाएं हाथ से दबाया जाता है। Motorcycle Operator Manual क्लच लीवर को हैंडलबार पर बाएं हाथ के कंट्रोल के रूप में सूचीबद्ध करता है।","ar":"يتم الضغط على ذراع القابض باليد اليسرى. يُدرج دليل مشغّل الدراجة النارية ذراع القابض كعنصر تحكم باليد اليسرى على المقود."}},{"cat":"controls","a":3,"q":{"en":"Which foot operates the gear-shift lever?","es":"¿Con qué pie se opera la palanca de cambios?","ru":"Какой ногой приводится в действие рычаг переключения передач?","tr":"Vites değiştirme kolunu hangi ayak kullanır?","hi":"गियर-शिफ्ट लीवर को कौन सा पैर चलाता है?","ar":"أي قدم تشغّل ذراع تغيير السرعات؟"},"o":[{"en":"The right foot","es":"El pie derecho","ru":"Правой ногой","tr":"Sağ ayak","hi":"दाहिना पैर","ar":"القدم اليمنى"},{"en":"Both feet together","es":"Ambos pies juntos","ru":"Обеими ногами одновременно","tr":"İki ayak birlikte","hi":"दोनों पैर एक साथ","ar":"كلتا القدمين معًا"},{"en":"Whichever foot is on the ground","es":"El pie que esté en el suelo","ru":"Той ногой, что стоит на земле","tr":"Yerde olan ayak hangisiyse o","hi":"जो भी पैर ज़मीन पर हो","ar":"أي قدم تكون على الأرض"},{"en":"The left foot","es":"El pie izquierdo","ru":"Левой ногой","tr":"Sol ayak","hi":"बायां पैर","ar":"القدم اليسرى"}],"e":{"en":"The gear-shift lever is located in front of the left footrest and is operated by the left foot. The Motorcycle Operator Manual states the gearshift lever is worked with the left foot.","es":"La palanca de cambios se ubica frente al estribo izquierdo y se opera con el pie izquierdo. El Manual del Operador de Motocicletas indica que la palanca de cambios se acciona con el pie izquierdo.","ru":"Рычаг переключения передач расположен перед левой подножкой и приводится в действие левой ногой. Руководство мотоциклиста указывает, что рычаг переключения передач работает левой ногой.","tr":"Vites değiştirme kolu sol ayak basamağının önünde bulunur ve sol ayakla kullanılır. Motosiklet Kullanıcı Kılavuzu, vites kolunun sol ayakla çalıştırıldığını belirtir.","hi":"गियर-शिफ्ट लीवर बाएं फुटरेस्ट के सामने स्थित होता है और इसे बाएं पैर से चलाया जाता है। Motorcycle Operator Manual बताता है कि गियरशिफ्ट लीवर को बाएं पैर से चलाया जाता है।","ar":"يقع ذراع تغيير السرعات أمام مسند القدم الأيسر ويُشغَّل بالقدم اليسرى. ينص دليل مشغّل الدراجة النارية على أن ذراع تغيير السرعات يُشغَّل بالقدم اليسرى."}},{"cat":"controls","a":2,"q":{"en":"Which control is operated by your right foot?","es":"¿Cuál control se opera con el pie derecho?","ru":"Какой орган управления приводится в действие правой ногой?","tr":"Sağ ayağınızla hangi kumanda kullanılır?","hi":"आपके दाहिने पैर से कौन सा कंट्रोल चलाया जाता है?","ar":"أي عنصر تحكم يُشغَّل بقدمك اليمنى؟"},"o":[{"en":"The clutch lever","es":"La palanca del embrague","ru":"Рычаг сцепления","tr":"Debriyaj kolu","hi":"क्लच लीवर","ar":"ذراع القابض"},{"en":"The gear-shift lever","es":"La palanca de cambios","ru":"Рычаг переключения передач","tr":"Vites değiştirme kolu","hi":"गियर-शिफ्ट लीवर","ar":"ذراع تغيير السرعات"},{"en":"The rear brake pedal","es":"El pedal del freno trasero","ru":"Педаль заднего тормоза","tr":"Arka fren pedalı","hi":"रियर ब्रेक पेडल","ar":"دواسة الفرامل الخلفية"},{"en":"The front brake lever","es":"La palanca del freno delantero","ru":"Рычаг переднего тормоза","tr":"Ön fren kolu","hi":"फ्रंट ब्रेक लीवर","ar":"ذراع الفرامل الأمامية"}],"e":{"en":"The rear brake pedal is pressed down with the right foot. The Motorcycle Operator Manual identifies the rear brake pedal as the right-foot control.","es":"El pedal del freno trasero se presiona hacia abajo con el pie derecho. El Manual del Operador de Motocicletas identifica el pedal del freno trasero como el control del pie derecho.","ru":"Педаль заднего тормоза нажимают вниз правой ногой. Руководство мотоциклиста относит педаль заднего тормоза к органам управления правой ноги.","tr":"Arka fren pedalı sağ ayakla aşağıya doğru basılır. Motosiklet Kullanıcı Kılavuzu, arka fren pedalını sağ ayak kumandası olarak tanımlar.","hi":"रियर ब्रेक पेडल को दाहिने पैर से नीचे दबाया जाता है। Motorcycle Operator Manual रियर ब्रेक पेडल को दाहिने पैर के कंट्रोल के रूप में पहचानता है।","ar":"يتم الضغط على دواسة الفرامل الخلفية للأسفل بالقدم اليمنى. يحدد دليل مشغّل الدراجة النارية دواسة الفرامل الخلفية كعنصر تحكم بالقدم اليمنى."}},{"cat":"controls","a":2,"q":{"en":"What is the \"friction zone\" of the clutch?","es":"¿Qué es la \"zona de fricción\" del embrague?","ru":"Что такое «зона пробуксовки сцепления»?","tr":"Debriyajın \"friksiyon bölgesi\" nedir?","hi":"क्लच का \"फ्रिक्शन ज़ोन\" क्या है?","ar":"ما هي \"منطقة الاحتكاك\" في القابض؟"},"o":[{"en":"The point where the front and rear brakes work together","es":"El punto donde el freno delantero y el trasero trabajan juntos","ru":"Точка, в которой передний и задний тормоза работают совместно","tr":"Ön ve arka frenin birlikte çalıştığı nokta","hi":"वह बिंदु जहाँ फ्रंट और रियर ब्रेक एक साथ काम करते हैं","ar":"النقطة التي تعمل فيها الفرامل الأمامية والخلفية معًا"},{"en":"The grip area where your right wrist rests on the throttle","es":"El área de agarre donde la muñeca derecha descansa sobre el acelerador","ru":"Участок хвата, где правое запястье лежит на ручке газа","tr":"Sağ bileğinizin gaz kolu üzerinde durduğu kabza alanı","hi":"वह ग्रिप क्षेत्र जहाँ आपकी दाहिनी कलाई थ्रॉटल पर टिकती है","ar":"منطقة المقبض حيث ترتكز رسغك اليمنى على الخانق"},{"en":"The small range of clutch-lever travel that controls power from the engine to the rear wheel","es":"El pequeño rango de recorrido de la palanca del embrague que controla la potencia del motor a la rueda trasera","ru":"Небольшой диапазон хода рычага сцепления, который регулирует передачу мощности от двигателя к заднему колесу","tr":"Motordan arka tekerleğe aktarılan gücü kontrol eden küçük debriyaj kolu hareket aralığı","hi":"क्लच-लीवर की उस छोटी रेंज की गति जो इंजन से रियर व्हील तक पावर को नियंत्रित करती है","ar":"المدى الصغير من حركة ذراع القابض الذي يتحكم في الطاقة المنتقلة من المحرك إلى العجلة الخلفية"},{"en":"The pivot point of the gear-shift lever on the left footrest","es":"El punto de pivote de la palanca de cambios en el estribo izquierdo","ru":"Точка опоры рычага переключения передач на левой подножке","tr":"Sol ayak basamağındaki vites kolunun dönme noktası","hi":"बाएं फुटरेस्ट पर गियर-शिफ्ट लीवर का पिवट पॉइंट","ar":"نقطة ارتكاز ذراع تغيير السرعات على مسند القدم الأيسر"}],"e":{"en":"The friction zone is the area of clutch-lever travel where the engine begins to transfer power to the rear wheel. The Motorcycle Operator Manual urges riders to be very familiar with the friction zone for manual transmissions.","es":"La zona de fricción es el área de recorrido de la palanca del embrague donde el motor empieza a transferir potencia a la rueda trasera. El Manual del Operador de Motocicletas insta a los conductores a familiarizarse muy bien con la zona de fricción en las transmisiones manuales.","ru":"Зона пробуксовки сцепления — это участок хода рычага сцепления, на котором двигатель начинает передавать мощность на заднее колесо. Руководство мотоциклиста настоятельно рекомендует хорошо изучить зону пробуксовки сцепления при работе с механической коробкой передач.","tr":"Friksiyon bölgesi, motorun arka tekerleğe güç aktarmaya başladığı debriyaj kolu hareket aralığıdır. Motosiklet Kullanıcı Kılavuzu, manuel şanzımanlar için sürücülerin friksiyon bölgesine çok aşina olmalarını ister.","hi":"फ्रिक्शन ज़ोन क्लच-लीवर की गति का वह क्षेत्र है जहाँ इंजन रियर व्हील को पावर ट्रांसफर करना शुरू करता है। Motorcycle Operator Manual राइडर्स को मैनुअल ट्रांसमिशन के लिए फ्रिक्शन ज़ोन से भली-भाँति परिचित होने का आग्रह करता है।","ar":"منطقة الاحتكاك هي المنطقة من حركة ذراع القابض التي يبدأ فيها المحرك بنقل الطاقة إلى العجلة الخلفية. يحث دليل مشغّل الدراجة النارية السائقين على أن يكونوا على دراية تامة بمنطقة الاحتكاك في ناقل الحركة اليدوي."}},{"cat":"controls","a":0,"q":{"en":"On a typical motorcycle with the gear pattern 1-N-2-3-4-5, where is first gear?","es":"En una motocicleta típica con el patrón de cambios 1-N-2-3-4-5, ¿dónde está la primera velocidad?","ru":"На типичном мотоцикле со схемой передач 1-N-2-3-4-5 где находится первая передача?","tr":"Vites düzeni 1-N-2-3-4-5 olan tipik bir motosiklette birinci vites nerededir?","hi":"1-N-2-3-4-5 गियर पैटर्न वाली एक सामान्य मोटरसाइकिल पर, पहला गियर कहाँ होता है?","ar":"في دراجة نارية نموذجية بنمط تروس 1-N-2-3-4-5، أين يقع الترس الأول؟"},"o":[{"en":"All the way down","es":"Totalmente abajo","ru":"В самом нижнем положении","tr":"En aşağıda","hi":"सबसे नीचे तक","ar":"في أسفل المدى تمامًا"},{"en":"All the way up","es":"Totalmente arriba","ru":"В самом верхнем положении","tr":"En yukarıda","hi":"सबसे ऊपर तक","ar":"في أعلى المدى تمامًا"},{"en":"Above neutral","es":"Por encima de neutral","ru":"Над нейтралью","tr":"Boşun üzerinde","hi":"न्यूट्रल के ऊपर","ar":"فوق الوضع المحايد"},{"en":"Two presses up from neutral","es":"Dos presiones hacia arriba desde neutral","ru":"На два нажатия вверх от нейтрали","tr":"Boştan iki basış yukarıda","hi":"न्यूट्रल से दो दबाव ऊपर","ar":"ضغطتان للأعلى من الوضع المحايد"}],"e":{"en":"In the standard 1-N-2-3-4-5 pattern, first gear is at the bottom (all the way down) and neutral is just above it. The Motorcycle Operator Manual describes this typical gear pattern.","es":"En el patrón estándar 1-N-2-3-4-5, la primera velocidad está abajo del todo (totalmente abajo) y neutral está justo por encima de ella. El Manual del Operador de Motocicletas describe este patrón de cambios típico.","ru":"В стандартной схеме 1-N-2-3-4-5 первая передача находится внизу (в самом нижнем положении), а нейтраль — чуть выше неё. Руководство мотоциклиста описывает эту типичную схему передач.","tr":"Standart 1-N-2-3-4-5 düzeninde birinci vites en alttadır (en aşağıda) ve boş hemen onun üzerindedir. Motosiklet Kullanıcı Kılavuzu bu tipik vites düzenini açıklar.","hi":"मानक 1-N-2-3-4-5 पैटर्न में, पहला गियर सबसे नीचे (पूरी तरह नीचे) होता है और न्यूट्रल उसके ठीक ऊपर होता है। Motorcycle Operator Manual इस सामान्य गियर पैटर्न का वर्णन करता है।","ar":"في النمط القياسي 1-N-2-3-4-5، يقع الترس الأول في الأسفل تمامًا، ويقع الوضع المحايد فوقه مباشرة. يصف دليل مشغّل الدراجة النارية نمط التروس النموذجي هذا."}},{"cat":"controls","a":2,"q":{"en":"In the typical 1-N-2-3-4-5 gear pattern, how is neutral selected from first gear?","es":"En el patrón típico de cambios 1-N-2-3-4-5, ¿cómo se selecciona neutral desde la primera velocidad?","ru":"В типичной схеме передач 1-N-2-3-4-5 как выбирается нейтраль из первой передачи?","tr":"Tipik 1-N-2-3-4-5 vites düzeninde, birinci vitesten boş nasıl seçilir?","hi":"सामान्य 1-N-2-3-4-5 गियर पैटर्न में, पहले गियर से न्यूट्रल कैसे चुना जाता है?","ar":"في نمط التروس النموذجي 1-N-2-3-4-5، كيف يُختار الوضع المحايد من الترس الأول؟"},"o":[{"en":"A full lift up two positions","es":"Un levantamiento completo hacia arriba de dos posiciones","ru":"Полным подъёмом вверх на две позиции","tr":"İki konum tam yukarı kaldırarak","hi":"दो स्थान पूरी तरह ऊपर उठाकर","ar":"رفع كامل للأعلى بمقدار وضعين"},{"en":"A full press down from first gear","es":"Una presión completa hacia abajo desde la primera velocidad","ru":"Полным нажатием вниз из первой передачи","tr":"Birinci vitesten tam aşağı basarak","hi":"पहले गियर से पूरी तरह नीचे दबाकर","ar":"ضغط كامل للأسفل من الترس الأول"},{"en":"A \"half lift\" up from first gear","es":"Un \"medio levantamiento\" hacia arriba desde la primera velocidad","ru":"«Половинным подъёмом» вверх из первой передачи","tr":"Birinci vitesten \"yarım kaldırarak\"","hi":"पहले गियर से एक \"आधा लिफ्ट\" ऊपर","ar":"\"نصف رفعة\" للأعلى من الترس الأول"},{"en":"By squeezing the clutch only, with no lever movement","es":"Apretando solo el embrague, sin mover la palanca","ru":"Только сжатием сцепления, без перемещения рычага","tr":"Sadece debriyajı sıkarak, kolu hareket ettirmeden","hi":"केवल क्लच दबाकर, बिना लीवर हिलाए","ar":"بالضغط على القابض فقط، دون تحريك الذراع"}],"e":{"en":"Neutral sits between first and second gear and is found with a \"half lift\" from first or a \"half press\" from second. The Motorcycle Operator Manual describes this method of selecting neutral.","es":"Neutral se ubica entre la primera y la segunda velocidad y se encuentra con un \"medio levantamiento\" desde la primera o una \"media presión\" desde la segunda. El Manual del Operador de Motocicletas describe este método para seleccionar neutral.","ru":"Нейтраль находится между первой и второй передачей, и её можно найти «половинным подъёмом» из первой или «половинным нажатием» из второй. Руководство мотоциклиста описывает этот способ выбора нейтрали.","tr":"Boş, birinci ve ikinci vites arasında yer alır ve birinciden \"yarım kaldırma\" ya da ikinciden \"yarım basma\" ile bulunur. Motosiklet Kullanıcı Kılavuzu, boş seçmenin bu yöntemini açıklar.","hi":"न्यूट्रल पहले और दूसरे गियर के बीच होता है और इसे पहले गियर से \"आधा लिफ्ट\" या दूसरे गियर से \"आधा प्रेस\" से पाया जाता है। Motorcycle Operator Manual न्यूट्रल चुनने की इस विधि का वर्णन करता है।","ar":"يقع الوضع المحايد بين الترس الأول والثاني، ويُوجد بـ\"نصف رفعة\" من الأول أو \"نصف ضغطة\" من الثاني. يصف دليل مشغّل الدراجة النارية هذه الطريقة لاختيار الوضع المحايد."}},{"cat":"controls","a":0,"q":{"en":"To shift up to a higher gear, how do you move the shift lever?","es":"Para subir a una velocidad más alta, ¿cómo se mueve la palanca de cambios?","ru":"Чтобы переключиться на повышенную передачу, как нужно перемещать рычаг переключения?","tr":"Daha yüksek bir vitese geçmek için vites kolunu nasıl hareket ettirirsiniz?","hi":"ऊँचे गियर में शिफ्ट अप करने के लिए, आप शिफ्ट लीवर को कैसे हिलाते हैं?","ar":"لرفع السرعة إلى ترس أعلى، كيف تحرّك ذراع التغيير؟"},"o":[{"en":"Position your foot under the lever and lift it","es":"Coloca el pie debajo de la palanca y levántala","ru":"Подвести ногу под рычаг и поднять его","tr":"Ayağınızı kolun altına yerleştirip kaldırın","hi":"अपने पैर को लीवर के नीचे रखें और उसे ऊपर उठाएं","ar":"ضع قدمك تحت الذراع وارفعه"},{"en":"Press the lever straight down","es":"Presiona la palanca derecho hacia abajo","ru":"Нажать на рычаг прямо вниз","tr":"Kola düz aşağı basın","hi":"लीवर को सीधा नीचे दबाएं","ar":"اضغط الذراع للأسفل مباشرة"},{"en":"Pull the lever toward you with your toe","es":"Jala la palanca hacia ti con la punta del pie","ru":"Потянуть рычаг на себя носком ноги","tr":"Kolu ayak ucunuzla kendinize doğru çekin","hi":"लीवर को अपने पंजे से अपनी ओर खींचें","ar":"اسحب الذراع نحوك بإصبع قدمك"},{"en":"Twist the lever outward","es":"Gira la palanca hacia afuera","ru":"Повернуть рычаг наружу","tr":"Kolu dışa doğru çevirin","hi":"लीवर को बाहर की ओर घुमाएं","ar":"لُفّ الذراع للخارج"}],"e":{"en":"To upshift, place your foot under the shift lever and lift; to downshift, press it down. The Motorcycle Operator Manual explains the lever changes one gear each time it is lifted or pressed.","es":"Para subir de velocidad, coloca el pie debajo de la palanca de cambios y levanta; para bajar de velocidad, presiónala hacia abajo. El Manual del Operador de Motocicletas explica que la palanca cambia una velocidad cada vez que se levanta o se presiona.","ru":"Чтобы повысить передачу, подведите ногу под рычаг переключения и поднимите его; чтобы понизить — нажмите вниз. Руководство мотоциклиста поясняет, что рычаг меняет одну передачу при каждом подъёме или нажатии.","tr":"Vites yükseltmek için ayağınızı vites kolunun altına koyup kaldırın; vites düşürmek için aşağı basın. Motosiklet Kullanıcı Kılavuzu, kolun her kaldırılış ya da basılışında bir vites değiştirdiğini açıklar.","hi":"अपशिफ्ट करने के लिए, अपने पैर को शिफ्ट लीवर के नीचे रखें और ऊपर उठाएं; डाउनशिफ्ट करने के लिए, इसे नीचे दबाएं। Motorcycle Operator Manual समझाता है कि हर बार उठाने या दबाने पर लीवर एक गियर बदलता है।","ar":"لرفع السرعة، ضع قدمك تحت ذراع التغيير وارفعه؛ ولخفض السرعة، اضغطه للأسفل. يوضح دليل مشغّل الدراجة النارية أن الذراع يغيّر ترسًا واحدًا في كل مرة يُرفع أو يُضغط فيها."}},{"cat":"controls","a":2,"q":{"en":"What is the correct 3-step process for upshifting to a higher gear?","es":"¿Cuál es el proceso correcto de 3 pasos para subir a una velocidad más alta?","ru":"Какова правильная последовательность из 3 шагов для переключения на повышенную передачу?","tr":"Daha yüksek bir vitese geçerken doğru 3 adımlı işlem nedir?","hi":"ऊँचे गियर में अपशिफ्ट करने की सही 3-चरण प्रक्रिया क्या है?","ar":"ما هي العملية الصحيحة المكوّنة من 3 خطوات لرفع السرعة إلى ترس أعلى؟"},"o":[{"en":"Roll on the throttle, lift the shift lever, then squeeze the clutch","es":"Acelera, levanta la palanca de cambios y luego aprieta el embrague","ru":"Прибавить газ, поднять рычаг переключения, затем сжать сцепление","tr":"Gazı aç, vites kolunu kaldır, sonra debriyajı sık","hi":"थ्रॉटल रोल ऑन करें, शिफ्ट लीवर उठाएं, फिर क्लच दबाएं","ar":"لُفّ الخانق، ارفع ذراع التغيير، ثم اضغط القابض"},{"en":"Press the rear brake, lift the shift lever, then release the clutch slowly","es":"Presiona el freno trasero, levanta la palanca de cambios y luego suelta el embrague lentamente","ru":"Нажать задний тормоз, поднять рычаг переключения, затем медленно отпустить сцепление","tr":"Arka frene bas, vites kolunu kaldır, sonra debriyajı yavaşça bırak","hi":"रियर ब्रेक दबाएं, शिफ्ट लीवर उठाएं, फिर क्लच धीरे-धीरे छोड़ें","ar":"اضغط الفرامل الخلفية، ارفع ذراع التغيير، ثم حرّر القابض ببطء"},{"en":"Roll off the throttle as you squeeze the clutch, lift the shift lever firmly, then ease out the clutch and adjust the throttle","es":"Suelta el acelerador mientras aprietas el embrague, levanta la palanca de cambios con firmeza y luego suelta el embrague suavemente y ajusta el acelerador","ru":"Сбросить газ, одновременно сжимая сцепление, уверенно поднять рычаг переключения, затем плавно отпустить сцепление и отрегулировать газ","tr":"Debriyajı sıkarken gazı kapat, vites kolunu kararlı şekilde kaldır, sonra debriyajı yavaşça bırakıp gazı ayarla","hi":"क्लच दबाते हुए थ्रॉटल रोल ऑफ करें, शिफ्ट लीवर को मज़बूती से उठाएं, फिर क्लच को धीरे से छोड़ें और थ्रॉटल को समायोजित करें","ar":"ارخِ الخانق أثناء الضغط على القابض، ارفع ذراع التغيير بثبات، ثم أرخِ القابض تدريجيًا واضبط الخانق"},{"en":"Squeeze the front brake, press the shift lever down, then roll on the throttle","es":"Aprieta el freno delantero, presiona la palanca de cambios hacia abajo y luego acelera","ru":"Сжать передний тормоз, нажать рычаг переключения вниз, затем прибавить газ","tr":"Ön freni sık, vites kolunu aşağı bas, sonra gazı aç","hi":"फ्रंट ब्रेक दबाएं, शिफ्ट लीवर को नीचे दबाएं, फिर थ्रॉटल रोल ऑन करें","ar":"اضغط الفرامل الأمامية، اضغط ذراع التغيير للأسفل، ثم لُفّ الخانق"}],"e":{"en":"Upshifting uses a 3-step process: roll off the throttle while squeezing the clutch, lift the shift lever firmly, then ease out the clutch and adjust the throttle. The Motorcycle Operator Manual lists these exact steps.","es":"Para subir de velocidad se usa un proceso de 3 pasos: suelta el acelerador mientras aprietas el embrague, levanta la palanca de cambios con firmeza y luego suelta el embrague suavemente y ajusta el acelerador. El Manual del Operador de Motocicletas indica estos pasos exactos.","ru":"Повышение передачи выполняется в 3 шага: сбросить газ, одновременно сжимая сцепление, уверенно поднять рычаг переключения, затем плавно отпустить сцепление и отрегулировать газ. Руководство мотоциклиста приводит именно эти шаги.","tr":"Vites yükseltme 3 adımlı bir işlem kullanır: debriyajı sıkarken gazı kapatın, vites kolunu kararlı şekilde kaldırın, sonra debriyajı yavaşça bırakıp gazı ayarlayın. Motosiklet Kullanıcı Kılavuzu bu adımları aynen sıralar.","hi":"अपशिफ्टिंग में 3-चरण प्रक्रिया होती है: क्लच दबाते हुए थ्रॉटल रोल ऑफ करें, शिफ्ट लीवर को मज़बूती से उठाएं, फिर क्लच को धीरे से छोड़ें और थ्रॉटल को समायोजित करें। Motorcycle Operator Manual इन्हीं चरणों को सूचीबद्ध करता है।","ar":"يستخدم رفع السرعة عملية من 3 خطوات: ارخِ الخانق أثناء الضغط على القابض، ارفع ذراع التغيير بثبات، ثم أرخِ القابض تدريجيًا واضبط الخانق. يُدرج دليل مشغّل الدراجة النارية هذه الخطوات بالضبط."}},{"cat":"controls","a":1,"q":{"en":"When downshifting, what should you do with the throttle as you ease the clutch lever back out?","es":"Al bajar de velocidad, ¿qué debes hacer con el acelerador mientras sueltas suavemente la palanca del embrague?","ru":"При понижении передачи что нужно делать с газом, когда вы плавно отпускаете рычаг сцепления?","tr":"Vites düşürürken, debriyaj kolunu yavaşça geri bırakırken gazla ne yapmalısınız?","hi":"डाउनशिफ्ट करते समय, जब आप क्लच लीवर को धीरे से वापस छोड़ते हैं तो आपको थ्रॉटल के साथ क्या करना चाहिए?","ar":"عند خفض السرعة، ماذا يجب أن تفعل بالخانق وأنت ترخي ذراع القابض للخارج؟"},"o":[{"en":"Keep the throttle fully closed until the clutch is released","es":"Mantener el acelerador totalmente cerrado hasta que se suelte el embrague","ru":"Держать газ полностью закрытым, пока сцепление не будет отпущено","tr":"Debriyaj bırakılana kadar gazı tamamen kapalı tutun","hi":"क्लच छूटने तक थ्रॉटल को पूरी तरह बंद रखें","ar":"أبقِ الخانق مغلقًا تمامًا حتى يُحرّر القابض"},{"en":"Roll on the throttle slightly to bring the engine up to speed","es":"Acelerar un poco para que el motor suba de revoluciones","ru":"Слегка прибавить газ, чтобы поднять обороты двигателя","tr":"Motoru devrine getirmek için gazı biraz açın","hi":"इंजन को गति तक लाने के लिए थ्रॉटल को थोड़ा रोल ऑन करें","ar":"لُفّ الخانق قليلًا لرفع سرعة المحرك"},{"en":"Snap the throttle fully open at once","es":"Abrir el acelerador por completo de golpe","ru":"Резко открыть газ полностью разом","tr":"Gazı bir anda tamamen sonuna kadar açın","hi":"थ्रॉटल को एक ही बार में पूरी तरह खोल दें","ar":"افتح الخانق بالكامل دفعة واحدة"},{"en":"Press the rear brake instead of using the throttle","es":"Presionar el freno trasero en lugar de usar el acelerador","ru":"Нажать задний тормоз вместо использования газа","tr":"Gaz yerine arka frene basın","hi":"थ्रॉटल के बजाय रियर ब्रेक दबाएं","ar":"اضغط الفرامل الخلفية بدلًا من استخدام الخانق"}],"e":{"en":"When downshifting, roll on the throttle as you ease out the clutch so the engine comes up to speed and the downshift is smoother. The Motorcycle Operator Manual describes this 3-step downshift technique.","es":"Al bajar de velocidad, acelera un poco mientras sueltas suavemente el embrague para que el motor suba de revoluciones y la reducción sea más suave. El Manual del Operador de Motocicletas describe esta técnica de reducción de 3 pasos.","ru":"При понижении передачи прибавляйте газ по мере того, как плавно отпускаете сцепление, чтобы обороты двигателя поднялись и понижение передачи прошло мягче. Руководство мотоциклиста описывает эту технику понижения передачи в 3 шага.","tr":"Vites düşürürken debriyajı bırakırken gazı biraz açın ki motor devrine gelsin ve vites düşürme daha yumuşak olsun. Motosiklet Kullanıcı Kılavuzu bu 3 adımlı vites düşürme tekniğini açıklar.","hi":"डाउनशिफ्ट करते समय, क्लच को धीरे से छोड़ते हुए थ्रॉटल रोल ऑन करें ताकि इंजन गति तक आ जाए और डाउनशिफ्ट सहज हो। Motorcycle Operator Manual इस 3-चरण डाउनशिफ्ट तकनीक का वर्णन करता है।","ar":"عند خفض السرعة، لُفّ الخانق وأنت ترخي القابض للخارج حتى يرتفع المحرك إلى السرعة المناسبة ويكون خفض السرعة أكثر سلاسة. يصف دليل مشغّل الدراجة النارية تقنية خفض السرعة هذه المكوّنة من 3 خطوات."}},{"cat":"controls","a":3,"q":{"en":"When you come to a stop and remain stopped, which gear should you keep the motorcycle in?","es":"Cuando llegas a una parada y permaneces detenido, ¿en qué velocidad debes mantener la motocicleta?","ru":"Когда вы останавливаетесь и стоите на месте, на какой передаче следует держать мотоцикл?","tr":"Durup beklerken motosikleti hangi viteste tutmalısınız?","hi":"जब आप रुकते हैं और रुके रहते हैं, तो आपको मोटरसाइकिल को किस गियर में रखना चाहिए?","ar":"عندما تتوقف وتبقى متوقفًا، في أي ترس يجب أن تُبقي الدراجة النارية؟"},"o":[{"en":"Neutral","es":"Neutral","ru":"Нейтраль","tr":"Boşta","hi":"न्यूट्रल","ar":"الوضع المحايد"},{"en":"Second gear","es":"Segunda velocidad","ru":"Вторая передача","tr":"İkinci viteste","hi":"दूसरा गियर","ar":"الترس الثاني"},{"en":"The highest gear you were using","es":"La velocidad más alta que estabas usando","ru":"Самая высокая из использованных передач","tr":"Kullandığınız en yüksek viteste","hi":"जो सबसे ऊँचा गियर आप उपयोग कर रहे थे","ar":"أعلى ترس كنت تستخدمه"},{"en":"First gear","es":"Primera velocidad","ru":"Первая передача","tr":"Birinci viteste","hi":"पहला गियर","ar":"الترس الأول"}],"e":{"en":"Remain in first gear while stopped so you can move out quickly if you need to. The Motorcycle Operator Manual specifically advises staying in first gear at a stop.","es":"Permanece en primera velocidad mientras estás detenido para poder arrancar rápidamente si lo necesitas. El Manual del Operador de Motocicletas aconseja específicamente quedarse en primera velocidad al detenerse.","ru":"Оставайтесь на первой передаче во время остановки, чтобы можно было быстро тронуться, если потребуется. Руководство мотоциклиста прямо советует оставаться на первой передаче при остановке.","tr":"Dururken birinci viteste kalın ki gerekirse hızlıca hareket edebilesiniz. Motosiklet Kullanıcı Kılavuzu, dururken özellikle birinci viteste kalmayı önerir.","hi":"रुके रहने के दौरान पहले गियर में रहें ताकि ज़रूरत पड़ने पर आप जल्दी निकल सकें। Motorcycle Operator Manual विशेष रूप से रुकने पर पहले गियर में रहने की सलाह देता है।","ar":"ابقَ في الترس الأول أثناء التوقف حتى تتمكن من الانطلاق بسرعة إذا احتجت. ينصح دليل مشغّل الدراجة النارية تحديدًا بالبقاء في الترس الأول عند التوقف."}},{"cat":"controls","a":1,"q":{"en":"Why should you start out with your right wrist held flat?","es":"¿Por qué debes comenzar con la muñeca derecha plana?","ru":"Почему трогаться с места следует, держа правое запястье ровно?","tr":"Sağ bileğinizi düz tutarak başlamanız neden önerilir?","hi":"आपको अपनी दाहिनी कलाई को सपाट रखकर शुरुआत क्यों करनी चाहिए?","ar":"لماذا يجب أن تبدأ ورسغك اليمنى مسطّحة؟"},"o":[{"en":"It keeps the front brake covered at all times","es":"Mantiene el freno delantero cubierto en todo momento","ru":"Это держит передний тормоз всегда наготове","tr":"Ön freni her zaman hazır tutar","hi":"यह हर समय फ्रंट ब्रेक को कवर रखता है","ar":"لأنها تُبقي الفرامل الأمامية مغطاة في كل الأوقات"},{"en":"It helps you keep from accidentally using too much throttle","es":"Ayuda a evitar que uses demasiado acelerador por accidente","ru":"Это помогает избежать случайной подачи слишком большого газа","tr":"Yanlışlıkla çok fazla gaz vermenizi önlemeye yardımcı olur","hi":"यह आपको गलती से बहुत अधिक थ्रॉटल का उपयोग करने से बचने में मदद करता है","ar":"لأنها تساعدك على تجنّب استخدام الخانق بإفراط عن طريق الخطأ"},{"en":"It locks your arm so you can hold yourself up","es":"Bloquea tu brazo para que puedas sostenerte","ru":"Это фиксирует руку, чтобы удерживать себя на мотоцикле","tr":"Kendinizi tutabilmek için kolunuzu kilitler","hi":"यह आपकी बाँह को लॉक कर देता है ताकि आप खुद को सहारा दे सकें","ar":"لأنها تثبّت ذراعك حتى تستطيع أن تسند نفسك"},{"en":"It points your fingers toward the clutch lever","es":"Apunta tus dedos hacia la palanca del embrague","ru":"Это направляет пальцы к рычагу сцепления","tr":"Parmaklarınızı debriyaj koluna doğru yönlendirir","hi":"यह आपकी उंगलियों को क्लच लीवर की ओर इंगित करता है","ar":"لأنها توجّه أصابعك نحو ذراع القابض"}],"e":{"en":"Starting with the right wrist flat helps prevent accidentally rolling on too much throttle. The Motorcycle Operator Manual recommends this hand position when holding the handgrips.","es":"Comenzar con la muñeca derecha plana ayuda a evitar acelerar demasiado por accidente. El Manual del Operador de Motocicletas recomienda esta posición de la mano al sostener las manijas.","ru":"Трогаясь с ровным правым запястьем, вы избегаете случайной подачи слишком большого газа. Руководство мотоциклиста рекомендует такое положение руки при удержании рукояток руля.","tr":"Sağ bilek düz başlamak, yanlışlıkla çok fazla gaz vermeyi önlemeye yardımcı olur. Motosiklet Kullanıcı Kılavuzu, gidon kabzalarını tutarken bu el konumunu önerir.","hi":"दाहिनी कलाई को सपाट रखकर शुरू करने से गलती से बहुत अधिक थ्रॉटल रोल ऑन होने से बचने में मदद मिलती है। Motorcycle Operator Manual हैंडग्रिप पकड़ते समय इस हाथ की स्थिति की सिफारिश करता है।","ar":"البدء والرسغ اليمنى مسطّحة يساعد على منع لفّ الخانق بإفراط عن طريق الخطأ. يوصي دليل مشغّل الدراجة النارية بوضعية اليد هذه عند الإمساك بالمقابض."}},{"cat":"controls","a":3,"q":{"en":"When checked or released, what should a properly working throttle do?","es":"Al revisarlo o soltarlo, ¿qué debe hacer un acelerador que funciona correctamente?","ru":"Что должна делать исправно работающая ручка газа при проверке или отпускании?","tr":"Kontrol edildiğinde ya da bırakıldığında, düzgün çalışan bir gaz kolu ne yapmalıdır?","hi":"जाँच या छोड़े जाने पर, सही ढंग से काम करने वाले थ्रॉटल को क्या करना चाहिए?","ar":"عند فحصه أو تحريره، ماذا يجب أن يفعل الخانق الذي يعمل بشكل سليم؟"},"o":[{"en":"Stay wherever it is set","es":"Quedarse donde quiera que se haya ajustado","ru":"Оставаться в том положении, в котором установлена","tr":"Bırakıldığı yerde kalmalı","hi":"जहाँ भी सेट हो वहीं रहना चाहिए","ar":"يبقى في الوضع الذي ضُبط عليه"},{"en":"Slowly creep open on its own","es":"Abrirse lentamente por sí solo","ru":"Медленно открываться сама по себе","tr":"Kendiliğinden yavaşça açılmalı","hi":"अपने आप धीरे-धीरे खुलते जाना चाहिए","ar":"ينفتح ببطء من تلقاء نفسه"},{"en":"Lock into the last position used","es":"Bloquearse en la última posición usada","ru":"Фиксироваться в последнем использованном положении","tr":"Son kullanılan konumda kilitlenmeli","hi":"अंतिम उपयोग की गई स्थिति में लॉक हो जाना चाहिए","ar":"يثبت في آخر وضع استُخدم"},{"en":"Snap back to the fully closed position","es":"Regresar de golpe a la posición totalmente cerrada","ru":"Возвращаться в полностью закрытое положение","tr":"Tamamen kapalı konuma geri dönmeli","hi":"पूरी तरह बंद स्थिति में वापस स्नैप होना चाहिए","ar":"يرتد بسرعة إلى الوضع المغلق تمامًا"}],"e":{"en":"During the pre-ride check, the throttle should snap back to fully closed when released. The Motorcycle Operator Manual lists this under the Controls portion of the inspection.","es":"Durante la revisión previa al viaje, el acelerador debe regresar de golpe a la posición totalmente cerrada al soltarlo. El Manual del Operador de Motocicletas incluye esto en la sección de Controles de la inspección.","ru":"Во время предрейсовой проверки ручка газа при отпускании должна возвращаться в полностью закрытое положение. Руководство мотоциклиста относит это к разделу «Органы управления» осмотра.","tr":"Sürüş öncesi kontrolde, bırakıldığında gaz kolu tamamen kapalı konuma geri dönmelidir. Motosiklet Kullanıcı Kılavuzu, bunu kontrolün Kumandalar bölümünde sıralar.","hi":"प्री-राइड जाँच के दौरान, छोड़े जाने पर थ्रॉटल को पूरी तरह बंद स्थिति में वापस स्नैप होना चाहिए। Motorcycle Operator Manual इसे निरीक्षण के Controls भाग में सूचीबद्ध करता है।","ar":"أثناء الفحص قبل القيادة، يجب أن يرتد الخانق بسرعة إلى الوضع المغلق تمامًا عند تحريره. يُدرج دليل مشغّل الدراجة النارية ذلك ضمن جزء عناصر التحكم من الفحص."}},{"cat":"controls","a":2,"q":{"en":"For the best stopping ability, how should you use the brakes for normal stops?","es":"Para la mejor capacidad de frenado, ¿cómo debes usar los frenos en las paradas normales?","ru":"Для наилучшей способности к торможению как следует использовать тормоза при обычных остановках?","tr":"En iyi durma kabiliyeti için normal duruşlarda frenleri nasıl kullanmalısınız?","hi":"सबसे अच्छी रुकने की क्षमता के लिए, सामान्य स्टॉप के लिए आपको ब्रेक का उपयोग कैसे करना चाहिए?","ar":"للحصول على أفضل قدرة على التوقف، كيف يجب أن تستخدم الفرامل في حالات التوقف العادية؟"},"o":[{"en":"Use the rear brake only to avoid flipping forward","es":"Usar solo el freno trasero para evitar volcar hacia adelante","ru":"Использовать только задний тормоз, чтобы не перевернуться вперёд","tr":"Öne takla atmamak için sadece arka freni kullanın","hi":"आगे की ओर पलटने से बचने के लिए केवल रियर ब्रेक का उपयोग करें","ar":"استخدم الفرامل الخلفية فقط لتجنّب الانقلاب للأمام"},{"en":"Use the front brake only because it is most powerful","es":"Usar solo el freno delantero porque es el más potente","ru":"Использовать только передний тормоз, так как он самый мощный","tr":"En güçlü olduğu için sadece ön freni kullanın","hi":"केवल फ्रंट ब्रेक का उपयोग करें क्योंकि यह सबसे शक्तिशाली है","ar":"استخدم الفرامل الأمامية فقط لأنها الأقوى"},{"en":"Use both the front and rear brakes every time you slow or stop","es":"Usar tanto el freno delantero como el trasero cada vez que reduzcas o te detengas","ru":"Использовать оба тормоза, передний и задний, каждый раз при замедлении или остановке","tr":"Her yavaşladığınızda ya da durduğunuzda hem ön hem arka freni kullanın","hi":"हर बार धीमा होने या रुकने पर फ्रंट और रियर दोनों ब्रेक का उपयोग करें","ar":"استخدم كلتا الفرامل الأمامية والخلفية في كل مرة تبطئ أو تتوقف فيها"},{"en":"Alternate between the two brakes, one then the other","es":"Alternar entre los dos frenos, uno y luego el otro","ru":"Чередовать тормоза, то один, то другой","tr":"İki fren arasında, biri sonra diğeri olacak şekilde dönüşümlü kullanın","hi":"दोनों ब्रेक के बीच बारी-बारी से, एक फिर दूसरा","ar":"تناوب بين الفرملتين، واحدة ثم الأخرى"}],"e":{"en":"Always use both brakes every time you slow or stop, even for normal stops, so the habit is ready in an emergency. The Motorcycle Operator Manual stresses using both brakes together.","es":"Usa siempre ambos frenos cada vez que reduzcas o te detengas, incluso en paradas normales, para que el hábito esté listo en una emergencia. El Manual del Operador de Motocicletas recalca usar ambos frenos juntos.","ru":"Всегда используйте оба тормоза каждый раз при замедлении или остановке, даже при обычных остановках, чтобы навык был готов в экстренной ситуации. Руководство мотоциклиста подчёркивает совместное использование обоих тормозов.","tr":"Acil durumda alışkanlık hazır olsun diye, normal duruşlarda bile her yavaşladığınızda ya da durduğunuzda her iki freni de kullanın. Motosiklet Kullanıcı Kılavuzu, her iki frenin birlikte kullanılmasını vurgular.","hi":"हर बार धीमा होने या रुकने पर हमेशा दोनों ब्रेक का उपयोग करें, यहाँ तक कि सामान्य स्टॉप के लिए भी, ताकि यह आदत आपातकाल में तैयार रहे। Motorcycle Operator Manual दोनों ब्रेक को एक साथ उपयोग करने पर ज़ोर देता है।","ar":"استخدم دائمًا كلتا الفرملتين في كل مرة تبطئ أو تتوقف فيها، حتى في حالات التوقف العادية، حتى تكون العادة جاهزة في حالة الطوارئ. يشدد دليل مشغّل الدراجة النارية على استخدام كلتا الفرملتين معًا."}},{"cat":"controls","a":2,"q":{"en":"About how much of a motorcycle's total stopping power can the front brake provide?","es":"¿Aproximadamente cuánto de la capacidad total de frenado de una motocicleta puede proporcionar el freno delantero?","ru":"Примерно какую долю общей тормозной силы мотоцикла может обеспечить передний тормоз?","tr":"Bir motosikletin toplam durma gücünün yaklaşık ne kadarını ön fren sağlayabilir?","hi":"मोटरसाइकिल की कुल रुकने की शक्ति का लगभग कितना हिस्सा फ्रंट ब्रेक प्रदान कर सकता है?","ar":"ما هي تقريبًا نسبة قدرة التوقف الكلية للدراجة النارية التي يمكن أن توفرها الفرامل الأمامية؟"},"o":[{"en":"About 25 percent or less","es":"Cerca del 25 por ciento o menos","ru":"Около 25 процентов или меньше","tr":"Yaklaşık yüzde 25 veya daha az","hi":"लगभग 25 प्रतिशत या उससे कम","ar":"نحو 25 بالمئة أو أقل"},{"en":"Exactly 50 percent","es":"Exactamente el 50 por ciento","ru":"Ровно 50 процентов","tr":"Tam olarak yüzde 50","hi":"ठीक 50 प्रतिशत","ar":"50 بالمئة بالضبط"},{"en":"70 percent or more","es":"70 por ciento o más","ru":"70 процентов или больше","tr":"%70 veya daha fazla","hi":"70% या अधिक","ar":"70% أو أكثر"},{"en":"None; the rear brake does all the stopping","es":"Nada; el freno trasero hace todo el frenado","ru":"Никакую; всё торможение выполняет задний тормоз","tr":"Hiç; durmanın tamamını arka fren yapar","hi":"कुछ नहीं; रियर ब्रेक ही सारी रुकावट करता है","ar":"لا شيء؛ فالفرامل الخلفية تقوم بكل التوقف"}],"e":{"en":"The front brake is more powerful and can provide 70% or more of total stopping power, and is safe when used properly. The Motorcycle Operator Manual states this.","es":"El freno delantero es más potente y puede proporcionar el 70% o más de la capacidad total de frenado, y es seguro cuando se usa correctamente. El Manual del Operador de Motocicletas lo indica.","ru":"Передний тормоз мощнее и может обеспечить 70% или больше общей тормозной силы, и он безопасен при правильном использовании. Об этом говорит Руководство мотоциклиста.","tr":"Ön fren daha güçlüdür ve toplam durma gücünün %70 veya daha fazlasını sağlayabilir, doğru kullanıldığında güvenlidir. Motosiklet Kullanıcı Kılavuzu bunu belirtir.","hi":"फ्रंट ब्रेक अधिक शक्तिशाली है और कुल रुकने की शक्ति का 70% या अधिक प्रदान कर सकता है, और सही ढंग से उपयोग करने पर सुरक्षित है। Motorcycle Operator Manual यह बताता है।","ar":"الفرامل الأمامية أقوى ويمكن أن توفر 70% أو أكثر من قدرة التوقف الكلية، وهي آمنة عند استخدامها بشكل صحيح. ينص دليل مشغّل الدراجة النارية على ذلك."}},{"cat":"controls","a":0,"q":{"en":"If your throttle sticks open and twisting it back and forth does not free it, what should you do?","es":"Si tu acelerador se queda abierto y girarlo de un lado a otro no lo libera, ¿qué debes hacer?","ru":"Если ручка газа заклинила в открытом положении и проворачивание её туда-сюда не помогает, что нужно делать?","tr":"Gaz kolunuz açık takılı kalırsa ve ileri geri çevirmek onu kurtarmazsa ne yapmalısınız?","hi":"यदि आपका थ्रॉटल खुला अटक जाए और इसे आगे-पीछे घुमाने से यह मुक्त न हो, तो आपको क्या करना चाहिए?","ar":"إذا علق الخانق مفتوحًا ولم يُحرّره لفّه ذهابًا وإيابًا، فماذا يجب أن تفعل؟"},"o":[{"en":"Immediately operate the engine cut-off switch and squeeze the clutch lever at the same time","es":"Operar de inmediato el interruptor de apagado del motor y apretar la palanca del embrague al mismo tiempo","ru":"Немедленно задействовать выключатель двигателя и одновременно сжать рычаг сцепления","tr":"Hemen motor durdurma anahtarını kullanıp aynı anda debriyaj kolunu sıkın","hi":"तुरंत इंजन कट-ऑफ स्विच चलाएं और साथ ही क्लच लीवर दबाएं","ar":"شغّل فورًا مفتاح إيقاف المحرك واضغط ذراع القابض في الوقت نفسه"},{"en":"Slam on the front brake only and keep the engine running","es":"Frenar de golpe solo con el freno delantero y mantener el motor encendido","ru":"Резко нажать только передний тормоз, оставив двигатель работать","tr":"Sadece ön frene sertçe basın ve motoru çalışır durumda tutun","hi":"केवल फ्रंट ब्रेक ज़ोर से दबाएं और इंजन चालू रखें","ar":"اضغط بقوة على الفرامل الأمامية فقط وأبقِ المحرك يعمل"},{"en":"Shift quickly into neutral and coast indefinitely","es":"Poner rápidamente en neutral y rodar sin parar","ru":"Быстро перейти на нейтраль и катиться сколь угодно долго","tr":"Hızlıca boşa alıp süresiz şekilde rölantide gidin","hi":"जल्दी से न्यूट्रल में शिफ्ट करें और अनिश्चित काल तक कोस्ट करें","ar":"حوّل بسرعة إلى الوضع المحايد وانزلق إلى ما لا نهاية"},{"en":"Turn the ignition key off and let go of the handgrips","es":"Apagar la llave de encendido y soltar las manijas","ru":"Выключить зажигание ключом и отпустить рукоятки руля","tr":"Kontak anahtarını kapatıp gidon kabzalarını bırakın","hi":"इग्निशन की बंद कर दें और हैंडग्रिप छोड़ दें","ar":"أطفئ مفتاح الإشعال واترك المقابض"}],"e":{"en":"If the throttle stays stuck, operate the engine cut-off switch and squeeze the clutch at the same time to remove power from the rear wheel, then move to a safe area and stop. The Motorcycle Operator Manual gives this exact procedure.","es":"Si el acelerador permanece atascado, opera el interruptor de apagado del motor y aprieta el embrague al mismo tiempo para quitar potencia de la rueda trasera, luego dirígete a un área segura y detente. El Manual del Operador de Motocicletas da este procedimiento exacto.","ru":"Если газ остаётся заклиненным, задействуйте выключатель двигателя и одновременно сжимайте сцепление, чтобы убрать мощность с заднего колеса, затем переместитесь в безопасное место и остановитесь. Руководство мотоциклиста даёт именно эту процедуру.","tr":"Gaz takılı kalmaya devam ederse, motor durdurma anahtarını kullanıp aynı anda debriyajı sıkarak arka tekerlekten gücü kesin, sonra güvenli bir alana geçip durun. Motosiklet Kullanıcı Kılavuzu bu işlemi aynen verir.","hi":"यदि थ्रॉटल अटका रहे, तो इंजन कट-ऑफ स्विच चलाएं और साथ ही क्लच दबाएं ताकि रियर व्हील से पावर हट जाए, फिर सुरक्षित क्षेत्र में जाकर रुकें। Motorcycle Operator Manual यही प्रक्रिया देता है।","ar":"إذا بقي الخانق عالقًا، شغّل مفتاح إيقاف المحرك واضغط القابض في الوقت نفسه لإزالة الطاقة عن العجلة الخلفية، ثم انتقل إلى منطقة آمنة وتوقف. يقدّم دليل مشغّل الدراجة النارية هذا الإجراء بالضبط."}},{"cat":"controls","a":3,"q":{"en":"What is a key benefit of stopping the engine with the engine cut-off switch?","es":"¿Cuál es un beneficio clave de apagar el motor con el interruptor de apagado del motor?","ru":"В чём ключевое преимущество остановки двигателя с помощью выключателя двигателя?","tr":"Motoru, motor durdurma anahtarıyla durdurmanın temel bir faydası nedir?","hi":"इंजन कट-ऑफ स्विच से इंजन रोकने का एक प्रमुख लाभ क्या है?","ar":"ما هي الفائدة الرئيسية لإيقاف المحرك باستخدام مفتاح إيقاف المحرك؟"},"o":[{"en":"It charges the battery faster than the key","es":"Carga la batería más rápido que la llave","ru":"Он заряжает аккумулятор быстрее, чем ключ","tr":"Bataryayı anahtardan daha hızlı şarj eder","hi":"यह की की तुलना में बैटरी को तेज़ी से चार्ज करता है","ar":"يشحن البطارية أسرع من المفتاح"},{"en":"It automatically shifts the motorcycle into first gear","es":"Cambia automáticamente la motocicleta a primera velocidad","ru":"Он автоматически переключает мотоцикл на первую передачу","tr":"Motosikleti otomatik olarak birinci vitese alır","hi":"यह मोटरसाइकिल को स्वतः पहले गियर में शिफ्ट कर देता है","ar":"يحوّل الدراجة النارية تلقائيًا إلى الترس الأول"},{"en":"It engages the front brake so the motorcycle cannot roll","es":"Acciona el freno delantero para que la motocicleta no pueda rodar","ru":"Он задействует передний тормоз, чтобы мотоцикл не катился","tr":"Motosiklet kaymasın diye ön freni devreye sokar","hi":"यह फ्रंट ब्रेक लगा देता है ताकि मोटरसाइकिल लुढ़क न सके","ar":"يشغّل الفرامل الأمامية حتى لا تتدحرج الدراجة النارية"},{"en":"It lets you shut off the engine while still holding the handgrip, building a habit useful in an emergency","es":"Te permite apagar el motor mientras sigues sujetando la manija, creando un hábito útil en una emergencia","ru":"Он позволяет заглушить двигатель, не отпуская рукоятку руля, формируя навык, полезный в экстренной ситуации","tr":"Gidon kabzasını tutmaya devam ederken motoru kapatmanıza olanak tanır ve acil durumda işe yarayacak bir alışkanlık oluşturur","hi":"यह आपको हैंडग्रिप पकड़े रहते हुए इंजन बंद करने देता है, जिससे आपातकाल में उपयोगी आदत बनती है","ar":"يتيح لك إيقاف المحرك مع الإمساك بالمقبض، مما يبني عادة مفيدة في حالة الطوارئ"}],"e":{"en":"The engine cut-off switch lets you stop the engine without removing your hand from the handgrip, and using it routinely builds the habit needed for an emergency such as a stuck throttle. The Motorcycle Operator Manual recommends developing this habit.","es":"El interruptor de apagado del motor te permite detener el motor sin quitar la mano de la manija, y usarlo de forma habitual crea el hábito necesario para una emergencia como un acelerador atascado. El Manual del Operador de Motocicletas recomienda desarrollar este hábito.","ru":"Выключатель двигателя позволяет заглушить двигатель, не убирая руку с рукоятки руля, и регулярное его использование формирует навык, необходимый в экстренной ситуации, например при заклинившем газе. Руководство мотоциклиста рекомендует вырабатывать эту привычку.","tr":"Motor durdurma anahtarı, elinizi gidon kabzasından çekmeden motoru durdurmanıza olanak tanır ve bunu rutin olarak kullanmak, takılı gaz kolu gibi bir acil durumda gereken alışkanlığı oluşturur. Motosiklet Kullanıcı Kılavuzu bu alışkanlığı geliştirmeyi önerir.","hi":"इंजन कट-ऑफ स्विच आपको हैंडग्रिप से हाथ हटाए बिना इंजन रोकने देता है, और इसे नियमित रूप से उपयोग करने से अटके थ्रॉटल जैसे आपातकाल के लिए आवश्यक आदत बनती है। Motorcycle Operator Manual इस आदत को विकसित करने की सिफारिश करता है।","ar":"يتيح لك مفتاح إيقاف المحرك إيقاف المحرك دون رفع يدك عن المقبض، واستخدامه بشكل روتيني يبني العادة اللازمة لحالة طوارئ مثل خانق عالق. يوصي دليل مشغّل الدراجة النارية بتطوير هذه العادة."}},{"cat":"controls","a":2,"q":{"en":"What is the proper position for your feet while riding?","es":"¿Cuál es la posición correcta de los pies mientras conduces?","ru":"Каково правильное положение ног во время езды?","tr":"Sürüş sırasında ayaklarınız için doğru konum nedir?","hi":"राइडिंग के दौरान आपके पैरों की सही स्थिति क्या है?","ar":"ما هي الوضعية الصحيحة لقدميك أثناء القيادة؟"},"o":[{"en":"Dragging lightly along the ground for balance","es":"Arrastrándolos ligeramente por el suelo para mantener el equilibrio","ru":"Слегка волочить по земле для равновесия","tr":"Denge için hafifçe yerde sürünerek","hi":"संतुलन के लिए हल्के से ज़मीन पर घिसटते हुए","ar":"تسحبهما بخفة على الأرض للتوازن"},{"en":"Firmly on the footrests with toes pointed downward","es":"Firmes en los estribos con las puntas apuntando hacia abajo","ru":"Прочно на подножках, носки направлены вниз","tr":"Ayak basamaklarında sağlam, ayak uçları aşağı bakacak şekilde","hi":"फुटरेस्ट पर मज़बूती से, पंजे नीचे की ओर इंगित करते हुए","ar":"بثبات على مساند القدمين وأصابع القدمين موجّهة للأسفل"},{"en":"Firmly on the footrests, near the controls, without pointing the toes down","es":"Firmes en los estribos, cerca de los controles, sin apuntar las puntas hacia abajo","ru":"Прочно на подножках, рядом с органами управления, без направления носков вниз","tr":"Ayak basamaklarında sağlam, kumandalara yakın, ayak uçlarını aşağı doğrultmadan","hi":"फुटरेस्ट पर मज़बूती से, कंट्रोल के पास, बिना पंजे नीचे की ओर किए","ar":"بثبات على مساند القدمين، بالقرب من عناصر التحكم، دون توجيه أصابع القدمين للأسفل"},{"en":"Stretched forward off the footrests to relax your legs","es":"Estirados hacia adelante fuera de los estribos para relajar las piernas","ru":"Вытянуты вперёд с подножек, чтобы расслабить ноги","tr":"Bacaklarınızı dinlendirmek için ayak basamaklarından öne uzatılmış","hi":"पैरों को आराम देने के लिए फुटरेस्ट से आगे की ओर फैलाकर","ar":"ممدودتان للأمام بعيدًا عن مساند القدمين لإراحة ساقيك"}],"e":{"en":"Keep your feet firmly on the footrests near the controls and do not let your toes point downward, where they could catch between the road and footrests. The Motorcycle Operator Manual describes this foot position.","es":"Mantén los pies firmes en los estribos cerca de los controles y no dejes que las puntas apunten hacia abajo, donde podrían atascarse entre la carretera y los estribos. El Manual del Operador de Motocicletas describe esta posición de los pies.","ru":"Держите ноги прочно на подножках рядом с органами управления и не направляйте носки вниз, где они могут зацепиться между дорогой и подножками. Руководство мотоциклиста описывает такое положение ног.","tr":"Ayaklarınızı kumandalara yakın şekilde ayak basamaklarında sağlam tutun ve ayak uçlarınızın aşağı bakmasına izin vermeyin; aksi halde yol ile ayak basamakları arasına sıkışabilirler. Motosiklet Kullanıcı Kılavuzu bu ayak konumunu açıklar.","hi":"अपने पैरों को कंट्रोल के पास फुटरेस्ट पर मज़बूती से रखें और अपने पंजों को नीचे की ओर इंगित न होने दें, जहाँ वे सड़क और फुटरेस्ट के बीच फँस सकते हैं। Motorcycle Operator Manual इस पैर की स्थिति का वर्णन करता है।","ar":"أبقِ قدميك بثبات على مساند القدمين بالقرب من عناصر التحكم، ولا تدع أصابع قدميك توجَّه للأسفل، حيث قد تعلق بين الطريق ومساند القدمين. يصف دليل مشغّل الدراجة النارية وضعية القدمين هذه."}},{"cat":"controls","a":2,"q":{"en":"What does the Motorcycle Operator Manual advise about your knees while riding?","es":"¿Qué aconseja el Manual del Operador de Motocicletas sobre tus rodillas mientras conduces?","ru":"Что Руководство мотоциклиста советует насчёт коленей во время езды?","tr":"Motosiklet Kullanıcı Kılavuzu, sürüş sırasında dizleriniz hakkında ne tavsiye eder?","hi":"Motorcycle Operator Manual राइडिंग के दौरान आपके घुटनों के बारे में क्या सलाह देता है?","ar":"ماذا ينصح دليل مشغّل الدراجة النارية بشأن ركبتيك أثناء القيادة؟"},"o":[{"en":"Spread them wide away from the tank for airflow","es":"Sepáralas bien del tanque para que haya flujo de aire","ru":"Широко разводить их от бака для притока воздуха","tr":"Hava akışı için onları depodan uzakta geniş tutun","hi":"हवा के बहाव के लिए उन्हें टैंक से दूर चौड़ा फैलाएं","ar":"باعد بينهما بعيدًا عن الخزان لتدفق الهواء"},{"en":"Lock them straight to brace against bumps","es":"Mantenlas rígidas para soportar los baches","ru":"Держать их выпрямленными, чтобы упираться при неровностях","tr":"Tümseklere karşı destek için onları düz kilitleyin","hi":"धक्कों के विरुद्ध सहारा देने के लिए उन्हें सीधा लॉक करें","ar":"ثبّتهما مستقيمتين للصمود أمام المطبات"},{"en":"Keep them against the gas tank to help keep your balance as the motorcycle turns","es":"Mantenlas contra el tanque de gasolina para ayudar a mantener el equilibrio cuando la motocicleta gira","ru":"Держать их прижатыми к бензобаку, чтобы помогать удерживать равновесие при поворотах мотоцикла","tr":"Motosiklet dönerken dengenizi korumaya yardımcı olması için onları benzin deposuna yaslayın","hi":"उन्हें गैस टैंक से सटाकर रखें ताकि मोटरसाइकिल मुड़ते समय आपका संतुलन बना रहे","ar":"أبقِهما ملاصقتين لخزان الوقود للمساعدة في حفظ توازنك أثناء انعطاف الدراجة النارية"},{"en":"Lift them onto the seat at low speeds","es":"Súbelas al asiento a baja velocidad","ru":"Поднимать их на сиденье на малой скорости","tr":"Düşük hızlarda onları koltuğa kaldırın","hi":"कम गति पर उन्हें सीट पर उठा लें","ar":"ارفعهما إلى المقعد عند السرعات المنخفضة"}],"e":{"en":"Keep your knees against the gas tank to help maintain balance as the motorcycle turns. The Motorcycle Operator Manual lists this under proper body position.","es":"Mantén las rodillas contra el tanque de gasolina para ayudar a mantener el equilibrio cuando la motocicleta gira. El Manual del Operador de Motocicletas incluye esto en la posición corporal correcta.","ru":"Держите колени прижатыми к бензобаку, чтобы помогать удерживать равновесие при поворотах мотоцикла. Руководство мотоциклиста относит это к правильному положению тела.","tr":"Motosiklet dönerken dengenizi korumaya yardımcı olması için dizlerinizi benzin deposuna yaslayın. Motosiklet Kullanıcı Kılavuzu bunu doğru vücut konumu altında sıralar.","hi":"अपने घुटनों को गैस टैंक से सटाकर रखें ताकि मोटरसाइकिल मुड़ते समय संतुलन बना रहे। Motorcycle Operator Manual इसे सही शारीरिक स्थिति के अंतर्गत सूचीबद्ध करता है।","ar":"أبقِ ركبتيك ملاصقتين لخزان الوقود للمساعدة في الحفاظ على التوازن أثناء انعطاف الدراجة النارية. يُدرج دليل مشغّل الدراجة النارية ذلك ضمن وضعية الجسم الصحيحة."}},{"cat":"controls","a":0,"q":{"en":"Why should you sit far enough forward so your arms are slightly bent at the handgrips?","es":"¿Por qué debes sentarte lo suficientemente adelante para que tus brazos estén ligeramente flexionados en las manijas?","ru":"Почему следует сидеть достаточно близко к рулю, чтобы руки на рукоятках были слегка согнуты?","tr":"Gidon kabzalarındayken kollarınız hafifçe bükülü olacak kadar öne oturmanız neden gereklidir?","hi":"आपको इतना आगे क्यों बैठना चाहिए कि हैंडग्रिप पर आपकी बाँहें थोड़ी मुड़ी हुई हों?","ar":"لماذا يجب أن تجلس متقدمًا بما يكفي لتكون ذراعاك منثنيتين قليلًا عند المقابض؟"},"o":[{"en":"So you can press on the handlebars without having to reach too far","es":"Para poder presionar el manillar sin tener que estirarte demasiado","ru":"Чтобы можно было давить на руль, не дотягиваясь слишком далеко","tr":"Çok uzanmadan gidona baskı yapabilmek için","hi":"ताकि आप बहुत दूर तक पहुँचे बिना हैंडलबार पर दबाव डाल सकें","ar":"حتى تتمكن من الضغط على المقود دون الحاجة إلى المد بعيدًا"},{"en":"So you can rest your full weight on your arms","es":"Para poder apoyar todo tu peso sobre los brazos","ru":"Чтобы можно было переносить весь свой вес на руки","tr":"Tüm ağırlığınızı kollarınıza yükleyebilmek için","hi":"ताकि आप अपना पूरा वज़न अपनी बाँहों पर डाल सकें","ar":"حتى تتمكن من إراحة كامل وزنك على ذراعيك"},{"en":"So your wrists stay angled high on the throttle","es":"Para que tus muñecas queden inclinadas hacia arriba sobre el acelerador","ru":"Чтобы запястья оставались высоко поднятыми на ручке газа","tr":"Bileklerinizin gaz kolunda yüksekte açılı kalması için","hi":"ताकि आपकी कलाइयाँ थ्रॉटल पर ऊँचे कोण पर रहें","ar":"حتى تبقى رسغاك مرفوعتين على الخانق"},{"en":"So your feet leave the footrests during turns","es":"Para que tus pies salgan de los estribos durante las curvas","ru":"Чтобы ноги отрывались от подножек в поворотах","tr":"Dönüşlerde ayaklarınız ayak basamaklarından ayrılsın diye","hi":"ताकि मोड़ों के दौरान आपके पैर फुटरेस्ट से हट जाएं","ar":"حتى تترك قدماك مساند القدمين أثناء الانعطافات"}],"e":{"en":"Sitting forward with slightly bent arms lets you press on the handlebars without overreaching, helping you steer rather than hold yourself up. The Motorcycle Operator Manual describes this seating position.","es":"Sentarte adelante con los brazos ligeramente flexionados te permite presionar el manillar sin estirarte de más, lo que te ayuda a conducir en lugar de sostenerte. El Manual del Operador de Motocicletas describe esta posición al sentarse.","ru":"Если сидеть близко со слегка согнутыми руками, можно давить на руль без чрезмерного вытягивания, что помогает рулить, а не удерживать себя. Руководство мотоциклиста описывает такое положение посадки.","tr":"Kollar hafifçe bükülü şekilde öne oturmak, fazla uzanmadan gidona baskı yapmanızı sağlar ve kendinizi tutmak yerine direksiyona yardımcı olur. Motosiklet Kullanıcı Kılavuzu bu oturuş konumunu açıklar.","hi":"थोड़ी मुड़ी हुई बाँहों के साथ आगे बैठने से आप बहुत दूर पहुँचे बिना हैंडलबार पर दबाव डाल सकते हैं, जिससे आपको खुद को सहारा देने के बजाय स्टीयर करने में मदद मिलती है। Motorcycle Operator Manual इस बैठने की स्थिति का वर्णन करता है।","ar":"الجلوس متقدمًا مع ثني الذراعين قليلًا يتيح لك الضغط على المقود دون المد المفرط، مما يساعدك على التوجيه بدلًا من إسناد نفسك. يصف دليل مشغّل الدراجة النارية وضعية الجلوس هذه."}},{"cat":"controls","a":1,"q":{"en":"In the MSF T-CLOCS pre-ride inspection, what do the letters stand for?","es":"En la inspección previa al viaje T-CLOCS de la MSF, ¿qué representan las letras?","ru":"Что означают буквы в предрейсовом осмотре MSF T-CLOCS?","tr":"MSF T-CLOCS sürüş öncesi kontrolünde harfler neyi ifade eder?","hi":"MSF T-CLOCS प्री-राइड निरीक्षण में, इन अक्षरों का क्या अर्थ है?","ar":"في فحص ما قبل القيادة T-CLOCS من MSF، ماذا ترمز الأحرف؟"},"o":[{"en":"Tank, Clutch, Lights, Oil, Cables, Speed","es":"Tanque, Embrague (Clutch), Luces (Lights), Aceite (Oil), Cables, Velocidad (Speed)","ru":"Бак, Сцепление, Свет, Масло, Тросы, Скорость","tr":"Depo, Debriyaj, Işıklar, Yağ, Kablolar, Hız","hi":"Tank, Clutch, Lights, Oil, Cables, Speed","ar":"الخزان، القابض، الأضواء، الزيت، الكابلات، السرعة"},{"en":"Tires and Wheels, Controls, Lights and Electrics, Oil and Other Fluids, Chassis, and Stands","es":"Llantas y Ruedas (Tires and Wheels), Controles, Luces y Sistema Eléctrico (Lights and Electrics), Aceite y Otros Fluidos (Oil and Other Fluids), Chasis (Chassis) y Soportes (Stands)","ru":"Шины и колёса (Tires and Wheels), Органы управления (Controls), Свет и электрика (Lights and Electrics), Масло и прочие жидкости (Oil and Other Fluids), Рама (Chassis) и Подножки/стойки (Stands)","tr":"Lastikler ve Jantlar, Kumandalar, Işıklar ve Elektrik, Yağ ve Diğer Sıvılar, Şasi ve Sehpalar","hi":"Tires and Wheels, Controls, Lights and Electrics, Oil and Other Fluids, Chassis, और Stands","ar":"الإطارات والعجلات، عناصر التحكم، الأضواء والكهربائيات، الزيت والسوائل الأخرى، الهيكل، والحوامل"},{"en":"Throttle, Clutch, Levers, Oil, Choke, and Seat","es":"Acelerador (Throttle), Embrague (Clutch), Palancas (Levers), Aceite (Oil), Estárter (Choke) y Asiento (Seat)","ru":"Газ, Сцепление, Рычаги, Масло, Подсос, Сиденье","tr":"Gaz Kolu, Debriyaj, Kollar, Yağ, Jikle ve Koltuk","hi":"Throttle, Clutch, Levers, Oil, Choke, और Seat","ar":"الخانق، القابض، الأذرع، الزيت، الشفّاط، والمقعد"},{"en":"Tires, Cooling, Lubrication, Odometer, Carburetor, and Steering","es":"Llantas (Tires), Enfriamiento (Cooling), Lubricación (Lubrication), Odómetro (Odometer), Carburador (Carburetor) y Dirección (Steering)","ru":"Шины, Охлаждение, Смазка, Одометр, Карбюратор, Рулевое управление","tr":"Lastikler, Soğutma, Yağlama, Kilometre Sayacı, Karbüratör ve Direksiyon","hi":"Tires, Cooling, Lubrication, Odometer, Carburetor, और Steering","ar":"الإطارات، التبريد، التزييت، عداد المسافة، المكربن، والتوجيه"}],"e":{"en":"T-CLOCS stands for Tires and Wheels, Controls, Lights and Electrics, Oil and Other Fluids, Chassis, and Stands. The Motorcycle Operator Manual presents T-CLOCS as the pre-ride inspection to perform before every ride.","es":"T-CLOCS representa Llantas y Ruedas (Tires and Wheels), Controles, Luces y Sistema Eléctrico (Lights and Electrics), Aceite y Otros Fluidos (Oil and Other Fluids), Chasis (Chassis) y Soportes (Stands). El Manual del Operador de Motocicletas presenta T-CLOCS como la inspección previa al viaje que debe realizarse antes de cada recorrido.","ru":"T-CLOCS означает Шины и колёса (Tires and Wheels), Органы управления (Controls), Свет и электрика (Lights and Electrics), Масло и прочие жидкости (Oil and Other Fluids), Рама (Chassis) и Подножки/стойки (Stands). Руководство мотоциклиста представляет T-CLOCS как предрейсовый осмотр, который следует выполнять перед каждой поездкой.","tr":"T-CLOCS; Lastikler ve Jantlar (Tires and Wheels), Kumandalar (Controls), Işıklar ve Elektrik (Lights and Electrics), Yağ ve Diğer Sıvılar (Oil and Other Fluids), Şasi (Chassis) ve Sehpalar (Stands) anlamına gelir. Motosiklet Kullanıcı Kılavuzu, T-CLOCS'u her sürüşten önce yapılacak sürüş öncesi kontrol olarak sunar.","hi":"T-CLOCS का अर्थ है Tires and Wheels, Controls, Lights and Electrics, Oil and Other Fluids, Chassis, और Stands। Motorcycle Operator Manual T-CLOCS को हर राइड से पहले किए जाने वाले प्री-राइड निरीक्षण के रूप में प्रस्तुत करता है।","ar":"يرمز T-CLOCS إلى الإطارات والعجلات، عناصر التحكم، الأضواء والكهربائيات، الزيت والسوائل الأخرى، الهيكل، والحوامل. يقدّم دليل مشغّل الدراجة النارية T-CLOCS كفحص ما قبل القيادة الواجب إجراؤه قبل كل رحلة."}},{"cat":"gear","a":2,"q":{"en":"According to the Motorcycle Operator Manual, what three items give you a far better chance of avoiding serious injury in a crash?","es":"Según el Manual del Operador de Motocicletas, ¿qué tres elementos te dan una probabilidad mucho mayor de evitar lesiones graves en un choque?","ru":"Согласно Руководству мотоциклиста, какие три предмета дают вам гораздо больше шансов избежать серьёзной травмы при аварии?","tr":"Motosiklet Kullanıcı Kılavuzu'na göre, bir kazada ciddi yaralanmayı önleme şansınızı çok daha fazla artıran üç şey nedir?","hi":"Motorcycle Operator Manual के अनुसार, कौन से तीन सामान दुर्घटना में गंभीर चोट से बचने का कहीं बेहतर मौका देते हैं?","ar":"وفقًا لدليل مشغّل الدراجة النارية، ما هي العناصر الثلاثة التي تمنحك فرصة أفضل بكثير لتجنّب الإصابة الخطيرة في حادث تصادم؟"},"o":[{"en":"Reflective tape, a tank bag, and engine guards","es":"Cinta reflectante, una bolsa de tanque y protectores de motor","ru":"Светоотражающая лента, сумка на бак и дуги безопасности двигателя","tr":"Reflektörlü bant, depo çantası ve motor koruyucuları","hi":"रिफ्लेक्टिव टेप, एक टैंक बैग, और इंजन गार्ड","ar":"شريط عاكس، حقيبة خزان، وواقيات المحرك"},{"en":"A loud horn, anti-lock brakes, and a windshield","es":"Una bocina fuerte, frenos antibloqueo y un parabrisas","ru":"Громкий сигнал, антиблокировочные тормоза и ветровое стекло","tr":"Yüksek sesli korna, ABS frenler ve ön cam","hi":"एक तेज़ हॉर्न, एंटी-लॉक ब्रेक, और एक विंडशील्ड","ar":"بوق عالٍ، فرامل مانعة للانغلاق، وحاجب أمامي"},{"en":"A DOT-compliant helmet, face or eye protection, and protective clothing","es":"Un casco que cumpla con la norma DOT, protección facial o para los ojos y ropa protectora","ru":"Шлем, соответствующий стандарту DOT, защита лица или глаз и защитная одежда","tr":"DOT uyumlu kask, yüz ya da göz koruması ve koruyucu kıyafet","hi":"एक DOT-अनुपालक हेलमेट, चेहरे या आँखों की सुरक्षा, और सुरक्षात्मक कपड़े","ar":"خوذة متوافقة مع معايير DOT، واقٍ للوجه أو العين، وملابس واقية"},{"en":"A passenger backrest, heated grips, and a tachometer","es":"Un respaldo para el pasajero, manijas calefaccionadas y un tacómetro","ru":"Спинка для пассажира, подогрев рукояток и тахометр","tr":"Yolcu sırt dayağı, ısıtmalı kabzalar ve devir saati","hi":"एक यात्री बैकरेस्ट, हीटेड ग्रिप, और एक टैकोमीटर","ar":"مسند ظهر للراكب، مقابض مدفّأة، ومقياس دوران"}],"e":{"en":"The Motorcycle Operator Manual states that in any crash you have a far better chance of avoiding serious injury if you wear a DOT-compliant helmet, face or eye protection, and protective clothing.","es":"El Manual del Operador de Motocicletas indica que en cualquier choque tienes una probabilidad mucho mayor de evitar lesiones graves si usas un casco que cumpla con la norma DOT, protección facial o para los ojos y ropa protectora.","ru":"Руководство мотоциклиста утверждает, что при любой аварии у вас гораздо больше шансов избежать серьёзной травмы, если вы носите шлем, соответствующий стандарту DOT, защиту лица или глаз и защитную одежду.","tr":"Motosiklet Kullanıcı Kılavuzu, herhangi bir kazada DOT uyumlu kask, yüz ya da göz koruması ve koruyucu kıyafet giyerseniz ciddi yaralanmayı önleme şansınızın çok daha fazla olduğunu belirtir.","hi":"Motorcycle Operator Manual बताता है कि किसी भी दुर्घटना में यदि आप DOT-अनुपालक हेलमेट, चेहरे या आँखों की सुरक्षा, और सुरक्षात्मक कपड़े पहनते हैं तो आपके पास गंभीर चोट से बचने का कहीं बेहतर मौका होता है।","ar":"ينص دليل مشغّل الدراجة النارية على أنه في أي حادث تصادم تكون لديك فرصة أفضل بكثير لتجنّب الإصابة الخطيرة إذا ارتديت خوذة متوافقة مع معايير DOT، وواقيًا للوجه أو العين، وملابس واقية."}},{"cat":"gear","a":0,"q":{"en":"About how many motorcycle crashes result in head or neck injuries, according to the Motorcycle Operator Manual?","es":"Según el Manual del Operador de Motocicletas, ¿aproximadamente cuántos choques de motocicleta resultan en lesiones en la cabeza o el cuello?","ru":"Примерно какая доля аварий на мотоцикле приводит к травмам головы или шеи, согласно Руководству мотоциклиста?","tr":"Motosiklet Kullanıcı Kılavuzu'na göre, motosiklet kazalarının yaklaşık ne kadarı baş ya da boyun yaralanmasıyla sonuçlanır?","hi":"Motorcycle Operator Manual के अनुसार, लगभग कितनी मोटरसाइकिल दुर्घटनाओं में सिर या गर्दन की चोटें होती हैं?","ar":"وفقًا لدليل مشغّل الدراجة النارية، كم تقريبًا من حوادث الدراجات النارية تؤدي إلى إصابات في الرأس أو الرقبة؟"},"o":[{"en":"One out of every five","es":"Uno de cada cinco","ru":"Одна из каждых пяти","tr":"Her beşte biri","hi":"हर पाँच में से एक","ar":"واحد من كل خمسة"},{"en":"One out of every fifty","es":"Uno de cada cincuenta","ru":"Одна из каждых пятидесяти","tr":"Her ellide biri","hi":"हर पचास में से एक","ar":"واحد من كل خمسين"},{"en":"One out of every two","es":"Uno de cada dos","ru":"Одна из каждых двух","tr":"Her ikide biri","hi":"हर दो में से एक","ar":"واحد من كل اثنين"},{"en":"One out of every twenty","es":"Uno de cada veinte","ru":"Одна из каждых двадцати","tr":"Her yirmide biri","hi":"हर बीस में से एक","ar":"واحد من كل عشرين"}],"e":{"en":"The Motorcycle Operator Manual reports that one out of every five motorcycle crashes results in head or neck injuries, and these account for a majority of serious and fatal injuries.","es":"El Manual del Operador de Motocicletas reporta que uno de cada cinco choques de motocicleta resulta en lesiones en la cabeza o el cuello, y estas representan la mayoría de las lesiones graves y fatales.","ru":"Руководство мотоциклиста сообщает, что одна из каждых пяти аварий на мотоцикле приводит к травмам головы или шеи, и на них приходится большинство серьёзных и смертельных травм.","tr":"Motosiklet Kullanıcı Kılavuzu, motosiklet kazalarının her beşte birinin baş ya da boyun yaralanmasıyla sonuçlandığını ve bunların ciddi ve ölümcül yaralanmaların çoğunu oluşturduğunu bildirir.","hi":"Motorcycle Operator Manual बताता है कि हर पाँच में से एक मोटरसाइकिल दुर्घटना में सिर या गर्दन की चोटें होती हैं, और ये गंभीर और घातक चोटों का बड़ा हिस्सा बनती हैं।","ar":"يفيد دليل مشغّل الدراجة النارية بأن واحدًا من كل خمسة حوادث دراجات نارية يؤدي إلى إصابات في الرأس أو الرقبة، وهذه تمثّل غالبية الإصابات الخطيرة والقاتلة."}},{"cat":"gear","a":3,"q":{"en":"According to the Motorcycle Operator Manual, what type of clothing is best for making both you and your motorcycle easiest to recognize?","es":"Según el Manual del Operador de Motocicletas, ¿qué tipo de ropa es la mejor para que tanto tú como tu motocicleta sean más fáciles de reconocer?","ru":"Согласно Руководству мотоциклиста, какой тип одежды лучше всего делает вас и ваш мотоцикл наиболее заметными?","tr":"Motosiklet Kullanıcı Kılavuzu'na göre, hem sizi hem de motosikletinizi en kolay fark edilir kılmak için en iyi kıyafet türü hangisidir?","hi":"Motorcycle Operator Manual के अनुसार, किस प्रकार के कपड़े आपको और आपकी मोटरसाइकिल दोनों को पहचानने में सबसे आसान बनाते हैं?","ar":"وفقًا لدليل مشغّل الدراجة النارية، أي نوع من الملابس هو الأفضل لجعلك أنت ودراجتك النارية أسهل في التمييز؟"},"o":[{"en":"Dark leather with no markings","es":"Cuero oscuro sin marcas","ru":"Тёмная кожа без каких-либо элементов","tr":"İşaretsiz koyu renk deri","hi":"बिना किसी निशान के गहरे रंग का चमड़ा","ar":"الجلد الداكن دون أي علامات"},{"en":"A single small reflective ankle band","es":"Una sola banda reflectante pequeña en el tobillo","ru":"Одна небольшая светоотражающая повязка на лодыжке","tr":"Tek bir küçük reflektörlü ayak bilekliği","hi":"एक छोटा रिफ्लेक्टिव टखने का बैंड","ar":"شريط عاكس صغير واحد حول الكاحل"},{"en":"Clothing that matches the color of the road","es":"Ropa que combine con el color de la carretera","ru":"Одежда, совпадающая по цвету с дорогой","tr":"Yolun rengiyle eşleşen kıyafet","hi":"सड़क के रंग से मेल खाते कपड़े","ar":"ملابس تطابق لون الطريق"},{"en":"Reflective, bright-colored clothing such as a helmet and jacket or vest","es":"Ropa reflectante de colores brillantes, como un casco y una chaqueta o chaleco","ru":"Светоотражающая одежда ярких цветов, например шлем и куртка или жилет","tr":"Kask ile ceket ya da yelek gibi reflektörlü, parlak renkli kıyafet","hi":"रिफ्लेक्टिव, चमकीले रंग के कपड़े जैसे हेलमेट और जैकेट या वेस्ट","ar":"ملابس عاكسة زاهية اللون مثل الخوذة والسترة أو الصدرية"}],"e":{"en":"The Motorcycle Operator Manual states reflective, bright-colored clothing (helmet and jacket/vest) is best; reflective material helps drivers spot you from the side, ahead, and behind.","es":"El Manual del Operador de Motocicletas indica que la ropa reflectante de colores brillantes (casco y chaqueta/chaleco) es la mejor; el material reflectante ayuda a los conductores a verte desde el costado, de frente y por detrás.","ru":"Руководство мотоциклиста утверждает, что светоотражающая одежда ярких цветов (шлем и куртка/жилет) лучше всего; светоотражающий материал помогает водителям заметить вас сбоку, спереди и сзади.","tr":"Motosiklet Kullanıcı Kılavuzu, reflektörlü, parlak renkli kıyafetin (kask ve ceket/yelek) en iyisi olduğunu belirtir; reflektörlü malzeme, sürücülerin sizi yandan, önden ve arkadan fark etmesine yardımcı olur.","hi":"Motorcycle Operator Manual बताता है कि रिफ्लेक्टिव, चमकीले रंग के कपड़े (हेलमेट और जैकेट/वेस्ट) सबसे अच्छे होते हैं; रिफ्लेक्टिव सामग्री ड्राइवरों को आपको बगल से, आगे से, और पीछे से देखने में मदद करती है।","ar":"ينص دليل مشغّل الدراجة النارية على أن الملابس العاكسة زاهية اللون (الخوذة والسترة/الصدرية) هي الأفضل؛ فالمادة العاكسة تساعد السائقين على رؤيتك من الجانب ومن الأمام ومن الخلف."}},{"cat":"gear","a":1,"q":{"en":"According to the Motorcycle Operator Manual, the single most important thing you can do to improve your chances of surviving a crash is to:","es":"Según el Manual del Operador de Motocicletas, lo más importante que puedes hacer para mejorar tus probabilidades de sobrevivir a un choque es:","ru":"Согласно Руководству мотоциклиста, самое важное, что вы можете сделать, чтобы повысить свои шансы выжить в аварии, — это:","tr":"Motosiklet Kullanıcı Kılavuzu'na göre, bir kazada hayatta kalma şansınızı artırmak için yapabileceğiniz en önemli tek şey:","hi":"Motorcycle Operator Manual के अनुसार, दुर्घटना से बचने की अपनी संभावना बेहतर करने के लिए आप जो एकमात्र सबसे महत्वपूर्ण काम कर सकते हैं, वह है:","ar":"وفقًا لدليل مشغّل الدراجة النارية، فإن أهم شيء واحد يمكنك فعله لتحسين فرصك في النجاة من حادث تصادم هو:"},"o":[{"en":"Ride only at speeds below 30 mph","es":"Conducir solo a velocidades menores a 30 mph","ru":"Ездить только со скоростью ниже 30 миль/ч","tr":"Sadece 30 mil/sa altındaki hızlarda sürmek","hi":"केवल 30 mph से कम गति पर राइड करना","ar":"القيادة فقط بسرعات أقل من 30 ميلاً في الساعة"},{"en":"Wear a securely-fastened, quality helmet","es":"Usar un casco de calidad bien abrochado","ru":"Носить надёжно застёгнутый качественный шлем","tr":"Sağlam takılmış, kaliteli bir kask takmak","hi":"एक सुरक्षित रूप से बँधा हुआ, गुणवत्तापूर्ण हेलमेट पहनना","ar":"ارتداء خوذة عالية الجودة ومثبّتة بإحكام"},{"en":"Install crash bars on the motorcycle","es":"Instalar barras de protección en la motocicleta","ru":"Установить дуги безопасности на мотоцикл","tr":"Motosiklete koruma demirleri takmak","hi":"मोटरसाइकिल पर क्रैश बार लगाना","ar":"تركيب قضبان واقية على الدراجة النارية"},{"en":"Always ride with a passenger present","es":"Conducir siempre con un pasajero presente","ru":"Всегда ездить с пассажиром","tr":"Her zaman bir yolcuyla sürmek","hi":"हमेशा एक यात्री के साथ राइड करना","ar":"القيادة دائمًا مع وجود راكب"}],"e":{"en":"The Motorcycle Operator Manual states the single most important thing you can do to improve your chances of surviving a crash is to wear a securely-fastened, quality helmet.","es":"El Manual del Operador de Motocicletas indica que lo más importante que puedes hacer para mejorar tus probabilidades de sobrevivir a un choque es usar un casco de calidad bien abrochado.","ru":"Руководство мотоциклиста утверждает, что самое важное, что вы можете сделать, чтобы повысить свои шансы выжить в аварии, — это носить надёжно застёгнутый качественный шлем.","tr":"Motosiklet Kullanıcı Kılavuzu, bir kazada hayatta kalma şansınızı artırmak için yapabileceğiniz en önemli tek şeyin sağlam takılmış, kaliteli bir kask takmak olduğunu belirtir.","hi":"Motorcycle Operator Manual बताता है कि दुर्घटना से बचने की अपनी संभावना बेहतर करने के लिए आप जो एकमात्र सबसे महत्वपूर्ण काम कर सकते हैं, वह है एक सुरक्षित रूप से बँधा हुआ, गुणवत्तापूर्ण हेलमेट पहनना।","ar":"ينص دليل مشغّل الدراجة النارية على أن أهم شيء واحد يمكنك فعله لتحسين فرصك في النجاة من حادث تصادم هو ارتداء خوذة عالية الجودة ومثبّتة بإحكام."}},{"cat":"gear","a":3,"q":{"en":"At the speeds at which most crashes occur (under 30 mph), what does the Motorcycle Operator Manual say a helmet can do?","es":"A las velocidades a las que ocurren la mayoría de los choques (por debajo de 30 mph), ¿qué dice el Manual del Operador de Motocicletas que puede hacer un casco?","ru":"На скоростях, при которых происходит большинство аварий (менее 30 миль/ч), что, по словам Руководства мотоциклиста, может сделать шлем?","tr":"Çoğu kazanın meydana geldiği hızlarda (30 mil/sa altında), Motosiklet Kullanıcı Kılavuzu kaskın ne yapabileceğini söyler?","hi":"जिन गति पर अधिकांश दुर्घटनाएं होती हैं (30 mph से कम), उन पर Motorcycle Operator Manual के अनुसार हेलमेट क्या कर सकता है?","ar":"عند السرعات التي تقع فيها معظم الحوادث (أقل من 30 ميلاً في الساعة)، ماذا يقول دليل مشغّل الدراجة النارية إن الخوذة تستطيع فعله؟"},"o":[{"en":"Reduce head injuries only on trips over five miles","es":"Reducir las lesiones en la cabeza solo en recorridos de más de cinco millas","ru":"Снизить травмы головы только в поездках свыше пяти миль","tr":"Baş yaralanmalarını yalnızca beş milden uzun yolculuklarda azaltır","hi":"केवल पाँच मील से अधिक की यात्राओं पर सिर की चोटें कम करता है","ar":"تقليل إصابات الرأس فقط في الرحلات التي تزيد عن خمسة أميال"},{"en":"Protect the neck but not the head","es":"Proteger el cuello pero no la cabeza","ru":"Защитить шею, но не голову","tr":"Başı değil ama boynu korur","hi":"गर्दन की रक्षा करता है लेकिन सिर की नहीं","ar":"حماية الرقبة دون الرأس"},{"en":"Eliminate the chance of any head injury entirely","es":"Eliminar por completo la posibilidad de cualquier lesión en la cabeza","ru":"Полностью исключить любую вероятность травмы головы","tr":"Herhangi bir baş yaralanması olasılığını tamamen ortadan kaldırır","hi":"किसी भी सिर की चोट की संभावना को पूरी तरह समाप्त कर देता है","ar":"القضاء التام على احتمال أي إصابة في الرأس"},{"en":"Cut both the number and severity of head injuries by half","es":"Reducir a la mitad tanto el número como la gravedad de las lesiones en la cabeza","ru":"Сократить как количество, так и тяжесть травм головы вдвое","tr":"Baş yaralanmalarının hem sayısını hem şiddetini yarı yarıya azaltır","hi":"सिर की चोटों की संख्या और गंभीरता दोनों को आधा कर देता है","ar":"خفض عدد إصابات الرأس وشدّتها إلى النصف"}],"e":{"en":"The Motorcycle Operator Manual notes most riders are going under 30 mph when a crash occurs, and at these speeds helmets can cut both the number and severity of head injuries by half.","es":"El Manual del Operador de Motocicletas señala que la mayoría de los conductores van a menos de 30 mph cuando ocurre un choque, y a estas velocidades los cascos pueden reducir a la mitad tanto el número como la gravedad de las lesiones en la cabeza.","ru":"Руководство мотоциклиста отмечает, что большинство мотоциклистов движутся со скоростью менее 30 миль/ч в момент аварии, и на этих скоростях шлемы могут сократить как количество, так и тяжесть травм головы вдвое.","tr":"Motosiklet Kullanıcı Kılavuzu, çoğu sürücünün bir kaza olduğunda 30 mil/sa altında gittiğini ve bu hızlarda kaskların baş yaralanmalarının hem sayısını hem şiddetini yarı yarıya azaltabileceğini belirtir.","hi":"Motorcycle Operator Manual नोट करता है कि जब दुर्घटना होती है तो अधिकांश राइडर 30 mph से कम पर जा रहे होते हैं, और इन गति पर हेलमेट सिर की चोटों की संख्या और गंभीरता दोनों को आधा कर सकते हैं।","ar":"يشير دليل مشغّل الدراجة النارية إلى أن معظم السائقين يسيرون بأقل من 30 ميلاً في الساعة عند وقوع حادث، وعند هذه السرعات تستطيع الخوذات خفض عدد إصابات الرأس وشدّتها إلى النصف."}},{"cat":"gear","a":2,"q":{"en":"Compared with riders not wearing a helmet, how much more likely are helmeted riders to survive head injuries, per the Motorcycle Operator Manual?","es":"En comparación con los conductores que no usan casco, ¿cuánto más probable es que los conductores con casco sobrevivan a lesiones en la cabeza, según el Manual del Operador de Motocicletas?","ru":"По сравнению с мотоциклистами без шлема, насколько вероятнее мотоциклисты в шлеме выживают при травмах головы, согласно Руководству мотоциклиста?","tr":"Motosiklet Kullanıcı Kılavuzu'na göre, kask takmayan sürücülere kıyasla, kask takan sürücülerin baş yaralanmalarından kurtulma olasılığı ne kadar daha fazladır?","hi":"Motorcycle Operator Manual के अनुसार, हेलमेट न पहनने वाले राइडर्स की तुलना में, हेलमेट पहनने वाले राइडर्स के सिर की चोटों से बचने की संभावना कितनी अधिक होती है?","ar":"مقارنةً بالسائقين الذين لا يرتدون خوذة، كم مرة يكون السائقون الذين يرتدون خوذة أكثر احتمالًا للنجاة من إصابات الرأس، بحسب دليل مشغّل الدراجة النارية؟"},"o":[{"en":"About 25 percent more likely","es":"Aproximadamente un 25 por ciento más probable","ru":"Примерно на 25 процентов вероятнее","tr":"Yaklaşık yüzde 25 daha fazla","hi":"लगभग 25 प्रतिशत अधिक","ar":"أكثر احتمالًا بنحو 25 بالمئة"},{"en":"Twice as likely","es":"El doble de probable","ru":"Вдвое вероятнее","tr":"İki kat daha fazla","hi":"दोगुनी","ar":"ضعف الاحتمال"},{"en":"Three times more likely","es":"Tres veces más probable","ru":"В три раза вероятнее","tr":"Üç kat daha fazla","hi":"तीन गुना अधिक","ar":"ثلاث مرات أكثر احتمالًا"},{"en":"Five times more likely","es":"Cinco veces más probable","ru":"В пять раз вероятнее","tr":"Beş kat daha fazla","hi":"पाँच गुना अधिक","ar":"خمس مرات أكثر احتمالًا"}],"e":{"en":"The Motorcycle Operator Manual states that no matter the speed, helmeted riders are three times more likely to survive head injuries than those not wearing helmets at the time of the crash.","es":"El Manual del Operador de Motocicletas indica que, sin importar la velocidad, los conductores con casco tienen tres veces más probabilidades de sobrevivir a lesiones en la cabeza que quienes no usaban casco al momento del choque.","ru":"Руководство мотоциклиста утверждает, что независимо от скорости мотоциклисты в шлеме в три раза вероятнее выживают при травмах головы, чем те, кто был без шлема в момент аварии.","tr":"Motosiklet Kullanıcı Kılavuzu, hız ne olursa olsun, kask takan sürücülerin baş yaralanmalarından kurtulma olasılığının, kaza anında kask takmayanlara göre üç kat daha fazla olduğunu belirtir.","hi":"Motorcycle Operator Manual बताता है कि गति चाहे जो भी हो, हेलमेट पहनने वाले राइडर्स के सिर की चोटों से बचने की संभावना दुर्घटना के समय हेलमेट न पहनने वालों की तुलना में तीन गुना अधिक होती है।","ar":"ينص دليل مشغّل الدراجة النارية على أنه بغض النظر عن السرعة، يكون السائقون الذين يرتدون خوذة أكثر احتمالًا بثلاث مرات للنجاة من إصابات الرأس مقارنةً بمن لا يرتدون خوذة وقت الحادث."}},{"cat":"gear","a":2,"q":{"en":"What are the two primary types of helmets described in the Motorcycle Operator Manual?","es":"¿Cuáles son los dos tipos principales de cascos descritos en el Manual del Operador de Motocicletas?","ru":"Какие два основных типа шлемов описаны в Руководстве мотоциклиста?","tr":"Motosiklet Kullanıcı Kılavuzu'nda açıklanan iki temel kask türü nedir?","hi":"Motorcycle Operator Manual में वर्णित दो प्रमुख प्रकार के हेलमेट कौन से हैं?","ar":"ما هما النوعان الرئيسيان من الخوذات الموصوفان في دليل مشغّل الدراجة النارية؟"},"o":[{"en":"Open-face and modular only","es":"Solo abierto y modular","ru":"Только открытый и модульный","tr":"Yalnızca açık yüz ve modüler","hi":"केवल ओपन-फेस और मॉड्यूलर","ar":"مفتوحة الوجه وقابلة للطي فقط"},{"en":"Half-shell and novelty","es":"Media cabeza y de imitación","ru":"Полушлем и сувенирный (неполноценный)","tr":"Yarım kafa ve süs kaskı","hi":"हाफ-शेल और नॉवेल्टी","ar":"نصف القشرة والزائفة"},{"en":"Three-quarter and full face","es":"De tres cuartos y de cara completa","ru":"Три четверти и полнолицевой","tr":"Dörtte üç ve tam yüz","hi":"तीन-चौथाई और फुल फेस","ar":"ثلاثة أرباع والوجه الكامل"},{"en":"Touring and racing","es":"De turismo y de carreras","ru":"Туристический и гоночный","tr":"Turing ve yarış","hi":"टूरिंग और रेसिंग","ar":"السياحية والسباق"}],"e":{"en":"The Motorcycle Operator Manual identifies two primary helmet types offering different levels of coverage: three-quarter and full face.","es":"El Manual del Operador de Motocicletas identifica dos tipos principales de cascos que ofrecen distintos niveles de cobertura: de tres cuartos y de cara completa.","ru":"Руководство мотоциклиста выделяет два основных типа шлемов, обеспечивающих разный уровень защиты: три четверти и полнолицевой.","tr":"Motosiklet Kullanıcı Kılavuzu, farklı düzeyde koruma sağlayan iki temel kask türü tanımlar: dörtte üç ve tam yüz.","hi":"Motorcycle Operator Manual दो प्रमुख प्रकार के हेलमेट की पहचान करता है जो अलग-अलग स्तर की कवरेज प्रदान करते हैं: तीन-चौथाई और फुल फेस।","ar":"يحدد دليل مشغّل الدراجة النارية نوعين رئيسيين من الخوذات يوفران مستويات مختلفة من التغطية: ثلاثة أرباع والوجه الكامل."}},{"cat":"gear","a":3,"q":{"en":"To get the most protection from any helmet, the Motorcycle Operator Manual says the helmet should be designed to meet which standard?","es":"Para obtener la mayor protección de cualquier casco, el Manual del Operador de Motocicletas dice que el casco debe estar diseñado para cumplir con cuál norma?","ru":"Чтобы получить наибольшую защиту от любого шлема, Руководство мотоциклиста говорит, что шлем должен быть рассчитан на соответствие какому стандарту?","tr":"Motosiklet Kullanıcı Kılavuzu'na göre, herhangi bir kasktan en fazla korumayı almak için kask hangi standardı karşılayacak şekilde tasarlanmış olmalıdır?","hi":"किसी भी हेलमेट से अधिकतम सुरक्षा पाने के लिए, Motorcycle Operator Manual कहता है कि हेलमेट को किस मानक को पूरा करने के लिए डिज़ाइन किया जाना चाहिए?","ar":"للحصول على أقصى حماية من أي خوذة، يقول دليل مشغّل الدراجة النارية إن الخوذة يجب أن تكون مصممة لتلبية أي معيار؟"},"o":[{"en":"OSHA workplace headgear standards","es":"Las normas de protección para la cabeza en el lugar de trabajo de OSHA","ru":"Стандартам OSHA для рабочих головных уборов","tr":"OSHA işyeri başlık standartları","hi":"OSHA कार्यस्थल हेडगियर मानक","ar":"معايير أغطية الرأس في أماكن العمل من OSHA"},{"en":"EPA emissions standards","es":"Las normas de emisiones de la EPA","ru":"Стандартам EPA по выбросам","tr":"EPA emisyon standartları","hi":"EPA उत्सर्जन मानक","ar":"معايير الانبعاثات من EPA"},{"en":"Federal Aviation Administration standards","es":"Las normas de la Administración Federal de Aviación","ru":"Стандартам Федерального управления гражданской авиации","tr":"Federal Havacılık İdaresi standartları","hi":"Federal Aviation Administration मानक","ar":"معايير الإدارة الفيدرالية للطيران"},{"en":"U.S. Department of Transportation (DOT) and state standards","es":"Las normas del Departamento de Transporte de EE. UU. (DOT) y las normas estatales","ru":"Стандартам Министерства транспорта США (DOT) и стандартам штата","tr":"ABD Ulaştırma Bakanlığı (DOT) ve eyalet standartları","hi":"U.S. Department of Transportation (DOT) और राज्य मानक","ar":"معايير وزارة النقل الأمريكية (DOT) ومعايير الولاية"}],"e":{"en":"The Motorcycle Operator Manual says a helmet should be designed to meet U.S. Department of Transportation (DOT) and state standards; a Snell Memorial Foundation label also assures quality.","es":"El Manual del Operador de Motocicletas dice que un casco debe estar diseñado para cumplir con las normas del Departamento de Transporte de EE. UU. (DOT) y las normas estatales; una etiqueta de la Snell Memorial Foundation también garantiza calidad.","ru":"Руководство мотоциклиста говорит, что шлем должен быть рассчитан на соответствие стандартам Министерства транспорта США (DOT) и стандартам штата; маркировка Snell Memorial Foundation также подтверждает качество.","tr":"Motosiklet Kullanıcı Kılavuzu, bir kaskın ABD Ulaştırma Bakanlığı (DOT) ve eyalet standartlarını karşılayacak şekilde tasarlanmış olması gerektiğini söyler; Snell Memorial Foundation etiketi de kaliteyi güvence altına alır.","hi":"Motorcycle Operator Manual कहता है कि हेलमेट को U.S. Department of Transportation (DOT) और राज्य मानकों को पूरा करने के लिए डिज़ाइन किया जाना चाहिए; Snell Memorial Foundation लेबल भी गुणवत्ता का आश्वासन देता है।","ar":"يقول دليل مشغّل الدراجة النارية إن الخوذة يجب أن تكون مصممة لتلبية معايير وزارة النقل الأمريكية (DOT) ومعايير الولاية؛ كما أن وجود ملصق مؤسسة Snell Memorial يؤكد الجودة."}},{"cat":"gear","a":3,"q":{"en":"Besides meeting DOT standards, which additional label gives assurance of helmet quality according to the Motorcycle Operator Manual?","es":"Además de cumplir con las normas DOT, ¿qué etiqueta adicional ofrece garantía de la calidad del casco según el Manual del Operador de Motocicletas?","ru":"Помимо соответствия стандартам DOT, какая дополнительная маркировка даёт гарантию качества шлема, согласно Руководству мотоциклиста?","tr":"Motosiklet Kullanıcı Kılavuzu'na göre, DOT standartlarını karşılamanın yanı sıra hangi ek etiket kask kalitesi güvencesi verir?","hi":"Motorcycle Operator Manual के अनुसार, DOT मानकों को पूरा करने के अलावा, कौन सा अतिरिक्त लेबल हेलमेट की गुणवत्ता का आश्वासन देता है?","ar":"إلى جانب تلبية معايير DOT، أي ملصق إضافي يمنح ضمانًا لجودة الخوذة وفقًا لدليل مشغّل الدراجة النارية؟"},"o":[{"en":"The American Motorcyclist Association sticker","es":"La calcomanía de la American Motorcyclist Association","ru":"Наклейка Американской ассоциации мотоциклистов","tr":"American Motorcyclist Association çıkartması","hi":"American Motorcyclist Association स्टिकर","ar":"ملصق جمعية راكبي الدراجات النارية الأمريكية"},{"en":"The Underwriters Laboratories label","es":"La etiqueta de Underwriters Laboratories","ru":"Маркировка Underwriters Laboratories","tr":"Underwriters Laboratories etiketi","hi":"Underwriters Laboratories लेबल","ar":"ملصق Underwriters Laboratories"},{"en":"The Better Business Bureau seal","es":"El sello del Better Business Bureau","ru":"Печать Better Business Bureau","tr":"Better Business Bureau mührü","hi":"Better Business Bureau सील","ar":"ختم مكتب تحسين الأعمال"},{"en":"The Snell Memorial Foundation label","es":"La etiqueta de la Snell Memorial Foundation","ru":"Маркировка Snell Memorial Foundation","tr":"Snell Memorial Foundation etiketi","hi":"Snell Memorial Foundation लेबल","ar":"ملصق مؤسسة Snell Memorial"}],"e":{"en":"The Motorcycle Operator Manual states that helmets with a label from the Snell Memorial Foundation also give you an assurance of quality, in addition to meeting DOT standards.","es":"El Manual del Operador de Motocicletas indica que los cascos con una etiqueta de la Snell Memorial Foundation también te dan una garantía de calidad, además de cumplir con las normas DOT.","ru":"Руководство мотоциклиста утверждает, что шлемы с маркировкой Snell Memorial Foundation также дают гарантию качества, в дополнение к соответствию стандартам DOT.","tr":"Motosiklet Kullanıcı Kılavuzu, DOT standartlarını karşılamanın yanı sıra Snell Memorial Foundation etiketli kaskların da size kalite güvencesi verdiğini belirtir.","hi":"Motorcycle Operator Manual बताता है कि Snell Memorial Foundation के लेबल वाले हेलमेट DOT मानकों को पूरा करने के अलावा गुणवत्ता का आश्वासन भी देते हैं।","ar":"ينص دليل مشغّل الدراجة النارية على أن الخوذات التي تحمل ملصقًا من مؤسسة Snell Memorial تمنحك أيضًا ضمانًا للجودة، إضافةً إلى تلبية معايير DOT."}},{"cat":"gear","a":2,"q":{"en":"Most motorcycle crashes occur in broad daylight. What does the Motorcycle Operator Manual recommend to increase your chances of being seen?","es":"La mayoría de los choques de motocicleta ocurren a plena luz del día. ¿Qué recomienda el Manual del Operador de Motocicletas para aumentar tus probabilidades de ser visto?","ru":"Большинство аварий на мотоцикле происходит средь бела дня. Что Руководство мотоциклиста рекомендует, чтобы повысить шансы быть замеченным?","tr":"Çoğu motosiklet kazası güpegündüz meydana gelir. Görülme şansınızı artırmak için Motosiklet Kullanıcı Kılavuzu neyi önerir?","hi":"अधिकांश मोटरसाइकिल दुर्घटनाएं दिन के उजाले में होती हैं। देखे जाने की अपनी संभावना बढ़ाने के लिए Motorcycle Operator Manual क्या सलाह देता है?","ar":"تقع معظم حوادث الدراجات النارية في وضح النهار. بماذا يوصي دليل مشغّل الدراجة النارية لزيادة فرص رؤيتك؟"},"o":[{"en":"Rely on your headlight alone for visibility","es":"Confiar únicamente en tu faro para la visibilidad","ru":"Полагаться только на свою фару для видимости","tr":"Görünürlük için yalnızca farınıza güvenin","hi":"दृश्यता के लिए केवल अपनी हेडलाइट पर निर्भर रहें","ar":"الاعتماد على المصباح الأمامي وحده للرؤية"},{"en":"Wear neutral gray so you don't distract drivers","es":"Usar gris neutro para no distraer a los conductores","ru":"Носить нейтральный серый цвет, чтобы не отвлекать водителей","tr":"Sürücülerin dikkatini dağıtmamak için nötr gri giyin","hi":"न्यूट्रल ग्रे पहनें ताकि आप ड्राइवरों का ध्यान न भटकाएं","ar":"ارتداء الرمادي المحايد حتى لا تشتت السائقين"},{"en":"Wear bright-colored clothing such as orange, red, yellow or green","es":"Usar ropa de colores brillantes, como naranja, rojo, amarillo o verde","ru":"Носить одежду ярких цветов, например оранжевого, красного, жёлтого или зелёного","tr":"Turuncu, kırmızı, sarı ya da yeşil gibi parlak renkli kıyafet giyin","hi":"नारंगी, लाल, पीले या हरे जैसे चमकीले रंग के कपड़े पहनें","ar":"ارتداء ملابس زاهية اللون مثل البرتقالي أو الأحمر أو الأصفر أو الأخضر"},{"en":"Wear all-black gear to create a sharp silhouette","es":"Usar equipo todo negro para crear una silueta marcada","ru":"Носить полностью чёрное снаряжение для создания чёткого силуэта","tr":"Keskin bir silüet oluşturmak için tamamen siyah giyin","hi":"एक तीखी आकृति बनाने के लिए पूरी तरह काले गियर पहनें","ar":"ارتداء ملابس سوداء بالكامل لخلق ظل حاد"}],"e":{"en":"The Motorcycle Operator Manual states most crashes occur in broad daylight, so wear bright-colored clothing (orange, red, yellow or green) to increase your chances of being seen.","es":"El Manual del Operador de Motocicletas indica que la mayoría de los choques ocurren a plena luz del día, así que usa ropa de colores brillantes (naranja, rojo, amarillo o verde) para aumentar tus probabilidades de ser visto.","ru":"Руководство мотоциклиста утверждает, что большинство аварий происходит средь бела дня, поэтому носите одежду ярких цветов (оранжевого, красного, жёлтого или зелёного), чтобы повысить шансы быть замеченным.","tr":"Motosiklet Kullanıcı Kılavuzu, çoğu kazanın güpegündüz meydana geldiğini, bu yüzden görülme şansınızı artırmak için parlak renkli kıyafet (turuncu, kırmızı, sarı ya da yeşil) giymeniz gerektiğini belirtir.","hi":"Motorcycle Operator Manual बताता है कि अधिकांश दुर्घटनाएं दिन के उजाले में होती हैं, इसलिए देखे जाने की अपनी संभावना बढ़ाने के लिए चमकीले रंग के कपड़े (नारंगी, लाल, पीले या हरे) पहनें।","ar":"ينص دليل مشغّل الدراجة النارية على أن معظم الحوادث تقع في وضح النهار، لذا ارتدِ ملابس زاهية اللون (برتقالي، أحمر، أصفر أو أخضر) لزيادة فرص رؤيتك."}},{"cat":"gear","a":3,"q":{"en":"Why does the Motorcycle Operator Manual stress keeping your helmet securely fastened while riding?","es":"¿Por qué el Manual del Operador de Motocicletas insiste en mantener el casco bien abrochado mientras conduces?","ru":"Почему Руководство мотоциклиста подчёркивает необходимость держать шлем надёжно застёгнутым во время езды?","tr":"Motosiklet Kullanıcı Kılavuzu, sürüş sırasında kaskınızı sağlam takılı tutmayı neden vurgular?","hi":"Motorcycle Operator Manual राइडिंग के दौरान अपने हेलमेट को सुरक्षित रूप से बँधा रखने पर ज़ोर क्यों देता है?","ar":"لماذا يشدد دليل مشغّل الدراجة النارية على إبقاء خوذتك مثبّتة بإحكام أثناء القيادة؟"},"o":[{"en":"Fastening straps are only legally required at night","es":"Las correas de sujeción solo son obligatorias por ley de noche","ru":"Застёгивание ремня обязательно по закону только ночью","tr":"Kayışı bağlamak yalnızca gece yasal olarak zorunludur","hi":"फास्टनिंग स्ट्रैप केवल रात में कानूनी रूप से आवश्यक होते हैं","ar":"لأن أحزمة التثبيت مطلوبة قانونيًا ليلًا فقط"},{"en":"A loose strap helps the helmet absorb more impact","es":"Una correa floja ayuda al casco a absorber más impacto","ru":"Ослабленный ремень помогает шлему лучше поглощать удар","tr":"Gevşek bir kayış, kaskın daha fazla darbe emmesine yardımcı olur","hi":"एक ढीला स्ट्रैप हेलमेट को अधिक प्रभाव सोखने में मदद करता है","ar":"لأن الحزام المرتخي يساعد الخوذة على امتصاص صدمة أكبر"},{"en":"An unfastened helmet improves airflow and comfort","es":"Un casco sin abrochar mejora el flujo de aire y la comodidad","ru":"Незастёгнутый шлем улучшает приток воздуха и комфорт","tr":"Bağlanmamış bir kask hava akışını ve konforu artırır","hi":"एक बिना बँधा हेलमेट हवा के बहाव और आराम को बेहतर बनाता है","ar":"لأن الخوذة غير المثبّتة تحسّن تدفق الهواء والراحة"},{"en":"An unfastened helmet is likely to fly off in a crash before it can protect you","es":"Un casco sin abrochar probablemente saldrá volando en un choque antes de poder protegerte","ru":"Незастёгнутый шлем, скорее всего, слетит при аварии прежде, чем сможет защитить вас","tr":"Bağlanmamış bir kaskın, sizi koruyamadan kazada başınızdan fırlama olasılığı yüksektir","hi":"एक बिना बँधा हेलमेट दुर्घटना में आपकी सुरक्षा करने से पहले ही उड़ जाने की संभावना रखता है","ar":"لأن الخوذة غير المثبّتة من المرجح أن تطير في حادث قبل أن تتمكن من حمايتك"}],"e":{"en":"The Motorcycle Operator Manual warns to keep the helmet securely fastened; otherwise in a crash it is likely to fly off your head before it gets a chance to protect you.","es":"El Manual del Operador de Motocicletas advierte que mantengas el casco bien abrochado; de lo contrario, en un choque probablemente saldrá volando de tu cabeza antes de tener la oportunidad de protegerte.","ru":"Руководство мотоциклиста предупреждает: держите шлем надёжно застёгнутым; иначе при аварии он, скорее всего, слетит с головы прежде, чем получит шанс защитить вас.","tr":"Motosiklet Kullanıcı Kılavuzu, kaskı sağlam takılı tutmanız konusunda uyarır; aksi halde bir kazada sizi koruma şansı bulamadan başınızdan fırlama olasılığı yüksektir.","hi":"Motorcycle Operator Manual चेतावनी देता है कि हेलमेट को सुरक्षित रूप से बँधा रखें; अन्यथा दुर्घटना में यह आपकी सुरक्षा करने का मौका पाने से पहले ही आपके सिर से उड़ जाने की संभावना रखता है।","ar":"يحذّر دليل مشغّل الدراجة النارية من ضرورة إبقاء الخوذة مثبّتة بإحكام؛ وإلا فمن المرجح في حادث أن تطير عن رأسك قبل أن تحظى بفرصة لحمايتك."}},{"cat":"gear","a":0,"q":{"en":"What is the key advantage of a face shield over goggles, according to the Motorcycle Operator Manual?","es":"¿Cuál es la ventaja clave de una visera facial sobre las gafas protectoras, según el Manual del Operador de Motocicletas?","ru":"В чём ключевое преимущество защитного щитка для лица перед очками, согласно Руководству мотоциклиста?","tr":"Motosiklet Kullanıcı Kılavuzu'na göre, yüz siperinin gözlüğe göre temel avantajı nedir?","hi":"Motorcycle Operator Manual के अनुसार, गॉगल्स की तुलना में फेस शील्ड का प्रमुख लाभ क्या है?","ar":"ما هي الميزة الرئيسية لواقي الوجه على النظارات الواقية، وفقًا لدليل مشغّل الدراجة النارية؟"},"o":[{"en":"A face shield can help protect your whole face, while goggles protect only the eyes","es":"Una visera facial puede ayudar a proteger toda tu cara, mientras que las gafas protectoras solo protegen los ojos","ru":"Защитный щиток может помочь защитить всё лицо, тогда как очки защищают только глаза","tr":"Yüz siperi tüm yüzünüzü korumaya yardımcı olabilirken, gözlük yalnızca gözleri korur","hi":"एक फेस शील्ड आपके पूरे चेहरे की रक्षा में मदद कर सकती है, जबकि गॉगल्स केवल आँखों की रक्षा करते हैं","ar":"يمكن لواقي الوجه أن يساعد في حماية وجهك بالكامل، بينما تحمي النظارات الواقية العينين فقط"},{"en":"A face shield reduces engine noise more than goggles","es":"Una visera facial reduce el ruido del motor más que las gafas protectoras","ru":"Защитный щиток снижает шум двигателя лучше, чем очки","tr":"Yüz siperi motor gürültüsünü gözlükten daha fazla azaltır","hi":"एक फेस शील्ड गॉगल्स की तुलना में इंजन की आवाज़ अधिक कम करती है","ar":"يقلل واقي الوجه ضوضاء المحرك أكثر من النظارات الواقية"},{"en":"Goggles protect the whole face better than a shield","es":"Las gafas protectoras protegen toda la cara mejor que una visera","ru":"Очки защищают всё лицо лучше, чем щиток","tr":"Gözlük tüm yüzü siperden daha iyi korur","hi":"गॉगल्स शील्ड की तुलना में पूरे चेहरे की बेहतर रक्षा करते हैं","ar":"تحمي النظارات الواقية الوجه بالكامل أفضل من الواقي"},{"en":"A face shield is the only protection that is legal at night","es":"Una visera facial es la única protección que es legal de noche","ru":"Защитный щиток — единственная защита, разрешённая ночью","tr":"Yüz siperi gece yasal olan tek korumadır","hi":"फेस शील्ड ही एकमात्र सुरक्षा है जो रात में कानूनी है","ar":"واقي الوجه هو الحماية الوحيدة القانونية ليلًا"}],"e":{"en":"The Motorcycle Operator Manual states a plastic impact-resistant face shield can help protect your whole face, while goggles protect your eyes but won't protect the rest of your face like a shield does.","es":"El Manual del Operador de Motocicletas indica que una visera facial de plástico resistente a impactos puede ayudar a proteger toda tu cara, mientras que las gafas protectoras protegen los ojos pero no protegen el resto de la cara como lo hace una visera.","ru":"Руководство мотоциклиста утверждает, что ударопрочный пластиковый защитный щиток для лица может помочь защитить всё лицо, тогда как очки защищают глаза, но не защищают остальную часть лица так, как щиток.","tr":"Motosiklet Kullanıcı Kılavuzu, darbeye dayanıklı plastik bir yüz siperinin tüm yüzünüzü korumaya yardımcı olabileceğini, gözlüğün ise gözlerinizi koruduğunu ancak yüzünüzün geri kalanını bir siper gibi korumayacağını belirtir.","hi":"Motorcycle Operator Manual बताता है कि एक प्लास्टिक इम्पैक्ट-रेज़िस्टेंट फेस शील्ड आपके पूरे चेहरे की रक्षा में मदद कर सकती है, जबकि गॉगल्स आपकी आँखों की रक्षा करते हैं पर बाकी चेहरे की शील्ड जैसी रक्षा नहीं करते।","ar":"ينص دليل مشغّل الدراجة النارية على أن واقي الوجه البلاستيكي المقاوم للصدمات يمكن أن يساعد في حماية وجهك بالكامل، بينما تحمي النظارات الواقية عينيك لكنها لا تحمي بقية وجهك كما يفعل الواقي."}},{"cat":"gear","a":2,"q":{"en":"According to the Motorcycle Operator Manual, why is a windshield NOT a substitute for a face shield or goggles?","es":"Según el Manual del Operador de Motocicletas, ¿por qué un parabrisas NO sustituye a una visera facial o gafas protectoras?","ru":"Согласно Руководству мотоциклиста, почему ветровое стекло НЕ является заменой защитному щитку для лица или очкам?","tr":"Motosiklet Kullanıcı Kılavuzu'na göre, ön cam neden yüz siperi ya da gözlüğün yerini tutmaz?","hi":"Motorcycle Operator Manual के अनुसार, विंडशील्ड फेस शील्ड या गॉगल्स का विकल्प क्यों नहीं है?","ar":"وفقًا لدليل مشغّل الدراجة النارية، لماذا لا يُعد الحاجب الأمامي بديلًا عن واقي الوجه أو النظارات الواقية؟"},"o":[{"en":"Windshields fog up faster than goggles","es":"Los parabrisas se empañan más rápido que las gafas protectoras","ru":"Ветровые стёкла запотевают быстрее, чем очки","tr":"Ön camlar gözlükten daha hızlı buğulanır","hi":"विंडशील्ड गॉगल्स की तुलना में तेज़ी से धुंधली हो जाती हैं","ar":"تتضبب الحواجب الأمامية أسرع من النظارات الواقية"},{"en":"Windshields are illegal in most states","es":"Los parabrisas son ilegales en la mayoría de los estados","ru":"Ветровые стёкла запрещены в большинстве штатов","tr":"Ön camlar çoğu eyalette yasa dışıdır","hi":"अधिकांश राज्यों में विंडशील्ड अवैध हैं","ar":"الحواجب الأمامية غير قانونية في معظم الولايات"},{"en":"Most windshields will not protect your eyes from the wind","es":"La mayoría de los parabrisas no protegen tus ojos del viento","ru":"Большинство ветровых стёкол не защитят ваши глаза от ветра","tr":"Çoğu ön cam gözlerinizi rüzgardan korumaz","hi":"अधिकांश विंडशील्ड आपकी आँखों को हवा से नहीं बचाएंगी","ar":"معظم الحواجب الأمامية لن تحمي عينيك من الرياح"},{"en":"Windshields block too much of the rider's forward view","es":"Los parabrisas bloquean demasiada visión frontal del conductor","ru":"Ветровые стёкла слишком сильно перекрывают обзор мотоциклиста вперёд","tr":"Ön camlar sürücünün önündeki görüşün çok fazlasını engeller","hi":"विंडशील्ड राइडर के आगे के दृश्य का बहुत अधिक हिस्सा रोक देती हैं","ar":"تحجب الحواجب الأمامية جزءًا كبيرًا جدًا من رؤية السائق الأمامية"}],"e":{"en":"The Motorcycle Operator Manual states a windshield is not a substitute for a face shield or goggles because most windshields will not protect your eyes from the wind.","es":"El Manual del Operador de Motocicletas indica que un parabrisas no sustituye a una visera facial o gafas protectoras porque la mayoría de los parabrisas no protegen tus ojos del viento.","ru":"Руководство мотоциклиста утверждает, что ветровое стекло не является заменой защитному щитку для лица или очкам, потому что большинство ветровых стёкол не защитят ваши глаза от ветра.","tr":"Motosiklet Kullanıcı Kılavuzu, çoğu ön camın gözlerinizi rüzgardan korumayacağı için ön camın yüz siperi ya da gözlüğün yerini tutmadığını belirtir.","hi":"Motorcycle Operator Manual बताता है कि विंडशील्ड फेस शील्ड या गॉगल्स का विकल्प नहीं है क्योंकि अधिकांश विंडशील्ड आपकी आँखों को हवा से नहीं बचाएंगी।","ar":"ينص دليل مشغّل الدراجة النارية على أن الحاجب الأمامي ليس بديلًا عن واقي الوجه أو النظارات الواقية لأن معظم الحواجب الأمامية لن تحمي عينيك من الرياح."}},{"cat":"gear","a":0,"q":{"en":"What does the Motorcycle Operator Manual say about using ordinary eyeglasses or sunglasses as eye protection?","es":"¿Qué dice el Manual del Operador de Motocicletas sobre usar anteojos comunes o gafas de sol como protección ocular?","ru":"Что Руководство мотоциклиста говорит об использовании обычных очков для зрения или солнцезащитных очков в качестве защиты глаз?","tr":"Motosiklet Kullanıcı Kılavuzu, sıradan numaralı gözlük ya da güneş gözlüğünü göz koruması olarak kullanmak hakkında ne der?","hi":"Motorcycle Operator Manual आँखों की सुरक्षा के रूप में साधारण चश्मे या धूप के चश्मे के उपयोग के बारे में क्या कहता है?","ar":"ماذا يقول دليل مشغّل الدراجة النارية عن استخدام النظارات الطبية العادية أو النظارات الشمسية كحماية للعين؟"},"o":[{"en":"They won't keep your eyes from watering and might blow off when you turn your head","es":"No evitan que tus ojos lagrimeen y podrían salir volando cuando giras la cabeza","ru":"Они не защитят глаза от слёзотечения и могут слететь, когда вы поворачиваете голову","tr":"Gözlerinizin sulanmasını önlemezler ve başınızı çevirdiğinizde uçabilirler","hi":"वे आपकी आँखों को पानी आने से नहीं बचाएंगे और सिर घुमाने पर उड़ सकते हैं","ar":"لن تمنع عينيك من الدمع وقد تطير عندما تدير رأسك"},{"en":"They fully protect against wind, dust, and insects","es":"Protegen por completo contra el viento, el polvo y los insectos","ru":"Они полностью защищают от ветра, пыли и насекомых","tr":"Rüzgara, toza ve böceklere karşı tam koruma sağlarlar","hi":"वे हवा, धूल और कीड़ों से पूरी तरह रक्षा करते हैं","ar":"تحمي تمامًا من الرياح والغبار والحشرات"},{"en":"They are acceptable only if they are prescription lenses","es":"Son aceptables solo si son lentes recetados","ru":"Они допустимы только если это очки с диоптриями","tr":"Yalnızca numaralı camlarsa kabul edilebilirler","hi":"वे केवल तभी स्वीकार्य हैं जब वे प्रिस्क्रिप्शन लेंस हों","ar":"مقبولة فقط إذا كانت عدسات طبية"},{"en":"They are an approved substitute for goggles at low speeds","es":"Son un sustituto aprobado de las gafas protectoras a baja velocidad","ru":"Они являются одобренной заменой защитным очкам на малой скорости","tr":"Düşük hızlarda gözlük yerine onaylı bir alternatiftirler","hi":"वे कम गति पर गॉगल्स का अनुमोदित विकल्प हैं","ar":"بديل معتمد عن النظارات الواقية عند السرعات المنخفضة"}],"e":{"en":"The Motorcycle Operator Manual states eyeglasses or sunglasses are not adequate: they won't keep your eyes from watering and might blow off when you turn your head while riding.","es":"El Manual del Operador de Motocicletas indica que los anteojos o gafas de sol no son adecuados: no evitan que tus ojos lagrimeen y podrían salir volando cuando giras la cabeza mientras conduces.","ru":"Руководство мотоциклиста утверждает, что очки для зрения или солнцезащитные очки недостаточны: они не защитят глаза от слёзотечения и могут слететь, когда вы поворачиваете голову во время езды.","tr":"Motosiklet Kullanıcı Kılavuzu, numaralı gözlük ya da güneş gözlüğünün yeterli olmadığını belirtir: gözlerinizin sulanmasını önlemezler ve sürerken başınızı çevirdiğinizde uçabilirler.","hi":"Motorcycle Operator Manual बताता है कि चश्मे या धूप के चश्मे पर्याप्त नहीं हैं: वे आपकी आँखों को पानी आने से नहीं बचाएंगे और राइडिंग के दौरान सिर घुमाने पर उड़ सकते हैं।","ar":"ينص دليل مشغّل الدراجة النارية على أن النظارات الطبية أو الشمسية غير كافية: فهي لن تمنع عينيك من الدمع وقد تطير عندما تدير رأسك أثناء القيادة."}},{"cat":"gear","a":0,"q":{"en":"Which of the following is a requirement the Motorcycle Operator Manual lists for effective eye or face-shield protection?","es":"¿Cuál de los siguientes es un requisito que enumera el Manual del Operador de Motocicletas para una protección ocular o de visera facial eficaz?","ru":"Какое из перечисленного является требованием, которое Руководство мотоциклиста предъявляет к эффективной защите глаз или защитному щитку для лица?","tr":"Aşağıdakilerden hangisi, Motosiklet Kullanıcı Kılavuzu'nun etkili göz ya da yüz siperi koruması için sıraladığı bir gerekliliktir?","hi":"निम्नलिखित में से कौन सी एक आवश्यकता है जिसे Motorcycle Operator Manual प्रभावी आँख या फेस-शील्ड सुरक्षा के लिए सूचीबद्ध करता है?","ar":"أي مما يلي يُعد متطلبًا يُدرجه دليل مشغّل الدراجة النارية لحماية فعّالة للعين أو واقي الوجه؟"},"o":[{"en":"It must be free of scratches and resistant to penetration","es":"Debe estar libre de rayones y ser resistente a la penetración","ru":"Она должна быть без царапин и устойчивой к проколу","tr":"Çiziksiz ve delinmeye dayanıklı olmalı","hi":"यह खरोंच से मुक्त और प्रवेश-प्रतिरोधी होनी चाहिए","ar":"يجب أن يكون خاليًا من الخدوش ومقاومًا للاختراق"},{"en":"It must be smaller than the rider's eyeglasses","es":"Debe ser más pequeña que los anteojos del conductor","ru":"Она должна быть меньше очков мотоциклиста","tr":"Sürücünün gözlüğünden daha küçük olmalı","hi":"यह राइडर के चश्मे से छोटी होनी चाहिए","ar":"يجب أن يكون أصغر من نظارات السائق الطبية"},{"en":"It must be heavily tinted in all conditions","es":"Debe estar muy oscurecida en todas las condiciones","ru":"Она должна быть сильно затемнённой во всех условиях","tr":"Her koşulda yoğun renkli (füme) olmalı","hi":"यह सभी परिस्थितियों में गहरे रंग की टिंटेड होनी चाहिए","ar":"يجب أن يكون داكن التظليل في جميع الظروف"},{"en":"It must completely seal off all airflow","es":"Debe sellar por completo todo el flujo de aire","ru":"Она должна полностью перекрывать любой приток воздуха","tr":"Tüm hava akışını tamamen kesmeli","hi":"यह सभी हवा के बहाव को पूरी तरह सील कर देनी चाहिए","ar":"يجب أن يغلق كل تدفق الهواء تمامًا"}],"e":{"en":"The Motorcycle Operator Manual says effective eye or face-shield protection must be free of scratches, resistant to penetration, give a clear view to either side, fasten securely, and permit air to pass through to reduce fogging.","es":"El Manual del Operador de Motocicletas dice que una protección ocular o de visera facial eficaz debe estar libre de rayones, ser resistente a la penetración, dar una vista clara hacia ambos lados, sujetarse de forma segura y permitir el paso del aire para reducir el empañamiento.","ru":"Руководство мотоциклиста говорит, что эффективная защита глаз или защитный щиток для лица должны быть без царапин, устойчивы к проколу, давать чёткий обзор в обе стороны, надёжно крепиться и пропускать воздух, чтобы уменьшить запотевание.","tr":"Motosiklet Kullanıcı Kılavuzu, etkili göz ya da yüz siperi korumasının çiziksiz, delinmeye dayanıklı olması, her iki yana net görüş vermesi, sağlam takılması ve buğulanmayı azaltmak için hava geçirmesi gerektiğini söyler.","hi":"Motorcycle Operator Manual कहता है कि प्रभावी आँख या फेस-शील्ड सुरक्षा खरोंच से मुक्त, प्रवेश-प्रतिरोधी होनी चाहिए, दोनों ओर स्पष्ट दृश्य दे, सुरक्षित रूप से बँधे, और धुंध कम करने के लिए हवा को गुज़रने दे।","ar":"يقول دليل مشغّل الدراجة النارية إن حماية العين أو واقي الوجه الفعّالة يجب أن تكون خالية من الخدوش، مقاومة للاختراق، تمنح رؤية واضحة إلى الجانبين، تُثبَّت بإحكام، وتسمح بمرور الهواء لتقليل التضبب."}},{"cat":"gear","a":3,"q":{"en":"What does the Motorcycle Operator Manual advise about wearing tinted eye protection?","es":"¿Qué aconseja el Manual del Operador de Motocicletas sobre el uso de protección ocular oscurecida?","ru":"Что Руководство мотоциклиста советует насчёт ношения затемнённой защиты глаз?","tr":"Motosiklet Kullanıcı Kılavuzu, renkli (füme) göz koruması takmak hakkında ne tavsiye eder?","hi":"Motorcycle Operator Manual टिंटेड आँख सुरक्षा पहनने के बारे में क्या सलाह देता है?","ar":"بماذا ينصح دليل مشغّل الدراجة النارية بشأن ارتداء حماية العين المظللة؟"},"o":[{"en":"It is required by DOT for daytime riding","es":"Es obligatoria por la DOT para conducir de día","ru":"Она требуется DOT для езды днём","tr":"Gündüz sürüşü için DOT tarafından zorunludur","hi":"दिन के समय राइडिंग के लिए DOT द्वारा यह आवश्यक है","ar":"إنها مطلوبة من DOT للقيادة النهارية"},{"en":"It must permit no air to pass through","es":"No debe permitir el paso de aire","ru":"Она не должна пропускать воздух","tr":"Hiç hava geçirmemelidir","hi":"इसमें से कोई हवा नहीं गुज़रनी चाहिए","ar":"يجب ألا تسمح بمرور أي هواء"},{"en":"It should be worn at all times for eye safety","es":"Debe usarse en todo momento por seguridad ocular","ru":"Её следует носить постоянно для безопасности глаз","tr":"Göz güvenliği için her zaman takılmalıdır","hi":"आँखों की सुरक्षा के लिए इसे हर समय पहना जाना चाहिए","ar":"يجب ارتداؤها في جميع الأوقات لسلامة العين"},{"en":"It should not be worn when little light is available","es":"No debe usarse cuando hay poca luz disponible","ru":"Её не следует носить при недостатке света","tr":"Az ışık olduğunda takılmamalıdır","hi":"जब बहुत कम रोशनी उपलब्ध हो तब इसे नहीं पहना जाना चाहिए","ar":"يجب عدم ارتدائها عند توفر القليل من الضوء"}],"e":{"en":"The Motorcycle Operator Manual advises that tinted eye protection should not be worn when little light is available, such as at night or in low-light conditions.","es":"El Manual del Operador de Motocicletas aconseja que la protección ocular oscurecida no debe usarse cuando hay poca luz disponible, como de noche o en condiciones de poca luz.","ru":"Руководство мотоциклиста советует, что затемнённую защиту глаз не следует носить при недостатке света, например ночью или в условиях слабой освещённости.","tr":"Motosiklet Kullanıcı Kılavuzu, renkli (füme) göz korumasının gece ya da düşük ışık koşulları gibi az ışık olduğunda takılmaması gerektiğini tavsiye eder.","hi":"Motorcycle Operator Manual सलाह देता है कि जब बहुत कम रोशनी उपलब्ध हो, जैसे रात में या कम रोशनी की स्थिति में, तब टिंटेड आँख सुरक्षा नहीं पहननी चाहिए।","ar":"ينصح دليل مشغّل الدراجة النارية بعدم ارتداء حماية العين المظللة عند توفر القليل من الضوء، مثل الليل أو في ظروف الإضاءة المنخفضة."}},{"cat":"gear","a":2,"q":{"en":"How should a jacket and pants fit for riding, according to the Motorcycle Operator Manual?","es":"¿Cómo debe quedar una chaqueta y un pantalón para conducir, según el Manual del Operador de Motocicletas?","ru":"Как должны сидеть куртка и брюки для езды, согласно Руководству мотоциклиста?","tr":"Motosiklet Kullanıcı Kılavuzu'na göre, sürüş için ceket ve pantolon nasıl oturmalıdır?","hi":"Motorcycle Operator Manual के अनुसार, राइडिंग के लिए जैकेट और पैंट कैसे फिट होने चाहिए?","ar":"كيف يجب أن تكون مقاسات السترة والبنطال للقيادة، وفقًا لدليل مشغّل الدراجة النارية؟"},"o":[{"en":"Tight enough to restrict arm movement for support","es":"Ajustados al punto de restringir el movimiento de los brazos para dar apoyo","ru":"Достаточно плотно, чтобы ограничивать движение рук для опоры","tr":"Destek için kol hareketini kısıtlayacak kadar dar","hi":"सहारे के लिए बाँह की गति को रोकने जितने तंग","ar":"ضيقة بما يكفي لتقييد حركة الذراع للإسناد"},{"en":"Short-sleeved in summer to prevent overheating","es":"De manga corta en verano para evitar el sobrecalentamiento","ru":"С короткими рукавами летом, чтобы не перегреваться","tr":"Aşırı ısınmayı önlemek için yazın kısa kollu","hi":"ज़्यादा गर्मी रोकने के लिए गर्मियों में छोटी आस्तीन वाले","ar":"قصيرة الأكمام في الصيف لمنع فرط الحرارة"},{"en":"Cover arms and legs completely, snug enough not to flap but loose enough to move freely","es":"Cubrir por completo brazos y piernas, lo suficientemente ceñidos para no ondear pero lo suficientemente sueltos para moverse con libertad","ru":"Полностью закрывать руки и ноги, плотно, чтобы не развевались, но достаточно свободно, чтобы двигаться","tr":"Kolları ve bacakları tamamen örtmeli, savrulmayacak kadar sıkı ama serbest hareket edecek kadar bol","hi":"बाँहों और पैरों को पूरी तरह ढकें, इतने फिट कि फड़फड़ाएं नहीं पर इतने ढीले कि स्वतंत्र रूप से हिल सकें","ar":"تغطي الذراعين والساقين بالكامل، محكمة بما يكفي حتى لا ترفرف لكن فضفاضة بما يكفي للتحرك بحرية"},{"en":"As loose and baggy as possible for ventilation","es":"Lo más sueltos y holgados posible para la ventilación","ru":"Как можно более свободными и мешковатыми для вентиляции","tr":"Havalandırma için mümkün olduğunca bol ve geniş","hi":"वेंटिलेशन के लिए जितना संभव हो उतने ढीले और बैगी","ar":"فضفاضة وواسعة قدر الإمكان للتهوية"}],"e":{"en":"The Motorcycle Operator Manual says jacket and pants should cover arms and legs completely, fitting snugly enough to keep from flapping in the wind yet loosely enough to move freely.","es":"El Manual del Operador de Motocicletas dice que la chaqueta y el pantalón deben cubrir por completo brazos y piernas, quedando lo suficientemente ceñidos para no ondear con el viento pero lo suficientemente sueltos para moverse con libertad.","ru":"Руководство мотоциклиста говорит, что куртка и брюки должны полностью закрывать руки и ноги, сидя достаточно плотно, чтобы не развеваться на ветру, но достаточно свободно, чтобы двигаться свободно.","tr":"Motosiklet Kullanıcı Kılavuzu, ceket ve pantolonun kolları ve bacakları tamamen örtmesi, rüzgarda savrulmayacak kadar sıkı ama serbest hareket edecek kadar bol oturması gerektiğini söyler.","hi":"Motorcycle Operator Manual कहता है कि जैकेट और पैंट बाँहों और पैरों को पूरी तरह ढकने चाहिए, इतने फिट कि हवा में फड़फड़ाएं नहीं पर इतने ढीले कि स्वतंत्र रूप से हिल सकें।","ar":"يقول دليل مشغّل الدراجة النارية إن السترة والبنطال يجب أن يغطيا الذراعين والساقين بالكامل، بحيث يكونان محكمين بما يكفي لمنع الرفرفة في الرياح لكن فضفاضين بما يكفي للتحرك بحرية."}},{"cat":"gear","a":2,"q":{"en":"Which clothing material does the Motorcycle Operator Manual say offers the most protection in a collision?","es":"¿Qué material de ropa dice el Manual del Operador de Motocicletas que ofrece la mayor protección en una colisión?","ru":"Какой материал одежды, по словам Руководства мотоциклиста, обеспечивает наибольшую защиту при столкновении?","tr":"Motosiklet Kullanıcı Kılavuzu'na göre, bir çarpışmada en fazla korumayı hangi kıyafet malzemesi sağlar?","hi":"Motorcycle Operator Manual के अनुसार, कौन सी कपड़े की सामग्री टक्कर में सबसे अधिक सुरक्षा प्रदान करती है?","ar":"أي مادة ملابس يقول دليل مشغّل الدراجة النارية إنها توفر أكبر حماية في التصادم؟"},"o":[{"en":"Cotton denim","es":"Mezclilla de algodón","ru":"Хлопковый деним","tr":"Pamuklu kot","hi":"कॉटन डेनिम","ar":"قطن الجينز"},{"en":"Lightweight nylon mesh","es":"Malla de nailon liviana","ru":"Лёгкая нейлоновая сетка","tr":"Hafif naylon file","hi":"हल्के वज़न का नायलॉन मेश","ar":"شبكة النايلون خفيفة الوزن"},{"en":"Leather","es":"Cuero","ru":"Кожа","tr":"Deri","hi":"चमड़ा","ar":"الجلد"},{"en":"Wool","es":"Lana","ru":"Шерсть","tr":"Yün","hi":"ऊन","ar":"الصوف"}],"e":{"en":"The Motorcycle Operator Manual states leather offers the most protection, though sturdy synthetic material provides a lot of protection as well.","es":"El Manual del Operador de Motocicletas indica que el cuero ofrece la mayor protección, aunque el material sintético resistente también brinda mucha protección.","ru":"Руководство мотоциклиста утверждает, что кожа обеспечивает наибольшую защиту, хотя прочный синтетический материал также обеспечивает значительную защиту.","tr":"Motosiklet Kullanıcı Kılavuzu, derinin en fazla korumayı sağladığını, ancak dayanıklı sentetik malzemenin de oldukça fazla koruma sunduğunu belirtir.","hi":"Motorcycle Operator Manual बताता है कि चमड़ा सबसे अधिक सुरक्षा प्रदान करता है, हालाँकि मज़बूत सिंथेटिक सामग्री भी काफी सुरक्षा देती है।","ar":"ينص دليل مشغّل الدراجة النارية على أن الجلد يوفر أكبر حماية، رغم أن المواد الاصطناعية المتينة توفر قدرًا كبيرًا من الحماية أيضًا."}},{"cat":"gear","a":2,"q":{"en":"Why does the Motorcycle Operator Manual recommend wearing a jacket even in warm weather?","es":"¿Por qué el Manual del Operador de Motocicletas recomienda usar una chaqueta incluso en clima cálido?","ru":"Почему Руководство мотоциклиста рекомендует носить куртку даже в тёплую погоду?","tr":"Motosiklet Kullanıcı Kılavuzu, sıcak havalarda bile neden ceket giymeyi önerir?","hi":"Motorcycle Operator Manual गर्म मौसम में भी जैकेट पहनने की सिफारिश क्यों करता है?","ar":"لماذا يوصي دليل مشغّل الدراجة النارية بارتداء سترة حتى في الطقس الدافئ؟"},"o":[{"en":"Because state law requires a jacket in all temperatures","es":"Porque la ley estatal exige una chaqueta a cualquier temperatura","ru":"Потому что закон штата требует куртку при любой температуре","tr":"Çünkü eyalet yasası her sıcaklıkta ceket zorunlu kılar","hi":"क्योंकि राज्य का कानून सभी तापमानों में जैकेट आवश्यक करता है","ar":"لأن قانون الولاية يفرض سترة في جميع درجات الحرارة"},{"en":"Because warm-weather riding causes the most crashes","es":"Porque conducir en clima cálido causa la mayoría de los choques","ru":"Потому что езда в тёплую погоду вызывает больше всего аварий","tr":"Çünkü en çok kaza sıcak hava sürüşünde olur","hi":"क्योंकि गर्म मौसम में राइडिंग सबसे अधिक दुर्घटनाओं का कारण बनती है","ar":"لأن القيادة في الطقس الدافئ تسبب أكثر الحوادث"},{"en":"To prevent dehydration; many are designed not to overheat you","es":"Para prevenir la deshidratación; muchas están diseñadas para no sobrecalentarte","ru":"Чтобы предотвратить обезвоживание; многие из них рассчитаны на то, чтобы не перегревать вас","tr":"Su kaybını önlemek için; çoğu sizi aşırı ısıtmayacak şekilde tasarlanmıştır","hi":"निर्जलीकरण रोकने के लिए; कई इस तरह डिज़ाइन की जाती हैं कि आपको ज़्यादा गर्मी न लगे","ar":"لمنع الجفاف؛ فالكثير منها مصمم بحيث لا يسبب لك فرط الحرارة"},{"en":"To add weight that improves traction","es":"Para agregar peso que mejore la tracción","ru":"Чтобы добавить вес, улучшающий сцепление с дорогой","tr":"Yol tutuşunu artıran ağırlık eklemek için","hi":"ट्रैक्शन सुधारने के लिए वज़न जोड़ने के लिए","ar":"لإضافة وزن يحسّن الالتصاق بالطريق"}],"e":{"en":"The Motorcycle Operator Manual advises wearing a jacket even in warm weather to prevent dehydration, noting many jackets are designed to protect without getting you overheated.","es":"El Manual del Operador de Motocicletas aconseja usar una chaqueta incluso en clima cálido para prevenir la deshidratación, señalando que muchas chaquetas están diseñadas para proteger sin sobrecalentarte.","ru":"Руководство мотоциклиста советует носить куртку даже в тёплую погоду, чтобы предотвратить обезвоживание, отмечая, что многие куртки рассчитаны на защиту без перегрева.","tr":"Motosiklet Kullanıcı Kılavuzu, su kaybını önlemek için sıcak havalarda bile ceket giymeyi tavsiye eder ve çoğu ceketin sizi aşırı ısıtmadan koruyacak şekilde tasarlandığını belirtir.","hi":"Motorcycle Operator Manual निर्जलीकरण रोकने के लिए गर्म मौसम में भी जैकेट पहनने की सलाह देता है, यह नोट करते हुए कि कई जैकेट आपको ज़्यादा गर्म किए बिना सुरक्षा देने के लिए डिज़ाइन की जाती हैं।","ar":"ينصح دليل مشغّل الدراجة النارية بارتداء سترة حتى في الطقس الدافئ لمنع الجفاف، مشيرًا إلى أن الكثير من السترات مصممة للحماية دون أن تسبب لك فرط الحرارة."}},{"cat":"gear","a":2,"q":{"en":"What does the Motorcycle Operator Manual say about footwear for riding?","es":"¿Qué dice el Manual del Operador de Motocicletas sobre el calzado para conducir?","ru":"Что Руководство мотоциклиста говорит об обуви для езды?","tr":"Motosiklet Kullanıcı Kılavuzu, sürüş için ayakkabı hakkında ne der?","hi":"Motorcycle Operator Manual राइडिंग के लिए जूतों के बारे में क्या कहता है?","ar":"ماذا يقول دليل مشغّل الدراجة النارية عن الأحذية للقيادة؟"},"o":[{"en":"Heels should be tall to grip the foot pegs","es":"Los tacones deben ser altos para agarrar los estribos","ru":"Каблуки должны быть высокими, чтобы цепляться за подножки","tr":"Topuklar, ayağı basamaklara kavratacak kadar yüksek olmalı","hi":"फुट पेग को पकड़ने के लिए हील ऊँची होनी चाहिए","ar":"يجب أن تكون الكعوب عالية للإمساك بمساند القدمين"},{"en":"Laces should hang loose for quick removal","es":"Las agujetas deben colgar sueltas para quitarse el calzado rápido","ru":"Шнурки должны свободно свисать для быстрого снятия","tr":"Bağcıklar hızlı çıkarma için serbest sarkmalı","hi":"जल्दी निकालने के लिए फीते ढीले लटकने चाहिए","ar":"يجب ترك أربطة الحذاء مرتخية للنزع السريع"},{"en":"Boots or shoes should be high and sturdy enough to cover your ankles and give support","es":"Las botas o zapatos deben ser altos y resistentes para cubrir los tobillos y dar apoyo","ru":"Ботинки или обувь должны быть достаточно высокими и прочными, чтобы закрывать лодыжки и обеспечивать поддержку","tr":"Botlar ya da ayakkabılar, bileklerinizi örtecek ve destek verecek kadar yüksek ve sağlam olmalı","hi":"बूट या जूते इतने ऊँचे और मज़बूत होने चाहिए कि आपके टखनों को ढक सकें और सहारा दे सकें","ar":"يجب أن تكون الجزمة أو الحذاء عاليًا ومتينًا بما يكفي لتغطية كاحليك وتوفير الإسناد"},{"en":"Open sandals are acceptable in hot weather","es":"Las sandalias abiertas son aceptables en clima caluroso","ru":"Открытые сандалии допустимы в жаркую погоду","tr":"Sıcak havalarda açık sandaletler kabul edilebilir","hi":"गर्म मौसम में खुली सैंडल स्वीकार्य हैं","ar":"الصنادل المفتوحة مقبولة في الطقس الحار"}],"e":{"en":"The Motorcycle Operator Manual says boots or shoes should be high and sturdy enough to cover your ankles, have hard slip-resistant soles, keep heels short, and have laces tucked in.","es":"El Manual del Operador de Motocicletas dice que las botas o zapatos deben ser altos y resistentes para cubrir los tobillos, tener suelas duras y antideslizantes, mantener los tacones cortos y tener las agujetas metidas.","ru":"Руководство мотоциклиста говорит, что ботинки или обувь должны быть достаточно высокими и прочными, чтобы закрывать лодыжки, иметь жёсткую нескользящую подошву, низкие каблуки и заправленные шнурки.","tr":"Motosiklet Kullanıcı Kılavuzu, botların ya da ayakkabıların bileklerinizi örtecek kadar yüksek ve sağlam olması, sert kaymaz tabanlı olması, topukların kısa tutulması ve bağcıkların içeri sokulması gerektiğini söyler.","hi":"Motorcycle Operator Manual कहता है कि बूट या जूते इतने ऊँचे और मज़बूत होने चाहिए कि आपके टखनों को ढक सकें, उनके तले सख्त और फिसलन-रोधी हों, हील छोटी रखें, और फीते अंदर दबे हों।","ar":"يقول دليل مشغّل الدراجة النارية إن الجزمة أو الحذاء يجب أن يكون عاليًا ومتينًا بما يكفي لتغطية كاحليك، وله نعل صلب مقاوم للانزلاق، وكعوب قصيرة، وأربطة مدسوسة للداخل."}},{"cat":"gear","a":2,"q":{"en":"Why does the Motorcycle Operator Manual recommend full-fingered gloves made of leather or similar durable material?","es":"¿Por qué el Manual del Operador de Motocicletas recomienda guantes de dedos completos hechos de cuero o material duradero similar?","ru":"Почему Руководство мотоциклиста рекомендует перчатки с полными пальцами из кожи или похожего прочного материала?","tr":"Motosiklet Kullanıcı Kılavuzu, deri ya da benzeri dayanıklı malzemeden yapılmış tam parmaklı eldivenleri neden önerir?","hi":"Motorcycle Operator Manual चमड़े या समान टिकाऊ सामग्री के पूर्ण-उंगली वाले दस्तानों की सिफारिश क्यों करता है?","ar":"لماذا يوصي دليل مشغّل الدراجة النارية بقفازات كاملة الأصابع مصنوعة من الجلد أو مادة متينة مماثلة؟"},"o":[{"en":"They are required only for nighttime riding","es":"Solo son obligatorios para conducir de noche","ru":"Они требуются только для езды ночью","tr":"Yalnızca gece sürüşü için zorunludurlar","hi":"वे केवल रात की राइडिंग के लिए आवश्यक हैं","ar":"إنها مطلوبة فقط للقيادة الليلية"},{"en":"They reduce engine noise reaching the hands","es":"Reducen el ruido del motor que llega a las manos","ru":"Они снижают шум двигателя, доходящий до рук","tr":"Ellere ulaşan motor gürültüsünü azaltırlar","hi":"वे हाथों तक पहुँचने वाली इंजन की आवाज़ कम करते हैं","ar":"تقلل ضوضاء المحرك التي تصل إلى اليدين"},{"en":"They allow a better grip and help protect your hands in a crash","es":"Permiten un mejor agarre y ayudan a proteger tus manos en un choque","ru":"Они обеспечивают лучший хват и помогают защитить руки при аварии","tr":"Daha iyi kavrama sağlarlar ve bir kazada ellerinizi korumaya yardımcı olurlar","hi":"वे बेहतर पकड़ देते हैं और दुर्घटना में आपके हाथों की रक्षा में मदद करते हैं","ar":"تتيح قبضة أفضل وتساعد في حماية يديك في حادث"},{"en":"They are needed to operate anti-lock brakes","es":"Son necesarios para operar los frenos antibloqueo","ru":"Они нужны для управления антиблокировочными тормозами","tr":"ABS frenleri çalıştırmak için gereklidirler","hi":"वे एंटी-लॉक ब्रेक चलाने के लिए आवश्यक हैं","ar":"ضرورية لتشغيل الفرامل المانعة للانغلاق"}],"e":{"en":"The Motorcycle Operator Manual states gloves allow a better grip and help protect your hands in a crash, and should be made of leather or similar durable material.","es":"El Manual del Operador de Motocicletas indica que los guantes permiten un mejor agarre y ayudan a proteger tus manos en un choque, y deben estar hechos de cuero o material duradero similar.","ru":"Руководство мотоциклиста утверждает, что перчатки обеспечивают лучший хват и помогают защитить руки при аварии, и должны быть из кожи или похожего прочного материала.","tr":"Motosiklet Kullanıcı Kılavuzu, eldivenlerin daha iyi kavrama sağladığını ve bir kazada ellerinizi korumaya yardımcı olduğunu, deri ya da benzeri dayanıklı malzemeden yapılmaları gerektiğini belirtir.","hi":"Motorcycle Operator Manual बताता है कि दस्ताने बेहतर पकड़ देते हैं और दुर्घटना में आपके हाथों की रक्षा में मदद करते हैं, और चमड़े या समान टिकाऊ सामग्री के बने होने चाहिए।","ar":"ينص دليل مشغّل الدراجة النارية على أن القفازات تتيح قبضة أفضل وتساعد في حماية يديك في حادث، ويجب أن تكون مصنوعة من الجلد أو مادة متينة مماثلة."}},{"cat":"gear","a":2,"q":{"en":"For riding in cold or wet weather, what does the Motorcycle Operator Manual emphasize about your clothing?","es":"Para conducir en clima frío o húmedo, ¿qué enfatiza el Manual del Operador de Motocicletas sobre tu ropa?","ru":"Для езды в холодную или сырую погоду что Руководство мотоциклиста подчёркивает насчёт вашей одежды?","tr":"Soğuk ya da yağışlı havalarda sürüş için, Motosiklet Kullanıcı Kılavuzu kıyafetinizle ilgili neyi vurgular?","hi":"ठंडे या गीले मौसम में राइडिंग के लिए, Motorcycle Operator Manual आपके कपड़ों के बारे में किस बात पर ज़ोर देता है?","ar":"للقيادة في الطقس البارد أو الممطر، ماذا يشدد عليه دليل مشغّل الدراجة النارية بشأن ملابسك؟"},"o":[{"en":"It only needs to protect against injury, not the cold","es":"Solo necesita proteger contra lesiones, no contra el frío","ru":"Она должна защищать только от травм, а не от холода","tr":"Yalnızca yaralanmaya karşı korumalı, soğuğa karşı değil","hi":"इसे केवल चोट से बचाने की ज़रूरत है, ठंड से नहीं","ar":"تحتاج فقط إلى الحماية من الإصابة، لا من البرد"},{"en":"It should be loose to allow cold air to keep you alert","es":"Debe quedar suelta para que el aire frío te mantenga alerta","ru":"Она должна быть свободной, чтобы холодный воздух поддерживал вашу бодрость","tr":"Soğuk havanın sizi uyanık tutması için bol olmalı","hi":"आपको सतर्क रखने के लिए ठंडी हवा आने देने हेतु यह ढीला होना चाहिए","ar":"يجب أن تكون فضفاضة للسماح للهواء البارد بإبقائك متيقظًا"},{"en":"It should keep you warm and dry, because you cannot control a motorcycle well if you are numb","es":"Debe mantenerte abrigado y seco, porque no puedes controlar bien una motocicleta si estás entumecido","ru":"Она должна сохранять вас в тепле и сухости, потому что вы не сможете хорошо управлять мотоциклом, если онемеете","tr":"Sizi sıcak ve kuru tutmalı, çünkü uyuşmuşken motosikleti iyi kontrol edemezsiniz","hi":"इसे आपको गर्म और सूखा रखना चाहिए, क्योंकि सुन्न होने पर आप मोटरसाइकिल को अच्छी तरह नियंत्रित नहीं कर सकते","ar":"يجب أن تبقيك دافئًا وجافًا، لأنك لا تستطيع التحكم جيدًا في الدراجة النارية إذا كنت مخدّرًا من البرد"},{"en":"A heavy raincoat that balloons in the wind is ideal","es":"Un impermeable pesado que se infle con el viento es ideal","ru":"Идеален тяжёлый дождевик, раздувающийся на ветру","tr":"Rüzgarda balonlaşan kalın bir yağmurluk idealdir","hi":"हवा में फूलने वाला एक भारी रेनकोट आदर्श है","ar":"المعطف الواقي الثقيل الذي ينتفخ في الرياح مثالي"}],"e":{"en":"The Motorcycle Operator Manual says in cold or wet weather your clothes should keep you warm and dry; you cannot control a motorcycle well if you are numb, and long cold rides cause severe chill and fatigue.","es":"El Manual del Operador de Motocicletas dice que en clima frío o húmedo tu ropa debe mantenerte abrigado y seco; no puedes controlar bien una motocicleta si estás entumecido, y los recorridos largos en frío causan escalofríos intensos y fatiga.","ru":"Руководство мотоциклиста говорит, что в холодную или сырую погоду одежда должна сохранять вас в тепле и сухости; вы не сможете хорошо управлять мотоциклом, если онемеете, а долгие холодные поездки вызывают сильное переохлаждение и усталость.","tr":"Motosiklet Kullanıcı Kılavuzu, soğuk ya da yağışlı havalarda kıyafetlerinizin sizi sıcak ve kuru tutması gerektiğini söyler; uyuşmuşken motosikleti iyi kontrol edemezsiniz ve uzun soğuk yolculuklar şiddetli üşüme ve yorgunluğa neden olur.","hi":"Motorcycle Operator Manual कहता है कि ठंडे या गीले मौसम में आपके कपड़े आपको गर्म और सूखा रखने चाहिए; सुन्न होने पर आप मोटरसाइकिल को अच्छी तरह नियंत्रित नहीं कर सकते, और लंबी ठंडी राइड गंभीर ठिठुरन और थकान का कारण बनती हैं।","ar":"يقول دليل مشغّل الدراجة النارية إنه في الطقس البارد أو الممطر يجب أن تبقيك ملابسك دافئًا وجافًا؛ فأنت لا تستطيع التحكم جيدًا في الدراجة النارية إذا كنت مخدّرًا من البرد، والرحلات الباردة الطويلة تسبب قشعريرة شديدة وإرهاقًا."}},{"cat":"braking","a":1,"q":{"en":"When slowing or stopping your motorcycle under normal conditions, which brakes should you use?","es":"Al reducir la velocidad o detener tu motocicleta en condiciones normales, ¿qué frenos debes usar?","ru":"При замедлении или остановке мотоцикла в обычных условиях какие тормоза следует использовать?","tr":"Normal koşullarda motosikletinizi yavaşlatırken ya da durdururken hangi frenleri kullanmalısınız?","hi":"सामान्य परिस्थितियों में अपनी मोटरसाइकिल को धीमा करते या रोकते समय, आपको कौन से ब्रेक का उपयोग करना चाहिए?","ar":"عند إبطاء أو إيقاف دراجتك النارية في الظروف العادية، أي فرامل يجب أن تستخدم؟"},"o":[{"en":"Only the rear brake to avoid flipping forward","es":"Solo el freno trasero para evitar volcar hacia adelante","ru":"Только задний тормоз, чтобы не перевернуться вперёд","tr":"Öne takla atmamak için yalnızca arka freni","hi":"आगे की ओर पलटने से बचने के लिए केवल रियर ब्रेक","ar":"الفرامل الخلفية فقط لتجنّب الانقلاب للأمام"},{"en":"Both the front and rear brakes together every time","es":"Ambos frenos, el delantero y el trasero, juntos cada vez","ru":"Оба тормоза, передний и задний, совместно каждый раз","tr":"Her seferinde hem ön hem arka freni birlikte","hi":"हर बार फ्रंट और रियर दोनों ब्रेक एक साथ","ar":"كلتا الفرامل الأمامية والخلفية معًا في كل مرة"},{"en":"Only the front brake because the rear is useless","es":"Solo el freno delantero porque el trasero es inútil","ru":"Только передний тормоз, потому что задний бесполезен","tr":"Arka işe yaramadığı için yalnızca ön freni","hi":"केवल फ्रंट ब्रेक क्योंकि रियर बेकार है","ar":"الفرامل الأمامية فقط لأن الخلفية عديمة الفائدة"},{"en":"Alternate between front and rear in quick pulses","es":"Alternar entre el delantero y el trasero en pulsaciones rápidas","ru":"Чередовать передний и задний короткими нажатиями","tr":"Hızlı darbelerle ön ve arka arasında dönüşümlü","hi":"फ्रंट और रियर के बीच तेज़ी से बारी-बारी से दबाव","ar":"التناوب بين الأمامية والخلفية بنبضات سريعة"}],"e":{"en":"The Motorcycle Operator Manual instructs riders to use both brakes every time they slow or stop, which provides the shortest, most controlled stop.","es":"El Manual del Operador de Motocicletas indica a los conductores usar ambos frenos cada vez que reduzcan la velocidad o se detengan, lo que proporciona la parada más corta y controlada.","ru":"Руководство мотоциклиста предписывает мотоциклистам использовать оба тормоза каждый раз при замедлении или остановке, что обеспечивает самую короткую и контролируемую остановку.","tr":"Motosiklet Kullanıcı Kılavuzu, sürücülere her yavaşladıklarında ya da durduklarında her iki freni de kullanmalarını söyler; bu, en kısa ve en kontrollü duruşu sağlar.","hi":"Motorcycle Operator Manual राइडर्स को हर बार धीमा होने या रुकने पर दोनों ब्रेक का उपयोग करने का निर्देश देता है, जो सबसे छोटा, सबसे नियंत्रित स्टॉप प्रदान करता है।","ar":"يوجّه دليل مشغّل الدراجة النارية السائقين إلى استخدام كلتا الفرملتين في كل مرة يبطئون أو يتوقفون فيها، مما يوفر أقصر توقف وأكثره تحكمًا."}},{"cat":"braking","a":1,"q":{"en":"Approximately how much of a motorcycle's total stopping power comes from the front brake?","es":"¿Aproximadamente cuánto de la capacidad total de frenado de una motocicleta proviene del freno delantero?","ru":"Примерно какую долю общей тормозной силы мотоцикла обеспечивает передний тормоз?","tr":"Bir motosikletin toplam durma gücünün yaklaşık ne kadarı ön frenden gelir?","hi":"मोटरसाइकिल की कुल रुकने की शक्ति का लगभग कितना हिस्सा फ्रंट ब्रेक से आता है?","ar":"تقريبًا، ما مقدار قدرة التوقف الكلية للدراجة النارية الذي يأتي من الفرامل الأمامية؟"},"o":[{"en":"About one quarter","es":"Cerca de un cuarto","ru":"Около одной четверти","tr":"Yaklaşık dörtte biri","hi":"लगभग एक चौथाई","ar":"نحو الربع"},{"en":"About three quarters (roughly 70 percent)","es":"Cerca de tres cuartos (aproximadamente el 70 por ciento)","ru":"Около трёх четвертей (примерно 70 процентов)","tr":"Yaklaşık dörtte üçü (kabaca yüzde 70)","hi":"लगभग तीन चौथाई (मोटे तौर पर 70 प्रतिशत)","ar":"نحو ثلاثة أرباع (حوالي 70 بالمئة)"},{"en":"About half","es":"Cerca de la mitad","ru":"Около половины","tr":"Yaklaşık yarısı","hi":"लगभग आधा","ar":"نحو النصف"},{"en":"Almost none, it is mostly cosmetic","es":"Casi nada, es mayormente estético","ru":"Почти никакую, он в основном декоративный","tr":"Neredeyse hiçbiri, çoğunlukla göstermeliktir","hi":"लगभग कुछ नहीं, यह ज़्यादातर दिखावटी है","ar":"تقريبًا لا شيء، فهي شكلية في الغالب"}],"e":{"en":"Per the Motorcycle Operator Manual, the front brake is the more powerful brake and can provide about three quarters (roughly 70 percent) of the total stopping power.","es":"Según el Manual del Operador de Motocicletas, el freno delantero es el freno más potente y puede proporcionar cerca de tres cuartos (aproximadamente el 70 por ciento) de la capacidad total de frenado.","ru":"Согласно Руководству мотоциклиста, передний тормоз — более мощный тормоз и может обеспечить около трёх четвертей (примерно 70 процентов) общей тормозной силы.","tr":"Motosiklet Kullanıcı Kılavuzu'na göre, ön fren daha güçlü olan frendir ve toplam durma gücünün yaklaşık dörtte üçünü (kabaca yüzde 70) sağlayabilir.","hi":"Motorcycle Operator Manual के अनुसार, फ्रंट ब्रेक अधिक शक्तिशाली ब्रेक है और कुल रुकने की शक्ति का लगभग तीन चौथाई (मोटे तौर पर 70 प्रतिशत) प्रदान कर सकता है।","ar":"بحسب دليل مشغّل الدراجة النارية، الفرامل الأمامية هي الأقوى ويمكن أن توفر نحو ثلاثة أرباع (حوالي 70 بالمئة) من قدرة التوقف الكلية."}},{"cat":"braking","a":2,"q":{"en":"Why is the front brake able to provide most of a motorcycle's stopping power?","es":"¿Por qué el freno delantero puede proporcionar la mayor parte de la capacidad de frenado de una motocicleta?","ru":"Почему передний тормоз способен обеспечить большую часть тормозной силы мотоцикла?","tr":"Ön fren neden bir motosikletin durma gücünün çoğunu sağlayabilir?","hi":"फ्रंट ब्रेक मोटरसाइकिल की अधिकांश रुकने की शक्ति क्यों प्रदान कर पाता है?","ar":"لماذا تستطيع الفرامل الأمامية توفير معظم قدرة التوقف للدراجة النارية؟"},"o":[{"en":"It uses a larger reservoir of brake fluid than the rear","es":"Usa un depósito de líquido de frenos más grande que el trasero","ru":"Он использует больший запас тормозной жидкости, чем задний","tr":"Arkadan daha büyük bir fren hidroliği deposu kullanır","hi":"यह रियर की तुलना में ब्रेक फ्लुइड का बड़ा भंडार उपयोग करता है","ar":"لأنها تستخدم خزان سائل فرامل أكبر من الخلفي"},{"en":"The front tire is always wider than the rear tire","es":"La llanta delantera siempre es más ancha que la trasera","ru":"Переднее колесо всегда шире заднего","tr":"Ön lastik her zaman arka lastikten daha geniştir","hi":"फ्रंट टायर हमेशा रियर टायर से चौड़ा होता है","ar":"لأن الإطار الأمامي أعرض دائمًا من الإطار الخلفي"},{"en":"Weight shifts forward during braking, pressing the front tire harder into the pavement","es":"El peso se desplaza hacia adelante durante el frenado, presionando la llanta delantera con más fuerza contra el pavimento","ru":"Вес смещается вперёд при торможении, сильнее прижимая переднюю шину к дороге","tr":"Frenleme sırasında ağırlık öne kayarak ön lastiği yola daha sert bastırır","hi":"ब्रेकिंग के दौरान वज़न आगे की ओर शिफ्ट होता है, जिससे फ्रंट टायर सड़क पर ज़्यादा ज़ोर से दबता है","ar":"لأن الوزن ينتقل للأمام أثناء الفرملة، فيضغط الإطار الأمامي بقوة أكبر على الرصيف"},{"en":"The rear brake is intentionally built weaker by law","es":"El freno trasero está fabricado intencionalmente más débil por ley","ru":"Задний тормоз намеренно сделан слабее по закону","tr":"Arka fren yasa gereği bilerek daha zayıf yapılır","hi":"रियर ब्रेक को कानूनन जानबूझकर कमज़ोर बनाया जाता है","ar":"لأن الفرامل الخلفية مصنوعة عمدًا أضعف بموجب القانون"}],"e":{"en":"The Motorcycle Operator Manual explains that as you brake, weight transfers forward onto the front tire, pressing it harder into the road and making the front brake more effective.","es":"El Manual del Operador de Motocicletas explica que al frenar el peso se transfiere hacia adelante sobre la llanta delantera, presionándola con más fuerza contra la carretera y haciendo que el freno delantero sea más eficaz.","ru":"Руководство мотоциклиста поясняет, что при торможении вес переносится вперёд на переднюю шину, сильнее прижимая её к дороге и делая передний тормоз более эффективным.","tr":"Motosiklet Kullanıcı Kılavuzu, frenlerken ağırlığın öne, ön lastiğe doğru aktarıldığını, lastiği yola daha sert bastırarak ön freni daha etkili kıldığını açıklar.","hi":"Motorcycle Operator Manual समझाता है कि जैसे ही आप ब्रेक लगाते हैं, वज़न फ्रंट टायर पर आगे की ओर स्थानांतरित होता है, जिससे यह सड़क में ज़्यादा ज़ोर से दबता है और फ्रंट ब्रेक अधिक प्रभावी हो जाता है।","ar":"يوضح دليل مشغّل الدراجة النارية أنه أثناء الفرملة ينتقل الوزن للأمام إلى الإطار الأمامي، فيضغطه بقوة أكبر على الطريق ويجعل الفرامل الأمامية أكثر فعالية."}},{"cat":"braking","a":3,"q":{"en":"To make a quick stop on good pavement, how should you apply the front brake lever?","es":"Para hacer una parada rápida sobre buen pavimento, ¿cómo debes aplicar la palanca del freno delantero?","ru":"Чтобы быстро остановиться на хорошем покрытии, как следует нажимать рычаг переднего тормоза?","tr":"İyi zeminde hızlı bir duruş yapmak için ön fren kolunu nasıl uygulamalısınız?","hi":"अच्छी सड़क पर त्वरित स्टॉप करने के लिए, आपको फ्रंट ब्रेक लीवर को कैसे लगाना चाहिए?","ar":"لإجراء توقف سريع على رصيف جيد، كيف يجب أن تطبّق ذراع الفرامل الأمامية؟"},"o":[{"en":"Grab it as hard and fast as possible","es":"Agárrala lo más fuerte y rápido posible","ru":"Схватить его как можно сильнее и быстрее","tr":"Mümkün olduğunca sert ve hızlı kavrayın","hi":"इसे जितना कठोर और तेज़ी से संभव हो पकड़ें","ar":"أمسكها بأقصى قوة وأسرع ما يمكن"},{"en":"Tap it lightly several times only","es":"Tócala suavemente varias veces solamente","ru":"Лишь несколько раз слегка постучать по нему","tr":"Yalnızca birkaç kez hafifçe dokunun","hi":"केवल कई बार हल्के से थपथपाएं","ar":"انقرها بخفة عدة مرات فقط"},{"en":"Avoid it entirely and rely on the rear brake","es":"Evítala por completo y confía en el freno trasero","ru":"Полностью его избегать и полагаться на задний тормоз","tr":"Tamamen ondan kaçınıp arka frene güvenin","hi":"इसे पूरी तरह छोड़ दें और रियर ब्रेक पर निर्भर रहें","ar":"تجنّبها تمامًا واعتمد على الفرامل الخلفية"},{"en":"Squeeze it firmly and progressively, increasing pressure","es":"Apriétala con firmeza y de forma progresiva, aumentando la presión","ru":"Сжимать его уверенно и постепенно, увеличивая усилие","tr":"Sıkıca ve giderek artan şekilde, basıncı yükselterek sıkın","hi":"इसे मज़बूती और क्रमशः दबाएं, दबाव बढ़ाते हुए","ar":"اضغطها بثبات وتدرّج، زائدًا الضغط"}],"e":{"en":"The Motorcycle Operator Manual says to squeeze the front brake lever firmly and progressively rather than grabbing it, applying both brakes at the same time for a quick stop.","es":"El Manual del Operador de Motocicletas dice que aprietes la palanca del freno delantero con firmeza y de forma progresiva en lugar de agarrarla de golpe, aplicando ambos frenos al mismo tiempo para una parada rápida.","ru":"Руководство мотоциклиста говорит сжимать рычаг переднего тормоза уверенно и постепенно, а не хватать его, применяя оба тормоза одновременно для быстрой остановки.","tr":"Motosiklet Kullanıcı Kılavuzu, ön fren kolunu kavramak yerine sıkıca ve giderek artan şekilde sıkmayı, hızlı bir duruş için her iki freni aynı anda uygulamayı söyler.","hi":"Motorcycle Operator Manual कहता है कि फ्रंट ब्रेक लीवर को झपटकर पकड़ने के बजाय मज़बूती और क्रमशः दबाएं, और त्वरित स्टॉप के लिए दोनों ब्रेक एक ही समय में लगाएं।","ar":"يقول دليل مشغّل الدراجة النارية إنه يجب الضغط على ذراع الفرامل الأمامية بثبات وتدرّج بدلًا من الإمساك بها بقوة، مع تطبيق كلتا الفرملتين في الوقت نفسه لإجراء توقف سريع."}},{"cat":"braking","a":1,"q":{"en":"During a hard stop, your front wheel locks up. What is the correct response?","es":"Durante una parada brusca, tu rueda delantera se bloquea. ¿Cuál es la respuesta correcta?","ru":"Во время резкой остановки переднее колесо блокируется. Каков правильный ответ?","tr":"Sert bir duruş sırasında ön tekerleğiniz kilitlenir. Doğru tepki nedir?","hi":"कठोर स्टॉप के दौरान, आपका फ्रंट व्हील लॉक हो जाता है। सही प्रतिक्रिया क्या है?","ar":"أثناء توقف قوي، تنغلق عجلتك الأمامية. ما هي الاستجابة الصحيحة؟"},"o":[{"en":"Keep the front brake fully applied until you stop","es":"Mantén el freno delantero totalmente aplicado hasta detenerte","ru":"Держать передний тормоз полностью зажатым до остановки","tr":"Durana kadar ön freni tam basılı tutun","hi":"रुकने तक फ्रंट ब्रेक पूरी तरह लगाए रखें","ar":"أبقِ الفرامل الأمامية مطبّقة بالكامل حتى تتوقف"},{"en":"Release the front brake immediately, then reapply it firmly","es":"Suelta el freno delantero de inmediato y luego vuelve a aplicarlo con firmeza","ru":"Немедленно отпустить передний тормоз, затем снова уверенно его нажать","tr":"Ön freni hemen bırakın, sonra sıkıca yeniden uygulayın","hi":"फ्रंट ब्रेक तुरंत छोड़ें, फिर इसे मज़बूती से दोबारा लगाएं","ar":"حرّر الفرامل الأمامية فورًا، ثم أعد تطبيقها بثبات"},{"en":"Let go of the handlebars and coast","es":"Suelta el manillar y rueda libremente","ru":"Отпустить руль и катиться","tr":"Gidonu bırakıp rölantide gidin","hi":"हैंडलबार छोड़ दें और कोस्ट करें","ar":"اترك المقود وانزلق"},{"en":"Apply much more rear brake to compensate","es":"Aplica mucho más freno trasero para compensar","ru":"Применить намного больше заднего тормоза для компенсации","tr":"Telafi için çok daha fazla arka fren uygulayın","hi":"भरपाई के लिए बहुत अधिक रियर ब्रेक लगाएं","ar":"طبّق فرملة خلفية أكبر بكثير للتعويض"}],"e":{"en":"The Motorcycle Operator Manual states that if the front wheel locks, release the front brake immediately to let the tire roll again, then reapply it firmly.","es":"El Manual del Operador de Motocicletas indica que si la rueda delantera se bloquea, sueltes el freno delantero de inmediato para que la llanta vuelva a rodar y luego lo apliques de nuevo con firmeza.","ru":"Руководство мотоциклиста утверждает, что если переднее колесо блокируется, немедленно отпустите передний тормоз, чтобы шина снова покатилась, затем снова уверенно его нажмите.","tr":"Motosiklet Kullanıcı Kılavuzu, ön tekerlek kilitlenirse, lastiğin tekrar dönmesi için ön freni hemen bırakmanızı, sonra sıkıca yeniden uygulamanızı belirtir.","hi":"Motorcycle Operator Manual बताता है कि यदि फ्रंट व्हील लॉक हो जाए, तो फ्रंट ब्रेक तुरंत छोड़ें ताकि टायर फिर से घूमने लगे, फिर इसे मज़बूती से दोबारा लगाएं।","ar":"ينص دليل مشغّل الدراجة النارية على أنه إذا انغلقت العجلة الأمامية، فحرّر الفرامل الأمامية فورًا للسماح للإطار بالدوران مجددًا، ثم أعد تطبيقها بثبات."}},{"cat":"braking","a":0,"q":{"en":"If your rear wheel locks up while you are stopping upright and in a straight line on good traction, you should:","es":"Si tu rueda trasera se bloquea mientras te detienes en posición vertical y en línea recta sobre buena tracción, debes:","ru":"Если заднее колесо блокируется, когда вы останавливаетесь вертикально и по прямой на хорошем сцеплении, следует:","tr":"İyi tutuşlu zeminde dik ve düz bir çizgide dururken arka tekerleğiniz kilitlenirse şunu yapmalısınız:","hi":"यदि अच्छी ट्रैक्शन पर सीधी रेखा में और सीधे खड़े होकर रुकते समय आपका रियर व्हील लॉक हो जाए, तो आपको:","ar":"إذا انغلقت عجلتك الخلفية أثناء توقفك وأنت منتصب وفي خط مستقيم على التصاق جيد، فعليك أن:"},"o":[{"en":"Keep the rear wheel locked until you have come to a complete stop","es":"Mantener la rueda trasera bloqueada hasta que te hayas detenido por completo","ru":"Держать заднее колесо заблокированным, пока полностью не остановитесь","tr":"Tamamen durana kadar arka tekerleği kilitli tutun","hi":"पूरी तरह रुकने तक रियर व्हील को लॉक रखना चाहिए","ar":"تُبقي العجلة الخلفية منغلقة حتى تتوقف توقفًا تامًا"},{"en":"Release the rear brake immediately and stop using it","es":"Soltar el freno trasero de inmediato y dejar de usarlo","ru":"Немедленно отпустить задний тормоз и прекратить его использовать","tr":"Arka freni hemen bırakın ve kullanmayı bırakın","hi":"रियर ब्रेक तुरंत छोड़ देना चाहिए और इसका उपयोग बंद कर देना चाहिए","ar":"تحرّر الفرامل الخلفية فورًا وتتوقف عن استخدامها"},{"en":"Pump the rear brake rapidly to free the wheel","es":"Bombear el freno trasero rápidamente para liberar la rueda","ru":"Быстро прокачивать задний тормоз, чтобы освободить колесо","tr":"Tekerleği kurtarmak için arka frene hızlıca basıp bırakın","hi":"व्हील को मुक्त करने के लिए रियर ब्रेक को तेज़ी से पंप करना चाहिए","ar":"تضخّ الفرامل الخلفية بسرعة لتحرير العجلة"},{"en":"Quickly steer hard to one side","es":"Girar bruscamente hacia un lado de inmediato","ru":"Резко повернуть в одну сторону","tr":"Hızlıca sert şekilde bir tarafa direksiyon kırın","hi":"जल्दी से एक ओर ज़ोर से स्टीयर करना चाहिए","ar":"توجّه بقوة إلى أحد الجانبين بسرعة"}],"e":{"en":"The Motorcycle Operator Manual notes that with a locked rear wheel you can still control the motorcycle if it is upright and going straight, so keep it locked until you stop completely.","es":"El Manual del Operador de Motocicletas señala que con la rueda trasera bloqueada aún puedes controlar la motocicleta si está vertical y va en línea recta, así que mantenla bloqueada hasta detenerte por completo.","ru":"Руководство мотоциклиста отмечает, что с заблокированным задним колесом вы всё ещё можете управлять мотоциклом, если он вертикален и едет прямо, поэтому держите его заблокированным, пока полностью не остановитесь.","tr":"Motosiklet Kullanıcı Kılavuzu, arka tekerlek kilitliyken motosiklet dik ve düz gidiyorsa onu kontrol edebileceğinizi belirtir, bu yüzden tamamen durana kadar kilitli tutun.","hi":"Motorcycle Operator Manual नोट करता है कि लॉक हुए रियर व्हील के साथ आप अभी भी मोटरसाइकिल को नियंत्रित कर सकते हैं यदि यह सीधी खड़ी है और सीधे जा रही है, इसलिए पूरी तरह रुकने तक इसे लॉक रखें।","ar":"يشير دليل مشغّل الدراجة النارية إلى أنه مع عجلة خلفية منغلقة لا يزال بإمكانك التحكم في الدراجة النارية إذا كانت منتصبة وتسير مستقيمة، لذا أبقِها منغلقة حتى تتوقف توقفًا تامًا."}},{"cat":"braking","a":0,"q":{"en":"What is the main reason for treating a locked front wheel differently from a locked rear wheel?","es":"¿Cuál es la razón principal para tratar una rueda delantera bloqueada de manera diferente a una rueda trasera bloqueada?","ru":"Какова основная причина по-разному относиться к заблокированному переднему колесу и заблокированному заднему колесу?","tr":"Kilitlenmiş bir ön tekerleğin, kilitlenmiş bir arka tekerlekten farklı ele alınmasının temel nedeni nedir?","hi":"लॉक हुए फ्रंट व्हील को लॉक हुए रियर व्हील से अलग तरीके से संभालने का मुख्य कारण क्या है?","ar":"ما هو السبب الرئيسي للتعامل مع عجلة أمامية منغلقة بشكل مختلف عن عجلة خلفية منغلقة؟"},"o":[{"en":"A locked front wheel can cause loss of steering control and a fall","es":"Una rueda delantera bloqueada puede causar pérdida del control de dirección y una caída","ru":"Заблокированное переднее колесо может вызвать потерю управляемости рулём и падение","tr":"Kilitlenmiş bir ön tekerlek, direksiyon kontrolünün kaybına ve düşmeye yol açabilir","hi":"लॉक हुआ फ्रंट व्हील स्टीयरिंग नियंत्रण खोने और गिरने का कारण बन सकता है","ar":"العجلة الأمامية المنغلقة قد تسبب فقدان التحكم في التوجيه والسقوط"},{"en":"A locked front wheel makes no difference to control","es":"Una rueda delantera bloqueada no afecta el control","ru":"Заблокированное переднее колесо никак не влияет на управление","tr":"Kilitlenmiş bir ön tekerlek kontrol açısından fark yaratmaz","hi":"लॉक हुए फ्रंट व्हील से नियंत्रण पर कोई फर्क नहीं पड़ता","ar":"العجلة الأمامية المنغلقة لا تُحدث فرقًا في التحكم"},{"en":"A locked rear wheel always causes the engine to stall","es":"Una rueda trasera bloqueada siempre hace que el motor se apague","ru":"Заблокированное заднее колесо всегда вызывает остановку двигателя","tr":"Kilitlenmiş bir arka tekerlek her zaman motorun stop etmesine neden olur","hi":"लॉक हुआ रियर व्हील हमेशा इंजन को बंद कर देता है","ar":"العجلة الخلفية المنغلقة تسبب دائمًا توقف المحرك"},{"en":"The front brake cannot actually lock the front wheel","es":"El freno delantero en realidad no puede bloquear la rueda delantera","ru":"Передний тормоз на самом деле не может заблокировать переднее колесо","tr":"Ön fren aslında ön tekerleği kilitleyemez","hi":"फ्रंट ब्रेक वास्तव में फ्रंट व्हील को लॉक नहीं कर सकता","ar":"لا يمكن للفرامل الأمامية فعليًا أن تغلق العجلة الأمامية"}],"e":{"en":"The Motorcycle Operator Manual emphasizes that a locked front wheel quickly leads to loss of steering control, so it must be released and reapplied, while a locked rear wheel can be ridden out to a stop if upright and straight.","es":"El Manual del Operador de Motocicletas enfatiza que una rueda delantera bloqueada lleva rápidamente a la pérdida del control de dirección, por lo que debe soltarse y volver a aplicarse, mientras que con una rueda trasera bloqueada puedes seguir hasta detenerte si vas vertical y en línea recta.","ru":"Руководство мотоциклиста подчёркивает, что заблокированное переднее колесо быстро приводит к потере управляемости рулём, поэтому его нужно отпустить и снова нажать, тогда как с заблокированным задним колесом можно доехать до остановки, если мотоцикл вертикален и едет прямо.","tr":"Motosiklet Kullanıcı Kılavuzu, kilitlenmiş bir ön tekerleğin hızla direksiyon kontrolü kaybına yol açtığını, bu yüzden bırakılıp yeniden uygulanması gerektiğini, kilitlenmiş bir arka tekerleğin ise dik ve düz olduğunda durana kadar sürdürülebileceğini vurgular.","hi":"Motorcycle Operator Manual ज़ोर देता है कि लॉक हुआ फ्रंट व्हील जल्दी ही स्टीयरिंग नियंत्रण खोने की ओर ले जाता है, इसलिए इसे छोड़कर दोबारा लगाना चाहिए, जबकि लॉक हुए रियर व्हील को सीधी खड़ी और सीधी स्थिति में रुकने तक चलाया जा सकता है।","ar":"يؤكد دليل مشغّل الدراجة النارية أن العجلة الأمامية المنغلقة تؤدي بسرعة إلى فقدان التحكم في التوجيه، لذا يجب تحريرها وإعادة تطبيقها، بينما يمكن قيادة عجلة خلفية منغلقة حتى التوقف إذا كنت منتصبًا ومستقيمًا."}},{"cat":"braking","a":3,"q":{"en":"You need to stop quickly while leaned over in a curve. What is the best technique?","es":"Necesitas detenerte rápidamente mientras estás inclinado en una curva. ¿Cuál es la mejor técnica?","ru":"Вам нужно быстро остановиться в наклоне в повороте. Какова наилучшая техника?","tr":"Bir virajda yatmışken hızlıca durmanız gerekiyor. En iyi teknik nedir?","hi":"आपको एक मोड़ में झुके हुए जल्दी रुकने की ज़रूरत है। सबसे अच्छी तकनीक क्या है?","ar":"تحتاج إلى التوقف بسرعة وأنت مائل في منحنى. ما هي أفضل تقنية؟"},"o":[{"en":"Apply maximum brakes immediately while fully leaned","es":"Aplicar los frenos al máximo de inmediato mientras estás totalmente inclinado","ru":"Немедленно применить максимальное торможение в полном наклоне","tr":"Tamamen yatmış haldeyken hemen maksimum fren uygulayın","hi":"पूरी तरह झुके रहते हुए तुरंत अधिकतम ब्रेक लगाएं","ar":"طبّق أقصى فرملة فورًا وأنت مائل بالكامل"},{"en":"Use only the rear brake until the curve ends","es":"Usar solo el freno trasero hasta que termine la curva","ru":"Использовать только задний тормоз до конца поворота","tr":"Viraj bitene kadar yalnızca arka freni kullanın","hi":"मोड़ खत्म होने तक केवल रियर ब्रेक का उपयोग करें","ar":"استخدم الفرامل الخلفية فقط حتى ينتهي المنحنى"},{"en":"Lean even harder to tighten your line first","es":"Inclinarte aún más para cerrar tu trazada primero","ru":"Сначала наклониться ещё сильнее, чтобы сузить траекторию","tr":"Önce çizginizi sıkmak için daha da fazla yatın","hi":"पहले अपनी लाइन कसने के लिए और भी ज़्यादा झुकें","ar":"ميل أكثر لتضييق مسارك أولًا"},{"en":"Straighten the motorcycle upright as you brake, then apply firmer braking","es":"Enderezar la motocicleta a posición vertical mientras frenas, y luego aplicar un frenado más firme","ru":"Выпрямить мотоцикл вертикально по мере замедления, затем применить более сильное торможение","tr":"Frenlerken motosikleti dikleştirin, sonra daha sert frenleyin","hi":"ब्रेक लगाते हुए मोटरसाइकिल को सीधा खड़ा करें, फिर मज़बूत ब्रेकिंग लगाएं","ar":"عدّل الدراجة النارية لتصبح منتصبة أثناء الفرملة، ثم طبّق فرملة أقوى"}],"e":{"en":"The Motorcycle Operator Manual advises reducing your lean angle and bringing the bike upright as you slow, then applying more brake pressure, because a leaned tire has less traction available for braking.","es":"El Manual del Operador de Motocicletas aconseja reducir tu ángulo de inclinación y poner la moto vertical mientras reduces la velocidad, y luego aplicar más presión de frenado, porque una llanta inclinada tiene menos tracción disponible para frenar.","ru":"Руководство мотоциклиста советует уменьшать угол наклона и выпрямлять мотоцикл по мере замедления, затем увеличивать усилие на тормозах, потому что у наклонённой шины меньше доступного сцепления для торможения.","tr":"Motosiklet Kullanıcı Kılavuzu, yavaşlarken yatma açınızı azaltıp motosikleti dikleştirmenizi, sonra daha fazla fren basıncı uygulamanızı tavsiye eder, çünkü yatmış bir lastiğin frenleme için daha az tutuşu vardır.","hi":"Motorcycle Operator Manual सलाह देता है कि धीमा होते हुए अपना झुकाव कोण कम करें और बाइक को सीधा खड़ा करें, फिर अधिक ब्रेक दबाव लगाएं, क्योंकि झुके हुए टायर के पास ब्रेकिंग के लिए कम ट्रैक्शन उपलब्ध होता है।","ar":"ينصح دليل مشغّل الدراجة النارية بتقليل زاوية ميلك وجعل الدراجة منتصبة أثناء الإبطاء، ثم تطبيق ضغط فرملة أكبر، لأن الإطار المائل لديه قدر أقل من الالتصاق المتاح للفرملة."}},{"cat":"braking","a":2,"q":{"en":"Why is it harder to brake hard in a curve than on a straight road?","es":"¿Por qué es más difícil frenar fuerte en una curva que en una carretera recta?","ru":"Почему сложнее сильно тормозить в повороте, чем на прямой дороге?","tr":"Bir virajda sert frenlemek neden düz yola göre daha zordur?","hi":"सीधी सड़क की तुलना में मोड़ में ज़ोर से ब्रेक लगाना कठिन क्यों होता है?","ar":"لماذا يصعب الفرملة بقوة في منحنى مقارنةً بطريق مستقيم؟"},"o":[{"en":"Brakes physically work less well when turning","es":"Los frenos físicamente funcionan peor al girar","ru":"Тормоза физически хуже работают при повороте","tr":"Frenler dönerken fiziksel olarak daha az çalışır","hi":"मुड़ते समय ब्रेक भौतिक रूप से कम अच्छी तरह काम करते हैं","ar":"لأن الفرامل تعمل بشكل أقل فعالية عند الانعطاف فيزيائيًا"},{"en":"The front brake disconnects automatically in a turn","es":"El freno delantero se desconecta automáticamente en una curva","ru":"Передний тормоз автоматически отключается в повороте","tr":"Ön fren dönüşte otomatik olarak devre dışı kalır","hi":"मोड़ में फ्रंट ब्रेक स्वतः डिस्कनेक्ट हो जाता है","ar":"لأن الفرامل الأمامية تنفصل تلقائيًا في الانعطاف"},{"en":"Some traction is already being used for cornering, leaving less for braking","es":"Parte de la tracción ya se está usando para tomar la curva, dejando menos para frenar","ru":"Часть сцепления уже используется для прохождения поворота, оставляя меньше для торможения","tr":"Tutuşun bir kısmı zaten viraj almak için kullanılır, frenlemeye daha azı kalır","hi":"कुछ ट्रैक्शन पहले से ही कॉर्नरिंग के लिए उपयोग हो रहा होता है, जिससे ब्रेकिंग के लिए कम बचता है","ar":"لأن جزءًا من الالتصاق يُستخدم بالفعل في المنعطف، مما يترك قدرًا أقل للفرملة"},{"en":"Tires grip better when leaned, so braking is unnecessary","es":"Las llantas agarran mejor cuando están inclinadas, así que frenar es innecesario","ru":"Шины лучше держат в наклоне, поэтому торможение не нужно","tr":"Lastikler yatınca daha iyi tutar, bu yüzden frenleme gereksizdir","hi":"झुकने पर टायर बेहतर पकड़ते हैं, इसलिए ब्रेकिंग अनावश्यक है","ar":"لأن الإطارات تلتصق أفضل عند الميل، فلا حاجة للفرملة"}],"e":{"en":"The Motorcycle Operator Manual explains that a tire has limited traction; in a curve some of it is used to corner, so less remains for braking until you straighten the bike.","es":"El Manual del Operador de Motocicletas explica que una llanta tiene tracción limitada; en una curva parte de ella se usa para tomar la curva, así que queda menos para frenar hasta que enderezas la moto.","ru":"Руководство мотоциклиста поясняет, что у шины ограниченное сцепление; в повороте часть его используется для прохождения поворота, поэтому меньше остаётся для торможения, пока вы не выпрямите мотоцикл.","tr":"Motosiklet Kullanıcı Kılavuzu, bir lastiğin sınırlı tutuşu olduğunu açıklar; virajda bunun bir kısmı viraj almak için kullanılır, bu yüzden motosikleti dikleştirene kadar frenlemeye daha azı kalır.","hi":"Motorcycle Operator Manual समझाता है कि टायर के पास सीमित ट्रैक्शन होता है; मोड़ में इसका कुछ हिस्सा कॉर्नरिंग के लिए उपयोग होता है, इसलिए जब तक आप बाइक सीधी नहीं करते, ब्रेकिंग के लिए कम बचता है।","ar":"يوضح دليل مشغّل الدراجة النارية أن الإطار لديه التصاق محدود؛ ففي المنحنى يُستخدم جزء منه للمنعطف، فيبقى قدر أقل للفرملة حتى تعدّل الدراجة لتصبح مستقيمة."}},{"cat":"braking","a":1,"q":{"en":"If you must brake in a curve before you can fully straighten the bike, you should:","es":"Si debes frenar en una curva antes de poder enderezar por completo la moto, debes:","ru":"Если вам нужно тормозить в повороте, прежде чем вы сможете полностью выпрямить мотоцикл, следует:","tr":"Motosikleti tamamen dikleştiremeden bir virajda frenlemek zorunda kalırsanız şunu yapmalısınız:","hi":"यदि आपको बाइक पूरी तरह सीधी करने से पहले मोड़ में ब्रेक लगाना ही पड़े, तो आपको:","ar":"إذا اضطررت إلى الفرملة في منحنى قبل أن تتمكن من جعل الدراجة مستقيمة تمامًا، فعليك أن:"},"o":[{"en":"Apply maximum front brake right away","es":"Aplicar el freno delantero al máximo de inmediato","ru":"Сразу применить максимальный передний тормоз","tr":"Hemen maksimum ön fren uygulayın","hi":"तुरंत अधिकतम फ्रंट ब्रेक लगाना चाहिए","ar":"تطبّق أقصى فرملة أمامية على الفور"},{"en":"Apply the brakes lightly at first and increase pressure as you reduce lean","es":"Aplicar los frenos suavemente al principio y aumentar la presión a medida que reduces la inclinación","ru":"Сначала применять тормоза слегка и увеличивать усилие по мере уменьшения наклона","tr":"Önce hafif fren basıncı uygulayın ve yatmayı azalttıkça basıncı artırın","hi":"पहले हल्के से ब्रेक लगाना चाहिए और झुकाव कम करते हुए दबाव बढ़ाना चाहिए","ar":"تطبّق الفرامل بخفة في البداية وتزيد الضغط مع تقليل الميل"},{"en":"Use the front brake only and ignore the rear","es":"Usar solo el freno delantero e ignorar el trasero","ru":"Использовать только передний тормоз и не использовать задний","tr":"Yalnızca ön freni kullanın, arkayı yok sayın","hi":"केवल फ्रंट ब्रेक का उपयोग करना चाहिए और रियर को नज़रअंदाज़ करना चाहिए","ar":"تستخدم الفرامل الأمامية فقط وتتجاهل الخلفية"},{"en":"Brake hard with the rear only and never the front","es":"Frenar fuerte solo con el trasero y nunca con el delantero","ru":"Сильно тормозить только задним и никогда передним","tr":"Yalnızca arka frenle sert frenleyin ve asla ön freni kullanmayın","hi":"केवल रियर से ज़ोर से ब्रेक लगाना चाहिए और कभी फ्रंट से नहीं","ar":"تفرمل بقوة بالخلفية فقط ولا تستخدم الأمامية أبدًا"}],"e":{"en":"The Motorcycle Operator Manual says to apply light brake pressure while leaned, then add pressure as you straighten the motorcycle and more traction becomes available for braking.","es":"El Manual del Operador de Motocicletas dice que apliques presión de frenado suave mientras estás inclinado, y luego añadas presión a medida que enderezas la motocicleta y hay más tracción disponible para frenar.","ru":"Руководство мотоциклиста говорит применять лёгкое усилие на тормозах в наклоне, затем добавлять усилие по мере выпрямления мотоцикла, когда становится доступно больше сцепления для торможения.","tr":"Motosiklet Kullanıcı Kılavuzu, yatmışken hafif fren basıncı uygulamayı, sonra motosikleti dikleştirip frenleme için daha fazla tutuş kullanılabilir hale geldikçe basınç eklemeyi söyler.","hi":"Motorcycle Operator Manual कहता है कि झुके हुए हल्के ब्रेक दबाव लगाएं, फिर जैसे-जैसे आप मोटरसाइकिल सीधी करते हैं और ब्रेकिंग के लिए अधिक ट्रैक्शन उपलब्ध होता है, दबाव बढ़ाएं।","ar":"يقول دليل مشغّل الدراجة النارية إنه يجب تطبيق ضغط فرملة خفيف وأنت مائل، ثم زيادة الضغط مع جعل الدراجة النارية مستقيمة وتوفر المزيد من الالتصاق للفرملة."}},{"cat":"braking","a":2,"q":{"en":"Which combination of maneuvers should you NEVER perform at the same time?","es":"¿Cuál combinación de maniobras NUNCA debes realizar al mismo tiempo?","ru":"Какое сочетание манёвров НИКОГДА не следует выполнять одновременно?","tr":"Hangi manevra kombinasyonunu ASLA aynı anda yapmamalısınız?","hi":"कौन से युद्धाभ्यासों का संयोजन आपको कभी भी एक साथ नहीं करना चाहिए?","ar":"أي مجموعة من المناورات يجب ألا تؤديها أبدًا في الوقت نفسه؟"},"o":[{"en":"Rolling off the throttle and downshifting","es":"Soltar el acelerador y bajar de velocidad","ru":"Сброс газа и понижение передачи","tr":"Gazı kapatmak ve vites düşürmek","hi":"थ्रॉटल रोल ऑफ करना और डाउनशिफ्ट करना","ar":"إرخاء الخانق وخفض السرعة"},{"en":"Using the front brake and the rear brake","es":"Usar el freno delantero y el freno trasero","ru":"Использование переднего и заднего тормоза","tr":"Ön freni ve arka freni kullanmak","hi":"फ्रंट ब्रेक और रियर ब्रेक का उपयोग करना","ar":"استخدام الفرامل الأمامية والفرامل الخلفية"},{"en":"Braking and swerving","es":"Frenar y esquivar","ru":"Торможение и объезд","tr":"Frenlemek ve manevra yapmak (yalpalamak)","hi":"ब्रेकिंग और स्वर्विंग","ar":"الفرملة والانحراف المفاجئ"},{"en":"Checking mirrors and signaling","es":"Revisar los espejos y señalizar","ru":"Проверка зеркал и подача сигнала","tr":"Aynaları kontrol etmek ve sinyal vermek","hi":"मिरर जाँचना और सिग्नल देना","ar":"فحص المرايا والإشارة"}],"e":{"en":"The Motorcycle Operator Manual warns to never brake while swerving, because braking reduces the traction needed to change direction. Brake before or after, but not during, a swerve.","es":"El Manual del Operador de Motocicletas advierte que nunca frenes mientras esquivas, porque frenar reduce la tracción necesaria para cambiar de dirección. Frena antes o después, pero no durante, una maniobra de esquive.","ru":"Руководство мотоциклиста предупреждает: никогда не тормозите во время объезда, потому что торможение уменьшает сцепление, необходимое для смены направления. Тормозите до или после объезда, но не во время.","tr":"Motosiklet Kullanıcı Kılavuzu, manevra yaparken (yalpalarken) asla frenlememeniz konusunda uyarır, çünkü frenleme yön değiştirmek için gereken tutuşu azaltır. Manevradan önce ya da sonra frenleyin, sırasında değil.","hi":"Motorcycle Operator Manual चेतावनी देता है कि स्वर्विंग करते समय कभी ब्रेक न लगाएं, क्योंकि ब्रेकिंग दिशा बदलने के लिए आवश्यक ट्रैक्शन को कम कर देती है। स्वर्व से पहले या बाद में ब्रेक लगाएं, पर उसके दौरान नहीं।","ar":"يحذّر دليل مشغّل الدراجة النارية من الفرملة أثناء الانحراف المفاجئ أبدًا، لأن الفرملة تقلل الالتصاق اللازم لتغيير الاتجاه. افرمل قبل أو بعد، لكن ليس أثناء الانحراف."}},{"cat":"braking","a":2,"q":{"en":"An obstacle suddenly appears and you have room to go around it but not stop in time. You should:","es":"Un obstáculo aparece de repente y tienes espacio para rodearlo pero no para detenerte a tiempo. Debes:","ru":"Внезапно появляется препятствие, и у вас есть место, чтобы объехать его, но не остановиться вовремя. Следует:","tr":"Aniden bir engel çıkıyor ve etrafından geçecek yeriniz var ama zamanında duramazsınız. Şunu yapmalısınız:","hi":"अचानक एक बाधा सामने आती है और आपके पास उसके चारों ओर जाने की जगह है पर समय पर रुकने की नहीं। आपको:","ar":"تظهر عقبة فجأة ولديك مساحة لتفاديها لكن لا يمكنك التوقف في الوقت المناسب. عليك أن:"},"o":[{"en":"Brake as hard as possible and hope to slow enough","es":"Frenar lo más fuerte posible y esperar reducir lo suficiente","ru":"Тормозить как можно сильнее и надеяться замедлиться достаточно","tr":"Mümkün olduğunca sert frenleyip yeterince yavaşlamayı umun","hi":"जितना ज़ोर से संभव हो ब्रेक लगाना चाहिए और पर्याप्त धीमे होने की उम्मीद करनी चाहिए","ar":"تفرمل بأقصى قوة وتأمل أن تبطئ بما يكفي"},{"en":"Brake and swerve at the same time for maximum effect","es":"Frenar y esquivar al mismo tiempo para máximo efecto","ru":"Тормозить и объезжать одновременно для максимального эффекта","tr":"Maksimum etki için aynı anda frenleyip manevra yapın","hi":"अधिकतम प्रभाव के लिए एक साथ ब्रेक और स्वर्व करना चाहिए","ar":"تفرمل وتنحرف في الوقت نفسه لأقصى تأثير"},{"en":"Swerve around it, separating any braking from the swerve","es":"Esquivarlo, separando cualquier frenado de la maniobra de esquive","ru":"Объехать его, отделив любое торможение от объезда","tr":"Etrafından manevrayla geçin, frenlemeyi manevradan ayrı tutarak","hi":"किसी भी ब्रेकिंग को स्वर्व से अलग रखते हुए, इसके चारों ओर स्वर्व करना चाहिए","ar":"تنحرف حولها، فاصلًا أي فرملة عن الانحراف"},{"en":"Close your eyes and hold a straight line","es":"Cerrar los ojos y mantener una línea recta","ru":"Закрыть глаза и держать прямую траекторию","tr":"Gözlerinizi kapatıp düz bir çizgide kalın","hi":"आँखें बंद करके एक सीधी लाइन पर बने रहना चाहिए","ar":"تغلق عينيك وتحافظ على خط مستقيم"}],"e":{"en":"The Motorcycle Operator Manual recommends swerving to avoid an obstacle when you cannot stop in time, and keeping braking separate from the swerve to preserve traction.","es":"El Manual del Operador de Motocicletas recomienda esquivar para evitar un obstáculo cuando no puedes detenerte a tiempo, y mantener el frenado separado de la maniobra de esquive para conservar la tracción.","ru":"Руководство мотоциклиста рекомендует объезжать препятствие, когда вы не можете остановиться вовремя, и держать торможение отдельно от объезда, чтобы сохранить сцепление.","tr":"Motosiklet Kullanıcı Kılavuzu, zamanında duramadığınızda bir engelden kaçınmak için manevra yapmanızı ve tutuşu korumak için frenlemeyi manevradan ayrı tutmanızı önerir.","hi":"Motorcycle Operator Manual सलाह देता है कि जब आप समय पर न रुक सकें तो बाधा से बचने के लिए स्वर्व करें, और ट्रैक्शन बनाए रखने के लिए ब्रेकिंग को स्वर्व से अलग रखें।","ar":"يوصي دليل مشغّل الدراجة النارية بالانحراف لتفادي عقبة عندما لا تستطيع التوقف في الوقت المناسب، وإبقاء الفرملة منفصلة عن الانحراف للحفاظ على الالتصاق."}},{"cat":"braking","a":2,"q":{"en":"If you decide to both slow down and swerve to avoid a hazard, the correct sequence is:","es":"Si decides tanto reducir la velocidad como esquivar para evitar un peligro, la secuencia correcta es:","ru":"Если вы решаете и замедлиться, и объехать, чтобы избежать опасности, правильная последовательность такова:","tr":"Bir tehlikeden kaçınmak için hem yavaşlamaya hem de manevra yapmaya karar verirseniz, doğru sıra şudur:","hi":"यदि आप एक खतरे से बचने के लिए धीमा होने और स्वर्व करने दोनों का निर्णय लेते हैं, तो सही क्रम है:","ar":"إذا قررت أن تبطئ وتنحرف معًا لتفادي خطر، فإن التسلسل الصحيح هو:"},"o":[{"en":"Brake and swerve simultaneously","es":"Frenar y esquivar simultáneamente","ru":"Тормозить и объезжать одновременно","tr":"Aynı anda frenleyip manevra yapın","hi":"एक साथ ब्रेक और स्वर्व करें","ar":"الفرملة والانحراف في وقت واحد"},{"en":"Always swerve first and never use the brakes","es":"Esquivar siempre primero y nunca usar los frenos","ru":"Всегда сначала объезжать и никогда не использовать тормоза","tr":"Her zaman önce manevra yapın ve asla fren kullanmayın","hi":"हमेशा पहले स्वर्व करें और कभी ब्रेक का उपयोग न करें","ar":"الانحراف أولًا دائمًا وعدم استخدام الفرامل أبدًا"},{"en":"Brake then swerve, or swerve then brake, but never both together","es":"Frenar y luego esquivar, o esquivar y luego frenar, pero nunca ambos a la vez","ru":"Сначала тормозить, потом объезжать, или сначала объезжать, потом тормозить, но никогда не вместе","tr":"Önce frenleyip sonra manevra yapın ya da önce manevra yapıp sonra frenleyin, ama asla ikisini birden yapmayın","hi":"ब्रेक फिर स्वर्व, या स्वर्व फिर ब्रेक, पर कभी दोनों एक साथ नहीं","ar":"الفرملة ثم الانحراف، أو الانحراف ثم الفرملة، لكن ليس معًا أبدًا"},{"en":"Always brake first and never swerve","es":"Frenar siempre primero y nunca esquivar","ru":"Всегда сначала тормозить и никогда не объезжать","tr":"Her zaman önce frenleyin ve asla manevra yapmayın","hi":"हमेशा पहले ब्रेक लगाएं और कभी स्वर्व न करें","ar":"الفرملة أولًا دائمًا وعدم الانحراف أبدًا"}],"e":{"en":"The Motorcycle Operator Manual states that braking and swerving must be done separately: brake then swerve, or swerve then brake, because doing both at once can cause a loss of traction.","es":"El Manual del Operador de Motocicletas indica que frenar y esquivar deben hacerse por separado: frena y luego esquiva, o esquiva y luego frena, porque hacer ambos a la vez puede causar una pérdida de tracción.","ru":"Руководство мотоциклиста утверждает, что торможение и объезд нужно выполнять раздельно: сначала тормозить, потом объезжать, или сначала объезжать, потом тормозить, потому что выполнение обоих одновременно может вызвать потерю сцепления.","tr":"Motosiklet Kullanıcı Kılavuzu, frenleme ve manevranın ayrı ayrı yapılması gerektiğini belirtir: önce frenle sonra manevra ya da önce manevra sonra frenle, çünkü ikisini aynı anda yapmak tutuş kaybına neden olabilir.","hi":"Motorcycle Operator Manual बताता है कि ब्रेकिंग और स्वर्विंग अलग-अलग की जानी चाहिए: ब्रेक फिर स्वर्व, या स्वर्व फिर ब्रेक, क्योंकि दोनों एक साथ करने से ट्रैक्शन खो सकता है।","ar":"ينص دليل مشغّل الدراجة النارية على أن الفرملة والانحراف يجب أن يتما بشكل منفصل: افرمل ثم انحرف، أو انحرف ثم افرمل، لأن القيام بكليهما في آن واحد قد يسبب فقدان الالتصاق."}},{"cat":"braking","a":1,"q":{"en":"A swerve to avoid an obstacle is best described as:","es":"Una maniobra de esquive para evitar un obstáculo se describe mejor como:","ru":"Объезд для избежания препятствия лучше всего описать как:","tr":"Bir engelden kaçınmak için yapılan manevra (yalpalama) en iyi nasıl tanımlanır?","hi":"किसी बाधा से बचने के लिए एक स्वर्व को सबसे अच्छी तरह कैसे वर्णित किया जाता है?","ar":"يُوصف الانحراف لتفادي عقبة على أفضل وجه بأنه:"},"o":[{"en":"A slow, gradual lane change over several seconds","es":"Un cambio de carril lento y gradual durante varios segundos","ru":"Медленную, плавную смену полосы за несколько секунд","tr":"Birkaç saniye süren yavaş, kademeli bir şerit değiştirme","hi":"कई सेकंड में एक धीमा, क्रमिक लेन परिवर्तन","ar":"تغيير حارة بطيء وتدريجي على مدى عدة ثوانٍ"},{"en":"Two quick, consecutive press-steers to change path and recover","es":"Dos giros de presión rápidos y consecutivos para cambiar la trayectoria y recuperarse","ru":"Два быстрых последовательных контрруления для смены траектории и возврата","tr":"Yolu değiştirip toparlamak için iki hızlı, art arda bastır-yönlendir hareketi","hi":"पथ बदलने और रिकवर करने के लिए दो त्वरित, लगातार प्रेस-स्टीयर","ar":"ضغطتا توجيه سريعتان متتاليتان لتغيير المسار والتعافي"},{"en":"Locking the brakes and sliding around the object","es":"Bloquear los frenos y deslizarse alrededor del objeto","ru":"Блокировку тормозов и скольжение вокруг объекта","tr":"Frenleri kilitleyip nesnenin etrafında kaymak","hi":"ब्रेक लॉक करना और वस्तु के चारों ओर फिसलना","ar":"إغلاق الفرامل والانزلاق حول الجسم"},{"en":"Standing on the pegs and leaning your whole body","es":"Pararse sobre los estribos e inclinar todo el cuerpo","ru":"Вставание на подножки и наклон всем телом","tr":"Basamakların üzerinde durup tüm vücudunuzu yatırmak","hi":"पेग पर खड़े होकर अपने पूरे शरीर को झुकाना","ar":"الوقوف على المساند وإمالة كامل جسمك"}],"e":{"en":"The Motorcycle Operator Manual describes a swerve as a quick maneuver: press the handgrip in the direction you want to go, then press the other way to recover, all without braking.","es":"El Manual del Operador de Motocicletas describe una maniobra de esquive como un movimiento rápido: presiona la manija en la dirección hacia la que quieres ir, y luego presiona hacia el otro lado para recuperarte, todo sin frenar.","ru":"Руководство мотоциклиста описывает объезд как быстрый манёвр: нажмите на рукоятку руля в направлении, куда хотите ехать, затем нажмите в обратную сторону для возврата, всё без торможения.","tr":"Motosiklet Kullanıcı Kılavuzu, bir manevrayı hızlı bir hareket olarak tanımlar: gitmek istediğiniz yöndeki gidon kabzasına bastırın, sonra toparlamak için diğer yöne bastırın, hepsi frenlemeden.","hi":"Motorcycle Operator Manual एक स्वर्व को एक त्वरित युद्धाभ्यास के रूप में वर्णित करता है: जिस दिशा में जाना है उस ओर हैंडग्रिप दबाएं, फिर रिकवर करने के लिए दूसरी ओर दबाएं, यह सब बिना ब्रेक लगाए।","ar":"يصف دليل مشغّل الدراجة النارية الانحراف بأنه مناورة سريعة: اضغط المقبض في الاتجاه الذي تريد الذهاب إليه، ثم اضغط في الاتجاه الآخر للتعافي، كل ذلك دون فرملة."}},{"cat":"braking","a":3,"q":{"en":"Under normal conditions, what is the minimum following distance the Motorcycle Operator Manual recommends behind the vehicle ahead?","es":"En condiciones normales, ¿cuál es la distancia mínima de seguimiento que recomienda el Manual del Operador de Motocicletas detrás del vehículo de adelante?","ru":"В обычных условиях какую минимальную дистанцию следования за впереди идущим транспортом рекомендует Руководство мотоциклиста?","tr":"Normal koşullarda, Motosiklet Kullanıcı Kılavuzu önünüzdeki araçtan ne kadar takip mesafesi bırakmanızı önerir?","hi":"सामान्य परिस्थितियों में, Motorcycle Operator Manual आगे वाले वाहन के पीछे न्यूनतम कितनी फॉलोइंग दूरी की सिफारिश करता है?","ar":"في الظروف العادية، ما هي مسافة الاتباع الدنيا التي يوصي بها دليل مشغّل الدراجة النارية خلف المركبة الأمامية؟"},"o":[{"en":"Half a second","es":"Medio segundo","ru":"Полсекунды","tr":"Yarım saniye","hi":"आधा सेकंड","ar":"نصف ثانية"},{"en":"One second","es":"Un segundo","ru":"Одну секунду","tr":"Bir saniye","hi":"1 सेकंड","ar":"ثانية واحدة"},{"en":"Five seconds","es":"Cinco segundos","ru":"Пять секунд","tr":"Beş saniye","hi":"5 सेकंड","ar":"خمس ثوانٍ"},{"en":"Two seconds","es":"Dos segundos","ru":"Две секунды","tr":"İki saniye","hi":"2 सेकंड","ar":"ثانيتان"}],"e":{"en":"The Motorcycle Operator Manual recommends a minimum following distance of two seconds behind the vehicle ahead under normal conditions.","es":"El Manual del Operador de Motocicletas recomienda una distancia mínima de seguimiento de dos segundos detrás del vehículo de adelante en condiciones normales.","ru":"Руководство мотоциклиста рекомендует минимальную дистанцию следования в две секунды за впереди идущим транспортом в обычных условиях.","tr":"Motosiklet Kullanıcı Kılavuzu, normal koşullarda önünüzdeki araçtan en az iki saniye takip mesafesi bırakmanızı önerir.","hi":"Motorcycle Operator Manual सामान्य परिस्थितियों में आगे वाले वाहन के पीछे न्यूनतम 2 सेकंड की फॉलोइंग दूरी की सिफारिश करता है।","ar":"يوصي دليل مشغّل الدراجة النارية بمسافة اتباع دنيا قدرها ثانيتان خلف المركبة الأمامية في الظروف العادية."}},{"cat":"braking","a":0,"q":{"en":"How do you measure a two-second following distance?","es":"¿Cómo se mide una distancia de seguimiento de dos segundos?","ru":"Как измерить дистанцию следования в две секунды?","tr":"İki saniyelik takip mesafesini nasıl ölçersiniz?","hi":"आप 2 सेकंड की फॉलोइंग दूरी कैसे मापते हैं?","ar":"كيف تقيس مسافة اتباع قدرها ثانيتان؟"},"o":[{"en":"When the vehicle ahead passes a fixed point, count the seconds until you reach the same point","es":"Cuando el vehículo de adelante pasa un punto fijo, cuenta los segundos hasta que llegues al mismo punto","ru":"Когда впереди идущий транспорт проезжает неподвижную точку, считайте секунды, пока вы не достигнете той же точки","tr":"Önünüzdeki araç sabit bir noktayı geçtiğinde, aynı noktaya gelene kadar saniyeleri sayın","hi":"जब आगे वाला वाहन एक निश्चित बिंदु पार करे, तो उसी बिंदु तक पहुँचने तक सेकंड गिनें","ar":"عندما تمر المركبة الأمامية بنقطة ثابتة، عُدّ الثواني حتى تصل إلى النقطة نفسها"},{"en":"Estimate the gap in motorcycle lengths and divide by two","es":"Estima la distancia en longitudes de motocicleta y divídela entre dos","ru":"Оцените промежуток в длинах мотоцикла и разделите на два","tr":"Aradaki boşluğu motosiklet boyu olarak tahmin edip ikiye bölün","hi":"अंतर का अनुमान मोटरसाइकिल की लंबाई में लगाएं और दो से भाग दें","ar":"قدّر الفجوة بأطوال الدراجات النارية واقسمها على اثنين"},{"en":"Watch your speedometer and subtract 2 from your speed","es":"Observa tu velocímetro y resta 2 a tu velocidad","ru":"Следите за спидометром и вычтите 2 из своей скорости","tr":"Hız göstergenizi izleyip hızınızdan 2 çıkarın","hi":"अपना स्पीडोमीटर देखें और अपनी गति से 2 घटाएं","ar":"راقب عداد سرعتك واطرح 2 من سرعتك"},{"en":"Count the lane markings between you and the car ahead","es":"Cuenta las marcas del carril entre tú y el auto de adelante","ru":"Считайте разметку полосы между вами и машиной впереди","tr":"Sizinle önünüzdeki araç arasındaki şerit çizgilerini sayın","hi":"आपके और आगे वाली कार के बीच की लेन मार्किंग गिनें","ar":"عُدّ علامات الحارة بينك وبين السيارة الأمامية"}],"e":{"en":"The Motorcycle Operator Manual says to pick a fixed point the vehicle ahead passes, then count the seconds until you reach that same point; two seconds or more is the goal.","es":"El Manual del Operador de Motocicletas dice que elijas un punto fijo que pase el vehículo de adelante y luego cuentes los segundos hasta que llegues a ese mismo punto; dos segundos o más es la meta.","ru":"Руководство мотоциклиста говорит выбрать неподвижную точку, которую проезжает впереди идущий транспорт, затем считать секунды, пока вы не достигнете той же точки; цель — две секунды или больше.","tr":"Motosiklet Kullanıcı Kılavuzu, önünüzdeki aracın geçtiği sabit bir nokta seçmenizi, sonra aynı noktaya gelene kadar saniyeleri saymanızı söyler; iki saniye ya da daha fazlası hedeftir.","hi":"Motorcycle Operator Manual कहता है कि एक निश्चित बिंदु चुनें जिसे आगे वाला वाहन पार करता है, फिर उसी बिंदु तक पहुँचने तक सेकंड गिनें; 2 सेकंड या अधिक लक्ष्य है।","ar":"يقول دليل مشغّل الدراجة النارية إنه يجب اختيار نقطة ثابتة تمر بها المركبة الأمامية، ثم عدّ الثواني حتى تصل إلى تلك النقطة نفسها؛ والهدف هو ثانيتان أو أكثر."}},{"cat":"braking","a":1,"q":{"en":"In which situation should you increase your following distance beyond two seconds?","es":"¿En cuál situación debes aumentar tu distancia de seguimiento más allá de dos segundos?","ru":"В какой ситуации следует увеличить дистанцию следования сверх двух секунд?","tr":"Hangi durumda takip mesafenizi iki saniyenin üzerine çıkarmalısınız?","hi":"किस स्थिति में आपको अपनी फॉलोइंग दूरी 2 सेकंड से अधिक बढ़ानी चाहिए?","ar":"في أي موقف يجب أن تزيد مسافة اتباعك عن ثانيتين؟"},"o":[{"en":"On a dry, clear day with light traffic","es":"En un día seco y despejado con poco tráfico","ru":"В сухой ясный день при лёгком трафике","tr":"Hafif trafiğin olduğu kuru, açık bir günde","hi":"हल्के ट्रैफ़िक वाले सूखे, साफ़ दिन में","ar":"في يوم جاف وصافٍ مع حركة مرور خفيفة"},{"en":"When the road is wet or slippery, visibility is poor, or traffic is heavy","es":"Cuando la carretera está mojada o resbaladiza, la visibilidad es mala o el tráfico es intenso","ru":"Когда дорога мокрая или скользкая, видимость плохая или трафик плотный","tr":"Yol ıslak ya da kayganken, görüş kötüyken ya da trafik yoğunken","hi":"जब सड़क गीली या फिसलन भरी हो, दृश्यता खराब हो, या ट्रैफ़िक भारी हो","ar":"عندما يكون الطريق مبللًا أو زلقًا، أو الرؤية ضعيفة، أو حركة المرور كثيفة"},{"en":"Only when riding below 25 mph","es":"Solo al conducir por debajo de 25 mph","ru":"Только при езде ниже 25 миль/ч","tr":"Yalnızca 25 mil/sa altında sürerken","hi":"केवल जब 25 mph से कम पर राइड कर रहे हों","ar":"فقط عند القيادة بأقل من 25 ميلاً في الساعة"},{"en":"Never; two seconds is always enough","es":"Nunca; dos segundos siempre es suficiente","ru":"Никогда; двух секунд всегда достаточно","tr":"Asla; iki saniye her zaman yeterlidir","hi":"कभी नहीं; 2 सेकंड हमेशा पर्याप्त है","ar":"أبدًا؛ فثانيتان كافيتان دائمًا"}],"e":{"en":"The Motorcycle Operator Manual advises opening up to three seconds or more when conditions are poor, such as wet roads, limited visibility, heavy traffic, or when being followed closely.","es":"El Manual del Operador de Motocicletas aconseja ampliar a tres segundos o más cuando las condiciones son malas, como carreteras mojadas, visibilidad limitada, tráfico intenso o cuando alguien te sigue de cerca.","ru":"Руководство мотоциклиста советует увеличивать до трёх секунд или больше, когда условия плохие, например на мокрых дорогах, при ограниченной видимости, плотном трафике или когда за вами едут вплотную.","tr":"Motosiklet Kullanıcı Kılavuzu, ıslak yollar, kısıtlı görüş, yoğun trafik ya da yakından takip edildiğinizde gibi koşullar kötüyken takip mesafesini üç saniye ya da daha fazlasına çıkarmayı tavsiye eder.","hi":"Motorcycle Operator Manual सलाह देता है कि जब परिस्थितियाँ खराब हों, जैसे गीली सड़कें, सीमित दृश्यता, भारी ट्रैफ़िक, या जब कोई आपके करीब-करीब पीछे चल रहा हो, तो 3 सेकंड या अधिक तक खोलें।","ar":"ينصح دليل مشغّل الدراجة النارية بالتوسّع إلى ثلاث ثوانٍ أو أكثر عندما تكون الظروف سيئة، مثل الطرق المبللة، أو الرؤية المحدودة، أو حركة المرور الكثيفة، أو عندما تتبعك مركبة عن قرب."}},{"cat":"braking","a":3,"q":{"en":"Why should motorcyclists keep a larger cushion of space ahead than many drivers expect?","es":"¿Por qué los motociclistas deben mantener un colchón de espacio mayor por delante de lo que muchos conductores esperan?","ru":"Почему мотоциклистам следует держать больший запас пространства впереди, чем ожидают многие водители?","tr":"Motosikletçiler neden birçok sürücünün beklediğinden daha büyük bir ön mesafe boşluğu bırakmalıdır?","hi":"मोटरसाइकिल चालकों को कई ड्राइवरों की अपेक्षा से अधिक आगे की जगह का कुशन क्यों रखना चाहिए?","ar":"لماذا يجب على راكبي الدراجات النارية الحفاظ على هامش مساحة أمامي أكبر مما يتوقعه كثير من السائقين؟"},"o":[{"en":"Motorcycles legally must travel slower than cars","es":"Las motocicletas legalmente deben circular más despacio que los autos","ru":"Мотоциклы по закону должны двигаться медленнее машин","tr":"Motosikletler yasal olarak otomobillerden yavaş gitmek zorundadır","hi":"मोटरसाइकिलों को कानूनन कारों से धीमी चलना चाहिए","ar":"لأن الدراجات النارية يجب قانونيًا أن تسير أبطأ من السيارات"},{"en":"It prevents the engine from overheating","es":"Evita que el motor se sobrecaliente","ru":"Это предотвращает перегрев двигателя","tr":"Motorun aşırı ısınmasını önler","hi":"यह इंजन को ज़्यादा गर्म होने से रोकता है","ar":"لأنه يمنع فرط حرارة المحرك"},{"en":"It is only required during driving tests","es":"Solo se exige durante los exámenes de manejo","ru":"Это требуется только во время экзамена по вождению","tr":"Yalnızca sürüş sınavları sırasında zorunludur","hi":"यह केवल ड्राइविंग टेस्ट के दौरान आवश्यक है","ar":"لأنه مطلوب فقط أثناء اختبارات القيادة"},{"en":"More space gives more time to spot hazards and brake or swerve safely","es":"Más espacio da más tiempo para detectar peligros y frenar o esquivar de forma segura","ru":"Больше пространства даёт больше времени заметить опасности и безопасно затормозить или объехать","tr":"Daha fazla mesafe, tehlikeleri fark etmek ve güvenle frenlemek ya da manevra yapmak için daha fazla zaman tanır","hi":"अधिक जगह खतरों को पहचानने और सुरक्षित रूप से ब्रेक या स्वर्व करने के लिए अधिक समय देती है","ar":"لأن المساحة الأكبر تمنح وقتًا أكثر لرصد المخاطر والفرملة أو الانحراف بأمان"}],"e":{"en":"The Motorcycle Operator Manual stresses that a larger space cushion gives you more time and room to see, react to, and avoid hazards by braking or swerving.","es":"El Manual del Operador de Motocicletas recalca que un mayor colchón de espacio te da más tiempo y espacio para ver, reaccionar y evitar peligros frenando o esquivando.","ru":"Руководство мотоциклиста подчёркивает, что больший запас пространства даёт вам больше времени и места, чтобы увидеть опасности, отреагировать на них и избежать их торможением или объездом.","tr":"Motosiklet Kullanıcı Kılavuzu, daha büyük bir mesafe boşluğunun, tehlikeleri görmeniz, tepki vermeniz ve frenleyerek ya da manevra yaparak kaçınmanız için daha fazla zaman ve alan tanıdığını vurgular.","hi":"Motorcycle Operator Manual ज़ोर देता है कि एक बड़ा स्पेस कुशन आपको ब्रेक या स्वर्व करके खतरों को देखने, उन पर प्रतिक्रिया करने और उनसे बचने के लिए अधिक समय और जगह देता है।","ar":"يشدد دليل مشغّل الدراجة النارية على أن هامش المساحة الأكبر يمنحك وقتًا ومجالًا أكبر لرؤية المخاطر والتفاعل معها وتفاديها بالفرملة أو الانحراف."}},{"cat":"braking","a":0,"q":{"en":"Total stopping distance for a motorcycle is best described as the distance traveled during:","es":"La distancia total de frenado de una motocicleta se describe mejor como la distancia recorrida durante:","ru":"Полный тормозной путь мотоцикла лучше всего описать как расстояние, пройденное за время:","tr":"Bir motosiklet için toplam durma mesafesi en iyi şu süre boyunca kat edilen mesafe olarak tanımlanır:","hi":"मोटरसाइकिल के लिए कुल रुकने की दूरी को सबसे अच्छी तरह किस दौरान तय की गई दूरी के रूप में वर्णित किया जाता है?","ar":"تُوصف مسافة التوقف الكلية للدراجة النارية على أفضل وجه بأنها المسافة المقطوعة خلال:"},"o":[{"en":"Perception time, plus reaction time, plus the actual braking distance","es":"El tiempo de percepción, más el tiempo de reacción, más la distancia real de frenado","ru":"Время восприятия плюс время реакции плюс собственно тормозной путь","tr":"Algılama süresi, artı tepki süresi, artı asıl frenleme mesafesi","hi":"परसेप्शन समय, साथ ही रिएक्शन समय, साथ ही वास्तविक ब्रेकिंग दूरी","ar":"وقت الإدراك، زائد وقت رد الفعل، زائد مسافة الفرملة الفعلية"},{"en":"Only the time the brakes are physically slowing the bike","es":"Solo el tiempo en que los frenos están físicamente reduciendo la velocidad de la moto","ru":"Только время, пока тормоза физически замедляют мотоцикл","tr":"Yalnızca frenlerin motosikleti fiziksel olarak yavaşlattığı süre","hi":"केवल वह समय जब ब्रेक भौतिक रूप से बाइक को धीमा कर रहे होते हैं","ar":"فقط الوقت الذي تُبطئ فيه الفرامل الدراجة فعليًا"},{"en":"Only the rider's reaction time","es":"Solo el tiempo de reacción del conductor","ru":"Только время реакции мотоциклиста","tr":"Yalnızca sürücünün tepki süresi","hi":"केवल राइडर का रिएक्शन समय","ar":"فقط وقت رد فعل السائق"},{"en":"The time from starting the engine to reaching full speed","es":"El tiempo desde que se enciende el motor hasta alcanzar la velocidad máxima","ru":"Время от запуска двигателя до достижения полной скорости","tr":"Motoru çalıştırmaktan tam hıza ulaşmaya kadar geçen süre","hi":"इंजन चालू करने से लेकर पूरी गति तक पहुँचने तक का समय","ar":"الوقت من بدء تشغيل المحرك حتى بلوغ السرعة الكاملة"}],"e":{"en":"The Motorcycle Operator Manual describes total stopping distance as the sum of the distance traveled while perceiving the hazard, reacting to it, and then braking to a stop.","es":"El Manual del Operador de Motocicletas describe la distancia total de frenado como la suma de la distancia recorrida mientras se percibe el peligro, se reacciona a él y luego se frena hasta detenerse.","ru":"Руководство мотоциклиста описывает полный тормозной путь как сумму расстояний, пройденных за время восприятия опасности, реакции на неё и последующего торможения до остановки.","tr":"Motosiklet Kullanıcı Kılavuzu, toplam durma mesafesini, tehlikeyi algılarken, ona tepki verirken ve sonra durana kadar frenlerken kat edilen mesafelerin toplamı olarak tanımlar.","hi":"Motorcycle Operator Manual कुल रुकने की दूरी को खतरे को पहचानने, उस पर प्रतिक्रिया करने और फिर रुकने के लिए ब्रेक लगाने के दौरान तय की गई दूरी के योग के रूप में वर्णित करता है।","ar":"يصف دليل مشغّل الدراجة النارية مسافة التوقف الكلية بأنها مجموع المسافة المقطوعة أثناء إدراك الخطر، والتفاعل معه، ثم الفرملة حتى التوقف."}},{"cat":"braking","a":0,"q":{"en":"Which factor will lengthen your total stopping distance?","es":"¿Cuál factor alargará tu distancia total de frenado?","ru":"Какой фактор удлинит ваш полный тормозной путь?","tr":"Hangi faktör toplam durma mesafenizi uzatır?","hi":"कौन सा कारक आपकी कुल रुकने की दूरी को बढ़ाएगा?","ar":"أي عامل سيطيل مسافة توقفك الكلية؟"},"o":[{"en":"Higher speed and slower reaction time","es":"Mayor velocidad y un tiempo de reacción más lento","ru":"Более высокая скорость и более медленная реакция","tr":"Daha yüksek hız ve daha yavaş tepki süresi","hi":"अधिक गति और धीमा रिएक्शन समय","ar":"سرعة أعلى ووقت رد فعل أبطأ"},{"en":"Fresh tires and dry pavement","es":"Llantas nuevas y pavimento seco","ru":"Новые шины и сухое покрытие","tr":"Yeni lastikler ve kuru zemin","hi":"नए टायर और सूखी सड़क","ar":"إطارات جديدة ورصيف جاف"},{"en":"Staying alert and scanning ahead","es":"Mantenerte alerta y escanear hacia adelante","ru":"Сохранение бдительности и просмотр дороги вперёд","tr":"Tetikte kalmak ve önü taramak","hi":"सतर्क रहना और आगे स्कैन करना","ar":"البقاء متيقظًا والمسح بالنظر للأمام"},{"en":"Using both brakes correctly together","es":"Usar ambos frenos correctamente juntos","ru":"Правильное совместное использование обоих тормозов","tr":"Her iki freni birlikte doğru kullanmak","hi":"दोनों ब्रेक को सही ढंग से एक साथ उपयोग करना","ar":"استخدام كلتا الفرملتين معًا بشكل صحيح"}],"e":{"en":"The Motorcycle Operator Manual notes that higher speed and any delay in perceiving or reacting to a hazard add to the distance traveled before you can stop, increasing total stopping distance.","es":"El Manual del Operador de Motocicletas señala que una mayor velocidad y cualquier retraso en percibir o reaccionar ante un peligro aumentan la distancia recorrida antes de poder detenerte, incrementando la distancia total de frenado.","ru":"Руководство мотоциклиста отмечает, что более высокая скорость и любая задержка в восприятии опасности или реакции на неё добавляют к расстоянию, пройденному до остановки, увеличивая полный тормозной путь.","tr":"Motosiklet Kullanıcı Kılavuzu, daha yüksek hızın ve bir tehlikeyi algılamadaki ya da ona tepki vermedeki herhangi bir gecikmenin, durabilmeden önce kat edilen mesafeye eklendiğini ve toplam durma mesafesini artırdığını belirtir.","hi":"Motorcycle Operator Manual नोट करता है कि अधिक गति और खतरे को पहचानने या उस पर प्रतिक्रिया करने में कोई भी देरी रुकने से पहले तय की गई दूरी को बढ़ाती है, जिससे कुल रुकने की दूरी बढ़ जाती है।","ar":"يشير دليل مشغّل الدراجة النارية إلى أن السرعة الأعلى وأي تأخير في إدراك الخطر أو التفاعل معه يضيفان إلى المسافة المقطوعة قبل أن تتمكن من التوقف، مما يزيد مسافة التوقف الكلية."}},{"cat":"braking","a":3,"q":{"en":"What is a key benefit of practicing quick stops in a safe area before you need one?","es":"¿Cuál es un beneficio clave de practicar paradas rápidas en un área segura antes de necesitarlas?","ru":"В чём ключевая польза отработки быстрых остановок в безопасном месте до того, как они понадобятся?","tr":"İhtiyaç duymadan önce güvenli bir alanda hızlı duruşlar pratiği yapmanın temel bir faydası nedir?","hi":"ज़रूरत पड़ने से पहले एक सुरक्षित क्षेत्र में त्वरित स्टॉप का अभ्यास करने का एक प्रमुख लाभ क्या है?","ar":"ما هي الفائدة الرئيسية لممارسة التوقفات السريعة في منطقة آمنة قبل أن تحتاج إليها؟"},"o":[{"en":"It lets you skip using the front brake in emergencies","es":"Te permite omitir el uso del freno delantero en emergencias","ru":"Это позволяет не использовать передний тормоз в экстренных ситуациях","tr":"Acil durumlarda ön freni kullanmamanıza olanak tanır","hi":"यह आपको आपातकाल में फ्रंट ब्रेक का उपयोग छोड़ने देता है","ar":"تتيح لك تجاوز استخدام الفرامل الأمامية في حالات الطوارئ"},{"en":"It allows you to stop without slowing down","es":"Te permite detenerte sin reducir la velocidad","ru":"Это позволяет останавливаться, не замедляясь","tr":"Yavaşlamadan durmanızı sağlar","hi":"यह आपको धीमा हुए बिना रुकने देता है","ar":"تتيح لك التوقف دون إبطاء"},{"en":"It eliminates the need for any following distance","es":"Elimina la necesidad de cualquier distancia de seguimiento","ru":"Это устраняет необходимость в какой-либо дистанции следования","tr":"Herhangi bir takip mesafesi ihtiyacını ortadan kaldırır","hi":"यह किसी भी फॉलोइंग दूरी की ज़रूरत समाप्त कर देता है","ar":"تلغي الحاجة إلى أي مسافة اتباع"},{"en":"It builds the skill to brake hard with both brakes without locking a wheel","es":"Desarrolla la habilidad de frenar fuerte con ambos frenos sin bloquear una rueda","ru":"Это формирует навык сильно тормозить обоими тормозами без блокировки колеса","tr":"Bir tekerleği kilitlemeden her iki frenle sert frenleme becerisini geliştirir","hi":"यह बिना व्हील लॉक किए दोनों ब्रेक से ज़ोर से ब्रेक लगाने का कौशल बनाता है","ar":"تبني مهارة الفرملة بقوة بكلتا الفرملتين دون إغلاق عجلة"}],"e":{"en":"The Motorcycle Operator Manual recommends practicing quick stops so you can apply both brakes firmly and progressively in an emergency without locking a wheel and losing control.","es":"El Manual del Operador de Motocicletas recomienda practicar paradas rápidas para que puedas aplicar ambos frenos con firmeza y de forma progresiva en una emergencia sin bloquear una rueda y perder el control.","ru":"Руководство мотоциклиста рекомендует отрабатывать быстрые остановки, чтобы в экстренной ситуации вы могли уверенно и постепенно применять оба тормоза без блокировки колеса и потери управления.","tr":"Motosiklet Kullanıcı Kılavuzu, bir acil durumda her iki freni sıkıca ve giderek artan şekilde uygulayabilmeniz için, bir tekerleği kilitleyip kontrolü kaybetmeden hızlı duruş pratiği yapmayı önerir.","hi":"Motorcycle Operator Manual त्वरित स्टॉप का अभ्यास करने की सिफारिश करता है ताकि आप आपातकाल में बिना व्हील लॉक किए और नियंत्रण खोए दोनों ब्रेक को मज़बूती और क्रमशः लगा सकें।","ar":"يوصي دليل مشغّل الدراجة النارية بممارسة التوقفات السريعة حتى تتمكن من تطبيق كلتا الفرملتين بثبات وتدرّج في حالة الطوارئ دون إغلاق عجلة وفقدان التحكم."}},{"cat":"braking","a":0,"q":{"en":"When making a hard stop, applying the rear brake too hard most commonly causes the rear wheel to:","es":"Al hacer una parada brusca, aplicar el freno trasero con demasiada fuerza comúnmente hace que la rueda trasera:","ru":"При резкой остановке слишком сильное нажатие заднего тормоза чаще всего приводит к тому, что заднее колесо:","tr":"Sert bir duruş yaparken arka frene çok sert basmak en çok arka tekerleğin ne yapmasına neden olur?","hi":"एक कठोर स्टॉप करते समय, रियर ब्रेक को बहुत ज़ोर से लगाने पर सबसे आम तौर पर रियर व्हील:","ar":"عند إجراء توقف قوي، فإن تطبيق الفرامل الخلفية بقوة مفرطة يتسبب غالبًا في أن العجلة الخلفية:"},"o":[{"en":"Lock up and skid","es":"Se bloquee y derrape","ru":"Блокируется и идёт юзом","tr":"Kilitlenip kaymasına","hi":"लॉक हो जाता है और स्किड करता है","ar":"تنغلق وتنزلق"},{"en":"Spin faster than the front wheel","es":"Gire más rápido que la rueda delantera","ru":"Вращается быстрее переднего колеса","tr":"Ön tekerlekten daha hızlı dönmesine","hi":"फ्रंट व्हील से तेज़ी से घूमता है","ar":"تدور أسرع من العجلة الأمامية"},{"en":"Lift completely off the ground and stay there","es":"Se levante por completo del suelo y se quede así","ru":"Полностью отрывается от земли и остаётся в воздухе","tr":"Tamamen yerden kalkıp öyle kalmasına","hi":"पूरी तरह ज़मीन से उठ जाता है और उठा रहता है","ar":"ترتفع تمامًا عن الأرض وتبقى مرفوعة"},{"en":"Turn the handlebars automatically","es":"Gire el manillar automáticamente","ru":"Автоматически поворачивает руль","tr":"Gidonu otomatik olarak çevirmesine","hi":"स्वतः हैंडलबार घुमा देता है","ar":"تدير المقود تلقائيًا"}],"e":{"en":"The Motorcycle Operator Manual explains that as weight shifts forward in a hard stop, the lighter rear wheel can lock and skid easily, so rear brake pressure must be controlled.","es":"El Manual del Operador de Motocicletas explica que a medida que el peso se desplaza hacia adelante en una parada brusca, la rueda trasera, más ligera, puede bloquearse y derrapar con facilidad, así que la presión del freno trasero debe controlarse.","ru":"Руководство мотоциклиста поясняет, что при смещении веса вперёд во время резкой остановки облегчённое заднее колесо легко блокируется и идёт юзом, поэтому усилие на заднем тормозе нужно контролировать.","tr":"Motosiklet Kullanıcı Kılavuzu, sert bir duruşta ağırlık öne kayarken, daha hafif kalan arka tekerleğin kolayca kilitlenip kayabileceğini, bu yüzden arka fren basıncının kontrol edilmesi gerektiğini açıklar.","hi":"Motorcycle Operator Manual समझाता है कि कठोर स्टॉप में वज़न आगे की ओर शिफ्ट होने पर हल्का रियर व्हील आसानी से लॉक होकर स्किड कर सकता है, इसलिए रियर ब्रेक दबाव को नियंत्रित किया जाना चाहिए।","ar":"يوضح دليل مشغّل الدراجة النارية أنه مع انتقال الوزن للأمام في توقف قوي، يمكن أن تنغلق العجلة الخلفية الأخف وتنزلق بسهولة، لذا يجب التحكم في ضغط الفرامل الخلفية."}},{"cat":"cornering","a":1,"q":{"en":"According to the Motorcycle Operator Manual, what is the correct order of the four steps for taking a turn?","es":"Según el Manual del Operador de Motocicletas, ¿cuál es el orden correcto de los cuatro pasos para tomar una curva?","ru":"Согласно Руководству мотоциклиста, какова правильная последовательность четырёх шагов прохождения поворота?","tr":"Motosiklet Kullanıcı Kılavuzu'na göre, bir dönüş yapmanın dört adımının doğru sırası nedir?","hi":"Motorcycle Operator Manual के अनुसार, एक मोड़ लेने के चार चरणों का सही क्रम क्या है?","ar":"وفقًا لدليل مشغّل الدراجة النارية، ما هو الترتيب الصحيح للخطوات الأربع لأخذ منعطف؟"},"o":[{"en":"Look, Slow, Roll, Press","es":"Mira, Reduce, Acelera, Presiona","ru":"Смотри, Замедлись, Прибавь газ, Нажми","tr":"Bak, Yavaşla, Gazla, Bastır","hi":"Look, Slow, Roll, Press","ar":"انظر، أبطئ، لُفّ، اضغط"},{"en":"Slow, Look, Press, Roll","es":"Reduce, Mira, Presiona, Acelera","ru":"Замедлись, Смотри, Нажми, Прибавь газ","tr":"Yavaşla, Bak, Bastır, Gazla","hi":"Slow, Look, Press, Roll","ar":"أبطئ، انظر، اضغط، لُفّ"},{"en":"Press, Slow, Look, Roll","es":"Presiona, Reduce, Mira, Acelera","ru":"Нажми, Замедлись, Смотри, Прибавь газ","tr":"Bastır, Yavaşla, Bak, Gazla","hi":"Press, Slow, Look, Roll","ar":"اضغط، أبطئ، انظر، لُفّ"},{"en":"Slow, Press, Roll, Look","es":"Reduce, Presiona, Acelera, Mira","ru":"Замедлись, Нажми, Прибавь газ, Смотри","tr":"Yavaşla, Bastır, Gazla, Bak","hi":"Slow, Press, Roll, Look","ar":"أبطئ، اضغط، لُفّ، انظر"}],"e":{"en":"The manual lists the four steps to turn effectively in order: SLOW (reduce speed before the turn), LOOK (look through the turn), PRESS (press the handgrip to lean), and ROLL (roll on the throttle through the turn). Source: Motorcycle Operator Manual.","es":"El manual enumera los cuatro pasos para tomar una curva de forma eficaz en orden: REDUCE (reduce la velocidad antes de la curva), MIRA (mira a través de la curva), PRESIONA (presiona la manija para inclinarte) y ACELERA (acelera a través de la curva). Fuente: Manual del Operador de Motocicletas.","ru":"Руководство перечисляет четыре шага эффективного прохождения поворота по порядку: ЗАМЕДЛИСЬ (снизь скорость перед поворотом), СМОТРИ (смотри сквозь поворот), НАЖМИ (нажми на рукоятку руля для наклона) и ПРИБАВЬ ГАЗ (прибавляй газ в повороте). Источник: Руководство мотоциклиста.","tr":"Kılavuz, etkili dönüş yapmanın dört adımını sırayla listeler: YAVAŞLA (dönüşten önce hızı azalt), BAK (dönüşün içinden bak), BASTIR (yatmak için gidon kabzasına bastır) ve GAZLA (dönüş boyunca gazı aç). Kaynak: Motosiklet Kullanıcı Kılavuzu.","hi":"मैनुअल प्रभावी ढंग से मुड़ने के चार चरणों को क्रम में सूचीबद्ध करता है: SLOW (मोड़ से पहले गति कम करें), LOOK (मोड़ के पार देखें), PRESS (झुकने के लिए हैंडग्रिप दबाएं), और ROLL (मोड़ के दौरान थ्रॉटल रोल ऑन करें)। स्रोत: Motorcycle Operator Manual।","ar":"يُدرج الدليل الخطوات الأربع للانعطاف بفعالية مرتبةً: أبطئ (قلل السرعة قبل المنعطف)، انظر (انظر عبر المنعطف)، اضغط (اضغط المقبض للميل)، ولُفّ (لُفّ الخانق عبر المنعطف). المصدر: دليل مشغّل الدراجة النارية."}},{"cat":"cornering","a":1,"q":{"en":"What does the 'SLOW' step of the four-step turning procedure require you to do?","es":"¿Qué te exige hacer el paso 'REDUCE' del procedimiento de cuatro pasos para tomar una curva?","ru":"Что требует от вас шаг «ЗАМЕДЛИСЬ» в четырёхшаговой процедуре прохождения поворота?","tr":"Dört adımlı dönüş işleminin 'YAVAŞLA' adımı ne yapmanızı gerektirir?","hi":"चार-चरण मुड़ने की प्रक्रिया का 'SLOW' चरण आपसे क्या करवाता है?","ar":"ماذا تتطلب منك خطوة 'أبطئ' في إجراء الانعطاف المكوّن من أربع خطوات؟"},"o":[{"en":"Slow down gradually only after you have entered the curve","es":"Reducir la velocidad gradualmente solo después de haber entrado a la curva","ru":"Замедляться постепенно только после входа в поворот","tr":"Yalnızca virajı girdikten sonra kademeli olarak yavaşlayın","hi":"मोड़ में प्रवेश करने के बाद ही धीरे-धीरे धीमा हों","ar":"أن تبطئ تدريجيًا فقط بعد أن تدخل المنحنى"},{"en":"Reduce speed before entering the turn by closing the throttle and, if needed, applying both brakes","es":"Reducir la velocidad antes de entrar a la curva cerrando el acelerador y, si es necesario, aplicando ambos frenos","ru":"Снизить скорость перед входом в поворот, закрыв газ и, при необходимости, применив оба тормоза","tr":"Gazı kapatarak ve gerekirse her iki freni uygulayarak dönüşe girmeden önce hızı azaltın","hi":"थ्रॉटल बंद करके और ज़रूरत हो तो दोनों ब्रेक लगाकर मोड़ में प्रवेश करने से पहले गति कम करें","ar":"أن تقلل السرعة قبل دخول المنعطف بإغلاق الخانق، وعند الحاجة، تطبيق كلتا الفرملتين"},{"en":"Coast through the entire turn in neutral to stay smooth","es":"Pasar toda la curva rodando en neutral para mantenerte suave","ru":"Проходить весь поворот накатом на нейтрали, чтобы было плавно","tr":"Yumuşak olmak için tüm dönüş boyunca boşta gidin","hi":"सहज रहने के लिए पूरे मोड़ में न्यूट्रल में कोस्ट करें","ar":"أن تنزلق عبر المنعطف كله في الوضع المحايد لتبقى سلسًا"},{"en":"Apply only the rear brake at the sharpest point of the curve","es":"Aplicar solo el freno trasero en el punto más cerrado de la curva","ru":"Применять только задний тормоз в самой острой точке поворота","tr":"Virajın en keskin noktasında yalnızca arka freni uygulayın","hi":"मोड़ के सबसे तीखे बिंदु पर केवल रियर ब्रेक लगाएं","ar":"أن تطبّق الفرامل الخلفية فقط عند أحدّ نقطة في المنحنى"}],"e":{"en":"In the SLOW step you reduce speed before the turn by rolling off the throttle and, if necessary, applying both brakes. Braking should be completed before you lean into the curve. Source: Motorcycle Operator Manual.","es":"En el paso REDUCE bajas la velocidad antes de la curva soltando el acelerador y, si es necesario, aplicando ambos frenos. El frenado debe completarse antes de inclinarte hacia la curva. Fuente: Manual del Operador de Motocicletas.","ru":"На шаге ЗАМЕДЛИСЬ вы снижаете скорость перед поворотом, сбрасывая газ и, при необходимости, применяя оба тормоза. Торможение следует завершить до того, как вы войдёте в поворот в наклоне. Источник: Руководство мотоциклиста.","tr":"YAVAŞLA adımında, gazı kapatarak ve gerekirse her iki freni uygulayarak dönüşten önce hızı azaltırsınız. Frenleme, viraja yatmadan önce tamamlanmalıdır. Kaynak: Motosiklet Kullanıcı Kılavuzu.","hi":"SLOW चरण में आप मोड़ से पहले थ्रॉटल रोल ऑफ करके और यदि आवश्यक हो तो दोनों ब्रेक लगाकर गति कम करते हैं। मोड़ में झुकने से पहले ब्रेकिंग पूरी हो जानी चाहिए। स्रोत: Motorcycle Operator Manual।","ar":"في خطوة أبطئ تقلل السرعة قبل المنعطف بإرخاء الخانق، وعند الضرورة، تطبيق كلتا الفرملتين. يجب إتمام الفرملة قبل أن تميل في المنحنى. المصدر: دليل مشغّل الدراجة النارية."}},{"cat":"cornering","a":2,"q":{"en":"When should you reduce your speed for a curve?","es":"¿Cuándo debes reducir tu velocidad para una curva?","ru":"Когда следует снижать скорость для поворота?","tr":"Bir viraj için hızınızı ne zaman azaltmalısınız?","hi":"आपको एक मोड़ के लिए अपनी गति कब कम करनी चाहिए?","ar":"متى يجب أن تقلل سرعتك قبل منحنى؟"},"o":[{"en":"While you are leaned over in the middle of the curve","es":"Mientras estás inclinado en medio de la curva","ru":"Пока вы наклонены в середине поворота","tr":"Virajın ortasında yatmış haldeyken","hi":"जब आप मोड़ के बीच में झुके हुए हों","ar":"وأنت مائل في منتصف المنحنى"},{"en":"Only as you exit the curve","es":"Solo al salir de la curva","ru":"Только при выходе из поворота","tr":"Yalnızca virajdan çıkarken","hi":"केवल जब आप मोड़ से बाहर निकल रहे हों","ar":"فقط عند خروجك من المنحنى"},{"en":"Before you enter the curve","es":"Antes de entrar a la curva","ru":"Перед входом в поворот","tr":"Viraja girmeden önce","hi":"मोड़ में प्रवेश करने से पहले","ar":"قبل أن تدخل المنحنى"},{"en":"You should speed up entering the curve and slow at the apex","es":"Debes acelerar al entrar a la curva y reducir en el vértice","ru":"Следует ускоряться на входе в поворот и замедляться в апексе","tr":"Viraja girerken hızlanıp tepe noktasında yavaşlamalısınız","hi":"आपको मोड़ में प्रवेश करते समय गति बढ़ानी चाहिए और शीर्ष पर धीमा होना चाहिए","ar":"يجب أن تسرّع عند دخول المنحنى وتبطئ عند القمة"}],"e":{"en":"The manual stresses slowing before the turn. Adjusting speed while leaned in a curve can cause a skid or loss of control, so reduce speed before you enter it. Source: Motorcycle Operator Manual.","es":"El manual recalca reducir antes de la curva. Ajustar la velocidad mientras estás inclinado en una curva puede causar un derrape o pérdida de control, así que reduce la velocidad antes de entrar a ella. Fuente: Manual del Operador de Motocicletas.","ru":"Руководство подчёркивает замедление до поворота. Регулировка скорости в наклоне в повороте может вызвать занос или потерю управления, поэтому снижайте скорость перед входом. Источник: Руководство мотоциклиста.","tr":"Kılavuz, dönüşten önce yavaşlamayı vurgular. Bir virajda yatmışken hızı ayarlamak kayma ya da kontrol kaybına neden olabilir, bu yüzden hızı viraja girmeden önce azaltın. Kaynak: Motosiklet Kullanıcı Kılavuzu.","hi":"मैनुअल मोड़ से पहले धीमा होने पर ज़ोर देता है। मोड़ में झुके हुए गति समायोजित करने से स्किड या नियंत्रण खो सकता है, इसलिए इसमें प्रवेश करने से पहले गति कम करें। स्रोत: Motorcycle Operator Manual।","ar":"يشدد الدليل على الإبطاء قبل المنعطف. تعديل السرعة وأنت مائل في منحنى قد يسبب انزلاقًا أو فقدان التحكم، لذا قلل السرعة قبل أن تدخله. المصدر: دليل مشغّل الدراجة النارية."}},{"cat":"cornering","a":3,"q":{"en":"To make a motorcycle turn at normal riding speeds, what must happen?","es":"Para hacer girar una motocicleta a velocidades normales de conducción, ¿qué debe ocurrir?","ru":"Чтобы мотоцикл повернул на обычной скорости езды, что должно произойти?","tr":"Normal sürüş hızlarında bir motosikleti döndürmek için ne olması gerekir?","hi":"सामान्य राइडिंग गति पर मोटरसाइकिल को मोड़ने के लिए, क्या होना चाहिए?","ar":"لجعل الدراجة النارية تنعطف عند سرعات القيادة العادية، ماذا يجب أن يحدث؟"},"o":[{"en":"The handlebars must be turned toward the turn like a car's steering wheel","es":"El manillar debe girarse hacia la curva como el volante de un auto","ru":"Руль нужно повернуть в сторону поворота, как руль автомобиля","tr":"Gidon, bir otomobilin direksiyonu gibi dönüş yönüne çevrilmeli","hi":"हैंडलबार को कार के स्टीयरिंग व्हील की तरह मोड़ की ओर घुमाना चाहिए","ar":"يجب توجيه المقود نحو الانعطاف مثل عجلة قيادة السيارة"},{"en":"The rider must lean opposite the direction of the turn","es":"El conductor debe inclinarse en dirección opuesta a la curva","ru":"Мотоциклист должен наклониться в сторону, противоположную повороту","tr":"Sürücü dönüşün tersi yönde yatmalı","hi":"राइडर को मोड़ की दिशा के विपरीत झुकना चाहिए","ar":"يجب أن يميل السائق عكس اتجاه الانعطاف"},{"en":"Both feet must come off the pegs to balance","es":"Ambos pies deben salir de los estribos para mantener el equilibrio","ru":"Обе ноги должны оторваться от подножек для равновесия","tr":"Dengeyi sağlamak için iki ayak da basamaklardan ayrılmalı","hi":"संतुलन के लिए दोनों पैर पेग से हट जाने चाहिए","ar":"يجب أن ترفع كلتا القدمين عن المساند للتوازن"},{"en":"The motorcycle must lean","es":"La motocicleta debe inclinarse","ru":"Мотоцикл должен наклониться","tr":"Motosiklet yatmalı","hi":"मोटरसाइकिल को झुकना चाहिए","ar":"يجب أن تميل الدراجة النارية"}],"e":{"en":"The manual states that to turn, the motorcycle must lean. You make it lean by pressing on the handgrip in the direction of the turn. Source: Motorcycle Operator Manual.","es":"El manual indica que para girar, la motocicleta debe inclinarse. La haces inclinarse presionando la manija en la dirección de la curva. Fuente: Manual del Operador de Motocicletas.","ru":"Руководство утверждает, что для поворота мотоцикл должен наклониться. Вы заставляете его наклониться, нажимая на рукоятку руля в направлении поворота. Источник: Руководство мотоциклиста.","tr":"Kılavuz, dönmek için motosikletin yatması gerektiğini belirtir. Gidon kabzasına dönüş yönünde bastırarak onu yatırırsınız. Kaynak: Motosiklet Kullanıcı Kılavuzu.","hi":"मैनुअल बताता है कि मुड़ने के लिए, मोटरसाइकिल को झुकना चाहिए। आप इसे मोड़ की दिशा में हैंडग्रिप दबाकर झुकाते हैं। स्रोत: Motorcycle Operator Manual।","ar":"ينص الدليل على أنه للانعطاف يجب أن تميل الدراجة النارية. تجعلها تميل بالضغط على المقبض في اتجاه الانعطاف. المصدر: دليل مشغّل الدراجة النارية."}},{"cat":"cornering","a":1,"q":{"en":"The technique of pressing on the handgrip in the direction you want to go is called:","es":"La técnica de presionar la manija en la dirección hacia la que quieres ir se llama:","ru":"Техника нажатия на рукоятку руля в направлении, куда вы хотите ехать, называется:","tr":"Gitmek istediğiniz yöndeki gidon kabzasına bastırma tekniğine ne ad verilir?","hi":"जिस दिशा में आप जाना चाहते हैं उस दिशा में हैंडग्रिप दबाने की तकनीक को कहा जाता है:","ar":"تقنية الضغط على المقبض في الاتجاه الذي تريد الذهاب إليه تُسمى:"},"o":[{"en":"Trail braking","es":"Frenado en curva (trail braking)","ru":"Торможение в повороте (trail braking)","tr":"İz frenlemesi","hi":"ट्रेल ब्रेकिंग","ar":"الفرملة عند المسار"},{"en":"Countersteering","es":"Contramanillar (countersteering)","ru":"Контрруление","tr":"Ters direksiyon","hi":"काउंटरस्टीयरिंग","ar":"التوجيه العكسي"},{"en":"Throttle blipping","es":"Acelerón breve (throttle blipping)","ru":"Перегазовка (throttle blipping)","tr":"Gaz vurma","hi":"थ्रॉटल ब्लिपिंग","ar":"نبض الخانق"},{"en":"Engine braking","es":"Freno motor (engine braking)","ru":"Торможение двигателем","tr":"Motor freni","hi":"इंजन ब्रेकिंग","ar":"فرملة المحرك"}],"e":{"en":"Pressing forward on the handgrip in the direction of the turn to make the motorcycle lean is countersteering, the 'PRESS' step of the turning procedure. Source: Motorcycle Operator Manual.","es":"Presionar hacia adelante la manija en la dirección de la curva para hacer que la motocicleta se incline es contramanillar (countersteering), el paso 'PRESIONA' del procedimiento para tomar la curva. Fuente: Manual del Operador de Motocicletas.","ru":"Нажатие вперёд на рукоятку руля в направлении поворота, чтобы заставить мотоцикл наклониться, — это контрруление, шаг «НАЖМИ» процедуры прохождения поворота. Источник: Руководство мотоциклиста.","tr":"Motosikleti yatırmak için gidon kabzasına dönüş yönünde ileriye doğru bastırmak ters direksiyondur, dönüş işleminin 'BASTIR' adımıdır. Kaynak: Motosiklet Kullanıcı Kılavuzu.","hi":"मोटरसाइकिल को झुकाने के लिए मोड़ की दिशा में हैंडग्रिप पर आगे दबाना काउंटरस्टीयरिंग है, जो मुड़ने की प्रक्रिया का 'PRESS' चरण है। स्रोत: Motorcycle Operator Manual।","ar":"الضغط للأمام على المقبض في اتجاه الانعطاف لجعل الدراجة النارية تميل هو التوجيه العكسي، وهو خطوة 'اضغط' في إجراء الانعطاف. المصدر: دليل مشغّل الدراجة النارية."}},{"cat":"cornering","a":0,"q":{"en":"To make the motorcycle lean and go to the left, what should you do with the handgrips?","es":"Para hacer que la motocicleta se incline y vaya hacia la izquierda, ¿qué debes hacer con las manijas?","ru":"Чтобы заставить мотоцикл наклониться и поехать влево, что нужно сделать с рукоятками руля?","tr":"Motosikleti yatırıp sola gitmesini sağlamak için gidon kabzalarıyla ne yapmalısınız?","hi":"मोटरसाइकिल को बाईं ओर झुकाने और मोड़ने के लिए, आपको हैंडग्रिप के साथ क्या करना चाहिए?","ar":"لجعل الدراجة النارية تميل وتتجه إلى اليسار، ماذا يجب أن تفعل بالمقابض؟"},"o":[{"en":"Press the left handgrip","es":"Presionar la manija izquierda","ru":"Нажать на левую рукоятку руля","tr":"Sol gidon kabzasına bastırın","hi":"बायां हैंडग्रिप दबाएं","ar":"اضغط المقبض الأيسر"},{"en":"Press the right handgrip","es":"Presionar la manija derecha","ru":"Нажать на правую рукоятку руля","tr":"Sağ gidon kabzasına bastırın","hi":"दायां हैंडग्रिप दबाएं","ar":"اضغط المقبض الأيمن"},{"en":"Pull the left handgrip toward you","es":"Jalar la manija izquierda hacia ti","ru":"Потянуть левую рукоятку руля на себя","tr":"Sol gidon kabzasını kendinize çekin","hi":"बायां हैंडग्रिप अपनी ओर खींचें","ar":"اسحب المقبض الأيسر نحوك"},{"en":"Push both handgrips forward equally","es":"Empujar ambas manijas hacia adelante por igual","ru":"Толкнуть обе рукоятки руля вперёд одинаково","tr":"Her iki gidon kabzasına eşit şekilde ileri itin","hi":"दोनों हैंडग्रिप समान रूप से आगे धकेलें","ar":"ادفع كلا المقبضين للأمام بالتساوي"}],"e":{"en":"The manual's rule for countersteering is: press left, lean left, go left; press right, lean right, go right. Pressing the left grip makes the motorcycle lean and turn left. Source: Motorcycle Operator Manual.","es":"La regla del manual para el contramanillar es: presiona a la izquierda, inclínate a la izquierda, ve a la izquierda; presiona a la derecha, inclínate a la derecha, ve a la derecha. Presionar la manija izquierda hace que la motocicleta se incline y gire a la izquierda. Fuente: Manual del Operador de Motocicletas.","ru":"Правило контрруления в Руководстве таково: нажми влево, наклонись влево, поезжай влево; нажми вправо, наклонись вправо, поезжай вправо. Нажатие на левую рукоятку заставляет мотоцикл наклониться и повернуть влево. Источник: Руководство мотоциклиста.","tr":"Kılavuzun ters direksiyon kuralı şudur: sola bastır, sola yat, sola git; sağa bastır, sağa yat, sağa git. Sol kabzaya bastırmak motosikleti sola yatırıp döndürür. Kaynak: Motosiklet Kullanıcı Kılavuzu.","hi":"मैनुअल का काउंटरस्टीयरिंग का नियम है: बाएं दबाएं, बाएं झुकें, बाएं जाएं; दाएं दबाएं, दाएं झुकें, दाएं जाएं। बायां ग्रिप दबाने से मोटरसाइकिल बाईं ओर झुकती और मुड़ती है। स्रोत: Motorcycle Operator Manual।","ar":"قاعدة الدليل للتوجيه العكسي هي: اضغط يسارًا، ميل يسارًا، اتجه يسارًا؛ اضغط يمينًا، ميل يمينًا، اتجه يمينًا. الضغط على المقبض الأيسر يجعل الدراجة النارية تميل وتنعطف يسارًا. المصدر: دليل مشغّل الدراجة النارية."}},{"cat":"cornering","a":0,"q":{"en":"While riding through a normal curve at speed, how should the rider and motorcycle lean?","es":"Mientras conduces a través de una curva normal a velocidad, ¿cómo deben inclinarse el conductor y la motocicleta?","ru":"Во время прохождения обычного поворота на скорости как должны наклоняться мотоциклист и мотоцикл?","tr":"Hızla normal bir virajdan geçerken sürücü ve motosiklet nasıl yatmalıdır?","hi":"गति पर एक सामान्य मोड़ से गुज़रते समय, राइडर और मोटरसाइकिल को कैसे झुकना चाहिए?","ar":"أثناء القيادة عبر منحنى عادي بسرعة، كيف يجب أن يميل السائق والدراجة النارية؟"},"o":[{"en":"The rider and the motorcycle should lean together at the same angle","es":"El conductor y la motocicleta deben inclinarse juntos en el mismo ángulo","ru":"Мотоциклист и мотоцикл должны наклоняться вместе под одним углом","tr":"Sürücü ve motosiklet aynı açıyla birlikte yatmalı","hi":"राइडर और मोटरसाइकिल को एक साथ समान कोण पर झुकना चाहिए","ar":"يجب أن يميل السائق والدراجة النارية معًا بالزاوية نفسها"},{"en":"The rider should stay upright while the motorcycle leans","es":"El conductor debe permanecer vertical mientras la motocicleta se inclina","ru":"Мотоциклист должен оставаться вертикально, пока мотоцикл наклоняется","tr":"Motosiklet yatarken sürücü dik durmalı","hi":"राइडर को सीधा रहना चाहिए जबकि मोटरसाइकिल झुके","ar":"يجب أن يبقى السائق منتصبًا بينما تميل الدراجة النارية"},{"en":"The rider should lean to the outside of the turn","es":"El conductor debe inclinarse hacia el exterior de la curva","ru":"Мотоциклист должен наклоняться наружу поворота","tr":"Sürücü dönüşün dış tarafına doğru yatmalı","hi":"राइडर को मोड़ के बाहरी ओर झुकना चाहिए","ar":"يجب أن يميل السائق إلى الجانب الخارجي من الانعطاف"},{"en":"Neither the rider nor the motorcycle should lean","es":"Ni el conductor ni la motocicleta deben inclinarse","ru":"Ни мотоциклист, ни мотоцикл не должны наклоняться","tr":"Ne sürücü ne de motosiklet yatmalı","hi":"न राइडर को न मोटरसाइकिल को झुकना चाहिए","ar":"يجب ألا يميل السائق ولا الدراجة النارية"}],"e":{"en":"In normal turns the rider and motorcycle should lean together at the same angle. (Only in slow, tight turns do you keep your body upright and lean the motorcycle alone.) Source: Motorcycle Operator Manual.","es":"En curvas normales el conductor y la motocicleta deben inclinarse juntos en el mismo ángulo. (Solo en curvas lentas y cerradas mantienes el cuerpo vertical e inclinas únicamente la motocicleta.) Fuente: Manual del Operador de Motocicletas.","ru":"В обычных поворотах мотоциклист и мотоцикл должны наклоняться вместе под одним углом. (Только в медленных, тесных поворотах вы держите тело вертикально и наклоняете только мотоцикл.) Источник: Руководство мотоциклиста.","tr":"Normal dönüşlerde sürücü ve motosiklet aynı açıyla birlikte yatmalıdır. (Yalnızca yavaş, dar dönüşlerde vücudunuzu dik tutup motosikleti tek başına yatırırsınız.) Kaynak: Motosiklet Kullanıcı Kılavuzu.","hi":"सामान्य मोड़ों में राइडर और मोटरसाइकिल को एक साथ समान कोण पर झुकना चाहिए। (केवल धीमे, तंग मोड़ों में आप अपना शरीर सीधा रखते हैं और अकेले मोटरसाइकिल को झुकाते हैं।) स्रोत: Motorcycle Operator Manual।","ar":"في المنعطفات العادية يجب أن يميل السائق والدراجة النارية معًا بالزاوية نفسها. (فقط في المنعطفات البطيئة الضيقة تُبقي جسمك منتصبًا وتميل الدراجة النارية وحدها.) المصدر: دليل مشغّل الدراجة النارية."}},{"cat":"cornering","a":3,"q":{"en":"During the 'LOOK' step of a turn, where should you direct your eyes?","es":"Durante el paso 'MIRA' de una curva, ¿hacia dónde debes dirigir la vista?","ru":"Во время шага «СМОТРИ» в повороте куда следует направлять взгляд?","tr":"Bir dönüşün 'BAK' adımı sırasında gözlerinizi nereye yöneltmelisiniz?","hi":"एक मोड़ के 'LOOK' चरण के दौरान, आपको अपनी आँखें कहाँ निर्देशित करनी चाहिए?","ar":"أثناء خطوة 'انظر' في المنعطف، إلى أين يجب أن توجّه عينيك؟"},"o":[{"en":"Down at the front fender to watch the pavement","es":"Hacia abajo, al guardabarros delantero, para observar el pavimento","ru":"Вниз на переднее крыло, чтобы следить за покрытием","tr":"Zemini izlemek için ön çamurluğa doğru aşağı","hi":"सड़क देखने के लिए फ्रंट फेंडर पर नीचे","ar":"لأسفل نحو الرفرف الأمامي لمراقبة الرصيف"},{"en":"At the vehicle directly behind you in your mirrors","es":"Al vehículo que está directamente detrás de ti en tus espejos","ru":"На транспорт прямо за вами в зеркалах","tr":"Aynalarınızdan tam arkanızdaki araca","hi":"अपने मिरर में सीधे अपने पीछे वाले वाहन पर","ar":"نحو المركبة التي خلفك مباشرة في مراياك"},{"en":"At the outer edge of the road surface just ahead of your front tire","es":"Al borde exterior de la superficie de la carretera justo delante de tu llanta delantera","ru":"На внешний край дорожного покрытия прямо перед передней шиной","tr":"Ön lastiğinizin hemen önündeki yol yüzeyinin dış kenarına","hi":"अपने फ्रंट टायर के ठीक आगे सड़क की सतह के बाहरी किनारे पर","ar":"نحو الحافة الخارجية لسطح الطريق أمام إطارك الأمامي مباشرة"},{"en":"Through the turn to where you want to go, keeping your eyes level with the horizon","es":"A través de la curva hacia donde quieres ir, manteniendo los ojos al nivel del horizonte","ru":"Сквозь поворот туда, куда вы хотите попасть, держа глаза на уровне горизонта","tr":"Dönüşün içinden gitmek istediğiniz yere, gözlerinizi ufukla aynı seviyede tutarak","hi":"मोड़ के पार जहाँ आप जाना चाहते हैं, अपनी आँखें क्षितिज के स्तर पर रखते हुए","ar":"عبر المنعطف إلى حيث تريد الذهاب، مع إبقاء عينيك بمستوى الأفق"}],"e":{"en":"The LOOK step says to look through the turn to where you want to go, turning your head (not your shoulders) and keeping your eyes level with the horizon. Source: Motorcycle Operator Manual.","es":"El paso MIRA dice que mires a través de la curva hacia donde quieres ir, girando la cabeza (no los hombros) y manteniendo los ojos al nivel del horizonte. Fuente: Manual del Operador de Motocicletas.","ru":"Шаг СМОТРИ предписывает смотреть сквозь поворот туда, куда вы хотите попасть, поворачивая голову (а не плечи) и держа глаза на уровне горизонта. Источник: Руководство мотоциклиста.","tr":"BAK adımı, dönüşün içinden gitmek istediğiniz yere bakmanızı, başınızı (omuzlarınızı değil) çevirmenizi ve gözlerinizi ufukla aynı seviyede tutmanızı söyler. Kaynak: Motosiklet Kullanıcı Kılavuzu.","hi":"LOOK चरण कहता है कि मोड़ के पार जहाँ आप जाना चाहते हैं वहाँ देखें, अपना सिर (कंधे नहीं) घुमाते हुए और आँखें क्षितिज के स्तर पर रखते हुए। स्रोत: Motorcycle Operator Manual।","ar":"تقول خطوة انظر إنه يجب النظر عبر المنعطف إلى حيث تريد الذهاب، مع إدارة رأسك (لا كتفيك) وإبقاء عينيك بمستوى الأفق. المصدر: دليل مشغّل الدراجة النارية."}},{"cat":"cornering","a":2,"q":{"en":"What is the purpose of the 'ROLL' step when cornering?","es":"¿Cuál es el propósito del paso 'ACELERA' al tomar una curva?","ru":"Какова цель шага «ПРИБАВЬ ГАЗ» при прохождении поворота?","tr":"Viraj alırken 'GAZLA' adımının amacı nedir?","hi":"कॉर्नरिंग करते समय 'ROLL' चरण का उद्देश्य क्या है?","ar":"ما هو الغرض من خطوة 'لُفّ' عند الانعطاف؟"},"o":[{"en":"Roll completely off the throttle to coast through the turn","es":"Soltar por completo el acelerador para pasar la curva rodando libremente","ru":"Полностью сбросить газ, чтобы пройти поворот накатом","tr":"Dönüş boyunca boşta gitmek için gazı tamamen kapatmak","hi":"मोड़ के दौरान कोस्ट करने के लिए थ्रॉटल पूरी तरह रोल ऑफ करें","ar":"إرخاء الخانق تمامًا للانزلاق عبر المنعطف"},{"en":"Roll the bike upright before you have finished the turn","es":"Poner la moto vertical antes de haber terminado la curva","ru":"Выпрямить мотоцикл до завершения поворота","tr":"Dönüşü bitirmeden önce motosikleti dikleştirmek","hi":"मोड़ खत्म करने से पहले बाइक को सीधा खड़ा करें","ar":"جعل الدراجة منتصبة قبل أن تنهي المنعطف"},{"en":"Roll on the throttle through the turn to stabilize the motorcycle","es":"Acelerar a través de la curva para estabilizar la motocicleta","ru":"Прибавлять газ в повороте, чтобы стабилизировать мотоцикл","tr":"Motosikleti dengelemek için dönüş boyunca gazı açmak","hi":"मोटरसाइकिल को स्थिर करने के लिए मोड़ के दौरान थ्रॉटल रोल ऑन करें","ar":"لفّ الخانق عبر المنعطف لتثبيت الدراجة النارية"},{"en":"Roll on the front brake to tighten your line","es":"Aplicar el freno delantero para cerrar tu trazada","ru":"Прибавить передний тормоз, чтобы сузить траекторию","tr":"Çizginizi sıkmak için ön frene basmak","hi":"अपनी लाइन कसने के लिए फ्रंट ब्रेक रोल ऑन करें","ar":"لفّ الفرامل الأمامية لتضييق مسارك"}],"e":{"en":"The ROLL step calls for rolling on the throttle through the turn to maintain or gradually increase speed, which stabilizes the suspension and helps the motorcycle hold its line. Source: Motorcycle Operator Manual.","es":"El paso ACELERA exige acelerar a través de la curva para mantener o aumentar gradualmente la velocidad, lo que estabiliza la suspensión y ayuda a la motocicleta a mantener su trazada. Fuente: Manual del Operador de Motocicletas.","ru":"Шаг ПРИБАВЬ ГАЗ требует прибавлять газ в повороте, чтобы поддерживать или постепенно увеличивать скорость, что стабилизирует подвеску и помогает мотоциклу держать траекторию. Источник: Руководство мотоциклиста.","tr":"GAZLA adımı, hızı korumak ya da kademeli artırmak için dönüş boyunca gazı açmayı gerektirir; bu, süspansiyonu dengeler ve motosikletin çizgisini korumasına yardımcı olur. Kaynak: Motosiklet Kullanıcı Kılavuzu.","hi":"ROLL चरण मोड़ के दौरान गति बनाए रखने या क्रमशः बढ़ाने के लिए थ्रॉटल रोल ऑन करने को कहता है, जो सस्पेंशन को स्थिर करता है और मोटरसाइकिल को अपनी लाइन पर बने रहने में मदद करता है। स्रोत: Motorcycle Operator Manual।","ar":"تدعو خطوة لُفّ إلى لفّ الخانق عبر المنعطف للحفاظ على السرعة أو زيادتها تدريجيًا، مما يثبّت نظام التعليق ويساعد الدراجة النارية على الحفاظ على مسارها. المصدر: دليل مشغّل الدراجة النارية."}},{"cat":"cornering","a":1,"q":{"en":"How many paths of travel, or lane positions, does the manual say each traffic lane gives a motorcyclist?","es":"¿Cuántas trayectorias de circulación, o posiciones de carril, dice el manual que cada carril de tráfico le da a un motociclista?","ru":"Сколько траекторий движения, или положений в полосе, по словам руководства, даёт мотоциклисту каждая полоса движения?","tr":"Kılavuza göre, her trafik şeridi bir motosikletçiye kaç sürüş yolu ya da şerit konumu sunar?","hi":"मैनुअल के अनुसार हर ट्रैफ़िक लेन एक मोटरसाइकिल चालक को कितने यात्रा पथ, या लेन स्थितियाँ देती है?","ar":"كم عدد مسارات السير، أو مواضع الحارة، التي يقول الدليل إن كل حارة مرورية تمنحها لراكب الدراجة النارية؟"},"o":[{"en":"One","es":"Una","ru":"Одну","tr":"Bir","hi":"एक","ar":"واحد"},{"en":"Three","es":"Tres","ru":"Три","tr":"Üç","hi":"तीन","ar":"ثلاثة"},{"en":"Two","es":"Dos","ru":"Две","tr":"İki","hi":"दो","ar":"اثنان"},{"en":"Five","es":"Cinco","ru":"Пять","tr":"Beş","hi":"पाँच","ar":"خمسة"}],"e":{"en":"The manual explains that each traffic lane gives a motorcycle three paths of travel: the left, center, and right portions of the lane. Source: Motorcycle Operator Manual.","es":"El manual explica que cada carril de tráfico le da a una motocicleta tres trayectorias de circulación: las porciones izquierda, central y derecha del carril. Fuente: Manual del Operador de Motocicletas.","ru":"Руководство поясняет, что каждая полоса движения даёт мотоциклу три траектории движения: левую, центральную и правую части полосы. Источник: Руководство мотоциклиста.","tr":"Kılavuz, her trafik şeridinin bir motosiklete üç sürüş yolu sunduğunu açıklar: şeridin sol, orta ve sağ kısımları. Kaynak: Motosiklet Kullanıcı Kılavuzu.","hi":"मैनुअल समझाता है कि हर ट्रैफ़िक लेन एक मोटरसाइकिल को तीन यात्रा पथ देती है: लेन के बाएं, केंद्र, और दाएं हिस्से। स्रोत: Motorcycle Operator Manual।","ar":"يوضح الدليل أن كل حارة مرورية تمنح الدراجة النارية ثلاثة مسارات سير: الأجزاء اليسرى والوسطى واليمنى من الحارة. المصدر: دليل مشغّل الدراجة النارية."}},{"cat":"cornering","a":2,"q":{"en":"The three lane positions for a motorcycle correspond to which parts of the lane?","es":"Las tres posiciones de carril para una motocicleta corresponden a cuáles partes del carril?","ru":"Три положения в полосе для мотоцикла соответствуют каким частям полосы?","tr":"Bir motosiklet için üç şerit konumu, şeridin hangi kısımlarına karşılık gelir?","hi":"एक मोटरसाइकिल के लिए तीन लेन स्थितियाँ लेन के किन हिस्सों से मेल खाती हैं?","ar":"مواضع الحارة الثلاثة للدراجة النارية تقابل أي أجزاء من الحارة؟"},"o":[{"en":"Only the painted lane lines on each side","es":"Solo las líneas pintadas del carril a cada lado","ru":"Только окрашенной разметке полосы с каждой стороны","tr":"Yalnızca her iki yandaki boyalı şerit çizgileri","hi":"केवल हर तरफ की रंगी हुई लेन लाइनें","ar":"فقط خطوط الحارة المطلية على كل جانب"},{"en":"The shoulder, the center, and the oncoming lane","es":"El acotamiento, el centro y el carril en sentido contrario","ru":"Обочине, центру и встречной полосе","tr":"Banket, orta ve karşı şerit","hi":"कंधा, केंद्र, और सामने से आने वाली लेन","ar":"الكتف، والوسط، والحارة المقابلة"},{"en":"The left, center, and right thirds of the lane","es":"Los tercios izquierdo, central y derecho del carril","ru":"Левой, центральной и правой третям полосы","tr":"Şeridin sol, orta ve sağ üçte birleri","hi":"लेन के बाएं, केंद्र, और दाएं तिहाई","ar":"الأثلاث اليسرى والوسطى واليمنى من الحارة"},{"en":"The front, middle, and rear of the lane","es":"La parte delantera, media y trasera del carril","ru":"Передней, средней и задней частям полосы","tr":"Şeridin önü, ortası ve arkası","hi":"लेन के आगे, बीच, और पीछे","ar":"الجزء الأمامي والأوسط والخلفي من الحارة"}],"e":{"en":"The three paths of travel are the left third, center third, and right third of the lane. A rider chooses among them to see, be seen, and keep a space cushion. Source: Motorcycle Operator Manual.","es":"Las tres trayectorias de circulación son el tercio izquierdo, el tercio central y el tercio derecho del carril. El conductor elige entre ellas para ver, ser visto y mantener un colchón de espacio. Fuente: Manual del Operador de Motocicletas.","ru":"Три траектории движения — это левая треть, центральная треть и правая треть полосы. Мотоциклист выбирает между ними, чтобы видеть, быть видимым и сохранять запас пространства. Источник: Руководство мотоциклиста.","tr":"Üç sürüş yolu, şeridin sol üçte biri, orta üçte biri ve sağ üçte biridir. Sürücü, görmek, görülmek ve bir mesafe boşluğu korumak için bunların arasından seçim yapar. Kaynak: Motosiklet Kullanıcı Kılavuzu.","hi":"तीन यात्रा पथ लेन के बाएं तिहाई, केंद्र तिहाई, और दाएं तिहाई हैं। एक राइडर देखने, दिखने और एक स्पेस कुशन बनाए रखने के लिए इनमें से चुनता है। स्रोत: Motorcycle Operator Manual।","ar":"مسارات السير الثلاثة هي الثلث الأيسر والثلث الأوسط والثلث الأيمن من الحارة. يختار السائق من بينها ليرى، ويُرى، ويحافظ على هامش مساحة. المصدر: دليل مشغّل الدراجة النارية."}},{"cat":"cornering","a":2,"q":{"en":"Why can the center portion of a traffic lane sometimes be slippery?","es":"¿Por qué la porción central de un carril de tráfico a veces puede ser resbaladiza?","ru":"Почему центральная часть полосы движения иногда может быть скользкой?","tr":"Bir trafik şeridinin orta kısmı bazen neden kaygan olabilir?","hi":"ट्रैफ़िक लेन का केंद्रीय हिस्सा कभी-कभी फिसलन भरा क्यों हो सकता है?","ar":"لماذا يمكن للجزء الأوسط من الحارة المرورية أن يكون زلقًا أحيانًا؟"},"o":[{"en":"It is paved with a smoother material than the rest of the lane","es":"Está pavimentada con un material más liso que el resto del carril","ru":"Она вымощена более гладким материалом, чем остальная полоса","tr":"Şeridin geri kalanından daha pürüzsüz bir malzemeyle kaplanmıştır","hi":"यह बाकी लेन की तुलना में अधिक चिकनी सामग्री से बना होता है","ar":"لأنه مرصوف بمادة أنعم من بقية الحارة"},{"en":"Rain always pools in the center of the lane","es":"La lluvia siempre se acumula en el centro del carril","ru":"Дождь всегда скапливается в центре полосы","tr":"Yağmur her zaman şeridin ortasında birikir","hi":"बारिश हमेशा लेन के केंद्र में जमा होती है","ar":"لأن المطر يتجمع دائمًا في وسط الحارة"},{"en":"It collects an oily strip of drippings from cars","es":"Acumula una franja aceitosa de goteos de los autos","ru":"Там собирается масляная полоса от подтёков с машин","tr":"Otomobillerden damlayan yağlı bir şerit toplar","hi":"यह कारों की टपकती बूँदों की एक तैलीय पट्टी जमा करता है","ar":"لأنه يجمع شريطًا زيتيًا من قطرات السيارات"},{"en":"Lane paint is applied down the center of every lane","es":"La pintura del carril se aplica por el centro de cada carril","ru":"Разметка полосы наносится по центру каждой полосы","tr":"Her şeridin ortasına şerit boyası uygulanır","hi":"हर लेन के केंद्र में लेन पेंट लगाया जाता है","ar":"لأن طلاء الحارة يُطبّق في وسط كل حارة"}],"e":{"en":"The center portion can collect an oily strip from drippings left by cars. The manual notes this strip is usually no more than two feet wide and, unless the road is wet, still allows adequate traction. Source: Motorcycle Operator Manual.","es":"La porción central puede acumular una franja aceitosa de goteos dejados por los autos. El manual señala que esta franja por lo general no mide más de dos pies de ancho y, a menos que la carretera esté mojada, aún permite tracción adecuada. Fuente: Manual del Operador de Motocicletas.","ru":"В центральной части может собираться масляная полоса от подтёков, оставленных машинами. Руководство отмечает, что эта полоса обычно не шире двух футов и, если дорога не мокрая, всё равно обеспечивает достаточное сцепление. Источник: Руководство мотоциклиста.","tr":"Orta kısım, otomobillerin bıraktığı damlamalardan oluşan yağlı bir şerit toplayabilir. Kılavuz, bu şeridin genellikle iki fitten geniş olmadığını ve yol ıslak olmadıkça yine de yeterli tutuş sağladığını belirtir. Kaynak: Motosiklet Kullanıcı Kılavuzu.","hi":"केंद्रीय हिस्सा कारों द्वारा छोड़ी गई टपकती बूँदों से एक तैलीय पट्टी जमा कर सकता है। मैनुअल नोट करता है कि यह पट्टी आमतौर पर 2 फ़ुट से अधिक चौड़ी नहीं होती और, जब तक सड़क गीली न हो, फिर भी पर्याप्त ट्रैक्शन देती है। स्रोत: Motorcycle Operator Manual।","ar":"يمكن للجزء الأوسط أن يجمع شريطًا زيتيًا من القطرات التي تتركها السيارات. يشير الدليل إلى أن هذا الشريط عادةً لا يزيد عرضه عن قدمين، وما لم يكن الطريق مبللًا، فإنه لا يزال يتيح التصاقًا كافيًا. المصدر: دليل مشغّل الدراجة النارية."}},{"cat":"cornering","a":2,"q":{"en":"According to the manual, the oily strip in the center of a lane is usually no more than about:","es":"Según el manual, la franja aceitosa en el centro de un carril por lo general no mide más de aproximadamente:","ru":"Согласно руководству, масляная полоса в центре полосы движения обычно не шире примерно:","tr":"Kılavuza göre, bir şeridin ortasındaki yağlı şerit genellikle en fazla yaklaşık ne kadardır?","hi":"मैनुअल के अनुसार, एक लेन के केंद्र में तैलीय पट्टी आमतौर पर लगभग कितनी से अधिक नहीं होती:","ar":"وفقًا للدليل، فإن الشريط الزيتي في وسط الحارة عادةً لا يزيد عن نحو:"},"o":[{"en":"Six inches wide","es":"Seis pulgadas de ancho","ru":"Шести дюймов","tr":"Altı inç genişliğinde","hi":"6 इंच चौड़ी","ar":"ست بوصات عرضًا"},{"en":"Six feet wide","es":"Seis pies de ancho","ru":"Шести футов","tr":"Altı fit genişliğinde","hi":"6 फ़ुट चौड़ी","ar":"ستة أقدام عرضًا"},{"en":"Two feet wide","es":"Dos pies de ancho","ru":"Двух футов","tr":"İki fit genişliğinde","hi":"2 फ़ुट चौड़ी","ar":"قدمين عرضًا"},{"en":"The full width of the lane","es":"El ancho completo del carril","ru":"Всей ширины полосы","tr":"Şeridin tam genişliğinde","hi":"लेन की पूरी चौड़ाई","ar":"عرض الحارة الكامل"}],"e":{"en":"The manual states the oily strip that collects car drippings is usually no more than two feet wide, leaving room on either side to ride safely within the center portion. Source: Motorcycle Operator Manual.","es":"El manual indica que la franja aceitosa que acumula los goteos de los autos por lo general no mide más de dos pies de ancho, dejando espacio a cada lado para conducir de forma segura dentro de la porción central. Fuente: Manual del Operador de Motocicletas.","ru":"Руководство утверждает, что масляная полоса, собирающая подтёки с машин, обычно не шире двух футов, оставляя место по обе стороны, чтобы безопасно ехать в пределах центральной части. Источник: Руководство мотоциклиста.","tr":"Kılavuz, otomobil damlamalarını toplayan yağlı şeridin genellikle iki fitten geniş olmadığını, orta kısımda güvenle sürmek için her iki yanda yer bıraktığını belirtir. Kaynak: Motosiklet Kullanıcı Kılavuzu.","hi":"मैनुअल बताता है कि कारों की टपकती बूँदें जमा करने वाली तैलीय पट्टी आमतौर पर 2 फ़ुट से अधिक चौड़ी नहीं होती, जिससे केंद्रीय हिस्से के भीतर सुरक्षित रूप से राइड करने के लिए दोनों ओर जगह बचती है। स्रोत: Motorcycle Operator Manual।","ar":"ينص الدليل على أن الشريط الزيتي الذي يجمع قطرات السيارات عادةً لا يزيد عرضه عن قدمين، مما يترك مجالًا على أي من الجانبين للقيادة بأمان ضمن الجزء الأوسط. المصدر: دليل مشغّل الدراجة النارية."}},{"cat":"cornering","a":1,"q":{"en":"Is it safe to ride in the center portion of a lane despite the oily strip?","es":"¿Es seguro conducir en la porción central de un carril a pesar de la franja aceitosa?","ru":"Безопасно ли ехать в центральной части полосы, несмотря на масляную полосу?","tr":"Yağlı şeride rağmen bir şeridin orta kısmında sürmek güvenli midir?","hi":"तैलीय पट्टी के बावजूद लेन के केंद्रीय हिस्से में राइड करना सुरक्षित है?","ar":"هل من الآمن القيادة في الجزء الأوسط من الحارة رغم الشريط الزيتي؟"},"o":[{"en":"No, you must never ride in the center portion of any lane","es":"No, nunca debes conducir en la porción central de ningún carril","ru":"Нет, никогда нельзя ехать в центральной части любой полосы","tr":"Hayır, hiçbir şeridin orta kısmında asla sürmemelisiniz","hi":"नहीं, आपको कभी भी किसी लेन के केंद्रीय हिस्से में राइड नहीं करना चाहिए","ar":"لا، يجب ألا تقود أبدًا في الجزء الأوسط من أي حارة"},{"en":"Yes, unless the road is wet the center strip usually permits adequate traction","es":"Sí, a menos que la carretera esté mojada, la franja central por lo general permite tracción adecuada","ru":"Да, если дорога не мокрая, центральная полоса обычно обеспечивает достаточное сцепление","tr":"Evet, yol ıslak olmadıkça orta şerit genellikle yeterli tutuş sağlar","hi":"हाँ, जब तक सड़क गीली न हो, केंद्रीय पट्टी आमतौर पर पर्याप्त ट्रैक्शन देती है","ar":"نعم، ما لم يكن الطريق مبللًا، فالشريط الأوسط عادةً يتيح التصاقًا كافيًا"},{"en":"Only at night when the oil has cooled and hardened","es":"Solo de noche, cuando el aceite se ha enfriado y endurecido","ru":"Только ночью, когда масло остыло и затвердело","tr":"Yalnızca gece yağ soğuyup sertleştiğinde","hi":"केवल रात में जब तेल ठंडा होकर सख्त हो गया हो","ar":"فقط ليلًا عندما يكون الزيت قد برد وتصلّب"},{"en":"Only if you ride exactly down the middle of the oily strip","es":"Solo si conduces exactamente por el medio de la franja aceitosa","ru":"Только если ехать точно по середине масляной полосы","tr":"Yalnızca tam olarak yağlı şeridin ortasından sürerseniz","hi":"केवल यदि आप ठीक तैलीय पट्टी के बीचों-बीच राइड करें","ar":"فقط إذا قُدت تمامًا في منتصف الشريط الزيتي"}],"e":{"en":"The manual says that unless the road is wet, the average center strip permits adequate traction to ride on safely, and you can ride to the left or right of the grease strip and still be in the center portion. Source: Motorcycle Operator Manual.","es":"El manual dice que, a menos que la carretera esté mojada, la franja central promedio permite tracción adecuada para conducir con seguridad, y puedes conducir a la izquierda o a la derecha de la franja de grasa y seguir estando en la porción central. Fuente: Manual del Operador de Motocicletas.","ru":"Руководство говорит, что если дорога не мокрая, средняя центральная полоса обеспечивает достаточное сцепление для безопасной езды, и вы можете ехать левее или правее масляной полосы и всё равно находиться в центральной части. Источник: Руководство мотоциклиста.","tr":"Kılavuz, yol ıslak olmadıkça ortalama orta şeridin güvenle sürmek için yeterli tutuş sağladığını ve yağ şeridinin soluna ya da sağına sürüp yine de orta kısımda kalabileceğinizi söyler. Kaynak: Motosiklet Kullanıcı Kılavuzu.","hi":"मैनुअल कहता है कि जब तक सड़क गीली न हो, औसत केंद्रीय पट्टी सुरक्षित रूप से राइड करने के लिए पर्याप्त ट्रैक्शन देती है, और आप ग्रीस पट्टी के बाएं या दाएं राइड कर सकते हैं और फिर भी केंद्रीय हिस्से में रह सकते हैं। स्रोत: Motorcycle Operator Manual।","ar":"يقول الدليل إنه ما لم يكن الطريق مبللًا، فإن الشريط الأوسط المتوسط يتيح التصاقًا كافيًا للقيادة بأمان، ويمكنك القيادة على يسار أو يمين شريط الشحم وتبقى ضمن الجزء الأوسط. المصدر: دليل مشغّل الدراجة النارية."}},{"cat":"cornering","a":3,"q":{"en":"How should you choose which lane position to ride in?","es":"¿Cómo debes elegir en qué posición de carril conducir?","ru":"Как следует выбирать, в каком положении полосы ехать?","tr":"Hangi şerit konumunda süreceğinizi nasıl seçmelisiniz?","hi":"आपको कौन सी लेन स्थिति में राइड करना है, यह कैसे चुनना चाहिए?","ar":"كيف يجب أن تختار موضع الحارة الذي تقود فيه؟"},"o":[{"en":"Always ride in the right portion of the lane no matter the situation","es":"Conduce siempre en la porción derecha del carril sin importar la situación","ru":"Всегда ехать в правой части полосы, независимо от ситуации","tr":"Durum ne olursa olsun her zaman şeridin sağ kısmında sürün","hi":"स्थिति चाहे जो हो, हमेशा लेन के दाएं हिस्से में राइड करें","ar":"قُد دائمًا في الجزء الأيمن من الحارة مهما كان الوضع"},{"en":"Always ride exactly in the center of every lane","es":"Conduce siempre exactamente en el centro de cada carril","ru":"Всегда ехать точно по центру каждой полосы","tr":"Her zaman tam olarak her şeridin ortasında sürün","hi":"हमेशा हर लेन के ठीक केंद्र में राइड करें","ar":"قُد دائمًا في وسط كل حارة بالضبط"},{"en":"Choose the position that lets you travel fastest","es":"Elige la posición que te permita avanzar más rápido","ru":"Выбирать положение, позволяющее ехать быстрее всего","tr":"En hızlı gitmenizi sağlayan konumu seçin","hi":"वह स्थिति चुनें जो आपको सबसे तेज़ चलने दे","ar":"اختر الموضع الذي يتيح لك السير أسرع"},{"en":"Pick whatever portion of the lane best helps you see, be seen, and keep a space cushion","es":"Elige la porción del carril que mejor te ayude a ver, ser visto y mantener un colchón de espacio","ru":"Выбирать ту часть полосы, которая лучше всего помогает видеть, быть видимым и сохранять запас пространства","tr":"Görmenize, görülmenize ve bir mesafe boşluğu korumanıza en iyi yardımcı olan şerit kısmını seçin","hi":"लेन का वह हिस्सा चुनें जो आपको सबसे अच्छी तरह देखने, दिखने और एक स्पेस कुशन बनाए रखने में मदद करे","ar":"اختر الجزء من الحارة الأنسب لمساعدتك على أن ترى، وتُرى، وتحافظ على هامش مساحة"}],"e":{"en":"There is no single best lane position. The manual says to change to whatever portion of the lane is best able to help you see, be seen, and maintain an adequate space cushion as conditions change. Source: Motorcycle Operator Manual.","es":"No hay una única mejor posición de carril. El manual dice que cambies a la porción del carril que mejor te ayude a ver, ser visto y mantener un colchón de espacio adecuado a medida que cambian las condiciones. Fuente: Manual del Operador de Motocicletas.","ru":"Единого лучшего положения в полосе нет. Руководство говорит переходить в ту часть полосы, которая лучше всего помогает видеть, быть видимым и сохранять достаточный запас пространства по мере изменения условий. Источник: Руководство мотоциклиста.","tr":"Tek bir en iyi şerit konumu yoktur. Kılavuz, koşullar değiştikçe görmenize, görülmenize ve yeterli bir mesafe boşluğu korumanıza en iyi yardımcı olan şerit kısmına geçmenizi söyler. Kaynak: Motosiklet Kullanıcı Kılavuzu.","hi":"कोई एक सर्वश्रेष्ठ लेन स्थिति नहीं है। मैनुअल कहता है कि जैसे-जैसे परिस्थितियाँ बदलती हैं, लेन के उस हिस्से में बदलें जो आपको सबसे अच्छी तरह देखने, दिखने और एक पर्याप्त स्पेस कुशन बनाए रखने में मदद करे। स्रोत: Motorcycle Operator Manual।","ar":"لا يوجد موضع حارة أفضل واحد. يقول الدليل إنه يجب التغيير إلى أي جزء من الحارة هو الأقدر على مساعدتك على أن ترى، وتُرى، وتحافظ على هامش مساحة كافٍ مع تغيّر الظروف. المصدر: دليل مشغّل الدراجة النارية."}},{"cat":"cornering","a":0,"q":{"en":"If there are parked cars on your right with the danger of doors opening, which lane position is generally best?","es":"Si hay autos estacionados a tu derecha con el peligro de que se abran las puertas, ¿cuál posición de carril es generalmente la mejor?","ru":"Если справа от вас стоят припаркованные машины с опасностью открывания дверей, какое положение в полосе обычно лучше?","tr":"Sağınızda kapıların açılma tehlikesi olan park etmiş arabalar varsa, genellikle hangi şerit konumu en iyisidir?","hi":"यदि आपके दाहिनी ओर खड़ी कारें हैं और दरवाज़े खुलने का खतरा है, तो आमतौर पर कौन सी लेन स्थिति सबसे अच्छी है?","ar":"إذا كانت هناك سيارات متوقفة على يمينك مع خطر فتح الأبواب، فأي موضع حارة هو الأفضل عمومًا؟"},"o":[{"en":"The center or left portion of the lane, away from the parked cars","es":"La porción central o izquierda del carril, lejos de los autos estacionados","ru":"Центральная или левая часть полосы, в стороне от припаркованных машин","tr":"Park etmiş arabalardan uzakta, şeridin orta ya da sol kısmı","hi":"लेन का केंद्रीय या बायां हिस्सा, खड़ी कारों से दूर","ar":"الجزء الأوسط أو الأيسر من الحارة، بعيدًا عن السيارات المتوقفة"},{"en":"The right portion of the lane, close to the parked cars","es":"La porción derecha del carril, cerca de los autos estacionados","ru":"Правая часть полосы, близко к припаркованным машинам","tr":"Park etmiş arabalara yakın, şeridin sağ kısmı","hi":"लेन का दायां हिस्सा, खड़ी कारों के करीब","ar":"الجزء الأيمن من الحارة، قريبًا من السيارات المتوقفة"},{"en":"Half on the shoulder beside the parked cars","es":"A medias sobre el acotamiento junto a los autos estacionados","ru":"Наполовину на обочине рядом с припаркованными машинами","tr":"Park etmiş arabaların yanında, yarı banket","hi":"खड़ी कारों के बगल में आधा कंधे पर","ar":"نصفًا على الكتف بجانب السيارات المتوقفة"},{"en":"Wherever the oily strip is widest","es":"Donde la franja aceitosa sea más ancha","ru":"Там, где масляная полоса шире всего","tr":"Yağlı şeridin en geniş olduğu yer","hi":"जहाँ तैलीय पट्टी सबसे चौड़ी हो","ar":"حيثما يكون الشريط الزيتي أعرض"}],"e":{"en":"When a hazard such as opening car doors is on your right, the manual advises riding in the center or left portion to keep a space cushion away from the hazard on that side. Source: Motorcycle Operator Manual.","es":"Cuando hay un peligro como puertas de autos que se abren a tu derecha, el manual aconseja conducir en la porción central o izquierda para mantener un colchón de espacio lejos del peligro de ese lado. Fuente: Manual del Operador de Motocicletas.","ru":"Когда опасность, например открывающиеся двери машин, находится справа, руководство советует ехать в центральной или левой части, чтобы сохранять запас пространства в стороне от опасности с этой стороны. Источник: Руководство мотоциклиста.","tr":"Açılan araba kapıları gibi bir tehlike sağınızdayken kılavuz, o yandaki tehlikeden uzakta bir mesafe boşluğu korumak için orta ya da sol kısımda sürmeyi tavsiye eder. Kaynak: Motosiklet Kullanıcı Kılavuzu.","hi":"जब आपके दाहिनी ओर खुलते कार दरवाज़ों जैसा कोई खतरा हो, तो मैनुअल केंद्रीय या बाएं हिस्से में राइड करने की सलाह देता है ताकि उस ओर के खतरे से दूर एक स्पेस कुशन बना रहे। स्रोत: Motorcycle Operator Manual।","ar":"عندما يكون خطر مثل فتح أبواب السيارات على يمينك، ينصح الدليل بالقيادة في الجزء الأوسط أو الأيسر للحفاظ على هامش مساحة بعيدًا عن الخطر على ذلك الجانب. المصدر: دليل مشغّل الدراجة النارية."}},{"cat":"cornering","a":1,"q":{"en":"When vehicles are traveling on both sides of you, which lane position is usually best?","es":"Cuando hay vehículos circulando a ambos lados de ti, ¿cuál posición de carril suele ser la mejor?","ru":"Когда транспорт движется по обе стороны от вас, какое положение в полосе обычно лучше?","tr":"Her iki yanınızda araçlar giderken genellikle hangi şerit konumu en iyisidir?","hi":"जब वाहन आपके दोनों ओर चल रहे हों, तो आमतौर पर कौन सी लेन स्थिति सबसे अच्छी है?","ar":"عندما تسير المركبات على جانبيك، أي موضع حارة هو الأفضل عادةً؟"},"o":[{"en":"The far left portion of the lane","es":"La porción más a la izquierda del carril","ru":"Крайняя левая часть полосы","tr":"Şeridin en sol kısmı","hi":"लेन का सबसे बायां हिस्सा","ar":"الجزء الأقصى يسارًا من الحارة"},{"en":"The center portion of the lane","es":"La porción central del carril","ru":"Центральная часть полосы","tr":"Şeridin orta kısmı","hi":"लेन का केंद्रीय हिस्सा","ar":"الجزء الأوسط من الحارة"},{"en":"The far right portion of the lane","es":"La porción más a la derecha del carril","ru":"Крайняя правая часть полосы","tr":"Şeridin en sağ kısmı","hi":"लेन का सबसे दायां हिस्सा","ar":"الجزء الأقصى يمينًا من الحارة"},{"en":"Straddling the lane line nearest the slower vehicle","es":"A horcajadas sobre la línea del carril más cercana al vehículo más lento","ru":"По разметке полосы ближе к более медленному транспорту","tr":"Daha yavaş araca en yakın şerit çizgisine biniş","hi":"धीमे वाहन के सबसे नज़दीक की लेन लाइन पर सवार होकर","ar":"التمركز على خط الحارة الأقرب إلى المركبة الأبطأ"}],"e":{"en":"When vehicles are on both sides of you, the center portion of the lane is usually your best option because it keeps a cushion of space on each side. Source: Motorcycle Operator Manual.","es":"Cuando hay vehículos a ambos lados de ti, la porción central del carril suele ser tu mejor opción porque mantiene un colchón de espacio a cada lado. Fuente: Manual del Operador de Motocicletas.","ru":"Когда транспорт находится по обе стороны от вас, центральная часть полосы обычно ваш лучший вариант, потому что она сохраняет запас пространства с каждой стороны. Источник: Руководство мотоциклиста.","tr":"Her iki yanınızda araçlar varken, şeridin orta kısmı genellikle en iyi seçeneğinizdir çünkü her iki yanda bir mesafe boşluğu korur. Kaynak: Motosiklet Kullanıcı Kılavuzu.","hi":"जब वाहन आपके दोनों ओर हों, तो लेन का केंद्रीय हिस्सा आमतौर पर आपका सबसे अच्छा विकल्प होता है क्योंकि यह हर तरफ जगह का कुशन बनाए रखता है। स्रोत: Motorcycle Operator Manual।","ar":"عندما تكون المركبات على جانبيك، يكون الجزء الأوسط من الحارة عادةً خيارك الأفضل لأنه يحافظ على هامش مساحة على كل جانب. المصدر: دليل مشغّل الدراجة النارية."}},{"cat":"cornering","a":3,"q":{"en":"How does lane position relate to being seen by the driver ahead of you?","es":"¿Cómo se relaciona la posición de carril con ser visto por el conductor que va delante de ti?","ru":"Как положение в полосе связано с тем, видит ли вас водитель впереди?","tr":"Şerit konumu, önünüzdeki sürücü tarafından görülmenizle nasıl ilişkilidir?","hi":"लेन स्थिति का आपके आगे वाले ड्राइवर द्वारा देखे जाने से क्या संबंध है?","ar":"كيف يرتبط موضع الحارة برؤية السائق الذي أمامك لك؟"},"o":[{"en":"Lane position has no effect on whether drivers can see you","es":"La posición de carril no influye en si los conductores pueden verte","ru":"Положение в полосе никак не влияет на то, могут ли водители вас видеть","tr":"Şerit konumunun, sürücülerin sizi görüp görmemesinde hiçbir etkisi yoktur","hi":"लेन स्थिति का इस पर कोई प्रभाव नहीं कि ड्राइवर आपको देख सकते हैं या नहीं","ar":"موضع الحارة لا يؤثر على ما إذا كان السائقون يرونك"},{"en":"Riding on the far edge of the lane makes you most visible in mirrors","es":"Conducir en el borde más alejado del carril te hace más visible en los espejos","ru":"Езда по крайнему краю полосы делает вас наиболее заметным в зеркалах","tr":"Şeridin en dış kenarında sürmek sizi aynalarda en görünür kılar","hi":"लेन के सबसे बाहरी किनारे पर राइड करना आपको मिरर में सबसे अधिक दृश्यमान बनाता है","ar":"القيادة على الحافة القصوى للحارة تجعلك أكثر وضوحًا في المرايا"},{"en":"Being seen depends only on your headlight, not your position","es":"Ser visto depende solo de tu faro, no de tu posición","ru":"Видимость зависит только от вашей фары, а не от положения","tr":"Görülmek yalnızca farınıza bağlıdır, konumunuza değil","hi":"देखे जाना केवल आपकी हेडलाइट पर निर्भर करता है, आपकी स्थिति पर नहीं","ar":"الرؤية تعتمد فقط على مصباحك الأمامي، لا على موضعك"},{"en":"Riding in the center portion can place your image in the middle of the driver's rearview mirror where you are most likely to be seen","es":"Conducir en la porción central puede colocar tu imagen en el medio del espejo retrovisor del conductor, donde es más probable que te vea","ru":"Езда в центральной части может поместить ваше изображение в середину зеркала заднего вида водителя, где вас вероятнее всего заметят","tr":"Orta kısımda sürmek, görüntünüzü sürücünün dikiz aynasının ortasına, sizi en çok fark edebileceği yere yerleştirebilir","hi":"केंद्रीय हिस्से में राइड करना आपकी छवि को ड्राइवर के रियरव्यू मिरर के बीच में रख सकता है जहाँ आप सबसे अधिक देखे जाने की संभावना रखते हैं","ar":"القيادة في الجزء الأوسط قد تضع صورتك في منتصف مرآة الرؤية الخلفية للسائق حيث يُرجَّح أكثر أن يراك"}],"e":{"en":"The manual notes that riding in the center portion places your image in the middle of a driver's rearview mirror, the spot where a driver is most likely to notice you. Lane position is a tool to be seen. Source: Motorcycle Operator Manual.","es":"El manual señala que conducir en la porción central coloca tu imagen en el medio del espejo retrovisor de un conductor, el lugar donde es más probable que un conductor te note. La posición de carril es una herramienta para ser visto. Fuente: Manual del Operador de Motocicletas.","ru":"Руководство отмечает, что езда в центральной части помещает ваше изображение в середину зеркала заднего вида водителя — место, где водитель вероятнее всего вас заметит. Положение в полосе — это инструмент, чтобы быть видимым. Источник: Руководство мотоциклиста.","tr":"Kılavuz, orta kısımda sürmenin görüntünüzü sürücünün dikiz aynasının ortasına, bir sürücünün sizi fark etme olasılığının en yüksek olduğu noktaya yerleştirdiğini belirtir. Şerit konumu, görülmek için bir araçtır. Kaynak: Motosiklet Kullanıcı Kılavuzu.","hi":"मैनुअल नोट करता है कि केंद्रीय हिस्से में राइड करना आपकी छवि को ड्राइवर के रियरव्यू मिरर के बीच में रखता है, वह स्थान जहाँ ड्राइवर आपको नोटिस करने की सबसे अधिक संभावना रखता है। लेन स्थिति दिखने का एक साधन है। स्रोत: Motorcycle Operator Manual।","ar":"يشير الدليل إلى أن القيادة في الجزء الأوسط تضع صورتك في منتصف مرآة الرؤية الخلفية للسائق، وهو الموضع الذي يُرجَّح فيه أكثر أن يلاحظك السائق. موضع الحارة أداة لكي تُرى. المصدر: دليل مشغّل الدراجة النارية."}},{"cat":"cornering","a":0,"q":{"en":"What is the minimum following distance the manual recommends behind the vehicle ahead under normal conditions?","es":"¿Cuál es la distancia mínima de seguimiento que recomienda el manual detrás del vehículo de adelante en condiciones normales?","ru":"Какую минимальную дистанцию следования за впереди идущим транспортом рекомендует руководство в обычных условиях?","tr":"Kılavuz, normal koşullarda önünüzdeki araçtan en az ne kadar takip mesafesi önerir?","hi":"सामान्य परिस्थितियों में मैनुअल आगे वाले वाहन के पीछे न्यूनतम कितनी फॉलोइंग दूरी की सिफारिश करता है?","ar":"ما هي مسافة الاتباع الدنيا التي يوصي بها الدليل خلف المركبة الأمامية في الظروف العادية؟"},"o":[{"en":"Two seconds","es":"Dos segundos","ru":"Две секунды","tr":"İki saniye","hi":"2 सेकंड","ar":"ثانيتان"},{"en":"Half a second","es":"Medio segundo","ru":"Полсекунды","tr":"Yarım saniye","hi":"आधा सेकंड","ar":"نصف ثانية"},{"en":"One car length per 10 mph","es":"Una longitud de auto por cada 10 mph","ru":"Одна длина машины на каждые 10 миль/ч","tr":"Her 10 mil/sa için bir araç boyu","hi":"प्रति 10 mph एक कार की लंबाई","ar":"طول سيارة واحد لكل 10 ميلاً في الساعة"},{"en":"Ten seconds","es":"Diez segundos","ru":"Десять секунд","tr":"On saniye","hi":"10 सेकंड","ar":"عشر ثوانٍ"}],"e":{"en":"The manual recommends keeping a minimum of two seconds of following distance behind the vehicle ahead to give yourself room to react and stop. Source: Motorcycle Operator Manual.","es":"El manual recomienda mantener un mínimo de dos segundos de distancia de seguimiento detrás del vehículo de adelante para darte espacio para reaccionar y detenerte. Fuente: Manual del Operador de Motocicletas.","ru":"Руководство рекомендует держать минимум две секунды дистанции следования за впереди идущим транспортом, чтобы дать себе место отреагировать и остановиться. Источник: Руководство мотоциклиста.","tr":"Kılavuz, tepki vermek ve durmak için kendinize alan tanımak amacıyla önünüzdeki araçtan en az iki saniye takip mesafesi bırakmanızı önerir. Kaynak: Motosiklet Kullanıcı Kılavuzu.","hi":"मैनुअल आगे वाले वाहन के पीछे न्यूनतम 2 सेकंड की फॉलोइंग दूरी रखने की सिफारिश करता है ताकि आपको प्रतिक्रिया करने और रुकने के लिए जगह मिल सके। स्रोत: Motorcycle Operator Manual।","ar":"يوصي الدليل بالحفاظ على ثانيتين كحد أدنى من مسافة الاتباع خلف المركبة الأمامية لتمنح نفسك مجالًا للتفاعل والتوقف. المصدر: دليل مشغّل الدراجة النارية."}},{"cat":"cornering","a":3,"q":{"en":"When should you increase your following distance to more than two seconds?","es":"¿Cuándo debes aumentar tu distancia de seguimiento a más de dos segundos?","ru":"Когда следует увеличить дистанцию следования более чем до двух секунд?","tr":"Takip mesafenizi ne zaman iki saniyenin üzerine çıkarmalısınız?","hi":"आपको अपनी फॉलोइंग दूरी 2 सेकंड से अधिक कब बढ़ानी चाहिए?","ar":"متى يجب أن تزيد مسافة اتباعك إلى أكثر من ثانيتين؟"},"o":[{"en":"Only on dry, clear, open highways","es":"Solo en autopistas secas, despejadas y abiertas","ru":"Только на сухих, ясных, открытых трассах","tr":"Yalnızca kuru, açık, geniş otoyollarda","hi":"केवल सूखे, साफ़, खुले राजमार्गों पर","ar":"فقط على الطرق السريعة الجافة الصافية المفتوحة"},{"en":"Never; two seconds is always enough in every condition","es":"Nunca; dos segundos siempre es suficiente en toda condición","ru":"Никогда; двух секунд всегда достаточно в любых условиях","tr":"Asla; iki saniye her koşulda her zaman yeterlidir","hi":"कभी नहीं; 2 सेकंड हर परिस्थिति में हमेशा पर्याप्त है","ar":"أبدًا؛ فثانيتان كافيتان دائمًا في كل الظروف"},{"en":"Only when you are leading a group of riders","es":"Solo cuando lideras un grupo de conductores","ru":"Только когда вы ведёте группу мотоциклистов","tr":"Yalnızca bir sürücü grubuna liderlik ederken","hi":"केवल जब आप राइडर्स के एक समूह का नेतृत्व कर रहे हों","ar":"فقط عندما تقود مجموعة من السائقين"},{"en":"On slippery roads, in poor visibility, or in heavy traffic","es":"En carreteras resbaladizas, con poca visibilidad o con tráfico intenso","ru":"На скользких дорогах, при плохой видимости или в плотном трафике","tr":"Kaygan yollarda, kötü görüşte ya da yoğun trafikte","hi":"फिसलन भरी सड़कों पर, खराब दृश्यता में, या भारी ट्रैफ़िक में","ar":"على الطرق الزلقة، أو في الرؤية الضعيفة، أو في حركة المرور الكثيفة"}],"e":{"en":"Two seconds is the minimum under ideal conditions. The manual advises a larger cushion (three seconds or more) when the road is slippery, visibility is reduced, or traffic is heavy. Source: Motorcycle Operator Manual.","es":"Dos segundos es el mínimo en condiciones ideales. El manual aconseja un colchón mayor (tres segundos o más) cuando la carretera está resbaladiza, la visibilidad es reducida o el tráfico es intenso. Fuente: Manual del Operador de Motocicletas.","ru":"Две секунды — это минимум в идеальных условиях. Руководство советует больший запас (три секунды или больше), когда дорога скользкая, видимость снижена или трафик плотный. Источник: Руководство мотоциклиста.","tr":"İki saniye, ideal koşullarda asgari süredir. Kılavuz, yol kaygan olduğunda, görüş azaldığında ya da trafik yoğun olduğunda daha büyük bir boşluk (üç saniye ya da daha fazla) bırakmayı tavsiye eder. Kaynak: Motosiklet Kullanıcı Kılavuzu.","hi":"आदर्श परिस्थितियों में 2 सेकंड न्यूनतम है। मैनुअल सलाह देता है कि जब सड़क फिसलन भरी हो, दृश्यता कम हो, या ट्रैफ़िक भारी हो तो एक बड़ा कुशन (3 सेकंड या अधिक) रखें। स्रोत: Motorcycle Operator Manual।","ar":"ثانيتان هما الحد الأدنى في الظروف المثالية. ينصح الدليل بهامش أكبر (ثلاث ثوانٍ أو أكثر) عندما يكون الطريق زلقًا، أو الرؤية منخفضة، أو حركة المرور كثيفة. المصدر: دليل مشغّل الدراجة النارية."}},{"cat":"cornering","a":0,"q":{"en":"Why is keeping a space cushion around your motorcycle important?","es":"¿Por qué es importante mantener un colchón de espacio alrededor de tu motocicleta?","ru":"Почему важно сохранять запас пространства вокруг мотоцикла?","tr":"Motosikletinizin çevresinde bir mesafe boşluğu korumak neden önemlidir?","hi":"अपनी मोटरसाइकिल के चारों ओर एक स्पेस कुशन रखना क्यों महत्वपूर्ण है?","ar":"لماذا يُعد الحفاظ على هامش مساحة حول دراجتك النارية مهمًا؟"},"o":[{"en":"It gives you time and room to see hazards and react or maneuver safely","es":"Te da tiempo y espacio para ver peligros y reaccionar o maniobrar de forma segura","ru":"Это даёт вам время и место, чтобы видеть опасности и безопасно реагировать или маневрировать","tr":"Tehlikeleri görmeniz ve güvenle tepki verip manevra yapmanız için size zaman ve alan tanır","hi":"यह आपको खतरों को देखने और सुरक्षित रूप से प्रतिक्रिया करने या युद्धाभ्यास करने के लिए समय और जगह देता है","ar":"لأنه يمنحك وقتًا ومجالًا لرؤية المخاطر والتفاعل أو المناورة بأمان"},{"en":"It guarantees other drivers will always yield to you","es":"Garantiza que otros conductores siempre te cederán el paso","ru":"Это гарантирует, что другие водители всегда вас пропустят","tr":"Diğer sürücülerin size her zaman yol vereceğini garanti eder","hi":"यह गारंटी देता है कि अन्य ड्राइवर हमेशा आपको रास्ता देंगे","ar":"لأنه يضمن أن السائقين الآخرين سيفسحون لك دائمًا"},{"en":"It allows you to ride faster than surrounding traffic","es":"Te permite conducir más rápido que el tráfico que te rodea","ru":"Это позволяет ехать быстрее окружающего трафика","tr":"Çevredeki trafikten daha hızlı sürmenizi sağlar","hi":"यह आपको आसपास के ट्रैफ़िक से तेज़ राइड करने देता है","ar":"لأنه يتيح لك القيادة أسرع من حركة المرور المحيطة"},{"en":"It is only required when riding in a group","es":"Solo se exige al conducir en grupo","ru":"Это требуется только при езде в группе","tr":"Yalnızca grup halinde sürerken zorunludur","hi":"यह केवल समूह में राइड करते समय आवश्यक है","ar":"لأنه مطلوب فقط عند القيادة في مجموعة"}],"e":{"en":"Maintaining a space cushion on all sides gives you the time and space to spot hazards, brake, or change position to avoid trouble. The manual stresses adjusting position to keep that cushion as traffic changes. Source: Motorcycle Operator Manual.","es":"Mantener un colchón de espacio en todos los lados te da el tiempo y el espacio para detectar peligros, frenar o cambiar de posición para evitar problemas. El manual recalca ajustar la posición para mantener ese colchón a medida que cambia el tráfico. Fuente: Manual del Operador de Motocicletas.","ru":"Сохранение запаса пространства со всех сторон даёт вам время и место, чтобы заметить опасности, затормозить или сменить положение во избежание неприятностей. Руководство подчёркивает корректировку положения для сохранения этого запаса по мере изменения трафика. Источник: Руководство мотоциклиста.","tr":"Her yönde bir mesafe boşluğu korumak, tehlikeleri fark etmeniz, frenlemeniz ya da sorundan kaçınmak için konum değiştirmeniz için size zaman ve alan tanır. Kılavuz, trafik değiştikçe bu boşluğu korumak için konumu ayarlamayı vurgular. Kaynak: Motosiklet Kullanıcı Kılavuzu.","hi":"हर तरफ एक स्पेस कुशन बनाए रखना आपको खतरों को पहचानने, ब्रेक लगाने, या मुसीबत से बचने के लिए स्थिति बदलने का समय और जगह देता है। मैनुअल जैसे-जैसे ट्रैफ़िक बदलता है, उस कुशन को बनाए रखने के लिए स्थिति समायोजित करने पर ज़ोर देता है। स्रोत: Motorcycle Operator Manual।","ar":"الحفاظ على هامش مساحة على جميع الجوانب يمنحك الوقت والمجال لرصد المخاطر، أو الفرملة، أو تغيير الموضع لتفادي المشاكل. يشدد الدليل على ضبط الموضع للحفاظ على ذلك الهامش مع تغيّر حركة المرور. المصدر: دليل مشغّل الدراجة النارية."}},{"cat":"visibility","a":3,"q":{"en":"In the SEE strategy taught in the Motorcycle Operator Manual, what do the three letters stand for?","es":"En la estrategia SEE que se enseña en el Manual del Operador de Motocicletas, ¿qué representan las tres letras?","ru":"В стратегии SEE, которой учит Руководство мотоциклиста, что означают эти три буквы?","tr":"Motosiklet Kullanıcı Kılavuzu'nda öğretilen SEE stratejisinde üç harf neyi ifade eder?","hi":"Motorcycle Operator Manual में सिखाई गई SEE रणनीति में, इन तीन अक्षरों का क्या अर्थ है?","ar":"في استراتيجية SEE التي يعلّمها دليل مشغّل الدراجة النارية، ماذا ترمز الأحرف الثلاثة؟"},"o":[{"en":"Stop, Examine, Enter","es":"Detente (Stop), Examina (Examine), Entra (Enter)","ru":"Stop, Examine, Enter (Остановись, Изучи, Войди)","tr":"Dur, İncele, Gir (Stop, Examine, Enter)","hi":"Stop, Examine, Enter","ar":"توقّف، افحص، ادخل"},{"en":"Scan, Estimate, Exit","es":"Escanea (Scan), Estima (Estimate), Sal (Exit)","ru":"Scan, Estimate, Exit (Просканируй, Оцени, Выйди)","tr":"Tara, Tahmin Et, Çık (Scan, Estimate, Exit)","hi":"Scan, Estimate, Exit","ar":"امسح، قدّر، اخرج"},{"en":"Slow, Engage, Escape","es":"Reduce (Slow), Involúcrate (Engage), Escapa (Escape)","ru":"Slow, Engage, Escape (Замедлись, Включись, Уйди)","tr":"Yavaşla, Devreye Gir, Kaç (Slow, Engage, Escape)","hi":"Slow, Engage, Escape","ar":"أبطئ، اشتبك، اهرب"},{"en":"Search, Evaluate, Execute","es":"Busca (Search), Evalúa (Evaluate), Ejecuta (Execute)","ru":"Search, Evaluate, Execute (Ищи, Оценивай, Действуй)","tr":"Ara, Değerlendir, Uygula (Search, Evaluate, Execute)","hi":"Search, Evaluate, Execute","ar":"ابحث، قيّم، نفّذ"}],"e":{"en":"SEE is a three-step process for making safe decisions in traffic: Search, Evaluate, and Execute, as described in the Motorcycle Operator Manual.","es":"SEE es un proceso de tres pasos para tomar decisiones seguras en el tráfico: Busca (Search), Evalúa (Evaluate) y Ejecuta (Execute), como se describe en el Manual del Operador de Motocicletas.","ru":"SEE — это трёхэтапный процесс принятия безопасных решений в трафике: Search (Ищи), Evaluate (Оценивай) и Execute (Действуй), как описано в Руководстве мотоциклиста.","tr":"SEE, trafikte güvenli kararlar vermek için üç adımlı bir süreçtir: Ara (Search), Değerlendir (Evaluate) ve Uygula (Execute); Motosiklet Kullanıcı Kılavuzu'nda açıklandığı gibi.","hi":"SEE ट्रैफ़िक में सुरक्षित निर्णय लेने के लिए एक तीन-चरण प्रक्रिया है: Search, Evaluate, और Execute, जैसा कि Motorcycle Operator Manual में वर्णित है।","ar":"SEE هي عملية من ثلاث خطوات لاتخاذ قرارات آمنة في حركة المرور: ابحث، وقيّم، ونفّذ، كما هو موصوف في دليل مشغّل الدراجة النارية."}},{"cat":"visibility","a":0,"q":{"en":"What does the 'Search' step of the SEE strategy mainly involve?","es":"¿Qué implica principalmente el paso de 'Buscar' (Search) de la estrategia SEE?","ru":"Что в основном включает в себя шаг «Поиск» (Search) стратегии SEE?","tr":"SEE stratejisinin 'Araştır' (Search) adımı esas olarak neyi içerir?","hi":"SEE रणनीति के 'Search' (खोज) चरण में मुख्य रूप से क्या शामिल होता है?","ar":"ما الذي تتضمنه خطوة 'البحث' (Search) في استراتيجية SEE بشكل رئيسي؟"},"o":[{"en":"Scanning aggressively ahead, to the sides, and behind for possible hazards","es":"Explorar activamente hacia adelante, a los lados y hacia atrás en busca de posibles peligros","ru":"Активное сканирование дороги впереди, по сторонам и сзади для выявления возможных опасностей","tr":"Olası tehlikeler için ileriyi, yanları ve arkayı dikkatlice taramayı","hi":"संभावित खतरों के लिए आगे, बगल में और पीछे की ओर सक्रियता से नज़र दौड़ाना","ar":"المسح البصري الحثيث للأمام وإلى الجانبين وإلى الخلف بحثاً عن المخاطر المحتملة"},{"en":"Choosing a faster route to your destination","es":"Elegir una ruta más rápida hacia tu destino","ru":"Выбор более быстрого маршрута к месту назначения","tr":"Hedefinize daha hızlı bir güzergah seçmeyi","hi":"अपने गंतव्य तक तेज़ रास्ता चुनना","ar":"اختيار طريق أسرع إلى وجهتك"},{"en":"Checking your fuel and tire pressure before riding","es":"Revisar el combustible y la presión de las llantas antes de conducir","ru":"Проверку топлива и давления в шинах перед поездкой","tr":"Sürüşten önce yakıt ve lastik basıncınızı kontrol etmeyi","hi":"सवारी से पहले अपना ईंधन और टायर का दबाव जाँचना","ar":"فحص الوقود وضغط الإطارات قبل القيادة"},{"en":"Looking only directly in front of your motorcycle","es":"Mirar únicamente justo frente a tu motocicleta","ru":"Наблюдение только за тем, что находится прямо перед мотоциклом","tr":"Yalnızca motosikletinizin tam önüne bakmayı","hi":"केवल अपनी मोटरसाइकिल के ठीक सामने देखना","ar":"النظر فقط إلى الأمام مباشرةً أمام دراجتك النارية"}],"e":{"en":"In the Search step, the rider scans aggressively ahead, to the sides, and behind to spot potential hazards early, per the Motorcycle Operator Manual.","es":"En el paso de Buscar, el conductor explora activamente hacia adelante, a los lados y hacia atrás para detectar peligros potenciales con anticipación, según el Manual del Operador de Motocicletas.","ru":"На шаге «Поиск» водитель активно сканирует дорогу впереди, по сторонам и сзади, чтобы заранее заметить потенциальные опасности, согласно Руководству для водителей мотоциклов.","tr":"Araştır adımında sürücü, olası tehlikeleri erkenden fark etmek için Motosiklet Sürücü Kılavuzu'na göre ileriyi, yanları ve arkayı dikkatlice tarar.","hi":"Search चरण में सवार आगे, बगल में और पीछे की ओर सक्रियता से नज़र दौड़ाता है ताकि संभावित खतरों को जल्दी पहचान सके, जैसा कि Motorcycle Operator Manual में बताया गया है।","ar":"في خطوة البحث، يقوم السائق بالمسح البصري الحثيث للأمام وإلى الجانبين وإلى الخلف لرصد المخاطر المحتملة مبكراً، وفقاً لدليل مشغل الدراجة النارية."}},{"cat":"visibility","a":0,"q":{"en":"Which action best fits the 'Execute' step of the SEE strategy?","es":"¿Qué acción corresponde mejor al paso de 'Ejecutar' (Execute) de la estrategia SEE?","ru":"Какое действие лучше всего соответствует шагу «Выполнение» (Execute) стратегии SEE?","tr":"Hangi eylem SEE stratejisinin 'Uygula' (Execute) adımına en iyi uyar?","hi":"कौन सी क्रिया SEE रणनीति के 'Execute' (निष्पादन) चरण से सबसे अच्छी तरह मेल खाती है?","ar":"أي إجراء يتوافق بشكل أفضل مع خطوة 'التنفيذ' (Execute) في استراتيجية SEE؟"},"o":[{"en":"Carrying out your decision by adjusting speed, position, or communicating your presence","es":"Llevar a cabo tu decisión ajustando la velocidad, la posición o comunicando tu presencia","ru":"Выполнение принятого решения путём изменения скорости, положения или обозначения своего присутствия","tr":"Hızınızı, konumunuzu ayarlayarak veya varlığınızı belirterek kararınızı hayata geçirmek","hi":"गति, स्थिति को समायोजित करके या अपनी उपस्थिति बताकर अपने निर्णय को अमल में लाना","ar":"تنفيذ قرارك عبر تعديل السرعة أو الموضع أو الإبلاغ عن وجودك"},{"en":"Thinking about how hazards might interact with one another","es":"Pensar en cómo los peligros podrían interactuar entre sí","ru":"Размышление о том, как опасности могут взаимодействовать друг с другом","tr":"Tehlikelerin birbirleriyle nasıl etkileşebileceğini düşünmek","hi":"सोचना कि खतरे एक-दूसरे के साथ कैसे टकरा सकते हैं","ar":"التفكير في كيفية تفاعل المخاطر مع بعضها البعض"},{"en":"Deciding which gear to keep your motorcycle parked in","es":"Decidir en qué cambio dejar tu motocicleta estacionada","ru":"Выбор передачи, на которой держать мотоцикл припаркованным","tr":"Motosikletinizi hangi viteste park edeceğinize karar vermek","hi":"यह तय करना कि अपनी मोटरसाइकिल को किस गियर में पार्क रखें","ar":"تحديد الترس الذي تُبقي عليه دراجتك النارية متوقفة"},{"en":"Searching the road far ahead for stopped traffic","es":"Buscar muy adelante en la vía si hay tráfico detenido","ru":"Поиск остановившегося транспорта далеко впереди на дороге","tr":"Durmuş trafik için yolun çok ilerisini taramak","hi":"रुकी हुई ट्रैफ़िक के लिए सड़क पर बहुत दूर तक खोजना","ar":"البحث في الطريق إلى الأمام البعيد عن حركة مرور متوقفة"}],"e":{"en":"Execute means carrying out your decision-adjusting speed or position and communicating with lights or horn, as described in the Motorcycle Operator Manual.","es":"Ejecutar significa llevar a cabo tu decisión —ajustar la velocidad o la posición y comunicarte con las luces o la bocina—, como se describe en el Manual del Operador de Motocicletas.","ru":"«Выполнение» означает реализацию принятого решения — изменение скорости или положения и обозначение своего присутствия светом или сигналом, как описано в Руководстве для водителей мотоциклов.","tr":"Uygula, kararınızı hayata geçirmek demektir; Motosiklet Sürücü Kılavuzu'nda açıklandığı gibi hızınızı veya konumunuzu ayarlamak ve farlar ya da kornayla iletişim kurmaktır.","hi":"Execute का मतलब है अपने निर्णय को अमल में लाना—गति या स्थिति को समायोजित करना और लाइट या हॉर्न से संवाद करना, जैसा कि Motorcycle Operator Manual में वर्णित है।","ar":"يعني التنفيذ تنفيذ قرارك عبر تعديل السرعة أو الموضع والإبلاغ عن وجودك بالأضواء أو البوق، كما هو موضح في دليل مشغل الدراجة النارية."}},{"cat":"visibility","a":2,"q":{"en":"According to the Motorcycle Operator Manual, where does the greatest potential for conflict with other traffic occur?","es":"Según el Manual del Operador de Motocicletas, ¿dónde ocurre el mayor potencial de conflicto con otro tráfico?","ru":"Согласно Руководству для водителей мотоциклов, где возникает наибольшая вероятность конфликта с другим транспортом?","tr":"Motosiklet Sürücü Kılavuzu'na göre, diğer trafikle çatışma potansiyeli en çok nerede ortaya çıkar?","hi":"Motorcycle Operator Manual के अनुसार, अन्य ट्रैफ़िक के साथ टकराव की सबसे अधिक संभावना कहाँ होती है?","ar":"وفقاً لدليل مشغل الدراجة النارية، أين تحدث أكبر احتمالية للتعارض مع حركة المرور الأخرى؟"},"o":[{"en":"On long, straight rural highways","es":"En carreteras rurales largas y rectas","ru":"На длинных прямых сельских шоссе","tr":"Uzun, düz kırsal otoyollarda","hi":"लंबे, सीधे ग्रामीण राजमार्गों पर","ar":"على الطرق السريعة الريفية الطويلة والمستقيمة"},{"en":"In parking lots while walking the bike","es":"En estacionamientos, mientras caminas con la moto","ru":"На парковках при проводке мотоцикла","tr":"Otoparklarda motosikleti iterken","hi":"पार्किंग लॉट में बाइक को पैदल ले जाते समय","ar":"في مواقف السيارات أثناء دفع الدراجة سيراً"},{"en":"At intersections","es":"En las intersecciones","ru":"На перекрёстках","tr":"Kavşaklarda","hi":"चौराहों पर","ar":"عند التقاطعات"},{"en":"On freeway on-ramps merging right","es":"En las rampas de acceso a la autopista al incorporarse por la derecha","ru":"На съездах на автомагистраль при перестроении вправо","tr":"Sağa katılan otoyol giriş rampalarında","hi":"दाईं ओर मिलने वाली फ़्रीवे ऑन-रैंप पर","ar":"على منحدرات الدخول إلى الطرق السريعة عند الاندماج يميناً"}],"e":{"en":"The manual states the greatest potential for conflict between a rider and other traffic is at intersections, where drivers often violate the rider's right-of-way.","es":"El manual indica que el mayor potencial de conflicto entre un conductor y otro tráfico se da en las intersecciones, donde los conductores a menudo violan el derecho de paso del motociclista.","ru":"В Руководстве указано, что наибольшая вероятность конфликта между водителем мотоцикла и другим транспортом возникает на перекрёстках, где водители часто нарушают преимущественное право проезда мотоциклиста.","tr":"Kılavuz, bir sürücü ile diğer trafik arasındaki çatışma potansiyelinin en çok, sürücülerin çoğu zaman sürücünün geçiş üstünlüğünü ihlal ettiği kavşaklarda olduğunu belirtir.","hi":"मैनुअल बताता है कि सवार और अन्य ट्रैफ़िक के बीच टकराव की सबसे अधिक संभावना चौराहों पर होती है, जहाँ चालक अक्सर सवार के रास्ते के अधिकार का उल्लंघन करते हैं।","ar":"ينص الدليل على أن أكبر احتمالية للتعارض بين السائق وحركة المرور الأخرى تكون عند التقاطعات، حيث كثيراً ما ينتهك السائقون حق أولوية المرور الخاص بسائق الدراجة."}},{"cat":"visibility","a":1,"q":{"en":"Which vehicle movement is identified by the manual as one of the biggest dangers to a motorcyclist at an intersection?","es":"¿Qué movimiento de vehículo identifica el manual como uno de los mayores peligros para un motociclista en una intersección?","ru":"Какой манёвр транспортного средства Руководство определяет как одну из самых больших опасностей для мотоциклиста на перекрёстке?","tr":"Kılavuz tarafından kavşakta bir motosikletliye yönelik en büyük tehlikelerden biri olarak hangi araç hareketi tanımlanmıştır?","hi":"मैनुअल के अनुसार, चौराहे पर मोटरसाइकिल चालक के लिए सबसे बड़े खतरों में से एक के रूप में कौन सी वाहन गतिविधि पहचानी गई है?","ar":"أي حركة مركبة يحددها الدليل بوصفها من أكبر المخاطر على سائق الدراجة النارية عند التقاطع؟"},"o":[{"en":"A car parallel parking on the right","es":"Un auto estacionándose en paralelo a la derecha","ru":"Автомобиль, паркующийся параллельно справа","tr":"Sağda paralel park eden bir araba","hi":"दाईं ओर समानांतर पार्क करती हुई कार","ar":"سيارة تركن بشكل موازٍ على اليمين"},{"en":"A car turning left in front of you","es":"Un auto que gira a la izquierda frente a ti","ru":"Автомобиль, поворачивающий налево перед вами","tr":"Önünüzde sola dönen bir araba","hi":"आपके सामने बाएँ मुड़ती हुई कार","ar":"سيارة تنعطف يساراً أمامك"},{"en":"A car slowing down well ahead of you","es":"Un auto que reduce la velocidad bastante adelante de ti","ru":"Автомобиль, замедляющийся далеко впереди вас","tr":"Çok ilerinizde yavaşlayan bir araba","hi":"आपसे काफी आगे धीमी होती हुई कार","ar":"سيارة تبطئ على بُعد جيد أمامك"},{"en":"A car backing slowly out of a driveway behind you","es":"Un auto que retrocede lentamente saliendo de una entrada detrás de ti","ru":"Автомобиль, медленно выезжающий задним ходом из проезда позади вас","tr":"Arkanızda bir garaj yolundan yavaşça geri geri çıkan bir araba","hi":"आपके पीछे ड्राइववे से धीरे-धीरे बैक होती हुई कार","ar":"سيارة ترجع للخلف ببطء خارجة من ممر خاص خلفك"}],"e":{"en":"The Motorcycle Operator Manual warns that cars turning left in front of you are among the biggest dangers, because drivers often fail to see the rider.","es":"El Manual del Operador de Motocicletas advierte que los autos que giran a la izquierda frente a ti están entre los mayores peligros, porque los conductores a menudo no ven al motociclista.","ru":"Руководство для водителей мотоциклов предупреждает, что автомобили, поворачивающие налево перед вами, относятся к числу самых больших опасностей, поскольку водители часто не замечают мотоциклиста.","tr":"Motosiklet Sürücü Kılavuzu, önünüzde sola dönen arabaların en büyük tehlikeler arasında olduğu konusunda uyarır; çünkü sürücüler çoğu zaman motosikletliyi görmezler.","hi":"Motorcycle Operator Manual चेतावनी देता है कि आपके सामने बाएँ मुड़ती हुई कारें सबसे बड़े खतरों में से एक हैं, क्योंकि चालक अक्सर सवार को देख नहीं पाते।","ar":"يحذر دليل مشغل الدراجة النارية من أن السيارات التي تنعطف يساراً أمامك من أكبر المخاطر، لأن السائقين كثيراً ما يفشلون في رؤية سائق الدراجة."}},{"cat":"visibility","a":2,"q":{"en":"The Motorcycle Operator Manual says that more than half of car-motorcycle crashes are caused by what?","es":"El Manual del Operador de Motocicletas dice que más de la mitad de los choques entre autos y motocicletas son causados por ¿qué?","ru":"Руководство для водителей мотоциклов утверждает, что более половины столкновений автомобилей с мотоциклами вызваны чем?","tr":"Motosiklet Sürücü Kılavuzu, araba-motosiklet kazalarının yarısından fazlasının neyin yüzünden olduğunu söyler?","hi":"Motorcycle Operator Manual कहता है कि कार-मोटरसाइकिल दुर्घटनाओं में से आधे से अधिक किस कारण से होती हैं?","ar":"يقول دليل مشغل الدراجة النارية إن أكثر من نصف حوادث التصادم بين السيارات والدراجات النارية يسببها ماذا؟"},"o":[{"en":"Riders speeding through yellow lights","es":"Motociclistas que pasan a toda velocidad las luces amarillas","ru":"Мотоциклистами, проезжающими на жёлтый сигнал на высокой скорости","tr":"Sürücülerin sarı ışıkta hızla geçmesi","hi":"सवार पीली बत्तियों से तेज़ गुज़रना","ar":"تجاوز السائقين الإشارات الصفراء بسرعة"},{"en":"Riders following too closely behind cars","es":"Motociclistas que siguen demasiado cerca detrás de los autos","ru":"Мотоциклистами, слишком близко следующими за автомобилями","tr":"Sürücülerin arabaları çok yakından takip etmesi","hi":"सवार कारों के बहुत पास-पास चलना","ar":"سير السائقين قريباً جداً خلف السيارات"},{"en":"Drivers entering a rider's right-of-way","es":"Conductores que invaden el derecho de paso de un motociclista","ru":"Водителями, въезжающими в зону преимущественного права мотоциклиста","tr":"Sürücülerin bir sürücünün geçiş üstünlüğüne girmesi","hi":"चालक सवार के रास्ते के अधिकार में प्रवेश करना","ar":"دخول السائقين إلى حق أولوية المرور الخاص بسائق الدراجة"},{"en":"Mechanical failures on the motorcycle","es":"Fallas mecánicas en la motocicleta","ru":"Механическими поломками мотоцикла","tr":"Motosiklette meydana gelen mekanik arızalar","hi":"मोटरसाइकिल में यांत्रिक खराबी","ar":"الأعطال الميكانيكية في الدراجة النارية"}],"e":{"en":"The manual reports that over half of motorcycle/car crashes are caused by drivers entering the rider's right-of-way, often by turning left in front of the rider.","es":"El manual informa que más de la mitad de los choques entre motocicletas y autos son causados por conductores que invaden el derecho de paso del motociclista, a menudo al girar a la izquierda frente a él.","ru":"Руководство сообщает, что более половины столкновений мотоциклов с автомобилями вызваны водителями, въезжающими в зону преимущественного права мотоциклиста, часто при повороте налево перед ним.","tr":"Kılavuz, motosiklet/araba kazalarının yarısından fazlasının, sürücülerin çoğu zaman sürücünün önünde sola dönerek onun geçiş üstünlüğüne girmesinden kaynaklandığını bildirir.","hi":"मैनुअल बताता है कि आधे से अधिक मोटरसाइकिल/कार दुर्घटनाएँ चालकों द्वारा सवार के रास्ते के अधिकार में प्रवेश करने से होती हैं, अक्सर सवार के सामने बाएँ मुड़कर।","ar":"يفيد الدليل بأن أكثر من نصف حوادث التصادم بين الدراجات النارية والسيارات يسببها دخول السائقين إلى حق أولوية المرور الخاص بسائق الدراجة، غالباً بالانعطاف يساراً أمام السائق."}},{"cat":"visibility","a":2,"q":{"en":"What does the Motorcycle Operator Manual advise about relying on eye contact with a driver?","es":"¿Qué aconseja el Manual del Operador de Motocicletas sobre confiar en el contacto visual con un conductor?","ru":"Что Руководство для водителей мотоциклов советует по поводу того, чтобы полагаться на зрительный контакт с водителем?","tr":"Motosiklet Sürücü Kılavuzu, bir sürücüyle göz teması kurmaya güvenmek konusunda ne tavsiye eder?","hi":"Motorcycle Operator Manual चालक के साथ नज़र मिलाने पर भरोसा करने के बारे में क्या सलाह देता है?","ar":"بماذا ينصح دليل مشغل الدراجة النارية بشأن الاعتماد على التواصل البصري مع السائق؟"},"o":[{"en":"Eye contact guarantees the driver has seen you","es":"El contacto visual garantiza que el conductor te ha visto","ru":"Зрительный контакт гарантирует, что водитель вас увидел","tr":"Göz teması, sürücünün sizi gördüğünü garanti eder","hi":"नज़र मिलाना इस बात की गारंटी देता है कि चालक ने आपको देख लिया है","ar":"التواصل البصري يضمن أن السائق قد رآك"},{"en":"Eye contact replaces the need to use your headlight","es":"El contacto visual reemplaza la necesidad de usar tu faro","ru":"Зрительный контакт заменяет необходимость использовать фару","tr":"Göz teması, farınızı kullanma ihtiyacının yerini tutar","hi":"नज़र मिलाना आपके हेडलाइट का उपयोग करने की आवश्यकता को बदल देता है","ar":"التواصل البصري يغني عن الحاجة لاستخدام مصباحك الأمامي"},{"en":"Never count on eye contact as a sign the driver will yield","es":"Nunca confíes en el contacto visual como señal de que el conductor cederá el paso","ru":"Никогда не рассчитывайте на зрительный контакт как на признак того, что водитель уступит дорогу","tr":"Sürücünün yol vereceğinin işareti olarak asla göz temasına güvenmeyin","hi":"नज़र मिलाने को कभी भी इस संकेत के रूप में न लें कि चालक रास्ता देगा","ar":"لا تعتمد أبداً على التواصل البصري كعلامة على أن السائق سيفسح لك الطريق"},{"en":"Only make eye contact with drivers turning right","es":"Haz contacto visual solo con los conductores que giran a la derecha","ru":"Устанавливайте зрительный контакт только с водителями, поворачивающими направо","tr":"Yalnızca sağa dönen sürücülerle göz teması kurun","hi":"केवल दाएँ मुड़ रहे चालकों से नज़र मिलाएँ","ar":"تواصل بصرياً فقط مع السائقين الذين ينعطفون يميناً"}],"e":{"en":"The manual cautions never to count on eye contact; a driver may look right at a motorcyclist and still fail to truly 'see' the rider.","es":"El manual advierte que nunca se debe confiar en el contacto visual; un conductor puede mirar directamente a un motociclista y aun así no 'ver' realmente al conductor.","ru":"Руководство предупреждает: никогда не рассчитывайте на зрительный контакт; водитель может смотреть прямо на мотоциклиста и всё равно по-настоящему его не «увидеть».","tr":"Kılavuz, asla göz temasına güvenmemek konusunda uyarır; bir sürücü doğrudan motosikletliye bakıyor olsa bile yine de sürücüyü gerçekten 'görememiş' olabilir.","hi":"मैनुअल चेतावनी देता है कि नज़र मिलाने पर कभी भरोसा न करें; एक चालक मोटरसाइकिल चालक की ओर सीधे देख सकता है और फिर भी सवार को वास्तव में 'देख' नहीं पाता।","ar":"يحذر الدليل من الاعتماد أبداً على التواصل البصري؛ فقد ينظر السائق إلى سائق الدراجة مباشرةً ومع ذلك يفشل في 'رؤيته' حقاً."}},{"cat":"visibility","a":3,"q":{"en":"According to the manual, what is the single best way to help others see your motorcycle?","es":"Según el manual, ¿cuál es la mejor manera de ayudar a que otros vean tu motocicleta?","ru":"Согласно Руководству, какой единственный лучший способ помочь другим увидеть ваш мотоцикл?","tr":"Kılavuza göre, başkalarının motosikletinizi görmesine yardımcı olmanın tek en iyi yolu nedir?","hi":"मैनुअल के अनुसार, दूसरों को आपकी मोटरसाइकिल दिखाने में मदद करने का सबसे अच्छा एकमात्र तरीका क्या है?","ar":"وفقاً للدليل، ما هي الطريقة الوحيدة الأفضل لمساعدة الآخرين على رؤية دراجتك النارية؟"},"o":[{"en":"Rev your engine loudly at intersections","es":"Acelerar el motor ruidosamente en las intersecciones","ru":"Громко газовать двигателем на перекрёстках","tr":"Kavşaklarda motorunuzu gürültülü bir şekilde gazlamak","hi":"चौराहों पर अपने इंजन को ज़ोर से रेव करना","ar":"إصدار صوت محرك عالٍ عند التقاطعات"},{"en":"Ride with your turn signal blinking continuously","es":"Conducir con la direccional parpadeando continuamente","ru":"Ехать с постоянно мигающим указателем поворота","tr":"Sinyalinizi sürekli yanıp sönecek şekilde sürmek","hi":"अपने टर्न सिग्नल को लगातार ब्लिंक करते हुए चलाना","ar":"القيادة مع إبقاء إشارة الانعطاف وامضة باستمرار"},{"en":"Stay in the far right edge of every lane","es":"Mantenerte en el extremo derecho de cada carril","ru":"Держаться у крайнего правого края каждой полосы","tr":"Her şeritin en sağ kenarında kalmak","hi":"हर लेन के बिल्कुल दाएँ किनारे पर रहना","ar":"البقاء في الحافة اليمنى القصوى من كل مسار"},{"en":"Keep your headlight on at all times","es":"Mantener tu faro encendido en todo momento","ru":"Держать фару включённой всё время","tr":"Farınızı her zaman açık tutmak","hi":"हर समय अपनी हेडलाइट चालू रखना","ar":"إبقاء مصباحك الأمامي مضاءً في جميع الأوقات"}],"e":{"en":"The Motorcycle Operator Manual states the best way to help others see you is to keep the headlight on at all times, day and night.","es":"El Manual del Operador de Motocicletas indica que la mejor manera de ayudar a que otros te vean es mantener el faro encendido en todo momento, de día y de noche.","ru":"Руководство для водителей мотоциклов гласит, что лучший способ помочь другим увидеть вас — держать фару включённой всё время, днём и ночью.","tr":"Motosiklet Sürücü Kılavuzu, başkalarının sizi görmesine yardımcı olmanın en iyi yolunun, farı gece gündüz her zaman açık tutmak olduğunu belirtir.","hi":"Motorcycle Operator Manual कहता है कि दूसरों को आपको देखने में मदद करने का सबसे अच्छा तरीका है दिन और रात हर समय हेडलाइट चालू रखना।","ar":"ينص دليل مشغل الدراجة النارية على أن أفضل طريقة لمساعدة الآخرين على رؤيتك هي إبقاء المصباح الأمامي مضاءً في جميع الأوقات، ليلاً ونهاراً."}},{"cat":"visibility","a":1,"q":{"en":"Studies cited in the manual show that a motorcycle running its headlight during the day is how much more likely to be noticed?","es":"Según los estudios citados en el manual, una motocicleta con el faro encendido durante el día ¿cuánto más probable es que sea notada?","ru":"Согласно исследованиям, упомянутым в Руководстве, насколько более заметным становится мотоцикл с включённой фарой днём?","tr":"Kılavuzda atıfta bulunulan çalışmalar, gündüz farını açık tutan bir motosikletin ne kadar daha fazla fark edilme olasılığı olduğunu gösterir?","hi":"मैनुअल में उद्धृत अध्ययन दिखाते हैं कि दिन में अपनी हेडलाइट चलाने वाली मोटरसाइकिल पर ध्यान दिए जाने की संभावना कितनी अधिक होती है?","ar":"تُظهر الدراسات المذكورة في الدليل أن الدراجة النارية التي تُشغّل مصباحها الأمامي خلال النهار يزداد احتمال ملاحظتها بأي قدر؟"},"o":[{"en":"About the same as with no light","es":"Casi lo mismo que sin luz","ru":"Примерно так же, как и без света","tr":"Hiç ışık olmamasıyla yaklaşık aynı","hi":"कोई लाइट न होने जितनी ही लगभग","ar":"تقريباً نفس القدر كما لو لم يكن هناك ضوء"},{"en":"About twice as likely to be noticed","es":"Cerca del doble de probable de ser notada","ru":"Примерно вдвое более заметным","tr":"Yaklaşık iki kat daha fazla fark edilme olasılığı","hi":"लगभग दोगुनी संभावना से ध्यान दिया जाना","ar":"تقريباً ضعف احتمال ملاحظتها"},{"en":"Slightly less likely to be noticed","es":"Ligeramente menos probable de ser notada","ru":"Чуть менее заметным","tr":"Biraz daha az fark edilme olasılığı","hi":"थोड़ी कम ध्यान दिए जाने की संभावना","ar":"احتمال أقل قليلاً لملاحظتها"},{"en":"Roughly ten times more likely to be noticed","es":"Aproximadamente diez veces más probable de ser notada","ru":"Примерно в десять раз более заметным","tr":"Kabaca on kat daha fazla","hi":"लगभग दस गुना अधिक संभावना","ar":"نحو عشرة أضعاف احتمال ملاحظتها"}],"e":{"en":"The manual notes that studies show a motorcycle with its headlight on during the day is about twice as likely to be noticed by other drivers.","es":"El manual señala que los estudios muestran que una motocicleta con el faro encendido durante el día tiene cerca del doble de probabilidad de ser notada por otros conductores.","ru":"Руководство отмечает, что, согласно исследованиям, мотоцикл с включённой фарой днём примерно вдвое более заметен для других водителей.","tr":"Kılavuz, çalışmaların gündüz farı açık olan bir motosikletin diğer sürücüler tarafından yaklaşık iki kat daha fazla fark edilme olasılığı olduğunu gösterdiğini belirtir.","hi":"मैनुअल बताता है कि अध्ययन दिखाते हैं कि दिन में अपनी हेडलाइट चालू रखने वाली मोटरसाइकिल पर अन्य चालकों द्वारा ध्यान दिए जाने की संभावना लगभग दोगुनी होती है।","ar":"يشير الدليل إلى أن الدراسات تُظهر أن الدراجة النارية التي يكون مصباحها الأمامي مضاءً خلال النهار يزداد احتمال ملاحظتها من قبل السائقين الآخرين بنحو الضعف."}},{"cat":"visibility","a":2,"q":{"en":"What clothing does the Motorcycle Operator Manual recommend to help you be seen?","es":"¿Qué vestimenta recomienda el Manual del Operador de Motocicletas para ayudar a que te vean?","ru":"Какую одежду рекомендует Руководство для водителей мотоциклов, чтобы вас было видно?","tr":"Motosiklet Sürücü Kılavuzu, görülmenize yardımcı olması için hangi kıyafeti önerir?","hi":"Motorcycle Operator Manual आपको दिखने में मदद करने के लिए कौन से कपड़ों की सिफ़ारिश करता है?","ar":"ما الملابس التي يوصي بها دليل مشغل الدراجة النارية لمساعدتك على أن تكون مرئياً؟"},"o":[{"en":"Dark, non-reflective clothing that resists dirt","es":"Ropa oscura y no reflectante que resista la suciedad","ru":"Тёмную, нессветоотражающую одежду, устойчивую к загрязнению","tr":"Koyu renkli, yansıtıcı olmayan ve kire dayanıklı kıyafet","hi":"गहरे रंग के, बिना परावर्तक कपड़े जो गंदगी से बचते हों","ar":"ملابس داكنة غير عاكسة تقاوم الأوساخ"},{"en":"Loose camouflage gear that blends with surroundings","es":"Ropa de camuflaje holgada que se mezcle con el entorno","ru":"Свободную камуфляжную экипировку, сливающуюся с окружением","tr":"Çevreyle kaynaşan bol kamuflaj giysi","hi":"ढीले छलावरण वाले कपड़े जो आसपास के माहौल में घुल-मिल जाएँ","ar":"ملابس تمويه فضفاضة تندمج مع المحيط"},{"en":"Bright-colored, reflective clothing such as a helmet and jacket or vest","es":"Ropa de colores brillantes y reflectante, como un casco y una chaqueta o chaleco","ru":"Яркую светоотражающую одежду, например шлем и куртку или жилет","tr":"Kask ve ceket ya da yelek gibi parlak renkli, yansıtıcı kıyafet","hi":"चमकीले रंग के, परावर्तक कपड़े जैसे हेलमेट और जैकेट या वेस्ट","ar":"ملابس زاهية الألوان وعاكسة مثل خوذة وسترة أو صدرية"},{"en":"Only black leather for maximum protection","es":"Solo cuero negro para máxima protección","ru":"Только чёрную кожу для максимальной защиты","tr":"Maksimum koruma için yalnızca siyah deri","hi":"अधिकतम सुरक्षा के लिए केवल काला चमड़ा","ar":"الجلد الأسود فقط لأقصى حماية"}],"e":{"en":"The manual recommends bright-colored, reflective clothing-helmet and a jacket or vest-as the best way to make yourself conspicuous to other drivers.","es":"El manual recomienda ropa de colores brillantes y reflectante —casco y una chaqueta o chaleco— como la mejor manera de hacerte visible ante otros conductores.","ru":"Руководство рекомендует яркую светоотражающую одежду — шлем и куртку или жилет — как лучший способ сделать себя заметным для других водителей.","tr":"Kılavuz, kendinizi diğer sürücülere belli etmenin en iyi yolu olarak parlak renkli, yansıtıcı kıyafeti (kask ve ceket ya da yelek) önerir.","hi":"मैनुअल चमकीले रंग के, परावर्तक कपड़ों—हेलमेट और जैकेट या वेस्ट—की सिफ़ारिश करता है, जो अन्य चालकों के लिए खुद को स्पष्ट दिखाने का सबसे अच्छा तरीका है।","ar":"يوصي الدليل بملابس زاهية الألوان وعاكسة — خوذة وسترة أو صدرية — بوصفها أفضل طريقة لجعل نفسك واضحاً للسائقين الآخرين."}},{"cat":"visibility","a":3,"q":{"en":"Why does the manual advise wearing reflective material on the sides of your gear or helmet?","es":"¿Por qué aconseja el manual usar material reflectante en los lados de tu equipo o casco?","ru":"Почему Руководство советует носить светоотражающий материал по бокам экипировки или шлема?","tr":"Kılavuz neden ekipmanınızın veya kaskınızın yanlarına yansıtıcı malzeme takmanızı tavsiye eder?","hi":"मैनुअल आपके गियर या हेलमेट के किनारों पर परावर्तक सामग्री पहनने की सलाह क्यों देता है?","ar":"لماذا ينصح الدليل بارتداء مواد عاكسة على جانبي معداتك أو خوذتك؟"},"o":[{"en":"It keeps the rider cooler in hot weather","es":"Mantiene al conductor más fresco en clima caluroso","ru":"Это сохраняет водителю прохладу в жаркую погоду","tr":"Sürücüyü sıcak havada daha serin tutar","hi":"यह गर्म मौसम में सवार को ठंडा रखता है","ar":"تُبقي السائق أكثر برودة في الطقس الحار"},{"en":"It reduces wind noise at highway speeds","es":"Reduce el ruido del viento a velocidades de autopista","ru":"Это снижает шум ветра на высокой скорости","tr":"Otoyol hızlarında rüzgar gürültüsünü azaltır","hi":"यह राजमार्ग की गति पर हवा का शोर कम करता है","ar":"تقلل ضوضاء الرياح عند سرعات الطرق السريعة"},{"en":"It improves the motorcycle's fuel economy","es":"Mejora el rendimiento de combustible de la motocicleta","ru":"Это улучшает экономичность расхода топлива мотоцикла","tr":"Motosikletin yakıt ekonomisini iyileştirir","hi":"यह मोटरसाइकिल की ईंधन क्षमता में सुधार करता है","ar":"تحسّن اقتصاد الوقود للدراجة النارية"},{"en":"It helps drivers approaching from the side spot you","es":"Ayuda a que los conductores que se acercan por el costado te vean","ru":"Это помогает водителям, приближающимся сбоку, заметить вас","tr":"Yandan yaklaşan sürücülerin sizi fark etmesine yardımcı olur","hi":"यह बगल से आ रहे चालकों को आपको देखने में मदद करता है","ar":"تساعد السائقين القادمين من الجانب على رصدك"}],"e":{"en":"Reflective material on the sides helps drivers approaching from the side notice you, improving your conspicuity, per the Motorcycle Operator Manual.","es":"El material reflectante en los lados ayuda a que los conductores que se acercan por el costado te noten, mejorando tu visibilidad, según el Manual del Operador de Motocicletas.","ru":"Светоотражающий материал по бокам помогает водителям, приближающимся сбоку, заметить вас, повышая вашу заметность, согласно Руководству для водителей мотоциклов.","tr":"Yanlardaki yansıtıcı malzeme, Motosiklet Sürücü Kılavuzu'na göre yandan yaklaşan sürücülerin sizi fark etmesine yardımcı olur ve görünürlüğünüzü artırır.","hi":"किनारों पर परावर्तक सामग्री बगल से आ रहे चालकों को आपको देखने में मदद करती है, जिससे आपकी दृश्यता बेहतर होती है, Motorcycle Operator Manual के अनुसार।","ar":"تساعد المواد العاكسة على الجانبين السائقين القادمين من الجانب على ملاحظتك، مما يحسّن وضوحك، وفقاً لدليل مشغل الدراجة النارية."}},{"cat":"visibility","a":2,"q":{"en":"How should you use lane position to improve your visibility, according to the manual?","es":"¿Cómo debes usar la posición en el carril para mejorar tu visibilidad, según el manual?","ru":"Как, согласно Руководству, следует использовать положение на полосе для повышения своей видимости?","tr":"Kılavuza göre, görünürlüğünüzü artırmak için şerit konumunu nasıl kullanmalısınız?","hi":"मैनुअल के अनुसार, अपनी दृश्यता बेहतर करने के लिए आपको लेन की स्थिति का उपयोग कैसे करना चाहिए?","ar":"كيف ينبغي أن تستخدم موضعك في المسار لتحسين وضوحك، وفقاً للدليل؟"},"o":[{"en":"Always hug the right edge line of the lane","es":"Siempre pégate a la línea del borde derecho del carril","ru":"Всегда прижиматься к правой краевой линии полосы","tr":"Her zaman şeritin sağ kenar çizgisine yapışın","hi":"हमेशा लेन की दाईं किनारा रेखा से सटे रहें","ar":"التصق دائماً بخط الحافة اليمنى للمسار"},{"en":"Weave between lane portions every few seconds","es":"Zigzaguea entre las porciones del carril cada pocos segundos","ru":"Перемещаться между частями полосы каждые несколько секунд","tr":"Birkaç saniyede bir şerit bölümleri arasında zikzak çizin","hi":"हर कुछ सेकंड में लेन के हिस्सों के बीच घूमते रहें","ar":"تنقّل بين أجزاء المسار كل بضع ثوانٍ"},{"en":"Ride in the portion of the lane where you are most likely to be seen","es":"Conduce en la porción del carril donde es más probable que te vean","ru":"Ехать в той части полосы, где вас вероятнее всего увидят","tr":"Şeritin en çok görülme olasılığınızın olduğu bölümünde sürün","hi":"लेन के उस हिस्से में चलें जहाँ आपके दिखने की सबसे अधिक संभावना हो","ar":"اركب في جزء المسار الذي يُرجّح أن تُرى فيه"},{"en":"Stay exactly on the center line of the road","es":"Mantente exactamente sobre la línea central de la vía","ru":"Держаться точно по центральной линии дороги","tr":"Tam olarak yolun orta çizgisinde kalın","hi":"सड़क की केंद्र रेखा पर बिल्कुल बने रहें","ar":"ابقَ تماماً على الخط الأوسط للطريق"}],"e":{"en":"The manual advises choosing the lane portion where you are most likely to be seen while keeping a space cushion, adjusting position as conditions change.","es":"El manual aconseja elegir la porción del carril donde es más probable que te vean, manteniendo un colchón de espacio y ajustando la posición a medida que cambian las condiciones.","ru":"Руководство советует выбирать ту часть полосы, где вас вероятнее всего увидят, сохраняя при этом запас пространства и меняя положение по мере изменения условий.","tr":"Kılavuz, bir tampon boşluğu korurken en çok görülme olasılığınızın olduğu şerit bölümünü seçmenizi ve koşullar değiştikçe konumunuzu ayarlamanızı tavsiye eder.","hi":"मैनुअल सलाह देता है कि स्पेस कुशन बनाए रखते हुए लेन का वह हिस्सा चुनें जहाँ आपके दिखने की सबसे अधिक संभावना हो, और परिस्थितियाँ बदलने पर स्थिति समायोजित करें।","ar":"ينصح الدليل باختيار جزء المسار الذي يُرجّح أن تُرى فيه مع الحفاظ على مسافة أمان، وتعديل موضعك مع تغير الظروف."}},{"cat":"visibility","a":1,"q":{"en":"When you are following a car, which lane position helps put your image in the driver's rearview mirror?","es":"Cuando vas siguiendo a un auto, ¿qué posición en el carril ayuda a poner tu imagen en el espejo retrovisor del conductor?","ru":"Когда вы следуете за автомобилем, какое положение на полосе помогает поместить ваше изображение в зеркало заднего вида водителя?","tr":"Bir arabayı takip ederken, hangi şerit konumu görüntünüzü sürücünün dikiz aynasına yerleştirmeye yardımcı olur?","hi":"जब आप किसी कार के पीछे चल रहे हों, तो कौन सी लेन स्थिति आपकी छवि को चालक के रियरव्यू मिरर में लाने में मदद करती है?","ar":"عندما تسير خلف سيارة، أي موضع في المسار يساعد على وضع صورتك في مرآة الرؤية الخلفية للسائق؟"},"o":[{"en":"The far right of the lane","es":"El extremo derecho del carril","ru":"Крайнее правое в полосе","tr":"Şeritin en sağı","hi":"लेन का बिल्कुल दायाँ हिस्सा","ar":"أقصى يمين المسار"},{"en":"The center portion of the lane","es":"La porción central del carril","ru":"Центральная часть полосы","tr":"Şeritin orta bölümü","hi":"लेन का केंद्रीय हिस्सा","ar":"الجزء الأوسط من المسار"},{"en":"The far left of the lane next to oncoming traffic","es":"El extremo izquierdo del carril, junto al tráfico que viene en sentido contrario","ru":"Крайнее левое в полосе, рядом со встречным потоком","tr":"Karşı trafiğin yanındaki şeritin en solu","hi":"सामने से आ रही ट्रैफ़िक के बगल में लेन का बिल्कुल बायाँ हिस्सा","ar":"أقصى يسار المسار بجوار حركة المرور القادمة"},{"en":"Riding directly on the car's bumper","es":"Conducir directamente sobre el parachoques del auto","ru":"Движение прямо за бампером автомобиля","tr":"Doğrudan arabanın tamponunda sürmek","hi":"कार के बंपर पर सीधे सटकर चलना","ar":"القيادة مباشرةً على مصد السيارة"}],"e":{"en":"The manual notes that riding in the center portion of the lane puts your image in the middle of the driver's rearview mirror, where they are most likely to see you.","es":"El manual señala que conducir en la porción central del carril coloca tu imagen en el centro del espejo retrovisor del conductor, donde es más probable que te vea.","ru":"Руководство отмечает, что движение в центральной части полосы помещает ваше изображение в середину зеркала заднего вида водителя, где он вероятнее всего вас увидит.","tr":"Kılavuz, şeritin orta bölümünde sürmenin, görüntünüzü sürücünün en çok sizi görme olasılığının olduğu dikiz aynasının ortasına yerleştirdiğini belirtir.","hi":"मैनुअल बताता है कि लेन के केंद्रीय हिस्से में चलना आपकी छवि को चालक के रियरव्यू मिरर के बीच में लाता है, जहाँ उनके आपको देखने की सबसे अधिक संभावना होती है।","ar":"يشير الدليل إلى أن القيادة في الجزء الأوسط من المسار تضع صورتك في منتصف مرآة الرؤية الخلفية للسائق، حيث يُرجّح أن يراك."}},{"cat":"visibility","a":0,"q":{"en":"Before changing lanes, what does the Motorcycle Operator Manual tell riders to do about blind spots?","es":"Antes de cambiar de carril, ¿qué les indica el Manual del Operador de Motocicletas a los conductores que hagan respecto a los puntos ciegos?","ru":"Перед перестроением что Руководство для водителей мотоциклов рекомендует делать в отношении слепых зон?","tr":"Şerit değiştirmeden önce Motosiklet Sürücü Kılavuzu, sürücülere kör noktalar konusunda ne yapmalarını söyler?","hi":"लेन बदलने से पहले, Motorcycle Operator Manual सवारों को ब्लाइंड स्पॉट के बारे में क्या करने को कहता है?","ar":"قبل تغيير المسارات، بماذا يخبر دليل مشغل الدراجة النارية السائقين أن يفعلوا بشأن النقاط العمياء؟"},"o":[{"en":"Turn your head and look to the side because motorcycles and cars have blind spots","es":"Girar la cabeza y mirar hacia el costado, porque las motocicletas y los autos tienen puntos ciegos","ru":"Повернуть голову и посмотреть в сторону, потому что у мотоциклов и автомобилей есть слепые зоны","tr":"Başınızı çevirip yana bakın, çünkü motosikletlerin ve arabaların kör noktaları vardır","hi":"अपना सिर घुमाएँ और बगल में देखें क्योंकि मोटरसाइकिल और कारों के ब्लाइंड स्पॉट होते हैं","ar":"أدر رأسك وانظر إلى الجانب لأن للدراجات النارية والسيارات نقاطاً عمياء"},{"en":"Rely only on the rearview mirrors","es":"Confiar solo en los espejos retrovisores","ru":"Полагаться только на зеркала заднего вида","tr":"Yalnızca dikiz aynalarına güvenin","hi":"केवल रियरव्यू मिरर पर भरोसा करें","ar":"اعتمد فقط على مرايا الرؤية الخلفية"},{"en":"Honk the horn and change lanes immediately","es":"Tocar la bocina y cambiar de carril de inmediato","ru":"Просигналить и немедленно перестроиться","tr":"Korna çalıp hemen şerit değiştirin","hi":"हॉर्न बजाएँ और तुरंत लेन बदल लें","ar":"انفخ البوق وغيّر المسار فوراً"},{"en":"Assume the lane is clear if no headlights are visible","es":"Suponer que el carril está libre si no se ven faros","ru":"Считать полосу свободной, если не видно фар","tr":"Far görünmüyorsa şeritin boş olduğunu varsayın","hi":"अगर कोई हेडलाइट न दिखे तो मान लें कि लेन खाली है","ar":"افترض أن المسار خالٍ إذا لم تكن هناك مصابيح أمامية مرئية"}],"e":{"en":"The manual says motorcycles, like cars, have blind spots, so you must turn your head and look to the side before changing lanes-not rely on mirrors alone.","es":"El manual dice que las motocicletas, al igual que los autos, tienen puntos ciegos, por lo que debes girar la cabeza y mirar hacia el costado antes de cambiar de carril, sin confiar solo en los espejos.","ru":"Руководство гласит, что у мотоциклов, как и у автомобилей, есть слепые зоны, поэтому перед перестроением нужно повернуть голову и посмотреть в сторону, а не полагаться только на зеркала.","tr":"Kılavuz, motosikletlerin de arabalar gibi kör noktaları olduğunu, bu yüzden şerit değiştirmeden önce yalnızca aynalara güvenmeyip başınızı çevirip yana bakmanız gerektiğini söyler.","hi":"मैनुअल कहता है कि कारों की तरह मोटरसाइकिलों के भी ब्लाइंड स्पॉट होते हैं, इसलिए लेन बदलने से पहले आपको अपना सिर घुमाकर बगल में देखना चाहिए—केवल मिरर पर भरोसा न करें।","ar":"يقول الدليل إن للدراجات النارية، مثل السيارات، نقاطاً عمياء، لذا يجب أن تدير رأسك وتنظر إلى الجانب قبل تغيير المسارات — لا أن تعتمد على المرايا وحدها."}},{"cat":"visibility","a":2,"q":{"en":"What does the manual recommend regarding riding in the blind spots of other vehicles?","es":"¿Qué recomienda el manual respecto a conducir en los puntos ciegos de otros vehículos?","ru":"Что Руководство рекомендует в отношении движения в слепых зонах других транспортных средств?","tr":"Kılavuz, diğer araçların kör noktalarında sürme konusunda ne önerir?","hi":"अन्य वाहनों के ब्लाइंड स्पॉट में चलने के बारे में मैनुअल क्या सिफ़ारिश करता है?","ar":"بماذا يوصي الدليل فيما يتعلق بالقيادة في النقاط العمياء للمركبات الأخرى؟"},"o":[{"en":"Stay in a truck's blind spot to save fuel by drafting","es":"Quedarte en el punto ciego de un camión para ahorrar combustible aprovechando su estela","ru":"Держаться в слепой зоне грузовика, чтобы экономить топливо за счёт движения в потоке за ним","tr":"Slipstream ile yakıt tasarrufu için bir kamyonun kör noktasında kalın","hi":"ईंधन बचाने के लिए ट्रक के ब्लाइंड स्पॉट में रहकर ड्राफ्टिंग करें","ar":"ابقَ في النقطة العمياء لشاحنة لتوفير الوقود عبر الانسياب خلفها"},{"en":"Ride in blind spots only on the highway","es":"Conducir en los puntos ciegos solo en la autopista","ru":"Ехать в слепых зонах только на шоссе","tr":"Kör noktalarda yalnızca otoyolda sürün","hi":"ब्लाइंड स्पॉट में केवल राजमार्ग पर चलें","ar":"اركب في النقاط العمياء فقط على الطريق السريع"},{"en":"Avoid riding in the blind spots of cars and trucks","es":"Evitar conducir en los puntos ciegos de autos y camiones","ru":"Избегать движения в слепых зонах автомобилей и грузовиков","tr":"Arabaların ve kamyonların kör noktalarında sürmekten kaçının","hi":"कारों और ट्रकों के ब्लाइंड स्पॉट में चलने से बचें","ar":"تجنّب القيادة في النقاط العمياء للسيارات والشاحنات"},{"en":"Blind spots are safe as long as your light is on","es":"Los puntos ciegos son seguros mientras tu luz esté encendida","ru":"Слепые зоны безопасны, пока ваша фара включена","tr":"Işığınız açıksa kör noktalar güvenlidir","hi":"जब तक आपकी लाइट चालू है, ब्लाइंड स्पॉट सुरक्षित हैं","ar":"النقاط العمياء آمنة طالما أن ضوءك مضاء"}],"e":{"en":"The Motorcycle Operator Manual advises avoiding the blind spots of cars and trucks so other drivers can see you and are aware of your presence.","es":"El Manual del Operador de Motocicletas aconseja evitar los puntos ciegos de autos y camiones para que los otros conductores puedan verte y estén conscientes de tu presencia.","ru":"Руководство для водителей мотоциклов советует избегать слепых зон автомобилей и грузовиков, чтобы другие водители могли вас видеть и осознавать ваше присутствие.","tr":"Motosiklet Sürücü Kılavuzu, diğer sürücülerin sizi görebilmesi ve varlığınızın farkında olabilmesi için arabaların ve kamyonların kör noktalarından kaçınmayı tavsiye eder.","hi":"Motorcycle Operator Manual कारों और ट्रकों के ब्लाइंड स्पॉट से बचने की सलाह देता है ताकि अन्य चालक आपको देख सकें और आपकी उपस्थिति से अवगत रहें।","ar":"ينصح دليل مشغل الدراجة النارية بتجنّب النقاط العمياء للسيارات والشاحنات حتى يتمكن السائقون الآخرون من رؤيتك ويكونوا على دراية بوجودك."}},{"cat":"visibility","a":0,"q":{"en":"What does the manual say about using your turn signals?","es":"¿Qué dice el manual sobre el uso de las direccionales?","ru":"Что Руководство говорит об использовании указателей поворота?","tr":"Kılavuz, sinyallerinizi kullanmak konusunda ne der?","hi":"अपने टर्न सिग्नल का उपयोग करने के बारे में मैनुअल क्या कहता है?","ar":"ماذا يقول الدليل عن استخدام إشارات الانعطاف الخاصة بك؟"},"o":[{"en":"Use them any time you plan to turn or change lanes, even if no one seems around","es":"Úsalas cada vez que planees girar o cambiar de carril, aunque parezca que no hay nadie cerca","ru":"Используйте их каждый раз, когда планируете повернуть или перестроиться, даже если рядом, кажется, никого нет","tr":"Etrafta kimse yokmuş gibi görünse bile, dönmeyi veya şerit değiştirmeyi planladığınız her an kullanın","hi":"जब भी आप मुड़ने या लेन बदलने की योजना बनाएँ तब उन्हें उपयोग करें, भले ही कोई आसपास न दिखे","ar":"استخدمها في أي وقت تخطط فيه للانعطاف أو تغيير المسار، حتى لو بدا أنه لا أحد حولك"},{"en":"Use them only when other vehicles are clearly nearby","es":"Úsalas solo cuando haya otros vehículos claramente cerca","ru":"Используйте их только когда поблизости явно есть другие транспортные средства","tr":"Yalnızca başka araçlar açıkça yakındayken kullanın","hi":"उन्हें केवल तब उपयोग करें जब अन्य वाहन स्पष्ट रूप से पास हों","ar":"استخدمها فقط عندما تكون المركبات الأخرى قريبة بوضوح"},{"en":"Avoid them because they distract other drivers","es":"Evítalas porque distraen a los demás conductores","ru":"Избегайте их, потому что они отвлекают других водителей","tr":"Diğer sürücülerin dikkatini dağıttığı için kullanmaktan kaçının","hi":"उनसे बचें क्योंकि वे अन्य चालकों का ध्यान भटकाते हैं","ar":"تجنّبها لأنها تشتت انتباه السائقين الآخرين"},{"en":"Use them only at night for added visibility","es":"Úsalas solo de noche para mayor visibilidad","ru":"Используйте их только ночью для дополнительной видимости","tr":"Ek görünürlük için yalnızca gece kullanın","hi":"अतिरिक्त दृश्यता के लिए उन्हें केवल रात में उपयोग करें","ar":"استخدمها فقط ليلاً لزيادة الوضوح"}],"e":{"en":"The manual instructs riders to signal their intentions early-any time they plan to turn or change lanes-even when they think no one else is around.","es":"El manual indica a los conductores que señalicen sus intenciones con anticipación —cada vez que planeen girar o cambiar de carril— incluso cuando crean que no hay nadie más alrededor.","ru":"Руководство предписывает водителям заранее сигнализировать о своих намерениях — каждый раз, когда они планируют повернуть или перестроиться, — даже когда кажется, что рядом никого нет.","tr":"Kılavuz, sürücülere niyetlerini erkenden, dönmeyi veya şerit değiştirmeyi planladıkları her an, etrafta başka kimse olmadığını düşündüklerinde bile sinyal vermelerini söyler.","hi":"मैनुअल सवारों को निर्देश देता है कि वे अपने इरादे जल्दी संकेत दें—जब भी वे मुड़ने या लेन बदलने की योजना बनाएँ—भले ही उन्हें लगे कि आसपास कोई और नहीं है।","ar":"يوجّه الدليل السائقين إلى الإشارة إلى نواياهم مبكراً — في أي وقت يخططون فيه للانعطاف أو تغيير المسار — حتى عندما يظنون أنه لا أحد آخر حولهم."}},{"cat":"visibility","a":3,"q":{"en":"After completing a turn, what does the manual remind riders to do with the turn signal?","es":"Después de completar un giro, ¿qué les recuerda el manual a los conductores que hagan con la direccional?","ru":"После завершения поворота о чём Руководство напоминает водителям в отношении указателя поворота?","tr":"Bir dönüşü tamamladıktan sonra kılavuz, sürücülere sinyalle ilgili ne yapmalarını hatırlatır?","hi":"मोड़ पूरा करने के बाद, मैनुअल सवारों को टर्न सिग्नल के साथ क्या करने की याद दिलाता है?","ar":"بعد إتمام الانعطاف، بماذا يذكّر الدليل السائقين أن يفعلوا بإشارة الانعطاف؟"},"o":[{"en":"Leave it blinking to stay visible longer","es":"Dejarla parpadeando para seguir siendo visible más tiempo","ru":"Оставить его мигающим, чтобы дольше оставаться заметным","tr":"Daha uzun süre görünür kalmak için yanıp sönmeye bırakın","hi":"अधिक समय तक दिखने के लिए इसे ब्लिंक करते रहने दें","ar":"اتركها وامضة لتبقى مرئياً لفترة أطول"},{"en":"Switch it to the opposite direction","es":"Cambiarla a la dirección opuesta","ru":"Переключить его на противоположное направление","tr":"Ters yöne çevirin","hi":"इसे विपरीत दिशा में बदल दें","ar":"حوّلها إلى الاتجاه المعاكس"},{"en":"Tap it three times to confirm the turn","es":"Tocarla tres veces para confirmar el giro","ru":"Нажать на него три раза для подтверждения поворота","tr":"Dönüşü onaylamak için üç kez basın","hi":"मोड़ की पुष्टि के लिए इसे तीन बार टैप करें","ar":"انقر عليها ثلاث مرات لتأكيد الانعطاف"},{"en":"Make sure it is turned off so a driver does not think you plan to turn again","es":"Asegurarte de que esté apagada para que un conductor no piense que planeas girar de nuevo","ru":"Убедиться, что он выключен, чтобы водитель не подумал, что вы снова собираетесь поворачивать","tr":"Bir sürücünün tekrar dönmeyi planladığınızı düşünmemesi için kapalı olduğundan emin olun","hi":"सुनिश्चित करें कि यह बंद हो जाए ताकि चालक यह न सोचे कि आप फिर से मुड़ने की योजना बना रहे हैं","ar":"تأكد من إيقافها حتى لا يظن السائق أنك تخطط للانعطاف مرة أخرى"}],"e":{"en":"The manual warns to cancel your signal after turning, because a driver seeing it still on may pull into your path thinking you intend to turn again.","es":"El manual advierte que canceles tu direccional después de girar, porque un conductor que la vea aún encendida podría meterse en tu trayectoria pensando que tienes la intención de girar otra vez.","ru":"Руководство предупреждает: отменяйте сигнал после поворота, потому что водитель, видя его всё ещё включённым, может выехать на ваш путь, думая, что вы снова намерены повернуть.","tr":"Kılavuz, dönüşten sonra sinyalinizi iptal etmeniz konusunda uyarır; çünkü hala açık gören bir sürücü, tekrar dönmek istediğinizi düşünerek yolunuza çıkabilir.","hi":"मैनुअल चेतावनी देता है कि मुड़ने के बाद अपना सिग्नल रद्द कर दें, क्योंकि इसे अभी भी चालू देखकर कोई चालक यह सोचकर आपके रास्ते में आ सकता है कि आप फिर से मुड़ने का इरादा रखते हैं।","ar":"يحذر الدليل من ضرورة إلغاء إشارتك بعد الانعطاف، لأن السائق الذي يراها لا تزال مضاءة قد يندفع إلى مسارك ظناً منه أنك تنوي الانعطاف مرة أخرى."}},{"cat":"visibility","a":1,"q":{"en":"What does the Motorcycle Operator Manual say about a motorcycle's horn?","es":"¿Qué dice el Manual del Operador de Motocicletas sobre la bocina de una motocicleta?","ru":"Что Руководство для водителей мотоциклов говорит о звуковом сигнале мотоцикла?","tr":"Motosiklet Sürücü Kılavuzu, bir motosikletin kornası hakkında ne der?","hi":"मोटरसाइकिल के हॉर्न के बारे में Motorcycle Operator Manual क्या कहता है?","ar":"ماذا يقول دليل مشغل الدراجة النارية عن بوق الدراجة النارية؟"},"o":[{"en":"It is louder than a car horn and stops all hazards","es":"Es más fuerte que la bocina de un auto y detiene todos los peligros","ru":"Он громче автомобильного сигнала и устраняет все опасности","tr":"Bir araba kornasından daha yüksek seslidir ve tüm tehlikeleri durdurur","hi":"यह कार के हॉर्न से तेज़ होता है और सभी खतरों को रोक देता है","ar":"إنه أعلى صوتاً من بوق السيارة ويوقف كل المخاطر"},{"en":"It is not as loud as a car horn, so use it but do not rely on it","es":"No es tan fuerte como la bocina de un auto, así que úsala pero no dependas de ella","ru":"Он не такой громкий, как автомобильный сигнал, поэтому используйте его, но не полагайтесь на него","tr":"Bir araba kornası kadar yüksek sesli değildir, bu yüzden kullanın ama ona güvenmeyin","hi":"यह कार के हॉर्न जितना तेज़ नहीं है, इसलिए इसका उपयोग करें लेकिन इस पर भरोसा न करें","ar":"إنه ليس بقوة صوت بوق السيارة، لذا استخدمه لكن لا تعتمد عليه"},{"en":"It should never be used in traffic","es":"Nunca debe usarse en el tráfico","ru":"Его никогда не следует использовать в потоке","tr":"Trafikte asla kullanılmamalıdır","hi":"इसे ट्रैफ़िक में कभी उपयोग नहीं करना चाहिए","ar":"يجب ألا يُستخدم أبداً في حركة المرور"},{"en":"It works only when the headlight is off","es":"Funciona solo cuando el faro está apagado","ru":"Он работает только когда фара выключена","tr":"Yalnızca far kapalıyken çalışır","hi":"यह केवल तब काम करता है जब हेडलाइट बंद हो","ar":"يعمل فقط عندما يكون المصباح الأمامي مطفأً"}],"e":{"en":"The manual states a motorcycle horn is not as loud as a car horn, so riders should use it to get attention but not rely on it to prevent a crash.","es":"El manual indica que la bocina de una motocicleta no es tan fuerte como la de un auto, por lo que los conductores deben usarla para llamar la atención pero no depender de ella para evitar un choque.","ru":"Руководство утверждает, что звуковой сигнал мотоцикла не такой громкий, как автомобильный, поэтому водителям следует использовать его, чтобы привлечь внимание, но не полагаться на него для предотвращения столкновения.","tr":"Kılavuz, bir motosiklet kornasının bir araba kornası kadar yüksek sesli olmadığını, bu yüzden sürücülerin dikkat çekmek için kullanması ama bir kazayı önlemek için ona güvenmemesi gerektiğini belirtir.","hi":"मैनुअल बताता है कि मोटरसाइकिल का हॉर्न कार के हॉर्न जितना तेज़ नहीं है, इसलिए सवारों को ध्यान आकर्षित करने के लिए इसका उपयोग करना चाहिए लेकिन दुर्घटना रोकने के लिए इस पर भरोसा नहीं करना चाहिए।","ar":"ينص الدليل على أن بوق الدراجة النارية ليس بقوة صوت بوق السيارة، لذا ينبغي للسائقين استخدامه للفت الانتباه لكن لا الاعتماد عليه لمنع التصادم."}},{"cat":"visibility","a":1,"q":{"en":"In what situation does the manual suggest being ready to use your horn?","es":"¿En qué situación sugiere el manual estar listo para usar tu bocina?","ru":"В какой ситуации Руководство советует быть готовым использовать звуковой сигнал?","tr":"Kılavuz, hangi durumda kornanızı kullanmaya hazır olmanızı önerir?","hi":"मैनुअल किस स्थिति में अपने हॉर्न का उपयोग करने के लिए तैयार रहने का सुझाव देता है?","ar":"في أي موقف يقترح الدليل أن تكون مستعداً لاستخدام بوقك؟"},"o":[{"en":"Only to greet other motorcyclists you recognize","es":"Solo para saludar a otros motociclistas que reconozcas","ru":"Только чтобы поприветствовать знакомых мотоциклистов","tr":"Yalnızca tanıdığınız diğer motosikletlileri selamlamak için","hi":"केवल उन मोटरसाइकिल चालकों का अभिवादन करने के लिए जिन्हें आप पहचानते हैं","ar":"فقط لتحية سائقي الدراجات النارية الآخرين الذين تعرفهم"},{"en":"When another vehicle may move into your lane or fail to see you","es":"Cuando otro vehículo pueda meterse en tu carril o no verte","ru":"Когда другое транспортное средство может въехать на вашу полосу или не заметить вас","tr":"Başka bir araç şeritinize girebileceğinde veya sizi göremeyebileceğinde","hi":"जब कोई अन्य वाहन आपकी लेन में आ सकता है या आपको देखने में विफल हो सकता है","ar":"عندما قد تتحرك مركبة أخرى إلى مسارك أو تفشل في رؤيتك"},{"en":"Continuously while riding through a city","es":"Continuamente mientras conduces por la ciudad","ru":"Постоянно во время движения по городу","tr":"Bir şehirde sürerken sürekli olarak","hi":"शहर में चलते समय लगातार","ar":"باستمرار أثناء القيادة عبر المدينة"},{"en":"Only when your headlight has burned out","es":"Solo cuando tu faro se haya fundido","ru":"Только когда перегорела фара","tr":"Yalnızca farınız yanıp söndüğünde","hi":"केवल तब जब आपकी हेडलाइट जल गई हो","ar":"فقط عندما يحترق مصباحك الأمامي"}],"e":{"en":"The manual advises being ready to sound your horn to quickly get the attention of a driver who may move into your lane or otherwise fail to see you.","es":"El manual aconseja estar listo para tocar la bocina para llamar rápidamente la atención de un conductor que pueda meterse en tu carril o que de otro modo no te vea.","ru":"Руководство советует быть готовым подать звуковой сигнал, чтобы быстро привлечь внимание водителя, который может въехать на вашу полосу или иным образом не заметить вас.","tr":"Kılavuz, şeritinize girebilecek veya başka şekilde sizi göremeyebilecek bir sürücünün dikkatini hızla çekmek için kornanızı çalmaya hazır olmanızı tavsiye eder.","hi":"मैनुअल सलाह देता है कि उस चालक का ध्यान तुरंत आकर्षित करने के लिए हॉर्न बजाने के लिए तैयार रहें जो आपकी लेन में आ सकता है या अन्यथा आपको देखने में विफल हो सकता है।","ar":"ينصح الدليل بأن تكون مستعداً لإطلاق بوقك للفت انتباه سائق بسرعة قد يتحرك إلى مسارك أو يفشل بطريقة أخرى في رؤيتك."}},{"cat":"visibility","a":0,"q":{"en":"Why does the Motorcycle Operator Manual emphasize keeping a 'cushion of space' around your motorcycle?","es":"¿Por qué enfatiza el Manual del Operador de Motocicletas mantener un 'colchón de espacio' alrededor de tu motocicleta?","ru":"Почему Руководство для водителей мотоциклов подчёркивает важность сохранения «запаса пространства» вокруг мотоцикла?","tr":"Motosiklet Sürücü Kılavuzu, motosikletinizin etrafında bir 'tampon boşluğu' tutmayı neden vurgular?","hi":"Motorcycle Operator Manual आपकी मोटरसाइकिल के चारों ओर 'स्पेस कुशन' बनाए रखने पर ज़ोर क्यों देता है?","ar":"لماذا يؤكد دليل مشغل الدراجة النارية على الحفاظ على 'مسافة أمان' حول دراجتك النارية؟"},"o":[{"en":"It gives you time to react and space to maneuver if someone makes a mistake","es":"Te da tiempo para reaccionar y espacio para maniobrar si alguien comete un error","ru":"Это даёт вам время на реакцию и пространство для манёвра, если кто-то совершит ошибку","tr":"Birisi hata yaparsa tepki vermeniz için zaman ve manevra yapmanız için alan tanır","hi":"अगर कोई गलती करे तो यह आपको प्रतिक्रिया करने का समय और चलने-फिरने की जगह देता है","ar":"تمنحك الوقت لرد الفعل والمساحة للمناورة إذا ارتكب أحدهم خطأً"},{"en":"It makes the motorcycle accelerate faster","es":"Hace que la motocicleta acelere más rápido","ru":"Это заставляет мотоцикл разгоняться быстрее","tr":"Motosikletin daha hızlı hızlanmasını sağlar","hi":"यह मोटरसाइकिल को तेज़ी से एक्सीलरेट कराता है","ar":"تجعل الدراجة النارية تتسارع أسرع"},{"en":"It is only needed when riding at night","es":"Solo se necesita al conducir de noche","ru":"Это нужно только при езде ночью","tr":"Yalnızca gece sürerken gereklidir","hi":"यह केवल रात में चलते समय आवश्यक है","ar":"ضرورية فقط عند القيادة ليلاً"},{"en":"It reduces the legal following distance required","es":"Reduce la distancia de seguimiento legal requerida","ru":"Это уменьшает требуемую законом дистанцию следования","tr":"Gerekli yasal takip mesafesini azaltır","hi":"यह आवश्यक कानूनी फॉलोइंग दूरी को कम करता है","ar":"تقلل مسافة الاتباع القانونية المطلوبة"}],"e":{"en":"The manual explains that a cushion of space all around the motorcycle gives you time to react and room to maneuver if another driver makes a mistake.","es":"El manual explica que un colchón de espacio alrededor de toda la motocicleta te da tiempo para reaccionar y espacio para maniobrar si otro conductor comete un error.","ru":"Руководство объясняет, что запас пространства со всех сторон мотоцикла даёт вам время на реакцию и место для манёвра, если другой водитель совершит ошибку.","tr":"Kılavuz, motosikletin tüm çevresindeki bir tampon boşluğunun, başka bir sürücü hata yaparsa tepki vermeniz için zaman ve manevra yapmanız için yer tanıdığını açıklar.","hi":"मैनुअल समझाता है कि मोटरसाइकिल के चारों ओर का स्पेस कुशन आपको प्रतिक्रिया करने का समय और चलने-फिरने की जगह देता है अगर कोई अन्य चालक गलती करे।","ar":"يوضح الدليل أن مسافة الأمان حول الدراجة النارية بالكامل تمنحك الوقت لرد الفعل والمساحة للمناورة إذا ارتكب سائق آخر خطأً."}},{"cat":"visibility","a":0,"q":{"en":"During the 'Evaluate' step of SEE, what is the rider primarily doing?","es":"Durante el paso de 'Evaluar' (Evaluate) de SEE, ¿qué hace principalmente el conductor?","ru":"Чем главным образом занимается водитель на шаге «Оценка» (Evaluate) стратегии SEE?","tr":"SEE'nin 'Değerlendir' (Evaluate) adımında, sürücü öncelikle ne yapar?","hi":"SEE के 'Evaluate' (मूल्यांकन) चरण के दौरान, सवार मुख्य रूप से क्या कर रहा होता है?","ar":"خلال خطوة 'التقييم' (Evaluate) في استراتيجية SEE، ما الذي يفعله السائق بشكل أساسي؟"},"o":[{"en":"Thinking about how hazards can interact and anticipating problems","es":"Pensar en cómo pueden interactuar los peligros y anticipar problemas","ru":"Размышляет о том, как опасности могут взаимодействовать, и предвидит проблемы","tr":"Tehlikelerin nasıl etkileşebileceğini düşünmek ve sorunları öngörmek","hi":"सोचना कि खतरे कैसे टकरा सकते हैं और समस्याओं का पूर्वानुमान लगाना","ar":"التفكير في كيفية تفاعل المخاطر وتوقّع المشكلات"},{"en":"Physically swerving away from danger","es":"Esquivar físicamente el peligro","ru":"Физически уклоняется от опасности","tr":"Tehlikeden fiziksel olarak savrularak kaçmak","hi":"शारीरिक रूप से खतरे से दूर मुड़ना","ar":"الانعطاف الجسدي بعيداً عن الخطر"},{"en":"Turning the headlight to high beam","es":"Poner el faro en luz alta","ru":"Переключает фару на дальний свет","tr":"Farı uzun huzmeye çevirmek","hi":"हेडलाइट को हाई बीम पर करना","ar":"تحويل المصباح الأمامي إلى الضوء العالي"},{"en":"Coming to a complete stop at every intersection","es":"Detenerse por completo en cada intersección","ru":"Полностью останавливается на каждом перекрёстке","tr":"Her kavşakta tamamen durmak","hi":"हर चौराहे पर पूरी तरह रुक जाना","ar":"التوقف الكامل عند كل تقاطع"}],"e":{"en":"Evaluate means thinking about how identified hazards can interact to create risk and anticipating problems so you can plan a response, per the Motorcycle Operator Manual.","es":"Evaluar significa pensar en cómo los peligros identificados pueden interactuar para crear riesgo y anticipar problemas para que puedas planear una respuesta, según el Manual del Operador de Motocicletas.","ru":"«Оценка» означает размышление о том, как выявленные опасности могут взаимодействовать, создавая риск, и предвидение проблем, чтобы спланировать реакцию, согласно Руководству для водителей мотоциклов.","tr":"Değerlendir, Motosiklet Sürücü Kılavuzu'na göre, tanımlanan tehlikelerin risk oluşturmak için nasıl etkileşebileceğini düşünmek ve bir yanıt planlayabilmeniz için sorunları öngörmek demektir.","hi":"Evaluate का मतलब है यह सोचना कि पहचाने गए खतरे कैसे टकराकर जोखिम पैदा कर सकते हैं और समस्याओं का पूर्वानुमान लगाना ताकि आप प्रतिक्रिया की योजना बना सकें, Motorcycle Operator Manual के अनुसार।","ar":"يعني التقييم التفكير في كيفية تفاعل المخاطر المحددة لخلق خطر وتوقّع المشكلات حتى تتمكن من التخطيط للاستجابة، وفقاً لدليل مشغل الدراجة النارية."}},{"cat":"visibility","a":3,"q":{"en":"According to the manual, why are motorcycles often not 'seen' by other drivers even in plain view?","es":"Según el manual, ¿por qué a menudo los demás conductores no 'ven' las motocicletas, incluso estando a plena vista?","ru":"Согласно Руководству, почему мотоциклы часто остаются «незамеченными» другими водителями даже на виду?","tr":"Kılavuza göre, motosikletler tam görüş alanında olsa bile diğer sürücüler tarafından neden çoğu zaman 'görülmez'?","hi":"मैनुअल के अनुसार, मोटरसाइकिलें अक्सर सामने होने पर भी अन्य चालकों को क्यों नहीं 'दिखाई' देतीं?","ar":"وفقاً للدليل، لماذا كثيراً ما لا 'يرى' السائقون الآخرون الدراجات النارية حتى عندما تكون في مرأى واضح؟"},"o":[{"en":"They are usually painted in bright colors that confuse drivers","es":"Suelen estar pintadas de colores brillantes que confunden a los conductores","ru":"Они обычно окрашены в яркие цвета, которые сбивают водителей с толку","tr":"Genellikle sürücüleri şaşırtan parlak renklere boyanmışlardır","hi":"वे आमतौर पर चमकीले रंगों में रंगी होती हैं जो चालकों को भ्रमित करते हैं","ar":"عادةً ما تكون مطلية بألوان زاهية تربك السائقين"},{"en":"They travel slower than the surrounding traffic","es":"Viajan más despacio que el tráfico que las rodea","ru":"Они движутся медленнее окружающего транспорта","tr":"Çevredeki trafikten daha yavaş giderler","hi":"वे आसपास की ट्रैफ़िक की तुलना में धीमी चलती हैं","ar":"تسير أبطأ من حركة المرور المحيطة"},{"en":"Their headlights blend in with car headlights","es":"Sus faros se confunden con los faros de los autos","ru":"Их фары сливаются с фарами автомобилей","tr":"Farları araba farlarıyla kaynaşır","hi":"उनकी हेडलाइट कार की हेडलाइट के साथ घुल-मिल जाती हैं","ar":"تندمج مصابيحها الأمامية مع مصابيح السيارات"},{"en":"Their smaller size makes them easy for drivers to overlook or misjudge","es":"Su menor tamaño hace que los conductores las pasen por alto o las juzguen mal con facilidad","ru":"Их меньший размер делает их лёгкими для пропуска или неверной оценки водителями","tr":"Daha küçük boyutları, sürücülerin onları gözden kaçırmasını veya yanlış değerlendirmesini kolaylaştırır","hi":"उनका छोटा आकार चालकों के लिए उन्हें अनदेखा करना या गलत आँकना आसान बनाता है","ar":"حجمها الأصغر يجعل من السهل على السائقين إغفالها أو إساءة تقدير موقعها"}],"e":{"en":"The manual explains a motorcycle's small size makes it easy for drivers to overlook, so riders must take active steps-light, clothing, and position-to be seen.","es":"El manual explica que el pequeño tamaño de una motocicleta hace que los conductores la pasen por alto con facilidad, por lo que los motociclistas deben tomar medidas activas —luz, ropa y posición— para ser vistos.","ru":"Руководство объясняет, что небольшой размер мотоцикла делает его лёгким для пропуска водителями, поэтому мотоциклисты должны предпринимать активные шаги — свет, одежда и положение, — чтобы быть замеченными.","tr":"Kılavuz, bir motosikletin küçük boyutunun sürücülerin onu gözden kaçırmasını kolaylaştırdığını, bu yüzden sürücülerin görülmek için aktif adımlar (ışık, kıyafet ve konum) atması gerektiğini açıklar.","hi":"मैनुअल समझाता है कि मोटरसाइकिल का छोटा आकार चालकों के लिए उसे अनदेखा करना आसान बनाता है, इसलिए सवारों को दिखने के लिए सक्रिय कदम—लाइट, कपड़े और स्थिति—उठाने चाहिए।","ar":"يوضح الدليل أن صغر حجم الدراجة النارية يجعل من السهل على السائقين إغفالها، لذا يجب على السائقين اتخاذ خطوات فعّالة — الضوء والملابس والموضع — لكي يُرَوا."}},{"cat":"hazards","a":0,"q":{"en":"When is wet pavement generally most slippery for a motorcycle rider?","es":"¿Cuándo suele estar más resbaloso el pavimento mojado para un motociclista?","ru":"Когда мокрое покрытие обычно наиболее скользкое для водителя мотоцикла?","tr":"Islak zemin, bir motosiklet sürücüsü için genellikle ne zaman en kaygandır?","hi":"मोटरसाइकिल सवार के लिए गीली सड़क आमतौर पर सबसे अधिक फिसलन भरी कब होती है?","ar":"متى يكون الرصيف المبلل عموماً أكثر زلقاً لسائق الدراجة النارية؟"},"o":[{"en":"Just after it starts to rain, before surface oil washes away","es":"Justo después de que empieza a llover, antes de que el aceite de la superficie se lave","ru":"Сразу после начала дождя, до того как поверхностное масло смоется","tr":"Yağmur yeni başladıktan hemen sonra, yüzeydeki yağ yıkanıp gitmeden önce","hi":"बारिश शुरू होने के ठीक बाद, इससे पहले कि सतह का तेल बह जाए","ar":"بعد بدء المطر مباشرةً، قبل أن يُغسل الزيت السطحي"},{"en":"After it has been raining steadily for several hours","es":"Después de que ha llovido de forma constante durante varias horas","ru":"После того как дождь идёт устойчиво в течение нескольких часов","tr":"Birkaç saat sürekli yağmur yağdıktan sonra","hi":"कई घंटों तक लगातार बारिश होने के बाद","ar":"بعد أن يستمر هطول المطر بثبات لعدة ساعات"},{"en":"Only when the rain finally stops and the road begins to dry","es":"Solo cuando finalmente deja de llover y la vía empieza a secarse","ru":"Только когда дождь наконец прекращается и дорога начинает высыхать","tr":"Yalnızca yağmur sonunda durup yol kurumaya başladığında","hi":"केवल तब जब बारिश आखिरकार रुक जाए और सड़क सूखने लगे","ar":"فقط عندما يتوقف المطر أخيراً ويبدأ الطريق بالجفاف"},{"en":"Wet pavement offers the same traction no matter how long it rains","es":"El pavimento mojado ofrece la misma tracción sin importar cuánto tiempo llueva","ru":"Мокрое покрытие обеспечивает одинаковое сцепление независимо от продолжительности дождя","tr":"Islak zemin, ne kadar süre yağmur yağarsa yağsın aynı tutuşu sunar","hi":"गीली सड़क समान कर्षण देती है चाहे कितनी भी देर बारिश हो","ar":"يوفر الرصيف المبلل نفس قوة الاحتكاك مهما طال هطول المطر"}],"e":{"en":"Pavement is most slippery just after it starts to rain, before the surface oil washes off to the side of the road. The Motorcycle Operator Manual warns riders to use extra caution during the first part of a rain.","es":"El pavimento está más resbaloso justo después de que empieza a llover, antes de que el aceite de la superficie se lave hacia los lados de la vía. El Manual del Operador de Motocicletas advierte a los conductores que extremen la precaución durante la primera parte de la lluvia.","ru":"Покрытие наиболее скользкое сразу после начала дождя, до того как поверхностное масло смоется к краю дороги. Руководство для водителей мотоциклов предупреждает водителей соблюдать особую осторожность в первой части дождя.","tr":"Zemin, yüzeydeki yağ yolun kenarına yıkanıp gitmeden önce, yağmur yeni başladıktan hemen sonra en kaygandır. Motosiklet Sürücü Kılavuzu, sürücüleri yağmurun ilk bölümünde ekstra dikkatli olmaları konusunda uyarır.","hi":"सड़क बारिश शुरू होने के ठीक बाद सबसे अधिक फिसलन भरी होती है, इससे पहले कि सतह का तेल सड़क के किनारे बह जाए। Motorcycle Operator Manual सवारों को बारिश के पहले हिस्से के दौरान अतिरिक्त सावधानी बरतने की चेतावनी देता है।","ar":"يكون الرصيف أكثر زلقاً بعد بدء المطر مباشرةً، قبل أن يُغسل الزيت السطحي إلى جانب الطريق. يحذر دليل مشغل الدراجة النارية السائقين من توخّي مزيد من الحذر خلال الجزء الأول من المطر."}},{"cat":"hazards","a":1,"q":{"en":"Where in the lane does oil and grease dripped from cars usually collect, making it slippery when wet?","es":"¿En qué parte del carril suelen acumularse el aceite y la grasa que gotean de los autos, haciéndolo resbaloso cuando está mojado?","ru":"Где в полосе обычно скапливаются масло и смазка, капающие с автомобилей, делая её скользкой при намокании?","tr":"Arabalardan damlayan yağ ve gres, şeritte genellikle nerede toplanarak ıslakken kaygan hale gelir?","hi":"कारों से टपका तेल और ग्रीस आमतौर पर लेन में कहाँ जमा होता है, जिससे गीला होने पर यह फिसलन भरा हो जाता है?","ar":"أين في المسار يتجمع عادةً الزيت والشحم المتساقط من السيارات، مما يجعله زلقاً عند البلل؟"},"o":[{"en":"Along the far right edge of the lane","es":"A lo largo del extremo derecho del carril","ru":"Вдоль крайнего правого края полосы","tr":"Şeritin en sağ kenarı boyunca","hi":"लेन के बिल्कुल दाएँ किनारे के साथ","ar":"على طول الحافة اليمنى القصوى من المسار"},{"en":"In the center portion of the lane","es":"En la porción central del carril","ru":"В центральной части полосы","tr":"Şeritin orta bölümünde","hi":"लेन के केंद्रीय हिस्से में","ar":"في الجزء الأوسط من المسار"},{"en":"Only in the left tire track","es":"Solo en la huella de la llanta izquierda","ru":"Только в левой колее","tr":"Yalnızca sol lastik izinde","hi":"केवल बाएँ टायर ट्रैक में","ar":"فقط في مسار الإطار الأيسر"},{"en":"Spread evenly across the whole lane","es":"Repartidos de manera uniforme por todo el carril","ru":"Равномерно распределяются по всей полосе","tr":"Tüm şerite eşit olarak yayılmış","hi":"पूरी लेन में समान रूप से फैला हुआ","ar":"موزعاً بالتساوي عبر المسار بأكمله"}],"e":{"en":"The oily strip that collects drippings from cars runs down the center of the lane and is usually no more than two feet wide. The Motorcycle Operator Manual notes it can be slippery, especially when wet.","es":"La franja aceitosa que acumula los goteos de los autos corre por el centro del carril y por lo general no mide más de dos pies de ancho. El Manual del Operador de Motocicletas señala que puede ser resbalosa, especialmente cuando está mojada.","ru":"Масляная полоса, в которой собираются капли с автомобилей, проходит по центру полосы и обычно имеет ширину не более двух футов. Руководство для водителей мотоциклов отмечает, что она может быть скользкой, особенно при намокании.","tr":"Arabalardan damlayanları toplayan yağlı şerit, şeritin ortasından gider ve genellikle iki fitten geniş değildir. Motosiklet Sürücü Kılavuzu, özellikle ıslakken kaygan olabileceğini belirtir.","hi":"कारों से टपकने वाली बूँदों को इकट्ठा करने वाली तैलीय पट्टी लेन के बीच में चलती है और आमतौर पर दो फ़ुट से अधिक चौड़ी नहीं होती। Motorcycle Operator Manual बताता है कि यह फिसलन भरी हो सकती है, खासकर गीला होने पर।","ar":"يمتد الشريط الزيتي الذي يتجمع فيه ما يتساقط من السيارات في وسط المسار وعادةً لا يزيد عرضه عن قدمين. يشير دليل مشغل الدراجة النارية إلى أنه يمكن أن يكون زلقاً، خاصة عند البلل."}},{"cat":"hazards","a":2,"q":{"en":"When it begins to rain, what is often the best lane position to find better traction?","es":"Cuando empieza a llover, ¿cuál suele ser la mejor posición en el carril para encontrar mejor tracción?","ru":"Когда начинается дождь, какое положение на полосе часто является лучшим для нахождения лучшего сцепления?","tr":"Yağmur başladığında, daha iyi tutuş bulmak için genellikle en iyi şerit konumu hangisidir?","hi":"जब बारिश शुरू होती है, तो बेहतर कर्षण पाने के लिए अक्सर सबसे अच्छी लेन स्थिति कौन सी होती है?","ar":"عندما يبدأ المطر، ما هو غالباً أفضل موضع في المسار للعثور على قوة احتكاك أفضل؟"},"o":[{"en":"Squarely in the center of the lane","es":"Justo en el centro del carril","ru":"Точно по центру полосы","tr":"Tam şeritin ortasında","hi":"लेन के बिल्कुल केंद्र में","ar":"في وسط المسار تماماً"},{"en":"On the painted lane markings","es":"Sobre las marcas pintadas del carril","ru":"По нанесённой разметке полосы","tr":"Boyalı şerit işaretlerinin üzerinde","hi":"पेंट की गई लेन चिह्नों पर","ar":"على علامات المسار المطلية"},{"en":"In the tire tracks left by other vehicles","es":"En las huellas de las llantas dejadas por otros vehículos","ru":"В колеях, оставленных другими транспортными средствами","tr":"Diğer araçların bıraktığı lastik izlerinde","hi":"अन्य वाहनों द्वारा छोड़े गए टायर ट्रैक में","ar":"في مسارات الإطارات التي تركتها المركبات الأخرى"},{"en":"As close to the shoulder gravel as possible","es":"Lo más cerca posible de la grava del acotamiento","ru":"Как можно ближе к гравию на обочине","tr":"Banket çakılına olabildiğince yakın","hi":"कंधे की बजरी के जितना संभव हो उतना पास","ar":"أقرب ما يمكن إلى حصى الكتف"}],"e":{"en":"When it starts to rain, ride in the tire tracks left by cars, where the surface is least slippery; the left track is often best. The Motorcycle Operator Manual advises riding on the least slippery portion of the lane.","es":"Cuando empieza a llover, conduce en las huellas de las llantas dejadas por los autos, donde la superficie es menos resbalosa; la huella izquierda suele ser la mejor. El Manual del Operador de Motocicletas aconseja conducir en la porción menos resbalosa del carril.","ru":"Когда начинается дождь, ездите в колеях, оставленных автомобилями, где поверхность наименее скользкая; левая колея часто лучше всего. Руководство для водителей мотоциклов советует ездить по наименее скользкой части полосы.","tr":"Yağmur başladığında, yüzeyin en az kaygan olduğu, arabaların bıraktığı lastik izlerinde sürün; sol iz çoğu zaman en iyisidir. Motosiklet Sürücü Kılavuzu, şeritin en az kaygan bölümünde sürmeyi tavsiye eder.","hi":"जब बारिश शुरू होती है, तो कारों द्वारा छोड़े गए टायर ट्रैक में चलें, जहाँ सतह सबसे कम फिसलन भरी होती है; बायाँ ट्रैक अक्सर सबसे अच्छा होता है। Motorcycle Operator Manual लेन के सबसे कम फिसलन भरे हिस्से पर चलने की सलाह देता है।","ar":"عندما يبدأ المطر، اركب في مسارات الإطارات التي تركتها السيارات، حيث يكون السطح أقل زلقاً؛ غالباً ما يكون المسار الأيسر هو الأفضل. ينصح دليل مشغل الدراجة النارية بالقيادة على الجزء الأقل زلقاً من المسار."}},{"cat":"hazards","a":3,"q":{"en":"Which of the following surfaces is most likely to be slippery and reduce traction, especially when wet?","es":"¿Cuál de las siguientes superficies es más probable que sea resbalosa y reduzca la tracción, especialmente cuando está mojada?","ru":"Какая из следующих поверхностей наиболее вероятно будет скользкой и снизит сцепление, особенно при намокании?","tr":"Aşağıdaki yüzeylerden hangisi, özellikle ıslakken kaygan olma ve tutuşu azaltma olasılığı en yüksek olanıdır?","hi":"निम्नलिखित में से कौन सी सतह सबसे अधिक फिसलन भरी होने और कर्षण कम करने की संभावना रखती है, खासकर गीला होने पर?","ar":"أي من الأسطح التالية يُرجّح أن يكون زلقاً ويقلل قوة الاحتكاك، خاصة عند البلل؟"},"o":[{"en":"Clean, dry, freshly laid asphalt","es":"Asfalto limpio, seco y recién colocado","ru":"Чистый, сухой, только что уложенный асфальт","tr":"Temiz, kuru, yeni serilmiş asfalt","hi":"साफ़, सूखा, ताज़ा बिछाया गया डामर","ar":"إسفلت نظيف وجاف وحديث الفرش"},{"en":"A coarse concrete roadway in the sun","es":"Una vía de concreto rugoso bajo el sol","ru":"Шероховатое бетонное покрытие на солнце","tr":"Güneşte pürüzlü bir beton yol","hi":"धूप में खुरदरी कंक्रीट की सड़क","ar":"طريق خرساني خشن تحت الشمس"},{"en":"Newly swept pavement free of debris","es":"Pavimento recién barrido y libre de escombros","ru":"Только что подметённое покрытие без мусора","tr":"Döküntüden arınmış, yeni süpürülmüş zemin","hi":"नई बुहारी गई सतह जिस पर कोई मलबा न हो","ar":"رصيف مكنوس حديثاً وخالٍ من الحطام"},{"en":"Painted lane markings, steel plates, and manhole covers","es":"Marcas pintadas del carril, placas de acero y tapas de alcantarilla","ru":"Нанесённая разметка полос, стальные плиты и канализационные люки","tr":"Boyalı şerit işaretleri, çelik plakalar ve rögar kapakları","hi":"पेंट की गई लेन चिह्न, स्टील प्लेट और मैनहोल कवर","ar":"علامات المسار المطلية والألواح الفولاذية وأغطية فتحات الصيانة"}],"e":{"en":"Lane markings, steel plates, manhole covers, and similar smooth surfaces offer little traction and are especially slippery when wet. The Motorcycle Operator Manual lists them among hazardous slippery surfaces.","es":"Las marcas del carril, las placas de acero, las tapas de alcantarilla y superficies lisas similares ofrecen poca tracción y son especialmente resbalosas cuando están mojadas. El Manual del Operador de Motocicletas las incluye entre las superficies resbalosas peligrosas.","ru":"Разметка полос, стальные плиты, канализационные люки и подобные гладкие поверхности обеспечивают слабое сцепление и особенно скользки при намокании. Руководство для водителей мотоциклов относит их к опасным скользким поверхностям.","tr":"Şerit işaretleri, çelik plakalar, rögar kapakları ve benzeri pürüzsüz yüzeyler çok az tutuş sunar ve özellikle ıslakken kaygandır. Motosiklet Sürücü Kılavuzu, bunları tehlikeli kaygan yüzeyler arasında sıralar.","hi":"लेन चिह्न, स्टील प्लेट, मैनहोल कवर और इसी तरह की चिकनी सतहें बहुत कम कर्षण देती हैं और गीली होने पर विशेष रूप से फिसलन भरी होती हैं। Motorcycle Operator Manual इन्हें खतरनाक फिसलन भरी सतहों में सूचीबद्ध करता है।","ar":"توفر علامات المسار والألواح الفولاذية وأغطية فتحات الصيانة والأسطح الناعمة المماثلة قوة احتكاك ضئيلة وتكون زلقة بشكل خاص عند البلل. يدرج دليل مشغل الدراجة النارية هذه ضمن الأسطح الزلقة الخطرة."}},{"cat":"hazards","a":1,"q":{"en":"How should you ride when you must travel across a stretch of gravel, sand, mud, or wet leaves?","es":"¿Cómo debes conducir cuando tienes que atravesar un tramo de grava, arena, lodo u hojas mojadas?","ru":"Как следует ехать, когда нужно пересечь участок гравия, песка, грязи или мокрых листьев?","tr":"Çakıl, kum, çamur veya ıslak yapraklardan oluşan bir kesimi geçmek zorunda kaldığınızda nasıl sürmelisiniz?","hi":"जब आपको बजरी, रेत, कीचड़ या गीली पत्तियों के किसी हिस्से से होकर गुज़रना पड़े तो आपको कैसे चलना चाहिए?","ar":"كيف ينبغي أن تقود عندما يتعين عليك السير عبر مساحة من الحصى أو الرمل أو الطين أو الأوراق المبللة؟"},"o":[{"en":"Speed up to power through quickly before losing traction","es":"Acelerar para pasarlo rápidamente antes de perder tracción","ru":"Ускориться, чтобы быстро проскочить, прежде чем потерять сцепление","tr":"Tutuşu kaybetmeden hızla geçmek için hızlanın","hi":"कर्षण खोने से पहले जल्दी से ताकत से पार करने के लिए गति बढ़ाएँ","ar":"تسارع لتعبرها بقوة وبسرعة قبل فقدان قوة الاحتكاك"},{"en":"Reduce speed, avoid sudden moves, and use both brakes gently","es":"Reducir la velocidad, evitar movimientos bruscos y usar ambos frenos suavemente","ru":"Снизить скорость, избегать резких движений и плавно использовать оба тормоза","tr":"Hızı azaltın, ani hareketlerden kaçının ve her iki freni de nazikçe kullanın","hi":"गति कम करें, अचानक हरकतों से बचें और दोनों ब्रेकों का हल्के से उपयोग करें","ar":"قلّل السرعة وتجنّب الحركات المفاجئة واستخدم كلا المكبحين برفق"},{"en":"Grab the front brake hard to keep the wheel from slipping","es":"Apretar el freno delantero con fuerza para evitar que la rueda resbale","ru":"Резко нажать на передний тормоз, чтобы колесо не проскальзывало","tr":"Tekerleğin kaymasını önlemek için ön frene sert basın","hi":"पहिए को फिसलने से रोकने के लिए फ्रंट ब्रेक को ज़ोर से दबाएँ","ar":"اقبض على المكبح الأمامي بقوة لمنع العجلة من الانزلاق"},{"en":"Lean the motorcycle far over to plant the tires firmly","es":"Inclinar la motocicleta bastante para asentar firmemente las llantas","ru":"Сильно наклонить мотоцикл, чтобы крепко прижать шины","tr":"Lastikleri sağlamca yerleştirmek için motosikleti iyice yatırın","hi":"टायरों को मज़बूती से टिकाने के लिए मोटरसाइकिल को बहुत झुकाएँ","ar":"أمِل الدراجة النارية بعيداً لتثبيت الإطارات بثبات"}],"e":{"en":"On any slippery surface, reduce speed, make no sudden moves, and use both brakes gradually. The Motorcycle Operator Manual stresses smooth, gentle control inputs to keep traction on slick surfaces.","es":"En cualquier superficie resbalosa, reduce la velocidad, no hagas movimientos bruscos y usa ambos frenos de forma gradual. El Manual del Operador de Motocicletas resalta usar controles suaves y delicados para mantener la tracción en superficies resbalosas.","ru":"На любой скользкой поверхности снижайте скорость, не делайте резких движений и плавно используйте оба тормоза. Руководство для водителей мотоциклов подчёркивает важность плавных, мягких управляющих воздействий для сохранения сцепления на скользких поверхностях.","tr":"Herhangi bir kaygan yüzeyde, hızı azaltın, ani hareket yapmayın ve her iki freni de kademeli olarak kullanın. Motosiklet Sürücü Kılavuzu, kaygan yüzeylerde tutuşu korumak için yumuşak, nazik kontrol girdilerini vurgular.","hi":"किसी भी फिसलन भरी सतह पर गति कम करें, कोई अचानक हरकत न करें और दोनों ब्रेकों का धीरे-धीरे उपयोग करें। Motorcycle Operator Manual फिसलन भरी सतहों पर कर्षण बनाए रखने के लिए सहज, हल्के नियंत्रण पर ज़ोर देता है।","ar":"على أي سطح زلق، قلّل السرعة، ولا تقم بحركات مفاجئة، واستخدم كلا المكبحين تدريجياً. يشدد دليل مشغل الدراجة النارية على نعومة ولطف مدخلات التحكم للحفاظ على قوة الاحتكاك على الأسطح الزلقة."}},{"cat":"hazards","a":2,"q":{"en":"Why are metal bridge gratings and rain grooves a special concern for motorcyclists?","es":"¿Por qué las rejillas metálicas de los puentes y las ranuras antilluvia son una preocupación especial para los motociclistas?","ru":"Почему металлические решётки мостов и дождевые канавки представляют особую проблему для мотоциклистов?","tr":"Metal köprü ızgaraları ve yağmur olukları motosikletliler için neden özel bir endişe kaynağıdır?","hi":"धातु के पुल की जालियाँ और रेन ग्रूव मोटरसाइकिल चालकों के लिए विशेष चिंता का विषय क्यों हैं?","ar":"لماذا تُعد شبكات الجسور المعدنية وأخاديد المطر مصدر قلق خاص لسائقي الدراجات النارية؟"},"o":[{"en":"They cause the tires to overheat and lose air pressure","es":"Hacen que las llantas se sobrecalienten y pierdan presión de aire","ru":"Они вызывают перегрев шин и потерю давления воздуха","tr":"Lastiklerin aşırı ısınmasına ve hava basıncı kaybetmesine neden olurlar","hi":"वे टायरों को ज़्यादा गर्म कर देते हैं और हवा का दबाव कम कर देते हैं","ar":"تتسبب في ارتفاع حرارة الإطارات وفقدان ضغط الهواء"},{"en":"They make the throttle stick in the open position","es":"Hacen que el acelerador se atasque en posición abierta","ru":"Они заставляют дроссель заклинивать в открытом положении","tr":"Gazın açık konumda takılı kalmasına neden olurlar","hi":"वे थ्रॉटल को खुली स्थिति में अटका देते हैं","ar":"تجعل دواسة الوقود عالقة في وضع الفتح"},{"en":"They can make the motorcycle weave and feel unsteady","es":"Pueden hacer que la motocicleta serpentee y se sienta inestable","ru":"Они могут заставить мотоцикл вилять и ощущаться неустойчиво","tr":"Motosikletin sallanmasına ve dengesiz hissettirmesine neden olabilirler","hi":"वे मोटरसाइकिल को लहराने और अस्थिर महसूस करा सकते हैं","ar":"يمكن أن تجعل الدراجة النارية تتمايل وتبدو غير مستقرة"},{"en":"They are completely safe and require no special attention","es":"Son completamente seguras y no requieren atención especial","ru":"Они полностью безопасны и не требуют особого внимания","tr":"Tamamen güvenlidirler ve özel dikkat gerektirmezler","hi":"वे पूरी तरह सुरक्षित हैं और किसी विशेष ध्यान की आवश्यकता नहीं है","ar":"إنها آمنة تماماً ولا تتطلب أي اهتمام خاص"}],"e":{"en":"Riding over rain grooves or bridge gratings may make a motorcycle weave. The Motorcycle Operator Manual explains this wandering feeling is generally not hazardous if you stay relaxed and ride straight across.","es":"Conducir sobre ranuras antilluvia o rejillas de puentes puede hacer que una motocicleta serpentee. El Manual del Operador de Motocicletas explica que esta sensación de vagabundeo por lo general no es peligrosa si te mantienes relajado y conduces recto a través de ellas.","ru":"Езда по дождевым канавкам или решёткам мостов может заставить мотоцикл вилять. Руководство для водителей мотоциклов объясняет, что это ощущение блуждания обычно не опасно, если вы остаётесь расслабленным и едете прямо поперёк.","tr":"Yağmur olukları veya köprü ızgaraları üzerinde sürmek motosikletin sallanmasına neden olabilir. Motosiklet Sürücü Kılavuzu, rahat kalır ve düz geçerseniz bu gezinme hissinin genellikle tehlikeli olmadığını açıklar.","hi":"रेन ग्रूव या पुल की जालियों पर चलने से मोटरसाइकिल लहरा सकती है। Motorcycle Operator Manual समझाता है कि अगर आप शांत रहें और सीधे पार करें तो यह भटकने का एहसास आमतौर पर खतरनाक नहीं होता।","ar":"قد يجعل القيادة فوق أخاديد المطر أو شبكات الجسور الدراجة النارية تتمايل. يوضح دليل مشغل الدراجة النارية أن هذا الشعور بالتجوال ليس خطراً عموماً إذا بقيت مسترخياً وقدت في خط مستقيم عبرها."}},{"cat":"hazards","a":3,"q":{"en":"What is the correct way to cross a metal bridge grating or section of rain grooves on a motorcycle?","es":"¿Cuál es la manera correcta de cruzar una rejilla metálica de puente o un tramo de ranuras antilluvia en motocicleta?","ru":"Каков правильный способ пересечения металлической решётки моста или участка дождевых канавок на мотоцикле?","tr":"Bir motosiklette metal köprü ızgarasını veya yağmur olukları bölümünü geçmenin doğru yolu nedir?","hi":"मोटरसाइकिल पर धातु की पुल जाली या रेन ग्रूव के हिस्से को पार करने का सही तरीका क्या है?","ar":"ما هي الطريقة الصحيحة لعبور شبكة جسر معدنية أو قسم من أخاديد المطر على دراجة نارية؟"},"o":[{"en":"Zigzag back and forth to follow the grooves","es":"Zigzaguear de un lado a otro para seguir las ranuras","ru":"Двигаться зигзагом из стороны в сторону, следуя за канавками","tr":"Olukları takip etmek için ileri geri zikzak çizin","hi":"ग्रूव का अनुसरण करने के लिए आगे-पीछे ज़िगज़ैग करें","ar":"تعرّج ذهاباً وإياباً لتتبع الأخاديد"},{"en":"Stop on the grating, then ease across slowly","es":"Detenerte sobre la rejilla y luego cruzar despacio","ru":"Остановиться на решётке, затем медленно переехать","tr":"Izgarada durun, ardından yavaşça geçin","hi":"जाली पर रुकें, फिर धीरे-धीरे पार करें","ar":"توقف على الشبكة، ثم اعبرها ببطء"},{"en":"Cross at a sharp angle to the grooves","es":"Cruzar en un ángulo cerrado respecto a las ranuras","ru":"Пересекать под острым углом к канавкам","tr":"Oluklara keskin bir açıyla geçin","hi":"ग्रूव के तीखे कोण पर पार करें","ar":"اعبر بزاوية حادة على الأخاديد"},{"en":"Relax, keep a steady speed, and ride straight across","es":"Relajarte, mantener una velocidad constante y conducir recto a través de ellas","ru":"Расслабиться, держать постоянную скорость и ехать прямо поперёк","tr":"Rahatlayın, sabit bir hız koruyun ve düz geçin","hi":"आराम से रहें, स्थिर गति बनाए रखें और सीधे पार करें","ar":"استرخِ، حافظ على سرعة ثابتة، وقُد في خط مستقيم عبرها"}],"e":{"en":"Relax, maintain a steady speed, and ride straight across gratings and grooves. The Motorcycle Operator Manual notes the wandering feeling is not dangerous, and zigzagging to fight it is far more hazardous.","es":"Relájate, mantén una velocidad constante y conduce recto a través de las rejillas y ranuras. El Manual del Operador de Motocicletas señala que la sensación de vagabundeo no es peligrosa, y que zigzaguear para combatirla es mucho más arriesgado.","ru":"Расслабьтесь, поддерживайте постоянную скорость и едьте прямо поперёк решёток и канавок. Руководство для водителей мотоциклов отмечает, что ощущение блуждания не опасно, а движение зигзагом для борьбы с ним гораздо опаснее.","tr":"Rahatlayın, sabit bir hız koruyun ve ızgaraları ve olukları düz geçin. Motosiklet Sürücü Kılavuzu, gezinme hissinin tehlikeli olmadığını ve buna karşı zikzak çizmenin çok daha tehlikeli olduğunu belirtir.","hi":"आराम से रहें, स्थिर गति बनाए रखें और जालियों व ग्रूव के सीधे पार करें। Motorcycle Operator Manual बताता है कि भटकने का एहसास खतरनाक नहीं है, और इससे लड़ने के लिए ज़िगज़ैग करना कहीं अधिक खतरनाक है।","ar":"استرخِ، حافظ على سرعة ثابتة، وقُد في خط مستقيم عبر الشبكات والأخاديد. يشير دليل مشغل الدراجة النارية إلى أن الشعور بالتجوال ليس خطراً، وأن التعرّج لمقاومته أكثر خطورة بكثير."}},{"cat":"hazards","a":0,"q":{"en":"What is usually the safest way to cross railroad or trolley tracks that run across your lane?","es":"¿Cuál suele ser la manera más segura de cruzar vías de tren o de tranvía que atraviesan tu carril?","ru":"Какой обычно самый безопасный способ пересечения железнодорожных или трамвайных путей, проходящих поперёк вашей полосы?","tr":"Şeritinizi enine kesen demiryolu veya tramvay raylarını geçmenin genellikle en güvenli yolu nedir?","hi":"आपकी लेन के आर-पार चलने वाली रेलरोड या ट्रॉली पटरियों को पार करने का आमतौर पर सबसे सुरक्षित तरीका क्या है?","ar":"ما هي عادةً الطريقة الأكثر أماناً لعبور سكك القطارات أو الترام التي تمتد عبر مسارك؟"},"o":[{"en":"Ride straight within your lane, crossing as near a right angle as practical","es":"Conducir recto dentro de tu carril, cruzando lo más cerca posible de un ángulo recto","ru":"Ехать прямо в пределах своей полосы, пересекая как можно ближе к прямому углу","tr":"Şeritinizin içinde düz sürün, raylara mümkün olduğunca dik açıya yakın geçin","hi":"अपनी लेन में सीधे चलें, जितना व्यावहारिक हो उतना समकोण के पास पार करें","ar":"قُد في خط مستقيم داخل مسارك، عابراً إياها بأقرب ما يمكن من زاوية قائمة عملياً"},{"en":"Stop completely and walk the motorcycle across the rails","es":"Detenerte por completo y caminar con la motocicleta a través de los rieles","ru":"Полностью остановиться и провести мотоцикл через рельсы пешком","tr":"Tamamen durun ve motosikleti raylardan iterek geçirin","hi":"पूरी तरह रुकें और मोटरसाइकिल को पटरियों के पार पैदल ले जाएँ","ar":"توقف تماماً وادفع الدراجة النارية سيراً عبر القضبان"},{"en":"Swerve into the next lane to take the tracks head-on at 90 degrees","es":"Desviarte al siguiente carril para tomar las vías de frente a 90 grados","ru":"Перестроиться в соседнюю полосу, чтобы пересечь пути в лоб под углом 90 градусов","tr":"Rayları 90 derecede karşıdan almak için bir sonraki şerite savrulun","hi":"अगली लेन में मुड़ें ताकि पटरियों को 90 डिग्री पर सीधे लें","ar":"انعطف إلى المسار التالي لتأخذ السكك بشكل مباشر بزاوية 90 درجة"},{"en":"Edge across the rails slowly at a shallow angle","es":"Cruzar los rieles despacio en un ángulo poco pronunciado","ru":"Медленно переезжать рельсы под небольшим углом","tr":"Raylardan sığ bir açıyla yavaşça geçin","hi":"पटरियों के उथले कोण पर धीरे-धीरे पार करें","ar":"اعبر القضبان ببطء بزاوية ضحلة"}],"e":{"en":"It is usually safest to ride straight within your lane to cross tracks, taking them as close to a right angle as practical. The Motorcycle Operator Manual warns that turning to take tracks head-on can send you into another lane.","es":"Por lo general es más seguro conducir recto dentro de tu carril para cruzar las vías, tomándolas lo más cerca posible de un ángulo recto. El Manual del Operador de Motocicletas advierte que girar para tomar las vías de frente puede mandarte a otro carril.","ru":"Обычно безопаснее всего ехать прямо в пределах своей полосы, чтобы пересечь пути, проходя их как можно ближе к прямому углу. Руководство для водителей мотоциклов предупреждает, что поворот для пересечения путей в лоб может выбросить вас на другую полосу.","tr":"Rayları geçmek için genellikle en güvenlisi şeritinizin içinde düz sürmek, onları mümkün olduğunca dik açıya yakın almaktır. Motosiklet Sürücü Kılavuzu, rayları karşıdan almak için dönmenin sizi başka bir şerite sokabileceği konusunda uyarır.","hi":"पटरियों को पार करने के लिए आमतौर पर अपनी लेन में सीधे चलना सबसे सुरक्षित होता है, जितना व्यावहारिक हो उतना समकोण के पास उन्हें लेते हुए। Motorcycle Operator Manual चेतावनी देता है कि पटरियों को सीधे लेने के लिए मुड़ना आपको दूसरी लेन में भेज सकता है।","ar":"عادةً ما يكون من الأكثر أماناً القيادة في خط مستقيم داخل مسارك لعبور السكك، آخذاً إياها بأقرب ما يمكن من زاوية قائمة عملياً. يحذر دليل مشغل الدراجة النارية من أن الانعطاف لأخذ السكك بشكل مباشر قد يدفعك إلى مسار آخر."}},{"cat":"hazards","a":2,"q":{"en":"When tracks, ruts, or pavement seams run parallel to your path of travel, how should you cross them?","es":"Cuando hay vías, surcos o juntas del pavimento que corren paralelos a tu trayectoria, ¿cómo debes cruzarlos?","ru":"Когда пути, колеи или швы покрытия проходят параллельно вашему направлению движения, как следует их пересекать?","tr":"Raylar, oyuklar veya zemin ekleri gidiş yolunuza paralel uzandığında, bunları nasıl geçmelisiniz?","hi":"जब पटरियाँ, खाँचे या सड़क की दरारें आपके चलने के रास्ते के समानांतर चलती हों, तो आपको उन्हें कैसे पार करना चाहिए?","ar":"عندما تمتد السكك أو الأخاديد أو وصلات الرصيف بشكل موازٍ لمسار سيرك، كيف ينبغي أن تعبرها؟"},"o":[{"en":"Cross with your tire riding right along the seam","es":"Cruzar con tu llanta justo sobre la junta","ru":"Пересекать, едучи шиной прямо вдоль шва","tr":"Lastiğiniz tam eke yaslanarak geçin","hi":"अपने टायर को दरार के ठीक साथ रखते हुए पार करें","ar":"اعبر وإطارك يسير تماماً على طول الوصلة"},{"en":"Cross at a shallow 10-degree angle to stay smooth","es":"Cruzar en un ángulo poco pronunciado de 10 grados para mantenerte suave","ru":"Пересекать под небольшим углом в 10 градусов для плавности","tr":"Pürüzsüz kalmak için sığ bir 10 derece açıyla geçin","hi":"सहज रहने के लिए उथले 10 डिग्री कोण पर पार करें","ar":"اعبر بزاوية ضحلة 10 درجات للبقاء بسلاسة"},{"en":"Move away first, then cross at an angle of at least 45 degrees","es":"Alejarte primero y luego cruzar en un ángulo de al menos 45 grados","ru":"Сначала отъехать в сторону, затем пересечь под углом не менее 45 градусов","tr":"Önce uzaklaşın, ardından en az 45 derecelik bir açıyla geçin","hi":"पहले दूर हटें, फिर कम से कम 45 डिग्री के कोण पर पार करें","ar":"ابتعد أولاً، ثم اعبر بزاوية لا تقل عن 45 درجة"},{"en":"Avoid crossing and ride with your tire in the groove","es":"Evitar cruzarlos y conducir con tu llanta dentro de la ranura","ru":"Избегать пересечения и ехать шиной в канавке","tr":"Geçmekten kaçının ve lastiğiniz oyukta olacak şekilde sürün","hi":"पार करने से बचें और अपने टायर को खाँचे में रखकर चलें","ar":"تجنّب العبور وقُد وإطارك في الأخدود"}],"e":{"en":"Move far enough away from parallel tracks or seams to cross them at an angle of at least 45 degrees, then make a quick, sharp turn. The Motorcycle Operator Manual warns that edging across could catch a tire and unbalance you.","es":"Aléjate lo suficiente de las vías o juntas paralelas para cruzarlas en un ángulo de al menos 45 grados, y luego haz un giro rápido y cerrado. El Manual del Operador de Motocicletas advierte que cruzarlas de canto podría atrapar una llanta y desequilibrarte.","ru":"Отъедьте достаточно далеко от параллельных путей или швов, чтобы пересечь их под углом не менее 45 градусов, затем сделайте быстрый резкий поворот. Руководство для водителей мотоциклов предупреждает, что движение вдоль края может зацепить шину и нарушить равновесие.","tr":"Paralel raylardan veya eklerden, en az 45 derecelik bir açıyla geçebilecek kadar uzaklaşın, ardından hızlı, keskin bir dönüş yapın. Motosiklet Sürücü Kılavuzu, kenarından geçmenin bir lastiği yakalayıp dengenizi bozabileceği konusunda uyarır.","hi":"समानांतर पटरियों या दरारों से इतना दूर हट जाएँ कि उन्हें कम से कम 45 डिग्री के कोण पर पार कर सकें, फिर एक तेज़, तीखा मोड़ लें। Motorcycle Operator Manual चेतावनी देता है कि किनारे से पार करना टायर को फँसा सकता है और आपको असंतुलित कर सकता है।","ar":"ابتعد بما يكفي عن السكك أو الوصلات الموازية لعبورها بزاوية لا تقل عن 45 درجة، ثم قم بانعطاف سريع وحاد. يحذر دليل مشغل الدراجة النارية من أن العبور على الحافة قد يحتجز الإطار ويفقدك توازنك."}},{"cat":"hazards","a":3,"q":{"en":"If you cannot avoid riding over an obstacle such as a piece of debris or a pothole edge, what should you do with the handlebars?","es":"Si no puedes evitar pasar sobre un obstáculo, como un trozo de escombro o el borde de un bache, ¿qué debes hacer con el manubrio?","ru":"Если вы не можете избежать наезда на препятствие, например на обломки или край ямы, что следует делать с рулём?","tr":"Bir döküntü parçası veya çukur kenarı gibi bir engelin üzerinden geçmekten kaçınamazsanız, gidonla ne yapmalısınız?","hi":"अगर आप किसी बाधा जैसे मलबे के टुकड़े या गड्ढे के किनारे पर चलने से बच नहीं सकते, तो आपको हैंडलबार के साथ क्या करना चाहिए?","ar":"إذا لم تستطع تجنّب القيادة فوق عائق مثل قطعة حطام أو حافة حفرة، فماذا ينبغي أن تفعل بالمقود؟"},"o":[{"en":"Turn them sharply at the last moment to skip around it","es":"Girarlo bruscamente en el último momento para esquivarlo","ru":"Резко повернуть его в последний момент, чтобы объехать препятствие","tr":"Etrafından atlamak için son anda keskin bir şekilde çevirin","hi":"इसके आसपास से बचने के लिए आखिरी क्षण में उन्हें तीखा मोड़ें","ar":"أدِره بحدة في اللحظة الأخيرة لتتجاوزه"},{"en":"Let them go loose so the wheel floats over the object","es":"Soltarlo para que la rueda flote sobre el objeto","ru":"Отпустить его, чтобы колесо свободно перекатилось через предмет","tr":"Tekerleğin nesnenin üzerinden süzülmesi için gevşek bırakın","hi":"उन्हें ढीला छोड़ दें ताकि पहिया वस्तु के ऊपर तैर जाए","ar":"اتركه مرتخياً حتى تطفو العجلة فوق الجسم"},{"en":"Pull them toward you to lift the front wheel high","es":"Jalarlo hacia ti para levantar bien la rueda delantera","ru":"Потянуть его на себя, чтобы высоко поднять переднее колесо","tr":"Ön tekerleği yükseltmek için kendinize doğru çekin","hi":"सामने के पहिए को ऊँचा उठाने के लिए उन्हें अपनी ओर खींचें","ar":"اسحبه نحوك لرفع العجلة الأمامية عالياً"},{"en":"Keep them straight so the motorcycle stays upright and balanced","es":"Mantenerlo recto para que la motocicleta se mantenga vertical y equilibrada","ru":"Держать его прямо, чтобы мотоцикл оставался вертикальным и сбалансированным","tr":"Motosikletin dik ve dengeli kalması için düz tutun","hi":"उन्हें सीधा रखें ताकि मोटरसाइकिल सीधी और संतुलित रहे","ar":"أبقِه مستقيماً حتى تبقى الدراجة النارية منتصبة ومتوازنة"}],"e":{"en":"Make sure the motorcycle is straight and keep the handlebars straight when riding over an obstacle. The Motorcycle Operator Manual states that an angled approach increases the chance the obstacle will deflect the front wheel.","es":"Asegúrate de que la motocicleta esté recta y mantén el manubrio recto al pasar sobre un obstáculo. El Manual del Operador de Motocicletas indica que un acercamiento en ángulo aumenta la probabilidad de que el obstáculo desvíe la rueda delantera.","ru":"Убедитесь, что мотоцикл едет прямо, и держите руль прямо при наезде на препятствие. Руководство для водителей мотоциклов утверждает, что подход под углом увеличивает вероятность того, что препятствие отклонит переднее колесо.","tr":"Bir engelin üzerinden geçerken motosikletin düz olduğundan emin olun ve gidonu düz tutun. Motosiklet Sürücü Kılavuzu, açılı bir yaklaşımın engelin ön tekerleği saptırma olasılığını artırdığını belirtir.","hi":"सुनिश्चित करें कि मोटरसाइकिल सीधी हो और बाधा पर चलते समय हैंडलबार को सीधा रखें। Motorcycle Operator Manual बताता है कि कोण से पहुँचने से बाधा द्वारा सामने के पहिए को मोड़ देने की संभावना बढ़ जाती है।","ar":"تأكد من أن الدراجة النارية مستقيمة وأبقِ المقود مستقيماً عند القيادة فوق عائق. ينص دليل مشغل الدراجة النارية على أن الاقتراب بزاوية يزيد من فرصة أن يحرف العائق العجلة الأمامية."}},{"cat":"hazards","a":1,"q":{"en":"When you must ride over an obstacle in the road, what should you do with your body just before contact?","es":"Cuando debes pasar sobre un obstáculo en la vía, ¿qué debes hacer con tu cuerpo justo antes del contacto?","ru":"Когда вам приходится наезжать на препятствие на дороге, что следует делать с телом непосредственно перед контактом?","tr":"Yoldaki bir engelin üzerinden geçmek zorunda kaldığınızda, temastan hemen önce vücudunuzla ne yapmalısınız?","hi":"जब आपको सड़क पर किसी बाधा पर चलना पड़े, तो संपर्क से ठीक पहले आपको अपने शरीर के साथ क्या करना चाहिए?","ar":"عندما يتعين عليك القيادة فوق عائق في الطريق، ماذا ينبغي أن تفعل بجسمك قبل الاصطدام مباشرةً؟"},"o":[{"en":"Press your full weight down into the seat to stay planted","es":"Presionar todo tu peso contra el asiento para mantenerte firme","ru":"Прижаться всем весом к сиденью, чтобы оставаться на месте","tr":"Sabit kalmak için tüm ağırlığınızı sele üzerine bastırın","hi":"टिके रहने के लिए अपना पूरा वज़न सीट में नीचे दबाएँ","ar":"اضغط بكامل وزنك على المقعد لتبقى ثابتاً"},{"en":"Rise slightly off the seat with your weight on the foot pegs","es":"Levantarte ligeramente del asiento con el peso sobre los estribos","ru":"Слегка приподняться над сиденьем, перенеся вес на подножки","tr":"Ağırlığınız basamaklarda olacak şekilde seleden hafifçe yükselin","hi":"अपना वज़न फुट पेग पर रखते हुए सीट से थोड़ा ऊपर उठें","ar":"ارتفع قليلاً عن المقعد مع وضع وزنك على مساند القدمين"},{"en":"Lean far back and lock both arms straight against the bars","es":"Inclinarte bien hacia atrás y trabar ambos brazos rectos contra el manubrio","ru":"Сильно откинуться назад и зафиксировать обе руки прямо на руле","tr":"Geriye doğru iyice yaslanın ve her iki kolu gidona karşı düz kilitleyin","hi":"बहुत पीछे झुकें और दोनों बाँहों को बार पर सीधा लॉक करें","ar":"انحنِ بعيداً للخلف واقفل كلتا ذراعيك مستقيمتين على المقود"},{"en":"Stand fully upright with your feet off the pegs","es":"Pararte completamente erguido con los pies fuera de los estribos","ru":"Полностью встать в полный рост, сняв ноги с подножек","tr":"Ayaklarınız basamaklardan kalkmış halde tamamen ayağa kalkın","hi":"अपने पैरों को पेग से हटाकर पूरी तरह सीधे खड़े हो जाएँ","ar":"قف منتصباً تماماً مع رفع قدميك عن المساند"}],"e":{"en":"Rise slightly off the seat with your weight on the foot pegs to let your knees and elbows absorb the shock. The Motorcycle Operator Manual says this keeps you from being thrown off when crossing an obstacle.","es":"Levántate ligeramente del asiento con el peso sobre los estribos para dejar que tus rodillas y codos absorban el impacto. El Manual del Operador de Motocicletas dice que esto evita que salgas despedido al cruzar un obstáculo.","ru":"Слегка приподнимитесь над сиденьем, перенеся вес на подножки, чтобы колени и локти поглотили удар. Руководство для водителей мотоциклов гласит, что это не даёт вам быть сброшенным при наезде на препятствие.","tr":"Dizlerinizin ve dirseklerinizin şoku emmesine izin vermek için ağırlığınız basamaklarda olacak şekilde seleden hafifçe yükselin. Motosiklet Sürücü Kılavuzu, bunun bir engeli geçerken atılmanızı önlediğini söyler.","hi":"अपना वज़न फुट पेग पर रखते हुए सीट से थोड़ा ऊपर उठें ताकि आपके घुटने और कोहनियाँ झटका सोख सकें। Motorcycle Operator Manual कहता है कि यह आपको बाधा पार करते समय फेंके जाने से बचाता है।","ar":"ارتفع قليلاً عن المقعد مع وضع وزنك على مساند القدمين للسماح لركبتيك ومرفقيك بامتصاص الصدمة. يقول دليل مشغل الدراجة النارية إن هذا يمنعك من أن تُقذف عند عبور عائق."}},{"cat":"hazards","a":0,"q":{"en":"What is the recommended approach to speed before riding over an unavoidable obstacle?","es":"¿Cuál es el enfoque recomendado respecto a la velocidad antes de pasar sobre un obstáculo inevitable?","ru":"Каков рекомендуемый подход к скорости перед наездом на неизбежное препятствие?","tr":"Kaçınılmaz bir engelin üzerinden geçmeden önce hız konusunda önerilen yaklaşım nedir?","hi":"किसी अपरिहार्य बाधा पर चलने से पहले गति के लिए अनुशंसित दृष्टिकोण क्या है?","ar":"ما هو الأسلوب الموصى به بشأن السرعة قبل القيادة فوق عائق لا يمكن تجنّبه؟"},"o":[{"en":"Slow down as much as possible before contact","es":"Reducir la velocidad tanto como sea posible antes del contacto","ru":"Снизить скорость как можно больше перед контактом","tr":"Temastan önce mümkün olduğunca yavaşlayın","hi":"संपर्क से पहले जितना संभव हो उतनी गति कम करें","ar":"أبطئ قدر الإمكان قبل الاصطدام"},{"en":"Accelerate hard to launch the front wheel over it","es":"Acelerar fuerte para impulsar la rueda delantera por encima","ru":"Сильно ускориться, чтобы запустить переднее колесо через него","tr":"Ön tekerleği üzerinden fırlatmak için sert hızlanın","hi":"सामने के पहिए को इसके ऊपर लॉन्च करने के लिए ज़ोर से एक्सीलरेट करें","ar":"تسارع بقوة لإطلاق العجلة الأمامية فوقه"},{"en":"Keep your normal cruising speed for stability","es":"Mantener tu velocidad de crucero normal para tener estabilidad","ru":"Сохранять обычную крейсерскую скорость для устойчивости","tr":"Stabilite için normal seyir hızınızı koruyun","hi":"स्थिरता के लिए अपनी सामान्य क्रूज़िंग गति बनाए रखें","ar":"حافظ على سرعتك العادية للحفاظ على الثبات"},{"en":"Coast in neutral with the clutch pulled in","es":"Avanzar en neutro con el embrague apretado","ru":"Катиться на нейтрали с выжатым сцеплением","tr":"Debriyaj basılı halde boşta süzülün","hi":"क्लच दबाकर न्यूट्रल में कोस्ट करें","ar":"انزلق في وضع الحياد مع سحب القابض"}],"e":{"en":"Slow down as much as possible before contact with an obstacle. The Motorcycle Operator Manual then advises making sure the bike is straight and rising off the seat to absorb the shock with your knees and elbows.","es":"Reduce la velocidad tanto como sea posible antes del contacto con un obstáculo. Luego, el Manual del Operador de Motocicletas aconseja asegurarte de que la moto esté recta y levantarte del asiento para absorber el impacto con las rodillas y los codos.","ru":"Снизьте скорость как можно больше перед контактом с препятствием. Затем Руководство для водителей мотоциклов советует убедиться, что мотоцикл едет прямо, и приподняться над сиденьем, чтобы поглотить удар коленями и локтями.","tr":"Bir engelle temastan önce mümkün olduğunca yavaşlayın. Motosiklet Sürücü Kılavuzu ardından motosikletin düz olduğundan emin olmayı ve şoku dizlerinizle ve dirseklerinizle emmek için seleden yükselmeyi tavsiye eder.","hi":"बाधा से संपर्क से पहले जितना संभव हो उतनी गति कम करें। Motorcycle Operator Manual फिर सलाह देता है कि सुनिश्चित करें कि बाइक सीधी हो और झटके को अपने घुटनों व कोहनियों से सोखने के लिए सीट से ऊपर उठें।","ar":"أبطئ قدر الإمكان قبل الاصطدام بعائق. ثم ينصح دليل مشغل الدراجة النارية بالتأكد من أن الدراجة مستقيمة والارتفاع عن المقعد لامتصاص الصدمة بركبتيك ومرفقيك."}},{"cat":"hazards","a":3,"q":{"en":"Compared with daytime riding, how should you adjust your speed when riding at night?","es":"En comparación con la conducción diurna, ¿cómo debes ajustar tu velocidad al conducir de noche?","ru":"По сравнению с дневной ездой, как следует регулировать скорость при езде ночью?","tr":"Gündüz sürüşüyle karşılaştırıldığında, gece sürerken hızınızı nasıl ayarlamalısınız?","hi":"दिन की सवारी की तुलना में, रात में सवारी करते समय आपको अपनी गति कैसे समायोजित करनी चाहिए?","ar":"مقارنةً بالقيادة نهاراً، كيف ينبغي أن تعدّل سرعتك عند القيادة ليلاً؟"},"o":[{"en":"Ride faster to spend less time in the dark","es":"Conducir más rápido para pasar menos tiempo en la oscuridad","ru":"Ехать быстрее, чтобы провести меньше времени в темноте","tr":"Karanlıkta daha az zaman geçirmek için daha hızlı sürün","hi":"अंधेरे में कम समय बिताने के लिए तेज़ चलें","ar":"قُد أسرع لتقضي وقتاً أقل في الظلام"},{"en":"Keep exactly the same speed as in daylight","es":"Mantener exactamente la misma velocidad que de día","ru":"Сохранять точно такую же скорость, как при дневном свете","tr":"Tam olarak gündüzdeki aynı hızı koruyun","hi":"दिन के उजाले की तरह बिल्कुल वही गति बनाए रखें","ar":"حافظ تماماً على نفس السرعة كما في وضح النهار"},{"en":"Match the speed of the fastest nearby traffic","es":"Igualar la velocidad del tráfico cercano más rápido","ru":"Подстраиваться под скорость самого быстрого транспорта поблизости","tr":"Yakındaki en hızlı trafiğin hızına uyun","hi":"आसपास की सबसे तेज़ ट्रैफ़िक की गति से मिलाएँ","ar":"اضبط سرعتك على سرعة أسرع حركة مرور قريبة"},{"en":"Ride even slower than you would during the day","es":"Conducir aún más despacio de lo que lo harías de día","ru":"Ехать ещё медленнее, чем вы ехали бы днём","tr":"Gündüz süreceğinizden bile daha yavaş sürün","hi":"दिन की तुलना में और भी धीमे चलें","ar":"قُد أبطأ حتى مما تفعل خلال النهار"}],"e":{"en":"Ride more slowly at night than you would during the day, especially on unfamiliar roads. The Motorcycle Operator Manual explains that reduced visibility means you need more room and time to react to hazards.","es":"Conduce más despacio de noche de lo que lo harías de día, especialmente en vías desconocidas. El Manual del Operador de Motocicletas explica que la visibilidad reducida significa que necesitas más espacio y tiempo para reaccionar ante los peligros.","ru":"Ездите медленнее ночью, чем днём, особенно на незнакомых дорогах. Руководство для водителей мотоциклов объясняет, что сниженная видимость означает, что вам нужно больше места и времени для реакции на опасности.","tr":"Gece, özellikle tanımadığınız yollarda gündüz süreceğinizden daha yavaş sürün. Motosiklet Sürücü Kılavuzu, azalan görüşün tehlikelere tepki vermek için daha fazla yer ve zamana ihtiyaç duymanız anlamına geldiğini açıklar.","hi":"रात में दिन की तुलना में अधिक धीमे चलें, खासकर अपरिचित सड़कों पर। Motorcycle Operator Manual समझाता है कि कम दृश्यता का मतलब है कि आपको खतरों पर प्रतिक्रिया करने के लिए अधिक जगह और समय चाहिए।","ar":"قُد أبطأ ليلاً مما تفعل خلال النهار، خاصة على الطرق غير المألوفة. يوضح دليل مشغل الدراجة النارية أن انخفاض الرؤية يعني أنك بحاجة إلى مزيد من المساحة والوقت لرد الفعل تجاه المخاطر."}},{"cat":"hazards","a":1,"q":{"en":"How can the vehicle ahead of you help you ride more safely at night?","es":"¿Cómo puede ayudarte el vehículo que va adelante a conducir con más seguridad de noche?","ru":"Как транспортное средство впереди вас может помочь вам ездить безопаснее ночью?","tr":"Önünüzdeki araç, gece daha güvenli sürmenize nasıl yardımcı olabilir?","hi":"आपके आगे चल रहा वाहन रात में अधिक सुरक्षित सवारी करने में आपकी मदद कैसे कर सकता है?","ar":"كيف يمكن للمركبة أمامك أن تساعدك على القيادة بأمان أكبر ليلاً؟"},"o":[{"en":"It blocks oncoming headlight glare so you can switch your lights off","es":"Bloquea el resplandor de los faros que vienen de frente para que puedas apagar tus luces","ru":"Оно блокирует слепящий свет встречных фар, чтобы вы могли выключить свои огни","tr":"Karşıdan gelen far parıltısını engeller, böylece ışıklarınızı kapatabilirsiniz","hi":"यह सामने से आ रही हेडलाइट की चकाचौंध रोकता है ताकि आप अपनी लाइट बंद कर सकें","ar":"تحجب وهج المصابيح الأمامية القادمة حتى تتمكن من إطفاء أضوائك"},{"en":"Its taillights and headlights can reveal dips, bumps, and the road ahead","es":"Sus luces traseras y faros pueden revelar hondonadas, baches y la vía adelante","ru":"Его задние и передние фары могут выявить впадины, неровности и дорогу впереди","tr":"Stop lambaları ve farları çukurları, tümsekleri ve ileriki yolu ortaya çıkarabilir","hi":"इसकी टेललाइट और हेडलाइट गड्ढों, उभारों और आगे की सड़क को उजागर कर सकती हैं","ar":"يمكن لأضوائها الخلفية والأمامية أن تكشف المنخفضات والمطبات والطريق أمامك"},{"en":"It lets you draft close behind to save fuel and stay alert","es":"Te permite ir muy pegado detrás para ahorrar combustible y mantenerte alerta","ru":"Оно позволяет вам двигаться вплотную за ним, чтобы экономить топливо и сохранять бдительность","tr":"Yakıt tasarrufu yapıp uyanık kalmak için arkasından yakın sürmenize olanak tanır","hi":"यह आपको ईंधन बचाने और सतर्क रहने के लिए पास से ड्राफ्ट करने देता है","ar":"تتيح لك الانسياب قريباً خلفها لتوفير الوقود والبقاء يقظاً"},{"en":"It guarantees the lane is clear so you no longer need to scan","es":"Garantiza que el carril está libre, así que ya no necesitas explorar","ru":"Оно гарантирует, что полоса свободна, так что вам больше не нужно сканировать","tr":"Şeritin boş olduğunu garanti eder, böylece artık taramaya gerek kalmaz","hi":"यह गारंटी देता है कि लेन खाली है ताकि आपको अब स्कैन करने की ज़रूरत न पड़े","ar":"تضمن أن المسار خالٍ فلا تعود بحاجة إلى المسح البصري"}],"e":{"en":"The headlights of a car ahead can give you a better view of the road than even your own high beam. The Motorcycle Operator Manual suggests using the lights of vehicles ahead to spot the road's contour and hazards.","es":"Los faros de un auto que va adelante pueden darte una mejor visión de la vía que incluso tu propia luz alta. El Manual del Operador de Motocicletas sugiere usar las luces de los vehículos que van adelante para detectar el contorno de la vía y los peligros.","ru":"Фары автомобиля впереди могут дать вам лучший обзор дороги, чем даже ваш собственный дальний свет. Руководство для водителей мотоциклов предлагает использовать огни транспортных средств впереди, чтобы заметить рельеф дороги и опасности.","tr":"Önünüzdeki bir arabanın farları, size kendi uzun huzmenizden bile daha iyi bir yol görüşü verebilir. Motosiklet Sürücü Kılavuzu, yolun konturunu ve tehlikeleri fark etmek için önünüzdeki araçların ışıklarını kullanmanızı önerir.","hi":"आगे चल रही कार की हेडलाइट आपको आपकी अपनी हाई बीम से भी बेहतर सड़क का दृश्य दे सकती है। Motorcycle Operator Manual सड़क की बनावट और खतरों को पहचानने के लिए आगे के वाहनों की लाइट का उपयोग करने का सुझाव देता है।","ar":"يمكن للمصابيح الأمامية لسيارة أمامك أن تمنحك رؤية أفضل للطريق من ضوئك العالي نفسه. يقترح دليل مشغل الدراجة النارية استخدام أضواء المركبات الأمامية لرصد تضاريس الطريق والمخاطر."}},{"cat":"hazards","a":2,"q":{"en":"When should you use your high beam at night while riding a motorcycle?","es":"¿Cuándo debes usar tu luz alta de noche al conducir una motocicleta?","ru":"Когда следует использовать дальний свет ночью при езде на мотоцикле?","tr":"Bir motosiklet sürerken gece uzun huzmeyi ne zaman kullanmalısınız?","hi":"मोटरसाइकिल चलाते समय रात में आपको अपनी हाई बीम का उपयोग कब करना चाहिए?","ar":"متى ينبغي أن تستخدم ضوءك العالي ليلاً أثناء قيادة دراجة نارية؟"},"o":[{"en":"Only when riding through well-lit city streets","es":"Solo al conducir por calles bien iluminadas de la ciudad","ru":"Только при езде по хорошо освещённым городским улицам","tr":"Yalnızca iyi aydınlatılmış şehir sokaklarında sürerken","hi":"केवल तब जब अच्छी रोशनी वाली शहरी सड़कों से गुज़र रहे हों","ar":"فقط عند القيادة عبر شوارع المدينة جيدة الإضاءة"},{"en":"Never, because a high beam blinds you to the road","es":"Nunca, porque la luz alta te deslumbra y te impide ver la vía","ru":"Никогда, потому что дальний свет ослепляет вас на дороге","tr":"Asla, çünkü uzun huzme sizi yola karşı kör eder","hi":"कभी नहीं, क्योंकि हाई बीम आपको सड़क के लिए अंधा कर देती है","ar":"أبداً، لأن الضوء العالي يُعمي رؤيتك للطريق"},{"en":"Whenever you are not following or meeting another vehicle","es":"Siempre que no estés siguiendo o cruzándote con otro vehículo","ru":"Всякий раз, когда вы не следуете за другим транспортным средством и не встречаете его","tr":"Başka bir aracı takip etmediğiniz veya karşılaşmadığınız her zaman","hi":"जब भी आप किसी अन्य वाहन के पीछे न चल रहे हों या सामने से न आ रहे हों","ar":"كلما لم تكن تسير خلف مركبة أخرى أو تلتقي بها"},{"en":"Only when another vehicle is close in front of you","es":"Solo cuando otro vehículo está cerca frente a ti","ru":"Только когда другое транспортное средство находится близко впереди вас","tr":"Yalnızca başka bir araç önünüzde yakınken","hi":"केवल तब जब कोई अन्य वाहन आपके बिल्कुल सामने हो","ar":"فقط عندما تكون مركبة أخرى قريبة أمامك"}],"e":{"en":"Use your high beam whenever you are not following or meeting a car, to see as far ahead as possible. The Motorcycle Operator Manual recommends the high beam in the dark except when it would dazzle other drivers.","es":"Usa tu luz alta siempre que no estés siguiendo a un auto ni cruzándote con uno, para ver lo más lejos posible. El Manual del Operador de Motocicletas recomienda la luz alta en la oscuridad, salvo cuando deslumbre a otros conductores.","ru":"Используйте дальний свет всякий раз, когда вы не следуете за автомобилем и не встречаете его, чтобы видеть как можно дальше вперёд. Руководство для водителей мотоциклов рекомендует дальний свет в темноте, кроме случаев, когда он ослепляет других водителей.","tr":"Mümkün olduğunca ileriyi görebilmek için bir arabayı takip etmediğiniz veya bir arabayla karşılaşmadığınız her zaman uzun huzmenizi kullanın. Motosiklet Sürücü Kılavuzu, diğer sürücülerin gözünü kamaştıracağı durumlar dışında karanlıkta uzun huzmeyi önerir.","hi":"जब भी आप किसी कार के पीछे न चल रहे हों या सामने से न मिल रहे हों, तो जितना दूर तक संभव हो देखने के लिए अपनी हाई बीम का उपयोग करें। Motorcycle Operator Manual अंधेरे में हाई बीम की सिफ़ारिश करता है, सिवाय जब यह अन्य चालकों को चकाचौंध कर दे।","ar":"استخدم ضوءك العالي كلما لم تكن تسير خلف سيارة أو تلتقي بها، لترى أبعد ما يمكن أمامك. يوصي دليل مشغل الدراجة النارية بالضوء العالي في الظلام إلا عندما يبهر السائقين الآخرين."}},{"cat":"hazards","a":0,"q":{"en":"How should you adjust your following distance when riding at night?","es":"¿Cómo debes ajustar tu distancia de seguimiento al conducir de noche?","ru":"Как следует регулировать дистанцию следования при езде ночью?","tr":"Gece sürerken takip mesafenizi nasıl ayarlamalısınız?","hi":"रात में सवारी करते समय आपको अपनी फॉलोइंग दूरी कैसे समायोजित करनी चाहिए?","ar":"كيف ينبغي أن تعدّل مسافة الاتباع عند القيادة ليلاً؟"},"o":[{"en":"Increase it, opening up a larger cushion than you keep by day","es":"Aumentarla, abriendo un colchón más grande del que mantienes de día","ru":"Увеличить её, оставляя больший запас, чем днём","tr":"Artırın, gündüz tuttuğunuzdan daha büyük bir tampon açın","hi":"इसे बढ़ाएँ, दिन में रखे जाने वाले कुशन से बड़ा कुशन खोलें","ar":"زِدها، بفتح مسافة أمان أكبر مما تحافظ عليه نهاراً"},{"en":"Decrease it so you can use the leader's lights up close","es":"Disminuirla para poder usar de cerca las luces del que va adelante","ru":"Уменьшить её, чтобы вблизи использовать огни едущего впереди","tr":"Önderin ışıklarını yakından kullanabilmek için azaltın","hi":"इसे कम करें ताकि आप आगे वाले की लाइट को पास से उपयोग कर सकें","ar":"قلّلها حتى تتمكن من استخدام أضواء المركبة الأمامية عن قرب"},{"en":"Keep the same one-second gap you use in daylight","es":"Mantener el mismo intervalo de un segundo que usas de día","ru":"Сохранять тот же односекундный интервал, что и днём","tr":"Gündüz kullandığınız aynı bir saniyelik boşluğu koruyun","hi":"वही एक-सेकंड का अंतर बनाए रखें जो आप दिन के उजाले में रखते हैं","ar":"حافظ على نفس فجوة الثانية الواحدة التي تستخدمها في وضح النهار"},{"en":"Following distance does not matter once headlights are on","es":"La distancia de seguimiento no importa una vez que los faros están encendidos","ru":"Дистанция следования не имеет значения, когда фары включены","tr":"Farlar açık olunca takip mesafesi önemli değildir","hi":"हेडलाइट चालू होने के बाद फॉलोइंग दूरी मायने नहीं रखती","ar":"لا تهم مسافة الاتباع بمجرد إضاءة المصابيح الأمامية"}],"e":{"en":"Increase your following distance at night because it is harder to judge distances and spot hazards in the dark. The Motorcycle Operator Manual advises opening up a larger space cushion when visibility is reduced.","es":"Aumenta tu distancia de seguimiento de noche porque es más difícil calcular distancias y detectar peligros en la oscuridad. El Manual del Operador de Motocicletas aconseja abrir un colchón de espacio más grande cuando la visibilidad es reducida.","ru":"Увеличивайте дистанцию следования ночью, потому что в темноте труднее оценивать расстояния и замечать опасности. Руководство для водителей мотоциклов советует оставлять больший запас пространства при сниженной видимости.","tr":"Gece mesafeleri değerlendirmek ve tehlikeleri fark etmek daha zor olduğu için takip mesafenizi artırın. Motosiklet Sürücü Kılavuzu, görüş azaldığında daha büyük bir tampon boşluğu açmayı tavsiye eder.","hi":"रात में अपनी फॉलोइंग दूरी बढ़ाएँ क्योंकि अंधेरे में दूरी आँकना और खतरों को पहचानना कठिन होता है। Motorcycle Operator Manual सलाह देता है कि दृश्यता कम होने पर बड़ा स्पेस कुशन खोलें।","ar":"زِد مسافة الاتباع ليلاً لأن من الأصعب تقدير المسافات ورصد المخاطر في الظلام. ينصح دليل مشغل الدراجة النارية بفتح مسافة أمان أكبر عند انخفاض الرؤية."}},{"cat":"hazards","a":3,"q":{"en":"How should you handle a sudden strong gust of wind that pushes you sideways while riding?","es":"¿Cómo debes manejar una ráfaga de viento fuerte y repentina que te empuja de lado mientras conduces?","ru":"Как следует справляться с внезапным сильным порывом ветра, толкающим вас вбок во время езды?","tr":"Sürerken sizi yana iten ani, güçlü bir rüzgar hamlesini nasıl ele almalısınız?","hi":"सवारी करते समय अचानक तेज़ हवा का झोंका जो आपको बगल में धकेलता है, उसे आपको कैसे संभालना चाहिए?","ar":"كيف ينبغي أن تتعامل مع هبّة رياح قوية مفاجئة تدفعك جانبياً أثناء القيادة؟"},"o":[{"en":"Lock your arms stiff and grip the bars as hard as you can","es":"Trabar los brazos rígidos y agarrar el manubrio lo más fuerte que puedas","ru":"Зафиксировать руки жёстко и схватить руль как можно крепче","tr":"Kollarınızı sertçe kilitleyin ve gidonu olabildiğince sıkı kavrayın","hi":"अपनी बाँहें अकड़कर लॉक करें और बार को जितना ज़ोर से पकड़ सकें पकड़ें","ar":"اقفل ذراعيك بصلابة واقبض على المقود بأقصى قوة"},{"en":"Brake hard and come to a quick stop in your lane","es":"Frenar fuerte y detenerte rápidamente en tu carril","ru":"Резко затормозить и быстро остановиться на своей полосе","tr":"Sert fren yapın ve şeritinizde hızla durun","hi":"ज़ोर से ब्रेक लगाएँ और अपनी लेन में जल्दी रुक जाएँ","ar":"اكبح بقوة وتوقف بسرعة في مسارك"},{"en":"Lift both feet and let the wind straighten the bike for you","es":"Levantar ambos pies y dejar que el viento enderece la moto por ti","ru":"Поднять обе ноги и дать ветру самому выровнять мотоцикл","tr":"Her iki ayağınızı kaldırın ve rüzgarın motoru sizin için düzeltmesine izin verin","hi":"दोनों पैर उठाएँ और हवा को बाइक सीधी करने दें","ar":"ارفع كلتا قدميك ودع الرياح تقوّم لك الدراجة"},{"en":"Stay relaxed on the bars and steer gently to bring the bike back into your lane","es":"Mantenerte relajado en el manubrio y dirigir con suavidad para volver a tu carril","ru":"Оставаться расслабленным на руле и мягко рулить, чтобы вернуть мотоцикл на свою полосу","tr":"Gidonda rahat kalın ve motosikleti şeritinize geri getirmek için nazikçe yönlendirin","hi":"बार पर आराम से रहें और बाइक को वापस अपनी लेन में लाने के लिए हल्के से स्टीयर करें","ar":"ابقَ مسترخياً على المقود ووجّه برفق لإعادة الدراجة إلى مسارك"}],"e":{"en":"Keep a firm but relaxed grip and make gentle steering corrections to recover from a wind gust. The Motorcycle Operator Manual warns that a stiff, locked grip makes a motorcycle harder to control in wind.","es":"Mantén un agarre firme pero relajado y haz correcciones suaves de dirección para recuperarte de una ráfaga de viento. El Manual del Operador de Motocicletas advierte que un agarre rígido y trabado hace que la motocicleta sea más difícil de controlar con viento.","ru":"Держите руль крепко, но расслабленно, и делайте мягкие корректировки рулём, чтобы восстановиться после порыва ветра. Руководство для водителей мотоциклов предупреждает, что жёсткий, зафиксированный хват затрудняет управление мотоциклом на ветру.","tr":"Bir rüzgar hamlesinden toparlanmak için sıkı ama rahat bir tutuş koruyun ve nazik yönlendirme düzeltmeleri yapın. Motosiklet Sürücü Kılavuzu, sert, kilitli bir tutuşun rüzgarda bir motosikleti kontrol etmeyi zorlaştırdığı konusunda uyarır.","hi":"हवा के झोंके से उबरने के लिए मज़बूत लेकिन आराम से पकड़ बनाए रखें और हल्के स्टीयरिंग सुधार करें। Motorcycle Operator Manual चेतावनी देता है कि अकड़ी, लॉक की गई पकड़ हवा में मोटरसाइकिल को नियंत्रित करना कठिन बना देती है।","ar":"حافظ على قبضة ثابتة لكن مسترخية وقم بتصحيحات توجيه لطيفة للتعافي من هبّة رياح. يحذر دليل مشغل الدراجة النارية من أن القبضة الصلبة المقفلة تجعل الدراجة النارية أصعب في التحكم في الرياح."}},{"cat":"hazards","a":1,"q":{"en":"What should you anticipate when a large truck or bus passes you or comes toward you on the highway?","es":"¿Qué debes anticipar cuando un camión o autobús grande te rebasa o viene hacia ti en la carretera?","ru":"Что следует ожидать, когда большой грузовик или автобус обгоняет вас или едет вам навстречу на шоссе?","tr":"Büyük bir kamyon veya otobüs sizi geçtiğinde ya da otoyolda size doğru geldiğinde neyi öngörmelisiniz?","hi":"जब कोई बड़ा ट्रक या बस राजमार्ग पर आपको पास करे या आपकी ओर आए तो आपको क्या अनुमान लगाना चाहिए?","ar":"ماذا ينبغي أن تتوقع عندما تتجاوزك شاحنة أو حافلة كبيرة أو تأتي نحوك على الطريق السريع؟"},"o":[{"en":"A loss of engine power as your bike is shielded from the air","es":"Una pérdida de potencia del motor al quedar tu moto resguardada del aire","ru":"Потери мощности двигателя, так как ваш мотоцикл оказывается заслонён от воздуха","tr":"Motorunuz havadan korunduğu için bir motor gücü kaybı","hi":"इंजन की शक्ति का नुकसान क्योंकि आपकी बाइक हवा से बच जाती है","ar":"فقدان قدرة المحرك مع حماية دراجتك من الهواء"},{"en":"A blast of wind that can push your motorcycle, so be ready to react","es":"Una ráfaga de viento que puede empujar tu motocicleta, así que prepárate para reaccionar","ru":"Порыва ветра, который может толкнуть ваш мотоцикл, поэтому будьте готовы среагировать","tr":"Motosikletinizi itebilecek bir rüzgar patlaması, bu yüzden tepki vermeye hazır olun","hi":"हवा का झोंका जो आपकी मोटरसाइकिल को धकेल सकता है, इसलिए प्रतिक्रिया के लिए तैयार रहें","ar":"هبّة رياح يمكن أن تدفع دراجتك النارية، فكن مستعداً للتفاعل"},{"en":"That your tires will suddenly grip the road much better","es":"Que tus llantas de pronto se agarrarán mucho mejor a la vía","ru":"Что ваши шины внезапно станут гораздо лучше держаться за дорогу","tr":"Lastiklerinizin aniden yola çok daha iyi tutunacağını","hi":"कि आपके टायर अचानक सड़क को बहुत बेहतर पकड़ लेंगे","ar":"أن إطاراتك ستلتصق فجأة بالطريق بشكل أفضل بكثير"},{"en":"Nothing, because large vehicles create no airflow effect","es":"Nada, porque los vehículos grandes no generan efecto de flujo de aire","ru":"Ничего, потому что большие транспортные средства не создают воздушного эффекта","tr":"Hiçbir şey, çünkü büyük araçlar hava akımı etkisi oluşturmaz","hi":"कुछ नहीं, क्योंकि बड़े वाहन कोई वायुप्रवाह प्रभाव पैदा नहीं करते","ar":"لا شيء، لأن المركبات الكبيرة لا تُحدث أي تأثير على تدفق الهواء"}],"e":{"en":"Large vehicles can create wind blasts that push a motorcycle around as they pass. The Motorcycle Operator Manual advises anticipating the gust, keeping a firm grip, and being ready to make steering corrections.","es":"Los vehículos grandes pueden crear ráfagas de viento que empujan a una motocicleta al pasar. El Manual del Operador de Motocicletas aconseja anticipar la ráfaga, mantener un agarre firme y estar listo para hacer correcciones de dirección.","ru":"Большие транспортные средства могут создавать порывы ветра, толкающие мотоцикл при проезде. Руководство для водителей мотоциклов советует предвидеть порыв, держать руль крепко и быть готовым делать корректировки рулём.","tr":"Büyük araçlar geçerken bir motosikleti oradan oraya itebilen rüzgar patlamaları oluşturabilir. Motosiklet Sürücü Kılavuzu, hamleyi öngörmeyi, sıkı bir tutuş korumayı ve yönlendirme düzeltmeleri yapmaya hazır olmayı tavsiye eder.","hi":"बड़े वाहन गुज़रते समय हवा के झोंके पैदा कर सकते हैं जो मोटरसाइकिल को इधर-उधर धकेलते हैं। Motorcycle Operator Manual झोंके का अनुमान लगाने, मज़बूत पकड़ बनाए रखने और स्टीयरिंग सुधार के लिए तैयार रहने की सलाह देता है।","ar":"يمكن للمركبات الكبيرة أن تُحدث هبّات رياح تدفع الدراجة النارية أثناء مرورها. ينصح دليل مشغل الدراجة النارية بتوقّع الهبّة، والحفاظ على قبضة ثابتة، والاستعداد لإجراء تصحيحات توجيه."}},{"cat":"hazards","a":2,"q":{"en":"You are riding in traffic when a small animal darts into your path. What is the safest response?","es":"Vas conduciendo en el tráfico cuando un animal pequeño se cruza de pronto en tu trayectoria. ¿Cuál es la respuesta más segura?","ru":"Вы едете в потоке, когда небольшое животное выскакивает на ваш путь. Какова самая безопасная реакция?","tr":"Trafikte sürerken küçük bir hayvan yolunuza atlıyor. En güvenli tepki nedir?","hi":"आप ट्रैफ़िक में चल रहे हैं जब एक छोटा जानवर आपके रास्ते में आ जाता है। सबसे सुरक्षित प्रतिक्रिया क्या है?","ar":"أنت تقود في حركة المرور عندما يندفع حيوان صغير إلى مسارك. ما هي الاستجابة الأكثر أماناً؟"},"o":[{"en":"Swerve sharply into the next lane to avoid hitting it","es":"Desviarte bruscamente al siguiente carril para evitar atropellarlo","ru":"Резко вильнуть в соседнюю полосу, чтобы не сбить его","tr":"Çarpmamak için keskin bir şekilde bir sonraki şerite savrulun","hi":"इसे टकराने से बचने के लिए तीखे ढंग से अगली लेन में मुड़ें","ar":"انعطف بحدة إلى المسار التالي لتجنّب الاصطدام به"},{"en":"Slam on the front brake only and skid to a stop","es":"Apretar solo el freno delantero y derrapar hasta detenerte","ru":"Нажать только на передний тормоз и остановиться юзом","tr":"Yalnızca ön frene basın ve kayarak durun","hi":"केवल फ्रंट ब्रेक ज़ोर से लगाएँ और स्किड करके रुकें","ar":"اضغط على المكبح الأمامي فقط وانزلق إلى التوقف"},{"en":"Stay in your lane, since swerving into traffic is more dangerous than the collision","es":"Permanecer en tu carril, ya que desviarte hacia el tráfico es más peligroso que la colisión","ru":"Оставаться на своей полосе, поскольку вилять в поток опаснее, чем столкновение","tr":"Şeritinizde kalın, çünkü trafiğe savrulmak çarpışmadan daha tehlikelidir","hi":"अपनी लेन में रहें, क्योंकि ट्रैफ़िक में मुड़ना टक्कर से अधिक खतरनाक है","ar":"ابقَ في مسارك، لأن الانعطاف إلى حركة المرور أخطر من الاصطدام"},{"en":"Speed up and steer toward the shoulder gravel","es":"Acelerar y dirigirte hacia la grava del acotamiento","ru":"Ускориться и направиться к гравию на обочине","tr":"Hızlanın ve banket çakılına doğru yönelin","hi":"गति बढ़ाएँ और कंधे की बजरी की ओर स्टीयर करें","ar":"تسارع ووجّه نحو حصى الكتف"}],"e":{"en":"In traffic, remain in your lane; hitting a small animal is less dangerous than swerving into another vehicle or off the road. The Motorcycle Operator Manual says do not risk a worse crash to spare a small animal.","es":"En el tráfico, permanece en tu carril; atropellar a un animal pequeño es menos peligroso que desviarte hacia otro vehículo o fuera de la vía. El Manual del Operador de Motocicletas dice que no arriesgues un choque peor por salvar a un animal pequeño.","ru":"В потоке оставайтесь на своей полосе; наезд на небольшое животное менее опасен, чем виляние в другое транспортное средство или съезд с дороги. Руководство для водителей мотоциклов гласит: не рискуйте более серьёзной аварией ради спасения небольшого животного.","tr":"Trafikte şeritinizde kalın; küçük bir hayvana çarpmak, başka bir araca veya yoldan dışarı savrulmaktan daha az tehlikelidir. Motosiklet Sürücü Kılavuzu, küçük bir hayvanı kurtarmak için daha kötü bir kaza riskine girmemeyi söyler.","hi":"ट्रैफ़िक में अपनी लेन में रहें; एक छोटे जानवर को टकराना किसी अन्य वाहन में मुड़ने या सड़क से बाहर जाने से कम खतरनाक है। Motorcycle Operator Manual कहता है कि एक छोटे जानवर को बचाने के लिए बदतर दुर्घटना का जोखिम न उठाएँ।","ar":"في حركة المرور، ابقَ في مسارك؛ الاصطدام بحيوان صغير أقل خطورة من الانعطاف إلى مركبة أخرى أو خارج الطريق. يقول دليل مشغل الدراجة النارية لا تخاطر بتصادم أسوأ لإنقاذ حيوان صغير."}},{"cat":"hazards","a":0,"q":{"en":"What does the manual advise if a dog chases your motorcycle?","es":"¿Qué aconseja el manual si un perro persigue tu motocicleta?","ru":"Что советует Руководство, если собака преследует ваш мотоцикл?","tr":"Bir köpek motosikletinizi kovalarsa kılavuz ne tavsiye eder?","hi":"अगर कोई कुत्ता आपकी मोटरसाइकिल का पीछा करे तो मैनुअल क्या सलाह देता है?","ar":"بماذا ينصح الدليل إذا طارد كلب دراجتك النارية؟"},"o":[{"en":"Downshift and approach slowly, then accelerate away once you near it","es":"Reducir la marcha y acercarte despacio, luego acelerar para alejarte una vez que estés cerca de él","ru":"Понизить передачу и приблизиться медленно, затем ускориться прочь, когда приблизитесь к ней","tr":"Vites küçültün ve yavaşça yaklaşın, ardından ona yaklaşınca hızlanarak uzaklaşın","hi":"डाउनशिफ्ट करें और धीरे-धीरे पास जाएँ, फिर उसके पास पहुँचते ही एक्सीलरेट करके निकल जाएँ","ar":"خفّض الترس واقترب ببطء، ثم تسارع مبتعداً بمجرد اقترابك منه"},{"en":"Kick at the dog to keep it away from your wheels","es":"Patear al perro para mantenerlo lejos de tus ruedas","ru":"Отбиваться от собаки ногой, чтобы держать её подальше от колёс","tr":"Köpeği tekerleklerinizden uzak tutmak için tekme atın","hi":"कुत्ते को अपने पहियों से दूर रखने के लिए उसे लात मारें","ar":"اركل الكلب لإبعاده عن عجلاتك"},{"en":"Stop and wait for the dog to lose interest","es":"Detenerte y esperar a que el perro pierda el interés","ru":"Остановиться и подождать, пока собака потеряет интерес","tr":"Durun ve köpeğin ilgisini kaybetmesini bekleyin","hi":"रुकें और कुत्ते की रुचि खत्म होने का इंतज़ार करें","ar":"توقف وانتظر حتى يفقد الكلب اهتمامه"},{"en":"Swerve repeatedly to confuse the animal","es":"Desviarte repetidamente para confundir al animal","ru":"Многократно вилять, чтобы запутать животное","tr":"Hayvanı şaşırtmak için defalarca savrulun","hi":"जानवर को भ्रमित करने के लिए बार-बार मुड़ें","ar":"انعطف مراراً لإرباك الحيوان"}],"e":{"en":"If a dog chases you, slow and downshift as you approach, then accelerate away to leave it behind. The Motorcycle Operator Manual warns never to kick at an animal, since that can cause you to lose control.","es":"Si un perro te persigue, reduce la velocidad y baja la marcha al acercarte, luego acelera para alejarte y dejarlo atrás. El Manual del Operador de Motocicletas advierte que nunca patees a un animal, ya que eso puede hacerte perder el control.","ru":"Если собака преследует вас, замедлитесь и понизьте передачу при приближении, затем ускорьтесь прочь, чтобы оставить её позади. Руководство для водителей мотоциклов предупреждает: никогда не отбивайтесь от животного ногой, поскольку это может привести к потере управления.","tr":"Bir köpek sizi kovalarsa, yaklaşırken yavaşlayın ve vites küçültün, ardından hızlanarak onu geride bırakın. Motosiklet Sürücü Kılavuzu, bunun kontrolü kaybetmenize neden olabileceği için asla bir hayvana tekme atmamak konusunda uyarır.","hi":"अगर कोई कुत्ता आपका पीछा करे, तो पास पहुँचते समय धीमा करें और डाउनशिफ्ट करें, फिर एक्सीलरेट करके उसे पीछे छोड़ दें। Motorcycle Operator Manual चेतावनी देता है कि किसी जानवर को कभी लात न मारें, क्योंकि इससे आपका नियंत्रण छूट सकता है।","ar":"إذا طاردك كلب، أبطئ وخفّض الترس عند اقترابك، ثم تسارع مبتعداً لتتركه خلفك. يحذر دليل مشغل الدراجة النارية من ركل حيوان أبداً، لأن ذلك قد يفقدك السيطرة."}},{"cat":"hazards","a":2,"q":{"en":"How should you treat a large animal such as a deer standing in or near the roadway?","es":"¿Cómo debes tratar a un animal grande, como un venado, que está en la vía o cerca de ella?","ru":"Как следует обращаться с крупным животным, например с оленем, стоящим на проезжей части или рядом с ней?","tr":"Yolda veya yol kenarında duran geyik gibi büyük bir hayvana nasıl davranmalısınız?","hi":"सड़क पर या उसके पास खड़े हिरण जैसे बड़े जानवर को आपको कैसे संभालना चाहिए?","ar":"كيف ينبغي أن تتعامل مع حيوان كبير مثل غزال يقف في الطريق أو بالقرب منه؟"},"o":[{"en":"Maintain speed and rely on the animal to move away","es":"Mantener la velocidad y confiar en que el animal se aparte","ru":"Сохранять скорость и полагаться на то, что животное уйдёт","tr":"Hızı koruyun ve hayvanın uzaklaşmasına güvenin","hi":"गति बनाए रखें और जानवर के हट जाने पर भरोसा करें","ar":"حافظ على السرعة واعتمد على ابتعاد الحيوان"},{"en":"Sound your horn once and accelerate past it","es":"Tocar la bocina una vez y acelerar para pasarlo","ru":"Один раз подать сигнал и проехать мимо на ускорении","tr":"Bir kez korna çalın ve hızlanarak geçin","hi":"एक बार हॉर्न बजाएँ और उसके पास से एक्सीलरेट करके निकल जाएँ","ar":"انفخ بوقك مرة واحدة وتسارع لتتجاوزه"},{"en":"Slow down, prepare to stop, and expect it to move unpredictably","es":"Reducir la velocidad, prepararte para detenerte y esperar que se mueva de forma impredecible","ru":"Снизить скорость, приготовиться к остановке и ожидать, что оно будет двигаться непредсказуемо","tr":"Yavaşlayın, durmaya hazırlanın ve öngörülemez şekilde hareket etmesini bekleyin","hi":"धीमा करें, रुकने के लिए तैयार रहें और उम्मीद करें कि यह अप्रत्याशित रूप से हिलेगा","ar":"أبطئ، واستعد للتوقف، وتوقّع أن يتحرك بشكل غير متوقع"},{"en":"Steer straight at it to scare it off the road","es":"Dirigirte recto hacia él para asustarlo y sacarlo de la vía","ru":"Направить мотоцикл прямо на него, чтобы согнать его с дороги","tr":"Onu yoldan korkutup kaçırmak için doğrudan üzerine yönelin","hi":"इसे सड़क से डराकर भगाने के लिए सीधे इसकी ओर स्टीयर करें","ar":"وجّه مباشرةً نحوه لإخافته خارج الطريق"}],"e":{"en":"Large animals like deer are unpredictable, so brake and prepare to stop. The Motorcycle Operator Manual advises slowing and being ready to stop rather than gambling on which way the animal will move.","es":"Los animales grandes como los venados son impredecibles, así que frena y prepárate para detenerte. El Manual del Operador de Motocicletas aconseja reducir la velocidad y estar listo para detenerte, en lugar de apostar a hacia qué lado se moverá el animal.","ru":"Крупные животные, такие как олени, непредсказуемы, поэтому тормозите и готовьтесь к остановке. Руководство для водителей мотоциклов советует снижать скорость и быть готовым остановиться, а не угадывать, в какую сторону двинется животное.","tr":"Geyik gibi büyük hayvanlar öngörülemez olduğundan fren yapın ve durmaya hazırlanın. Motosiklet Sürücü Kılavuzu, hayvanın ne tarafa hareket edeceği üzerine kumar oynamak yerine yavaşlamayı ve durmaya hazır olmayı tavsiye eder.","hi":"हिरण जैसे बड़े जानवर अप्रत्याशित होते हैं, इसलिए ब्रेक लगाएँ और रुकने के लिए तैयार रहें। Motorcycle Operator Manual जानवर किस दिशा में जाएगा इस पर दाँव लगाने के बजाय धीमा करने और रुकने के लिए तैयार रहने की सलाह देता है।","ar":"الحيوانات الكبيرة مثل الغزلان غير متوقعة، لذا اكبح واستعد للتوقف. ينصح دليل مشغل الدراجة النارية بالإبطاء والاستعداد للتوقف بدلاً من المراهنة على الاتجاه الذي سيتحرك إليه الحيوان."}},{"cat":"hazards","a":3,"q":{"en":"Why should you avoid riding directly on painted lane lines, tar snakes, or steel plates, particularly in the rain?","es":"¿Por qué debes evitar conducir directamente sobre líneas pintadas del carril, sellos de alquitrán (tar snakes) o placas de acero, en especial bajo la lluvia?","ru":"Почему следует избегать езды прямо по нанесённой разметке, битумным заплаткам или стальным плитам, особенно в дождь?","tr":"Özellikle yağmurda, doğrudan boyalı şerit çizgilerinin, zift dolgularının veya çelik plakaların üzerinde sürmekten neden kaçınmalısınız?","hi":"आपको पेंट की गई लेन रेखाओं, टार स्नेक या स्टील प्लेटों पर सीधे चलने से क्यों बचना चाहिए, खासकर बारिश में?","ar":"لماذا ينبغي أن تتجنّب القيادة مباشرةً على خطوط المسار المطلية أو خطوط القار أو الألواح الفولاذية، خاصة في المطر؟"},"o":[{"en":"They always carry a small electric charge that can shock the tires","es":"Siempre llevan una pequeña carga eléctrica que puede dar toques a las llantas","ru":"Они всегда несут небольшой электрический заряд, который может ударить шины током","tr":"Her zaman lastikleri çarpabilecek küçük bir elektrik yükü taşırlar","hi":"वे हमेशा एक छोटा बिजली का चार्ज रखते हैं जो टायरों को झटका दे सकता है","ar":"تحمل دائماً شحنة كهربائية صغيرة يمكن أن تصعق الإطارات"},{"en":"They reflect headlights and blind oncoming drivers","es":"Reflejan los faros y deslumbran a los conductores que vienen de frente","ru":"Они отражают свет фар и ослепляют встречных водителей","tr":"Farları yansıtır ve karşıdan gelen sürücülerin gözünü kör eder","hi":"वे हेडलाइट परावर्तित करते हैं और सामने से आ रहे चालकों को अंधा कर देते हैं","ar":"تعكس المصابيح الأمامية وتُعمي السائقين القادمين"},{"en":"They are softer than the road and can trap a motorcycle tire","es":"Son más blandos que la vía y pueden atrapar una llanta de motocicleta","ru":"Они мягче дороги и могут защемить шину мотоцикла","tr":"Yoldan daha yumuşaktırlar ve bir motosiklet lastiğini hapsedebilirler","hi":"वे सड़क से नरम होते हैं और मोटरसाइकिल के टायर को फँसा सकते हैं","ar":"إنها أنعم من الطريق ويمكن أن تحتجز إطار دراجة نارية"},{"en":"They are smooth surfaces that offer much less traction than pavement","es":"Son superficies lisas que ofrecen mucha menos tracción que el pavimento","ru":"Это гладкие поверхности, обеспечивающие гораздо меньшее сцепление, чем покрытие","tr":"Zeminden çok daha az tutuş sunan pürüzsüz yüzeylerdir","hi":"वे चिकनी सतहें हैं जो सड़क की तुलना में बहुत कम कर्षण देती हैं","ar":"إنها أسطح ناعمة توفر قوة احتكاك أقل بكثير من الرصيف"}],"e":{"en":"Smooth surfaces like lane markings, tar patches, and steel plates provide far less grip than ordinary pavement and become especially slick when wet. The Motorcycle Operator Manual urges riders to avoid them or cross with caution.","es":"Las superficies lisas como las marcas del carril, los parches de alquitrán y las placas de acero ofrecen mucho menos agarre que el pavimento común y se vuelven especialmente resbalosas cuando están mojadas. El Manual del Operador de Motocicletas insta a los conductores a evitarlas o cruzarlas con precaución.","ru":"Гладкие поверхности, такие как разметка полос, битумные заплатки и стальные плиты, обеспечивают гораздо меньшее сцепление, чем обычное покрытие, и становятся особенно скользкими при намокании. Руководство для водителей мотоциклов настоятельно советует избегать их или пересекать с осторожностью.","tr":"Şerit işaretleri, zift yamaları ve çelik plakalar gibi pürüzsüz yüzeyler, sıradan zeminden çok daha az tutuş sağlar ve ıslakken özellikle kayganlaşır. Motosiklet Sürücü Kılavuzu, sürücüleri bunlardan kaçınmaya veya dikkatle geçmeye teşvik eder.","hi":"लेन चिह्न, टार पैच और स्टील प्लेट जैसी चिकनी सतहें साधारण सड़क की तुलना में बहुत कम पकड़ देती हैं और गीली होने पर विशेष रूप से फिसलन भरी हो जाती हैं। Motorcycle Operator Manual सवारों से इनसे बचने या सावधानी से पार करने का आग्रह करता है।","ar":"توفر الأسطح الناعمة مثل علامات المسار ورقع القار والألواح الفولاذية قوة قبضة أقل بكثير من الرصيف العادي وتصبح زلقة بشكل خاص عند البلل. يحث دليل مشغل الدراجة النارية السائقين على تجنّبها أو عبورها بحذر."}},{"cat":"passenger","a":0,"q":{"en":"Before carrying a passenger, your motorcycle must be properly equipped. Which of the following is required?","es":"Antes de llevar a un pasajero, tu motocicleta debe estar debidamente equipada. ¿Cuál de los siguientes es requerido?","ru":"Перед перевозкой пассажира мотоцикл должен быть надлежащим образом оборудован. Что из перечисленного является обязательным?","tr":"Bir yolcu taşımadan önce, motosikletiniz uygun şekilde donatılmış olmalıdır. Aşağıdakilerden hangisi gereklidir?","hi":"यात्री ले जाने से पहले, आपकी मोटरसाइकिल ठीक से सुसज्जित होनी चाहिए। निम्नलिखित में से कौन सी आवश्यक है?","ar":"قبل حمل راكب، يجب أن تكون دراجتك النارية مجهّزة بشكل صحيح. أي مما يلي مطلوب؟"},"o":[{"en":"A proper seat large enough for both of you plus footrests for the passenger","es":"Un asiento adecuado lo bastante grande para los dos, además de estribos para el pasajero","ru":"Подходящее сиденье, достаточно большое для вас обоих, плюс подножки для пассажира","tr":"İkinizi de alacak kadar büyük uygun bir sele ve yolcu için ayaklıklar","hi":"आप दोनों के लिए पर्याप्त बड़ी उचित सीट और यात्री के लिए फुटरेस्ट","ar":"مقعد مناسب كبير بما يكفي لكليكما إضافةً إلى مساند قدمين للراكب"},{"en":"A windshield to shield the passenger from wind","es":"Un parabrisas para proteger al pasajero del viento","ru":"Ветровое стекло для защиты пассажира от ветра","tr":"Yolcuyu rüzgardan korumak için bir ön cam","hi":"यात्री को हवा से बचाने के लिए विंडशील्ड","ar":"حاجب رياح لحماية الراكب من الرياح"},{"en":"A backrest bolted to the rear fender","es":"Un respaldo atornillado al guardabarros trasero","ru":"Спинка, привинченная к заднему крылу","tr":"Arka çamurluğa cıvatalanmış bir sırt desteği","hi":"पीछे के फेंडर पर बोल्ट किया गया बैकरेस्ट","ar":"مسند ظهر مثبّت بالرفرف الخلفي"},{"en":"An extra mirror mounted for the passenger","es":"Un espejo adicional montado para el pasajero","ru":"Дополнительное зеркало, установленное для пассажира","tr":"Yolcu için monte edilmiş ekstra bir ayna","hi":"यात्री के लिए लगाया गया एक अतिरिक्त मिरर","ar":"مرآة إضافية مركّبة للراكب"}],"e":{"en":"The motorcycle should have a proper seat large enough to hold both you and the passenger without crowding, along with passenger footrests. Source: Motorcycle Operator Manual.","es":"La motocicleta debe tener un asiento adecuado lo bastante grande para sostenerte a ti y al pasajero sin apretujarse, junto con estribos para el pasajero. Fuente: Manual del Operador de Motocicletas.","ru":"Мотоцикл должен иметь подходящее сиденье, достаточно большое, чтобы вместить вас и пассажира без тесноты, а также подножки для пассажира. Источник: Руководство для водителей мотоциклов.","tr":"Motosiklet, sizi ve yolcuyu sıkışmadan alacak kadar büyük uygun bir seleye ve yolcu ayaklıklarına sahip olmalıdır. Kaynak: Motosiklet Sürücü Kılavuzu.","hi":"मोटरसाइकिल में आप और यात्री दोनों को बिना भीड़ के समाने के लिए पर्याप्त बड़ी उचित सीट होनी चाहिए, साथ ही यात्री के फुटरेस्ट भी। स्रोत: Motorcycle Operator Manual।","ar":"ينبغي أن يكون للدراجة النارية مقعد مناسب كبير بما يكفي لاستيعابك أنت والراكب دون ازدحام، إضافةً إلى مساند قدمين للراكب. المصدر: دليل مشغل الدراجة النارية."}},{"cat":"passenger","a":1,"q":{"en":"Where should a passenger hold on while you are riding?","es":"¿De dónde debe sujetarse un pasajero mientras conduces?","ru":"За что должен держаться пассажир, пока вы едете?","tr":"Siz sürerken bir yolcu nereye tutunmalıdır?","hi":"सवारी करते समय यात्री को कहाँ पकड़ना चाहिए?","ar":"أين ينبغي أن يتمسك الراكب أثناء قيادتك؟"},"o":[{"en":"Onto the rear of the seat with both hands","es":"De la parte trasera del asiento con ambas manos","ru":"За заднюю часть сиденья обеими руками","tr":"İki eliyle selenin arkasına","hi":"सीट के पीछे दोनों हाथों से","ar":"بمؤخرة المقعد بكلتا يديه"},{"en":"To your waist, hips, or belt, or to the passenger handholds","es":"De tu cintura, caderas o cinturón, o de los agarres para pasajero","ru":"За вашу талию, бёдра или ремень, либо за поручни для пассажира","tr":"Belinize, kalçanıza veya kemerinize ya da yolcu tutamaklarına","hi":"आपकी कमर, कूल्हों या बेल्ट को, या यात्री हैंडहोल्ड को","ar":"بخصرك أو وركيك أو حزامك، أو بمقابض اليد الخاصة بالراكب"},{"en":"Onto your shoulders to steer with you","es":"De tus hombros para dirigir contigo","ru":"За ваши плечи, чтобы рулить вместе с вами","tr":"Sizinle birlikte yönlendirmek için omuzlarınıza","hi":"आपके साथ स्टीयर करने के लिए आपके कंधों को","ar":"بكتفيك ليوجّه معك"},{"en":"To the sissy bar behind them","es":"De la barra trasera (sissy bar) que está detrás de él","ru":"За спинку-дугу позади себя","tr":"Arkalarındaki sissy bara","hi":"उनके पीछे की सिसी बार को","ar":"بقضيب المسند الخلفي خلفه"}],"e":{"en":"A passenger should hold firmly to your waist, hips, or belt, or use the motorcycle's passenger handholds. Source: Motorcycle Operator Manual.","es":"El pasajero debe sujetarse firmemente de tu cintura, caderas o cinturón, o usar los agarres para pasajero de la motocicleta. Fuente: Manual del Operador de Motocicletas.","ru":"Пассажир должен крепко держаться за вашу талию, бёдра или ремень, либо использовать пассажирские поручни мотоцикла. Источник: Руководство для водителей мотоциклов.","tr":"Bir yolcu, belinize, kalçanıza veya kemerinize sıkıca tutunmalı ya da motosikletin yolcu tutamaklarını kullanmalıdır. Kaynak: Motosiklet Sürücü Kılavuzu.","hi":"यात्री को आपकी कमर, कूल्हों या बेल्ट को मज़बूती से पकड़ना चाहिए, या मोटरसाइकिल के यात्री हैंडहोल्ड का उपयोग करना चाहिए। स्रोत: Motorcycle Operator Manual।","ar":"ينبغي أن يتمسك الراكب بإحكام بخصرك أو وركيك أو حزامك، أو يستخدم مقابض اليد الخاصة بالراكب في الدراجة النارية. المصدر: دليل مشغل الدراجة النارية."}},{"cat":"passenger","a":2,"q":{"en":"What should a passenger do with their feet when the motorcycle comes to a stop at a red light?","es":"¿Qué debe hacer un pasajero con los pies cuando la motocicleta se detiene en una luz roja?","ru":"Что должен делать пассажир со своими ногами, когда мотоцикл останавливается на красный сигнал?","tr":"Motosiklet kırmızı ışıkta durduğunda bir yolcu ayaklarıyla ne yapmalıdır?","hi":"जब मोटरसाइकिल लाल बत्ती पर रुके तो यात्री को अपने पैरों के साथ क्या करना चाहिए?","ar":"ماذا ينبغي أن يفعل الراكب بقدميه عندما تتوقف الدراجة النارية عند إشارة حمراء؟"},"o":[{"en":"Put both feet down on the ground for balance","es":"Poner ambos pies en el suelo para mantener el equilibrio","ru":"Поставить обе ноги на землю для равновесия","tr":"Denge için iki ayağını da yere koymalı","hi":"संतुलन के लिए दोनों पैर ज़मीन पर रखें","ar":"يضع كلتا قدميه على الأرض للتوازن"},{"en":"Lift their feet up onto the seat","es":"Levantar los pies sobre el asiento","ru":"Поднять ноги на сиденье","tr":"Ayaklarını selenin üzerine kaldırmalı","hi":"अपने पैर सीट पर ऊपर उठाएँ","ar":"يرفع قدميه إلى المقعد"},{"en":"Keep both feet firmly on the footrests","es":"Mantener ambos pies firmes sobre los estribos","ru":"Держать обе ноги крепко на подножках","tr":"Her iki ayağını da ayaklıklarda sıkıca tutmalı","hi":"दोनों पैर फुटरेस्ट पर मज़बूती से रखें","ar":"يبقي كلتا قدميه بثبات على مساند القدمين"},{"en":"Place one foot down to steady the bike","es":"Poner un pie en el suelo para estabilizar la moto","ru":"Поставить одну ногу на землю, чтобы стабилизировать мотоцикл","tr":"Motosikleti dengelemek için bir ayağını yere koymalı","hi":"बाइक को स्थिर करने के लिए एक पैर नीचे रखें","ar":"يضع قدماً واحدة على الأرض لتثبيت الدراجة"}],"e":{"en":"A passenger should keep both feet firmly on the footrests even when the motorcycle is stopped; firm footing keeps them from falling off and pulling you off. Source: Motorcycle Operator Manual.","es":"Un pasajero debe mantener ambos pies firmes sobre los estribos incluso cuando la motocicleta está detenida; un apoyo firme evita que se caiga y te tire a ti también. Fuente: Manual del Operador de Motocicletas.","ru":"Пассажир должен держать обе ноги крепко на подножках, даже когда мотоцикл стоит; крепкая опора не даёт ему упасть и стянуть вас за собой. Источник: Руководство для водителей мотоциклов.","tr":"Bir yolcu, motosiklet dururken bile her iki ayağını da ayaklıklarda sıkıca tutmalıdır; sağlam basış, düşüp sizi de düşürmesini önler. Kaynak: Motosiklet Sürücü Kılavuzu.","hi":"यात्री को मोटरसाइकिल रुकी होने पर भी दोनों पैर फुटरेस्ट पर मज़बूती से रखने चाहिए; मज़बूत पकड़ उन्हें गिरने और आपको खींचकर गिराने से रोकती है। स्रोत: Motorcycle Operator Manual।","ar":"ينبغي أن يبقي الراكب كلتا قدميه بثبات على مساند القدمين حتى عند توقف الدراجة النارية؛ فالموطئ الثابت يمنعه من السقوط وجذبك معه. المصدر: دليل مشغل الدراجة النارية."}},{"cat":"passenger","a":1,"q":{"en":"Where should the passenger sit on the motorcycle?","es":"¿Dónde debe sentarse el pasajero en la motocicleta?","ru":"Где должен сидеть пассажир на мотоцикле?","tr":"Yolcu motosiklette nerede oturmalıdır?","hi":"यात्री को मोटरसाइकिल पर कहाँ बैठना चाहिए?","ar":"أين ينبغي أن يجلس الراكب على الدراجة النارية؟"},"o":[{"en":"As far back as possible to reduce crowding","es":"Lo más atrás posible para reducir el apretujamiento","ru":"Как можно дальше назад, чтобы уменьшить тесноту","tr":"Sıkışmayı azaltmak için olabildiğince geride","hi":"भीड़ कम करने के लिए जितना संभव हो उतना पीछे","ar":"في أقصى الخلف قدر الإمكان لتقليل الازدحام"},{"en":"As far forward as possible without crowding you, directly behind you","es":"Lo más adelante posible sin apretujarte, directamente detrás de ti","ru":"Как можно дальше вперёд, не создавая для вас тесноты, прямо позади вас","tr":"Sizi sıkıştırmadan olabildiğince önde, tam arkanızda","hi":"आपको भीड़ दिए बिना जितना संभव हो उतना आगे, सीधे आपके पीछे","ar":"في أقصى الأمام قدر الإمكان دون ازدحامك، مباشرةً خلفك"},{"en":"In front of you so you can watch over them","es":"Frente a ti para que puedas vigilarlo","ru":"Перед вами, чтобы вы могли присматривать за ним","tr":"Onları gözetebilmeniz için önünüzde","hi":"आपके सामने ताकि आप उन पर नज़र रख सकें","ar":"أمامك حتى تتمكن من مراقبته"},{"en":"Off to one side to balance the load","es":"A un lado para equilibrar la carga","ru":"Сбоку, чтобы уравновесить нагрузку","tr":"Yükü dengelemek için bir tarafa","hi":"भार संतुलित करने के लिए एक तरफ़","ar":"إلى أحد الجانبين لموازنة الحمل"}],"e":{"en":"A passenger should sit as far forward as possible without crowding you and stay directly behind you. Source: Motorcycle Operator Manual.","es":"Un pasajero debe sentarse lo más adelante posible sin apretujarte y permanecer directamente detrás de ti. Fuente: Manual del Operador de Motocicletas.","ru":"Пассажир должен сидеть как можно дальше вперёд, не создавая для вас тесноты, и оставаться прямо позади вас. Источник: Руководство для водителей мотоциклов.","tr":"Bir yolcu, sizi sıkıştırmadan olabildiğince önde oturmalı ve tam arkanızda kalmalıdır. Kaynak: Motosiklet Sürücü Kılavuzu.","hi":"यात्री को आपको भीड़ दिए बिना जितना संभव हो उतना आगे बैठना चाहिए और सीधे आपके पीछे रहना चाहिए। स्रोत: Motorcycle Operator Manual।","ar":"ينبغي أن يجلس الراكب في أقصى الأمام قدر الإمكان دون ازدحامك ويبقى مباشرةً خلفك. المصدر: دليل مشغل الدراجة النارية."}},{"cat":"passenger","a":2,"q":{"en":"How should a passenger handle their body when you ride through a turn or curve?","es":"¿Cómo debe manejar su cuerpo un pasajero cuando conduces por un giro o una curva?","ru":"Как должен вести себя пассажир, когда вы проезжаете поворот или вираж?","tr":"Bir dönüş veya virajdan geçerken yolcu vücuduyla nasıl baş etmelidir?","hi":"जब आप किसी मोड़ या कर्व से गुज़रें तो यात्री को अपने शरीर को कैसे संभालना चाहिए?","ar":"كيف ينبغي أن يتعامل الراكب مع جسمه عندما تقود عبر انعطاف أو منعطف؟"},"o":[{"en":"Sit upright and resist leaning to stay stable","es":"Sentarse erguido y resistir inclinarse para mantenerse estable","ru":"Сидеть прямо и сопротивляться наклону, чтобы сохранять устойчивость","tr":"Sabit kalmak için dik oturup yatmaya direnmeli","hi":"स्थिर रहने के लिए सीधे बैठें और झुकने से बचें","ar":"يجلس منتصباً ويقاوم الميل ليبقى ثابتاً"},{"en":"Lean away from the turn to counterbalance the bike","es":"Inclinarse en sentido contrario a la curva para contrabalancear la moto","ru":"Наклоняться в сторону от поворота, чтобы уравновесить мотоцикл","tr":"Motosikleti dengelemek için dönüşten uzağa yatmalı","hi":"बाइक को संतुलित करने के लिए मोड़ से दूर झुकें","ar":"يميل بعيداً عن الانعطاف لموازنة الدراجة"},{"en":"Lean with you, looking over your shoulder in the direction of the turn","es":"Inclinarse contigo, mirando por encima de tu hombro en la dirección del giro","ru":"Наклоняться вместе с вами, глядя через ваше плечо в направлении поворота","tr":"Sizinle birlikte yatmalı, dönüş yönünde omzunuzun üzerinden bakmalı","hi":"आपके साथ झुकें, मोड़ की दिशा में आपके कंधे के ऊपर से देखते हुए","ar":"يميل معك، ناظراً فوق كتفك في اتجاه الانعطاف"},{"en":"Shift their weight to the outside of the curve","es":"Desplazar su peso hacia el exterior de la curva","ru":"Переносить вес на внешнюю сторону виража","tr":"Ağırlığını virajın dışına kaydırmalı","hi":"अपना वज़न कर्व के बाहर की ओर शिफ्ट करें","ar":"ينقل وزنه إلى خارج المنعطف"}],"e":{"en":"A passenger should lean as you lean and look over your shoulder in the direction of turns and curves. Source: Motorcycle Operator Manual.","es":"Un pasajero debe inclinarse cuando tú te inclines y mirar por encima de tu hombro en la dirección de los giros y curvas. Fuente: Manual del Operador de Motocicletas.","ru":"Пассажир должен наклоняться, когда наклоняетесь вы, и смотреть через ваше плечо в направлении поворотов и виражей. Источник: Руководство для водителей мотоциклов.","tr":"Bir yolcu, siz yattıkça yatmalı ve dönüşler ile virajların yönünde omzunuzun üzerinden bakmalıdır. Kaynak: Motosiklet Sürücü Kılavuzu.","hi":"यात्री को आपके झुकने पर झुकना चाहिए और मोड़ों व कर्व की दिशा में आपके कंधे के ऊपर से देखना चाहिए। स्रोत: Motorcycle Operator Manual।","ar":"ينبغي أن يميل الراكب كما تميل وينظر فوق كتفك في اتجاه الانعطافات والمنعطفات. المصدر: دليل مشغل الدراجة النارية."}},{"cat":"passenger","a":1,"q":{"en":"When should the passenger get on the motorcycle?","es":"¿Cuándo debe subirse el pasajero a la motocicleta?","ru":"Когда пассажир должен садиться на мотоцикл?","tr":"Yolcu motosiklete ne zaman binmelidir?","hi":"यात्री को मोटरसाइकिल पर कब चढ़ना चाहिए?","ar":"متى ينبغي أن يصعد الراكب على الدراجة النارية؟"},"o":[{"en":"Before you start the engine, while the bike is on its stand","es":"Antes de que arranques el motor, mientras la moto está en su soporte","ru":"До того как вы заведёте двигатель, пока мотоцикл стоит на подставке","tr":"Siz motoru çalıştırmadan önce, motosiklet sehpasındayken","hi":"आपके इंजन शुरू करने से पहले, जब बाइक अपने स्टैंड पर हो","ar":"قبل تشغيل المحرك، بينما الدراجة على حاملها"},{"en":"After you have started the engine","es":"Después de que hayas arrancado el motor","ru":"После того как вы завели двигатель","tr":"Siz motoru çalıştırdıktan sonra","hi":"आपके इंजन शुरू करने के बाद","ar":"بعد أن تكون قد شغّلت المحرك"},{"en":"While the motorcycle is rolling slowly","es":"Mientras la motocicleta avanza despacio","ru":"Пока мотоцикл медленно катится","tr":"Motosiklet yavaşça hareket halindeyken","hi":"जब मोटरसाइकिल धीरे-धीरे चल रही हो","ar":"بينما الدراجة النارية تتدحرج ببطء"},{"en":"Only after you have already begun to ride","es":"Solo después de que ya hayas empezado a conducir","ru":"Только после того как вы уже начали движение","tr":"Yalnızca siz sürmeye başladıktan sonra","hi":"केवल आपके सवारी शुरू करने के बाद","ar":"فقط بعد أن تكون قد بدأت القيادة بالفعل"}],"e":{"en":"The passenger should get on the motorcycle only after the engine has been started. Source: Motorcycle Operator Manual.","es":"El pasajero debe subirse a la motocicleta solo después de que el motor haya sido arrancado. Fuente: Manual del Operador de Motocicletas.","ru":"Пассажир должен садиться на мотоцикл только после того, как двигатель запущен. Источник: Руководство для водителей мотоциклов.","tr":"Yolcu, motosiklete yalnızca motor çalıştırıldıktan sonra binmelidir. Kaynak: Motosiklet Sürücü Kılavuzu.","hi":"यात्री को इंजन शुरू हो जाने के बाद ही मोटरसाइकिल पर चढ़ना चाहिए। स्रोत: Motorcycle Operator Manual।","ar":"ينبغي أن يصعد الراكب على الدراجة النارية فقط بعد تشغيل المحرك. المصدر: دليل مشغل الدراجة النارية."}},{"cat":"passenger","a":0,"q":{"en":"While your passenger is mounting the motorcycle, what should you do?","es":"Mientras tu pasajero se sube a la motocicleta, ¿qué debes hacer?","ru":"Пока ваш пассажир садится на мотоцикл, что следует делать вам?","tr":"Yolcunuz motosiklete binerken ne yapmalısınız?","hi":"जब आपका यात्री मोटरसाइकिल पर चढ़ रहा हो, तब आपको क्या करना चाहिए?","ar":"أثناء صعود راكبك على الدراجة النارية، ماذا ينبغي أن تفعل؟"},"o":[{"en":"Keep both feet on the ground with the brakes applied","es":"Mantener ambos pies en el suelo con los frenos aplicados","ru":"Держать обе ноги на земле с зажатыми тормозами","tr":"Frenler basılı halde her iki ayağınızı yerde tutun","hi":"दोनों पैर ज़मीन पर रखें और ब्रेक लगाए रखें","ar":"أبقِ كلتا قدميك على الأرض مع تطبيق المكابح"},{"en":"Rev the throttle slightly to keep the engine from stalling","es":"Acelerar ligeramente para evitar que el motor se apague","ru":"Слегка газовать дросселем, чтобы двигатель не заглох","tr":"Motorun stop etmemesi için gazı hafifçe artırın","hi":"इंजन को बंद होने से बचाने के लिए थ्रॉटल को थोड़ा रेव करें","ar":"ارفع سرعة دواسة الوقود قليلاً لمنع المحرك من التوقف"},{"en":"Put the bike in first gear and hold the clutch","es":"Poner la moto en primera y sostener el embrague","ru":"Включить первую передачу и держать сцепление","tr":"Motosikleti birinci vitese takın ve debriyajı tutun","hi":"बाइक को पहले गियर में रखें और क्लच पकड़ें","ar":"ضع الدراجة في الترس الأول وامسك القابض"},{"en":"Lift the side stand and balance with one foot","es":"Levantar el soporte lateral y equilibrarte con un pie","ru":"Поднять боковую подставку и балансировать на одной ноге","tr":"Yan sehpayı kaldırın ve tek ayakla dengeleyin","hi":"साइड स्टैंड उठाएँ और एक पैर से संतुलन बनाएँ","ar":"ارفع الحامل الجانبي وحافظ على التوازن بقدم واحدة"}],"e":{"en":"As the passenger mounts, keep both of your feet on the ground and the brakes applied to hold the motorcycle steady. Source: Motorcycle Operator Manual.","es":"Mientras el pasajero se sube, mantén ambos pies en el suelo y los frenos aplicados para sostener la motocicleta firme. Fuente: Manual del Operador de Motocicletas.","ru":"Пока пассажир садится, держите обе свои ноги на земле и зажатые тормоза, чтобы удерживать мотоцикл устойчиво. Источник: Руководство для водителей мотоциклов.","tr":"Yolcu binerken, motosikleti sabit tutmak için her iki ayağınızı yerde ve frenleri basılı tutun. Kaynak: Motosiklet Sürücü Kılavuzu.","hi":"जब यात्री चढ़ता है, तो मोटरसाइकिल को स्थिर रखने के लिए अपने दोनों पैर ज़मीन पर रखें और ब्रेक लगाए रखें। स्रोत: Motorcycle Operator Manual।","ar":"أثناء صعود الراكب، أبقِ كلتا قدميك على الأرض والمكابح مطبّقة لتثبيت الدراجة النارية. المصدر: دليل مشغل الدراجة النارية."}},{"cat":"passenger","a":1,"q":{"en":"Why should you instruct your passenger on cycling basics before every trip?","es":"¿Por qué debes instruir a tu pasajero sobre lo básico del manejo en moto antes de cada viaje?","ru":"Почему следует инструктировать пассажира об основах езды на мотоцикле перед каждой поездкой?","tr":"Her yolculuktan önce yolcunuza motosiklet sürmenin temelleri konusunda neden talimat vermelisiniz?","hi":"आपको हर यात्रा से पहले अपने यात्री को साइकिलिंग की बुनियादी बातें क्यों समझानी चाहिए?","ar":"لماذا ينبغي أن تُرشد راكبك إلى أساسيات ركوب الدراجة قبل كل رحلة؟"},"o":[{"en":"Because the law requires a verbal safety briefing","es":"Porque la ley exige una charla verbal de seguridad","ru":"Потому что закон требует устного инструктажа по безопасности","tr":"Yasa sözlü bir güvenlik bilgilendirmesi gerektirdiği için","hi":"क्योंकि कानून मौखिक सुरक्षा ब्रीफिंग की आवश्यकता रखता है","ar":"لأن القانون يتطلب إحاطة أمان شفهية"},{"en":"Because you should not assume passengers know how to handle a motorcycle, even experienced riders","es":"Porque no debes suponer que los pasajeros saben cómo manejar una motocicleta, incluso los conductores experimentados","ru":"Потому что не следует предполагать, что пассажиры знают, как вести себя на мотоцикле, даже опытные мотоциклисты","tr":"Deneyimli sürücüler bile olsalar yolcuların bir motosikleti nasıl ele alacaklarını bildiklerini varsaymamanız gerektiği için","hi":"क्योंकि आपको यह नहीं मान लेना चाहिए कि यात्री मोटरसाइकिल संभालना जानते हैं, भले ही वे अनुभवी सवार हों","ar":"لأنه لا ينبغي أن تفترض أن الركاب يعرفون كيفية التعامل مع دراجة نارية، حتى السائقين ذوي الخبرة"},{"en":"Because the passenger must repeat the instructions back to you","es":"Porque el pasajero debe repetirte las instrucciones","ru":"Потому что пассажир должен повторить инструкции вам в ответ","tr":"Yolcunun talimatları size geri tekrar etmesi gerektiği için","hi":"क्योंकि यात्री को निर्देश आपको दोहराकर बताने पड़ते हैं","ar":"لأن على الراكب أن يكرر التعليمات لك"},{"en":"Because it warms up the engine while you talk","es":"Porque calienta el motor mientras hablas","ru":"Потому что это прогревает двигатель, пока вы говорите","tr":"Siz konuşurken motoru ısıttığı için","hi":"क्योंकि बात करते समय यह इंजन को गर्म कर देता है","ar":"لأن ذلك يُسخّن المحرك أثناء حديثك"}],"e":{"en":"Riders should not assume passengers are familiar with motorcycle handling and balance, so always instruct your passenger before starting, even if the passenger is a rider. Source: Motorcycle Operator Manual.","es":"Los conductores no deben suponer que los pasajeros están familiarizados con el manejo y el equilibrio de una motocicleta, así que siempre instruye a tu pasajero antes de arrancar, aunque el pasajero también sea conductor. Fuente: Manual del Operador de Motocicletas.","ru":"Водителям не следует предполагать, что пассажиры знакомы с управлением и балансировкой мотоцикла, поэтому всегда инструктируйте своего пассажира перед началом движения, даже если пассажир сам водитель. Источник: Руководство для водителей мотоциклов.","tr":"Sürücüler, yolcuların motosiklet kullanımı ve dengesine aşina olduklarını varsaymamalıdır, bu yüzden yolcu bir sürücü olsa bile başlamadan önce her zaman yolcunuza talimat verin. Kaynak: Motosiklet Sürücü Kılavuzu.","hi":"सवारों को यह नहीं मान लेना चाहिए कि यात्री मोटरसाइकिल को संभालने और संतुलन से परिचित हैं, इसलिए शुरू करने से पहले हमेशा अपने यात्री को निर्देश दें, भले ही यात्री स्वयं सवार हो। स्रोत: Motorcycle Operator Manual।","ar":"لا ينبغي للسائقين أن يفترضوا أن الركاب على دراية بالتعامل مع الدراجة النارية وتوازنها، لذا أرشد راكبك دائماً قبل البدء، حتى لو كان الراكب سائقاً. المصدر: دليل مشغل الدراجة النارية."}},{"cat":"passenger","a":0,"q":{"en":"Why should a passenger keep their legs positioned carefully during the ride?","es":"¿Por qué debe un pasajero mantener las piernas cuidadosamente colocadas durante el viaje?","ru":"Почему пассажир должен внимательно следить за положением своих ног во время поездки?","tr":"Bir yolcu, yolculuk boyunca bacaklarını neden dikkatlice konumlandırmalıdır?","hi":"यात्री को सवारी के दौरान अपने पैरों को सावधानी से क्यों रखना चाहिए?","ar":"لماذا ينبغي أن يبقي الراكب ساقيه في وضع دقيق أثناء الرحلة؟"},"o":[{"en":"To keep their legs away from the hot muffler and moving parts","es":"Para mantener las piernas lejos del mofle caliente y de las partes móviles","ru":"Чтобы держать ноги подальше от горячего глушителя и движущихся частей","tr":"Bacaklarını sıcak egzozdan ve hareketli parçalardan uzak tutmak için","hi":"अपने पैरों को गर्म मफलर और चलते पुर्ज़ों से दूर रखने के लिए","ar":"لإبعاد ساقيه عن كاتم الصوت الساخن والأجزاء المتحركة"},{"en":"To help push the motorcycle through turns","es":"Para ayudar a empujar la motocicleta en las curvas","ru":"Чтобы помогать толкать мотоцикл в поворотах","tr":"Motosikleti dönüşlerden geçirmeye yardımcı olmak için","hi":"मोटरसाइकिल को मोड़ों से धकेलने में मदद के लिए","ar":"للمساعدة في دفع الدراجة النارية عبر الانعطافات"},{"en":"To act as an extra kickstand at stops","es":"Para servir de pata de apoyo adicional en las paradas","ru":"Чтобы служить дополнительной подставкой на остановках","tr":"Duruşlarda ekstra bir yan sehpa görevi görmek için","hi":"रुकने पर एक अतिरिक्त किकस्टैंड के रूप में काम करने के लिए","ar":"ليعمل كحامل إضافي عند التوقف"},{"en":"To grip the rear tire for traction","es":"Para agarrar la llanta trasera y dar tracción","ru":"Чтобы держаться за заднюю шину для сцепления","tr":"Tutuş için arka lastiği kavramak için","hi":"कर्षण के लिए पीछे के टायर को पकड़ने के लिए","ar":"ليُمسك بالإطار الخلفي لزيادة قوة الاحتكاك"}],"e":{"en":"A passenger should keep their legs away from the muffler(s), chains, and other moving parts to avoid burns and injury. Source: Motorcycle Operator Manual.","es":"Un pasajero debe mantener las piernas lejos del o de los mofles, las cadenas y otras partes móviles para evitar quemaduras y lesiones. Fuente: Manual del Operador de Motocicletas.","ru":"Пассажир должен держать ноги подальше от глушителя(ей), цепей и других движущихся частей, чтобы избежать ожогов и травм. Источник: Руководство для водителей мотоциклов.","tr":"Bir yolcu, yanıkları ve yaralanmaları önlemek için bacaklarını egzoz(lar)dan, zincirlerden ve diğer hareketli parçalardan uzak tutmalıdır. Kaynak: Motosiklet Sürücü Kılavuzu.","hi":"यात्री को जलने और चोट से बचने के लिए अपने पैरों को मफलर, चेन और अन्य चलते पुर्ज़ों से दूर रखना चाहिए। स्रोत: Motorcycle Operator Manual।","ar":"ينبغي أن يبقي الراكب ساقيه بعيداً عن كاتم (كواتم) الصوت والسلاسل والأجزاء المتحركة الأخرى لتجنّب الحروق والإصابة. المصدر: دليل مشغل الدراجة النارية."}},{"cat":"passenger","a":1,"q":{"en":"How does carrying a passenger affect the way your motorcycle responds?","es":"¿Cómo afecta llevar a un pasajero la forma en que responde tu motocicleta?","ru":"Как перевозка пассажира влияет на то, как реагирует ваш мотоцикл?","tr":"Bir yolcu taşımak motosikletinizin tepki verme şeklini nasıl etkiler?","hi":"यात्री ले जाना आपकी मोटरसाइकिल की प्रतिक्रिया करने के तरीके को कैसे प्रभावित करता है?","ar":"كيف يؤثر حمل راكب على طريقة استجابة دراجتك النارية؟"},"o":[{"en":"It speeds up and stops faster because of added traction","es":"Acelera y se detiene más rápido por la tracción adicional","ru":"Он разгоняется и останавливается быстрее из-за дополнительного сцепления","tr":"Ek tutuş nedeniyle daha hızlı hızlanır ve daha hızlı durur","hi":"जोड़े गए कर्षण के कारण यह तेज़ी से गति पकड़ती और रुकती है","ar":"تتسارع وتتوقف أسرع بسبب زيادة قوة الاحتكاك"},{"en":"It responds more slowly, taking longer to speed up, slow down, or turn","es":"Responde más lento, tardando más en acelerar, frenar o girar","ru":"Он реагирует медленнее, дольше разгоняется, замедляется или поворачивает","tr":"Daha yavaş tepki verir; hızlanması, yavaşlaması veya dönmesi daha uzun sürer","hi":"यह अधिक धीरे प्रतिक्रिया करती है, गति पकड़ने, धीमा होने या मुड़ने में अधिक समय लेती है","ar":"تستجيب ببطء أكبر، وتستغرق وقتاً أطول للتسارع أو الإبطاء أو الانعطاف"},{"en":"It has no noticeable effect once you are moving","es":"No tiene un efecto notable una vez que estás en movimiento","ru":"Это не оказывает заметного влияния, когда вы уже движетесь","tr":"Hareket halindeyken fark edilir bir etkisi yoktur","hi":"एक बार चलने के बाद इसका कोई ध्यान देने योग्य प्रभाव नहीं होता","ar":"ليس له تأثير ملحوظ بمجرد أن تتحرك"},{"en":"It only affects cornering, not acceleration or braking","es":"Solo afecta el manejo en curvas, no la aceleración ni el frenado","ru":"Это влияет только на прохождение поворотов, а не на разгон или торможение","tr":"Yalnızca virajları etkiler, hızlanmayı veya frenlemeyi değil","hi":"यह केवल कॉर्नरिंग को प्रभावित करती है, एक्सीलरेशन या ब्रेकिंग को नहीं","ar":"يؤثر فقط على المنعطفات، وليس على التسارع أو الكبح"}],"e":{"en":"The motorcycle responds more slowly with a passenger; the heavier the passenger, the longer it takes to speed up, slow down, or turn. Source: Motorcycle Operator Manual.","es":"La motocicleta responde más lento con un pasajero; mientras más pesado sea el pasajero, más tarda en acelerar, frenar o girar. Fuente: Manual del Operador de Motocicletas.","ru":"С пассажиром мотоцикл реагирует медленнее; чем тяжелее пассажир, тем дольше уходит на разгон, замедление или поворот. Источник: Руководство для водителей мотоциклов.","tr":"Motosiklet bir yolcuyla daha yavaş tepki verir; yolcu ne kadar ağırsa hızlanması, yavaşlaması veya dönmesi o kadar uzun sürer. Kaynak: Motosiklet Sürücü Kılavuzu.","hi":"यात्री के साथ मोटरसाइकिल अधिक धीरे प्रतिक्रिया करती है; यात्री जितना भारी होगा, गति पकड़ने, धीमा होने या मुड़ने में उतना ही अधिक समय लगता है। स्रोत: Motorcycle Operator Manual।","ar":"تستجيب الدراجة النارية ببطء أكبر مع راكب؛ كلما كان الراكب أثقل، استغرق الأمر وقتاً أطول للتسارع أو الإبطاء أو الانعطاف. المصدر: دليل مشغل الدراجة النارية."}},{"cat":"passenger","a":1,"q":{"en":"When riding with a passenger, how should you approach a stop?","es":"Cuando conduces con un pasajero, ¿cómo debes acercarte a una parada?","ru":"При езде с пассажиром как следует подъезжать к остановке?","tr":"Bir yolcuyla sürerken bir duruşa nasıl yaklaşmalısınız?","hi":"यात्री के साथ सवारी करते समय, आपको रुकने के लिए कैसे पहुँचना चाहिए?","ar":"عند القيادة مع راكب، كيف ينبغي أن تقترب من التوقف؟"},"o":[{"en":"Brake harder at the last moment to save distance","es":"Frenar más fuerte en el último momento para ahorrar distancia","ru":"Тормозить сильнее в последний момент, чтобы сэкономить дистанцию","tr":"Mesafeden tasarruf etmek için son anda daha sert fren yapın","hi":"दूरी बचाने के लिए आखिरी क्षण में ज़ोर से ब्रेक लगाएँ","ar":"اكبح بقوة أكبر في اللحظة الأخيرة لتوفير المسافة"},{"en":"Start slowing earlier and keep a larger space cushion","es":"Empezar a reducir la velocidad antes y mantener un colchón de espacio más grande","ru":"Начинать замедление раньше и сохранять больший запас пространства","tr":"Daha erken yavaşlamaya başlayın ve daha büyük bir tampon boşluğu koruyun","hi":"पहले धीमा करना शुरू करें और बड़ा स्पेस कुशन बनाए रखें","ar":"ابدأ الإبطاء مبكراً وحافظ على مسافة أمان أكبر"},{"en":"Coast in neutral to reduce braking effort","es":"Avanzar en neutro para reducir el esfuerzo de frenado","ru":"Катиться на нейтрали, чтобы уменьшить усилие торможения","tr":"Frenleme çabasını azaltmak için boşta süzülün","hi":"ब्रेकिंग प्रयास कम करने के लिए न्यूट्रल में कोस्ट करें","ar":"انزلق في وضع الحياد لتقليل جهد الكبح"},{"en":"Stop in the same distance as you would riding alone","es":"Detenerte en la misma distancia que lo harías conduciendo solo","ru":"Останавливаться на той же дистанции, что и при езде в одиночку","tr":"Tek başına sürerken yapacağınız aynı mesafede durun","hi":"अकेले सवारी करने जितनी ही दूरी में रुकें","ar":"توقف في نفس المسافة كما لو كنت تقود بمفردك"}],"e":{"en":"With a passenger you should start slowing earlier and maintain a larger space cushion whenever slowing or stopping. Source: Motorcycle Operator Manual.","es":"Con un pasajero debes empezar a reducir la velocidad antes y mantener un colchón de espacio más grande siempre que reduzcas la velocidad o te detengas. Fuente: Manual del Operador de Motocicletas.","ru":"С пассажиром следует начинать замедление раньше и сохранять больший запас пространства всякий раз при замедлении или остановке. Источник: Руководство для водителей мотоциклов.","tr":"Bir yolcuyla, yavaşlarken veya dururken daha erken yavaşlamaya başlamalı ve daha büyük bir tampon boşluğu korumalısınız. Kaynak: Motosiklet Sürücü Kılavuzu.","hi":"यात्री के साथ आपको पहले धीमा करना शुरू करना चाहिए और जब भी धीमा हों या रुकें तो बड़ा स्पेस कुशन बनाए रखना चाहिए। स्रोत: Motorcycle Operator Manual।","ar":"مع راكب، ينبغي أن تبدأ الإبطاء مبكراً وتحافظ على مسافة أمان أكبر كلما أبطأت أو توقفت. المصدر: دليل مشغل الدراجة النارية."}},{"cat":"passenger","a":1,"q":{"en":"When carrying a passenger, how should you handle gaps in traffic when crossing or merging?","es":"Al llevar a un pasajero, ¿cómo debes manejar los espacios en el tráfico al cruzar o incorporarte?","ru":"При перевозке пассажира как следует обращаться с промежутками в потоке при пересечении или перестроении?","tr":"Bir yolcu taşırken, geçerken veya katılırken trafikteki boşlukları nasıl ele almalısınız?","hi":"यात्री ले जाते समय, सड़क पार करते या मर्ज करते समय आपको ट्रैफ़िक के अंतरालों को कैसे संभालना चाहिए?","ar":"عند حمل راكب، كيف ينبغي أن تتعامل مع الفجوات في حركة المرور عند العبور أو الاندماج؟"},"o":[{"en":"Use the same gaps you would use riding alone","es":"Usar los mismos espacios que usarías conduciendo solo","ru":"Использовать те же промежутки, что и при езде в одиночку","tr":"Tek başına sürerken kullanacağınız aynı boşlukları kullanın","hi":"वही अंतराल उपयोग करें जो आप अकेले सवारी करते समय करते हैं","ar":"استخدم نفس الفجوات التي تستخدمها عند القيادة بمفردك"},{"en":"Wait for larger gaps to cross, enter, or merge","es":"Esperar espacios más grandes para cruzar, entrar o incorporarte","ru":"Ждать более крупных промежутков для пересечения, въезда или перестроения","tr":"Geçmek, girmek veya katılmak için daha büyük boşlukları bekleyin","hi":"पार करने, प्रवेश करने या मर्ज करने के लिए बड़े अंतरालों का इंतज़ार करें","ar":"انتظر فجوات أكبر للعبور أو الدخول أو الاندماج"},{"en":"Take smaller gaps quickly before the extra weight slows you","es":"Tomar espacios más pequeños rápidamente antes de que el peso extra te frene","ru":"Быстро использовать меньшие промежутки, пока дополнительный вес не замедлил вас","tr":"Ekstra ağırlık sizi yavaşlatmadan önce küçük boşlukları hızla alın","hi":"अतिरिक्त वज़न आपको धीमा करने से पहले छोटे अंतरालों को जल्दी लें","ar":"استغل الفجوات الأصغر بسرعة قبل أن يبطئك الوزن الإضافي"},{"en":"Avoid merging entirely until the passenger gets off","es":"Evitar incorporarte por completo hasta que el pasajero se baje","ru":"Полностью избегать перестроений, пока пассажир не сойдёт","tr":"Yolcu inene kadar katılmaktan tamamen kaçının","hi":"यात्री के उतरने तक मर्ज करने से पूरी तरह बचें","ar":"تجنّب الاندماج تماماً حتى ينزل الراكب"}],"e":{"en":"Because the loaded motorcycle accelerates more slowly, wait for larger gaps to cross, enter, or merge in traffic when carrying a passenger. Source: Motorcycle Operator Manual.","es":"Como la motocicleta cargada acelera más lento, espera espacios más grandes para cruzar, entrar o incorporarte al tráfico cuando lleves a un pasajero. Fuente: Manual del Operador de Motocicletas.","ru":"Поскольку нагруженный мотоцикл разгоняется медленнее, ждите более крупных промежутков для пересечения, въезда или перестроения в потоке при перевозке пассажира. Источник: Руководство для водителей мотоциклов.","tr":"Yüklü motosiklet daha yavaş hızlandığı için bir yolcu taşırken trafiğe geçmek, girmek veya katılmak için daha büyük boşlukları bekleyin. Kaynak: Motosiklet Sürücü Kılavuzu.","hi":"क्योंकि लदी हुई मोटरसाइकिल अधिक धीरे गति पकड़ती है, इसलिए यात्री ले जाते समय ट्रैफ़िक में पार करने, प्रवेश करने या मर्ज करने के लिए बड़े अंतरालों का इंतज़ार करें। स्रोत: Motorcycle Operator Manual।","ar":"لأن الدراجة النارية المحمّلة تتسارع ببطء أكبر، انتظر فجوات أكبر للعبور أو الدخول أو الاندماج في حركة المرور عند حمل راكب. المصدر: دليل مشغل الدراجة النارية."}},{"cat":"passenger","a":1,"q":{"en":"What is the recommended way to position cargo relative to the rear axle?","es":"¿Cuál es la forma recomendada de colocar la carga respecto al eje trasero?","ru":"Каков рекомендуемый способ размещения груза относительно задней оси?","tr":"Yükü arka aksa göre konumlandırmanın önerilen yolu nedir?","hi":"पीछे के एक्सल के सापेक्ष कार्गो को रखने का अनुशंसित तरीका क्या है?","ar":"ما هي الطريقة الموصى بها لوضع البضائع بالنسبة للمحور الخلفي؟"},"o":[{"en":"Behind the rear axle to keep weight off the front tire","es":"Detrás del eje trasero para quitar peso de la llanta delantera","ru":"Позади задней оси, чтобы убрать вес с передней шины","tr":"Ağırlığı ön lastikten uzak tutmak için arka aksın arkasında","hi":"सामने के टायर से वज़न हटाने के लिए पीछे के एक्सल के पीछे","ar":"خلف المحور الخلفي لإبعاد الوزن عن الإطار الأمامي"},{"en":"Over, or in front of, the rear axle","es":"Sobre el eje trasero, o delante de él","ru":"Над задней осью или перед ней","tr":"Arka aksın üzerinde veya önünde","hi":"पीछे के एक्सल के ऊपर, या उसके सामने","ar":"فوق المحور الخلفي أو أمامه"},{"en":"Directly above the rear axle only","es":"Directamente encima del eje trasero únicamente","ru":"Только прямо над задней осью","tr":"Yalnızca tam olarak arka aksın üzerinde","hi":"केवल पीछे के एक्सल के ठीक ऊपर","ar":"فوق المحور الخلفي مباشرةً فقط"},{"en":"As far to the rear as the luggage rack allows","es":"Lo más atrás que permita el portaequipajes","ru":"Как можно дальше назад, насколько позволяет багажник","tr":"Bagaj rafının izin verdiği kadar arkada","hi":"लगेज रैक जितना पीछे अनुमति दे उतना पीछे","ar":"في أقصى الخلف قدر ما يسمح حامل الأمتعة"}],"e":{"en":"Keep the load forward by placing it over, or in front of, the rear axle; loads mounted behind the rear axle can affect turning and braking and cause a wobble. Source: Motorcycle Operator Manual.","es":"Mantén la carga hacia adelante colocándola sobre el eje trasero o delante de él; las cargas montadas detrás del eje trasero pueden afectar el giro y el frenado y causar un bamboleo. Fuente: Manual del Operador de Motocicletas.","ru":"Держите груз спереди, размещая его над задней осью или перед ней; груз, установленный позади задней оси, может влиять на поворот и торможение и вызывать вихляние. Источник: Руководство для водителей мотоциклов.","tr":"Yükü aksın üzerine veya önüne yerleştirerek öne doğru tutun; arka aksın arkasına monte edilen yükler dönüşü ve frenlemeyi etkileyebilir ve sallanmaya neden olabilir. Kaynak: Motosiklet Sürücü Kılavuzu.","hi":"भार को पीछे के एक्सल के ऊपर, या उसके सामने रखकर आगे रखें; पीछे के एक्सल के पीछे लगाए गए भार मुड़ने और ब्रेकिंग को प्रभावित कर सकते हैं और लड़खड़ाहट पैदा कर सकते हैं। स्रोत: Motorcycle Operator Manual।","ar":"أبقِ الحمل إلى الأمام بوضعه فوق المحور الخلفي أو أمامه؛ فالأحمال المركّبة خلف المحور الخلفي يمكن أن تؤثر على الانعطاف والكبح وتسبب تمايلاً. المصدر: دليل مشغل الدراجة النارية."}},{"cat":"passenger","a":0,"q":{"en":"Why should you avoid mounting a heavy load behind the rear axle?","es":"¿Por qué debes evitar montar una carga pesada detrás del eje trasero?","ru":"Почему следует избегать размещения тяжёлого груза позади задней оси?","tr":"Arka aksın arkasına ağır bir yük monte etmekten neden kaçınmalısınız?","hi":"आपको पीछे के एक्सल के पीछे भारी भार लगाने से क्यों बचना चाहिए?","ar":"لماذا ينبغي أن تتجنّب تركيب حمل ثقيل خلف المحور الخلفي؟"},"o":[{"en":"It can affect how the motorcycle turns and brakes and may cause a wobble","es":"Puede afectar cómo gira y frena la motocicleta y puede causar un bamboleo","ru":"Это может повлиять на то, как мотоцикл поворачивает и тормозит, и может вызвать вихляние","tr":"Motosikletin nasıl döndüğünü ve frenlediğini etkileyebilir ve sallanmaya neden olabilir","hi":"यह मोटरसाइकिल के मुड़ने और ब्रेकिंग को प्रभावित कर सकता है और लड़खड़ाहट पैदा कर सकता है","ar":"يمكن أن يؤثر على كيفية انعطاف الدراجة النارية وكبحها وقد يسبب تمايلاً"},{"en":"It improves cornering but ruins fuel economy","es":"Mejora el manejo en curvas pero arruina el rendimiento de combustible","ru":"Это улучшает прохождение поворотов, но ухудшает экономичность расхода топлива","tr":"Virajı iyileştirir ama yakıt ekonomisini bozar","hi":"यह कॉर्नरिंग सुधारता है लेकिन ईंधन क्षमता बर्बाद करता है","ar":"يحسّن المنعطفات لكنه يدمّر اقتصاد الوقود"},{"en":"It overloads the front tire and causes a skid","es":"Sobrecarga la llanta delantera y causa un derrape","ru":"Это перегружает переднюю шину и вызывает занос","tr":"Ön lastiği aşırı yükler ve kaymaya neden olur","hi":"यह सामने के टायर पर अधिक भार डालता है और स्किड पैदा करता है","ar":"يثقل الإطار الأمامي ويسبب انزلاقاً"},{"en":"It is illegal in most states","es":"Es ilegal en la mayoría de los estados","ru":"Это незаконно в большинстве штатов","tr":"Çoğu eyalette yasa dışıdır","hi":"यह अधिकांश राज्यों में अवैध है","ar":"إنه غير قانوني في معظم الولايات"}],"e":{"en":"Mounting loads behind the rear axle can affect how the motorcycle turns and brakes and can also cause a wobble. Source: Motorcycle Operator Manual.","es":"Montar cargas detrás del eje trasero puede afectar cómo gira y frena la motocicleta y también puede causar un bamboleo. Fuente: Manual del Operador de Motocicletas.","ru":"Размещение груза позади задней оси может повлиять на то, как мотоцикл поворачивает и тормозит, а также может вызвать вихляние. Источник: Руководство для водителей мотоциклов.","tr":"Yükleri arka aksın arkasına monte etmek, motosikletin nasıl döndüğünü ve frenlediğini etkileyebilir ve ayrıca sallanmaya neden olabilir. Kaynak: Motosiklet Sürücü Kılavuzu.","hi":"पीछे के एक्सल के पीछे भार लगाने से मोटरसाइकिल के मुड़ने और ब्रेकिंग का तरीका प्रभावित हो सकता है और लड़खड़ाहट भी पैदा हो सकती है। स्रोत: Motorcycle Operator Manual।","ar":"يمكن أن يؤثر تركيب الأحمال خلف المحور الخلفي على كيفية انعطاف الدراجة النارية وكبحها ويمكن أيضاً أن يسبب تمايلاً. المصدر: دليل مشغل الدراجة النارية."}},{"cat":"passenger","a":1,"q":{"en":"How high on the motorcycle should you secure cargo?","es":"¿A qué altura de la motocicleta debes asegurar la carga?","ru":"На какой высоте на мотоцикле следует закреплять груз?","tr":"Yükü motosiklette ne kadar yükseğe sabitlemelisiniz?","hi":"आपको मोटरसाइकिल पर कार्गो को कितनी ऊँचाई पर सुरक्षित करना चाहिए?","ar":"إلى أي ارتفاع على الدراجة النارية ينبغي أن تثبّت البضائع؟"},"o":[{"en":"As high as possible to keep it out of the wheels","es":"Lo más alto posible para mantenerla fuera de las ruedas","ru":"Как можно выше, чтобы держать его подальше от колёс","tr":"Tekerleklerden uzak tutmak için olabildiğince yükseğe","hi":"जितना संभव हो उतना ऊँचा ताकि यह पहियों से बाहर रहे","ar":"إلى أعلى ارتفاع ممكن لإبقائها بعيداً عن العجلات"},{"en":"As low as possible, or in the saddlebags","es":"Lo más bajo posible, o en las alforjas","ru":"Как можно ниже или в боковых кофрах","tr":"Olabildiğince alçağa veya yan çantalara","hi":"जितना संभव हो उतना नीचा, या सैडलबैग में","ar":"إلى أدنى ارتفاع ممكن، أو في الحقائب الجانبية"},{"en":"On top of a sissy bar for easy access","es":"Encima de una barra trasera (sissy bar) para acceder con facilidad","ru":"На верху спинки-дуги для удобного доступа","tr":"Kolay erişim için bir sissy barın üzerine","hi":"आसान पहुँच के लिए सिसी बार के ऊपर","ar":"فوق قضيب المسند الخلفي لسهولة الوصول"},{"en":"At seat height, strapped to the backrest","es":"A la altura del asiento, amarrada al respaldo","ru":"На высоте сиденья, пристёгнутым к спинке","tr":"Sele yüksekliğinde, sırt desteğine bağlı","hi":"सीट की ऊँचाई पर, बैकरेस्ट से बँधा हुआ","ar":"عند ارتفاع المقعد، مربوطة بمسند الظهر"}],"e":{"en":"Secure loads low, or put them in saddlebags; attaching a load high (such as to a sissy bar) raises the center of gravity and can upset the bike's balance. Source: Motorcycle Operator Manual.","es":"Asegura las cargas en una posición baja, o ponlas en las alforjas; sujetar una carga en alto (como a una barra trasera o sissy bar) eleva el centro de gravedad y puede alterar el equilibrio de la moto. Fuente: Manual del Operador de Motocicletas.","ru":"Закрепляйте груз низко или кладите его в боковые кофры; крепление груза высоко (например, к спинке-дуге) поднимает центр тяжести и может нарушить баланс мотоцикла. Источник: Руководство для водителей мотоциклов.","tr":"Yükleri alçağa sabitleyin veya yan çantalara koyun; bir yükü yükseğe (sissy bar gibi) bağlamak ağırlık merkezini yükseltir ve motosikletin dengesini bozabilir. Kaynak: Motosiklet Sürücü Kılavuzu.","hi":"भार को नीचे सुरक्षित करें, या उन्हें सैडलबैग में रखें; भार को ऊँचा (जैसे सिसी बार से) लगाना गुरुत्वाकर्षण केंद्र को ऊपर उठाता है और बाइक का संतुलन बिगाड़ सकता है। स्रोत: Motorcycle Operator Manual।","ar":"ثبّت الأحمال منخفضة، أو ضعها في الحقائب الجانبية؛ فربط الحمل عالياً (مثل قضيب المسند الخلفي) يرفع مركز الثقل ويمكن أن يخلّ بتوازن الدراجة. المصدر: دليل مشغل الدراجة النارية."}},{"cat":"passenger","a":1,"q":{"en":"How should you distribute weight when loading saddlebags on both sides?","es":"¿Cómo debes distribuir el peso al cargar alforjas en ambos lados?","ru":"Как следует распределять вес при загрузке боковых кофров с обеих сторон?","tr":"Her iki tarafa yan çanta yüklerken ağırlığı nasıl dağıtmalısınız?","hi":"दोनों ओर सैडलबैग लोड करते समय आपको वज़न कैसे वितरित करना चाहिए?","ar":"كيف ينبغي أن توزّع الوزن عند تحميل الحقائب الجانبية على كلا الجانبين؟"},"o":[{"en":"Put more weight on the side away from traffic","es":"Poner más peso en el lado alejado del tráfico","ru":"Класть больше веса на сторону, удалённую от потока","tr":"Trafikten uzak tarafa daha fazla ağırlık koyun","hi":"ट्रैफ़िक से दूर वाली ओर अधिक वज़न रखें","ar":"ضع وزناً أكبر على الجانب البعيد عن حركة المرور"},{"en":"Load each saddlebag with about the same weight","es":"Cargar cada alforja con aproximadamente el mismo peso","ru":"Загружать каждый кофр примерно одинаковым весом","tr":"Her yan çantaya yaklaşık aynı ağırlığı yükleyin","hi":"प्रत्येक सैडलबैग को लगभग समान वज़न से लोड करें","ar":"حمّل كل حقيبة جانبية بوزن متساوٍ تقريباً"},{"en":"Put all the heavy items in one bag for easy access","es":"Poner todos los objetos pesados en una alforja para acceder con facilidad","ru":"Класть все тяжёлые предметы в один кофр для удобного доступа","tr":"Kolay erişim için tüm ağır eşyaları tek çantaya koyun","hi":"आसान पहुँच के लिए सभी भारी सामान एक बैग में रखें","ar":"ضع كل الأشياء الثقيلة في حقيبة واحدة لسهولة الوصول"},{"en":"Keep the right bag heavier to offset the kickstand","es":"Mantener la alforja derecha más pesada para compensar el soporte","ru":"Держать правый кофр тяжелее, чтобы компенсировать подставку","tr":"Yan sehpayı dengelemek için sağ çantayı daha ağır tutun","hi":"किकस्टैंड की भरपाई के लिए दायाँ बैग भारी रखें","ar":"أبقِ الحقيبة اليمنى أثقل لموازنة الحامل الجانبي"}],"e":{"en":"Load each saddlebag with about the same weight; an uneven load can cause the motorcycle to pull to one side. Source: Motorcycle Operator Manual.","es":"Carga cada alforja con aproximadamente el mismo peso; una carga despareja puede hacer que la motocicleta jale hacia un lado. Fuente: Manual del Operador de Motocicletas.","ru":"Загружайте каждый боковой кофр примерно одинаковым весом; неравномерная нагрузка может заставить мотоцикл тянуть в одну сторону. Источник: Руководство для водителей мотоциклов.","tr":"Her yan çantaya yaklaşık aynı ağırlığı yükleyin; dengesiz bir yük motosikletin bir tarafa çekmesine neden olabilir. Kaynak: Motosiklet Sürücü Kılavuzu.","hi":"प्रत्येक सैडलबैग को लगभग समान वज़न से लोड करें; असमान भार मोटरसाइकिल को एक तरफ़ खींच सकता है। स्रोत: Motorcycle Operator Manual।","ar":"حمّل كل حقيبة جانبية بوزن متساوٍ تقريباً؛ فالحمل غير المتساوي يمكن أن يجعل الدراجة النارية تنحرف إلى جانب واحد. المصدر: دليل مشغل الدراجة النارية."}},{"cat":"passenger","a":1,"q":{"en":"What is the recommended way to fasten cargo to your motorcycle?","es":"¿Cuál es la forma recomendada de sujetar la carga a tu motocicleta?","ru":"Каков рекомендуемый способ крепления груза к мотоциклу?","tr":"Yükü motosikletinize sabitlemenin önerilen yolu nedir?","hi":"अपनी मोटरसाइकिल पर कार्गो बाँधने का अनुशंसित तरीका क्या है?","ar":"ما هي الطريقة الموصى بها لربط البضائع بدراجتك النارية؟"},"o":[{"en":"Tie it down with rope and knots","es":"Amarrarla con cuerda y nudos","ru":"Привязать его верёвкой с узлами","tr":"İp ve düğümlerle bağlayın","hi":"इसे रस्सी और गाँठों से बाँधें","ar":"اربطها بحبل وعُقد"},{"en":"Fasten it securely with elastic cords such as bungee cords or nets","es":"Sujetarla firmemente con cuerdas elásticas, como cuerdas elásticas (bungee) o redes","ru":"Надёжно закрепить его эластичными шнурами, например резиновыми стяжками или сетками","tr":"Bungee kordonlar veya filer gibi elastik kordonlarla sıkıca sabitleyin","hi":"इसे लचीली डोरियों जैसे बंजी कॉर्ड या जालों से मज़बूती से बाँधें","ar":"ثبّتها بإحكام بحبال مطاطية مثل حبال البنجي أو الشِّباك"},{"en":"Set it loosely so it can shift to absorb bumps","es":"Colocarla suelta para que pueda moverse y absorber los baches","ru":"Уложить его свободно, чтобы он мог смещаться, поглощая неровности","tr":"Tümsekleri emmesi için gevşekçe yerleştirin","hi":"इसे ढीला रखें ताकि यह उभारों को सोखने के लिए हिल सके","ar":"ضعها بشكل مرتخٍ حتى تتمكن من التحرك لامتصاص المطبات"},{"en":"Hold it in place with one hand while riding","es":"Sostenerla en su lugar con una mano mientras conduces","ru":"Удерживать его на месте одной рукой во время езды","tr":"Sürerken tek elinizle yerinde tutun","hi":"सवारी करते समय इसे एक हाथ से पकड़ें","ar":"أمسكها في مكانها بيد واحدة أثناء القيادة"}],"e":{"en":"Fasten the load securely with elastic cords (bungee cords or nets); rope can stretch and knots can come loose, letting the load shift or fall. Source: Motorcycle Operator Manual.","es":"Sujeta la carga firmemente con cuerdas elásticas (cuerdas bungee o redes); la cuerda puede estirarse y los nudos pueden aflojarse, dejando que la carga se mueva o se caiga. Fuente: Manual del Operador de Motocicletas.","ru":"Надёжно закрепляйте груз эластичными шнурами (резиновыми стяжками или сетками); верёвка может растягиваться, а узлы развязываться, позволяя грузу сместиться или упасть. Источник: Руководство для водителей мотоциклов.","tr":"Yükü elastik kordonlarla (bungee kordonlar veya filer) sıkıca sabitleyin; ip esneyebilir ve düğümler gevşeyebilir, bu da yükün kaymasına veya düşmesine izin verir. Kaynak: Motosiklet Sürücü Kılavuzu.","hi":"भार को लचीली डोरियों (बंजी कॉर्ड या जालों) से मज़बूती से बाँधें; रस्सी खिंच सकती है और गाँठें ढीली हो सकती हैं, जिससे भार हिल सकता है या गिर सकता है। स्रोत: Motorcycle Operator Manual।","ar":"ثبّت الحمل بإحكام بحبال مطاطية (حبال البنجي أو الشِّباك)؛ فالحبل يمكن أن يتمدد والعُقد يمكن أن تنفك، مما يجعل الحمل يتحرك أو يسقط. المصدر: دليل مشغل الدراجة النارية."}},{"cat":"passenger","a":1,"q":{"en":"What can happen if cargo or a saddlebag works loose and catches in the wheel or chain?","es":"¿Qué puede pasar si la carga o una alforja se afloja y se atora en la rueda o la cadena?","ru":"Что может произойти, если груз или боковой кофр ослабнет и попадёт в колесо или цепь?","tr":"Yük veya bir yan çanta gevşeyip tekerleğe ya da zincire takılırsa ne olabilir?","hi":"अगर कार्गो या सैडलबैग ढीला होकर पहिए या चेन में फँस जाए तो क्या हो सकता है?","ar":"ماذا يمكن أن يحدث إذا انفكّت البضائع أو حقيبة جانبية وعلقت في العجلة أو السلسلة؟"},"o":[{"en":"Nothing serious, the load simply drags behind","es":"Nada grave, la carga simplemente se arrastra detrás","ru":"Ничего серьёзного, груз просто потащится сзади","tr":"Ciddi bir şey olmaz, yük sadece arkadan sürüklenir","hi":"कुछ गंभीर नहीं, भार बस पीछे घिसटता है","ar":"لا شيء خطير، فالحمل ببساطة يُجرّ خلفها"},{"en":"The rear wheel can lock up, causing the motorcycle to skid","es":"La rueda trasera puede bloquearse, causando que la motocicleta derrape","ru":"Заднее колесо может заблокироваться, вызвав занос мотоцикла","tr":"Arka tekerlek kilitlenebilir ve motosikletin kaymasına neden olabilir","hi":"पीछे का पहिया लॉक हो सकता है, जिससे मोटरसाइकिल स्किड कर सकती है","ar":"يمكن أن تنغلق العجلة الخلفية، مما يسبب انزلاق الدراجة النارية"},{"en":"The engine will stall safely","es":"El motor se apagará de forma segura","ru":"Двигатель безопасно заглохнет","tr":"Motor güvenli bir şekilde stop eder","hi":"इंजन सुरक्षित रूप से बंद हो जाएगा","ar":"سيتوقف المحرك بأمان"},{"en":"The front brake will automatically release","es":"El freno delantero se soltará automáticamente","ru":"Передний тормоз автоматически отпустится","tr":"Ön fren otomatik olarak serbest kalır","hi":"फ्रंट ब्रेक अपने आप रिलीज़ हो जाएगा","ar":"سيُحرّر المكبح الأمامي تلقائياً"}],"e":{"en":"A loose load or overloaded saddlebag can catch in the wheel or chain, locking the rear wheel and causing the motorcycle to skid, so check the load often. Source: Motorcycle Operator Manual.","es":"Una carga suelta o una alforja sobrecargada puede atorarse en la rueda o la cadena, bloqueando la rueda trasera y causando que la motocicleta derrape, así que revisa la carga con frecuencia. Fuente: Manual del Operador de Motocicletas.","ru":"Ослабленный груз или перегруженный боковой кофр может попасть в колесо или цепь, заблокировав заднее колесо и вызвав занос мотоцикла, поэтому проверяйте груз почаще. Источник: Руководство для водителей мотоциклов.","tr":"Gevşek bir yük veya aşırı yüklenmiş bir yan çanta tekerleğe veya zincire takılabilir, arka tekerleği kilitleyip motosikletin kaymasına neden olabilir, bu yüzden yükü sık sık kontrol edin. Kaynak: Motosiklet Sürücü Kılavuzu.","hi":"ढीला भार या ज़्यादा लदा सैडलबैग पहिए या चेन में फँस सकता है, जिससे पीछे का पहिया लॉक हो जाता है और मोटरसाइकिल स्किड कर जाती है, इसलिए भार को बार-बार जाँचें। स्रोत: Motorcycle Operator Manual।","ar":"يمكن لحمل منفك أو حقيبة جانبية محمّلة بإفراط أن يعلق في العجلة أو السلسلة، مما يقفل العجلة الخلفية ويسبب انزلاق الدراجة النارية، لذا افحص الحمل كثيراً. المصدر: دليل مشغل الدراجة النارية."}},{"cat":"passenger","a":1,"q":{"en":"Who should be chosen as the lead rider and the sweep (last) rider in a group ride?","es":"¿A quién se debe elegir como conductor líder y como conductor de cierre (último) en un recorrido en grupo?","ru":"Кого следует выбирать ведущим и замыкающим (последним) при групповой поездке?","tr":"Bir grup sürüşünde lider sürücü ve sweep (en son) sürücü olarak kim seçilmelidir?","hi":"समूह सवारी में लीड सवार और स्वीप (अंतिम) सवार के रूप में किसे चुना जाना चाहिए?","ar":"من ينبغي أن يُختار سائقاً قائداً وسائقاً مرافقاً (الأخير) في ركوب جماعي؟"},"o":[{"en":"The two riders with the fastest motorcycles","es":"A los dos conductores con las motocicletas más rápidas","ru":"Двух мотоциклистов с самыми быстрыми мотоциклами","tr":"En hızlı motosikletlere sahip iki sürücü","hi":"सबसे तेज़ मोटरसाइकिलों वाले दो सवार","ar":"السائقان اللذان يملكان أسرع دراجتين ناريتين"},{"en":"The most experienced riders in the group","es":"A los conductores más experimentados del grupo","ru":"Самых опытных мотоциклистов в группе","tr":"Gruptaki en deneyimli sürücüler","hi":"समूह के सबसे अनुभवी सवार","ar":"أكثر السائقين خبرة في المجموعة"},{"en":"The newest riders, so they can learn","es":"A los conductores más nuevos, para que aprendan","ru":"Самых новых мотоциклистов, чтобы они учились","tr":"En yeni sürücüler, öğrenebilmeleri için","hi":"सबसे नए सवार, ताकि वे सीख सकें","ar":"أحدث السائقين، حتى يتعلموا"},{"en":"Whoever knows the route, regardless of experience","es":"A quien conozca la ruta, sin importar su experiencia","ru":"Того, кто знает маршрут, независимо от опыта","tr":"Deneyimden bağımsız olarak güzergahı bilen kişi","hi":"जो भी रास्ता जानता हो, अनुभव की परवाह किए बिना","ar":"من يعرف الطريق، بغض النظر عن الخبرة"}],"e":{"en":"The lead rider and the sweep rider should be the most experienced riders of the group. Source: Motorcycle Operator Manual.","es":"El conductor líder y el conductor de cierre deben ser los conductores más experimentados del grupo. Fuente: Manual del Operador de Motocicletas.","ru":"Ведущим и замыкающим должны быть самые опытные мотоциклисты группы. Источник: Руководство для водителей мотоциклов.","tr":"Lider sürücü ve sweep sürücü, grubun en deneyimli sürücüleri olmalıdır. Kaynak: Motosiklet Sürücü Kılavuzu.","hi":"लीड सवार और स्वीप सवार समूह के सबसे अनुभवी सवार होने चाहिए। स्रोत: Motorcycle Operator Manual।","ar":"ينبغي أن يكون السائق القائد والسائق المرافق أكثر السائقين خبرة في المجموعة. المصدر: دليل مشغل الدراجة النارية."}},{"cat":"passenger","a":1,"q":{"en":"Where should inexperienced riders be placed in a group formation?","es":"¿Dónde se debe ubicar a los conductores sin experiencia en una formación de grupo?","ru":"Где в групповом построении следует размещать неопытных мотоциклистов?","tr":"Bir grup formasyonunda deneyimsiz sürücüler nereye yerleştirilmelidir?","hi":"समूह संरचना में अनुभवहीन सवारों को कहाँ रखा जाना चाहिए?","ar":"أين ينبغي أن يُوضع السائقون عديمو الخبرة في تشكيل جماعي؟"},"o":[{"en":"At the very back, behind the sweep rider","es":"En la parte de atrás, detrás del conductor de cierre","ru":"В самом конце, позади замыкающего","tr":"En arkaya, sweep sürücünün arkasına","hi":"सबसे पीछे, स्वीप सवार के पीछे","ar":"في أقصى الخلف، خلف السائق المرافق"},{"en":"Just behind the leader","es":"Justo detrás del líder","ru":"Сразу за ведущим","tr":"Hemen liderin arkasına","hi":"लीडर के ठीक पीछे","ar":"خلف القائد مباشرةً"},{"en":"In the middle, surrounded by experienced riders","es":"En el medio, rodeados de conductores experimentados","ru":"В середине, в окружении опытных мотоциклистов","tr":"Ortaya, deneyimli sürücülerle çevrili","hi":"बीच में, अनुभवी सवारों से घिरे हुए","ar":"في المنتصف، محاطين بسائقين ذوي خبرة"},{"en":"Wherever they feel most comfortable","es":"Donde se sientan más cómodos","ru":"Там, где им наиболее комфортно","tr":"En rahat hissettikleri yere","hi":"जहाँ भी वे सबसे सहज महसूस करें","ar":"حيثما يشعرون بالراحة أكثر"}],"e":{"en":"Place inexperienced riders just behind the leader so they do not have to chase the group and the experienced riders behind can watch them. Source: Motorcycle Operator Manual.","es":"Ubica a los conductores sin experiencia justo detrás del líder, para que no tengan que perseguir al grupo y los conductores experimentados de atrás puedan vigilarlos. Fuente: Manual del Operador de Motocicletas.","ru":"Размещайте неопытных мотоциклистов сразу за ведущим, чтобы им не приходилось догонять группу, а опытные мотоциклисты позади могли за ними присматривать. Источник: Руководство для водителей мотоциклов.","tr":"Deneyimsiz sürücüleri hemen liderin arkasına yerleştirin, böylece grubu kovalamak zorunda kalmazlar ve arkadaki deneyimli sürücüler onları gözetebilir. Kaynak: Motosiklet Sürücü Kılavuzu.","hi":"अनुभवहीन सवारों को लीडर के ठीक पीछे रखें ताकि उन्हें समूह का पीछा न करना पड़े और पीछे के अनुभवी सवार उन पर नज़र रख सकें। स्रोत: Motorcycle Operator Manual।","ar":"ضع السائقين عديمي الخبرة خلف القائد مباشرةً حتى لا يضطروا إلى ملاحقة المجموعة ويتمكن السائقون ذوو الخبرة في الخلف من مراقبتهم. المصدر: دليل مشغل الدراجة النارية."}},{"cat":"passenger","a":1,"q":{"en":"In a staggered formation on a straight road, where does the leader ride and where does the second rider ride?","es":"En una formación escalonada en una vía recta, ¿dónde conduce el líder y dónde conduce el segundo conductor?","ru":"В шахматном построении на прямой дороге где едет ведущий и где едет второй мотоциклист?","tr":"Düz bir yolda kaydırmalı (staggered) formasyonda lider nerede sürer ve ikinci sürücü nerede sürer?","hi":"सीधी सड़क पर स्टैगर्ड संरचना में, लीडर कहाँ चलता है और दूसरा सवार कहाँ चलता है?","ar":"في تشكيل متعرّج على طريق مستقيم، أين يركب القائد وأين يركب السائق الثاني؟"},"o":[{"en":"The leader rides in the center; the second rider rides directly behind","es":"El líder conduce en el centro; el segundo conductor va directamente detrás","ru":"Ведущий едет по центру; второй мотоциклист едет прямо позади","tr":"Lider ortada sürer; ikinci sürücü tam arkasında sürer","hi":"लीडर केंद्र में चलता है; दूसरा सवार सीधे पीछे चलता है","ar":"يركب القائد في المنتصف؛ ويركب السائق الثاني خلفه مباشرةً"},{"en":"The leader rides in the left of the lane; the second rider rides at least one second back in the right of the lane","es":"El líder conduce en la parte izquierda del carril; el segundo conductor va al menos un segundo atrás en la parte derecha del carril","ru":"Ведущий едет в левой части полосы; второй мотоциклист едет не менее чем в одной секунде позади в правой части полосы","tr":"Lider şeritin solunda sürer; ikinci sürücü şeritin sağında en az bir saniye geride sürer","hi":"लीडर लेन के बाएँ में चलता है; दूसरा सवार लेन के दाएँ में कम से कम 1 सेकंड पीछे रहता है","ar":"يركب القائد في يسار المسار؛ ويركب السائق الثاني على بُعد ثانية واحدة على الأقل في يمين المسار"},{"en":"The leader and second rider ride side by side across the lane","es":"El líder y el segundo conductor van lado a lado a lo ancho del carril","ru":"Ведущий и второй мотоциклист едут бок о бок поперёк полосы","tr":"Lider ve ikinci sürücü şerit boyunca yan yana sürer","hi":"लीडर और दूसरा सवार लेन के आर-पार अगल-बगल चलते हैं","ar":"يركب القائد والسائق الثاني جنباً إلى جنب عبر المسار"},{"en":"The leader rides in the right of the lane; the second rider rides on the shoulder","es":"El líder conduce en la parte derecha del carril; el segundo conductor va en el acotamiento","ru":"Ведущий едет в правой части полосы; второй мотоциклист едет по обочине","tr":"Lider şeritin sağında sürer; ikinci sürücü bankette sürer","hi":"लीडर लेन के दाएँ में चलता है; दूसरा सवार कंधे पर चलता है","ar":"يركب القائد في يمين المسار؛ ويركب السائق الثاني على الكتف"}],"e":{"en":"In staggered formation the leader rides in the left of the lane and the second rider stays at least one second back in the right of the lane, keeping the group close with a space cushion. Source: Motorcycle Operator Manual.","es":"En la formación escalonada el líder conduce en la parte izquierda del carril y el segundo conductor se mantiene al menos un segundo atrás en la parte derecha del carril, manteniendo al grupo unido con un colchón de espacio. Fuente: Manual del Operador de Motocicletas.","ru":"В шахматном построении ведущий едет в левой части полосы, а второй мотоциклист держится не менее чем в одной секунде позади в правой части полосы, сохраняя группу плотной с запасом пространства. Источник: Руководство для водителей мотоциклов.","tr":"Kaydırmalı formasyonda lider şeritin solunda sürer ve ikinci sürücü şeritin sağında en az bir saniye geride kalır, grubu bir tampon boşluğuyla yakın tutar. Kaynak: Motosiklet Sürücü Kılavuzu.","hi":"स्टैगर्ड संरचना में लीडर लेन के बाएँ में चलता है और दूसरा सवार लेन के दाएँ में कम से कम 1 सेकंड पीछे रहता है, समूह को स्पेस कुशन के साथ पास रखते हुए। स्रोत: Motorcycle Operator Manual।","ar":"في التشكيل المتعرّج يركب القائد في يسار المسار ويبقى السائق الثاني على بُعد ثانية واحدة على الأقل في يمين المسار، مع إبقاء المجموعة متقاربة مع مسافة أمان. المصدر: دليل مشغل الدراجة النارية."}},{"cat":"passenger","a":1,"q":{"en":"When is it best for a group to switch from staggered formation to single file?","es":"¿Cuándo es mejor que un grupo cambie de la formación escalonada a fila india (uno detrás de otro)?","ru":"Когда группе лучше всего переходить из шахматного построения в одну колонну?","tr":"Bir grubun kaydırmalı formasyondan tek sıraya geçmesi en iyi ne zamandır?","hi":"समूह के लिए स्टैगर्ड संरचना से सिंगल फ़ाइल में बदलना कब सबसे अच्छा होता है?","ar":"متى يكون من الأفضل للمجموعة أن تتحول من التشكيل المتعرّج إلى الصف الواحد؟"},"o":[{"en":"Only at night or in the rain","es":"Solo de noche o bajo la lluvia","ru":"Только ночью или в дождь","tr":"Yalnızca gece veya yağmurda","hi":"केवल रात में या बारिश में","ar":"فقط ليلاً أو في المطر"},{"en":"When riding in curves, turning, or entering or leaving freeways and highways","es":"Al conducir en curvas, al girar o al entrar o salir de autopistas y carreteras","ru":"При прохождении поворотов, виражей или въезде на автомагистрали и шоссе и съезде с них","tr":"Virajlarda sürerken, dönerken veya otoyollara ve karayollarına girip çıkarken","hi":"कर्व में चलते समय, मुड़ते समय, या फ़्रीवे और राजमार्गों में प्रवेश करते या निकलते समय","ar":"عند القيادة في المنعطفات أو الانعطاف أو الدخول إلى الطرق السريعة أو الخروج منها"},{"en":"Whenever the speed limit increases","es":"Cada vez que aumenta el límite de velocidad","ru":"Всякий раз, когда повышается ограничение скорости","tr":"Hız sınırı her arttığında","hi":"जब भी गति सीमा बढ़े","ar":"كلما زادت سرعة الحد المسموح"},{"en":"Never; staggered formation is used everywhere","es":"Nunca; la formación escalonada se usa en todas partes","ru":"Никогда; шахматное построение используется везде","tr":"Asla; kaydırmalı formasyon her yerde kullanılır","hi":"कभी नहीं; स्टैगर्ड संरचना हर जगह उपयोग होती है","ar":"أبداً؛ يُستخدم التشكيل المتعرّج في كل مكان"}],"e":{"en":"It is best to move to single-file formation when riding in curves, turning, and entering or leaving freeways or highways. Source: Motorcycle Operator Manual.","es":"Lo mejor es pasar a la formación en fila india al conducir en curvas, al girar y al entrar o salir de autopistas o carreteras. Fuente: Manual del Operador de Motocicletas.","ru":"Лучше всего переходить в построение в одну колонну при прохождении поворотов, виражей и въезде на автомагистрали или шоссе и съезде с них. Источник: Руководство для водителей мотоциклов.","tr":"Virajlarda sürerken, dönerken ve otoyollara veya karayollarına girip çıkarken tek sıra formasyona geçmek en iyisidir. Kaynak: Motosiklet Sürücü Kılavuzu.","hi":"कर्व में चलते समय, मुड़ते समय, और फ़्रीवे या राजमार्गों में प्रवेश करते या निकलते समय सिंगल-फ़ाइल संरचना में जाना सबसे अच्छा होता है। स्रोत: Motorcycle Operator Manual।","ar":"من الأفضل الانتقال إلى تشكيل الصف الواحد عند القيادة في المنعطفات والانعطاف والدخول إلى الطرق السريعة أو الخروج منها. المصدر: دليل مشغل الدراجة النارية."}},{"cat":"impairment","a":1,"q":{"en":"According to studies cited in the Motorcycle Operator Manual, roughly what share of riders killed in motorcycle crashes had been drinking?","es":"Según los estudios citados en el Manual del Operador de Motocicletas, ¿aproximadamente qué proporción de los conductores muertos en choques de motocicleta habían estado bebiendo?","ru":"Согласно исследованиям, приведённым в Руководстве для водителей мотоциклов, какая примерно доля мотоциклистов, погибших в авариях, употребляла алкоголь?","tr":"Motosiklet Sürücü Kılavuzu'nda atıfta bulunulan çalışmalara göre, motosiklet kazalarında ölen sürücülerin kabaca ne kadarı içki içmişti?","hi":"Motorcycle Operator Manual में उद्धृत अध्ययनों के अनुसार, मोटरसाइकिल दुर्घटनाओं में मारे गए सवारों में से लगभग कितने हिस्से ने शराब पी रखी थी?","ar":"وفقاً للدراسات المذكورة في دليل مشغل الدراجة النارية، ما هي تقريباً نسبة السائقين الذين قُتلوا في حوادث الدراجات النارية وكانوا قد تناولوا الكحول؟"},"o":[{"en":"Nearly 90 percent","es":"Casi 90 por ciento","ru":"Почти 90 процентов","tr":"Neredeyse yüzde 90","hi":"लगभग 90 प्रतिशत","ar":"نحو 90 بالمئة"},{"en":"About 40 to 45 percent","es":"Cerca de 40 a 45 por ciento","ru":"Около 40–45 процентов","tr":"Yaklaşık yüzde 40 ila 45","hi":"लगभग 40 से 45 प्रतिशत","ar":"نحو 40 إلى 45 بالمئة"},{"en":"About 10 percent","es":"Cerca de 10 por ciento","ru":"Около 10 процентов","tr":"Yaklaşık yüzde 10","hi":"लगभग 10 प्रतिशत","ar":"نحو 10 بالمئة"},{"en":"Fewer than 5 percent","es":"Menos de 5 por ciento","ru":"Менее 5 процентов","tr":"Yüzde 5'ten az","hi":"5 प्रतिशत से कम","ar":"أقل من 5 بالمئة"}],"e":{"en":"Studies show that 40 to 45 percent of all riders killed in motorcycle crashes had been drinking, making alcohol a leading factor in fatal motorcycle crashes per the Motorcycle Operator Manual.","es":"Los estudios muestran que del 40 al 45 por ciento de todos los conductores muertos en choques de motocicleta habían estado bebiendo, lo que hace del alcohol un factor principal en los choques mortales de motocicleta, según el Manual del Operador de Motocicletas.","ru":"Исследования показывают, что от 40 до 45 процентов всех мотоциклистов, погибших в авариях, употребляли алкоголь, что делает алкоголь ведущим фактором смертельных аварий мотоциклов, согласно Руководству для водителей мотоциклов.","tr":"Çalışmalar, motosiklet kazalarında ölen tüm sürücülerin yüzde 40 ila 45'inin içki içmiş olduğunu göstermektedir; bu da Motosiklet Sürücü Kılavuzu'na göre alkolü ölümcül motosiklet kazalarında önde gelen bir etken yapar.","hi":"अध्ययन दिखाते हैं कि मोटरसाइकिल दुर्घटनाओं में मारे गए सभी सवारों में से 40 से 45 प्रतिशत ने शराब पी रखी थी, जिससे Motorcycle Operator Manual के अनुसार शराब घातक मोटरसाइकिल दुर्घटनाओं में एक प्रमुख कारक बन जाती है।","ar":"تُظهر الدراسات أن 40 إلى 45 بالمئة من جميع السائقين الذين قُتلوا في حوادث الدراجات النارية كانوا قد تناولوا الكحول، مما يجعل الكحول عاملاً رئيسياً في حوادث الدراجات النارية المميتة وفقاً لدليل مشغل الدراجة النارية."}},{"cat":"impairment","a":0,"q":{"en":"Which ability does alcohol begin to impair first, even at low levels well below the legal limit?","es":"¿Qué capacidad empieza a afectar primero el alcohol, incluso en niveles bajos muy por debajo del límite legal?","ru":"Какую способность алкоголь начинает ослаблять в первую очередь, даже при низких уровнях, значительно ниже допустимого предела?","tr":"Yasal sınırın çok altındaki düşük seviyelerde bile alkol önce hangi yeteneği bozmaya başlar?","hi":"शराब किस क्षमता को सबसे पहले बिगाड़ना शुरू करती है, यहाँ तक कि कानूनी सीमा से काफी कम निम्न स्तर पर भी?","ar":"أي قدرة يبدأ الكحول بإضعافها أولاً، حتى عند مستويات منخفضة أقل بكثير من الحد القانوني؟"},"o":[{"en":"Judgment and good sense","es":"El juicio y el buen sentido","ru":"Рассудительность и здравый смысл","tr":"Muhakeme ve sağduyu","hi":"निर्णय और समझदारी","ar":"الحكم والإدراك السليم"},{"en":"Hearing","es":"La audición","ru":"Слух","tr":"İşitme","hi":"सुनना","ar":"السمع"},{"en":"Grip strength","es":"La fuerza de agarre","ru":"Силу хвата","tr":"Kavrama gücü","hi":"पकड़ की ताकत","ar":"قوة القبضة"},{"en":"Sense of smell","es":"El sentido del olfato","ru":"Обоняние","tr":"Koku alma duyusu","hi":"सूँघने की भावना","ar":"حاسة الشم"}],"e":{"en":"Alcohol affects judgment and good sense first, often before any obvious signs appear and before a rider reaches the legal limit, according to the Motorcycle Operator Manual.","es":"El alcohol afecta primero el juicio y el buen sentido, a menudo antes de que aparezca cualquier señal evidente y antes de que un conductor alcance el límite legal, según el Manual del Operador de Motocicletas.","ru":"Алкоголь в первую очередь влияет на рассудительность и здравый смысл, часто до появления каких-либо явных признаков и до того, как мотоциклист достигнет допустимого предела, согласно Руководству для водителей мотоциклов.","tr":"Alkol, Motosiklet Sürücü Kılavuzu'na göre, çoğu zaman herhangi bir belirgin işaret ortaya çıkmadan ve sürücü yasal sınıra ulaşmadan önce, ilk olarak muhakemeyi ve sağduyuyu etkiler.","hi":"शराब सबसे पहले निर्णय और समझदारी को प्रभावित करती है, अक्सर किसी भी स्पष्ट संकेत के प्रकट होने से पहले और सवार के कानूनी सीमा तक पहुँचने से पहले, Motorcycle Operator Manual के अनुसार।","ar":"يؤثر الكحول على الحكم والإدراك السليم أولاً، غالباً قبل ظهور أي علامات واضحة وقبل أن يصل السائق إلى الحد القانوني، وفقاً لدليل مشغل الدراجة النارية."}},{"cat":"impairment","a":3,"q":{"en":"What is the only thing that will actually sober up a person who has been drinking?","es":"¿Qué es lo único que realmente despeja a una persona que ha estado bebiendo?","ru":"Что единственное действительно отрезвит человека, который употреблял алкоголь?","tr":"İçki içmiş bir kişiyi gerçekten ayıltacak tek şey nedir?","hi":"शराब पीने वाले व्यक्ति को वास्तव में होश में लाने वाली एकमात्र चीज़ क्या है?","ar":"ما هو الشيء الوحيد الذي يُفيق فعلاً شخصاً تناول الكحول؟"},"o":[{"en":"Taking a cold shower","es":"Darse una ducha fría","ru":"Холодный душ","tr":"Soğuk duş almak","hi":"ठंडा शॉवर लेना","ar":"أخذ دش بارد"},{"en":"Drinking strong coffee","es":"Tomar café cargado","ru":"Крепкий кофе","tr":"Sert kahve içmek","hi":"कड़क कॉफ़ी पीना","ar":"شرب قهوة قوية"},{"en":"Doing physical exercise","es":"Hacer ejercicio físico","ru":"Физические упражнения","tr":"Fiziksel egzersiz yapmak","hi":"शारीरिक व्यायाम करना","ar":"ممارسة التمارين البدنية"},{"en":"The passage of time","es":"El paso del tiempo","ru":"Прошедшее время","tr":"Zamanın geçmesi","hi":"समय का बीतना","ar":"مرور الوقت"}],"e":{"en":"Only time eliminates alcohol from the body. Coffee, cold showers, and exercise do not speed up the process, says the Motorcycle Operator Manual.","es":"Solo el tiempo elimina el alcohol del cuerpo. El café, las duchas frías y el ejercicio no aceleran el proceso, dice el Manual del Operador de Motocicletas.","ru":"Только время выводит алкоголь из организма. Кофе, холодный душ и упражнения не ускоряют этот процесс, говорит Руководство для водителей мотоциклов.","tr":"Alkolü vücuttan yalnızca zaman temizler. Motosiklet Sürücü Kılavuzu'na göre kahve, soğuk duş ve egzersiz bu süreci hızlandırmaz.","hi":"केवल समय ही शरीर से शराब को खत्म करता है। कॉफ़ी, ठंडे शॉवर और व्यायाम इस प्रक्रिया को तेज़ नहीं करते, Motorcycle Operator Manual कहता है।","ar":"الوقت وحده هو ما يزيل الكحول من الجسم. القهوة والدش البارد والتمارين لا تسرّع العملية، يقول دليل مشغل الدراجة النارية."}},{"cat":"impairment","a":2,"q":{"en":"About how quickly does the body eliminate alcohol?","es":"¿Aproximadamente qué tan rápido elimina el cuerpo el alcohol?","ru":"Примерно с какой скоростью организм выводит алкоголь?","tr":"Vücut alkolü yaklaşık ne kadar hızlı atar?","hi":"शरीर लगभग कितनी जल्दी शराब को खत्म करता है?","ar":"ما هي تقريباً السرعة التي يتخلص بها الجسم من الكحول؟"},"o":[{"en":"About one drink every ten minutes","es":"Cerca de un trago cada diez minutos","ru":"Примерно одна порция каждые десять минут","tr":"Her on dakikada yaklaşık bir içki","hi":"लगभग हर 10 मिनट में एक ड्रिंक","ar":"نحو مشروب واحد كل عشر دقائق"},{"en":"Almost instantly","es":"Casi de inmediato","ru":"Почти мгновенно","tr":"Neredeyse anında","hi":"लगभग तुरंत","ar":"تقريباً فوراً"},{"en":"About one drink per hour","es":"Cerca de un trago por hora","ru":"Примерно одна порция в час","tr":"Saatte yaklaşık bir içki","hi":"लगभग एक ड्रिंक प्रति घंटा","ar":"نحو مشروب واحد في الساعة"},{"en":"About four drinks per hour","es":"Cerca de cuatro tragos por hora","ru":"Примерно четыре порции в час","tr":"Saatte yaklaşık dört içki","hi":"लगभग चार ड्रिंक प्रति घंटा","ar":"نحو أربعة مشروبات في الساعة"}],"e":{"en":"The body eliminates alcohol at a rate of about one drink per hour, so drinking faster than that causes alcohol to accumulate, per the Motorcycle Operator Manual.","es":"El cuerpo elimina el alcohol a una tasa de cerca de un trago por hora, así que beber más rápido que eso hace que el alcohol se acumule, según el Manual del Operador de Motocicletas.","ru":"Организм выводит алкоголь со скоростью примерно одна порция в час, поэтому употребление быстрее этого приводит к накоплению алкоголя, согласно Руководству для водителей мотоциклов.","tr":"Vücut, alkolü saatte yaklaşık bir içki hızında atar, bu yüzden bundan daha hızlı içmek, Motosiklet Sürücü Kılavuzu'na göre alkolün birikmesine neden olur.","hi":"शरीर लगभग एक ड्रिंक प्रति घंटे की दर से शराब को खत्म करता है, इसलिए इससे तेज़ी से पीने पर शराब जमा हो जाती है, Motorcycle Operator Manual के अनुसार।","ar":"يتخلص الجسم من الكحول بمعدل نحو مشروب واحد في الساعة، لذا فإن الشرب بمعدل أسرع من ذلك يجعل الكحول يتراكم، وفقاً لدليل مشغل الدراجة النارية."}},{"cat":"impairment","a":2,"q":{"en":"Besides judgment, which combination of riding skills is most directly impaired by alcohol?","es":"Además del juicio, ¿qué combinación de habilidades de conducción se ve afectada más directamente por el alcohol?","ru":"Помимо рассудительности, какое сочетание навыков езды наиболее напрямую ослабляется алкоголем?","tr":"Muhakemenin yanı sıra, hangi sürüş becerileri kombinasyonu alkolden en doğrudan etkilenir?","hi":"निर्णय के अलावा, सवारी कौशल का कौन सा संयोजन शराब से सबसे सीधे प्रभावित होता है?","ar":"إلى جانب الحكم، أي مجموعة من مهارات القيادة هي الأكثر تأثراً مباشرةً بالكحول؟"},"o":[{"en":"Color vision only","es":"Solo la visión de color","ru":"Только цветовое зрение","tr":"Yalnızca renkli görüş","hi":"केवल रंग दृष्टि","ar":"رؤية الألوان فقط"},{"en":"Memory and appetite","es":"La memoria y el apetito","ru":"Память и аппетит","tr":"Hafıza ve iştah","hi":"स्मृति और भूख","ar":"الذاكرة والشهية"},{"en":"Balance and coordination","es":"El equilibrio y la coordinación","ru":"Равновесие и координация","tr":"Denge ve koordinasyon","hi":"संतुलन और समन्वय","ar":"التوازن والتناسق"},{"en":"Height perception only","es":"Solo la percepción de altura","ru":"Только восприятие высоты","tr":"Yalnızca yükseklik algısı","hi":"केवल ऊँचाई की धारणा","ar":"إدراك الارتفاع فقط"}],"e":{"en":"Alcohol impairs the balance and coordination that motorcycle control depends on, in addition to judgment and vision, according to the Motorcycle Operator Manual.","es":"El alcohol afecta el equilibrio y la coordinación de los que depende el control de la motocicleta, además del juicio y la visión, según el Manual del Operador de Motocicletas.","ru":"Алкоголь ослабляет равновесие и координацию, от которых зависит управление мотоциклом, в дополнение к рассудительности и зрению, согласно Руководству для водителей мотоциклов.","tr":"Alkol, Motosiklet Sürücü Kılavuzu'na göre, muhakeme ve görüşün yanı sıra motosiklet kontrolünün dayandığı denge ve koordinasyonu da bozar.","hi":"शराब उस संतुलन और समन्वय को बिगाड़ती है जिस पर मोटरसाइकिल का नियंत्रण निर्भर करता है, निर्णय और दृष्टि के अलावा, Motorcycle Operator Manual के अनुसार।","ar":"يُضعف الكحول التوازن والتناسق اللذين يعتمد عليهما التحكم في الدراجة النارية، إضافةً إلى الحكم والرؤية، وفقاً لدليل مشغل الدراجة النارية."}},{"cat":"impairment","a":2,"q":{"en":"Which of the following counts as one standard drink for purposes of estimating impairment?","es":"¿Cuál de los siguientes cuenta como un trago estándar para efectos de estimar el deterioro?","ru":"Что из перечисленного считается одной стандартной порцией для целей оценки опьянения?","tr":"Aşağıdakilerden hangisi, bozulmayı tahmin etmek açısından bir standart içki sayılır?","hi":"निम्नलिखित में से कौन सा क्षीणता आँकने के उद्देश्य से एक मानक ड्रिंक के रूप में गिना जाता है?","ar":"أي مما يلي يُحتسب مشروباً قياسياً واحداً لأغراض تقدير الضعف؟"},"o":[{"en":"A pint of liquor","es":"Una pinta de licor","ru":"Пинта крепкого алкоголя","tr":"Bir pint sert içki","hi":"एक पिंट शराब","ar":"نصف لتر من المشروبات الروحية"},{"en":"Three shots of liquor","es":"Tres caballitos de licor","ru":"Три рюмки крепкого алкоголя","tr":"Üç shot sert içki","hi":"तीन शॉट शराब","ar":"ثلاث جرعات من المشروبات الروحية"},{"en":"A 12-ounce can of regular beer","es":"Una lata de 12 onzas de cerveza regular","ru":"Банка обычного пива объёмом 12 унций","tr":"12 onsluk bir kutu normal bira","hi":"12-ounce साधारण बीयर का एक कैन","ar":"علبة بيرة عادية سعة 12 أونصة"},{"en":"A full bottle of wine","es":"Una botella completa de vino","ru":"Полная бутылка вина","tr":"Bir şişe dolusu şarap","hi":"शराब की एक पूरी बोतल","ar":"زجاجة نبيذ كاملة"}],"e":{"en":"A standard drink is a 12-ounce can of beer, a 5-ounce glass of wine, or a mixed drink with one shot of liquor, notes the Motorcycle Operator Manual.","es":"Un trago estándar es una lata de 12 onzas de cerveza, una copa de 5 onzas de vino o un trago mezclado con un caballito de licor, señala el Manual del Operador de Motocicletas.","ru":"Стандартная порция — это банка пива объёмом 12 унций, бокал вина объёмом 5 унций или смешанный напиток с одной рюмкой крепкого алкоголя, отмечает Руководство для водителей мотоциклов.","tr":"Motosiklet Sürücü Kılavuzu'na göre bir standart içki, 12 onsluk bir kutu bira, 5 onsluk bir kadeh şarap veya bir shot sert içki içeren bir kokteyldir.","hi":"एक मानक ड्रिंक 12-ounce बीयर का कैन, 5-ounce वाइन का गिलास, या एक शॉट शराब वाला मिश्रित पेय होता है, Motorcycle Operator Manual बताता है।","ar":"المشروب القياسي هو علبة بيرة سعة 12 أونصة، أو كأس نبيذ سعة 5 أونصات، أو مشروب ممزوج بجرعة واحدة من المشروبات الروحية، يشير دليل مشغل الدراجة النارية."}},{"cat":"impairment","a":0,"q":{"en":"A friend has had several drinks and wants to ride home. What is the best way to help, according to the manual?","es":"Un amigo ha tomado varios tragos y quiere irse conduciendo a casa. ¿Cuál es la mejor manera de ayudar, según el manual?","ru":"Ваш друг выпил несколько порций и хочет ехать домой. Как, согласно Руководству, лучше всего помочь?","tr":"Bir arkadaşınız birkaç içki içti ve eve gitmek üzere sürmek istiyor. Kılavuza göre yardım etmenin en iyi yolu nedir?","hi":"एक दोस्त ने कई ड्रिंक पी ली हैं और घर तक बाइक चलाना चाहता है। मैनुअल के अनुसार मदद करने का सबसे अच्छा तरीका क्या है?","ar":"تناول صديق عدة مشروبات ويريد القيادة إلى المنزل. ما هي أفضل طريقة للمساعدة، وفقاً للدليل؟"},"o":[{"en":"Arrange a safe ride home for them","es":"Conseguirle un viaje seguro a casa","ru":"Организовать ему безопасную доставку домой","tr":"Onlar için eve güvenli bir ulaşım ayarlamak","hi":"उनके लिए घर तक सुरक्षित सवारी की व्यवस्था करें","ar":"رتّب له وسيلة آمنة للعودة إلى المنزل"},{"en":"Have them ride slowly behind the group","es":"Hacer que conduzca despacio detrás del grupo","ru":"Пусть едет медленно позади группы","tr":"Grubun arkasında yavaşça sürmelerini sağlamak","hi":"उन्हें समूह के पीछे धीरे-धीरे चलने दें","ar":"اجعله يقود ببطء خلف المجموعة"},{"en":"Give them coffee and let them go","es":"Darle café y dejarlo ir","ru":"Дать ему кофе и отпустить","tr":"Onlara kahve verip gitmelerine izin vermek","hi":"उन्हें कॉफ़ी दें और जाने दें","ar":"أعطه قهوة ودعه يذهب"},{"en":"Let them ride if they feel fine","es":"Dejarlo conducir si se siente bien","ru":"Позволить ему ехать, если он чувствует себя нормально","tr":"İyi hissediyorlarsa sürmelerine izin vermek","hi":"अगर वे ठीक महसूस करें तो उन्हें बाइक चलाने दें","ar":"دعه يقود إذا شعر أنه بخير"}],"e":{"en":"Arranging a safe ride home, such as a sober driver or a place to stay, keeps an impaired rider off the bike. The Motorcycle Operator Manual lists this as a key intervention.","es":"Conseguir un viaje seguro a casa, como un conductor sobrio o un lugar para quedarse, mantiene a un conductor afectado fuera de la moto. El Manual del Operador de Motocicletas menciona esto como una intervención clave.","ru":"Организация безопасной доставки домой, например с трезвым водителем или с местом для ночлега, не даёт нетрезвому мотоциклисту сесть за руль. Руководство для водителей мотоциклов перечисляет это как ключевое вмешательство.","tr":"Ayık bir sürücü veya kalacak bir yer gibi eve güvenli bir ulaşım ayarlamak, bozulmuş bir sürücüyü motosikletten uzak tutar. Motosiklet Sürücü Kılavuzu bunu önemli bir müdahale olarak sıralar.","hi":"घर तक सुरक्षित सवारी की व्यवस्था करना, जैसे कोई शांत चालक या रुकने की जगह, क्षीण सवार को बाइक से दूर रखता है। Motorcycle Operator Manual इसे एक प्रमुख हस्तक्षेप के रूप में सूचीबद्ध करता है।","ar":"ترتيب وسيلة آمنة للعودة إلى المنزل، مثل سائق غير ثمل أو مكان للمبيت، يُبقي السائق المتأثر بعيداً عن الدراجة. يدرج دليل مشغل الدراجة النارية هذا كتدخّل رئيسي."}},{"cat":"impairment","a":1,"q":{"en":"Which group strategy can help keep a friend from drinking too much to ride at a gathering?","es":"¿Qué estrategia de grupo puede ayudar a evitar que un amigo beba demasiado para conducir en una reunión?","ru":"Какая групповая стратегия может помочь не дать другу выпить слишком много, чтобы ехать, на мероприятии?","tr":"Bir buluşmada bir arkadaşın sürmek için çok fazla içmesini önlemeye hangi grup stratejisi yardımcı olabilir?","hi":"कौन सी समूह रणनीति किसी समारोह में किसी दोस्त को बाइक चलाने के लिए बहुत अधिक पीने से रोकने में मदद कर सकती है?","ar":"أي استراتيجية جماعية يمكن أن تساعد في منع صديق من الإفراط في الشرب بحيث لا يستطيع القيادة في تجمّع؟"},"o":[{"en":"Ignore how much they drink","es":"Ignorar cuánto bebe","ru":"Игнорировать, сколько он пьёт","tr":"Ne kadar içtiklerini görmezden gelin","hi":"वे कितना पीते हैं इसे अनदेखा करें","ar":"تجاهل كمية ما يشربه"},{"en":"Slow the pace of drinking","es":"Hacer más lento el ritmo de la bebida","ru":"Замедлить темп употребления","tr":"İçki temposunu yavaşlatın","hi":"पीने की गति धीमी करें","ar":"إبطاء وتيرة الشرب"},{"en":"Switch them to stronger drinks","es":"Cambiarlo a tragos más fuertes","ru":"Перевести его на более крепкие напитки","tr":"Onları daha sert içkilere geçirin","hi":"उन्हें तेज़ ड्रिंक पर शिफ्ट करें","ar":"تحويله إلى مشروبات أقوى"},{"en":"Buy rounds faster","es":"Comprar rondas más rápido","ru":"Покупать раунды быстрее","tr":"Daha hızlı sıra ısmarlayın","hi":"तेज़ी से राउंड खरीदें","ar":"شراء جولات بوتيرة أسرع"}],"e":{"en":"Slowing the pace of drinking, by involving the person in other activities and encouraging food and non-alcoholic drinks, reduces impairment, per the Motorcycle Operator Manual.","es":"Hacer más lento el ritmo de la bebida, involucrando a la persona en otras actividades y animándola a comer y a tomar bebidas sin alcohol, reduce el deterioro, según el Manual del Operador de Motocicletas.","ru":"Замедление темпа употребления путём вовлечения человека в другие занятия и поощрения еды и безалкогольных напитков снижает опьянение, согласно Руководству для водителей мотоциклов.","tr":"Kişiyi başka etkinliklere dahil ederek ve yemek ile alkolsüz içecekleri teşvik ederek içki temposunu yavaşlatmak, Motosiklet Sürücü Kılavuzu'na göre bozulmayı azaltır.","hi":"पीने की गति धीमी करना, व्यक्ति को अन्य गतिविधियों में शामिल करके और भोजन व ग़ैर-शराबी पेय को प्रोत्साहित करके, क्षीणता को कम करता है, Motorcycle Operator Manual के अनुसार।","ar":"إبطاء وتيرة الشرب، بإشراك الشخص في أنشطة أخرى وتشجيع تناول الطعام والمشروبات غير الكحولية، يقلل الضعف، وفقاً لدليل مشغل الدراجة النارية."}},{"cat":"impairment","a":2,"q":{"en":"A riding buddy is clearly impaired but insists on leaving. What does the manual suggest the group do?","es":"Un compañero de viaje está claramente afectado pero insiste en irse. ¿Qué sugiere el manual que haga el grupo?","ru":"Товарищ по поездке явно нетрезв, но настаивает на отъезде. Что Руководство предлагает сделать группе?","tr":"Bir sürüş arkadaşı açıkça bozulmuş ama ayrılmakta ısrar ediyor. Kılavuz grubun ne yapmasını önerir?","hi":"एक सवारी साथी स्पष्ट रूप से क्षीण है लेकिन जाने पर अड़ा है। मैनुअल समूह को क्या करने का सुझाव देता है?","ar":"رفيق ركوب متأثر بوضوح لكنه يصرّ على المغادرة. بماذا يقترح الدليل أن تفعل المجموعة؟"},"o":[{"en":"Let one person argue alone","es":"Dejar que una sola persona discuta a solas","ru":"Пусть один человек спорит в одиночку","tr":"Bir kişinin tek başına tartışmasına izin verin","hi":"एक व्यक्ति को अकेले बहस करने दें","ar":"دع شخصاً واحداً يجادل بمفرده"},{"en":"Race ahead so they keep up","es":"Adelantarse para que él siga el ritmo","ru":"Мчаться вперёд, чтобы он не отставал","tr":"Onlar yetişsin diye öne fırlayın","hi":"आगे दौड़ें ताकि वे साथ चलते रहें","ar":"تسابق إلى الأمام حتى يواكب"},{"en":"Get other friends involved to intervene","es":"Involucrar a otros amigos para intervenir","ru":"Привлечь других друзей для вмешательства","tr":"Müdahale etmek için diğer arkadaşları da işin içine katın","hi":"हस्तक्षेप के लिए अन्य दोस्तों को शामिल करें","ar":"أشرك أصدقاء آخرين للتدخل"},{"en":"Take away only their helmet","es":"Quitarle solo el casco","ru":"Забрать только его шлем","tr":"Yalnızca kasklarını alın","hi":"केवल उनका हेलमेट ले लें","ar":"خذ خوذته فقط"}],"e":{"en":"Getting friends involved increases the social pressure to make the safe choice; a group is harder to ignore than one person. The Motorcycle Operator Manual recommends this.","es":"Involucrar a los amigos aumenta la presión social para tomar la decisión segura; es más difícil ignorar a un grupo que a una sola persona. El Manual del Operador de Motocicletas recomienda esto.","ru":"Привлечение друзей усиливает социальное давление в пользу безопасного выбора; группу труднее проигнорировать, чем одного человека. Руководство для водителей мотоциклов рекомендует это.","tr":"Arkadaşları işin içine katmak, güvenli seçimi yapma yönündeki sosyal baskıyı artırır; bir grubu görmezden gelmek tek bir kişiyi görmezden gelmekten daha zordur. Motosiklet Sürücü Kılavuzu bunu önerir.","hi":"दोस्तों को शामिल करना सुरक्षित विकल्प चुनने के लिए सामाजिक दबाव बढ़ाता है; एक समूह को नज़रअंदाज़ करना एक व्यक्ति की तुलना में कठिन होता है। Motorcycle Operator Manual इसकी सिफ़ारिश करता है।","ar":"إشراك الأصدقاء يزيد الضغط الاجتماعي لاتخاذ الخيار الآمن؛ فمن الأصعب تجاهل مجموعة من تجاهل شخص واحد. يوصي دليل مشغل الدراجة النارية بهذا."}},{"cat":"impairment","a":3,"q":{"en":"If you cannot stop an impaired friend from leaving immediately, what is another reasonable step?","es":"Si no puedes evitar que un amigo afectado se vaya de inmediato, ¿cuál es otro paso razonable?","ru":"Если вы не можете сразу остановить нетрезвого друга от отъезда, какой ещё разумный шаг можно предпринять?","tr":"Bozulmuş bir arkadaşınızın hemen ayrılmasını engelleyemezseniz, makul bir başka adım nedir?","hi":"अगर आप किसी क्षीण दोस्त को तुरंत जाने से नहीं रोक सकते, तो एक और उचित कदम क्या है?","ar":"إذا لم تستطع منع صديق متأثر من المغادرة فوراً، ما هي خطوة معقولة أخرى؟"},"o":[{"en":"Pour them one more drink","es":"Servirle un trago más","ru":"Налить ему ещё одну порцию","tr":"Onlara bir içki daha doldurun","hi":"उन्हें एक और ड्रिंक डालकर दें","ar":"اسكب له مشروباً آخر"},{"en":"Remove their mirrors","es":"Quitarle los espejos","ru":"Снять его зеркала","tr":"Aynalarını çıkarın","hi":"उनके मिरर हटा दें","ar":"أزل مراياه"},{"en":"Tell them to ride faster to get home sooner","es":"Decirle que conduzca más rápido para llegar antes a casa","ru":"Сказать ему ехать быстрее, чтобы скорее добраться домой","tr":"Eve daha çabuk varmaları için daha hızlı sürmelerini söyleyin","hi":"उन्हें जल्दी घर पहुँचने के लिए तेज़ चलने को कहें","ar":"اطلب منه القيادة أسرع للوصول إلى المنزل في وقت أقرب"},{"en":"Find a way to keep them there until they sober up","es":"Encontrar la manera de retenerlo ahí hasta que se le pase el efecto","ru":"Найти способ удержать его на месте, пока он не протрезвеет","tr":"Ayılana kadar onları orada tutmanın bir yolunu bulun","hi":"उन्हें होश में आने तक वहाँ रोके रखने का कोई तरीका खोजें","ar":"جِد طريقة لإبقائه هناك حتى يفيق"}],"e":{"en":"Keeping the person there, by slowing things down or offering food and a place to rest, buys time for the alcohol to wear off, says the Motorcycle Operator Manual.","es":"Retener a la persona ahí, haciendo más lentas las cosas u ofreciéndole comida y un lugar para descansar, da tiempo para que el efecto del alcohol disminuya, dice el Manual del Operador de Motocicletas.","ru":"Удержание человека на месте путём замедления событий или предложения еды и места для отдыха выигрывает время для выведения алкоголя, говорит Руководство для водителей мотоциклов.","tr":"İşleri yavaşlatarak veya yemek ve dinlenecek bir yer sunarak kişiyi orada tutmak, Motosiklet Sürücü Kılavuzu'na göre alkolün etkisinin geçmesi için zaman kazandırır.","hi":"व्यक्ति को वहीं रोके रखना, चीज़ों को धीमा करके या भोजन व आराम की जगह देकर, शराब का असर कम होने के लिए समय देता है, Motorcycle Operator Manual कहता है।","ar":"إبقاء الشخص هناك، بإبطاء الأمور أو تقديم الطعام ومكان للراحة، يكسب وقتاً حتى يزول مفعول الكحول، يقول دليل مشغل الدراجة النارية."}},{"cat":"impairment","a":2,"q":{"en":"How does fatigue affect a motorcycle rider?","es":"¿Cómo afecta la fatiga a un motociclista?","ru":"Как усталость влияет на водителя мотоцикла?","tr":"Yorgunluk bir motosiklet sürücüsünü nasıl etkiler?","hi":"थकान मोटरसाइकिल सवार को कैसे प्रभावित करती है?","ar":"كيف يؤثر التعب على سائق الدراجة النارية؟"},"o":[{"en":"It has no real effect on a short trip","es":"No tiene un efecto real en un viaje corto","ru":"Она не оказывает реального влияния в короткой поездке","tr":"Kısa bir yolculukta gerçek bir etkisi yoktur","hi":"छोटी यात्रा पर इसका कोई वास्तविक प्रभाव नहीं होता","ar":"ليس له تأثير حقيقي في رحلة قصيرة"},{"en":"It sharpens reaction time","es":"Agudiza el tiempo de reacción","ru":"Она обостряет время реакции","tr":"Tepki süresini keskinleştirir","hi":"यह प्रतिक्रिया समय को तेज़ करती है","ar":"يُحدّ من زمن رد الفعل"},{"en":"It slows reactions and impairs judgment like alcohol","es":"Hace más lentas las reacciones y afecta el juicio, como el alcohol","ru":"Она замедляет реакции и ослабляет рассудительность подобно алкоголю","tr":"Tepkileri yavaşlatır ve muhakemeyi tıpkı alkol gibi bozar","hi":"यह शराब की तरह प्रतिक्रियाओं को धीमा करती है और निर्णय बिगाड़ती है","ar":"يُبطئ ردود الفعل ويُضعف الحكم مثل الكحول"},{"en":"It only affects vision at night","es":"Solo afecta la visión de noche","ru":"Она влияет только на зрение ночью","tr":"Yalnızca gece görüşü etkiler","hi":"यह केवल रात में दृष्टि को प्रभावित करती है","ar":"يؤثر فقط على الرؤية ليلاً"}],"e":{"en":"Fatigue, like alcohol, slows reactions and impairs judgment and concentration. The Motorcycle Operator Manual stresses protecting yourself against it on long rides.","es":"La fatiga, al igual que el alcohol, hace más lentas las reacciones y afecta el juicio y la concentración. El Manual del Operador de Motocicletas resalta protegerte contra ella en los recorridos largos.","ru":"Усталость, как и алкоголь, замедляет реакции и ослабляет рассудительность и концентрацию. Руководство для водителей мотоциклов подчёркивает важность защиты от неё в длительных поездках.","tr":"Yorgunluk, tıpkı alkol gibi tepkileri yavaşlatır ve muhakeme ile konsantrasyonu bozar. Motosiklet Sürücü Kılavuzu, uzun sürüşlerde kendinizi buna karşı korumanın önemini vurgular.","hi":"थकान, शराब की तरह, प्रतिक्रियाओं को धीमा करती है और निर्णय व एकाग्रता को बिगाड़ती है। Motorcycle Operator Manual लंबी सवारियों पर इससे खुद को बचाने पर ज़ोर देता है।","ar":"التعب، مثل الكحول، يُبطئ ردود الفعل ويُضعف الحكم والتركيز. يشدد دليل مشغل الدراجة النارية على حماية نفسك منه في الرحلات الطويلة."}},{"cat":"impairment","a":3,"q":{"en":"Which is a good way to protect yourself against fatigue on a long ride?","es":"¿Cuál es una buena manera de protegerte contra la fatiga en un recorrido largo?","ru":"Что является хорошим способом защититься от усталости в длительной поездке?","tr":"Uzun bir sürüşte kendinizi yorgunluğa karşı korumanın iyi bir yolu nedir?","hi":"लंबी सवारी पर थकान से खुद को बचाने का एक अच्छा तरीका कौन सा है?","ar":"ما هي الطريقة الجيدة لحماية نفسك من التعب في رحلة طويلة؟"},"o":[{"en":"Skip meals to stay alert","es":"Saltarte las comidas para mantenerte alerta","ru":"Пропускать приёмы пищи, чтобы оставаться бодрым","tr":"Uyanık kalmak için öğünleri atlayın","hi":"सतर्क रहने के लिए भोजन छोड़ दें","ar":"تخطّ الوجبات للبقاء يقظاً"},{"en":"Ride straight through without stopping","es":"Conducir de corrido sin detenerte","ru":"Ехать без остановок до конца","tr":"Hiç durmadan baştan sona sürün","hi":"बिना रुके सीधे चलते रहें","ar":"قُد دون توقف حتى النهاية"},{"en":"Wear heavier dark clothing","es":"Usar ropa oscura más pesada","ru":"Носить более тяжёлую тёмную одежду","tr":"Daha ağır koyu kıyafetler giyin","hi":"भारी गहरे रंग के कपड़े पहनें","ar":"ارتدِ ملابس داكنة أثقل"},{"en":"Limit your distance and take frequent rest breaks","es":"Limitar tu distancia y tomar descansos frecuentes","ru":"Ограничивать дистанцию и делать частые перерывы на отдых","tr":"Mesafenizi sınırlayın ve sık sık dinlenme molaları verin","hi":"अपनी दूरी सीमित करें और बार-बार आराम के ब्रेक लें","ar":"حُدّ من مسافتك وخذ فترات راحة متكررة"}],"e":{"en":"Limiting distance, taking frequent breaks, dressing to stay protected from the elements, and avoiding alcohol all help fight fatigue, per the Motorcycle Operator Manual.","es":"Limitar la distancia, tomar descansos frecuentes, vestirte para protegerte de los elementos y evitar el alcohol ayudan a combatir la fatiga, según el Manual del Operador de Motocicletas.","ru":"Ограничение дистанции, частые перерывы, одежда, защищающая от стихии, и отказ от алкоголя — всё это помогает бороться с усталостью, согласно Руководству для водителей мотоциклов.","tr":"Mesafeyi sınırlamak, sık molalar vermek, hava koşullarından korunmak için giyinmek ve alkolden kaçınmak, Motosiklet Sürücü Kılavuzu'na göre yorgunlukla mücadeleye yardımcı olur.","hi":"दूरी सीमित करना, बार-बार ब्रेक लेना, मौसम से बचाव के लिए कपड़े पहनना और शराब से बचना सभी थकान से लड़ने में मदद करते हैं, Motorcycle Operator Manual के अनुसार।","ar":"الحد من المسافة، وأخذ فترات راحة متكررة، والملبس الذي يحميك من العوامل الجوية، وتجنّب الكحول، كلها تساعد على مكافحة التعب، وفقاً لدليل مشغل الدراجة النارية."}},{"cat":"impairment","a":1,"q":{"en":"How much of the lane is a motorcycle entitled to use?","es":"¿Cuánto del carril tiene derecho a usar una motocicleta?","ru":"Какую часть полосы мотоцикл имеет право использовать?","tr":"Bir motosiklet şeritin ne kadarını kullanma hakkına sahiptir?","hi":"एक मोटरसाइकिल लेन का कितना हिस्सा उपयोग करने की हकदार है?","ar":"ما مقدار المسار الذي يحق للدراجة النارية استخدامه؟"},"o":[{"en":"Half the lane so a car can share it","es":"La mitad del carril para que un auto pueda compartirlo","ru":"Половину полосы, чтобы автомобиль мог делить её с ним","tr":"Bir arabanın paylaşabilmesi için şeritin yarısı","hi":"आधी लेन ताकि एक कार साझा कर सके","ar":"نصف المسار حتى تتمكن سيارة من مشاركته"},{"en":"The full width of the lane","es":"El ancho completo del carril","ru":"Полную ширину полосы","tr":"Şeritin tüm genişliği","hi":"लेन की पूरी चौड़ाई","ar":"العرض الكامل للمسار"},{"en":"Only the right third","es":"Solo el tercio derecho","ru":"Только правую треть","tr":"Yalnızca sağ üçte biri","hi":"केवल दायाँ तिहाई","ar":"الثلث الأيمن فقط"},{"en":"Only the center stripe area","es":"Solo el área de la raya central","ru":"Только зону центральной полосы","tr":"Yalnızca orta şerit bölgesi","hi":"केवल केंद्र पट्टी का क्षेत्र","ar":"منطقة الخط الأوسط فقط"}],"e":{"en":"A motorcycle is entitled to the full width of a lane. It needs the whole lane to maneuver and respond to hazards, according to the Motorcycle Operator Manual.","es":"Una motocicleta tiene derecho al ancho completo de un carril. Necesita todo el carril para maniobrar y responder ante los peligros, según el Manual del Operador de Motocicletas.","ru":"Мотоцикл имеет право на полную ширину полосы. Ему нужна вся полоса для манёвра и реагирования на опасности, согласно Руководству для водителей мотоциклов.","tr":"Bir motosiklet, şeritin tüm genişliğini kullanma hakkına sahiptir. Motosiklet Sürücü Kılavuzu'na göre manevra yapmak ve tehlikelere tepki vermek için tüm şerite ihtiyaç duyar.","hi":"एक मोटरसाइकिल लेन की पूरी चौड़ाई की हकदार है। इसे चलने-फिरने और खतरों पर प्रतिक्रिया करने के लिए पूरी लेन चाहिए, Motorcycle Operator Manual के अनुसार।","ar":"يحق للدراجة النارية استخدام العرض الكامل للمسار. فهي تحتاج إلى المسار بأكمله للمناورة والاستجابة للمخاطر، وفقاً لدليل مشغل الدراجة النارية."}},{"cat":"impairment","a":0,"q":{"en":"Why should you not ride side-by-side in the same lane next to a car?","es":"¿Por qué no debes conducir lado a lado en el mismo carril junto a un auto?","ru":"Почему не следует ехать бок о бок в одной полосе рядом с автомобилем?","tr":"Bir arabanın yanında aynı şeritte yan yana neden sürmemelisiniz?","hi":"आपको किसी कार के बगल में एक ही लेन में अगल-बगल क्यों नहीं चलना चाहिए?","ar":"لماذا ينبغي ألا تركب جنباً إلى جنب في نفس المسار بجوار سيارة؟"},"o":[{"en":"A car and a motorcycle each need a full lane to operate safely","es":"Un auto y una motocicleta necesitan cada uno un carril completo para operar de forma segura","ru":"Автомобилю и мотоциклу каждому нужна полная полоса для безопасного движения","tr":"Bir araba ve bir motosikletin her biri güvenli çalışmak için tam bir şerite ihtiyaç duyar","hi":"सुरक्षित रूप से चलने के लिए कार और मोटरसाइकिल को एक-एक पूरी लेन चाहिए","ar":"تحتاج كل من السيارة والدراجة النارية إلى مسار كامل للعمل بأمان"},{"en":"It is required only on highways","es":"Solo es obligatorio en las autopistas","ru":"Это требуется только на шоссе","tr":"Yalnızca otoyollarda gereklidir","hi":"यह केवल राजमार्गों पर आवश्यक है","ar":"إنه مطلوب فقط على الطرق السريعة"},{"en":"It is faster for both vehicles","es":"Es más rápido para ambos vehículos","ru":"Это быстрее для обоих транспортных средств","tr":"Her iki araç için de daha hızlıdır","hi":"यह दोनों वाहनों के लिए तेज़ है","ar":"إنه أسرع لكلتا المركبتين"},{"en":"Cars cannot see motorcycles behind them","es":"Los autos no pueden ver a las motocicletas detrás de ellos","ru":"Автомобили не видят мотоциклы позади себя","tr":"Arabalar arkalarındaki motosikletleri göremez","hi":"कारें अपने पीछे की मोटरसाइकिलों को नहीं देख सकतीं","ar":"لا تستطيع السيارات رؤية الدراجات النارية خلفها"}],"e":{"en":"Cars and motorcycles each need a full lane; sharing one side-by-side leaves no room to maneuver and the driver may move over. The Motorcycle Operator Manual warns against it.","es":"Los autos y las motocicletas necesitan cada uno un carril completo; compartir uno lado a lado no deja espacio para maniobrar y el conductor podría moverse hacia ti. El Manual del Operador de Motocicletas advierte contra esto.","ru":"Автомобилям и мотоциклам каждому нужна полная полоса; совместное использование одной полосы бок о бок не оставляет места для манёвра, и водитель может перестроиться. Руководство для водителей мотоциклов предостерегает от этого.","tr":"Arabalar ve motosikletlerin her biri tam bir şerite ihtiyaç duyar; bir şeriti yan yana paylaşmak manevra için yer bırakmaz ve sürücü size doğru kayabilir. Motosiklet Sürücü Kılavuzu buna karşı uyarır.","hi":"कारों और मोटरसाइकिलों को एक-एक पूरी लेन चाहिए; एक को अगल-बगल साझा करने पर चलने-फिरने की कोई जगह नहीं बचती और चालक इधर आ सकता है। Motorcycle Operator Manual इसके खिलाफ़ चेतावनी देता है।","ar":"تحتاج السيارات والدراجات النارية كل منها إلى مسار كامل؛ فمشاركة مسار واحد جنباً إلى جنب لا تترك مجالاً للمناورة وقد ينتقل السائق نحوك. يحذر دليل مشغل الدراجة النارية من ذلك."}},{"cat":"impairment","a":0,"q":{"en":"What does the manual say about lane splitting, riding between rows of stopped or moving cars?","es":"¿Qué dice el manual sobre la circulación entre carriles (lane splitting), conducir entre filas de autos detenidos o en movimiento?","ru":"Что Руководство говорит о езде между рядами, то есть движении между рядами стоящих или движущихся автомобилей?","tr":"Kılavuz, şerit ayırma (lane splitting), yani durmuş veya hareket halindeki araba sıraları arasında sürme hakkında ne der?","hi":"लेन स्प्लिटिंग, यानी रुकी हुई या चलती कारों की कतारों के बीच चलने, के बारे में मैनुअल क्या कहता है?","ar":"ماذا يقول الدليل عن شق المسار، أي القيادة بين صفوف السيارات المتوقفة أو المتحركة؟"},"o":[{"en":"Its legality varies by state and it can be dangerous","es":"Su legalidad varía según el estado y puede ser peligrosa","ru":"Её законность зависит от штата, и она может быть опасной","tr":"Yasallığı eyalete göre değişir ve tehlikeli olabilir","hi":"इसकी वैधता राज्य के अनुसार बदलती है और यह खतरनाक हो सकता है","ar":"تتفاوت قانونيته حسب الولاية ويمكن أن يكون خطراً"},{"en":"It is required in heavy traffic","es":"Es obligatoria en tráfico pesado","ru":"Она обязательна в плотном потоке","tr":"Yoğun trafikte zorunludur","hi":"भारी ट्रैफ़िक में यह आवश्यक है","ar":"إنه مطلوب في حركة المرور الكثيفة"},{"en":"It is the safest place to ride","es":"Es el lugar más seguro para conducir","ru":"Это самое безопасное место для езды","tr":"Sürmek için en güvenli yerdir","hi":"यह चलने के लिए सबसे सुरक्षित जगह है","ar":"إنه أكثر مكان آمن للقيادة"},{"en":"It is always legal nationwide","es":"Siempre es legal en todo el país","ru":"Она всегда законна по всей стране","tr":"Ülke genelinde her zaman yasaldır","hi":"यह देशभर में हमेशा वैध है","ar":"إنه قانوني دائماً على مستوى البلاد"}],"e":{"en":"Lane splitting is illegal in most states and its legality varies; it leaves no space cushion and is hazardous, says the Motorcycle Operator Manual.","es":"La circulación entre carriles es ilegal en la mayoría de los estados y su legalidad varía; no deja colchón de espacio y es peligrosa, dice el Manual del Operador de Motocicletas.","ru":"Езда между рядами незаконна в большинстве штатов, и её законность различается; она не оставляет запаса пространства и опасна, говорит Руководство для водителей мотоциклов.","tr":"Şerit ayırma çoğu eyalette yasa dışıdır ve yasallığı değişir; tampon boşluğu bırakmaz ve tehlikelidir, der Motosiklet Sürücü Kılavuzu.","hi":"लेन स्प्लिटिंग अधिकांश राज्यों में अवैध है और इसकी वैधता बदलती रहती है; यह कोई स्पेस कुशन नहीं छोड़ता और खतरनाक है, Motorcycle Operator Manual कहता है।","ar":"شق المسار غير قانوني في معظم الولايات وتتفاوت قانونيته؛ وهو لا يترك مسافة أمان وخطر، يقول دليل مشغل الدراجة النارية."}},{"cat":"impairment","a":1,"q":{"en":"When riding near a large truck or bus, what should you keep in mind about its blind spots?","es":"Al conducir cerca de un camión o autobús grande, ¿qué debes tener en cuenta sobre sus puntos ciegos?","ru":"При езде рядом с большим грузовиком или автобусом что следует помнить о его слепых зонах?","tr":"Büyük bir kamyon veya otobüsün yakınında sürerken, kör noktaları hakkında neyi akılda tutmalısınız?","hi":"किसी बड़े ट्रक या बस के पास चलते समय, आपको इसके ब्लाइंड स्पॉट के बारे में क्या ध्यान रखना चाहिए?","ar":"عند القيادة بالقرب من شاحنة أو حافلة كبيرة، ماذا ينبغي أن تضع في اعتبارك بشأن نقاطها العمياء؟"},"o":[{"en":"Large vehicles have no blind spots","es":"Los vehículos grandes no tienen puntos ciegos","ru":"У больших транспортных средств нет слепых зон","tr":"Büyük araçların kör noktası yoktur","hi":"बड़े वाहनों के कोई ब्लाइंड स्पॉट नहीं होते","ar":"ليس للمركبات الكبيرة نقاط عمياء"},{"en":"They have big blind spots, so avoid lingering alongside","es":"Tienen puntos ciegos grandes, así que evita quedarte a su costado","ru":"У них большие слепые зоны, поэтому не задерживайтесь рядом с ними","tr":"Büyük kör noktaları vardır, bu yüzden yanlarında oyalanmaktan kaçının","hi":"उनके बड़े ब्लाइंड स्पॉट होते हैं, इसलिए बगल में रुके रहने से बचें","ar":"لها نقاط عمياء كبيرة، لذا تجنّب البقاء بجانبها"},{"en":"Their mirrors show everything behind them","es":"Sus espejos muestran todo lo que hay detrás de ellos","ru":"Их зеркала показывают всё, что находится позади них","tr":"Aynaları arkalarındaki her şeyi gösterir","hi":"उनके मिरर पीछे का सब कुछ दिखाते हैं","ar":"مراياها تُظهر كل شيء خلفها"},{"en":"Only the front has a blind spot","es":"Solo el frente tiene un punto ciego","ru":"Слепая зона есть только спереди","tr":"Yalnızca ön tarafın bir kör noktası vardır","hi":"केवल सामने एक ब्लाइंड स्पॉट होता है","ar":"الجزء الأمامي فقط له نقطة عمياء"}],"e":{"en":"Large vehicles have big blind spots; if you cannot see the driver in the mirror, the driver cannot see you, so do not linger alongside, per the Motorcycle Operator Manual.","es":"Los vehículos grandes tienen puntos ciegos grandes; si no puedes ver al conductor en el espejo, el conductor no puede verte a ti, así que no te quedes a su costado, según el Manual del Operador de Motocicletas.","ru":"У больших транспортных средств большие слепые зоны; если вы не видите водителя в зеркале, водитель не видит вас, поэтому не задерживайтесь рядом, согласно Руководству для водителей мотоциклов.","tr":"Büyük araçların büyük kör noktaları vardır; sürücüyü aynada göremiyorsanız, sürücü de sizi göremez, bu yüzden yanlarında oyalanmayın, Motosiklet Sürücü Kılavuzu'na göre.","hi":"बड़े वाहनों के बड़े ब्लाइंड स्पॉट होते हैं; अगर आप मिरर में चालक को नहीं देख सकते, तो चालक आपको नहीं देख सकता, इसलिए बगल में रुके न रहें, Motorcycle Operator Manual के अनुसार।","ar":"للمركبات الكبيرة نقاط عمياء كبيرة؛ إذا لم تستطع رؤية السائق في المرآة، فلا يستطيع السائق رؤيتك، لذا لا تبقَ بجانبها، وفقاً لدليل مشغل الدراجة النارية."}},{"cat":"impairment","a":2,"q":{"en":"You find yourself riding alongside another vehicle in the next lane. What is the safer choice?","es":"Te encuentras conduciendo junto a otro vehículo en el carril contiguo. ¿Cuál es la opción más segura?","ru":"Вы обнаруживаете, что едете рядом с другим транспортным средством в соседней полосе. Какой выбор безопаснее?","tr":"Kendinizi bir sonraki şeritte başka bir aracın yanında sürerken buluyorsunuz. Daha güvenli seçim hangisidir?","hi":"आप खुद को अगली लेन में किसी अन्य वाहन के बगल में चलते हुए पाते हैं। अधिक सुरक्षित विकल्प क्या है?","ar":"تجد نفسك تقود بجانب مركبة أخرى في المسار المجاور. ما هو الخيار الأكثر أماناً؟"},"o":[{"en":"Stay even with it so it can see you","es":"Quedarte a la par de él para que pueda verte","ru":"Держаться вровень с ним, чтобы оно могло вас видеть","tr":"Sizi görebilmesi için onunla aynı hizada kalın","hi":"इसके बराबर बने रहें ताकि यह आपको देख सके","ar":"ابقَ محاذياً لها حتى تتمكن من رؤيتك"},{"en":"Match its exact speed indefinitely","es":"Igualar su velocidad exacta de forma indefinida","ru":"Постоянно подстраиваться под его точную скорость","tr":"Tam hızına süresiz olarak uyun","hi":"अनिश्चित काल तक इसकी ठीक गति से मिलाएँ","ar":"اضبط سرعتك تماماً على سرعتها إلى ما لا نهاية"},{"en":"Speed up or drop back out of the blind spot","es":"Acelerar o quedarte atrás para salir del punto ciego","ru":"Ускориться или отстать, выйдя из слепой зоны","tr":"Hızlanın veya kör noktadan geriye düşün","hi":"गति बढ़ाएँ या ब्लाइंड स्पॉट से पीछे हट जाएँ","ar":"تسارع أو تراجع للخروج من النقطة العمياء"},{"en":"Move onto the lane line","es":"Colocarte sobre la línea del carril","ru":"Перестроиться на разделительную линию полос","tr":"Şerit çizgisinin üzerine geçin","hi":"लेन रेखा पर आ जाएँ","ar":"انتقل إلى خط المسار"}],"e":{"en":"Riding alongside puts you in a blind spot and limits your escape routes; speeding up or dropping back keeps you visible and safe, advises the Motorcycle Operator Manual.","es":"Conducir a la par te coloca en un punto ciego y limita tus rutas de escape; acelerar o quedarte atrás te mantiene visible y seguro, aconseja el Manual del Operador de Motocicletas.","ru":"Езда рядом помещает вас в слепую зону и ограничивает пути отхода; ускорение или отставание сохраняет вашу видимость и безопасность, советует Руководство для водителей мотоциклов.","tr":"Yan yana sürmek sizi bir kör noktaya sokar ve kaçış yollarınızı sınırlar; hızlanmak veya geriye düşmek sizi görünür ve güvende tutar, der Motosiklet Sürücü Kılavuzu.","hi":"बगल में चलना आपको ब्लाइंड स्पॉट में डालता है और आपके बचने के रास्ते सीमित करता है; गति बढ़ाना या पीछे हटना आपको दृश्यमान और सुरक्षित रखता है, Motorcycle Operator Manual सलाह देता है।","ar":"القيادة بجانبها تضعك في نقطة عمياء وتحد من مسارات هروبك؛ التسارع أو التراجع يُبقيك مرئياً وآمناً، ينصح دليل مشغل الدراجة النارية."}},{"cat":"impairment","a":2,"q":{"en":"When another vehicle is passing you, what is the best lane position to hold?","es":"Cuando otro vehículo te está rebasando, ¿cuál es la mejor posición en el carril que debes mantener?","ru":"Когда другое транспортное средство обгоняет вас, какое положение на полосе лучше всего держать?","tr":"Başka bir araç sizi geçerken, en iyi şerit konumu hangisidir?","hi":"जब कोई अन्य वाहन आपको पास कर रहा हो, तो रखने के लिए सबसे अच्छी लेन स्थिति क्या है?","ar":"عندما تتجاوزك مركبة أخرى، ما هو أفضل موضع في المسار للحفاظ عليه؟"},"o":[{"en":"Ride the lane line nearest the passer","es":"Conducir sobre la línea del carril más cercana a quien te rebasa","ru":"Ехать по линии полосы, ближайшей к обгоняющему","tr":"Geçen aracın en yakınındaki şerit çizgisinde sürün","hi":"पास करने वाले के सबसे पास वाली लेन रेखा पर चलें","ar":"اركب على خط المسار الأقرب إلى المتجاوِز"},{"en":"Move to the far side away from the vehicle","es":"Moverte al extremo opuesto, lejos del vehículo","ru":"Сместиться на дальнюю сторону, подальше от транспортного средства","tr":"Araçtan uzak tarafa geçin","hi":"वाहन से दूर वाली ओर हट जाएँ","ar":"انتقل إلى الجانب البعيد بعيداً عن المركبة"},{"en":"Stay in the center portion of your lane","es":"Permanecer en la porción central de tu carril","ru":"Оставаться в центральной части своей полосы","tr":"Şeritinizin orta bölümünde kalın","hi":"अपनी लेन के केंद्रीय हिस्से में रहें","ar":"ابقَ في الجزء الأوسط من مسارك"},{"en":"Move onto the shoulder","es":"Moverte al acotamiento","ru":"Сместиться на обочину","tr":"Bankete geçin","hi":"कंधे पर हट जाएँ","ar":"انتقل إلى الكتف"}],"e":{"en":"Stay in the center portion of your lane while being passed; moving away can invite the driver to cut back in too soon, says the Motorcycle Operator Manual.","es":"Permanece en la porción central de tu carril mientras te rebasan; moverte hacia un lado puede invitar al conductor a regresar a tu carril demasiado pronto, dice el Manual del Operador de Motocicletas.","ru":"Оставайтесь в центральной части своей полосы во время обгона; смещение в сторону может побудить водителя перестроиться обратно слишком рано, говорит Руководство для водителей мотоциклов.","tr":"Geçilirken şeritinizin orta bölümünde kalın; uzaklaşmak sürücünün çok erken geri kesmesine davetiye çıkarabilir, der Motosiklet Sürücü Kılavuzu.","hi":"पास किए जाने के दौरान अपनी लेन के केंद्रीय हिस्से में रहें; दूर हटना चालक को बहुत जल्दी वापस कट करने का न्योता दे सकता है, Motorcycle Operator Manual कहता है।","ar":"ابقَ في الجزء الأوسط من مسارك أثناء تجاوزك؛ فالابتعاد قد يدعو السائق إلى العودة إلى مسارك مبكراً جداً، يقول دليل مشغل الدراجة النارية."}},{"cat":"impairment","a":3,"q":{"en":"What is the correct sequence when you pass another vehicle on a motorcycle?","es":"¿Cuál es la secuencia correcta cuando rebasas a otro vehículo en motocicleta?","ru":"Какова правильная последовательность действий при обгоне другого транспортного средства на мотоцикле?","tr":"Bir motosiklette başka bir aracı geçtiğinizde doğru sıralama nedir?","hi":"जब आप मोटरसाइकिल पर किसी अन्य वाहन को पास करें तो सही क्रम क्या है?","ar":"ما هو التسلسل الصحيح عندما تتجاوز مركبة أخرى على دراجة نارية؟"},"o":[{"en":"Honk, then drift across slowly","es":"Tocar la bocina y luego desplazarte lentamente","ru":"Подать сигнал, затем медленно сместиться поперёк","tr":"Korna çalın, ardından yavaşça karşıya geçin","hi":"हॉर्न बजाएँ, फिर धीरे-धीरे आर-पार बहें","ar":"انفخ البوق، ثم انتقل عبره ببطء"},{"en":"Pass first, then signal once clear","es":"Rebasar primero y luego señalizar una vez libre","ru":"Сначала обогнать, затем просигналить, когда освободитесь","tr":"Önce geçin, ardından temiz olunca bir kez sinyal verin","hi":"पहले पास करें, फिर साफ़ होने पर सिग्नल दें","ar":"تجاوز أولاً، ثم أشِر بمجرد أن تخلو الطريق"},{"en":"Pass on the shoulder without signaling","es":"Rebasar por el acotamiento sin señalizar","ru":"Обгонять по обочине без сигнала","tr":"Sinyal vermeden bankette geçin","hi":"बिना सिग्नल दिए कंधे पर पास करें","ar":"تجاوز على الكتف دون إشارة"},{"en":"Signal, check mirrors and turn your head, then pass and signal back","es":"Señalizar, revisar los espejos y girar la cabeza, luego rebasar y volver a señalizar","ru":"Просигналить, проверить зеркала и повернуть голову, затем обогнать и снова просигналить","tr":"Sinyal verin, aynaları kontrol edip başınızı çevirin, ardından geçip geri sinyal verin","hi":"सिग्नल दें, मिरर जाँचें और सिर घुमाएँ, फिर पास करें और वापस सिग्नल दें","ar":"أشِر، تحقق من المرايا وأدِر رأسك، ثم تجاوز وأشِر للعودة"}],"e":{"en":"Signal and check for traffic with your mirrors and a head turn before moving out, complete the pass, then signal and return to your lane, per the Motorcycle Operator Manual.","es":"Señaliza y revisa el tráfico con tus espejos y un giro de cabeza antes de salirte, completa el rebase, luego señaliza y regresa a tu carril, según el Manual del Operador de Motocicletas.","ru":"Просигнальте и проверьте обстановку зеркалами и поворотом головы перед выездом, завершите обгон, затем просигнальте и вернитесь на свою полосу, согласно Руководству для водителей мотоциклов.","tr":"Dışarı çıkmadan önce sinyal verin ve aynalarınız ile bir baş çevirmeyle trafiği kontrol edin, geçişi tamamlayın, ardından sinyal verip şeritinize dönün, Motosiklet Sürücü Kılavuzu'na göre.","hi":"बाहर निकलने से पहले सिग्नल दें और मिरर व सिर घुमाकर ट्रैफ़िक जाँचें, पास पूरा करें, फिर सिग्नल देकर अपनी लेन में लौटें, Motorcycle Operator Manual के अनुसार।","ar":"أشِر وتحقق من حركة المرور بمراياك وإدارة الرأس قبل الانتقال، أكمل التجاوز، ثم أشِر وعُد إلى مسارك، وفقاً لدليل مشغل الدراجة النارية."}},{"cat":"impairment","a":1,"q":{"en":"When should you use your turn signals on a motorcycle?","es":"¿Cuándo debes usar tus direccionales en una motocicleta?","ru":"Когда следует использовать указатели поворота на мотоцикле?","tr":"Bir motosiklette sinyallerinizi ne zaman kullanmalısınız?","hi":"आपको मोटरसाइकिल पर अपने टर्न सिग्नल कब उपयोग करने चाहिए?","ar":"متى ينبغي أن تستخدم إشارات الانعطاف على دراجة نارية؟"},"o":[{"en":"Only at intersections with signals","es":"Solo en intersecciones con semáforos","ru":"Только на перекрёстках со светофорами","tr":"Yalnızca sinyalizasyonlu kavşaklarda","hi":"केवल सिग्नल वाले चौराहों पर","ar":"فقط عند التقاطعات ذات الإشارات"},{"en":"Anytime you plan to turn or change lanes, even if no one seems around","es":"Cada vez que planees girar o cambiar de carril, aunque parezca que no hay nadie cerca","ru":"Каждый раз, когда планируете повернуть или перестроиться, даже если рядом, кажется, никого нет","tr":"Etrafta kimse yokmuş gibi görünse bile, dönmeyi veya şerit değiştirmeyi planladığınız her an","hi":"जब भी आप मुड़ने या लेन बदलने की योजना बनाएँ, भले ही कोई आसपास न दिखे","ar":"في أي وقت تخطط فيه للانعطاف أو تغيير المسار، حتى لو بدا أنه لا أحد حولك"},{"en":"Only when turning left","es":"Solo al girar a la izquierda","ru":"Только при повороте налево","tr":"Yalnızca sola dönerken","hi":"केवल बाएँ मुड़ते समय","ar":"فقط عند الانعطاف يساراً"},{"en":"Only when other vehicles are nearby","es":"Solo cuando haya otros vehículos cerca","ru":"Только когда поблизости есть другие транспортные средства","tr":"Yalnızca başka araçlar yakındayken","hi":"केवल जब अन्य वाहन पास हों","ar":"فقط عندما تكون مركبات أخرى قريبة"}],"e":{"en":"Use your signals anytime you plan to turn or change lanes, even when you think no one is around, because they make your intentions clear, says the Motorcycle Operator Manual.","es":"Usa tus direccionales cada vez que planees girar o cambiar de carril, incluso cuando creas que no hay nadie alrededor, porque dejan claras tus intenciones, dice el Manual del Operador de Motocicletas.","ru":"Используйте сигналы каждый раз, когда планируете повернуть или перестроиться, даже когда кажется, что рядом никого нет, потому что они ясно показывают ваши намерения, говорит Руководство для водителей мотоциклов.","tr":"Sinyallerinizi, dönmeyi veya şerit değiştirmeyi planladığınız her an, etrafta kimse olmadığını düşündüğünüzde bile kullanın, çünkü niyetlerinizi netleştirirler, der Motosiklet Sürücü Kılavuzu.","hi":"अपने सिग्नल जब भी मुड़ने या लेन बदलने की योजना बनाएँ तब उपयोग करें, भले ही आपको लगे कि कोई आसपास नहीं है, क्योंकि वे आपके इरादे स्पष्ट करते हैं, Motorcycle Operator Manual कहता है।","ar":"استخدم إشاراتك في أي وقت تخطط فيه للانعطاف أو تغيير المسار، حتى عندما تظن أنه لا أحد حولك، لأنها توضّح نواياك، يقول دليل مشغل الدراجة النارية."}},{"cat":"impairment","a":2,"q":{"en":"Because most motorcycle turn signals do not self-cancel, what must the rider remember to do?","es":"Como la mayoría de las direccionales de motocicleta no se cancelan solas, ¿qué debe recordar hacer el conductor?","ru":"Поскольку большинство указателей поворота на мотоциклах не отключаются автоматически, что должен помнить водитель?","tr":"Çoğu motosiklet sinyali kendiliğinden iptal olmadığı için, sürücünün ne yapmayı hatırlaması gerekir?","hi":"क्योंकि अधिकांश मोटरसाइकिल टर्न सिग्नल स्वतः रद्द नहीं होते, सवार को क्या याद रखना चाहिए?","ar":"لأن معظم إشارات الانعطاف في الدراجات النارية لا تُلغى ذاتياً، ماذا يجب أن يتذكر السائق فعله؟"},"o":[{"en":"Replace the signal bulb weekly","es":"Reemplazar el foco de la direccional cada semana","ru":"Менять лампу указателя поворота еженедельно","tr":"Sinyal ampulünü haftalık değiştirmek","hi":"हर हफ़्ते सिग्नल बल्ब बदलें","ar":"استبدال مصباح الإشارة أسبوعياً"},{"en":"Signal only with hand gestures","es":"Señalizar solo con gestos de la mano","ru":"Сигналить только жестами рук","tr":"Yalnızca el işaretleriyle sinyal vermek","hi":"केवल हाथ के इशारों से सिग्नल दें","ar":"الإشارة فقط بإيماءات اليد"},{"en":"Manually cancel the signal after completing the turn","es":"Cancelar manualmente la direccional después de completar el giro","ru":"Вручную отключать указатель поворота после завершения поворота","tr":"Dönüşü tamamladıktan sonra sinyali manuel olarak iptal etmek","hi":"मोड़ पूरा करने के बाद सिग्नल को मैन्युअल रूप से रद्द करें","ar":"إلغاء الإشارة يدوياً بعد إتمام الانعطاف"},{"en":"Leave the signal on until the next turn","es":"Dejar la direccional encendida hasta el siguiente giro","ru":"Оставлять указатель включённым до следующего поворота","tr":"Sinyali bir sonraki dönüşe kadar açık bırakmak","hi":"अगले मोड़ तक सिग्नल चालू छोड़ दें","ar":"ترك الإشارة مضاءة حتى الانعطاف التالي"}],"e":{"en":"Most motorcycle signals are not self-canceling, so cancel them manually after the maneuver; a forgotten signal can mislead other drivers, notes the Motorcycle Operator Manual.","es":"La mayoría de las direccionales de motocicleta no se cancelan solas, así que cancélalas manualmente después de la maniobra; una direccional olvidada puede confundir a otros conductores, señala el Manual del Operador de Motocicletas.","ru":"Большинство указателей поворота на мотоциклах не отключаются автоматически, поэтому отменяйте их вручную после манёвра; забытый сигнал может ввести в заблуждение других водителей, отмечает Руководство для водителей мотоциклов.","tr":"Çoğu motosiklet sinyali kendiliğinden iptal olmaz, bu yüzden manevradan sonra bunları manuel olarak iptal edin; unutulmuş bir sinyal diğer sürücüleri yanıltabilir, belirtir Motosiklet Sürücü Kılavuzu.","hi":"अधिकांश मोटरसाइकिल सिग्नल स्वतः रद्द नहीं होते, इसलिए युद्धाभ्यास के बाद उन्हें मैन्युअल रूप से रद्द करें; एक भूला हुआ सिग्नल अन्य चालकों को गुमराह कर सकता है, Motorcycle Operator Manual बताता है।","ar":"معظم إشارات الدراجات النارية لا تُلغى ذاتياً، لذا ألغِها يدوياً بعد المناورة؛ فالإشارة المنسية يمكن أن تضلل السائقين الآخرين، يشير دليل مشغل الدراجة النارية."}},{"cat":"impairment","a":3,"q":{"en":"A driver is tailgating you closely. What does the manual recommend?","es":"Un conductor te va siguiendo muy de cerca (te va pegado). ¿Qué recomienda el manual?","ru":"Водитель близко едет у вас на хвосте. Что рекомендует Руководство?","tr":"Bir sürücü sizi yakından takip ediyor (yakın takip). Kılavuz ne önerir?","hi":"एक चालक आपके बहुत पास से पीछे लगकर चल रहा है। मैनुअल क्या सिफ़ारिश करता है?","ar":"سائق يلتصق بك من الخلف عن قرب. بماذا يوصي الدليل؟"},"o":[{"en":"Brake hard to warn them","es":"Frenar fuerte para advertirle","ru":"Резко затормозить, чтобы предупредить его","tr":"Onları uyarmak için sert fren yapın","hi":"उन्हें चेताने के लिए ज़ोर से ब्रेक लगाएँ","ar":"اكبح بقوة لتحذيره"},{"en":"Speed up to outrun the tailgater","es":"Acelerar para dejar atrás al que te va pegado","ru":"Ускориться, чтобы оторваться от того, кто едет на хвосте","tr":"Yakın takipçiyi geride bırakmak için hızlanın","hi":"टेलगेटर से आगे निकलने के लिए गति बढ़ाएँ","ar":"تسارع للهروب من الملتصق"},{"en":"Ignore them and keep your speed","es":"Ignorarlo y mantener tu velocidad","ru":"Игнорировать его и держать свою скорость","tr":"Onları görmezden gelin ve hızınızı koruyun","hi":"उन्हें अनदेखा करें और अपनी गति बनाए रखें","ar":"تجاهله وحافظ على سرعتك"},{"en":"Change lanes or slow down to let them pass","es":"Cambiar de carril o reducir la velocidad para dejarlo pasar","ru":"Перестроиться или замедлиться, чтобы дать ему обогнать","tr":"Şerit değiştirin veya yavaşlayıp geçmelerine izin verin","hi":"लेन बदलें या धीमा करें ताकि वे पास कर सकें","ar":"غيّر المسار أو أبطئ للسماح له بالتجاوز"}],"e":{"en":"Encourage a tailgater to pass by changing lanes or slowing and opening extra space ahead so both of you have room to stop, advises the Motorcycle Operator Manual.","es":"Anima a quien te va pegado a rebasar cambiando de carril o reduciendo la velocidad y abriendo espacio adicional adelante, para que ambos tengan lugar para detenerse, aconseja el Manual del Operador de Motocicletas.","ru":"Побудите едущего на хвосте обогнать, перестроившись или замедлившись и открыв дополнительное пространство впереди, чтобы у вас обоих было место для остановки, советует Руководство для водителей мотоциклов.","tr":"Yakın takipçiyi geçmeye teşvik etmek için şerit değiştirin ya da yavaşlayıp önünüzde ekstra alan açın, böylece ikinizin de durmak için yeri olur, tavsiye eder Motosiklet Sürücü Kılavuzu.","hi":"लेन बदलकर या धीमा करके और आगे अतिरिक्त जगह खोलकर टेलगेटर को पास करने के लिए प्रोत्साहित करें ताकि आप दोनों के पास रुकने की जगह हो, Motorcycle Operator Manual सलाह देता है।","ar":"شجّع الملتصق من الخلف على التجاوز بتغيير المسار أو الإبطاء وفتح مساحة إضافية أمامك حتى يكون لكليكما مجال للتوقف، ينصح دليل مشغل الدراجة النارية."}},{"cat":"controls","a":0,"q":{"en":"What does easing out the clutch through the friction zone allow you to do?","es":"¿Qué le permite hacer soltar el embrague gradualmente a través de la zona de fricción?","ru":"Что позволяет делать плавный отпуск сцепления через зону сцепления?","tr":"Debriyajı friksiyon bölgesinden yavaşça bırakmak ne yapmanızı sağlar?","hi":"फ्रिक्शन ज़ोन के जरिए क्लच को धीरे-धीरे छोड़ना आपको क्या करने देता है?","ar":"ماذا يتيح لك تحرير القابض تدريجياً عبر منطقة الاحتكاك؟"},"o":[{"en":"Begin moving smoothly from a stop","es":"Empezar a moverse suavemente desde parado","ru":"Плавно тронуться с места","tr":"Duruştan yumuşakça hareket etmeye başlamak","hi":"रुकी हुई स्थिति से सहजता से चलना शुरू करना","ar":"البدء بالتحرك بسلاسة من وضع التوقف"},{"en":"Turn off the engine quickly","es":"Apagar el motor rápidamente","ru":"Быстро заглушить двигатель","tr":"Motoru hızlıca kapatmak","hi":"इंजन को जल्दी बंद करना","ar":"إيقاف المحرك بسرعة"},{"en":"Increase the fuel supply","es":"Aumentar el suministro de combustible","ru":"Увеличить подачу топлива","tr":"Yakıt akışını artırmak","hi":"ईंधन आपूर्ति बढ़ाना","ar":"زيادة إمداد الوقود"},{"en":"Lock the rear wheel","es":"Bloquear la rueda trasera","ru":"Заблокировать заднее колесо","tr":"Arka tekerleği kilitlemek","hi":"रियर व्हील को लॉक करना","ar":"قفل العجلة الخلفية"}],"e":{"en":"The friction zone is where the clutch begins to transmit power to the rear wheel; easing out through it lets you start moving smoothly and control speed at very low speeds.","es":"La zona de fricción es donde el embrague empieza a transmitir potencia a la rueda trasera; soltarlo gradualmente le permite arrancar suavemente y controlar la velocidad a marcha muy lenta.","ru":"Зона сцепления — это участок, где сцепление начинает передавать мощность на заднее колесо; плавный отпуск через неё позволяет мягко тронуться и контролировать скорость на малом ходу.","tr":"Friksiyon bölgesi, debriyajın arka tekerleğe güç aktarmaya başladığı yerdir; buradan yavaşça bırakmak yumuşak kalkış yapmanızı ve çok düşük hızda hızı kontrol etmenizi sağlar.","hi":"फ्रिक्शन ज़ोन वह जगह है जहाँ क्लच रियर व्हील को पावर देना शुरू करता है; इससे धीरे-धीरे छोड़ने पर आप सहजता से चलना शुरू करते हैं और बहुत कम गति पर स्पीड नियंत्रित करते हैं।","ar":"منطقة الاحتكاك هي حيث يبدأ القابض بنقل القدرة إلى العجلة الخلفية؛ وتحريره تدريجياً عبرها يتيح لك الانطلاق بسلاسة والتحكم في السرعة عند السرعات المنخفضة جداً."}},{"cat":"controls","a":1,"q":{"en":"When starting the engine, what should you do with the clutch lever?","es":"Al arrancar el motor, ¿qué debe hacer con la palanca del embrague?","ru":"При запуске двигателя что следует сделать с рычагом сцепления?","tr":"Motoru çalıştırırken debriyaj kolu ile ne yapmalısınız?","hi":"इंजन शुरू करते समय आपको क्लच लीवर के साथ क्या करना चाहिए?","ar":"عند تشغيل المحرك، ماذا يجب أن تفعل بذراع القابض؟"},"o":[{"en":"Release it fully","es":"Soltarla por completo","ru":"Полностью отпустить его","tr":"Tamamen bırakmak","hi":"इसे पूरी तरह छोड़ देना","ar":"تحريره بالكامل"},{"en":"Squeeze it in","es":"Apretarla","ru":"Выжать его","tr":"İçeri çekmek (basmak)","hi":"इसे दबाकर रखना","ar":"الضغط عليه للداخل"},{"en":"Hold it halfway only","es":"Sostenerla solo a la mitad","ru":"Держать его наполовину","tr":"Sadece yarıda tutmak","hi":"केवल आधा दबाना","ar":"إمساكه في المنتصف فقط"},{"en":"Remove your hand from it","es":"Quitar la mano de ella","ru":"Убрать с него руку","tr":"Elinizi ondan çekmek","hi":"अपना हाथ इससे हटा लेना","ar":"رفع يدك عنه"}],"e":{"en":"Squeeze (pull in) the clutch before starting so the engine is disengaged from the drive wheel and the motorcycle cannot lurch forward when it starts.","es":"Apriete el embrague antes de arrancar para que el motor quede desconectado de la rueda motriz y la motocicleta no dé un tirón hacia adelante al encender.","ru":"Выжмите сцепление перед запуском, чтобы двигатель был отсоединён от ведущего колеса и мотоцикл не рванул вперёд при пуске.","tr":"Çalıştırmadan önce debriyaja basın; böylece motor tahrik tekerleğinden ayrılır ve motosiklet çalışırken öne fırlamaz.","hi":"शुरू करने से पहले क्लच दबाएँ ताकि इंजन ड्राइव व्हील से अलग रहे और चालू होने पर मोटरसाइकिल आगे न झटके।","ar":"اضغط على القابض قبل التشغيل حتى ينفصل المحرك عن عجلة الدفع ولا تندفع الدراجة إلى الأمام عند بدء التشغيل."}},{"cat":"controls","a":2,"q":{"en":"What is the purpose of the engine cut-off switch?","es":"¿Cuál es la función del interruptor de corte del motor?","ru":"Каково назначение выключателя двигателя (cut-off)?","tr":"Motor durdurma (cut-off) düğmesinin amacı nedir?","hi":"इंजन कट-ऑफ स्विच का उद्देश्य क्या है?","ar":"ما الغرض من مفتاح إيقاف المحرك (cut-off)؟"},"o":[{"en":"To engage the clutch","es":"Para accionar el embrague","ru":"Включать сцепление","tr":"Debriyajı devreye almak","hi":"क्लच को लगाना","ar":"تعشيق القابض"},{"en":"To adjust the headlight","es":"Para ajustar el faro","ru":"Регулировать фару","tr":"Farı ayarlamak","hi":"हेडलाइट समायोजित करना","ar":"ضبط المصباح الأمامي"},{"en":"To stop the engine quickly in an emergency","es":"Para detener el motor rápidamente en una emergencia","ru":"Быстро заглушить двигатель в аварийной ситуации","tr":"Acil durumda motoru hızlıca durdurmak","hi":"आपात स्थिति में इंजन को जल्दी बंद करना","ar":"إيقاف المحرك بسرعة في حالة الطوارئ"},{"en":"To signal a turn","es":"Para señalar un giro","ru":"Подавать сигнал поворота","tr":"Dönüş sinyali vermek","hi":"मोड़ का संकेत देना","ar":"الإشارة إلى الانعطاف"}],"e":{"en":"The engine cut-off switch lets you shut off the engine quickly without removing a hand from the handlebar, which is useful in an emergency.","es":"El interruptor de corte permite apagar el motor rápidamente sin quitar una mano del manillar, lo que es útil en una emergencia.","ru":"Выключатель двигателя позволяет быстро заглушить мотор, не убирая руку с руля, что полезно в экстренной ситуации.","tr":"Motor durdurma düğmesi, elinizi gidondan çekmeden motoru hızla kapatmanıza olanak tanır; bu acil durumda faydalıdır.","hi":"इंजन कट-ऑफ स्विच से आप हैंडलबार से हाथ हटाए बिना इंजन को जल्दी बंद कर सकते हैं, जो आपात स्थिति में उपयोगी है।","ar":"يتيح لك مفتاح إيقاف المحرك إطفاء المحرك بسرعة دون رفع يدك عن المقود، وهو مفيد في حالات الطوارئ."}},{"cat":"controls","a":3,"q":{"en":"To slow the motorcycle using engine braking, what should you do?","es":"Para frenar la motocicleta usando el freno de motor, ¿qué debe hacer?","ru":"Чтобы замедлить мотоцикл торможением двигателем, что нужно сделать?","tr":"Motosikleti motor freni ile yavaşlatmak için ne yapmalısınız?","hi":"इंजन ब्रेकिंग से मोटरसाइकिल धीमी करने के लिए आपको क्या करना चाहिए?","ar":"لإبطاء الدراجة النارية باستخدام كبح المحرك، ماذا يجب أن تفعل؟"},"o":[{"en":"Pull in the clutch and coast","es":"Apretar el embrague y rodar libre","ru":"Выжать сцепление и катиться накатом","tr":"Debriyaja basıp boşta kaymak","hi":"क्लच दबाकर बिना गियर के लुढ़कना","ar":"الضغط على القابض والانزلاق بحرية"},{"en":"Shift into neutral","es":"Poner punto muerto","ru":"Перейти на нейтраль","tr":"Boşa almak","hi":"न्यूट्रल में डालना","ar":"التحويل إلى الوضع المحايد"},{"en":"Twist the throttle open","es":"Girar el acelerador hacia adentro","ru":"Прибавить газ","tr":"Gazı açmak","hi":"थ्रॉटल खोलना","ar":"فتح الخانق (تسريع)"},{"en":"Roll off the throttle and downshift as needed","es":"Soltar el acelerador y reducir de marcha según haga falta","ru":"Сбросить газ и понижать передачи по мере необходимости","tr":"Gazı bırakıp gerektikçe vites küçültmek","hi":"थ्रॉटल छोड़ना और जरूरत अनुसार गियर कम करना","ar":"تخفيف الخانق وتخفيض السرعة حسب الحاجة"}],"e":{"en":"Rolling off the throttle and downshifting lets the engine help slow you (engine braking) while keeping the bike in gear and ready to accelerate.","es":"Soltar el acelerador y reducir de marcha permite que el motor ayude a frenar (freno de motor) manteniendo la moto engranada y lista para acelerar.","ru":"Сброс газа и понижение передачи позволяют двигателю помогать замедлению (торможение двигателем), оставляя мотоцикл на передаче и готовым к разгону.","tr":"Gazı bırakıp vites küçültmek, motorun yavaşlamaya yardım etmesini (motor freni) sağlar ve motosikleti viteste, hızlanmaya hazır tutar.","hi":"थ्रॉटल छोड़ना और गियर कम करना इंजन को धीमा करने में मदद करता है (इंजन ब्रेकिंग), और बाइक गियर में तथा तेज होने के लिए तैयार रहती है।","ar":"تخفيف الخانق وتخفيض السرعة يجعل المحرك يساعد على الإبطاء (كبح المحرك) مع إبقاء الدراجة في وضع التعشيق وجاهزة للتسارع."}},{"cat":"controls","a":0,"q":{"en":"How should you use the throttle and clutch together for the smoothest start from a stop?","es":"¿Cómo debe usar el acelerador y el embrague juntos para el arranque más suave desde parado?","ru":"Как совместно использовать газ и сцепление для самого плавного старта с места?","tr":"Duruştan en yumuşak kalkış için gaz ve debriyajı birlikte nasıl kullanmalısınız?","hi":"रुकी स्थिति से सबसे सहज शुरुआत के लिए थ्रॉटल और क्लच को एक साथ कैसे इस्तेमाल करें?","ar":"كيف تستخدم الخانق والقابض معاً لأكثر انطلاقة سلاسة من التوقف؟"},"o":[{"en":"Ease the clutch out while gradually rolling on the throttle","es":"Soltar el embrague poco a poco mientras se acelera gradualmente","ru":"Плавно отпускать сцепление, постепенно прибавляя газ","tr":"Debriyajı yavaşça bırakırken gazı kademeli açmak","hi":"धीरे-धीरे थ्रॉटल बढ़ाते हुए क्लच को धीरे-धीरे छोड़ना","ar":"تحرير القابض تدريجياً مع فتح الخانق بالتدريج"},{"en":"Release the clutch quickly and hold the throttle steady","es":"Soltar el embrague de golpe y mantener el acelerador fijo","ru":"Резко бросить сцепление, держа газ ровным","tr":"Debriyajı hızla bırakıp gazı sabit tutmak","hi":"क्लच को तेजी से छोड़ना और थ्रॉटल स्थिर रखना","ar":"تحرير القابض بسرعة وإبقاء الخانق ثابتاً"},{"en":"Keep the clutch fully in and rev the engine","es":"Mantener el embrague apretado y acelerar el motor","ru":"Держать сцепление выжатым и газовать","tr":"Debriyajı tam basılı tutup motoru gazlamak","hi":"क्लच पूरा दबाए रखना और इंजन रेव करना","ar":"إبقاء القابض مضغوطاً بالكامل وتدوير المحرك بقوة"},{"en":"Close the throttle and drop the clutch","es":"Cerrar el acelerador y soltar el embrague de golpe","ru":"Закрыть газ и бросить сцепление","tr":"Gazı kapatıp debriyajı bırakmak","hi":"थ्रॉटल बंद करना और क्लच झटके से छोड़ना","ar":"إغلاق الخانق وإفلات القابض فجأة"}],"e":{"en":"Coordinating a gradual throttle roll-on with easing the clutch through the friction zone gives a smooth, controlled start without stalling or lurching.","es":"Coordinar una aceleración gradual con soltar el embrague por la zona de fricción produce un arranque suave y controlado sin calarse ni dar tirones.","ru":"Согласование плавного прибавления газа с отпусканием сцепления через зону сцепления даёт мягкий, контролируемый старт без глохнущего двигателя и рывков.","tr":"Gazı kademeli açmayı, debriyajı friksiyon bölgesinden bırakmakla eşgüdümlü yapmak, boğulmadan ve sarsılmadan yumuşak, kontrollü bir kalkış sağlar.","hi":"थ्रॉटल को धीरे-धीरे बढ़ाना और क्लच को फ्रिक्शन ज़ोन से छोड़ना मिलकर बिना बंद हुए या झटके के सहज, नियंत्रित शुरुआत देता है।","ar":"تنسيق فتح الخانق تدريجياً مع تحرير القابض عبر منطقة الاحتكاك يمنح انطلاقة سلسة ومنضبطة دون انطفاء أو اندفاع."}},{"cat":"controls","a":1,"q":{"en":"On most motorcycles, which gear position is between first and second?","es":"En la mayoría de las motocicletas, ¿qué posición de marcha está entre primera y segunda?","ru":"На большинстве мотоциклов какое положение передачи находится между первой и второй?","tr":"Çoğu motosiklette birinci ve ikinci vites arasında hangi konum bulunur?","hi":"अधिकांश मोटरसाइकिलों में पहले और दूसरे गियर के बीच कौन सी स्थिति होती है?","ar":"في معظم الدراجات النارية، ما الوضع الذي يقع بين الترس الأول والثاني؟"},"o":[{"en":"Third gear","es":"Tercera marcha","ru":"Третья передача","tr":"Üçüncü vites","hi":"तीसरा गियर","ar":"الترس الثالث"},{"en":"Neutral","es":"Punto muerto","ru":"Нейтраль","tr":"Boş (neutral)","hi":"न्यूट्रल","ar":"الوضع المحايد"},{"en":"Reverse","es":"Reversa","ru":"Задний ход","tr":"Geri vites","hi":"रिवर्स","ar":"الترس الخلفي"},{"en":"Overdrive","es":"Sobremarcha","ru":"Овердрайв","tr":"Overdrive","hi":"ओवरड्राइव","ar":"الترس العالي (overdrive)"}],"e":{"en":"In the standard 1-N-2-3-4-5 pattern, neutral sits between first and second gear, found with a light half-click up from first.","es":"En el patrón estándar 1-N-2-3-4-5, el punto muerto está entre primera y segunda, y se encuentra con medio golpe hacia arriba desde primera.","ru":"В стандартной схеме 1-N-2-3-4-5 нейтраль находится между первой и второй передачами и включается лёгким полущелчком вверх с первой.","tr":"Standart 1-N-2-3-4-5 düzeninde boş vites, birinci ile ikinci arasında yer alır ve birinciden hafif yarım tıklama yukarı ile bulunur.","hi":"मानक 1-N-2-3-4-5 पैटर्न में न्यूट्रल पहले और दूसरे गियर के बीच होता है, जो पहले से हल्के आधे क्लिक ऊपर पर मिलता है।","ar":"في النمط القياسي 1-N-2-3-4-5، يقع الوضع المحايد بين الترس الأول والثاني، ويُوجد بنصف نقرة خفيفة للأعلى من الأول."}},{"cat":"controls","a":2,"q":{"en":"What can happen if you release the clutch too quickly when starting from a stop?","es":"¿Qué puede pasar si suelta el embrague demasiado rápido al arrancar desde parado?","ru":"Что может произойти, если слишком быстро отпустить сцепление при старте с места?","tr":"Duruştan kalkarken debriyajı çok hızlı bırakırsanız ne olabilir?","hi":"रुकी स्थिति से चलते समय क्लच बहुत जल्दी छोड़ देने पर क्या हो सकता है?","ar":"ماذا قد يحدث إذا حررت القابض بسرعة كبيرة عند الانطلاق من التوقف؟"},"o":[{"en":"The engine will rev higher","es":"El motor girará más alto","ru":"Двигатель раскрутится сильнее","tr":"Motor daha yüksek devir yapar","hi":"इंजन ज्यादा रेव करेगा","ar":"سيرتفع دوران المحرك أكثر"},{"en":"The front brake will lock","es":"El freno delantero se bloqueará","ru":"Заблокируется передний тормоз","tr":"Ön fren kilitlenir","hi":"फ्रंट ब्रेक लॉक हो जाएगा","ar":"سيُقفل الفرامل الأمامية"},{"en":"The engine may stall or the bike may jerk forward","es":"El motor puede calarse o la moto dar un tirón hacia adelante","ru":"Двигатель может заглохнуть, а мотоцикл дёрнуться вперёд","tr":"Motor stop edebilir veya motosiklet öne sıçrayabilir","hi":"इंजन बंद हो सकता है या बाइक आगे झटक सकती है","ar":"قد ينطفئ المحرك أو تندفع الدراجة إلى الأمام"},{"en":"The headlight will switch off","es":"El faro se apagará","ru":"Погаснет фара","tr":"Far söner","hi":"हेडलाइट बंद हो जाएगी","ar":"سينطفئ المصباح الأمامي"}],"e":{"en":"Letting the clutch out too fast can stall the engine or cause the motorcycle to jerk or lurch forward; ease it out through the friction zone instead.","es":"Soltar el embrague muy rápido puede calar el motor o hacer que la moto dé un tirón hacia adelante; en su lugar, suéltelo gradualmente por la zona de fricción.","ru":"Слишком быстрый отпуск сцепления может заглушить двигатель или заставить мотоцикл дёрнуться вперёд; вместо этого плавно отпускайте его через зону сцепления.","tr":"Debriyajı çok hızlı bırakmak motoru boğabilir veya motosikletin öne sıçramasına neden olabilir; bunun yerine friksiyon bölgesinden yavaşça bırakın.","hi":"क्लच बहुत तेजी से छोड़ने पर इंजन बंद हो सकता है या बाइक आगे झटक सकती है; इसके बजाय इसे फ्रिक्शन ज़ोन से धीरे-धीरे छोड़ें।","ar":"تحرير القابض بسرعة كبيرة قد يُطفئ المحرك أو يجعل الدراجة تندفع إلى الأمام؛ بدلاً من ذلك حرّره تدريجياً عبر منطقة الاحتكاك."}},{"cat":"controls","a":3,"q":{"en":"Why should you keep both hands on the handgrips and both feet on the footrests while riding?","es":"¿Por qué debe mantener ambas manos en los puños y ambos pies en los estribos al conducir?","ru":"Почему во время движения нужно держать обе руки на рукоятках, а обе ноги на подножках?","tr":"Sürüş sırasında neden iki elinizi de gidonda, iki ayağınızı da basamaklarda tutmalısınız?","hi":"चलाते समय दोनों हाथ हैंडग्रिप पर और दोनों पैर फुटरेस्ट पर क्यों रखने चाहिए?","ar":"لماذا يجب أن تُبقي كلتا يديك على المقبضين وكلتا قدميك على المسندين أثناء القيادة؟"},"o":[{"en":"To save fuel","es":"Para ahorrar combustible","ru":"Чтобы экономить топливо","tr":"Yakıt tasarrufu için","hi":"ईंधन बचाने के लिए","ar":"لتوفير الوقود"},{"en":"To keep the engine cool","es":"Para mantener el motor frío","ru":"Чтобы охлаждать двигатель","tr":"Motoru serin tutmak için","hi":"इंजन को ठंडा रखने के लिए","ar":"للحفاظ على برودة المحرك"},{"en":"To reduce tire wear","es":"Para reducir el desgaste de las llantas","ru":"Чтобы снизить износ шин","tr":"Lastik aşınmasını azaltmak için","hi":"टायर घिसाव कम करने के लिए","ar":"لتقليل تآكل الإطارات"},{"en":"To stay ready to control the motorcycle at all times","es":"Para estar siempre listo para controlar la motocicleta","ru":"Чтобы всегда быть готовым управлять мотоциклом","tr":"Motosikleti her an kontrol etmeye hazır olmak için","hi":"हर समय मोटरसाइकिल को नियंत्रित करने के लिए तैयार रहने हेतु","ar":"للبقاء جاهزاً للتحكم في الدراجة في كل وقت"}],"e":{"en":"Keeping both hands and feet in place means the brakes, clutch, throttle and shifter are always within instant reach if you need to react.","es":"Mantener ambas manos y pies en su lugar significa que los frenos, el embrague, el acelerador y el cambio están siempre al alcance inmediato para reaccionar.","ru":"Обе руки и ноги на месте — значит тормоза, сцепление, газ и переключатель всегда мгновенно доступны, если понадобится среагировать.","tr":"İki eli ve ayağı yerinde tutmak, tepki vermeniz gerektiğinde fren, debriyaj, gaz ve vitesin her zaman anında erişilebilir olması demektir.","hi":"दोनों हाथ-पैर अपनी जगह रखने का अर्थ है कि प्रतिक्रिया करने की जरूरत पड़ने पर ब्रेक, क्लच, थ्रॉटल और शिफ्टर हमेशा तुरंत पहुँच में हों।","ar":"إبقاء اليدين والقدمين في مكانهما يعني أن الفرامل والقابض والخانق وذراع التروس في متناولك فوراً عند الحاجة للتفاعل."}},{"cat":"controls","a":0,"q":{"en":"Before shifting to a lower gear, what should you generally do?","es":"Antes de reducir a una marcha más baja, ¿qué debe hacer en general?","ru":"Прежде чем переключиться на пониженную передачу, что обычно следует сделать?","tr":"Daha düşük bir vitese geçmeden önce genellikle ne yapmalısınız?","hi":"नीचे के गियर में शिफ्ट करने से पहले आम तौर पर क्या करना चाहिए?","ar":"قبل التحويل إلى ترس أدنى، ماذا يجب أن تفعل عادةً؟"},"o":[{"en":"Make sure the engine will not over-rev at that gear","es":"Asegurarse de que el motor no se sobrerrevolucione en esa marcha","ru":"Убедиться, что двигатель не перекрутится на этой передаче","tr":"Motorun o viteste aşırı devir yapmayacağından emin olmak","hi":"सुनिश्चित करना कि उस गियर में इंजन ओवर-रेव न हो","ar":"التأكد من أن المحرك لن يفرط في الدوران عند ذلك الترس"},{"en":"Pull in the front brake hard","es":"Apretar fuerte el freno delantero","ru":"Резко нажать передний тормоз","tr":"Ön frene sertçe basmak","hi":"फ्रंट ब्रेक जोर से दबाना","ar":"الضغط بقوة على الفرامل الأمامية"},{"en":"Turn off the engine","es":"Apagar el motor","ru":"Заглушить двигатель","tr":"Motoru kapatmak","hi":"इंजन बंद करना","ar":"إيقاف المحرك"},{"en":"Fully release the clutch first","es":"Soltar totalmente el embrague primero","ru":"Сначала полностью отпустить сцепление","tr":"Önce debriyajı tamamen bırakmak","hi":"पहले क्लच पूरा छोड़ना","ar":"تحرير القابض بالكامل أولاً"}],"e":{"en":"Downshift only when the engine speed will stay in a safe range for the lower gear; downshifting too soon can over-rev the engine and lock the rear wheel.","es":"Reduzca de marcha solo cuando el régimen del motor se mantenga en un rango seguro para la marcha más baja; hacerlo demasiado pronto puede sobrerrevolucionar el motor y bloquear la rueda trasera.","ru":"Понижайте передачу только когда обороты останутся в безопасном диапазоне для неё; слишком раннее понижение может перекрутить двигатель и заблокировать заднее колесо.","tr":"Yalnızca motor devri düşük vites için güvenli aralıkta kalacaksa vites küçültün; çok erken küçültmek motoru aşırı devirletebilir ve arka tekerleği kilitleyebilir.","hi":"गियर तभी कम करें जब उस निचले गियर के लिए इंजन की गति सुरक्षित सीमा में रहे; बहुत जल्दी गियर कम करने से इंजन ओवर-रेव हो सकता है और रियर व्हील लॉक हो सकता है।","ar":"خفّض السرعة فقط عندما تبقى سرعة المحرك ضمن نطاق آمن للترس الأدنى؛ التخفيض المبكر قد يفرط في دوران المحرك ويقفل العجلة الخلفية."}},{"cat":"controls","a":1,"q":{"en":"What is the recommended way to make a normal stop on a motorcycle?","es":"¿Cuál es la forma recomendada de hacer una parada normal en motocicleta?","ru":"Как рекомендуется совершать обычную остановку на мотоцикле?","tr":"Motosiklette normal bir duruş yapmanın önerilen yolu nedir?","hi":"मोटरसाइकिल पर सामान्य रुकावट का अनुशंसित तरीका क्या है?","ar":"ما الطريقة الموصى بها للتوقف الطبيعي على الدراجة النارية؟"},"o":[{"en":"Use the rear brake only","es":"Usar solo el freno trasero","ru":"Использовать только задний тормоз","tr":"Yalnızca arka freni kullanmak","hi":"केवल रियर ब्रेक का उपयोग","ar":"استخدام الفرامل الخلفية فقط"},{"en":"Use both brakes and downshift as you slow","es":"Usar ambos frenos y reducir de marcha al frenar","ru":"Использовать оба тормоза и понижать передачи по мере замедления","tr":"Her iki freni kullanıp yavaşladıkça vites küçültmek","hi":"दोनों ब्रेक इस्तेमाल करें और धीमा होते हुए गियर कम करें","ar":"استخدام كلا الفرملتين وتخفيض السرعة أثناء الإبطاء"},{"en":"Use the front brake only","es":"Usar solo el freno delantero","ru":"Использовать только передний тормоз","tr":"Yalnızca ön freni kullanmak","hi":"केवल फ्रंट ब्रेक का उपयोग","ar":"استخدام الفرامل الأمامية فقط"},{"en":"Coast in neutral to a stop","es":"Rodar en punto muerto hasta detenerse","ru":"Катиться на нейтрали до остановки","tr":"Boşta kayarak durmak","hi":"न्यूट्रल में लुढ़ककर रुकना","ar":"الانزلاق في الوضع المحايد حتى التوقف"}],"e":{"en":"For normal stops the manual advises using both brakes and downshifting so you finish in first gear, ready to move again.","es":"Para paradas normales, el manual aconseja usar ambos frenos y reducir de marcha para terminar en primera, listo para arrancar de nuevo.","ru":"Для обычных остановок руководство советует использовать оба тормоза и понижать передачи, чтобы остановиться на первой и быть готовым тронуться.","tr":"Normal duruşlar için kılavuz, her iki freni kullanmayı ve vites küçültmeyi önerir; böylece birinci viteste, tekrar kalkmaya hazır durursunuz.","hi":"सामान्य रुकावटों के लिए मैनुअल दोनों ब्रेक इस्तेमाल करने और गियर कम करने की सलाह देता है ताकि आप पहले गियर में रुकें और फिर चलने को तैयार रहें।","ar":"للتوقفات العادية ينصح الدليل باستخدام كلا الفرملتين وتخفيض السرعة حتى تنتهي في الترس الأول، جاهزاً للانطلاق مجدداً."}},{"cat":"controls","a":2,"q":{"en":"When you shift gears, the clutch should be:","es":"Al cambiar de marcha, el embrague debe estar:","ru":"При переключении передач сцепление должно быть:","tr":"Vites değiştirirken debriyaj:","hi":"गियर बदलते समय क्लच होना चाहिए:","ar":"عند تغيير السرعات، يجب أن يكون القابض:"},"o":[{"en":"Fully released the whole time","es":"Totalmente suelto todo el tiempo","ru":"Полностью отпущено всё время","tr":"Sürekli tamamen bırakılmış","hi":"पूरे समय पूरी तरह छूटा हुआ","ar":"محرّراً بالكامل طوال الوقت"},{"en":"Left untouched","es":"Sin tocar","ru":"Не тронуто","tr":"Hiç dokunulmamış","hi":"अछूता छोड़ा हुआ","ar":"دون لمس"},{"en":"Squeezed in as you move the shift lever, then eased back out","es":"Apretado al mover la palanca de cambios y luego soltado gradualmente","ru":"Выжато при переводе рычага передач, затем плавно отпущено","tr":"Vites kolunu hareket ettirirken içeri basılmış, sonra yavaşça bırakılmış","hi":"शिफ्ट लीवर हिलाते समय दबाया हुआ, फिर धीरे-धीरे छोड़ा हुआ","ar":"مضغوطاً أثناء تحريك ذراع التروس، ثم يُحرَّر تدريجياً"},{"en":"Held halfway for several seconds","es":"Sostenido a la mitad varios segundos","ru":"Удержано наполовину несколько секунд","tr":"Birkaç saniye yarıda tutulmuş","hi":"कई सेकंड आधा दबाया हुआ","ar":"ممسوكاً في المنتصف لعدة ثوانٍ"}],"e":{"en":"To shift, squeeze the clutch in as you move the shift lever, then ease the clutch back out smoothly to re-engage the drive.","es":"Para cambiar, apriete el embrague al mover la palanca y luego suéltelo suavemente para volver a engranar la transmisión.","ru":"Для переключения выжмите сцепление при перемещении рычага, затем плавно отпустите его, чтобы снова включить передачу.","tr":"Vites için, vites kolunu hareket ettirirken debriyaja basın, ardından tahriki yeniden devreye almak için debriyajı yumuşakça bırakın.","hi":"गियर बदलने के लिए शिफ्ट लीवर हिलाते समय क्लच दबाएँ, फिर ड्राइव फिर से जोड़ने के लिए क्लच को सहजता से छोड़ें।","ar":"للتبديل، اضغط القابض أثناء تحريك ذراع التروس، ثم حرّره بسلاسة لإعادة تعشيق نقل الحركة."}},{"cat":"controls","a":3,"q":{"en":"What is the main advantage of downshifting before you enter a turn rather than while in it?","es":"¿Cuál es la principal ventaja de reducir de marcha antes de entrar a una curva en vez de dentro de ella?","ru":"В чём главное преимущество понижения передачи до входа в поворот, а не в самом повороте?","tr":"Bir dönüşe girmeden önce vites küçültmenin, dönüş içindeyken yapmaya kıyasla temel avantajı nedir?","hi":"मोड़ में प्रवेश करने से पहले गियर कम करने का, मोड़ के भीतर करने की तुलना में, मुख्य लाभ क्या है?","ar":"ما الميزة الرئيسية لتخفيض السرعة قبل الدخول في منعطف بدلاً من أثناء وجودك فيه؟"},"o":[{"en":"It saves fuel in the turn","es":"Ahorra combustible en la curva","ru":"Экономит топливо в повороте","tr":"Dönüşte yakıt tasarrufu sağlar","hi":"मोड़ में ईंधन बचाता है","ar":"يوفر الوقود في المنعطف"},{"en":"It lets you brake harder mid-turn","es":"Permite frenar más fuerte a mitad de curva","ru":"Позволяет сильнее тормозить в середине поворота","tr":"Dönüş ortasında daha sert frenlemenizi sağlar","hi":"मोड़ के बीच में ज्यादा जोर से ब्रेक लगाने देता है","ar":"يتيح لك الكبح بقوة أكبر في منتصف المنعطف"},{"en":"It turns off the engine braking","es":"Desactiva el freno de motor","ru":"Отключает торможение двигателем","tr":"Motor frenini kapatır","hi":"इंजन ब्रेकिंग बंद कर देता है","ar":"يوقف كبح المحرك"},{"en":"It avoids upsetting the bike's balance while leaned over","es":"Evita alterar el equilibrio de la moto mientras está inclinada","ru":"Позволяет не нарушить баланс мотоцикла в наклоне","tr":"Yatık haldeyken motosikletin dengesini bozmaktan kaçınır","hi":"झुकी हुई अवस्था में बाइक का संतुलन बिगड़ने से बचाता है","ar":"يتجنب الإخلال بتوازن الدراجة أثناء ميلها"}],"e":{"en":"Selecting the right gear before the turn keeps you from shifting while leaned over, which could jerk the drivetrain and upset the bike's stability.","es":"Elegir la marcha adecuada antes de la curva evita cambiar mientras está inclinado, lo que podría dar un tirón a la transmisión y desestabilizar la moto.","ru":"Выбор нужной передачи до поворота избавляет от переключения в наклоне, которое могло бы рвануть трансмиссию и нарушить устойчивость.","tr":"Dönüşten önce doğru vitesi seçmek, yatıkken vites değiştirmenizi önler; bu, aktarma organlarını sarsıp motosikletin dengesini bozabilir.","hi":"मोड़ से पहले सही गियर चुनना झुकी हुई अवस्था में गियर बदलने से रोकता है, जो ड्राइवट्रेन को झटका देकर बाइक की स्थिरता बिगाड़ सकता है।","ar":"اختيار الترس المناسب قبل المنعطف يمنعك من التبديل أثناء الميل، وهو ما قد يهز نظام نقل الحركة ويخل باستقرار الدراجة."}},{"cat":"controls","a":0,"q":{"en":"If you must ride away from a stop on an uphill grade, what helps prevent rolling backward?","es":"Si debe arrancar en una pendiente cuesta arriba, ¿qué ayuda a evitar rodar hacia atrás?","ru":"Если нужно тронуться на подъёме, что помогает не покатиться назад?","tr":"Yokuş yukarı bir eğimde kalkmanız gerekiyorsa, geriye kaymayı önlemeye ne yardımcı olur?","hi":"यदि चढ़ाई पर रुकी स्थिति से चलना हो, तो पीछे लुढ़कने से रोकने में क्या मदद करता है?","ar":"إذا اضطررت للانطلاق من التوقف على منحدر صاعد، فما الذي يساعد على منع التدحرج للخلف؟"},"o":[{"en":"Using the rear brake while you ease out the clutch and add throttle","es":"Usar el freno trasero mientras suelta el embrague y da acelerador","ru":"Использование заднего тормоза при отпуске сцепления и добавлении газа","tr":"Debriyajı bırakıp gaz eklerken arka freni kullanmak","hi":"क्लच छोड़ते और थ्रॉटल देते समय रियर ब्रेक का उपयोग","ar":"استخدام الفرامل الخلفية أثناء تحرير القابض وإضافة الخانق"},{"en":"Shifting into neutral first","es":"Poner primero punto muerto","ru":"Сначала перейти на нейтраль","tr":"Önce boşa almak","hi":"पहले न्यूट्रल में डालना","ar":"التحويل إلى المحايد أولاً"},{"en":"Releasing both brakes immediately","es":"Soltar ambos frenos de inmediato","ru":"Немедленно отпустить оба тормоза","tr":"Her iki freni hemen bırakmak","hi":"तुरंत दोनों ब्रेक छोड़ना","ar":"تحرير كلا الفرملتين فوراً"},{"en":"Turning the handlebars fully to one side","es":"Girar el manillar por completo a un lado","ru":"Полностью повернуть руль в сторону","tr":"Gidonu bir tarafa tam çevirmek","hi":"हैंडलबार पूरी तरह एक ओर मोड़ना","ar":"تدوير المقود بالكامل إلى جانب واحد"}],"e":{"en":"On an uphill start, hold the rear brake while you find the friction zone and add throttle, then release the brake as the bike begins to pull forward so it does not roll back.","es":"En un arranque cuesta arriba, mantenga el freno trasero mientras encuentra la zona de fricción y da acelerador; luego suelte el freno cuando la moto empiece a avanzar para que no ruede hacia atrás.","ru":"На старте в гору держите задний тормоз, находя зону сцепления и добавляя газ, затем отпускайте тормоз, когда мотоцикл начнёт двигаться вперёд, чтобы он не покатился назад.","tr":"Yokuş yukarı kalkışta, friksiyon bölgesini bulup gaz eklerken arka freni tutun; motosiklet öne çekmeye başlayınca freni bırakın ki geriye kaymasın.","hi":"चढ़ाई पर चलते समय फ्रिक्शन ज़ोन खोजते और थ्रॉटल देते हुए रियर ब्रेक पकड़ें, फिर जब बाइक आगे बढ़ने लगे तो ब्रेक छोड़ दें ताकि वह पीछे न लुढ़के।","ar":"عند الانطلاق صعوداً، أمسك الفرامل الخلفية أثناء إيجاد منطقة الاحتكاك وإضافة الخانق، ثم حرّر الفرامل عندما تبدأ الدراجة بالتحرك للأمام كي لا تتدحرج للخلف."}},{"cat":"controls","a":1,"q":{"en":"Rolling on the throttle through a turn helps the motorcycle by:","es":"Acelerar suavemente a lo largo de una curva ayuda a la motocicleta al:","ru":"Плавное добавление газа в повороте помогает мотоциклу тем, что:","tr":"Dönüş boyunca gazı yavaşça açmak motosiklete şu şekilde yardımcı olur:","hi":"मोड़ में थ्रॉटल धीरे-धीरे बढ़ाना मोटरसाइकिल की इस तरह मदद करता है:","ar":"فتح الخانق تدريجياً خلال المنعطف يساعد الدراجة عن طريق:"},"o":[{"en":"Locking the front wheel","es":"Bloqueando la rueda delantera","ru":"Блокируя переднее колесо","tr":"Ön tekerleği kilitleyerek","hi":"फ्रंट व्हील को लॉक करके","ar":"قفل العجلة الأمامية"},{"en":"Stabilizing it and maintaining smooth speed","es":"Estabilizándola y manteniendo una velocidad suave","ru":"Стабилизируя его и поддерживая ровную скорость","tr":"Onu dengeleyip düzgün hızı koruyarak","hi":"इसे स्थिर करके और सहज गति बनाए रखकर","ar":"تثبيتها والحفاظ على سرعة سلسة"},{"en":"Shutting off the engine","es":"Apagando el motor","ru":"Глуша двигатель","tr":"Motoru kapatarak","hi":"इंजन बंद करके","ar":"إطفاء المحرك"},{"en":"Straightening it upright instantly","es":"Enderezándola de golpe","ru":"Мгновенно выпрямляя его","tr":"Onu anında dikleştirerek","hi":"इसे तुरंत सीधा करके","ar":"تعديلها لتقف مستقيمة فوراً"}],"e":{"en":"Maintaining or gently rolling on the throttle through a curve stabilizes the motorcycle and keeps traction balanced; that is the 'roll' step of slow-look-press-roll.","es":"Mantener o abrir suavemente el acelerador en una curva estabiliza la moto y equilibra la tracción; ese es el paso 'roll' de despacio-mirar-presionar-acelerar.","ru":"Поддержание или лёгкое прибавление газа в повороте стабилизирует мотоцикл и уравновешивает сцепление — это шаг «roll» в схеме «медленно-смотри-нажми-газуй».","tr":"Dönüşte gazı korumak veya hafifçe açmak motosikleti dengeler ve tutuşu dengede tutar; bu, yavaşla-bak-bastır-gazla adımının 'gazla' aşamasıdır.","hi":"मोड़ में थ्रॉटल बनाए रखना या हल्के से बढ़ाना मोटरसाइकिल को स्थिर करता है और ट्रैक्शन संतुलित रखता है; यह धीरे-देखो-दबाओ-गैस दो का 'गैस' चरण है।","ar":"الحفاظ على الخانق أو فتحه بلطف خلال المنعطف يثبّت الدراجة ويوازن التماسك؛ وهذه هي خطوة 'الخانق' من: أبطئ-انظر-اضغط-سرّع."}},{"cat":"controls","a":2,"q":{"en":"What does the manual advise about your speed as you pull away and pick up gears?","es":"¿Qué aconseja el manual sobre su velocidad al arrancar y subir de marchas?","ru":"Что советует руководство о скорости при трогании и наборе передач?","tr":"Kılavuz, kalkarken ve vites yükseltirken hızınız konusunda ne önerir?","hi":"चलना शुरू करते और गियर बढ़ाते समय गति के बारे में मैनुअल क्या सलाह देता है?","ar":"ماذا ينصح الدليل بشأن سرعتك عند الانطلاق ورفع التروس؟"},"o":[{"en":"Rev the engine to redline in each gear","es":"Llevar el motor al límite en cada marcha","ru":"Раскручивать двигатель до отсечки на каждой передаче","tr":"Her viteste motoru kırmızı bölgeye kadar çevirmek","hi":"हर गियर में इंजन को रेडलाइन तक रेव करना","ar":"تدوير المحرك حتى الخط الأحمر في كل ترس"},{"en":"Stay in first gear as long as possible","es":"Permanecer en primera todo lo posible","ru":"Оставаться на первой передаче как можно дольше","tr":"Mümkün olduğunca birinci viteste kalmak","hi":"जितना संभव हो पहले गियर में रहना","ar":"البقاء في الترس الأول أطول فترة ممكنة"},{"en":"Shift up smoothly and keep the engine in a comfortable range","es":"Subir de marcha suavemente y mantener el motor en un rango cómodo","ru":"Плавно повышать передачи и держать двигатель в комфортном диапазоне","tr":"Yumuşakça vites yükseltip motoru rahat bir aralıkta tutmak","hi":"सहजता से गियर बढ़ाना और इंजन को आरामदायक सीमा में रखना","ar":"رفع التروس بسلاسة وإبقاء المحرك في نطاق مريح"},{"en":"Skip from first straight to top gear","es":"Saltar de primera directamente a la marcha más alta","ru":"Прыгать с первой сразу на высшую передачу","tr":"Birinciden doğrudan en yüksek vitese atlamak","hi":"पहले से सीधे टॉप गियर पर कूदना","ar":"القفز من الأول مباشرة إلى أعلى ترس"}],"e":{"en":"Upshift smoothly through the gears to keep the engine running in a comfortable power range, which gives good control and avoids over-revving or lugging.","es":"Suba de marcha suavemente para mantener el motor en un rango de potencia cómodo, lo que da buen control y evita sobrerrevolucionar o forzar el motor.","ru":"Плавно повышайте передачи, удерживая двигатель в комфортном диапазоне мощности — это даёт хороший контроль и исключает перекрут или «задушивание» мотора.","tr":"Vitesleri yumuşakça yükseltip motoru rahat bir güç aralığında tutun; bu iyi kontrol sağlar ve aşırı devir ya da motoru zorlamayı önler.","hi":"गियर सहजता से बढ़ाएँ ताकि इंजन आरामदायक पावर रेंज में चले, जो अच्छा नियंत्रण देता है और ओवर-रेव या लगिंग से बचाता है।","ar":"ارفع التروس بسلاسة لإبقاء المحرك في نطاق قدرة مريح، مما يمنحك تحكماً جيداً ويتجنب الإفراط في الدوران أو إجهاد المحرك."}},{"cat":"controls","a":3,"q":{"en":"Why is it important to keep your wrist low (flat) when operating the throttle?","es":"¿Por qué es importante mantener la muñeca baja (plana) al usar el acelerador?","ru":"Почему важно держать запястье низко (ровно) при работе с газом?","tr":"Gazı kullanırken bileğinizi alçak (düz) tutmak neden önemlidir?","hi":"थ्रॉटल चलाते समय कलाई नीची (सपाट) रखना क्यों महत्वपूर्ण है?","ar":"لماذا من المهم إبقاء معصمك منخفضاً (مسطّحاً) عند استخدام الخانق؟"},"o":[{"en":"It makes shifting faster","es":"Hace los cambios más rápidos","ru":"Ускоряет переключение передач","tr":"Vites değiştirmeyi hızlandırır","hi":"गियर बदलना तेज करता है","ar":"يجعل تغيير التروس أسرع"},{"en":"It cools the engine","es":"Enfría el motor","ru":"Охлаждает двигатель","tr":"Motoru soğutur","hi":"इंजन को ठंडा करता है","ar":"يبرّد المحرك"},{"en":"It improves the mirrors' view","es":"Mejora la vista de los espejos","ru":"Улучшает обзор в зеркала","tr":"Ayna görüşünü iyileştirir","hi":"शीशों का दृश्य बेहतर करता है","ar":"يحسّن رؤية المرايا"},{"en":"It helps prevent accidentally applying too much throttle","es":"Ayuda a evitar dar acelerador de más sin querer","ru":"Помогает не дать случайно слишком много газа","tr":"Kazayla fazla gaz vermeyi önlemeye yardımcı olur","hi":"अनजाने में बहुत ज्यादा थ्रॉटल देने से बचाता है","ar":"يساعد على منع إعطاء خانق زائد عن غير قصد"}],"e":{"en":"Keeping the wrist flat prevents you from accidentally rolling on too much throttle, especially if you are jolted, giving smoother and safer control.","es":"Mantener la muñeca plana evita que dé acelerador de más sin querer, sobre todo ante una sacudida, y ofrece un control más suave y seguro.","ru":"Ровное запястье не даёт случайно прибавить слишком много газа, особенно при толчке, обеспечивая более плавное и безопасное управление.","tr":"Bileği düz tutmak, özellikle sarsıldığınızda kazayla fazla gaz vermenizi önler ve daha yumuşak, daha güvenli kontrol sağlar.","hi":"कलाई सपाट रखने से आप अनजाने में बहुत ज्यादा थ्रॉटल नहीं देते, खासकर झटका लगने पर, जिससे नियंत्रण अधिक सहज और सुरक्षित रहता है।","ar":"إبقاء المعصم مسطّحاً يمنعك من إعطاء خانق زائد عن غير قصد، خاصة عند التعرّض لهزّة، مما يمنح تحكماً أكثر سلاسة وأماناً."}},{"cat":"controls","a":2,"q":{"en":"When you park a motorcycle, in which gear should you usually leave it?","es":"Al estacionar una motocicleta, ¿en qué marcha debe dejarla normalmente?","ru":"Когда паркуете мотоцикл, на какой передаче обычно его оставлять?","tr":"Bir motosikleti park ederken genellikle hangi viteste bırakmalısınız?","hi":"मोटरसाइकिल पार्क करते समय आमतौर पर इसे किस गियर में छोड़ना चाहिए?","ar":"عند ركن الدراجة النارية، في أي ترس يجب أن تتركها عادةً؟"},"o":[{"en":"In neutral","es":"En punto muerto","ru":"На нейтрали","tr":"Boşta","hi":"न्यूट्रल में","ar":"في الوضع المحايد"},{"en":"In the highest gear","es":"En la marcha más alta","ru":"На высшей передаче","tr":"En yüksek viteste","hi":"सबसे ऊँचे गियर में","ar":"في أعلى ترس"},{"en":"In first gear","es":"En primera","ru":"На первой передаче","tr":"Birinci viteste","hi":"पहले गियर में","ar":"في الترس الأول"},{"en":"In any gear except first","es":"En cualquier marcha menos primera","ru":"На любой передаче, кроме первой","tr":"Birinci hariç herhangi bir viteste","hi":"पहले को छोड़कर किसी भी गियर में","ar":"في أي ترس عدا الأول"}],"e":{"en":"Leaving the motorcycle in first gear when parked helps keep it from rolling, especially on a slope; you can shift to neutral once it is on its stand and stable.","es":"Dejar la moto en primera al estacionar ayuda a evitar que ruede, sobre todo en pendiente; puede poner punto muerto una vez que esté en el caballete y estable.","ru":"Оставленная на первой передаче припаркованная машина не покатится, особенно на склоне; на нейтраль можно перейти, когда она устойчиво стоит на подножке.","tr":"Park ederken motosikleti birinci viteste bırakmak, özellikle eğimde kaymasını önlemeye yardımcı olur; sehpaya alıp sabitledikten sonra boşa alabilirsiniz.","hi":"पार्क करते समय मोटरसाइकिल को पहले गियर में छोड़ना उसे लुढ़कने से रोकता है, खासकर ढलान पर; स्टैंड पर स्थिर होने पर आप न्यूट्रल में डाल सकते हैं।","ar":"ترك الدراجة في الترس الأول عند الركن يساعد على منع تدحرجها، خاصة على منحدر؛ ويمكنك التحويل إلى المحايد بعد وضعها على الحامل واستقرارها."}},{"cat":"controls","a":3,"q":{"en":"What is the safest way to hold the front brake lever during normal riding?","es":"¿Cuál es la forma más segura de tener la palanca del freno delantero durante la conducción normal?","ru":"Как безопаснее всего держать рычаг переднего тормоза при обычной езде?","tr":"Normal sürüşte ön fren kolunu tutmanın en güvenli yolu nedir?","hi":"सामान्य राइडिंग के दौरान फ्रंट ब्रेक लीवर को पकड़ने का सबसे सुरक्षित तरीका क्या है?","ar":"ما الطريقة الأكثر أماناً لإمساك ذراع الفرامل الأمامية أثناء القيادة العادية؟"},"o":[{"en":"Squeeze it partly at all times","es":"Apretarla parcialmente en todo momento","ru":"Постоянно держать его слегка нажатым","tr":"Her zaman kısmen basılı tutmak","hi":"हर समय इसे आंशिक रूप से दबाए रखना","ar":"الضغط عليها جزئياً طوال الوقت"},{"en":"Cover it only when going downhill","es":"Cubrirla solo al bajar pendientes","ru":"Держать пальцы над ним только на спусках","tr":"Yalnızca yokuş aşağı inerken üzerinde tutmak","hi":"केवल ढलान पर इसे कवर करना","ar":"وضع الأصابع عليها فقط عند النزول"},{"en":"Rest your whole weight on it","es":"Apoyar todo su peso en ella","ru":"Опираться на него всем весом","tr":"Tüm ağırlığınızı ona vermek","hi":"अपना पूरा वजन इस पर टिकाना","ar":"إسناد كامل وزنك عليها"},{"en":"Keep fingers ready on it without squeezing until needed","es":"Mantener los dedos listos sobre ella sin apretar hasta que haga falta","ru":"Держать пальцы наготове на нём, не нажимая, пока не нужно","tr":"Gerekene kadar sıkmadan parmakları hazır tutmak","hi":"जरूरत पड़ने तक बिना दबाए उंगलियाँ इस पर तैयार रखना","ar":"إبقاء الأصابع جاهزة عليها دون ضغط حتى الحاجة"}],"e":{"en":"Riding with fingers resting over (covering) the front brake lets you react faster in an emergency, but you should not apply pressure until you actually need to brake.","es":"Conducir con los dedos apoyados sobre (cubriendo) el freno delantero permite reaccionar más rápido en una emergencia, pero no debe aplicar presión hasta que realmente necesite frenar.","ru":"Езда с пальцами над рычагом переднего тормоза позволяет быстрее среагировать в экстренной ситуации, но давить не следует, пока действительно не понадобится торможение.","tr":"Parmakları ön frenin üzerinde tutarak (kaplayarak) sürmek acil durumda daha hızlı tepki vermenizi sağlar, ancak gerçekten frenlemeniz gerekene kadar basınç uygulamamalısınız.","hi":"फ्रंट ब्रेक पर उंगलियाँ रखकर (कवर करके) चलाना आपात स्थिति में तेज प्रतिक्रिया देता है, पर जब तक वास्तव में ब्रेक की जरूरत न हो, दबाव न डालें।","ar":"القيادة مع وضع الأصابع فوق الفرامل الأمامية (تغطيتها) يتيح تفاعلاً أسرع في حالة الطوارئ، لكن لا تضغط حتى تحتاج فعلاً إلى الكبح."}},{"cat":"gear","a":0,"q":{"en":"Which type of helmet does the Motorcycle Operator Manual say offers the most protection?","es":"¿Qué tipo de casco dice el Manual del Operador de Motocicletas que ofrece la mayor protección?","ru":"Какой тип шлема, по данным Руководства мотоциклиста, обеспечивает наибольшую защиту?","tr":"Motosiklet Kullanıcı Kılavuzu'na göre hangi kask türü en fazla korumayı sağlar?","hi":"Motorcycle Operator Manual के अनुसार किस प्रकार का हेलमेट सबसे अधिक सुरक्षा देता है?","ar":"أي نوع من الخوذات يقول دليل مشغّل الدراجة النارية إنه يوفر أكبر حماية؟"},"o":[{"en":"A full-face helmet that covers the whole head","es":"Un casco integral que cubre toda la cabeza","ru":"Полнолицевой шлем, закрывающий всю голову","tr":"Tüm başı kapatan tam yüz (integral) kask","hi":"पूरा सिर ढकने वाला फुल-फेस हेलमेट","ar":"خوذة كاملة الوجه تغطي الرأس بأكمله"},{"en":"A half helmet that covers the top only","es":"Un medio casco que cubre solo la parte superior","ru":"Полушлем, закрывающий только макушку","tr":"Yalnızca üstü kapatan yarım kask","hi":"केवल ऊपरी हिस्सा ढकने वाला हाफ हेलमेट","ar":"نصف خوذة تغطي الجزء العلوي فقط"},{"en":"A novelty helmet","es":"Un casco de fantasía (no homologado)","ru":"Сувенирный (несертифицированный) шлем","tr":"Süs (onaysız) kask","hi":"नकली (नॉवेल्टी) हेलमेट","ar":"خوذة زخرفية (غير معتمدة)"},{"en":"Any cap-style helmet","es":"Cualquier casco tipo gorra","ru":"Любой шлем в виде кепки","tr":"Şapka tarzı herhangi bir kask","hi":"कोई भी कैप-शैली का हेलमेट","ar":"أي خوذة على شكل قبعة"}],"e":{"en":"The manual notes that helmets covering more of the head, especially full-face helmets, give the most protection because they also shield the face and chin.","es":"El manual señala que los cascos que cubren más la cabeza, sobre todo los integrales, dan la mayor protección porque también protegen la cara y el mentón.","ru":"Руководство отмечает, что шлемы, закрывающие большую часть головы, особенно полнолицевые, дают наибольшую защиту, так как прикрывают также лицо и подбородок.","tr":"Kılavuz, başın daha fazlasını kapatan kaskların, özellikle tam yüz kaskların en fazla korumayı sağladığını belirtir çünkü yüzü ve çeneyi de korurlar.","hi":"मैनुअल बताता है कि सिर को अधिक ढकने वाले हेलमेट, खासकर फुल-फेस, सबसे अधिक सुरक्षा देते हैं क्योंकि वे चेहरे और ठुड्डी की भी रक्षा करते हैं।","ar":"يشير الدليل إلى أن الخوذات التي تغطي جزءاً أكبر من الرأس، خاصة كاملة الوجه، توفر أكبر حماية لأنها تحمي الوجه والذقن أيضاً."}},{"cat":"gear","a":1,"q":{"en":"According to the manual, how should a helmet fit to protect you properly?","es":"Según el manual, ¿cómo debe quedar un casco para protegerlo adecuadamente?","ru":"Согласно руководству, как должен сидеть шлем, чтобы надёжно защищать?","tr":"Kılavuza göre, sizi düzgün koruması için kask nasıl oturmalıdır?","hi":"मैनुअल के अनुसार, आपकी ठीक से रक्षा के लिए हेलमेट कैसे फिट होना चाहिए?","ar":"وفقاً للدليل، كيف يجب أن تكون ملاءمة الخوذة لحمايتك بشكل صحيح؟"},"o":[{"en":"Loosely so air can circulate","es":"Holgado para que circule el aire","ru":"Свободно, чтобы циркулировал воздух","tr":"Havanın dolaşması için gevşek","hi":"ढीला ताकि हवा गुजर सके","ar":"فضفاضة كي يمر الهواء"},{"en":"Snugly and fastened securely","es":"Ajustado y bien abrochado","ru":"Плотно и надёжно застёгнутым","tr":"Sıkıca ve güvenli şekilde bağlanmış","hi":"कसकर और सुरक्षित रूप से बंधा हुआ","ar":"محكمة ومربوطة بإحكام"},{"en":"With the strap left undone","es":"Con la correa sin abrochar","ru":"С незастёгнутым ремешком","tr":"Kayışı bağlanmadan","hi":"पट्टा खुला रखते हुए","ar":"مع ترك الحزام غير مربوط"},{"en":"Tilted back off the forehead","es":"Inclinado hacia atrás dejando libre la frente","ru":"Сдвинутым назад, открывая лоб","tr":"Alnı açıkta bırakacak şekilde geriye yatık","hi":"माथे से पीछे झुका हुआ","ar":"مائلة للخلف كاشفة الجبين"}],"e":{"en":"A helmet must fit snugly all the way around and be fastened securely, or it can shift or come off in a crash and fail to protect you.","es":"El casco debe quedar ajustado en todo el contorno y abrochado con firmeza, o podría moverse o salirse en un choque y no protegerlo.","ru":"Шлем должен плотно сидеть по всей голове и быть надёжно застёгнут, иначе он может сместиться или слететь при аварии и не защитить вас.","tr":"Kask her yönden sıkı oturmalı ve güvenli biçimde bağlanmalıdır; aksi halde kazada kayabilir veya çıkabilir ve sizi koruyamaz.","hi":"हेलमेट चारों ओर से कसकर फिट होना चाहिए और सुरक्षित रूप से बंधा होना चाहिए, वरना दुर्घटना में यह खिसक या उतर सकता है और रक्षा नहीं कर पाएगा।","ar":"يجب أن تكون الخوذة محكمة من كل الجهات ومربوطة جيداً، وإلا فقد تنزلق أو تسقط في الحادث ولا تحميك."}},{"cat":"gear","a":2,"q":{"en":"What color clothing does the manual recommend for daytime riding to be most visible?","es":"¿Qué color de ropa recomienda el manual para conducir de día y ser más visible?","ru":"Одежду какого цвета руководство рекомендует для дневной езды, чтобы быть заметнее?","tr":"Kılavuz, gündüz sürüşünde en görünür olmak için hangi renk giysiyi önerir?","hi":"दिन में सबसे अधिक दिखने के लिए मैनुअल किस रंग के कपड़ों की सलाह देता है?","ar":"ما لون الملابس الذي يوصي به الدليل للقيادة نهاراً لتكون أكثر وضوحاً؟"},"o":[{"en":"Dark colors like black","es":"Colores oscuros como el negro","ru":"Тёмные цвета, например чёрный","tr":"Siyah gibi koyu renkler","hi":"काले जैसे गहरे रंग","ar":"ألوان داكنة مثل الأسود"},{"en":"Earth tones like brown","es":"Tonos tierra como el marrón","ru":"Землистые тона, например коричневый","tr":"Kahverengi gibi toprak tonları","hi":"भूरे जैसे मिट्टी के रंग","ar":"ألوان ترابية مثل البني"},{"en":"Bright or fluorescent colors","es":"Colores brillantes o fluorescentes","ru":"Яркие или флуоресцентные цвета","tr":"Parlak veya floresan renkler","hi":"चमकीले या फ्लोरोसेंट रंग","ar":"ألوان زاهية أو فسفورية"},{"en":"Matte gray shades","es":"Tonos gris mate","ru":"Матовые серые оттенки","tr":"Mat gri tonlar","hi":"मैट स्लेटी रंग","ar":"درجات رمادية غير لامعة"}],"e":{"en":"Bright or fluorescent jackets, vests and helmets make you far easier for other drivers to see in daylight than dark clothing.","es":"Las chaquetas, chalecos y cascos brillantes o fluorescentes hacen que otros conductores lo vean mucho más fácil de día que con ropa oscura.","ru":"Яркие или флуоресцентные куртки, жилеты и шлемы делают вас гораздо заметнее для других водителей днём, чем тёмная одежда.","tr":"Parlak veya floresan mont, yelek ve kasklar, gündüz koyu giysilere kıyasla diğer sürücülerin sizi çok daha kolay görmesini sağlar.","hi":"चमकीले या फ्लोरोसेंट जैकेट, वेस्ट और हेलमेट दिन में गहरे कपड़ों की तुलना में आपको दूसरों को कहीं आसानी से दिखने योग्य बनाते हैं।","ar":"السترات والصداري والخوذات الزاهية أو الفسفورية تجعل رؤيتك أسهل بكثير للسائقين الآخرين نهاراً مقارنة بالملابس الداكنة."}},{"cat":"gear","a":3,"q":{"en":"Why does the manual recommend wearing boots or shoes that cover the ankles?","es":"¿Por qué recomienda el manual usar botas o zapatos que cubran los tobillos?","ru":"Почему руководство советует носить ботинки или обувь, закрывающие щиколотки?","tr":"Kılavuz neden ayak bileğini kapatan bot veya ayakkabı giymeyi önerir?","hi":"मैनुअल टखनों को ढकने वाले बूट या जूते पहनने की सलाह क्यों देता है?","ar":"لماذا يوصي الدليل بارتداء أحذية تغطي الكاحلين؟"},"o":[{"en":"To improve fuel economy","es":"Para mejorar el consumo de combustible","ru":"Чтобы улучшить расход топлива","tr":"Yakıt ekonomisini iyileştirmek için","hi":"ईंधन दक्षता सुधारने के लिए","ar":"لتحسين استهلاك الوقود"},{"en":"To make shifting quieter","es":"Para hacer los cambios más silenciosos","ru":"Чтобы переключение было тише","tr":"Vites değiştirmeyi sessizleştirmek için","hi":"गियर बदलना शांत करने के लिए","ar":"لجعل تغيير التروس أهدأ"},{"en":"To keep your feet warm only","es":"Solo para mantener los pies calientes","ru":"Только чтобы держать ноги в тепле","tr":"Yalnızca ayakları sıcak tutmak için","hi":"केवल पैर गर्म रखने के लिए","ar":"للحفاظ على دفء القدمين فقط"},{"en":"To protect your feet and ankles and give a firm footing","es":"Para proteger pies y tobillos y dar un apoyo firme","ru":"Чтобы защитить стопы и щиколотки и дать надёжную опору","tr":"Ayakları ve bilekleri korumak ve sağlam basış sağlamak için","hi":"पैरों और टखनों की रक्षा और मजबूत पकड़ देने के लिए","ar":"لحماية القدمين والكاحلين وتوفير ثبات في الوقوف"}],"e":{"en":"Sturdy over-the-ankle boots protect your feet and ankles in a fall and give firm support when you put your feet down or operate the controls.","es":"Las botas resistentes por encima del tobillo protegen pies y tobillos en una caída y dan un apoyo firme al poner los pies o usar los controles.","ru":"Прочные ботинки выше щиколотки защищают стопы и щиколотки при падении и дают надёжную опору, когда вы ставите ноги или работаете органами управления.","tr":"Sağlam, bilek üstü botlar düşmede ayakları ve bilekleri korur; ayağınızı yere koyarken veya kumandaları kullanırken sağlam destek verir.","hi":"मजबूत, टखने से ऊपर के बूट गिरने पर पैरों और टखनों की रक्षा करते हैं और पैर रखने या नियंत्रण चलाते समय मजबूत सहारा देते हैं।","ar":"الأحذية المتينة التي تتجاوز الكاحل تحمي القدمين والكاحلين عند السقوط وتمنح ثباتاً عند وضع القدمين أو استخدام أدوات التحكم."}},{"cat":"gear","a":0,"q":{"en":"According to the manual, gloves for riding should ideally be made of what?","es":"Según el manual, los guantes para conducir deberían ser idealmente de qué material?","ru":"По руководству, из чего в идеале должны быть перчатки для езды?","tr":"Kılavuza göre, sürüş eldivenleri ideal olarak neyden yapılmış olmalıdır?","hi":"मैनुअल के अनुसार, राइडिंग दस्ताने आदर्श रूप से किससे बने होने चाहिए?","ar":"وفقاً للدليل، من أي مادة يُفضّل أن تُصنع قفازات القيادة؟"},"o":[{"en":"Leather or other durable material","es":"Cuero u otro material resistente","ru":"Кожа или другой прочный материал","tr":"Deri veya başka dayanıklı bir malzeme","hi":"चमड़ा या अन्य टिकाऊ सामग्री","ar":"الجلد أو مادة متينة أخرى"},{"en":"Thin cotton","es":"Algodón delgado","ru":"Тонкий хлопок","tr":"İnce pamuk","hi":"पतला सूती कपड़ा","ar":"قطن رقيق"},{"en":"Loose wool","es":"Lana suelta","ru":"Свободная шерсть","tr":"Bol yün","hi":"ढीली ऊन","ar":"صوف فضفاض"},{"en":"No material; bare hands grip better","es":"Ningún material; las manos desnudas agarran mejor","ru":"Без материала; голые руки держат лучше","tr":"Hiçbir malzeme; çıplak eller daha iyi tutar","hi":"कोई सामग्री नहीं; नंगे हाथ बेहतर पकड़ते हैं","ar":"بلا مادة؛ اليدان العاريتان تُمسكان أفضل"}],"e":{"en":"The manual recommends full-fingered gloves of leather or similarly durable material, which protect your hands and improve your grip on the controls.","es":"El manual recomienda guantes de dedos completos de cuero o material igual de resistente, que protegen las manos y mejoran el agarre en los controles.","ru":"Руководство рекомендует перчатки с полными пальцами из кожи или столь же прочного материала — они защищают руки и улучшают хват на органах управления.","tr":"Kılavuz, elleri koruyan ve kumandalardaki kavramayı artıran, deri veya benzer dayanıklı malzemeden tam parmaklı eldivenler önerir.","hi":"मैनुअल चमड़े या समान टिकाऊ सामग्री के पूर्ण-उंगली दस्ताने की सलाह देता है, जो हाथों की रक्षा करते हैं और नियंत्रण पर पकड़ बेहतर करते हैं।","ar":"يوصي الدليل بقفازات كاملة الأصابع من الجلد أو مادة متينة مماثلة، تحمي يديك وتحسّن قبضتك على أدوات التحكم."}},{"cat":"gear","a":1,"q":{"en":"What does the manual say a face shield should do besides protect your face?","es":"¿Qué dice el manual que una pantalla facial debe hacer además de proteger la cara?","ru":"Что, по руководству, должен делать лицевой щиток, помимо защиты лица?","tr":"Kılavuz, bir yüz siperinin yüzü korumanın yanında ne yapması gerektiğini söyler?","hi":"मैनुअल के अनुसार, चेहरे की रक्षा के अलावा फेस शील्ड को और क्या करना चाहिए?","ar":"ماذا يقول الدليل إن واقي الوجه يجب أن يفعله إلى جانب حماية وجهك؟"},"o":[{"en":"Darken the road completely","es":"Oscurecer la vía por completo","ru":"Полностью затемнять дорогу","tr":"Yolu tamamen karartmak","hi":"सड़क को पूरी तरह अंधेरा करना","ar":"تعتيم الطريق بالكامل"},{"en":"Provide a clear, unobstructed view","es":"Ofrecer una vista clara y sin obstrucciones","ru":"Обеспечивать чёткий, беспрепятственный обзор","tr":"Net ve engelsiz bir görüş sağlamak","hi":"स्पष्ट, बाधारहित दृश्य देना","ar":"توفير رؤية واضحة وغير معوّقة"},{"en":"Amplify engine sound","es":"Amplificar el sonido del motor","ru":"Усиливать звук двигателя","tr":"Motor sesini yükseltmek","hi":"इंजन की आवाज बढ़ाना","ar":"تضخيم صوت المحرك"},{"en":"Replace your mirrors","es":"Reemplazar los espejos","ru":"Заменять зеркала","tr":"Aynalarınızın yerini almak","hi":"आपके शीशों की जगह लेना","ar":"استبدال المرايا"}],"e":{"en":"A good face shield must protect your whole face while still giving a clear, unobstructed view and staying free of scratches or fog.","es":"Una buena pantalla facial debe proteger toda la cara y a la vez dar una vista clara y sin obstrucciones, libre de rayones o empañamiento.","ru":"Хороший лицевой щиток должен защищать всё лицо, но при этом давать чёткий, беспрепятственный обзор и не иметь царапин и запотевания.","tr":"İyi bir yüz siperi tüm yüzü korurken net, engelsiz bir görüş sağlamalı ve çizik ya da buğudan uzak olmalıdır.","hi":"अच्छी फेस शील्ड पूरे चेहरे की रक्षा करे और साथ ही स्पष्ट, बाधारहित दृश्य दे तथा खरोंच या धुंध से मुक्त रहे।","ar":"يجب أن يحمي واقي الوجه الجيد وجهك بالكامل مع توفير رؤية واضحة غير معوّقة وخالٍ من الخدوش أو الضباب."}},{"cat":"gear","a":2,"q":{"en":"Why does the manual advise against tinted eye protection at night?","es":"¿Por qué desaconseja el manual la protección ocular tintada de noche?","ru":"Почему руководство не советует тонированную защиту глаз ночью?","tr":"Kılavuz neden gece renkli (koyu) göz korumasını önermez?","hi":"मैनुअल रात में रंगीन आँख सुरक्षा के खिलाफ सलाह क्यों देता है?","ar":"لماذا ينصح الدليل بعدم استخدام واقي عيون ملوّن (داكن) ليلاً؟"},"o":[{"en":"It fogs up faster","es":"Se empaña más rápido","ru":"Оно быстрее запотевает","tr":"Daha hızlı buğulanır","hi":"यह जल्दी धुंधला हो जाता है","ar":"يتضبب أسرع"},{"en":"It is illegal everywhere","es":"Es ilegal en todas partes","ru":"Это везде запрещено","tr":"Her yerde yasa dışıdır","hi":"यह हर जगह अवैध है","ar":"غير قانوني في كل مكان"},{"en":"It reduces how much you can see in the dark","es":"Reduce cuánto puede ver en la oscuridad","ru":"Оно уменьшает то, что видно в темноте","tr":"Karanlıkta görebildiğinizi azaltır","hi":"यह अंधेरे में दिखने की मात्रा घटाता है","ar":"يقلّل مقدار ما تراه في الظلام"},{"en":"It scratches more easily","es":"Se raya con más facilidad","ru":"Оно легче царапается","tr":"Daha kolay çizilir","hi":"यह आसानी से खरोंच जाता है","ar":"يُخدش بسهولة أكبر"}],"e":{"en":"Tinted shields or glasses cut down the light reaching your eyes, so they should not be used at night or in other low-light conditions where you need to see clearly.","es":"Las pantallas o gafas tintadas reducen la luz que llega a los ojos, por lo que no deben usarse de noche ni con poca luz, cuando necesita ver con claridad.","ru":"Тонированные щитки или очки уменьшают количество света, попадающего в глаза, поэтому их нельзя использовать ночью и при слабом освещении, когда нужна хорошая видимость.","tr":"Renkli siperler veya gözlükler gözünüze ulaşan ışığı azaltır; bu yüzden net görmeniz gereken gece veya az ışıklı durumlarda kullanılmamalıdır.","hi":"रंगीन शील्ड या चश्मे आँखों तक पहुँचने वाली रोशनी घटाते हैं, इसलिए रात में या कम रोशनी में, जब स्पष्ट देखना जरूरी हो, इन्हें उपयोग नहीं करना चाहिए।","ar":"الواقيات أو النظارات الملوّنة تقلّل الضوء الواصل إلى عينيك، لذا يجب عدم استخدامها ليلاً أو في الإضاءة المنخفضة حيث تحتاج إلى رؤية واضحة."}},{"cat":"gear","a":3,"q":{"en":"How should a riding jacket and pants fit for the best protection?","es":"¿Cómo deben quedar una chaqueta y un pantalón de conducir para la mejor protección?","ru":"Как должны сидеть куртка и брюки для езды ради лучшей защиты?","tr":"En iyi koruma için sürüş montu ve pantolonu nasıl oturmalıdır?","hi":"सर्वोत्तम सुरक्षा के लिए राइडिंग जैकेट और पैंट कैसे फिट होने चाहिए?","ar":"كيف يجب أن تكون ملاءمة سترة وبنطال القيادة لأفضل حماية؟"},"o":[{"en":"Very loose so they flap in the wind","es":"Muy holgados para que ondeen al viento","ru":"Очень свободно, чтобы развевались на ветру","tr":"Rüzgârda dalgalanacak kadar çok bol","hi":"बहुत ढीले ताकि हवा में फड़फड़ाएँ","ar":"فضفاضة جداً كي ترفرف في الرياح"},{"en":"So tight they restrict movement","es":"Tan ajustados que limiten el movimiento","ru":"Настолько тесно, чтобы стеснять движения","tr":"Hareketi kısıtlayacak kadar dar","hi":"इतने कसे कि हिलना-डुलना कठिन हो","ar":"ضيقة لدرجة تقيّد الحركة"},{"en":"Made only of mesh in all seasons","es":"Hechos solo de malla en todas las estaciones","ru":"Только из сетчатой ткани в любой сезон","tr":"Her mevsim yalnızca fileden yapılmış","hi":"हर मौसम में केवल जालीदार कपड़े के","ar":"مصنوعة من الشبك فقط في كل الفصول"},{"en":"Snug enough to stay in place without flapping, but allowing full movement","es":"Ajustados para no ondear pero permitiendo moverse con libertad","ru":"Достаточно облегающими, чтобы не развеваться, но не мешать движениям","tr":"Dalgalanmadan yerinde duracak kadar oturmuş, ama tam harekete izin veren","hi":"इतने फिट कि फड़फड़ाएँ नहीं पर पूरी गति की छूट दें","ar":"ملائمة بما يكفي لتبقى في مكانها دون رفرفة، مع السماح بحرية الحركة"}],"e":{"en":"Jackets and pants should fit snugly enough not to flap in the wind, yet loose enough to move freely and add layers underneath in cold weather.","es":"La chaqueta y el pantalón deben quedar lo bastante ajustados para no ondear al viento, pero lo bastante amplios para moverse con libertad y añadir capas debajo con frío.","ru":"Куртка и брюки должны сидеть достаточно плотно, чтобы не развеваться на ветру, но при этом не мешать движениям и позволять поддеть слои в холод.","tr":"Mont ve pantolon, rüzgârda dalgalanmayacak kadar oturmalı, ancak rahatça hareket etmeye ve soğukta alta kat giymeye izin verecek kadar da bol olmalıdır.","hi":"जैकेट और पैंट इतने फिट हों कि हवा में न फड़फड़ाएँ, फिर भी इतने ढीले कि स्वतंत्र गति और ठंड में नीचे परतें जोड़ी जा सकें।","ar":"يجب أن تكون السترة والبنطال ملائمة بما يكفي لعدم الرفرفة في الرياح، لكن فضفاضة بما يسمح بحرية الحركة وإضافة طبقات تحتها في البرد."}},{"cat":"gear","a":0,"q":{"en":"Besides a DOT sticker, what does the manual say a quality helmet often carries?","es":"Además de la etiqueta DOT, ¿qué dice el manual que suele llevar un casco de calidad?","ru":"Помимо наклейки DOT, что, по руководству, часто имеет качественный шлем?","tr":"DOT etiketinin yanında, kılavuz kaliteli bir kaskın genellikle neyi taşıdığını söyler?","hi":"DOT स्टिकर के अलावा, मैनुअल के अनुसार गुणवत्ता वाले हेलमेट पर अक्सर क्या होता है?","ar":"إلى جانب ملصق DOT، ماذا يقول الدليل إن الخوذة الجيدة تحمله غالباً؟"},"o":[{"en":"A label from a recognized standards organization such as Snell","es":"Una etiqueta de una organización de normas reconocida como Snell","ru":"Маркировку признанной организации стандартов, например Snell","tr":"Snell gibi tanınmış bir standart kuruluşunun etiketi","hi":"Snell जैसी मान्यता प्राप्त मानक संस्था का लेबल","ar":"ملصق من جهة معايير معترف بها مثل Snell"},{"en":"A fashion brand logo only","es":"Solo un logo de marca de moda","ru":"Только логотип модного бренда","tr":"Yalnızca bir moda markası logosu","hi":"केवल फैशन ब्रांड का लोगो","ar":"شعار علامة أزياء فقط"},{"en":"A speed rating in mph","es":"Una clasificación de velocidad en mph","ru":"Рейтинг скорости в милях/ч","tr":"Mil/saat cinsinden hız değeri","hi":"मील प्रति घंटा में गति रेटिंग","ar":"تصنيف سرعة بالميل/ساعة"},{"en":"A tire pressure chart","es":"Una tabla de presión de llantas","ru":"Таблицу давления в шинах","tr":"Lastik basıncı tablosu","hi":"टायर दबाव चार्ट","ar":"جدول ضغط الإطارات"}],"e":{"en":"In addition to meeting DOT standards, a label from a group like the Snell Memorial Foundation gives added assurance of a helmet's quality.","es":"Además de cumplir las normas DOT, una etiqueta de un grupo como la Snell Memorial Foundation da una garantía adicional de la calidad del casco.","ru":"Помимо соответствия стандартам DOT, маркировка организации вроде Snell Memorial Foundation даёт дополнительную гарантию качества шлема.","tr":"DOT standartlarını karşılamanın yanı sıra, Snell Memorial Foundation gibi bir kuruluşun etiketi kaskın kalitesine ek güvence verir.","hi":"DOT मानकों को पूरा करने के अलावा, Snell Memorial Foundation जैसी संस्था का लेबल हेलमेट की गुणवत्ता का अतिरिक्त आश्वासन देता है।","ar":"إلى جانب استيفاء معايير DOT، يمنح ملصق من جهة مثل مؤسسة Snell التذكارية ضماناً إضافياً لجودة الخوذة."}},{"cat":"gear","a":1,"q":{"en":"Why is a windshield NOT enough to protect your eyes while riding?","es":"¿Por qué un parabrisas NO basta para proteger los ojos al conducir?","ru":"Почему ветровое стекло НЕ достаточно для защиты глаз при езде?","tr":"Sürüş sırasında gözlerinizi korumak için bir ön cam neden YETERLİ değildir?","hi":"राइडिंग के दौरान आँखों की रक्षा के लिए विंडशील्ड पर्याप्त क्यों नहीं है?","ar":"لماذا لا يكفي الزجاج الأمامي وحده لحماية عينيك أثناء القيادة؟"},"o":[{"en":"It blocks the mirrors","es":"Bloquea los espejos","ru":"Оно закрывает зеркала","tr":"Aynaları engeller","hi":"यह शीशों को रोकता है","ar":"يحجب المرايا"},{"en":"It does not stop wind, dust and debris from reaching your eyes","es":"No impide que el viento, el polvo y los residuos lleguen a los ojos","ru":"Оно не защищает глаза от ветра, пыли и мусора","tr":"Rüzgâr, toz ve döküntünün gözünüze ulaşmasını engellemez","hi":"यह हवा, धूल और मलबे को आँखों तक पहुँचने से नहीं रोकता","ar":"لا يمنع الرياح والغبار والحطام من الوصول إلى عينيك"},{"en":"It is only for cold weather","es":"Es solo para clima frío","ru":"Оно только для холодной погоды","tr":"Yalnızca soğuk hava içindir","hi":"यह केवल ठंडे मौसम के लिए है","ar":"مخصص للطقس البارد فقط"},{"en":"It reduces engine cooling","es":"Reduce la refrigeración del motor","ru":"Оно ухудшает охлаждение двигателя","tr":"Motor soğutmasını azaltır","hi":"यह इंजन शीतलन घटाता है","ar":"يقلّل تبريد المحرك"}],"e":{"en":"A windshield does not fully protect your eyes; wind, dust, rain and insects can still get around it, so you also need a face shield or goggles.","es":"Un parabrisas no protege del todo los ojos; el viento, el polvo, la lluvia y los insectos pueden rodearlo, por lo que también necesita pantalla o gafas.","ru":"Ветровое стекло не защищает глаза полностью; ветер, пыль, дождь и насекомые могут его обойти, поэтому нужны ещё щиток или очки.","tr":"Ön cam gözlerinizi tam korumaz; rüzgâr, toz, yağmur ve böcekler onu aşabilir, bu yüzden ayrıca yüz siperi veya gözlük gerekir.","hi":"विंडशील्ड आँखों की पूरी रक्षा नहीं करती; हवा, धूल, बारिश और कीड़े इसके इर्द-गिर्द आ सकते हैं, इसलिए फेस शील्ड या गॉगल्स भी चाहिए।","ar":"الزجاج الأمامي لا يحمي عينيك بالكامل؛ فالرياح والغبار والمطر والحشرات قد تلتف حوله، لذا تحتاج أيضاً إلى واقٍ للوجه أو نظارات واقية."}},{"cat":"gear","a":2,"q":{"en":"Why does the manual recommend a jacket even in warm weather?","es":"¿Por qué recomienda el manual una chaqueta incluso con calor?","ru":"Почему руководство советует куртку даже в тёплую погоду?","tr":"Kılavuz neden sıcak havada bile mont önerir?","hi":"मैनुअल गर्म मौसम में भी जैकेट की सलाह क्यों देता है?","ar":"لماذا يوصي الدليل بارتداء سترة حتى في الطقس الحار؟"},"o":[{"en":"To look more professional","es":"Para verse más profesional","ru":"Чтобы выглядеть профессиональнее","tr":"Daha profesyonel görünmek için","hi":"अधिक पेशेवर दिखने के लिए","ar":"للظهور بمظهر أكثر احترافية"},{"en":"To hold more cargo","es":"Para llevar más carga","ru":"Чтобы возить больше груза","tr":"Daha fazla yük taşımak için","hi":"अधिक सामान रखने के लिए","ar":"لحمل حمولة أكبر"},{"en":"To protect against abrasion, sunburn and dehydration","es":"Para proteger contra la abrasión, quemaduras solares y deshidratación","ru":"Для защиты от ссадин, солнечных ожогов и обезвоживания","tr":"Sürtünme, güneş yanığı ve susuz kalmaya karşı korunmak için","hi":"घर्षण, धूप से जलन और निर्जलीकरण से बचाव के लिए","ar":"للحماية من الاحتكاك وحروق الشمس والجفاف"},{"en":"To reduce engine noise","es":"Para reducir el ruido del motor","ru":"Чтобы снизить шум двигателя","tr":"Motor gürültüsünü azaltmak için","hi":"इंजन की आवाज घटाने के लिए","ar":"لتقليل ضجيج المحرك"}],"e":{"en":"A proper jacket guards against road rash in a fall and also shields you from sun, wind and dehydration on warm rides; many are ventilated for hot weather.","es":"Una buena chaqueta protege de la abrasión en una caída y también del sol, el viento y la deshidratación con calor; muchas tienen ventilación para el clima cálido.","ru":"Хорошая куртка защищает от ссадин при падении, а также от солнца, ветра и обезвоживания в жару; многие модели имеют вентиляцию.","tr":"İyi bir mont, düşmede yol yanığından korur; ayrıca sıcak sürüşlerde güneş, rüzgâr ve susuzluğa karşı da korur; birçoğu sıcak hava için havalandırmalıdır.","hi":"अच्छी जैकेट गिरने पर घर्षण से बचाती है और गर्म राइड में धूप, हवा तथा निर्जलीकरण से भी; कई में गर्म मौसम के लिए वेंटिलेशन होता है।","ar":"السترة الجيدة تقي من سحجات الطريق عند السقوط، وتحميك أيضاً من الشمس والرياح والجفاف في الأجواء الحارة؛ وكثير منها مهوّى للطقس الحار."}},{"cat":"gear","a":3,"q":{"en":"What is the main reason the manual gives for wearing eye protection even with a windshield?","es":"¿Cuál es la razón principal que da el manual para usar protección ocular aun con parabrisas?","ru":"Какова главная причина, по которой руководство советует защиту глаз даже с ветровым стеклом?","tr":"Kılavuzun, ön cam olsa bile göz koruması takmak için verdiği temel neden nedir?","hi":"विंडशील्ड होने पर भी आँख सुरक्षा पहनने का मैनुअल जो मुख्य कारण देता है वह क्या है?","ar":"ما السبب الرئيسي الذي يذكره الدليل لارتداء واقي عيون حتى مع وجود زجاج أمامي؟"},"o":[{"en":"Eye protection looks better","es":"La protección ocular se ve mejor","ru":"Защита глаз выглядит лучше","tr":"Göz koruması daha iyi görünür","hi":"आँख सुरक्षा बेहतर दिखती है","ar":"واقي العيون يبدو أفضل"},{"en":"It keeps insects off the windshield","es":"Mantiene los insectos fuera del parabrisas","ru":"Оно защищает ветровое стекло от насекомых","tr":"Böcekleri ön camdan uzak tutar","hi":"यह कीड़ों को विंडशील्ड से दूर रखता है","ar":"يبقي الحشرات بعيدة عن الزجاج الأمامي"},{"en":"It is required to start the engine","es":"Es obligatorio para arrancar el motor","ru":"Оно нужно для запуска двигателя","tr":"Motoru çalıştırmak için gereklidir","hi":"इंजन शुरू करने के लिए आवश्यक है","ar":"مطلوب لتشغيل المحرك"},{"en":"Wind or objects can still reach your eyes and blur your vision","es":"El viento u objetos aún pueden llegar a los ojos y nublar la visión","ru":"Ветер или предметы всё ещё могут попасть в глаза и ухудшить зрение","tr":"Rüzgâr veya cisimler yine de gözünüze ulaşıp görüşünüzü bulanıklaştırabilir","hi":"हवा या वस्तुएँ फिर भी आँखों तक पहुँचकर दृष्टि धुंधली कर सकती हैं","ar":"قد تصل الرياح أو الأجسام إلى عينيك وتشوّش رؤيتك"}],"e":{"en":"Even behind a windshield, wind, dust or flying objects can reach your eyes and blur your vision, so separate eye or face protection is still needed.","es":"Incluso tras un parabrisas, el viento, el polvo o los objetos pueden llegar a los ojos y nublar la visión, por lo que sigue siendo necesaria protección ocular o facial aparte.","ru":"Даже за ветровым стеклом ветер, пыль или летящие предметы могут попасть в глаза и размыть зрение, поэтому нужна отдельная защита глаз или лица.","tr":"Ön camın arkasında bile rüzgâr, toz veya uçan cisimler gözünüze ulaşıp görüşünüzü bulanıklaştırabilir; bu yüzden ayrı göz veya yüz koruması yine gerekir.","hi":"विंडशील्ड के पीछे भी हवा, धूल या उड़ती वस्तुएँ आँखों तक पहुँचकर दृष्टि धुंधली कर सकती हैं, इसलिए अलग आँख या चेहरा सुरक्षा फिर भी जरूरी है।","ar":"حتى خلف الزجاج الأمامي، قد تصل الرياح أو الغبار أو الأجسام الطائرة إلى عينيك وتشوّش رؤيتك، لذا يبقى واقي العيون أو الوجه المنفصل ضرورياً."}},{"cat":"gear","a":0,"q":{"en":"According to the manual, when is wearing reflective material most valuable?","es":"Según el manual, ¿cuándo es más valioso llevar material reflectante?","ru":"Согласно руководству, когда светоотражающий материал наиболее полезен?","tr":"Kılavuza göre, yansıtıcı malzeme giymek ne zaman en değerlidir?","hi":"मैनुअल के अनुसार, परावर्तक सामग्री पहनना कब सबसे मूल्यवान है?","ar":"وفقاً للدليل، متى يكون ارتداء المواد العاكسة أكثر قيمة؟"},"o":[{"en":"At night and in low light","es":"De noche y con poca luz","ru":"Ночью и при слабом освещении","tr":"Gece ve az ışıkta","hi":"रात में और कम रोशनी में","ar":"ليلاً وفي الإضاءة المنخفضة"},{"en":"Only on the highway","es":"Solo en la autopista","ru":"Только на автомагистрали","tr":"Yalnızca otoyolda","hi":"केवल राजमार्ग पर","ar":"على الطريق السريع فقط"},{"en":"Only when it rains","es":"Solo cuando llueve","ru":"Только когда идёт дождь","tr":"Yalnızca yağmur yağdığında","hi":"केवल जब बारिश हो","ar":"فقط عندما تمطر"},{"en":"Only in parking lots","es":"Solo en estacionamientos","ru":"Только на парковках","tr":"Yalnızca otoparklarda","hi":"केवल पार्किंग में","ar":"في مواقف السيارات فقط"}],"e":{"en":"Reflective material on your jacket, vest and helmet is especially important at night and in low light, when bright colors alone are hard to see.","es":"El material reflectante en chaqueta, chaleco y casco es especialmente importante de noche y con poca luz, cuando los colores brillantes por sí solos se ven mal.","ru":"Светоотражающий материал на куртке, жилете и шлеме особенно важен ночью и при слабом свете, когда одни только яркие цвета плохо видны.","tr":"Mont, yelek ve kaskınızdaki yansıtıcı malzeme, özellikle gece ve az ışıkta önemlidir; çünkü o zaman yalnızca parlak renkler zor görülür.","hi":"जैकेट, वेस्ट और हेलमेट पर परावर्तक सामग्री रात और कम रोशनी में खासकर जरूरी है, जब अकेले चमकीले रंग कठिनाई से दिखते हैं।","ar":"المواد العاكسة على سترتك وصدارك وخوذتك مهمة خاصة ليلاً وفي الإضاءة المنخفضة، حين يصعب رؤية الألوان الزاهية وحدها."}},{"cat":"gear","a":1,"q":{"en":"What does the manual say about wearing shorts and sandals to ride in hot weather?","es":"¿Qué dice el manual sobre usar pantalones cortos y sandalias para conducir con calor?","ru":"Что руководство говорит о шортах и сандалиях для езды в жару?","tr":"Kılavuz, sıcak havada şort ve sandaletle sürmek konusunda ne der?","hi":"गर्म मौसम में शॉर्ट्स और सैंडल पहनकर चलाने के बारे में मैनुअल क्या कहता है?","ar":"ماذا يقول الدليل عن ارتداء الشورت والصنادل للقيادة في الطقس الحار؟"},"o":[{"en":"It is fine as long as you go slowly","es":"Está bien mientras vaya despacio","ru":"Это нормально, если ехать медленно","tr":"Yavaş gittiğiniz sürece sorun yok","hi":"धीरे चलने तक ठीक है","ar":"لا بأس ما دمت تسير ببطء"},{"en":"It leaves your skin unprotected and should be avoided","es":"Deja la piel desprotegida y debe evitarse","ru":"Это оставляет кожу незащищённой, и этого следует избегать","tr":"Cildinizi korumasız bırakır ve bundan kaçınılmalıdır","hi":"यह त्वचा को असुरक्षित छोड़ता है और इससे बचना चाहिए","ar":"يترك جلدك دون حماية ويجب تجنّبه"},{"en":"It improves cooling and is recommended","es":"Mejora la refrigeración y se recomienda","ru":"Это улучшает охлаждение и рекомендуется","tr":"Serinlemeyi artırır ve önerilir","hi":"यह ठंडक बढ़ाता है और अनुशंसित है","ar":"يحسّن التبريد ويُوصى به"},{"en":"It is required by the manual","es":"Es exigido por el manual","ru":"Это требуется руководством","tr":"Kılavuz tarafından zorunlu tutulur","hi":"मैनुअल द्वारा आवश्यक है","ar":"مطلوب بموجب الدليل"}],"e":{"en":"Shorts, short sleeves and sandals leave skin exposed to serious injury in even a minor fall; the manual advises covering arms, legs and feet with sturdy gear.","es":"Los pantalones cortos, las mangas cortas y las sandalias dejan la piel expuesta a lesiones graves incluso en una caída menor; el manual aconseja cubrir brazos, piernas y pies con equipo resistente.","ru":"Шорты, короткие рукава и сандалии оставляют кожу открытой для серьёзных травм даже при лёгком падении; руководство советует закрывать руки, ноги и стопы прочной экипировкой.","tr":"Şort, kısa kol ve sandalet, hafif bir düşmede bile cildi ciddi yaralanmaya açık bırakır; kılavuz kolları, bacakları ve ayakları sağlam ekipmanla örtmeyi önerir.","hi":"शॉर्ट्स, छोटी आस्तीन और सैंडल मामूली गिरावट में भी त्वचा को गंभीर चोट के लिए खुला छोड़ते हैं; मैनुअल हाथ, पैर और तलवों को मजबूत गियर से ढकने की सलाह देता है।","ar":"الشورت والأكمام القصيرة والصنادل تترك الجلد عرضة لإصابات خطيرة حتى في سقوط بسيط؛ ينصح الدليل بتغطية الذراعين والساقين والقدمين بمعدات متينة."}},{"cat":"gear","a":2,"q":{"en":"What is one sign that a helmet no longer offers full protection and should be replaced?","es":"¿Cuál es una señal de que un casco ya no ofrece protección total y debe reemplazarse?","ru":"Каков один из признаков того, что шлем больше не защищает полностью и подлежит замене?","tr":"Bir kaskın artık tam koruma sağlamadığını ve değiştirilmesi gerektiğini gösteren bir işaret nedir?","hi":"यह किसका एक संकेत है कि हेलमेट अब पूरी सुरक्षा नहीं देता और बदला जाना चाहिए?","ar":"ما إحدى العلامات على أن الخوذة لم تعد توفر حماية كاملة ويجب استبدالها؟"},"o":[{"en":"The color has faded slightly","es":"El color se ha desteñido un poco","ru":"Цвет немного выцвел","tr":"Rengi biraz solmuş","hi":"रंग थोड़ा फीका पड़ गया है","ar":"بهت لونها قليلاً"},{"en":"It has a new strap","es":"Tiene una correa nueva","ru":"У него новый ремешок","tr":"Yeni bir kayışı var","hi":"इसमें नया पट्टा है","ar":"لديها حزام جديد"},{"en":"It has been dropped hard or worn in a crash","es":"Se ha caído con fuerza o se usó en un choque","ru":"Он сильно падал или был в аварии","tr":"Sert düşmüş veya bir kazada kullanılmış","hi":"यह जोर से गिरा है या दुर्घटना में पहना गया है","ar":"سقطت بقوة أو ارتُديت في حادث"},{"en":"It has a tinted visor","es":"Tiene una visera tintada","ru":"У него тонированный визор","tr":"Renkli bir vizörü var","hi":"इसमें रंगीन वाइज़र है","ar":"لديها واقٍ ملوّن"}],"e":{"en":"A helmet that has taken a hard impact in a crash or serious drop may have hidden damage and should be replaced, since it may not protect you again.","es":"Un casco que ha recibido un fuerte impacto en un choque o una caída seria puede tener daños ocultos y debe reemplazarse, pues quizá no vuelva a protegerlo.","ru":"Шлем, принявший сильный удар в аварии или при серьёзном падении, может иметь скрытые повреждения и подлежит замене, так как повторно может не защитить.","tr":"Bir kazada veya ciddi düşmede sert darbe almış bir kaskın gizli hasarı olabilir ve değiştirilmelidir; çünkü sizi tekrar korumayabilir.","hi":"जिस हेलमेट को दुर्घटना या गंभीर गिरावट में तेज झटका लगा हो उसमें छिपी क्षति हो सकती है और उसे बदला जाना चाहिए, क्योंकि वह दोबारा रक्षा न कर पाए।","ar":"الخوذة التي تلقت صدمة قوية في حادث أو سقوط شديد قد يكون بها ضرر خفي ويجب استبدالها، لأنها قد لا تحميك مرة أخرى."}},{"cat":"gear","a":3,"q":{"en":"For riding in the rain, what does the manual suggest about your gear?","es":"Para conducir bajo la lluvia, ¿qué sugiere el manual sobre su equipo?","ru":"Что руководство советует относительно экипировки для езды под дождём?","tr":"Yağmurda sürüş için kılavuz ekipmanınız hakkında ne önerir?","hi":"बारिश में चलाने के लिए मैनुअल आपके गियर के बारे में क्या सुझाव देता है?","ar":"للقيادة في المطر، بماذا يوصي الدليل بشأن معداتك؟"},"o":[{"en":"Wear nothing extra; get wet to stay cool","es":"No usar nada extra; mojarse para refrescarse","ru":"Не надевать ничего дополнительного; промокнуть, чтобы охладиться","tr":"Ekstra hiçbir şey giymemek; serin kalmak için ıslanmak","hi":"कुछ अतिरिक्त न पहनें; ठंडा रहने के लिए भीगें","ar":"عدم ارتداء شيء إضافي؛ والبلل للبقاء منتعشاً"},{"en":"Only a helmet is needed in rain","es":"Solo se necesita el casco bajo la lluvia","ru":"В дождь нужен только шлем","tr":"Yağmurda yalnızca kask gerekir","hi":"बारिश में केवल हेलमेट चाहिए","ar":"يكفي الخوذة فقط في المطر"},{"en":"Remove gloves for better grip when wet","es":"Quitarse los guantes para mejor agarre en mojado","ru":"Снять перчатки для лучшего хвата в мокрую погоду","tr":"Islakta daha iyi kavrama için eldivenleri çıkarmak","hi":"गीले में बेहतर पकड़ के लिए दस्ताने उतारें","ar":"خلع القفازات لقبضة أفضل عند البلل"},{"en":"Wear waterproof gear to stay dry and avoid getting chilled","es":"Usar equipo impermeable para mantenerse seco y evitar enfriarse","ru":"Носить водонепроницаемую экипировку, чтобы оставаться сухим и не замёрзнуть","tr":"Kuru kalmak ve üşümemek için su geçirmez ekipman giymek","hi":"सूखा रहने और ठंड से बचने के लिए वाटरप्रूफ गियर पहनें","ar":"ارتداء معدات مقاومة للماء للبقاء جافاً وتجنّب البرد"}],"e":{"en":"Waterproof clothing keeps you dry and warm; getting wet and chilled reduces concentration and control, so the manual advises rain gear for wet rides.","es":"La ropa impermeable lo mantiene seco y abrigado; mojarse y enfriarse reduce la concentración y el control, por eso el manual aconseja equipo de lluvia.","ru":"Водонепроницаемая одежда сохраняет вас сухим и тёплым; промокание и переохлаждение снижают концентрацию и контроль, поэтому руководство советует дождевую экипировку.","tr":"Su geçirmez giysiler sizi kuru ve sıcak tutar; ıslanıp üşümek konsantrasyonu ve kontrolü azaltır, bu yüzden kılavuz ıslak sürüşlerde yağmurluk önerir.","hi":"वाटरप्रूफ कपड़े आपको सूखा और गर्म रखते हैं; भीगने और ठिठुरने से एकाग्रता व नियंत्रण घटता है, इसलिए मैनुअल गीली राइड में रेन गियर की सलाह देता है।","ar":"الملابس المقاومة للماء تُبقيك جافاً ودافئاً؛ فالبلل والبرد يقلّلان التركيز والسيطرة، لذا ينصح الدليل بمعدات المطر في القيادة تحت المطر."}},{"cat":"gear","a":0,"q":{"en":"What does the manual say about hearing protection on long rides?","es":"¿Qué dice el manual sobre la protección auditiva en viajes largos?","ru":"Что руководство говорит о защите слуха в дальних поездках?","tr":"Kılavuz, uzun sürüşlerde işitme koruması hakkında ne der?","hi":"लंबी राइड पर श्रवण सुरक्षा के बारे में मैनुअल क्या कहता है?","ar":"ماذا يقول الدليل عن حماية السمع في الرحلات الطويلة؟"},"o":[{"en":"Long-term wind and engine noise can harm hearing, so ear protection can help","es":"El ruido prolongado del viento y del motor puede dañar la audición, por lo que la protección auditiva ayuda","ru":"Длительный шум ветра и двигателя может навредить слуху, поэтому защита ушей полезна","tr":"Uzun süreli rüzgâr ve motor gürültüsü işitmeye zarar verebilir, bu yüzden kulak koruması yardımcı olabilir","hi":"लंबे समय तक हवा और इंजन का शोर श्रवण को नुकसान पहुँचा सकता है, इसलिए कान की सुरक्षा मदद करती है","ar":"ضجيج الرياح والمحرك لفترات طويلة قد يضر السمع، لذا قد تساعد حماية الأذن"},{"en":"It is never needed at any speed","es":"Nunca es necesaria a ninguna velocidad","ru":"Она никогда не нужна ни на какой скорости","tr":"Hiçbir hızda asla gerekmez","hi":"किसी भी गति पर कभी जरूरत नहीं","ar":"لا حاجة لها إطلاقاً عند أي سرعة"},{"en":"It blocks all warning sounds and is banned","es":"Bloquea todos los sonidos de advertencia y está prohibida","ru":"Она блокирует все предупреждающие звуки и запрещена","tr":"Tüm uyarı seslerini engeller ve yasaktır","hi":"यह सभी चेतावनी ध्वनियाँ रोकती है और प्रतिबंधित है","ar":"تحجب كل أصوات التحذير وممنوعة"},{"en":"Only passengers need it","es":"Solo la necesitan los pasajeros","ru":"Она нужна только пассажирам","tr":"Yalnızca yolcular buna ihtiyaç duyar","hi":"केवल सवारियों को इसकी जरूरत है","ar":"يحتاجها الركاب فقط"}],"e":{"en":"Long exposure to wind and engine noise can permanently damage hearing; proper earplugs still let you hear important sounds like horns and sirens.","es":"La exposición prolongada al ruido del viento y del motor puede dañar la audición de forma permanente; los buenos tapones aún permiten oír bocinas y sirenas.","ru":"Длительное воздействие шума ветра и двигателя может необратимо повредить слух; правильные беруши всё же позволяют слышать важные звуки — сигналы и сирены.","tr":"Rüzgâr ve motor gürültüsüne uzun süre maruz kalmak işitmeye kalıcı zarar verebilir; uygun kulak tıkaçları korna ve siren gibi önemli sesleri yine de duymanızı sağlar.","hi":"हवा और इंजन के शोर के लंबे संपर्क से श्रवण को स्थायी क्षति हो सकती है; उपयुक्त इयरप्लग फिर भी हॉर्न और सायरन जैसी महत्वपूर्ण आवाजें सुनने देते हैं।","ar":"التعرّض الطويل لضجيج الرياح والمحرك قد يضر السمع بشكل دائم؛ وسدادات الأذن المناسبة تتيح لك سماع الأصوات المهمة كالأبواق وصفارات الإنذار."}},{"cat":"gear","a":3,"q":{"en":"Which item does the manual consider essential eye protection?","es":"¿Qué elemento considera el manual protección ocular esencial?","ru":"Что руководство считает необходимой защитой глаз?","tr":"Kılavuz hangi ögeyi temel göz koruması sayar?","hi":"मैनुअल किस वस्तु को आवश्यक आँख सुरक्षा मानता है?","ar":"أي عنصر يعتبره الدليل واقياً أساسياً للعين؟"},"o":[{"en":"Ordinary sunglasses","es":"Gafas de sol comunes","ru":"Обычные солнцезащитные очки","tr":"Sıradan güneş gözlüğü","hi":"साधारण धूप का चश्मा","ar":"نظارات شمسية عادية"},{"en":"A helmet visor only","es":"Solo la visera del casco","ru":"Только козырёк шлема","tr":"Yalnızca kask siperi","hi":"केवल हेलमेट का वाइज़र","ar":"واقي الخوذة فقط"},{"en":"Any eyeglasses you own","es":"Cualquier gafa que tenga","ru":"Любые ваши очки","tr":"Sahip olduğunuz herhangi bir gözlük","hi":"आपके पास कोई भी चश्मा","ar":"أي نظارة تملكها"},{"en":"A shatter-resistant face shield or goggles","es":"Una pantalla facial o gafas resistentes a impactos","ru":"Небьющийся лицевой щиток или защитные очки","tr":"Kırılmaya dayanıklı yüz siperi veya gözlük","hi":"टूट-प्रतिरोधी फेस शील्ड या गॉगल्स","ar":"واقٍ للوجه أو نظارات واقية مقاومة للكسر"}],"e":{"en":"The manual calls for a shatter-resistant face shield or goggles; ordinary glasses and sunglasses can shatter and do not seal out wind, so they are not adequate.","es":"El manual exige una pantalla o gafas resistentes a impactos; las gafas comunes y de sol pueden romperse y no sellan el viento, por lo que no bastan.","ru":"Руководство требует небьющийся щиток или защитные очки; обычные очки и солнцезащитные могут разбиться и не защищают от ветра, поэтому их недостаточно.","tr":"Kılavuz kırılmaya dayanıklı yüz siperi veya gözlük ister; sıradan gözlük ve güneş gözlüğü kırılabilir ve rüzgârı kesmez, bu yüzden yeterli değildir.","hi":"मैनुअल टूट-प्रतिरोधी फेस शील्ड या गॉगल्स की माँग करता है; साधारण चश्मे और धूप के चश्मे टूट सकते हैं और हवा नहीं रोकते, इसलिए पर्याप्त नहीं हैं।","ar":"يطالب الدليل بواقٍ للوجه أو نظارات مقاومة للكسر؛ فالنظارات العادية والشمسية قد تتحطم ولا تحجب الرياح، لذا فهي غير كافية."}},{"cat":"braking","a":0,"q":{"en":"When making a normal stop, why should you use both the front and rear brakes?","es":"Al hacer una parada normal, ¿por qué debe usar el freno delantero y el trasero?","ru":"Почему при обычной остановке следует использовать оба тормоза — передний и задний?","tr":"Normal bir duruşta neden hem ön hem arka freni kullanmalısınız?","hi":"सामान्य रुकावट करते समय आपको फ्रंट और रियर दोनों ब्रेक क्यों इस्तेमाल करने चाहिए?","ar":"عند التوقف الطبيعي، لماذا يجب أن تستخدم الفرملتين الأمامية والخلفية معاً؟"},"o":[{"en":"Using both gives the shortest, most controlled stop","es":"Usar ambos da la parada más corta y controlada","ru":"Использование обоих даёт самую короткую и контролируемую остановку","tr":"İkisini kullanmak en kısa ve en kontrollü duruşu sağlar","hi":"दोनों का उपयोग सबसे छोटी, सबसे नियंत्रित रुकावट देता है","ar":"استخدامهما معاً يمنح أقصر توقف وأكثره تحكماً"},{"en":"It saves brake pads","es":"Ahorra pastillas de freno","ru":"Это экономит тормозные колодки","tr":"Fren balatalarını korur","hi":"यह ब्रेक पैड बचाता है","ar":"يوفّر أقمشة الفرامل"},{"en":"The front brake alone is illegal","es":"El freno delantero solo es ilegal","ru":"Только передний тормоз запрещён","tr":"Yalnızca ön fren yasa dışıdır","hi":"अकेला फ्रंट ब्रेक अवैध है","ar":"استخدام الفرامل الأمامية وحدها غير قانوني"},{"en":"It reduces engine wear","es":"Reduce el desgaste del motor","ru":"Это снижает износ двигателя","tr":"Motor aşınmasını azaltır","hi":"यह इंजन घिसाव घटाता है","ar":"يقلّل تآكل المحرك"}],"e":{"en":"The manual says to always use both brakes every time you slow or stop; using them together provides the maximum, most controlled braking.","es":"El manual dice usar siempre ambos frenos al frenar o detenerse; usarlos juntos da el frenado máximo y más controlado.","ru":"Руководство советует всегда использовать оба тормоза при замедлении и остановке; вместе они дают максимальное, наиболее контролируемое торможение.","tr":"Kılavuz her yavaşlama ve duruşta iki freni de kullanmayı söyler; birlikte kullanmak en fazla ve en kontrollü frenlemeyi sağlar.","hi":"मैनुअल कहता है कि धीमा होते या रुकते समय हमेशा दोनों ब्रेक इस्तेमाल करें; इन्हें साथ इस्तेमाल करना अधिकतम, सबसे नियंत्रित ब्रेकिंग देता है।","ar":"يقول الدليل استخدم الفرملتين دائماً عند كل إبطاء أو توقف؛ فاستخدامهما معاً يمنح أقصى كبح وأكثره تحكماً."}},{"cat":"braking","a":1,"q":{"en":"On a motorcycle with anti-lock brakes (ABS), what should you do in a hard stop?","es":"En una motocicleta con frenos antibloqueo (ABS), ¿qué debe hacer en una parada fuerte?","ru":"На мотоцикле с антиблокировочной системой (ABS) что делать при резком торможении?","tr":"Kilitlenme önleyici frenli (ABS) bir motosiklette sert duruşta ne yapmalısınız?","hi":"एंटी-लॉक ब्रेक (ABS) वाली मोटरसाइकिल पर, कठोर रुकावट में आपको क्या करना चाहिए?","ar":"في دراجة نارية مزوّدة بفرامل مانعة للانغلاق (ABS)، ماذا يجب أن تفعل عند التوقف الشديد؟"},"o":[{"en":"Pump the brakes rapidly","es":"Bombear los frenos rápidamente","ru":"Быстро прокачивать тормоза","tr":"Frenleri hızla pompalamak","hi":"ब्रेक को तेजी से पंप करना","ar":"ضخ الفرامل بسرعة"},{"en":"Apply full, firm brake pressure and hold it","es":"Aplicar presión de freno total y firme y mantenerla","ru":"Приложить полное, сильное усилие на тормоз и удерживать его","tr":"Tam ve sağlam fren basıncı uygulayıp basılı tutmak","hi":"पूरा, दृढ़ ब्रेक दबाव लगाएँ और बनाए रखें","ar":"الضغط على الفرامل بقوة كاملة والاستمرار بذلك"},{"en":"Use only the rear brake","es":"Usar solo el freno trasero","ru":"Использовать только задний тормоз","tr":"Yalnızca arka freni kullanmak","hi":"केवल रियर ब्रेक इस्तेमाल करना","ar":"استخدام الفرامل الخلفية فقط"},{"en":"Release the brakes and coast","es":"Soltar los frenos y rodar libre","ru":"Отпустить тормоза и катиться","tr":"Frenleri bırakıp boşta kaymak","hi":"ब्रेक छोड़ें और लुढ़कें","ar":"تحرير الفرامل والانزلاق"}],"e":{"en":"With ABS you can apply full brake pressure and hold it; the system automatically prevents wheel lockup, so you should not pump the brakes.","es":"Con ABS puede aplicar presión total y mantenerla; el sistema evita automáticamente el bloqueo, por lo que no debe bombear los frenos.","ru":"С ABS можно приложить полное усилие и удерживать его; система автоматически не даёт колёсам заблокироваться, поэтому прокачивать тормоза не нужно.","tr":"ABS ile tam fren basıncı uygulayıp basılı tutabilirsiniz; sistem tekerlek kilitlenmesini otomatik önler, bu yüzden frenleri pompalamamalısınız.","hi":"ABS के साथ आप पूरा ब्रेक दबाव लगाकर बनाए रख सकते हैं; सिस्टम स्वचालित रूप से व्हील लॉकअप रोकता है, इसलिए ब्रेक पंप न करें।","ar":"مع ABS يمكنك الضغط على الفرامل بقوة كاملة والاستمرار؛ فالنظام يمنع انغلاق العجلات تلقائياً، لذا لا تضخّ الفرامل."}},{"cat":"braking","a":2,"q":{"en":"What is engine braking, and when is it useful?","es":"¿Qué es el freno de motor y cuándo es útil?","ru":"Что такое торможение двигателем и когда оно полезно?","tr":"Motor freni nedir ve ne zaman yararlıdır?","hi":"इंजन ब्रेकिंग क्या है, और यह कब उपयोगी है?","ar":"ما هو كبح المحرك، ومتى يكون مفيداً؟"},"o":[{"en":"Turning off the engine to stop faster","es":"Apagar el motor para detenerse antes","ru":"Выключение двигателя, чтобы быстрее остановиться","tr":"Daha hızlı durmak için motoru kapatmak","hi":"तेजी से रुकने के लिए इंजन बंद करना","ar":"إطفاء المحرك للتوقف أسرع"},{"en":"Using the front brake only on hills","es":"Usar solo el freno delantero en pendientes","ru":"Использование только переднего тормоза на спусках","tr":"Yokuşlarda yalnızca ön freni kullanmak","hi":"ढलानों पर केवल फ्रंट ब्रेक इस्तेमाल करना","ar":"استخدام الفرامل الأمامية فقط على المنحدرات"},{"en":"Letting the engine slow you when you roll off the throttle in gear","es":"Dejar que el motor lo frene al soltar el acelerador en marcha","ru":"Позволить двигателю замедлять вас при сбросе газа на передаче","tr":"Viteste gazı bıraktığınızda motorun sizi yavaşlatmasına izin vermek","hi":"गियर में थ्रॉटल छोड़ने पर इंजन को धीमा करने देना","ar":"ترك المحرك يبطئك عندما تخفف الخانق وأنت في وضع تعشيق"},{"en":"Revving the engine while braking","es":"Acelerar el motor mientras frena","ru":"Газовать во время торможения","tr":"Frenlerken motoru gazlamak","hi":"ब्रेक लगाते समय इंजन रेव करना","ar":"تدوير المحرك بقوة أثناء الكبح"}],"e":{"en":"Engine braking is the slowing effect when you roll off the throttle with the bike in gear; it is helpful on long downgrades to avoid overheating the brakes.","es":"El freno de motor es el efecto de frenado al soltar el acelerador con la moto engranada; ayuda en bajadas largas para no sobrecalentar los frenos.","ru":"Торможение двигателем — это замедление при сбросе газа с включённой передачей; оно помогает на длинных спусках, чтобы не перегреть тормоза.","tr":"Motor freni, motosiklet viteste iken gazı bıraktığınızda oluşan yavaşlama etkisidir; uzun inişlerde frenlerin aşırı ısınmasını önlemeye yardımcı olur.","hi":"इंजन ब्रेकिंग वह मंदन प्रभाव है जब बाइक गियर में हो और आप थ्रॉटल छोड़ें; लंबी ढलानों पर यह ब्रेक अधिक गरम होने से बचाने में मदद करता है।","ar":"كبح المحرك هو أثر الإبطاء عند تخفيف الخانق والدراجة في وضع تعشيق؛ وهو مفيد في المنحدرات الطويلة لتجنّب ارتفاع حرارة الفرامل."}},{"cat":"braking","a":3,"q":{"en":"If you need to brake in a curve, what should you do first?","es":"Si necesita frenar en una curva, ¿qué debe hacer primero?","ru":"Если нужно тормозить в повороте, что следует сделать сначала?","tr":"Bir virajda frenlemeniz gerekirse önce ne yapmalısınız?","hi":"यदि आपको मोड़ में ब्रेक लगाना पड़े, तो पहले क्या करना चाहिए?","ar":"إذا احتجت للكبح في منعطف، فماذا يجب أن تفعل أولاً؟"},"o":[{"en":"Grab the front brake hard","es":"Apretar fuerte el freno delantero","ru":"Резко схватить передний тормоз","tr":"Ön frene sertçe asılmak","hi":"फ्रंट ब्रेक जोर से पकड़ना","ar":"الإمساك بقوة بالفرامل الأمامية"},{"en":"Lean the bike over more","es":"Inclinar más la moto","ru":"Сильнее наклонить мотоцикл","tr":"Motosikleti daha fazla yatırmak","hi":"बाइक को और झुकाना","ar":"إمالة الدراجة أكثر"},{"en":"Close the throttle completely and coast","es":"Cerrar el acelerador por completo y rodar libre","ru":"Полностью закрыть газ и катиться","tr":"Gazı tamamen kapatıp boşta kaymak","hi":"थ्रॉटल पूरी तरह बंद कर लुढ़कना","ar":"إغلاق الخانق تماماً والانزلاق"},{"en":"Reduce lean and straighten the bike as much as possible, then brake","es":"Reducir la inclinación y enderezar la moto lo posible, luego frenar","ru":"Уменьшить наклон и максимально выпрямить мотоцикл, затем тормозить","tr":"Yatışı azaltıp motosikleti mümkün olduğunca dikleştirmek, sonra frenlemek","hi":"झुकाव घटाकर बाइक को यथासंभव सीधा करें, फिर ब्रेक लगाएँ","ar":"تقليل الميل وتعديل الدراجة قدر الإمكان، ثم الكبح"}],"e":{"en":"A leaned-over tire has less traction available for braking; straighten the motorcycle as much as the curve allows before applying firm brakes.","es":"Un neumático inclinado tiene menos tracción para frenar; enderece la moto tanto como permita la curva antes de frenar con firmeza.","ru":"У наклонённой шины меньше сцепления для торможения; выпрямляйте мотоцикл насколько позволяет поворот, прежде чем сильно тормозить.","tr":"Yatık bir lastiğin frenleme için daha az tutuşu vardır; sert frenlemeden önce virajın izin verdiği kadar motosikleti dikleştirin.","hi":"झुके हुए टायर के पास ब्रेकिंग के लिए कम ट्रैक्शन होता है; दृढ़ ब्रेक लगाने से पहले मोड़ जितना अनुमति दे बाइक को उतना सीधा करें।","ar":"الإطار المائل لديه تماسك أقل متاح للكبح؛ عدّل الدراجة قدر ما يسمح المنعطف قبل الضغط بقوة على الفرامل."}},{"cat":"braking","a":0,"q":{"en":"Why can the front brake provide most of a motorcycle's stopping power?","es":"¿Por qué el freno delantero puede aportar la mayor parte de la fuerza de frenado?","ru":"Почему передний тормоз может обеспечивать большую часть тормозной силы мотоцикла?","tr":"Ön fren neden motosikletin durma gücünün çoğunu sağlayabilir?","hi":"फ्रंट ब्रेक मोटरसाइकिल की अधिकांश रुकने की शक्ति क्यों दे सकता है?","ar":"لماذا يمكن للفرامل الأمامية أن توفّر معظم قوة إيقاف الدراجة النارية؟"},"o":[{"en":"Weight shifts forward onto the front wheel when braking","es":"El peso se desplaza hacia adelante sobre la rueda delantera al frenar","ru":"При торможении вес смещается вперёд на переднее колесо","tr":"Frenlemede ağırlık öne, ön tekerleğe kayar","hi":"ब्रेक लगाने पर वजन आगे फ्रंट व्हील पर स्थानांतरित होता है","ar":"ينتقل الوزن للأمام إلى العجلة الأمامية عند الكبح"},{"en":"The front tire is always larger","es":"La llanta delantera siempre es más grande","ru":"Переднее колесо всегда больше","tr":"Ön lastik her zaman daha büyüktür","hi":"फ्रंट टायर हमेशा बड़ा होता है","ar":"الإطار الأمامي دائماً أكبر"},{"en":"The rear brake is only for parking","es":"El freno trasero es solo para estacionar","ru":"Задний тормоз только для парковки","tr":"Arka fren yalnızca park için","hi":"रियर ब्रेक केवल पार्किंग के लिए है","ar":"الفرامل الخلفية للركن فقط"},{"en":"The engine is over the front wheel","es":"El motor está sobre la rueda delantera","ru":"Двигатель находится над передним колесом","tr":"Motor ön tekerleğin üzerindedir","hi":"इंजन फ्रंट व्हील के ऊपर होता है","ar":"المحرك فوق العجلة الأمامية"}],"e":{"en":"As you brake, weight transfers forward and presses the front tire harder onto the road, giving it more traction and about 70% of the stopping power.","es":"Al frenar, el peso se transfiere hacia adelante y presiona más la llanta delantera contra el suelo, dándole más tracción y cerca del 70% del frenado.","ru":"При торможении вес переносится вперёд и сильнее прижимает переднюю шину к дороге, давая ей больше сцепления и около 70% тормозной силы.","tr":"Frenlerken ağırlık öne aktarılır ve ön lastiği yola daha sert bastırır; bu ona daha fazla tutuş ve durma gücünün yaklaşık %70'ini kazandırır.","hi":"ब्रेक लगाने पर वजन आगे स्थानांतरित होकर फ्रंट टायर को सड़क पर अधिक दबाता है, जिससे उसे अधिक ट्रैक्शन और लगभग 70% रुकने की शक्ति मिलती है।","ar":"عند الكبح ينتقل الوزن للأمام ويضغط الإطار الأمامي أكثر على الطريق، مما يمنحه تماسكاً أكبر ونحو 70% من قوة الإيقاف."}},{"cat":"braking","a":1,"q":{"en":"If your rear wheel locks during a straight-line stop on good traction, the manual says to:","es":"Si la rueda trasera se bloquea en una parada recta con buena tracción, el manual dice:","ru":"Если заднее колесо блокируется при торможении по прямой с хорошим сцеплением, руководство советует:","tr":"İyi tutuşta düz çizgide dururken arka tekerlek kilitlenirse kılavuz şunu söyler:","hi":"अच्छी ट्रैक्शन पर सीधी रुकावट के दौरान रियर व्हील लॉक हो जाए, तो मैनुअल कहता है:","ar":"إذا انغلقت العجلة الخلفية أثناء توقف في خط مستقيم على تماسك جيد، يقول الدليل:"},"o":[{"en":"Release the front brake immediately","es":"Soltar el freno delantero de inmediato","ru":"Немедленно отпустить передний тормоз","tr":"Ön freni hemen bırakmak","hi":"तुरंत फ्रंट ब्रेक छोड़ें","ar":"تحرير الفرامل الأمامية فوراً"},{"en":"Keep it locked until you stop","es":"Mantenerla bloqueada hasta detenerse","ru":"Держать его заблокированным до остановки","tr":"Durana kadar kilitli tutmak","hi":"रुकने तक इसे लॉक रखें","ar":"إبقاؤها مقفلة حتى تتوقف"},{"en":"Add throttle to unlock it","es":"Dar acelerador para desbloquearla","ru":"Прибавить газ, чтобы разблокировать его","tr":"Kilidi açmak için gaz eklemek","hi":"इसे अनलॉक करने के लिए थ्रॉटल दें","ar":"إضافة خانق لفك القفل"},{"en":"Grab more front brake","es":"Apretar más el freno delantero","ru":"Сильнее нажать передний тормоз","tr":"Ön frene daha çok asılmak","hi":"और फ्रंट ब्रेक पकड़ें","ar":"الضغط أكثر على الفرامل الأمامية"}],"e":{"en":"If the rear wheel locks while you are upright and straight, you can keep it locked until you stop; a locked rear wheel is usually manageable in a straight line.","es":"Si la rueda trasera se bloquea estando recto y erguido, puede mantenerla bloqueada hasta detenerse; una rueda trasera bloqueada suele ser manejable en línea recta.","ru":"Если заднее колесо заблокировалось, когда вы стоите прямо и вертикально, можно держать его заблокированным до остановки; на прямой это обычно управляемо.","tr":"Dik ve düz giderken arka tekerlek kilitlenirse, durana kadar kilitli tutabilirsiniz; düz çizgide kilitli arka tekerlek genellikle yönetilebilir.","hi":"यदि आप सीधे और सीधी रेखा में हों और रियर व्हील लॉक हो जाए, तो आप रुकने तक इसे लॉक रख सकते हैं; सीधी रेखा में लॉक रियर व्हील आम तौर पर संभालने योग्य है।","ar":"إذا انغلقت العجلة الخلفية وأنت مستقيم ومنتصب، يمكنك إبقاؤها مقفلة حتى تتوقف؛ فالعجلة الخلفية المقفلة عادةً يمكن التحكم بها في خط مستقيم."}},{"cat":"braking","a":2,"q":{"en":"What is the danger of squeezing the front brake suddenly and hard?","es":"¿Cuál es el peligro de apretar el freno delantero de golpe y con fuerza?","ru":"В чём опасность резкого и сильного нажатия переднего тормоза?","tr":"Ön freni ani ve sert sıkmanın tehlikesi nedir?","hi":"फ्रंट ब्रेक को अचानक और जोर से दबाने का खतरा क्या है?","ar":"ما خطر الضغط على الفرامل الأمامية فجأة وبقوة؟"},"o":[{"en":"It has no effect at low speed","es":"No tiene efecto a baja velocidad","ru":"На малой скорости это не действует","tr":"Düşük hızda etkisi yoktur","hi":"कम गति पर इसका कोई असर नहीं","ar":"لا أثر له عند السرعة المنخفضة"},{"en":"It only wears the pads","es":"Solo desgasta las pastillas","ru":"Это лишь изнашивает колодки","tr":"Yalnızca balataları aşındırır","hi":"यह केवल पैड घिसता है","ar":"يبلي الأقمشة فقط"},{"en":"The front wheel can lock and cause a fall","es":"La rueda delantera puede bloquearse y provocar una caída","ru":"Переднее колесо может заблокироваться и вызвать падение","tr":"Ön tekerlek kilitlenip düşmeye neden olabilir","hi":"फ्रंट व्हील लॉक होकर गिरने का कारण बन सकता है","ar":"قد تنغلق العجلة الأمامية وتسبّب سقوطاً"},{"en":"It disables the rear brake","es":"Desactiva el freno trasero","ru":"Это отключает задний тормоз","tr":"Arka freni devre dışı bırakır","hi":"यह रियर ब्रेक को निष्क्रिय करता है","ar":"يعطّل الفرامل الخلفية"}],"e":{"en":"Grabbing the front brake abruptly can lock the front wheel, which is likely to cause a loss of steering and a fall; squeeze it firmly but progressively.","es":"Apretar el freno delantero de golpe puede bloquear la rueda delantera, lo que probablemente cause pérdida de dirección y una caída; apriételo firme pero progresivamente.","ru":"Резкий захват переднего тормоза может заблокировать переднее колесо, что скорее всего приведёт к потере управления и падению; нажимайте твёрдо, но постепенно.","tr":"Ön frene ani asılmak ön tekerleği kilitleyebilir; bu da yön kaybına ve düşmeye yol açar. Sağlam ama kademeli sıkın.","hi":"फ्रंट ब्रेक को अचानक पकड़ना फ्रंट व्हील को लॉक कर सकता है, जिससे स्टीयरिंग खोकर गिरने की संभावना है; इसे दृढ़ पर क्रमिक रूप से दबाएँ।","ar":"الإمساك المفاجئ بالفرامل الأمامية قد يقفل العجلة الأمامية، مما يُرجّح فقدان التوجيه والسقوط؛ اضغط بثبات لكن تدريجياً."}},{"cat":"braking","a":3,"q":{"en":"How does total stopping distance break down for a rider?","es":"¿Cómo se descompone la distancia total de frenado para un conductor?","ru":"Из чего складывается общий тормозной путь для мотоциклиста?","tr":"Bir sürücü için toplam durma mesafesi nelerden oluşur?","hi":"एक राइडर के लिए कुल रुकने की दूरी किन भागों में बँटती है?","ar":"مِمَّ تتكوّن مسافة التوقف الكلية بالنسبة للسائق؟"},"o":[{"en":"Only the distance the brakes act","es":"Solo la distancia en que actúan los frenos","ru":"Только расстояние, на котором действуют тормоза","tr":"Yalnızca frenlerin etki ettiği mesafe","hi":"केवल वह दूरी जिसमें ब्रेक काम करते हैं","ar":"فقط المسافة التي تعمل خلالها الفرامل"},{"en":"Only your reaction time","es":"Solo su tiempo de reacción","ru":"Только время реакции","tr":"Yalnızca tepki süreniz","hi":"केवल आपका प्रतिक्रिया समय","ar":"فقط زمن رد فعلك"},{"en":"Just the engine braking distance","es":"Solo la distancia del freno de motor","ru":"Только путь торможения двигателем","tr":"Yalnızca motor freni mesafesi","hi":"केवल इंजन ब्रेकिंग की दूरी","ar":"فقط مسافة كبح المحرك"},{"en":"Perception distance, reaction distance, and braking distance","es":"Distancia de percepción, de reacción y de frenado","ru":"Расстояние восприятия, реакции и торможения","tr":"Algılama mesafesi, tepki mesafesi ve frenleme mesafesi","hi":"अनुभव दूरी, प्रतिक्रिया दूरी और ब्रेकिंग दूरी","ar":"مسافة الإدراك ومسافة رد الفعل ومسافة الكبح"}],"e":{"en":"Total stopping distance is the sum of the distance traveled while you perceive a hazard, react to it, and then physically brake to a stop.","es":"La distancia total de frenado es la suma de lo recorrido mientras percibe un peligro, reacciona y luego frena hasta detenerse.","ru":"Общий тормозной путь — это сумма расстояний, пройденных за время восприятия опасности, реакции и собственно торможения до остановки.","tr":"Toplam durma mesafesi; bir tehlikeyi algılarken, tepki verirken ve ardından fiilen durana kadar frenlerken alınan mesafelerin toplamıdır.","hi":"कुल रुकने की दूरी उस दूरी का योग है जो खतरे को समझने, प्रतिक्रिया देने और फिर वास्तव में रुकने तक ब्रेक लगाने में तय होती है।","ar":"مسافة التوقف الكلية هي مجموع المسافة المقطوعة أثناء إدراكك للخطر، ثم رد فعلك، ثم كبحك فعلياً حتى التوقف."}},{"cat":"braking","a":0,"q":{"en":"Why should you practice quick stops in a safe area?","es":"¿Por qué debe practicar paradas rápidas en un área segura?","ru":"Почему стоит отрабатывать экстренные остановки в безопасном месте?","tr":"Neden güvenli bir alanda hızlı duruş pratiği yapmalısınız?","hi":"आपको सुरक्षित स्थान पर त्वरित रुकावट का अभ्यास क्यों करना चाहिए?","ar":"لماذا يجب أن تتدرّب على التوقفات السريعة في منطقة آمنة؟"},"o":[{"en":"So the skill is automatic when you truly need it","es":"Para que la habilidad sea automática cuando de verdad la necesite","ru":"Чтобы навык стал автоматическим, когда он действительно понадобится","tr":"Gerçekten ihtiyaç duyduğunuzda beceri otomatik olsun diye","hi":"ताकि जब वास्तव में जरूरत हो तो कौशल स्वचालित हो","ar":"كي تصبح المهارة تلقائية عندما تحتاجها فعلاً"},{"en":"To wear in new tires","es":"Para asentar llantas nuevas","ru":"Чтобы обкатать новые шины","tr":"Yeni lastikleri rodaj yapmak için","hi":"नए टायर घिसाने के लिए","ar":"لترويض إطارات جديدة"},{"en":"To improve fuel mileage","es":"Para mejorar el rendimiento de combustible","ru":"Чтобы улучшить расход топлива","tr":"Yakıt verimini artırmak için","hi":"ईंधन माइलेज सुधारने के लि","ar":"لتحسين استهلاك الوقود"},{"en":"To break in the brakes only","es":"Solo para asentar los frenos","ru":"Только чтобы приработать тормоза","tr":"Yalnızca frenleri rodaj yapmak için","hi":"केवल ब्रेक बैठाने के लिए","ar":"لترويض الفرامل فقط"}],"e":{"en":"Practicing quick stops builds the reflexes and feel for maximum braking so you can react correctly and automatically in a real emergency.","es":"Practicar paradas rápidas desarrolla los reflejos y el tacto para el frenado máximo, para reaccionar bien y de forma automática en una emergencia real.","ru":"Отработка экстренных остановок развивает рефлексы и чувство максимального торможения, чтобы правильно и автоматически реагировать в реальной ситуации.","tr":"Hızlı duruş pratiği, gerçek acil durumda doğru ve otomatik tepki verebilmeniz için maksimum frenleme refleksini ve hissini geliştirir.","hi":"त्वरित रुकावट का अभ्यास अधिकतम ब्रेकिंग के लिए प्रतिवर्त और अनुभूति बनाता है, ताकि असली आपात में आप सही और स्वचालित रूप से प्रतिक्रिया दें।","ar":"التدرّب على التوقفات السريعة يبني ردود الفعل والإحساس بالكبح الأقصى كي تتفاعل بشكل صحيح وتلقائي في حالة طوارئ حقيقية."}},{"cat":"braking","a":1,"q":{"en":"On a slippery surface, how should you apply the brakes?","es":"Sobre una superficie resbaladiza, ¿cómo debe aplicar los frenos?","ru":"На скользкой поверхности как следует тормозить?","tr":"Kaygan bir zeminde frenleri nasıl uygulamalısınız?","hi":"फिसलन भरी सतह पर आपको ब्रेक कैसे लगाने चाहिए?","ar":"على سطح زلق، كيف يجب أن تضغط الفرامل؟"},"o":[{"en":"Grab both brakes as hard as possible","es":"Apretar ambos frenos lo más fuerte posible","ru":"Схватить оба тормоза как можно сильнее","tr":"İki frene de olabildiğince sert asılmak","hi":"दोनों ब्रेक जितना जोर से हो सके पकड़ें","ar":"الإمساك بكلا الفرملتين بأقصى قوة"},{"en":"Gently and gradually, with less pressure than on dry pavement","es":"Con suavidad y gradualmente, con menos presión que en seco","ru":"Мягко и постепенно, с меньшим усилием, чем на сухом покрытии","tr":"Yumuşak ve kademeli, kuru zemine göre daha az basınçla","hi":"धीरे और क्रमशः, सूखी सड़क से कम दबाव के साथ","ar":"بلطف وبالتدريج، بضغط أقل من الرصيف الجاف"},{"en":"Use only the front brake hard","es":"Usar solo el freno delantero con fuerza","ru":"Использовать только передний тормоз сильно","tr":"Yalnızca ön freni sert kullanmak","hi":"केवल फ्रंट ब्रेक जोर से इस्तेमाल करें","ar":"استخدام الفرامل الأمامية بقوة فقط"},{"en":"Avoid braking and steer only","es":"Evitar frenar y solo dirigir","ru":"Не тормозить и только рулить","tr":"Frenlemekten kaçınıp yalnızca yön vermek","hi":"ब्रेक से बचें और केवल स्टीयर करें","ar":"تجنّب الكبح والتوجيه فقط"}],"e":{"en":"On slippery pavement there is less traction, so brake gently and gradually with both brakes to avoid locking a wheel and losing control.","es":"En pavimento resbaladizo hay menos tracción, así que frene con suavidad y gradualmente con ambos frenos para no bloquear una rueda ni perder el control.","ru":"На скользком покрытии сцепления меньше, поэтому тормозите мягко и постепенно обоими тормозами, чтобы не заблокировать колесо и не потерять контроль.","tr":"Kaygan zeminde tutuş azdır; bu yüzden bir tekerleği kilitleyip kontrolü kaybetmemek için iki frenle yumuşak ve kademeli frenleyin.","hi":"फिसलन भरी सड़क पर ट्रैक्शन कम होता है, इसलिए दोनों ब्रेक से धीरे और क्रमशः ब्रेक लगाएँ ताकि व्हील लॉक न हो और नियंत्रण न खोएँ।","ar":"على الرصيف الزلق يكون التماسك أقل، لذا اكبح بلطف وبالتدريج بكلا الفرملتين لتجنّب قفل عجلة وفقدان السيطرة."}},{"cat":"braking","a":2,"q":{"en":"What advantage does ABS give a rider in an emergency stop?","es":"¿Qué ventaja da el ABS a un conductor en una parada de emergencia?","ru":"Какое преимущество ABS даёт мотоциклисту при экстренной остановке?","tr":"ABS, acil bir duruşta sürücüye ne avantaj sağlar?","hi":"आपात रुकावट में ABS राइडर को क्या लाभ देता है?","ar":"ما الميزة التي يمنحها ABS للسائق في توقف طارئ؟"},"o":[{"en":"It shortens stopping distance on every surface","es":"Acorta la distancia de frenado en toda superficie","ru":"Он сокращает тормозной путь на любой поверхности","tr":"Her zeminde durma mesafesini kısaltır","hi":"यह हर सतह पर रुकने की दूरी घटाता है","ar":"يقصّر مسافة التوقف على كل سطح"},{"en":"It lets you brake without a helmet","es":"Permite frenar sin casco","ru":"Он позволяет тормозить без шлема","tr":"Kask olmadan frenlemenizi sağlar","hi":"यह बिना हेलमेट ब्रेक लगाने देता है","ar":"يتيح لك الكبح دون خوذة"},{"en":"It helps keep the wheels from locking so you can steer while braking","es":"Ayuda a evitar que las ruedas se bloqueen para poder dirigir mientras frena","ru":"Он не даёт колёсам блокироваться, позволяя рулить во время торможения","tr":"Tekerleklerin kilitlenmesini önleyerek frenlerken yön vermenizi sağlar","hi":"यह पहियों को लॉक होने से रोककर ब्रेक लगाते हुए स्टीयर करने देता है","ar":"يساعد على منع انغلاق العجلات كي تتمكن من التوجيه أثناء الكبح"},{"en":"It replaces the need to use the front brake","es":"Elimina la necesidad de usar el freno delantero","ru":"Он избавляет от необходимости использовать передний тормоз","tr":"Ön freni kullanma ihtiyacını ortadan kaldırır","hi":"यह फ्रंट ब्रेक इस्तेमाल की जरूरत खत्म करता है","ar":"يلغي الحاجة لاستخدام الفرامل الأمامية"}],"e":{"en":"ABS keeps the wheels from locking during hard braking, letting you maintain steering control and stability; it does not guarantee a shorter stop on every surface.","es":"El ABS evita que las ruedas se bloqueen al frenar fuerte, permitiendo mantener el control de dirección y la estabilidad; no garantiza una parada más corta en toda superficie.","ru":"ABS не даёт колёсам блокироваться при сильном торможении, сохраняя управляемость и устойчивость; он не гарантирует более короткой остановки на любой поверхности.","tr":"ABS sert frenlemede tekerleklerin kilitlenmesini önler; yön kontrolünü ve dengeyi korumanızı sağlar; her zeminde daha kısa duruşu garanti etmez.","hi":"ABS कठोर ब्रेकिंग में पहियों को लॉक होने से रोकता है, जिससे आप स्टीयरिंग नियंत्रण और स्थिरता बनाए रखते हैं; यह हर सतह पर छोटी रुकावट की गारंटी नहीं देता।","ar":"يمنع ABS انغلاق العجلات أثناء الكبح الشديد، فيتيح لك الحفاظ على التوجيه والاستقرار؛ لكنه لا يضمن توقفاً أقصر على كل سطح."}},{"cat":"braking","a":3,"q":{"en":"Why is covering the brakes useful when you ride through heavy traffic?","es":"¿Por qué es útil cubrir los frenos al circular en tráfico denso?","ru":"Почему полезно держать пальцы над тормозами при движении в плотном потоке?","tr":"Yoğun trafikte sürerken frenleri kaplamak neden faydalıdır?","hi":"घने ट्रैफ़िक में चलते समय ब्रेक कवर करना क्यों उपयोगी है?","ar":"لماذا يُفيد وضع الأصابع على الفرامل عند القيادة في الزحام الكثيف؟"},"o":[{"en":"It cools the brake fluid","es":"Enfría el líquido de frenos","ru":"Это охлаждает тормозную жидкость","tr":"Fren hidroliğini soğutur","hi":"यह ब्रेक फ्लूइड को ठंडा करता है","ar":"يبرّد سائل الفرامل"},{"en":"It charges the battery","es":"Carga la batería","ru":"Это заряжает аккумулятор","tr":"Aküyü şarj eder","hi":"यह बैटरी चार्ज करता है","ar":"يشحن البطارية"},{"en":"It reduces the time needed to react and brake","es":"Reduce el tiempo necesario para reaccionar y frenar","ru":"Это сокращает время, нужное на реакцию и торможение","tr":"Tepki verip frenlemek için gereken süreyi azaltır","hi":"यह प्रतिक्रिया करने और ब्रेक लगाने में लगने वाला समय घटाता है","ar":"يقلّل الوقت اللازم لرد الفعل والكبح"},{"en":"It lets you ride without signaling","es":"Permite conducir sin señalizar","ru":"Это позволяет ехать без сигналов поворота","tr":"Sinyal vermeden sürmenizi sağlar","hi":"यह बिना संकेत दिए चलने देता है","ar":"يتيح لك القيادة دون إشارات"}],"e":{"en":"Covering the brakes means resting your fingers and toe over the levers so you can react and begin braking faster when a hazard appears in dense traffic.","es":"Cubrir los frenos es apoyar los dedos y la punta del pie sobre las palancas para reaccionar y empezar a frenar más rápido si aparece un peligro en tráfico denso.","ru":"«Прикрывать тормоза» — значит держать пальцы и носок над рычагами, чтобы быстрее среагировать и начать торможение при появлении опасности в плотном потоке.","tr":"Frenleri kaplamak, parmak ve ayak ucunuzu kolların üzerinde tutmak demektir; böylece yoğun trafikte bir tehlike belirince daha hızlı tepki verip frenlemeye başlarsınız.","hi":"ब्रेक कवर करने का अर्थ है उंगलियाँ और पैर का अंगूठा लीवर पर टिकाए रखना ताकि घने ट्रैफ़िक में खतरा आने पर आप तेजी से प्रतिक्रिया देकर ब्रेक लगाना शुरू कर सकें।","ar":"وضع الأصابع على الفرامل يعني إراحة أصابعك وطرف قدمك فوق الذراعين كي تتفاعل وتبدأ الكبح أسرع عند ظهور خطر في الزحام الكثيف."}},{"cat":"braking","a":0,"q":{"en":"Why should you avoid braking hard while the motorcycle is leaned into a turn?","es":"¿Por qué debe evitar frenar fuerte con la moto inclinada en una curva?","ru":"Почему не стоит сильно тормозить, когда мотоцикл наклонён в повороте?","tr":"Motosiklet viraja yatmışken neden sert frenlemekten kaçınmalısınız?","hi":"मोड़ में झुकी हुई मोटरसाइकिल पर जोर से ब्रेक लगाने से क्यों बचना चाहिए?","ar":"لماذا يجب تجنّب الكبح بقوة أثناء ميل الدراجة في منعطف؟"},"o":[{"en":"Traction is shared between turning and braking, so a wheel may slide","es":"La tracción se reparte entre girar y frenar, y una rueda puede deslizarse","ru":"Сцепление делится между поворотом и торможением, и колесо может проскользить","tr":"Tutuş, dönme ve frenleme arasında paylaşılır, bu yüzden bir tekerlek kayabilir","hi":"ट्रैक्शन मुड़ने और ब्रेकिंग के बीच बँटता है, इसलिए व्हील फिसल सकता है","ar":"يتوزّع التماسك بين الانعطاف والكبح، لذا قد تنزلق عجلة"},{"en":"The brakes stop working when leaned","es":"Los frenos dejan de funcionar al inclinarse","ru":"Тормоза перестают работать при наклоне","tr":"Yatıkken frenler çalışmayı durdurur","hi":"झुकने पर ब्रेक काम करना बंद कर देते हैं","ar":"تتوقف الفرامل عن العمل عند الميل"},{"en":"It uses more fuel","es":"Consume más combustible","ru":"Это расходует больше топлива","tr":"Daha fazla yakıt tüketir","hi":"यह अधिक ईंधन खर्च करता है","ar":"يستهلك وقوداً أكثر"},{"en":"The horn may sound","es":"Puede sonar la bocina","ru":"Может сработать сигнал","tr":"Korna çalabilir","hi":"हॉर्न बज सकता है","ar":"قد يعمل البوق"}],"e":{"en":"A tire has only so much traction; when it is already used for cornering, hard braking can exceed it and make the tire slide, so straighten up before braking hard.","es":"Un neumático tiene una tracción limitada; si ya se usa para girar, frenar fuerte puede superarla y hacer que deslice, así que enderece antes de frenar fuerte.","ru":"У шины ограниченное сцепление; если оно уже расходуется на поворот, сильное торможение может превысить предел и вызвать скольжение — выпрямитесь, прежде чем резко тормозить.","tr":"Bir lastiğin tutuşu sınırlıdır; dönüş için zaten kullanılıyorsa sert frenleme bunu aşıp lastiği kaydırabilir; bu yüzden sert frenlemeden önce dikleşin.","hi":"टायर की ट्रैक्शन सीमित होती है; जब यह पहले से मुड़ने में लग रही हो, तो जोर से ब्रेक इसे पार कर टायर फिसला सकता है, इसलिए जोर से ब्रेक से पहले सीधा करें।","ar":"للإطار تماسك محدود؛ وإن كان مستخدماً بالفعل للانعطاف، فقد يتجاوزه الكبح الشديد ويجعل الإطار ينزلق، لذا عدّل الدراجة قبل الكبح بقوة."}},{"cat":"braking","a":1,"q":{"en":"When you must stop quickly, what should you do with the clutch?","es":"Cuando deba parar rápido, ¿qué debe hacer con el embrague?","ru":"Когда нужно быстро остановиться, что делать со сцеплением?","tr":"Hızlı durmanız gerektiğinde debriyaj ile ne yapmalısınız?","hi":"जब तेजी से रुकना पड़े, तो क्लच के साथ क्या करना चाहिए?","ar":"عندما يجب أن تتوقف بسرعة، ماذا تفعل بالقابض؟"},"o":[{"en":"Leave it fully out the whole time","es":"Dejarlo totalmente suelto todo el tiempo","ru":"Оставить его полностью отпущенным всё время","tr":"Baştan sona tamamen bırakmak","hi":"पूरे समय इसे पूरी तरह छूटा रखें","ar":"تركه محرّراً بالكامل طوال الوقت"},{"en":"Squeeze it in as you brake so the engine does not stall","es":"Apretarlo al frenar para que el motor no se cale","ru":"Выжать его при торможении, чтобы двигатель не заглох","tr":"Motor stop etmesin diye frenlerken içeri basmak","hi":"ब्रेक लगाते समय इसे दबाएँ ताकि इंजन बंद न हो","ar":"الضغط عليه أثناء الكبح كي لا ينطفئ المحرك"},{"en":"Ignore it entirely","es":"Ignorarlo por completo","ru":"Полностью его игнорировать","tr":"Tamamen görmezden gelmek","hi":"इसे पूरी तरह अनदेखा करें","ar":"تجاهله تماماً"},{"en":"Release it suddenly to add engine braking","es":"Soltarlo de golpe para añadir freno de motor","ru":"Резко отпустить его, чтобы добавить торможение двигателем","tr":"Motor freni eklemek için aniden bırakmak","hi":"इंजन ब्रेकिंग जोड़ने के लिए इसे अचानक छोड़ें","ar":"تحريره فجأة لإضافة كبح المحرك"}],"e":{"en":"During a quick stop, squeeze the clutch as you brake hard so the engine does not stall and you finish ready to move; focus on smooth, firm braking.","es":"Durante una parada rápida, apriete el embrague al frenar fuerte para que el motor no se cale y termine listo para arrancar; concéntrese en un frenado suave y firme.","ru":"При экстренной остановке выжимайте сцепление во время сильного торможения, чтобы двигатель не заглох и вы были готовы тронуться; сосредоточьтесь на плавном, твёрдом торможении.","tr":"Hızlı duruşta sert frenlerken debriyaja basın ki motor stop etmesin ve kalkmaya hazır durun; yumuşak, sağlam frenlemeye odaklanın.","hi":"त्वरित रुकावट के दौरान जोर से ब्रेक लगाते समय क्लच दबाएँ ताकि इंजन बंद न हो और आप चलने को तैयार रहें; सहज, दृढ़ ब्रेकिंग पर ध्यान दें।","ar":"أثناء التوقف السريع، اضغط القابض وأنت تكبح بقوة كي لا ينطفئ المحرك وتبقى جاهزاً للانطلاق؛ وركّز على كبح سلس وثابت."}},{"cat":"braking","a":2,"q":{"en":"What is the safest way to slow down on a long, steep downhill?","es":"¿Cuál es la forma más segura de reducir en una bajada larga y pronunciada?","ru":"Как безопаснее всего замедляться на длинном крутом спуске?","tr":"Uzun ve dik bir inişte yavaşlamanın en güvenli yolu nedir?","hi":"लंबी, तीखी ढलान पर धीमा होने का सबसे सुरक्षित तरीका क्या है?","ar":"ما الطريقة الأكثر أماناً للإبطاء على منحدر طويل وشديد الانحدار؟"},"o":[{"en":"Ride in neutral to save the engine","es":"Rodar en punto muerto para cuidar el motor","ru":"Ехать на нейтрали, чтобы беречь двигатель","tr":"Motoru korumak için boşta gitmek","hi":"इंजन बचाने के लिए न्यूट्रल में चलें","ar":"القيادة في المحايد للحفاظ على المحرك"},{"en":"Hold the front brake on continuously","es":"Mantener el freno delantero aplicado continuamente","ru":"Держать передний тормоз нажатым непрерывно","tr":"Ön freni sürekli basılı tutmak","hi":"फ्रंट ब्रेक को लगातार दबाए रखें","ar":"إبقاء الفرامل الأمامية مضغوطة باستمرار"},{"en":"Downshift to let engine braking help, using the brakes as needed","es":"Reducir de marcha para que ayude el freno de motor, usando los frenos según haga falta","ru":"Понизить передачу, чтобы помогало торможение двигателем, применяя тормоза по мере надобности","tr":"Motor freninin yardımı için vites küçültmek, gerektikçe frenleri kullanmak","hi":"इंजन ब्रेकिंग की मदद के लिए गियर कम करें, जरूरत अनुसार ब्रेक का उपयोग करें","ar":"تخفيض السرعة ليساعد كبح المحرك، مع استخدام الفرامل حسب الحاجة"},{"en":"Coast with the clutch pulled in","es":"Rodar con el embrague apretado","ru":"Катиться с выжатым сцеплением","tr":"Debriyaj basılı halde boşta kaymak","hi":"क्लच दबाकर लुढ़कें","ar":"الانزلاق مع الضغط على القابض"}],"e":{"en":"On a long downgrade, downshift so engine braking helps control speed and the brakes do not overheat; apply the brakes intermittently as needed.","es":"En una bajada larga, reduzca de marcha para que el freno de motor ayude a controlar la velocidad y los frenos no se sobrecalienten; frene de forma intermitente según haga falta.","ru":"На длинном спуске понижайте передачу, чтобы торможение двигателем помогало держать скорость и тормоза не перегревались; тормозите с перерывами по мере необходимости.","tr":"Uzun inişte vites küçültün ki motor freni hızı kontrol etsin ve frenler aşırı ısınmasın; gerektikçe frenleri aralıklı kullanın.","hi":"लंबी ढलान पर गियर कम करें ताकि इंजन ब्रेकिंग गति नियंत्रित करने में मदद करे और ब्रेक अधिक गरम न हों; जरूरत अनुसार रुक-रुककर ब्रेक लगाएँ।","ar":"على منحدر طويل، خفّض السرعة كي يساعد كبح المحرك في التحكم بالسرعة ولا ترتفع حرارة الفرامل؛ واكبح على فترات حسب الحاجة."}},{"cat":"braking","a":3,"q":{"en":"After an emergency stop, what should you do before continuing?","es":"Tras una parada de emergencia, ¿qué debe hacer antes de continuar?","ru":"После экстренной остановки что следует сделать перед продолжением движения?","tr":"Acil bir duruştan sonra devam etmeden önce ne yapmalısınız?","hi":"आपात रुकावट के बाद, आगे बढ़ने से पहले क्या करना चाहिए?","ar":"بعد توقف طارئ، ماذا يجب أن تفعل قبل المتابعة؟"},"o":[{"en":"Accelerate away immediately","es":"Acelerar de inmediato","ru":"Немедленно ускориться и уехать","tr":"Hemen hızlanıp uzaklaşmak","hi":"तुरंत तेज होकर निकल जाएँ","ar":"التسارع والانطلاق فوراً"},{"en":"Turn the engine off","es":"Apagar el motor","ru":"Заглушить двигатель","tr":"Motoru kapatmak","hi":"इंजन बंद करें","ar":"إيقاف المحرك"},{"en":"Remove your gloves","es":"Quitarse los guantes","ru":"Снять перчатки","tr":"Eldivenleri çıkarmak","hi":"दस्ताने उतारें","ar":"خلع القفازات"},{"en":"Check traffic behind and around you before moving","es":"Verificar el tráfico detrás y alrededor antes de avanzar","ru":"Проверить обстановку сзади и вокруг, прежде чем трогаться","tr":"Hareket etmeden önce arkanızdaki ve çevrenizdeki trafiği kontrol etmek","hi":"चलने से पहले पीछे और आसपास के ट्रैफ़िक की जाँच करें","ar":"فحص حركة المرور خلفك وحولك قبل التحرك"}],"e":{"en":"After a hard stop, quickly check mirrors and around you for traffic that may be closing in from behind before you move off again.","es":"Tras una parada fuerte, revise rápido los espejos y alrededor por tráfico que pueda acercarse por detrás antes de volver a arrancar.","ru":"После резкой остановки быстро проверьте зеркала и обстановку вокруг на предмет транспорта, приближающегося сзади, прежде чем снова тронуться.","tr":"Sert bir duruştan sonra tekrar hareket etmeden önce aynaları ve çevrenizi, arkadan yaklaşabilecek trafik için hızla kontrol edin.","hi":"कठोर रुकावट के बाद फिर चलने से पहले शीशों और आसपास पीछे से आ रहे संभावित ट्रैफ़िक की तेजी से जाँच करें।","ar":"بعد توقف شديد، افحص بسرعة المرايا وما حولك بحثاً عن مركبات قد تقترب من الخلف قبل أن تنطلق مجدداً."}},{"cat":"braking","a":2,"q":{"en":"Why should you avoid using only the rear brake to slow down?","es":"¿Por qué debe evitar usar solo el freno trasero para reducir?","ru":"Почему не стоит для замедления пользоваться только задним тормозом?","tr":"Yavaşlamak için neden yalnızca arka freni kullanmaktan kaçınmalısınız?","hi":"धीमा होने के लिए केवल रियर ब्रेक इस्तेमाल करने से क्यों बचना चाहिए?","ar":"لماذا يجب تجنّب استخدام الفرامل الخلفية وحدها للإبطاء؟"},"o":[{"en":"The rear brake damages the chain","es":"El freno trasero daña la cadena","ru":"Задний тормоз повреждает цепь","tr":"Arka fren zinciri bozar","hi":"रियर ब्रेक चेन को नुकसान पहुँचाता है","ar":"الفرامل الخلفية تتلف السلسلة"},{"en":"It is illegal to use alone","es":"Es ilegal usarlo solo","ru":"Использовать его отдельно запрещено","tr":"Tek başına kullanmak yasa dışıdır","hi":"अकेले इसका उपयोग अवैध है","ar":"استخدامها وحدها غير قانوني"},{"en":"The rear brake alone gives much less stopping power","es":"El freno trasero solo da mucha menos fuerza de frenado","ru":"Один задний тормоз даёт гораздо меньшую тормозную силу","tr":"Yalnızca arka fren çok daha az durma gücü verir","hi":"अकेला रियर ब्रेक बहुत कम रुकने की शक्ति देता है","ar":"الفرامل الخلفية وحدها تعطي قوة إيقاف أقل بكثير"},{"en":"It cools the front tire too much","es":"Enfría demasiado la llanta delantera","ru":"Он слишком охлаждает переднюю шину","tr":"Ön lastiği aşırı soğutur","hi":"यह फ्रंट टायर को बहुत ठंडा करता है","ar":"يبرّد الإطار الأمامي كثيراً"}],"e":{"en":"The rear brake supplies only a small share of stopping power, so relying on it alone greatly lengthens your stop; always use both brakes together.","es":"El freno trasero aporta solo una pequeña parte del frenado, por lo que depender solo de él alarga mucho la parada; use siempre ambos frenos juntos.","ru":"Задний тормоз даёт лишь малую долю тормозной силы, поэтому опора только на него сильно удлиняет остановку; всегда используйте оба тормоза вместе.","tr":"Arka fren durma gücünün yalnızca küçük bir kısmını sağlar; buna tek başına güvenmek duruşu çok uzatır; her zaman iki freni birlikte kullanın.","hi":"रियर ब्रेक रुकने की शक्ति का केवल छोटा हिस्सा देता है, इसलिए अकेले उस पर निर्भर रहना रुकावट को बहुत बढ़ाता है; हमेशा दोनों ब्रेक साथ इस्तेमाल करें।","ar":"توفّر الفرامل الخلفية جزءاً صغيراً فقط من قوة الإيقاف، لذا الاعتماد عليها وحدها يطيل التوقف كثيراً؛ استخدم دائماً كلتا الفرملتين معاً."}},{"cat":"braking","a":3,"q":{"en":"What happens to your traction for braking as the road becomes wet?","es":"¿Qué ocurre con su tracción para frenar cuando la vía se moja?","ru":"Что происходит со сцеплением для торможения, когда дорога становится мокрой?","tr":"Yol ıslandıkça frenleme için tutuşunuza ne olur?","hi":"जब सड़क गीली हो जाती है तो ब्रेकिंग के लिए आपकी ट्रैक्शन का क्या होता है?","ar":"ماذا يحدث لتماسكك للكبح عندما يصبح الطريق مبللاً؟"},"o":[{"en":"It increases","es":"Aumenta","ru":"Оно увеличивается","tr":"Artar","hi":"यह बढ़ती है","ar":"يزداد"},{"en":"It stays the same","es":"Se mantiene igual","ru":"Оно остаётся прежним","tr":"Aynı kalır","hi":"यह वही रहती है","ar":"يبقى كما هو"},{"en":"It only changes at night","es":"Solo cambia de noche","ru":"Оно меняется только ночью","tr":"Yalnızca gece değişir","hi":"यह केवल रात में बदलती है","ar":"يتغيّر ليلاً فقط"},{"en":"It decreases, so you need to brake more gently","es":"Disminuye, por lo que debe frenar con más suavidad","ru":"Оно уменьшается, поэтому тормозить нужно мягче","tr":"Azalır, bu yüzden daha yumuşak frenlemeniz gerekir","hi":"यह घटती है, इसलिए आपको अधिक धीरे ब्रेक लगाना चाहिए","ar":"يقلّ، لذا تحتاج إلى الكبح بلطف أكثر"}],"e":{"en":"Wet pavement offers less traction, so braking distances get longer; apply both brakes more gently and allow extra space to stop.","es":"El pavimento mojado ofrece menos tracción, por lo que las distancias de frenado aumentan; frene con ambos más suavemente y deje más espacio para parar.","ru":"Мокрое покрытие даёт меньше сцепления, поэтому тормозной путь растёт; тормозите обоими тормозами мягче и оставляйте больше места для остановки.","tr":"Islak zemin daha az tutuş sağlar, bu yüzden frenleme mesafeleri uzar; iki frene daha yumuşak basın ve durmak için fazladan boşluk bırakın.","hi":"गीली सड़क कम ट्रैक्शन देती है, इसलिए ब्रेकिंग दूरी बढ़ती है; दोनों ब्रेक अधिक धीरे लगाएँ और रुकने के लिए अतिरिक्त जगह रखें।","ar":"الرصيف المبلل يوفّر تماسكاً أقل، لذا تطول مسافات الكبح؛ اضغط الفرملتين بلطف أكثر واترك مسافة إضافية للتوقف."}},{"cat":"cornering","a":0,"q":{"en":"In the four-step turning procedure, what does 'Press' refer to?","es":"En el procedimiento de giro de cuatro pasos, ¿a qué se refiere 'Presionar'?","ru":"В четырёхшаговой процедуре поворота что означает «Нажать» (Press)?","tr":"Dört adımlı dönüş yönteminde 'Bastır' neyi ifade eder?","hi":"चार-चरणीय मोड़ प्रक्रिया में 'दबाना' (Press) किसका संदर्भ है?","ar":"في إجراء الانعطاف من أربع خطوات، إلى ماذا تشير كلمة 'اضغط' (Press)؟"},"o":[{"en":"Pressing the handgrip on the side you want to turn toward","es":"Presionar el puño del lado hacia el que quiere girar","ru":"Нажатие на рукоятку со стороны, куда хотите повернуть","tr":"Dönmek istediğiniz taraftaki gidona bastırmak","hi":"जिस ओर मुड़ना है उस ओर के हैंडग्रिप को दबाना","ar":"الضغط على المقبض في الجهة التي تريد الانعطاف نحوها"},{"en":"Pressing the rear brake pedal","es":"Presionar el pedal del freno trasero","ru":"Нажатие на педаль заднего тормоза","tr":"Arka fren pedalına basmak","hi":"रियर ब्रेक पेडल दबाना","ar":"الضغط على دواسة الفرامل الخلفية"},{"en":"Pressing down on the seat","es":"Presionar hacia abajo sobre el asiento","ru":"Надавливание на сиденье","tr":"Sele bastırmak","hi":"सीट पर नीचे दबाना","ar":"الضغط على المقعد"},{"en":"Pressing the horn","es":"Presionar la bocina","ru":"Нажатие на сигнал","tr":"Kornaya basmak","hi":"हॉर्न दबाना","ar":"الضغط على البوق"}],"e":{"en":"'Press' is the countersteering step: press forward on the handgrip on the side you want to go, which makes the motorcycle lean and turn that way.","es":"'Presionar' es el paso de contradirección: empuje hacia adelante el puño del lado hacia donde quiere ir, lo que hace que la moto se incline y gire hacia allá.","ru":"«Нажать» — это контрруление: надавите вперёд на рукоятку со стороны, куда хотите ехать, и мотоцикл наклонится и повернёт туда.","tr":"'Bastır', ters direksiyon adımıdır: gitmek istediğiniz taraftaki gidona öne doğru bastırın; bu, motosikletin o yöne yatıp dönmesini sağlar.","hi":"'दबाना' काउंटरस्टीयरिंग चरण है: जिस ओर जाना है उस ओर के हैंडग्रिप को आगे दबाएँ, जिससे मोटरसाइकिल उसी ओर झुककर मुड़ती है।","ar":"'اضغط' هي خطوة التوجيه العكسي: ادفع المقبض للأمام في الجهة التي تريد الذهاب إليها، فتميل الدراجة وتنعطف نحو تلك الجهة."}},{"cat":"cornering","a":1,"q":{"en":"What is target fixation, and why is it dangerous in a curve?","es":"¿Qué es la fijación en el objetivo y por qué es peligrosa en una curva?","ru":"Что такое фиксация взгляда на цели и почему это опасно в повороте?","tr":"Hedefe kilitlenme nedir ve virajda neden tehlikelidir?","hi":"टारगेट फिक्सेशन क्या है, और मोड़ में यह खतरनाक क्यों है?","ar":"ما هو تثبيت النظر على الهدف، ولماذا هو خطير في المنعطف؟"},"o":[{"en":"Staring at your speedometer; it distracts you","es":"Mirar fijamente el velocímetro; lo distrae","ru":"Пристальный взгляд на спидометр; он отвлекает","tr":"Hız göstergesine bakmak; dikkatinizi dağıtır","hi":"स्पीडोमीटर को घूरना; यह ध्यान भटकाता है","ar":"التحديق في عداد السرعة؛ فهو يشتت انتباهك"},{"en":"Staring at a hazard so you steer toward it instead of where you want to go","es":"Mirar fijamente un peligro y dirigirse hacia él en vez de a donde quiere ir","ru":"Пристальный взгляд на опасность, из-за чего вы едете к ней, а не туда, куда хотите","tr":"Bir tehlikeye kilitlenip gitmek istediğiniz yer yerine ona doğru yönelmek","hi":"किसी खतरे को घूरना जिससे आप वहीं की ओर चले जाते हैं, न कि जहाँ जाना है","ar":"التحديق في خطر فتتجه نحوه بدلاً من حيث تريد الذهاب"},{"en":"Looking only at your mirrors","es":"Mirar solo los espejos","ru":"Смотреть только в зеркала","tr":"Yalnızca aynalara bakmak","hi":"केवल शीशों में देखना","ar":"النظر إلى المرايا فقط"},{"en":"Closing your eyes briefly","es":"Cerrar los ojos brevemente","ru":"Кратко закрывать глаза","tr":"Gözleri kısa süre kapatmak","hi":"संक्षेप में आँखें बंद करना","ar":"إغلاق عينيك لوهلة"}],"e":{"en":"Target fixation is staring at an obstacle; because you tend to steer where you look, the manual says to keep your eyes on your intended path through the turn.","es":"La fijación en el objetivo es mirar fijamente un obstáculo; como tiende a dirigirse a donde mira, el manual dice mantener la vista en el camino que quiere seguir en la curva.","ru":"Фиксация на цели — это пристальный взгляд на препятствие; поскольку вы едете туда, куда смотрите, руководство советует держать взгляд на нужной траектории поворота.","tr":"Hedefe kilitlenme, bir engele gözünü dikmektir; baktığınız yere yöneldiğiniz için kılavuz, gözünüzü virajda gitmek istediğiniz yola dikmeyi söyler.","hi":"टारगेट फिक्सेशन किसी बाधा को घूरना है; चूँकि आप जहाँ देखते हैं वहीं मुड़ते हैं, मैनुअल कहता है कि नजर मोड़ में अपने इच्छित रास्ते पर रखें।","ar":"تثبيت النظر هو التحديق في عائق؛ ولأنك تتجه إلى حيث تنظر، يقول الدليل أبقِ عينيك على مسارك المقصود عبر المنعطف."}},{"cat":"cornering","a":2,"q":{"en":"To go around a curve to the right, which way do you press the handgrips?","es":"Para tomar una curva a la derecha, ¿hacia dónde presiona los puños?","ru":"Чтобы пройти правый поворот, в какую сторону нажимать на рукоятки?","tr":"Sağa dönen bir virajı almak için gidonlara hangi yöne bastırırsınız?","hi":"दाईं ओर के मोड़ में जाने के लिए हैंडग्रिप किस ओर दबाते हैं?","ar":"للدوران في منعطف نحو اليمين، في أي اتجاه تضغط المقبضين؟"},"o":[{"en":"Press the left grip forward","es":"Empujar el puño izquierdo hacia adelante","ru":"Нажать левую рукоятку вперёд","tr":"Sol kabzayı öne bastırmak","hi":"बायाँ ग्रिप आगे दबाएँ","ar":"ادفع المقبض الأيسر للأمام"},{"en":"Pull both grips back evenly","es":"Tirar de ambos puños hacia atrás por igual","ru":"Тянуть обе рукоятки назад одинаково","tr":"İki kabzayı eşit şekilde geriye çekmek","hi":"दोनों ग्रिप समान रूप से पीछे खींचें","ar":"اسحب المقبضين للخلف بالتساوي"},{"en":"Press the right grip forward","es":"Empujar el puño derecho hacia adelante","ru":"Нажать правую рукоятку вперёд","tr":"Sağ kabzayı öne bastırmak","hi":"दायाँ ग्रिप आगे दबाएँ","ar":"ادفع المقبض الأيمن للأمام"},{"en":"Push down on both grips","es":"Empujar hacia abajo ambos puños","ru":"Надавить вниз на обе рукоятки","tr":"İki kabzaya da aşağı bastırmak","hi":"दोनों ग्रिप नीचे दबाएँ","ar":"اضغط المقبضين للأسفل"}],"e":{"en":"To turn right you press the right grip forward (press right, go right); countersteering leans the motorcycle into the curve.","es":"Para girar a la derecha empuje el puño derecho (presione a la derecha, vaya a la derecha); la contradirección inclina la moto hacia la curva.","ru":"Чтобы повернуть направо, нажмите правую рукоятку вперёд («жми вправо — едешь вправо»); контрруление наклоняет мотоцикл в поворот.","tr":"Sağa dönmek için sağ kabzayı öne bastırın (sağa bastır, sağa git); ters direksiyon motosikleti viraja yatırır.","hi":"दाएँ मुड़ने के लिए दायाँ ग्रिप आगे दबाएँ (दाएँ दबाओ, दाएँ जाओ); काउंटरस्टीयरिंग बाइक को मोड़ में झुकाता है।","ar":"للانعطاف يميناً ادفع المقبض الأيمن للأمام (اضغط يميناً، تتجه يميناً)؛ فالتوجيه العكسي يميل الدراجة داخل المنعطف."}},{"cat":"cornering","a":3,"q":{"en":"When entering a curve, where should you generally look?","es":"Al entrar a una curva, ¿hacia dónde debe mirar en general?","ru":"При входе в поворот куда обычно нужно смотреть?","tr":"Bir viraja girerken genellikle nereye bakmalısınız?","hi":"मोड़ में प्रवेश करते समय आपको आम तौर पर कहाँ देखना चाहिए?","ar":"عند الدخول في منعطف، إلى أين يجب أن تنظر عادةً؟"},"o":[{"en":"Down at your front tire","es":"Hacia abajo, a la rueda delantera","ru":"Вниз, на переднее колесо","tr":"Aşağıya, ön lastiğinize","hi":"नीचे अपने फ्रंट टायर पर","ar":"للأسفل نحو إطارك الأمامي"},{"en":"At the vehicle just ahead of you","es":"Al vehículo justo delante de usted","ru":"На машину прямо перед вами","tr":"Hemen önünüzdeki araca","hi":"ठीक आगे वाले वाहन पर","ar":"إلى المركبة التي أمامك مباشرة"},{"en":"At the edge line beside you","es":"A la línea del borde a su lado","ru":"На краевую линию рядом с вами","tr":"Yanınızdaki kenar çizgisine","hi":"अपने बगल की किनारे की लाइन पर","ar":"إلى خط الحافة بجانبك"},{"en":"Through the turn to where you want to go","es":"A través de la curva, hacia donde quiere ir","ru":"Сквозь поворот, туда, куда хотите ехать","tr":"Virajın içinden, gitmek istediğiniz yere","hi":"मोड़ के पार, जहाँ आप जाना चाहते हैं वहाँ","ar":"عبر المنعطف نحو حيث تريد الذهاب"}],"e":{"en":"Look well through the turn toward where you want to exit, not down at the road just in front; your line of sight guides your path.","es":"Mire bien a través de la curva, hacia donde quiere salir, no al suelo justo delante; su línea de visión guía su trayectoria.","ru":"Смотрите сквозь поворот, туда, где хотите из него выйти, а не на дорогу прямо перед собой; направление взгляда задаёт траекторию.","tr":"Hemen önünüzdeki yola değil, virajın içinden çıkmak istediğiniz yere doğru iyice bakın; bakış hattınız yolunuzu yönlendirir.","hi":"ठीक सामने की सड़क पर नहीं, बल्कि मोड़ के पार जहाँ निकलना है उस ओर अच्छी तरह देखें; आपकी दृष्टि रेखा आपका रास्ता तय करती है।","ar":"انظر جيداً عبر المنعطف نحو حيث تريد الخروج، لا للأسفل إلى الطريق أمامك مباشرة؛ فخط نظرك يوجّه مسارك."}},{"cat":"cornering","a":0,"q":{"en":"Why should you finish slowing down before you enter a curve, not during it?","es":"¿Por qué debe terminar de reducir antes de entrar a una curva y no dentro de ella?","ru":"Почему замедляться нужно закончить до входа в поворот, а не в нём?","tr":"Neden yavaşlamayı viraja girmeden önce bitirmelisiniz, viraj içinde değil?","hi":"मोड़ में प्रवेश से पहले धीमा होना पूरा क्यों करना चाहिए, उसके दौरान नहीं?","ar":"لماذا يجب أن تنهي الإبطاء قبل الدخول في المنعطف، لا أثناءه؟"},"o":[{"en":"So most of your traction is available for cornering","es":"Para que la mayor parte de la tracción quede disponible para girar","ru":"Чтобы большая часть сцепления оставалась для прохождения поворота","tr":"Tutuşunuzun çoğu dönüş için elde kalsın diye","hi":"ताकि आपकी अधिकांश ट्रैक्शन मुड़ने के लिए उपलब्ध रहे","ar":"كي يبقى معظم تماسكك متاحاً للانعطاف"},{"en":"To save fuel","es":"Para ahorrar combustible","ru":"Чтобы экономить топливо","tr":"Yakıt tasarrufu için","hi":"ईंधन बचाने के लिए","ar":"لتوفير الوقود"},{"en":"Because braking is not allowed in curves","es":"Porque frenar no está permitido en curvas","ru":"Потому что тормозить в поворотах запрещено","tr":"Virajda frenleme yasak olduğu için","hi":"क्योंकि मोड़ में ब्रेक लगाना अनुमत नहीं है","ar":"لأن الكبح ممنوع في المنعطفات"},{"en":"To warm the tires","es":"Para calentar las llantas","ru":"Чтобы прогреть шины","tr":"Lastikleri ısıtmak için","hi":"टायर गर्म करने के लिए","ar":"لتسخين الإطارات"}],"e":{"en":"Slow to a safe entry speed before the curve so that your tires' traction is used for turning, not braking, once you are leaned over.","es":"Reduzca a una velocidad de entrada segura antes de la curva para que la tracción se use para girar y no para frenar una vez inclinado.","ru":"Снизьте скорость до безопасной перед поворотом, чтобы сцепление шин шло на поворот, а не на торможение, когда вы уже в наклоне.","tr":"Virajdan önce güvenli bir giriş hızına inin ki yatıkken lastiklerin tutuşu frenleme için değil dönüş için kullanılsın.","hi":"मोड़ से पहले सुरक्षित प्रवेश गति तक धीमे हों ताकि झुकने के बाद टायर की ट्रैक्शन ब्रेकिंग नहीं बल्कि मुड़ने में लगे।","ar":"أبطئ إلى سرعة دخول آمنة قبل المنعطف كي يُستخدم تماسك إطاراتك للانعطاف لا للكبح بعد أن تميل."}},{"cat":"cornering","a":1,"q":{"en":"Which lane position gives the best view and setup approaching a blind right-hand curve?","es":"¿Qué posición en el carril da mejor visión y preparación al acercarse a una curva ciega a la derecha?","ru":"Какое положение в полосе даёт лучший обзор и подготовку при подъезде к слепому правому повороту?","tr":"Görüşü kapalı sağa dönüşe yaklaşırken hangi şerit konumu en iyi görüşü ve hazırlığı sağlar?","hi":"अंधे दाएँ मोड़ के पास पहुँचते समय कौन सी लेन स्थिति सर्वोत्तम दृश्य और तैयारी देती है?","ar":"أي وضع في المسار يمنح أفضل رؤية واستعداد عند الاقتراب من منعطف أيمن أعمى؟"},"o":[{"en":"Hugging the right edge","es":"Pegado al borde derecho","ru":"Прижавшись к правому краю","tr":"Sağ kenara yaslanmak","hi":"दाएँ किनारे से सटकर","ar":"الالتصاق بالحافة اليمنى"},{"en":"Toward the outside (left) of your lane to see farther around it","es":"Hacia el exterior (izquierda) del carril para ver más lejos alrededor","ru":"Ближе к внешней (левой) части полосы, чтобы видеть дальше за поворотом","tr":"Virajın etrafını daha uzağı görmek için şeridin dış (sol) tarafına doğru","hi":"मोड़ के इर्द-गिर्द दूर तक देखने के लिए लेन के बाहरी (बाएँ) ओर","ar":"نحو الجانب الخارجي (الأيسر) من مسارك لترى أبعد حول المنعطف"},{"en":"Straddling the center line","es":"A caballo sobre la línea central","ru":"Верхом на осевой линии","tr":"Orta çizgiye basarak","hi":"केंद्र रेखा पर सवार होकर","ar":"فوق الخط الأوسط"},{"en":"Right behind another car","es":"Justo detrás de otro auto","ru":"Прямо за другой машиной","tr":"Başka bir aracın hemen arkasında","hi":"किसी अन्य कार के ठीक पीछे","ar":"خلف سيارة أخرى مباشرة"}],"e":{"en":"Approaching a right curve, positioning toward the outside (left) of your lane opens up your view around the bend; move to the inside as you turn in.","es":"Al acercarse a una curva a la derecha, colocarse hacia el exterior (izquierda) del carril amplía la visión alrededor; muévase al interior al entrar en la curva.","ru":"При подъезде к правому повороту положение ближе к внешней (левой) части полосы открывает обзор за поворотом; смещайтесь к внутренней стороне при входе.","tr":"Sağa dönüşe yaklaşırken şeridin dış (sol) tarafına yerleşmek virajın ardını görmenizi açar; dönerken içe doğru geçin.","hi":"दाएँ मोड़ के पास लेन के बाहरी (बाएँ) ओर स्थिति मोड़ के इर्द-गिर्द दृश्य खोलती है; मुड़ते समय अंदर की ओर आ जाएँ।","ar":"عند الاقتراب من منعطف أيمن، التموضع نحو الخارج (الأيسر) من مسارك يفتح رؤيتك حول المنعطف؛ وانتقل للداخل أثناء الدخول فيه."}},{"cat":"cornering","a":2,"q":{"en":"What should you do if you enter a curve too fast?","es":"¿Qué debe hacer si entra a una curva demasiado rápido?","ru":"Что делать, если вы вошли в поворот слишком быстро?","tr":"Bir viraja çok hızlı girerseniz ne yapmalısınız?","hi":"यदि आप मोड़ में बहुत तेज प्रवेश कर जाएँ तो क्या करना चाहिए?","ar":"ماذا يجب أن تفعل إذا دخلت منعطفاً بسرعة كبيرة جداً؟"},"o":[{"en":"Straighten up and brake hard mid-curve","es":"Enderezar y frenar fuerte a mitad de curva","ru":"Выпрямиться и резко тормозить в середине поворота","tr":"Dikleşip viraj ortasında sert frenlemek","hi":"सीधा होकर मोड़ के बीच जोर से ब्रेक लगाएँ","ar":"التعديل والكبح بقوة في منتصف المنعطف"},{"en":"Grab the front brake and stop","es":"Apretar el freno delantero y detenerse","ru":"Схватить передний тормоз и остановиться","tr":"Ön frene asılıp durmak","hi":"फ्रंट ब्रेक पकड़कर रुक जाएँ","ar":"الإمساك بالفرامل الأمامية والتوقف"},{"en":"Keep looking through the turn and press harder to lean more and tighten your line","es":"Seguir mirando a través de la curva y presionar más para inclinarse y cerrar la trayectoria","ru":"Продолжать смотреть сквозь поворот и сильнее нажимать, чтобы больше наклониться и сузить траекторию","tr":"Virajın içinden bakmaya devam edip daha çok bastırarak daha fazla yatmak ve çizgiyi daraltmak","hi":"मोड़ के पार देखते रहें और अधिक झुककर अपनी लाइन कसने के लिए अधिक दबाएँ","ar":"استمر بالنظر عبر المنعطف واضغط أكثر لتميل أكثر وتضيّق مسارك"},{"en":"Close your eyes and coast","es":"Cerrar los ojos y rodar libre","ru":"Закрыть глаза и катиться","tr":"Gözleri kapatıp boşta kaymak","hi":"आँखें बंद कर लुढ़कें","ar":"إغلاق عينيك والانزلاق"}],"e":{"en":"If you are going too fast in a curve, do not brake abruptly; keep your eyes up through the turn and press harder on the inside grip to lean more and stay in your lane.","es":"Si va muy rápido en una curva, no frene de golpe; mantenga la vista en la curva y presione más el puño interior para inclinarse más y permanecer en su carril.","ru":"Если скорость в повороте слишком велика, не тормозите резко; держите взгляд по ходу поворота и сильнее нажимайте на внутреннюю рукоятку, чтобы больше наклониться и остаться в полосе.","tr":"Virajda çok hızlıysanız aniden frenlemeyin; gözünüzü virajın içinde tutun ve daha fazla yatıp şeridinizde kalmak için iç kabzaya daha çok bastırın.","hi":"मोड़ में बहुत तेज हों तो अचानक ब्रेक न लगाएँ; नजर मोड़ के पार रखें और अधिक झुककर अपनी लेन में रहने के लिए अंदरूनी ग्रिप को अधिक दबाएँ।","ar":"إذا كنت مسرعاً في منعطف فلا تكبح فجأة؛ أبقِ نظرك عبر المنعطف واضغط أكثر على المقبض الداخلي لتميل أكثر وتبقى في مسارك."}},{"cat":"cornering","a":3,"q":{"en":"Why is a smooth, steady throttle important through a curve?","es":"¿Por qué es importante un acelerador suave y constante a lo largo de una curva?","ru":"Почему в повороте важен плавный, ровный газ?","tr":"Bir viraj boyunca yumuşak, sabit gaz neden önemlidir?","hi":"मोड़ में सहज, स्थिर थ्रॉटल क्यों महत्वपूर्ण है?","ar":"لماذا يُعدّ الخانق السلس والثابت مهماً خلال المنعطف؟"},"o":[{"en":"It lets you brake harder","es":"Permite frenar más fuerte","ru":"Он позволяет сильнее тормозить","tr":"Daha sert frenlemenizi sağlar","hi":"यह ज्यादा जोर से ब्रेक लगाने देता है","ar":"يتيح لك الكبح بقوة أكبر"},{"en":"It saves the tires","es":"Cuida las llantas","ru":"Он бережёт шины","tr":"Lastikleri korur","hi":"यह टायर बचाता है","ar":"يحافظ على الإطارات"},{"en":"It lets you look down","es":"Permite mirar hacia abajo","ru":"Он позволяет смотреть вниз","tr":"Aşağı bakmanızı sağlar","hi":"यह नीचे देखने देता है","ar":"يتيح لك النظر للأسفل"},{"en":"Sudden throttle changes can upset traction and the bike's balance","es":"Los cambios bruscos de acelerador pueden alterar la tracción y el equilibrio","ru":"Резкие изменения газа могут нарушить сцепление и баланс мотоцикла","tr":"Ani gaz değişimleri tutuşu ve motosikletin dengesini bozabilir","hi":"अचानक थ्रॉटल बदलाव ट्रैक्शन और बाइक का संतुलन बिगाड़ सकते हैं","ar":"تغيّرات الخانق المفاجئة قد تخل بالتماسك وتوازن الدراجة"}],"e":{"en":"Abruptly rolling on or chopping the throttle mid-curve can break traction or make the bike stand up or wobble; smooth, steady throttle keeps it stable.","es":"Acelerar de golpe o cortar el acelerador a mitad de curva puede romper la tracción o hacer que la moto se enderece o tambalee; un acelerador suave la mantiene estable.","ru":"Резкий газ или его сброс в середине поворота может сорвать сцепление или заставить мотоцикл выпрямиться либо вилять; плавный ровный газ сохраняет устойчивость.","tr":"Viraj ortasında gazı ani açmak veya kesmek tutuşu bozabilir ya da motosikleti dikleştirip sallayabilir; yumuşak, sabit gaz onu dengede tutar.","hi":"मोड़ के बीच अचानक थ्रॉटल बढ़ाना या काटना ट्रैक्शन तोड़ सकता है या बाइक को सीधा/डगमगा सकता है; सहज, स्थिर थ्रॉटल इसे स्थिर रखता है।","ar":"فتح الخانق فجأة أو قطعه في منتصف المنعطف قد يكسر التماسك أو يجعل الدراجة تنتصب أو تهتز؛ والخانق السلس الثابت يبقيها مستقرة."}},{"cat":"cornering","a":0,"q":{"en":"What is the benefit of choosing an 'outside-inside-outside' line through a curve?","es":"¿Cuál es el beneficio de elegir una trayectoria 'exterior-interior-exterior' en una curva?","ru":"В чём польза выбора траектории «снаружи-внутрь-наружу» в повороте?","tr":"Bir virajda 'dıştan-içten-dışa' çizgi seçmenin faydası nedir?","hi":"मोड़ में 'बाहर-अंदर-बाहर' लाइन चुनने का लाभ क्या है?","ar":"ما فائدة اختيار مسار 'خارج-داخل-خارج' عبر المنعطف؟"},"o":[{"en":"It straightens the curve slightly and improves your view","es":"Endereza levemente la curva y mejora su visión","ru":"Он слегка спрямляет поворот и улучшает обзор","tr":"Virajı biraz düzleştirir ve görüşünüzü iyileştirir","hi":"यह मोड़ को थोड़ा सीधा करती है और दृश्य बेहतर बनाती है","ar":"يُقوّم المنعطف قليلاً ويحسّن رؤيتك"},{"en":"It uses less fuel","es":"Consume menos combustible","ru":"Он расходует меньше топлива","tr":"Daha az yakıt kullanır","hi":"यह कम ईंधन खर्च करती है","ar":"يستهلك وقوداً أقل"},{"en":"It lets you skip signaling","es":"Permite omitir la señalización","ru":"Он позволяет не подавать сигналы","tr":"Sinyal vermeyi atlamanızı sağlar","hi":"यह संकेत देना छोड़ने देती है","ar":"يتيح لك تجاوز الإشارة"},{"en":"It requires more lean angle","es":"Requiere más ángulo de inclinación","ru":"Он требует большего угла наклона","tr":"Daha fazla yatış açısı gerektirir","hi":"इसमें अधिक झुकाव कोण चाहिए","ar":"يتطلّب زاوية ميل أكبر"}],"e":{"en":"Entering wide, apexing to the inside, and exiting wide flattens the curve's effective radius and lets you see farther through it, allowing a smoother, safer line.","es":"Entrar por fuera, buscar el vértice interior y salir por fuera reduce el radio efectivo de la curva y permite ver más lejos, logrando una trayectoria más suave y segura.","ru":"Вход широко, апекс по внутренней стороне и широкий выход уменьшают эффективный радиус поворота и позволяют видеть дальше, обеспечивая более плавную и безопасную траекторию.","tr":"Geniş girip iç noktaya (apeks) yaklaşmak ve geniş çıkmak virajın etkin yarıçapını azaltır ve daha uzağı görmenizi sağlar; böylece daha yumuşak, güvenli bir çizgi elde edersiniz.","hi":"चौड़ा प्रवेश, अंदर की ओर एपेक्स और चौड़ा निकास मोड़ की प्रभावी त्रिज्या घटाते हैं और आगे तक देखने देते हैं, जिससे अधिक सहज, सुरक्षित लाइन बनती है।","ar":"الدخول واسعاً والاقتراب من القمة الداخلية والخروج واسعاً يقلّل نصف قطر المنعطف الفعّال ويتيح رؤية أبعد، مما يمنح مساراً أكثر سلاسة وأماناً."}},{"cat":"cornering","a":1,"q":{"en":"At normal speeds, how do you make a motorcycle lean to begin a turn?","es":"A velocidades normales, ¿cómo hace que la moto se incline para iniciar un giro?","ru":"На обычной скорости как заставить мотоцикл наклониться, чтобы начать поворот?","tr":"Normal hızlarda motosikleti dönüşe başlamak için nasıl yatırırsınız?","hi":"सामान्य गति पर मोड़ शुरू करने के लिए मोटरसाइकिल को कैसे झुकाते हैं?","ar":"عند السرعات العادية، كيف تجعل الدراجة تميل لبدء الانعطاف؟"},"o":[{"en":"Lean your body first and wait","es":"Inclinar el cuerpo primero y esperar","ru":"Сначала наклонить корпус и подождать","tr":"Önce vücudunuzu yatırıp beklemek","hi":"पहले शरीर झुकाएँ और प्रतीक्षा करें","ar":"إمالة جسمك أولاً والانتظار"},{"en":"Press forward on the handgrip in the direction of the turn","es":"Presionar el puño hacia adelante en la dirección del giro","ru":"Нажать рукоятку вперёд в сторону поворота","tr":"Dönüş yönündeki gidona öne bastırmak","hi":"मोड़ की दिशा में हैंडग्रिप को आगे दबाएँ","ar":"الضغط على المقبض للأمام في اتجاه الانعطاف"},{"en":"Shift your weight to the outside peg","es":"Cargar el peso en el estribo exterior","ru":"Перенести вес на внешнюю подножку","tr":"Ağırlığı dış basamağa vermek","hi":"वजन बाहरी पेग पर डालें","ar":"نقل وزنك إلى المسند الخارجي"},{"en":"Turn the handlebars away from the turn and hold","es":"Girar el manillar en sentido contrario al giro y sostener","ru":"Повернуть руль в сторону от поворота и держать","tr":"Gidonu dönüşün tersine çevirip tutmak","hi":"हैंडलबार को मोड़ से विपरीत घुमाकर पकड़ें","ar":"تدوير المقود بعكس الانعطاف والإمساك"}],"e":{"en":"At riding speed you countersteer: a forward press on the handgrip toward your turn makes the motorcycle lean and turn that way.","es":"A velocidad de marcha se contradirige: una presión hacia adelante del puño hacia el giro hace que la moto se incline y gire en esa dirección.","ru":"На ходу применяют контрруление: нажатие рукоятки вперёд в сторону поворота наклоняет мотоцикл и поворачивает его туда.","tr":"Sürüş hızında ters direksiyon yaparsınız: dönüş yönündeki gidona öne bastırmak motosikleti o yöne yatırıp döndürür.","hi":"राइडिंग गति पर आप काउंटरस्टीयर करते हैं: मोड़ की ओर हैंडग्रिप पर आगे दबाव बाइक को उसी ओर झुकाकर मोड़ता है।","ar":"عند سرعة القيادة تستخدم التوجيه العكسي: الضغط للأمام على المقبض نحو انعطافك يجعل الدراجة تميل وتنعطف نحو تلك الجهة."}},{"cat":"cornering","a":2,"q":{"en":"In slow-look-press-roll, what is the purpose of the 'Roll' step?","es":"En despacio-mirar-presionar-acelerar, ¿cuál es el objetivo del paso 'Acelerar'?","ru":"В схеме «медленно-смотри-нажми-газуй» какова цель шага «Газуй»?","tr":"Yavaşla-bak-bastır-gazla içinde 'Gazla' adımının amacı nedir?","hi":"धीरे-देखो-दबाओ-गैस में 'गैस' चरण का उद्देश्य क्या है?","ar":"في: أبطئ-انظر-اضغط-سرّع، ما الغرض من خطوة 'سرّع'؟"},"o":[{"en":"To brake through the curve","es":"Frenar a lo largo de la curva","ru":"Тормозить в повороте","tr":"Viraj boyunca frenlemek","hi":"मोड़ के दौरान ब्रेक लगाना","ar":"الكبح عبر المنعطف"},{"en":"To downshift repeatedly","es":"Reducir de marcha repetidamente","ru":"Многократно понижать передачи","tr":"Sürekli vites küçültmek","hi":"बार-बार गियर कम करना","ar":"تخفيض السرعة مراراً"},{"en":"To gently roll on the throttle to stabilize the bike through and out of the turn","es":"Acelerar suavemente para estabilizar la moto en y al salir de la curva","ru":"Плавно прибавлять газ, чтобы стабилизировать мотоцикл в повороте и на выходе","tr":"Motosikleti virajda ve çıkışta dengelemek için gazı yavaşça açmak","hi":"मोड़ में और बाहर बाइक को स्थिर करने के लिए थ्रॉटल धीरे-धीरे बढ़ाना","ar":"فتح الخانق بلطف لتثبيت الدراجة خلال المنعطف وعند الخروج منه"},{"en":"To turn off the headlight","es":"Apagar el faro","ru":"Выключить фару","tr":"Farı kapatmak","hi":"हेडलाइट बंद करना","ar":"إطفاء المصباح الأمامي"}],"e":{"en":"'Roll' means gently rolling on the throttle through the turn to maintain or slightly increase speed, which stabilizes the motorcycle and settles the suspension.","es":"'Acelerar' significa abrir suavemente el acelerador en la curva para mantener o aumentar levemente la velocidad, lo que estabiliza la moto y asienta la suspensión.","ru":"«Газуй» — плавно прибавлять газ в повороте, чтобы сохранить или слегка увеличить скорость; это стабилизирует мотоцикл и «загружает» подвеску.","tr":"'Gazla', virajda hızı korumak veya biraz artırmak için gazı yumuşakça açmaktır; bu motosikleti dengeler ve süspansiyonu oturtur.","hi":"'गैस' का अर्थ है मोड़ में गति बनाए रखने या थोड़ा बढ़ाने के लिए थ्रॉटल धीरे-धीरे बढ़ाना, जो बाइक को स्थिर करता है और सस्पेंशन बैठाता है।","ar":"'سرّع' يعني فتح الخانق بلطف خلال المنعطف للحفاظ على السرعة أو زيادتها قليلاً، مما يثبّت الدراجة ويستقر نظام التعليق."}},{"cat":"cornering","a":3,"q":{"en":"How should your body be positioned relative to the motorcycle in a normal highway curve?","es":"¿Cómo debe estar su cuerpo respecto a la moto en una curva normal de carretera?","ru":"Как располагать корпус относительно мотоцикла в обычном шоссейном повороте?","tr":"Normal bir karayolu virajında vücudunuz motosiklete göre nasıl konumlanmalıdır?","hi":"सामान्य राजमार्ग मोड़ में मोटरसाइकिल के सापेक्ष आपका शरीर कैसे होना चाहिए?","ar":"كيف يجب أن يكون وضع جسمك بالنسبة للدراجة في منعطف طريق سريع عادي؟"},"o":[{"en":"Leaning opposite to the bike","es":"Inclinado en sentido contrario a la moto","ru":"Наклонённым в сторону, противоположную мотоциклу","tr":"Motosiklete ters yatık","hi":"बाइक के विपरीत झुका हुआ","ar":"مائلاً عكس الدراجة"},{"en":"Hanging far off the inside","es":"Colgando muy hacia el interior","ru":"Свисающим далеко внутрь","tr":"İçe doğru çok sarkmış","hi":"अंदर की ओर बहुत झुका हुआ","ar":"متدلياً بعيداً إلى الداخل"},{"en":"Twisted toward the outside","es":"Girado hacia el exterior","ru":"Развёрнутым наружу","tr":"Dışa doğru dönük","hi":"बाहर की ओर मुड़ा हुआ","ar":"ملتوياً نحو الخارج"},{"en":"Leaning together with the motorcycle as one unit","es":"Inclinado junto con la moto como una sola unidad","ru":"Наклонённым вместе с мотоциклом как единое целое","tr":"Motosikletle birlikte tek bir bütün gibi yatık","hi":"मोटरसाइकिल के साथ एक इकाई की तरह झुका हुआ","ar":"مائلاً مع الدراجة كوحدة واحدة"}],"e":{"en":"For ordinary highway curves, the manual advises leaning at the same angle as the motorcycle, keeping your body in line with it as a single unit.","es":"Para curvas normales de carretera, el manual aconseja inclinarse en el mismo ángulo que la moto, manteniendo el cuerpo alineado con ella como una sola unidad.","ru":"Для обычных шоссейных поворотов руководство советует наклоняться под тем же углом, что и мотоцикл, сохраняя тело в одну линию с ним как единое целое.","tr":"Sıradan karayolu virajlarında kılavuz, motosikletle aynı açıda yatmayı ve vücudunuzu onunla tek bir bütün olarak hizada tutmayı önerir.","hi":"सामान्य राजमार्ग मोड़ों के लिए मैनुअल बाइक के समान कोण पर झुकने और शरीर को उसके साथ एक इकाई के रूप में संरेखित रखने की सलाह देता है।","ar":"للمنعطفات العادية على الطريق السريع، ينصح الدليل بالميل بنفس زاوية الدراجة، مع إبقاء جسمك محاذياً لها كوحدة واحدة."}},{"cat":"cornering","a":0,"q":{"en":"What is the risk of changing your lane position mid-way through a curve?","es":"¿Cuál es el riesgo de cambiar su posición en el carril a mitad de una curva?","ru":"Каков риск смены положения в полосе в середине поворота?","tr":"Viraj ortasında şerit konumunuzu değiştirmenin riski nedir?","hi":"मोड़ के बीच में लेन स्थिति बदलने का जोखिम क्या है?","ar":"ما خطر تغيير وضعك في المسار في منتصف المنعطف؟"},"o":[{"en":"It can force sudden steering and traction changes that reduce your margin for error","es":"Puede forzar cambios bruscos de dirección y tracción que reducen su margen de error","ru":"Это может вызвать резкие изменения руления и сцепления, снижая запас на ошибку","tr":"Ani direksiyon ve tutuş değişimlerine yol açıp hata payınızı azaltabilir","hi":"यह अचानक स्टीयरिंग और ट्रैक्शन बदलाव पैदा कर सकता है जो त्रुटि का मार्जिन घटाते हैं","ar":"قد يفرض تغييرات مفاجئة في التوجيه والتماسك تقلّل هامش الخطأ لديك"},{"en":"It saves fuel but is uncomfortable","es":"Ahorra combustible pero es incómodo","ru":"Это экономит топливо, но некомфортно","tr":"Yakıt tasarrufu sağlar ama rahatsızdır","hi":"यह ईंधन बचाता है पर असुविधाजनक है","ar":"يوفّر الوقود لكنه غير مريح"},{"en":"It has no real effect","es":"No tiene un efecto real","ru":"Это не имеет реального эффекта","tr":"Gerçek bir etkisi yoktur","hi":"इसका कोई वास्तविक असर नहीं","ar":"ليس له أثر حقيقي"},{"en":"It only matters on straight roads","es":"Solo importa en carreteras rectas","ru":"Это важно только на прямых дорогах","tr":"Yalnızca düz yollarda önemlidir","hi":"यह केवल सीधी सड़कों पर मायने रखता है","ar":"يهمّ فقط على الطرق المستقيمة"}],"e":{"en":"Picking your line before the curve and holding it is safer; changing position mid-curve forces mid-corner steering inputs that can upset traction and stability.","es":"Elegir la trayectoria antes de la curva y mantenerla es más seguro; cambiar de posición a media curva obliga a correcciones que pueden alterar la tracción y la estabilidad.","ru":"Безопаснее выбрать траекторию до поворота и держать её; смена положения в середине заставляет подруливать, что может нарушить сцепление и устойчивость.","tr":"Çizginizi virajdan önce seçip korumak daha güvenlidir; viraj ortasında konum değiştirmek, tutuşu ve dengeyi bozabilecek direksiyon düzeltmeleri gerektirir.","hi":"मोड़ से पहले लाइन चुनकर बनाए रखना सुरक्षित है; बीच मोड़ में स्थिति बदलना ऐसे स्टीयरिंग इनपुट माँगता है जो ट्रैक्शन और स्थिरता बिगाड़ सकते हैं।","ar":"اختيار مسارك قبل المنعطف والحفاظ عليه أكثر أماناً؛ فتغيير الوضع في منتصف المنعطف يفرض تصحيحات توجيه قد تخل بالتماسك والاستقرار."}},{"cat":"cornering","a":1,"q":{"en":"Why is it important to select the proper gear before a curve?","es":"¿Por qué es importante elegir la marcha adecuada antes de una curva?","ru":"Почему важно выбрать нужную передачу до поворота?","tr":"Virajdan önce doğru vitesi seçmek neden önemlidir?","hi":"मोड़ से पहले उचित गियर चुनना क्यों महत्वपूर्ण है?","ar":"لماذا من المهم اختيار الترس المناسب قبل المنعطف؟"},"o":[{"en":"So you can coast in neutral","es":"Para poder rodar en punto muerto","ru":"Чтобы катиться на нейтрали","tr":"Boşta kayabilmek için","hi":"ताकि न्यूट्रल में लुढ़क सकें","ar":"كي تنزلق في المحايد"},{"en":"So you can maintain steady throttle without shifting while leaned over","es":"Para mantener un acelerador constante sin cambiar mientras está inclinado","ru":"Чтобы держать ровный газ без переключения в наклоне","tr":"Yatıkken vites değiştirmeden sabit gaz tutabilmek için","hi":"ताकि झुके होने पर बिना गियर बदले स्थिर थ्रॉटल बनाए रखें","ar":"كي تحافظ على خانق ثابت دون تبديل أثناء الميل"},{"en":"So the engine turns off","es":"Para que el motor se apague","ru":"Чтобы двигатель заглох","tr":"Motorun kapanması için","hi":"ताकि इंजन बंद हो जाए","ar":"كي ينطفئ المحرك"},{"en":"So you brake harder","es":"Para frenar más fuerte","ru":"Чтобы сильнее тормозить","tr":"Daha sert frenlemek için","hi":"ताकि ज्यादा जोर से ब्रेक लगे","ar":"كي تكبح بقوة أكبر"}],"e":{"en":"Choosing the gear before you enter lets you hold a smooth, steady throttle through the curve; shifting while leaned can jerk the bike and reduce stability.","es":"Elegir la marcha antes de entrar permite mantener un acelerador suave y constante en la curva; cambiar inclinado puede dar tirones y reducir la estabilidad.","ru":"Выбор передачи до входа позволяет держать плавный ровный газ в повороте; переключение в наклоне может дёрнуть мотоцикл и снизить устойчивость.","tr":"Girmeden önce vitesi seçmek virajda yumuşak, sabit gaz tutmanızı sağlar; yatıkken vites değiştirmek motosikleti sarsıp dengeyi azaltabilir.","hi":"प्रवेश से पहले गियर चुनना मोड़ में सहज, स्थिर थ्रॉटल बनाए रखने देता है; झुके होने पर गियर बदलना बाइक को झटका देकर स्थिरता घटा सकता है।","ar":"اختيار الترس قبل الدخول يتيح لك الحفاظ على خانق سلس وثابت خلال المنعطف؛ والتبديل أثناء الميل قد يهز الدراجة ويقلّل الاستقرار."}},{"cat":"cornering","a":2,"q":{"en":"If gravel or sand is spread across a curve, how should you adjust?","es":"Si hay grava o arena esparcida en una curva, ¿cómo debe ajustarse?","ru":"Если в повороте рассыпан гравий или песок, как скорректировать езду?","tr":"Bir viraja çakıl veya kum yayılmışsa nasıl ayarlama yapmalısınız?","hi":"यदि मोड़ पर बजरी या रेत फैली हो, तो आपको कैसे समायोजन करना चाहिए?","ar":"إذا كان هناك حصى أو رمل منتشر عبر منعطف، فكيف تتكيف؟"},"o":[{"en":"Lean more aggressively","es":"Inclinarse más agresivamente","ru":"Наклоняться агрессивнее","tr":"Daha agresif yatmak","hi":"अधिक आक्रामक रूप से झुकें","ar":"الميل بقوة أكبر"},{"en":"Brake hard in the middle of the curve","es":"Frenar fuerte en medio de la curva","ru":"Резко тормозить в середине поворота","tr":"Viraj ortasında sert frenlemek","hi":"मोड़ के बीच जोर से ब्रेक लगाएँ","ar":"الكبح بقوة في منتصف المنعطف"},{"en":"Slow down before the curve and reduce your lean angle","es":"Reducir antes de la curva y disminuir el ángulo de inclinación","ru":"Снизить скорость до поворота и уменьшить угол наклона","tr":"Virajdan önce yavaşlamak ve yatış açısını azaltmak","hi":"मोड़ से पहले धीमे हों और झुकाव कोण घटाएँ","ar":"الإبطاء قبل المنعطف وتقليل زاوية الميل"},{"en":"Accelerate to power through","es":"Acelerar para pasar con fuerza","ru":"Ускоряться, чтобы проскочить","tr":"Güçle geçmek için hızlanmak","hi":"जोर से निकलने के लिए तेज हों","ar":"التسارع لتجاوزه بقوة"}],"e":{"en":"Loose surfaces cut traction, so slow down before the curve and keep the bike more upright with a smaller lean angle to reduce the chance of sliding.","es":"Las superficies sueltas reducen la tracción, así que reduzca antes de la curva y mantenga la moto más erguida con menor inclinación para evitar deslizar.","ru":"Сыпучие поверхности снижают сцепление, поэтому сбросьте скорость до поворота и держите мотоцикл более вертикально с меньшим наклоном, чтобы не проскользнуть.","tr":"Gevşek zeminler tutuşu azaltır; bu yüzden virajdan önce yavaşlayın ve kayma olasılığını azaltmak için motosikleti daha dik, daha az yatış açısıyla tutun.","hi":"ढीली सतहें ट्रैक्शन घटाती हैं, इसलिए मोड़ से पहले धीमे हों और फिसलने की संभावना घटाने के लिए बाइक को कम झुकाव के साथ अधिक सीधा रखें।","ar":"الأسطح المفككة تقلّل التماسك، لذا أبطئ قبل المنعطف وأبقِ الدراجة أكثر انتصاباً بزاوية ميل أصغر لتقليل احتمال الانزلاق."}},{"cat":"cornering","a":3,"q":{"en":"What does it mean to 'roll on' the throttle as you exit a curve?","es":"¿Qué significa 'abrir' el acelerador al salir de una curva?","ru":"Что значит «прибавить» газ на выходе из поворота?","tr":"Bir virajdan çıkarken gazı 'açmak' ne demektir?","hi":"मोड़ से निकलते समय थ्रॉटल 'रोल ऑन' करने का क्या मतलब है?","ar":"ماذا يعني 'فتح' الخانق تدريجياً عند الخروج من منعطف؟"},"o":[{"en":"Snapping it fully open at once","es":"Abrirlo del todo de golpe","ru":"Резко открыть его полностью сразу","tr":"Bir anda tamamen açmak","hi":"इसे एक बार में पूरा खोल देना","ar":"فتحه بالكامل دفعة واحدة"},{"en":"Closing it completely","es":"Cerrarlo por completo","ru":"Полностью закрыть его","tr":"Tamamen kapatmak","hi":"इसे पूरी तरह बंद करना","ar":"إغلاقه تماماً"},{"en":"Turning it on and off rapidly","es":"Encenderlo y apagarlo rápidamente","ru":"Быстро то открывать, то закрывать","tr":"Hızlıca açıp kapatmak","hi":"इसे तेजी से चालू-बंद करना","ar":"فتحه وإغلاقه بسرعة"},{"en":"Smoothly and gradually increasing throttle as you straighten up","es":"Aumentar el acelerador de forma suave y gradual al enderezarse","ru":"Плавно и постепенно прибавлять газ по мере выпрямления","tr":"Dikleşirken gazı yumuşak ve kademeli olarak artırmak","hi":"सीधा होते हुए थ्रॉटल को सहज और क्रमशः बढ़ाना","ar":"زيادة الخانق بسلاسة وتدريجياً أثناء تعديل الدراجة"}],"e":{"en":"'Rolling on' means smoothly and progressively opening the throttle as the bike stands up out of the curve, which keeps traction balanced and the exit stable.","es":"'Abrir' significa aumentar el acelerador de forma suave y progresiva al enderezarse saliendo de la curva, lo que mantiene la tracción equilibrada y la salida estable.","ru":"«Прибавить» — плавно и постепенно открывать газ, когда мотоцикл выпрямляется на выходе из поворота; это уравновешивает сцепление и делает выход устойчивым.","tr":"'Açmak', motosiklet virajdan çıkarken dikleşirken gazı yumuşak ve kademeli açmak demektir; bu tutuşu dengeler ve çıkışı stabil tutar.","hi":"'रोल ऑन' का अर्थ है बाइक के मोड़ से सीधा होते समय थ्रॉटल को सहज और क्रमिक रूप से खोलना, जो ट्रैक्शन संतुलित और निकास स्थिर रखता है।","ar":"'الفتح التدريجي' يعني فتح الخانق بسلاسة وتدرّج أثناء انتصاب الدراجة خارجاً من المنعطف، مما يبقي التماسك متوازناً والخروج مستقراً."}},{"cat":"cornering","a":2,"q":{"en":"Why should you avoid braking and countersteering aggressively at the same time in a curve?","es":"¿Por qué debe evitar frenar y contradireccionar con fuerza a la vez en una curva?","ru":"Почему в повороте не стоит одновременно резко тормозить и активно контрулить?","tr":"Bir virajda neden aynı anda sert frenleme ve agresif ters direksiyondan kaçınmalısınız?","hi":"मोड़ में एक साथ जोर से ब्रेक और आक्रामक काउंटरस्टीयर करने से क्यों बचना चाहिए?","ar":"لماذا يجب تجنّب الكبح والتوجيه العكسي بقوة في آنٍ واحد داخل منعطف؟"},"o":[{"en":"It uses more fuel","es":"Consume más combustible","ru":"Это расходует больше топлива","tr":"Daha fazla yakıt tüketir","hi":"यह अधिक ईंधन खर्च करता है","ar":"يستهلك وقوداً أكثر"},{"en":"It disables the brake light","es":"Desactiva la luz de freno","ru":"Это отключает стоп-сигнал","tr":"Fren lambasını devre dışı bırakır","hi":"यह ब्रेक लाइट बंद कर देता है","ar":"يعطّل ضوء الفرامل"},{"en":"Both demand tire traction, and together they can exceed what the tire can grip","es":"Ambos exigen tracción, y juntos pueden superar el agarre disponible","ru":"Оба расходуют сцепление шины, и вместе они могут превысить её предел","tr":"İkisi de lastik tutuşu ister; birlikte, lastiğin sağlayabileceğini aşabilir","hi":"दोनों टायर ट्रैक्शन माँगते हैं, और साथ में टायर की पकड़ की सीमा पार कर सकते हैं","ar":"كلاهما يتطلّب تماسك الإطار، ومعاً قد يتجاوزان ما يستطيع الإطار الإمساك به"},{"en":"It makes the horn sound","es":"Hace sonar la bocina","ru":"Это включает сигнал","tr":"Kornayı çaldırır","hi":"यह हॉर्न बजाता है","ar":"يجعل البوق يعمل"}],"e":{"en":"Turning and braking both use the tire's limited traction; doing both hard at once can overwhelm the tire and cause a slide, so separate the actions.","es":"Girar y frenar usan la tracción limitada del neumático; hacer ambos con fuerza a la vez puede superarla y causar un deslizamiento, así que sepárelos.","ru":"Поворот и торможение расходуют ограниченное сцепление шины; делать и то и другое сильно одновременно может превысить предел и вызвать скольжение — разделяйте действия.","tr":"Dönmek ve frenlemek lastiğin sınırlı tutuşunu kullanır; ikisini birden sert yapmak lastiği aşıp kaymaya yol açabilir, bu yüzden eylemleri ayırın.","hi":"मुड़ना और ब्रेक लगाना दोनों टायर की सीमित ट्रैक्शन इस्तेमाल करते हैं; दोनों एक साथ जोर से करना टायर को हरा कर फिसलन ला सकता है, इसलिए इन क्रियाओं को अलग करें।","ar":"الانعطاف والكبح كلاهما يستخدم تماسك الإطار المحدود؛ والقيام بهما بقوة معاً قد يُرهق الإطار ويسبب انزلاقاً، لذا افصل بين الإجراءين."}},{"cat":"cornering","a":3,"q":{"en":"On a curve that tightens as it goes (a decreasing-radius turn), what is the safer approach?","es":"En una curva que se cierra progresivamente (radio decreciente), ¿cuál es el enfoque más seguro?","ru":"На повороте, который сужается по ходу (уменьшающийся радиус), какой подход безопаснее?","tr":"Gittikçe daralan bir virajda (azalan yarıçaplı dönüş) daha güvenli yaklaşım nedir?","hi":"ऐसे मोड़ पर जो आगे बढ़ते हुए तंग होता जाता है (घटती त्रिज्या), सुरक्षित तरीका क्या है?","ar":"في منعطف يضيق كلما تقدّمت (نصف قطر متناقص)، ما النهج الأكثر أماناً؟"},"o":[{"en":"Enter as fast as possible","es":"Entrar lo más rápido posible","ru":"Входить как можно быстрее","tr":"Olabildiğince hızlı girmek","hi":"जितना तेज हो सके प्रवेश करें","ar":"الدخول بأقصى سرعة ممكنة"},{"en":"Ignore the exit and focus on the entry","es":"Ignorar la salida y concentrarse en la entrada","ru":"Игнорировать выход и сосредоточиться на входе","tr":"Çıkışı yok sayıp girişe odaklanmak","hi":"निकास को अनदेखा कर प्रवेश पर ध्यान दें","ar":"تجاهل المخرج والتركيز على المدخل"},{"en":"Straighten up completely at the apex","es":"Enderezar por completo en el vértice","ru":"Полностью выпрямляться на апексе","tr":"Apeks noktasında tamamen dikleşmek","hi":"एपेक्स पर पूरी तरह सीधा हो जाएँ","ar":"التعديل بالكامل عند القمة"},{"en":"Enter a bit slower and delay your turn-in so you can see how it tightens","es":"Entrar algo más despacio y retrasar el punto de giro para ver cómo se cierra","ru":"Входить чуть медленнее и позже начинать поворот, чтобы увидеть, как он сужается","tr":"Biraz daha yavaş girip dönüş noktasını geciktirerek nasıl daraldığını görmek","hi":"थोड़ा धीमे प्रवेश करें और टर्न-इन में देरी करें ताकि देख सकें यह कैसे तंग होता है","ar":"الدخول أبطأ قليلاً وتأخير نقطة الانعطاف كي ترى كيف يضيق"}],"e":{"en":"On a decreasing-radius curve, enter slower and turn in a little later so you can see the tightening road and avoid running wide as the radius shrinks.","es":"En una curva de radio decreciente, entre más despacio y gire un poco más tarde para ver cómo se cierra y evitar salirse al reducirse el radio.","ru":"На повороте с уменьшающимся радиусом входите медленнее и начинайте поворот чуть позже, чтобы видеть сужение и не вылететь наружу, когда радиус уменьшается.","tr":"Azalan yarıçaplı virajda daha yavaş girin ve biraz daha geç dönün ki daralan yolu görün ve yarıçap küçülürken dışa savrulmayın.","hi":"घटती-त्रिज्या मोड़ पर धीमे प्रवेश करें और थोड़ा देर से मुड़ें ताकि तंग होती सड़क दिखे और त्रिज्या घटने पर आप चौड़े न निकलें।","ar":"في منعطف بنصف قطر متناقص، ادخل أبطأ وانعطف متأخراً قليلاً كي ترى الطريق المتضيّق وتتجنّب الانحراف للخارج مع تناقص نصف القطر."}},{"cat":"cornering","a":0,"q":{"en":"When you have finished a turn, what should you do with your speed?","es":"Cuando termina un giro, ¿qué debe hacer con su velocidad?","ru":"Когда поворот пройден, что делать со скоростью?","tr":"Bir dönüşü bitirdiğinizde hızınızla ne yapmalısınız?","hi":"जब आप मोड़ पूरा कर लें, तो अपनी गति के साथ क्या करना चाहिए?","ar":"عند الانتهاء من انعطاف، ماذا يجب أن تفعل بسرعتك؟"},"o":[{"en":"Smoothly roll on the throttle to accelerate out as the bike straightens","es":"Acelerar suavemente para salir a medida que la moto se endereza","ru":"Плавно прибавить газ, разгоняясь на выходе по мере выпрямления","tr":"Motosiklet dikleşirken çıkışta hızlanmak için gazı yumuşakça açmak","hi":"बाइक के सीधा होते ही निकलने के लिए थ्रॉटल धीरे-धीरे बढ़ाएँ","ar":"فتح الخانق بسلاسة للتسارع خارجاً مع انتصاب الدراجة"},{"en":"Brake hard immediately","es":"Frenar fuerte de inmediato","ru":"Немедленно резко тормозить","tr":"Hemen sert frenlemek","hi":"तुरंत जोर से ब्रेक लगाएँ","ar":"الكبح بقوة فوراً"},{"en":"Pull in the clutch and coast","es":"Apretar el embrague y rodar libre","ru":"Выжать сцепление и катиться","tr":"Debriyaja basıp boşta kaymak","hi":"क्लच दबाकर लुढ़कें","ar":"الضغط على القابض والانزلاق"},{"en":"Shift into neutral","es":"Poner punto muerto","ru":"Перейти на нейтраль","tr":"Boşa almak","hi":"न्यूट्रल में डालें","ar":"التحويل إلى المحايد"}],"e":{"en":"As you straighten out of the turn, gradually roll on the throttle to bring speed back up smoothly; this completes the 'roll' phase and stabilizes the exit.","es":"Al enderezarse saliendo de la curva, abra el acelerador de forma gradual para recuperar velocidad con suavidad; así completa la fase 'acelerar' y estabiliza la salida.","ru":"Выпрямляясь на выходе, постепенно прибавляйте газ, чтобы плавно набрать скорость; это завершает фазу «газуй» и стабилизирует выход.","tr":"Virajdan çıkarken dikleşirken gazı kademeli açarak hızı yumuşakça yeniden artırın; bu 'gazla' aşamasını tamamlar ve çıkışı dengeler.","hi":"मोड़ से सीधा होते हुए धीरे-धीरे थ्रॉटल बढ़ाकर गति सहजता से वापस लाएँ; यह 'गैस' चरण पूरा करता है और निकास स्थिर करता है।","ar":"مع انتصابك خارجاً من المنعطف، افتح الخانق تدريجياً لاستعادة السرعة بسلاسة؛ فهذا يُكمل مرحلة 'التسريع' ويثبّت الخروج."}},{"cat":"visibility","a":1,"q":{"en":"How many lane positions does the Motorcycle Operator Manual say are available in a typical lane?","es":"¿Cuántas posiciones de carril dice el Manual del Operador de Motocicletas que hay en un carril típico?","ru":"Сколько положений в полосе, по данным Руководства мотоциклиста, доступно в обычной полосе?","tr":"Motosiklet Kullanıcı Kılavuzu, tipik bir şeritte kaç şerit konumu bulunduğunu söyler?","hi":"Motorcycle Operator Manual के अनुसार एक सामान्य लेन में कितनी लेन स्थितियाँ उपलब्ध होती हैं?","ar":"كم عدد مواضع المسار التي يقول دليل مشغّل الدراجة النارية إنها متاحة في مسار نموذجي؟"},"o":[{"en":"One","es":"Una","ru":"Одно","tr":"Bir","hi":"एक","ar":"واحد"},{"en":"Three","es":"Tres","ru":"Три","tr":"Üç","hi":"तीन","ar":"ثلاثة"},{"en":"Five","es":"Cinco","ru":"Пять","tr":"Beş","hi":"पाँच","ar":"خمسة"},{"en":"Seven","es":"Siete","ru":"Семь","tr":"Yedi","hi":"सात","ar":"سبعة"}],"e":{"en":"The manual describes three lane positions - left, center and right - each giving you a different view and level of visibility to others.","es":"El manual describe tres posiciones de carril - izquierda, centro y derecha - cada una con distinta visión y visibilidad ante los demás.","ru":"Руководство описывает три положения в полосе — левое, центральное и правое, каждое даёт свой обзор и заметность для других.","tr":"Kılavuz üç şerit konumu tanımlar - sol, orta ve sağ - her biri farklı bir görüş ve başkalarına karşı görünürlük sağlar.","hi":"मैनुअल तीन लेन स्थितियाँ बताता है - बायाँ, केंद्र और दायाँ - प्रत्येक अलग दृश्य और दूसरों के लिए दृश्यता देती है।","ar":"يصف الدليل ثلاثة مواضع في المسار - يسار ووسط ويمين - كل منها يمنحك رؤية مختلفة ومستوى ظهور مختلفاً للآخرين."}},{"cat":"visibility","a":2,"q":{"en":"To help the driver ahead notice you in their mirror, which lane position often works well?","es":"Para que el conductor de adelante lo note en su espejo, ¿qué posición de carril suele funcionar bien?","ru":"Чтобы водитель впереди заметил вас в зеркале, какое положение в полосе часто подходит?","tr":"Öndeki sürücünün sizi aynasında fark etmesi için hangi şerit konumu genellikle işe yarar?","hi":"आगे वाले चालक को अपने शीशे में आपको देखने में मदद के लिए कौन सी लेन स्थिति अक्सर अच्छी रहती है?","ar":"لمساعدة السائق الذي أمامك على ملاحظتك في مرآته، أي وضع في المسار غالباً ما ينجح؟"},"o":[{"en":"Riding in his blind spot","es":"Circular en su punto ciego","ru":"Ехать в его слепой зоне","tr":"Kör noktasında sürmek","hi":"उसके ब्लाइंड स्पॉट में चलना","ar":"القيادة في نقطته العمياء"},{"en":"Directly behind his bumper","es":"Justo detrás de su parachoques","ru":"Прямо за его бампером","tr":"Tamponunun hemen arkasında","hi":"ठीक उसके बंपर के पीछे","ar":"خلف مصدّه مباشرة"},{"en":"A position that puts your headlight in his rearview mirror","es":"Una posición que ponga su faro en el espejo retrovisor de él","ru":"Положение, при котором ваша фара попадает в его зеркало заднего вида","tr":"Farınızı onun dikiz aynasına getiren bir konum","hi":"ऐसी स्थिति जो आपकी हेडलाइट को उसके रियरव्यू शीशे में लाए","ar":"وضع يجعل مصباحك الأمامي في مرآته الخلفية"},{"en":"Far to the right shoulder","es":"Muy a la derecha, en el arcén","ru":"Далеко справа, на обочине","tr":"Sağ banket tarafına iyice yakın","hi":"बहुत दाएँ, कंधे पर","ar":"بعيداً إلى الكتف الأيمن"}],"e":{"en":"Choosing a lane position that places your headlight in the driver's rearview mirror makes you easier to notice, while still allowing you an escape path.","es":"Elegir una posición que coloque su faro en el espejo retrovisor del conductor lo hace más fácil de notar, y aún le deja una vía de escape.","ru":"Выбор положения, при котором ваша фара оказывается в зеркале заднего вида водителя, делает вас заметнее и оставляет путь для манёвра.","tr":"Farınızı sürücünün dikiz aynasına getiren bir konum seçmek sizi fark etmeyi kolaylaştırır ve size hâlâ bir kaçış yolu bırakır.","hi":"ऐसी लेन स्थिति चुनना जो आपकी हेडलाइट को चालक के रियरव्यू शीशे में लाए, आपको देखना आसान बनाती है और फिर भी बचने का रास्ता देती है।","ar":"اختيار وضع يضع مصباحك الأمامي في مرآة السائق الخلفية يجعل ملاحظتك أسهل، ويبقي لك مع ذلك مسار هروب."}},{"cat":"visibility","a":3,"q":{"en":"What is the main reason to ride with your headlight on during the day?","es":"¿Cuál es la razón principal para conducir con el faro encendido de día?","ru":"Какова главная причина ездить днём с включённой фарой?","tr":"Gündüz farınız açık sürmenin temel nedeni nedir?","hi":"दिन में हेडलाइट जलाकर चलाने का मुख्य कारण क्या है?","ar":"ما السبب الرئيسي للقيادة مع تشغيل المصباح الأمامي نهاراً؟"},"o":[{"en":"To see the road better in daylight","es":"Para ver mejor la vía de día","ru":"Чтобы лучше видеть дорогу днём","tr":"Gündüz yolu daha iyi görmek için","hi":"दिन में सड़क बेहतर देखने के लिए","ar":"لرؤية الطريق أفضل نهاراً"},{"en":"To satisfy a fuel-saving mode","es":"Para cumplir un modo de ahorro de combustible","ru":"Чтобы включить режим экономии топлива","tr":"Yakıt tasarrufu modunu sağlamak için","hi":"ईंधन-बचत मोड पूरा करने के लिए","ar":"لتفعيل وضع توفير الوقود"},{"en":"To warm up the bulb","es":"Para calentar la bombilla","ru":"Чтобы прогреть лампу","tr":"Ampulü ısıtmak için","hi":"बल्ब गर्म करने के लिए","ar":"لتسخين المصباح"},{"en":"To make you more visible to other drivers","es":"Para ser más visible a otros conductores","ru":"Чтобы быть заметнее для других водителей","tr":"Diğer sürücülere daha görünür olmak için","hi":"अन्य चालकों को अधिक दिखने के लिए","ar":"لتكون أكثر وضوحاً للسائقين الآخرين"}],"e":{"en":"A motorcycle's headlight makes it much easier for other drivers to see you even in daylight, which is why the manual recommends keeping it on.","es":"El faro de la moto hace mucho más fácil que otros conductores lo vean incluso de día, por eso el manual recomienda mantenerlo encendido.","ru":"Фара мотоцикла делает вас гораздо заметнее для других водителей даже днём, поэтому руководство советует держать её включённой.","tr":"Motosiklet farı, gündüz bile diğer sürücülerin sizi görmesini çok kolaylaştırır; bu yüzden kılavuz açık tutmayı önerir.","hi":"मोटरसाइकिल की हेडलाइट दिन में भी अन्य चालकों के लिए आपको देखना बहुत आसान बनाती है, इसलिए मैनुअल इसे जलाए रखने की सलाह देता है।","ar":"مصباح الدراجة الأمامي يجعل رؤيتك أسهل بكثير للسائقين الآخرين حتى نهاراً، ولهذا يوصي الدليل بإبقائه مضاءً."}},{"cat":"visibility","a":0,"q":{"en":"In the SEE strategy, what does the 'Search' step focus on?","es":"En la estrategia SEE, ¿en qué se centra el paso 'Buscar'?","ru":"В стратегии SEE на чём сосредоточен шаг «Search» (Искать)?","tr":"SEE stratejisinde 'Ara' adımı neye odaklanır?","hi":"SEE रणनीति में 'खोज' (Search) चरण किस पर केंद्रित है?","ar":"في استراتيجية SEE، على ماذا تركّز خطوة 'ابحث' (Search)؟"},"o":[{"en":"Actively scanning ahead and around for hazards","es":"Explorar activamente adelante y alrededor buscando peligros","ru":"Активно осматривать пространство впереди и вокруг на предмет опасностей","tr":"Tehlikeler için önü ve çevreyi etkin biçimde taramak","hi":"खतरों के लिए आगे और आसपास सक्रिय रूप से देखना","ar":"المسح النشط للأمام وما حولك بحثاً عن المخاطر"},{"en":"Checking your fuel gauge","es":"Revisar el indicador de combustible","ru":"Проверять указатель топлива","tr":"Yakıt göstergesini kontrol etmek","hi":"ईंधन गेज जाँचना","ar":"فحص مؤشر الوقود"},{"en":"Adjusting your mirrors only","es":"Ajustar solo los espejos","ru":"Только регулировать зеркала","tr":"Yalnızca aynaları ayarlamak","hi":"केवल शीशे समायोजित करना","ar":"ضبط المرايا فقط"},{"en":"Signaling your turns","es":"Señalizar sus giros","ru":"Подавать сигналы поворота","tr":"Dönüşlerinizi sinyalle bildirmek","hi":"अपने मोड़ों का संकेत देना","ar":"الإشارة إلى انعطافاتك"}],"e":{"en":"'Search' means aggressively scanning the road ahead, to the sides and behind for hazards and changing conditions so you get early warning of trouble.","es":"'Buscar' significa explorar activamente adelante, a los lados y atrás en busca de peligros y cambios, para anticipar los problemas.","ru":"«Искать» — активно осматривать дорогу впереди, по сторонам и сзади, выявляя опасности и изменения, чтобы заранее заметить проблему.","tr":"'Ara', tehlikeler ve değişen koşullar için önü, yanları ve arkayı etkin biçimde taramak demektir; böylece sorunları erkenden fark edersiniz.","hi":"'खोज' का अर्थ है आगे, बगल और पीछे खतरों तथा बदलती परिस्थितियों के लिए सक्रिय रूप से देखना ताकि समस्या की पूर्व चेतावनी मिले।","ar":"'ابحث' يعني مسح الطريق أمامك وعلى الجانبين وخلفك بنشاط بحثاً عن المخاطر والظروف المتغيّرة كي تحصل على إنذار مبكر بالمشكلة."}},{"cat":"visibility","a":1,"q":{"en":"In the SEE strategy, the 'Evaluate' step means:","es":"En la estrategia SEE, el paso 'Evaluar' significa:","ru":"В стратегии SEE шаг «Evaluate» (Оценить) означает:","tr":"SEE stratejisinde 'Değerlendir' adımı şu demektir:","hi":"SEE रणनीति में 'मूल्यांकन' (Evaluate) चरण का अर्थ है:","ar":"في استراتيجية SEE، خطوة 'قيّم' (Evaluate) تعني:"},"o":[{"en":"Speeding up to clear traffic","es":"Acelerar para librar el tráfico","ru":"Ускоряться, чтобы уйти от потока","tr":"Trafiği geçmek için hızlanmak","hi":"ट्रैफ़िक निकालने के लिए तेज होना","ar":"التسارع لتجاوز الزحام"},{"en":"Thinking about how hazards might interact and what could happen","es":"Pensar cómo pueden interactuar los peligros y qué podría pasar","ru":"Обдумывать, как опасности могут взаимодействовать и что может произойти","tr":"Tehlikelerin nasıl etkileşebileceğini ve ne olabileceğini düşünmek","hi":"सोचना कि खतरे कैसे परस्पर क्रिया कर सकते हैं और क्या हो सकता है","ar":"التفكير في كيفية تفاعل المخاطر وما قد يحدث"},{"en":"Braking as hard as possible","es":"Frenar lo más fuerte posible","ru":"Тормозить как можно сильнее","tr":"Olabildiğince sert frenlemek","hi":"जितना हो सके जोर से ब्रेक लगाना","ar":"الكبح بأقصى قوة"},{"en":"Turning off your lights","es":"Apagar las luces","ru":"Выключать фары","tr":"Işıklarınızı kapatmak","hi":"अपनी लाइटें बंद करना","ar":"إطفاء أضوائك"}],"e":{"en":"'Evaluate' is anticipating how the hazards you have spotted might develop or combine, and predicting how they could affect you, so you can plan a response.","es":"'Evaluar' es anticipar cómo pueden desarrollarse o combinarse los peligros detectados y prever cómo podrían afectarlo, para planear una respuesta.","ru":"«Оценить» — предвидеть, как замеченные опасности могут развиться или сочетаться, и предсказать их влияние на вас, чтобы спланировать реакцию.","tr":"'Değerlendir', fark ettiğiniz tehlikelerin nasıl gelişip birleşebileceğini öngörmek ve sizi nasıl etkileyebileceğini tahmin ederek bir yanıt planlamaktır.","hi":"'मूल्यांकन' का अर्थ है यह अनुमान लगाना कि देखे गए खतरे कैसे विकसित या संयुक्त हो सकते हैं और वे आप पर कैसे असर डाल सकते हैं, ताकि आप प्रतिक्रिया की योजना बना सकें।","ar":"'قيّم' هو توقّع كيف قد تتطور المخاطر التي رصدتها أو تتجمّع، والتنبؤ بكيفية تأثيرها عليك، كي تخطط للاستجابة."}},{"cat":"visibility","a":2,"q":{"en":"In the SEE strategy, which action best fits the 'Execute' step?","es":"En la estrategia SEE, ¿qué acción encaja mejor con el paso 'Ejecutar'?","ru":"В стратегии SEE какое действие лучше всего соответствует шагу «Execute» (Действовать)?","tr":"SEE stratejisinde hangi eylem 'Uygula' adımına en iyi uyar?","hi":"SEE रणनीति में कौन सी क्रिया 'निष्पादन' (Execute) चरण से सबसे मेल खाती है?","ar":"في استراتيجية SEE، أي إجراء يناسب خطوة 'نفّذ' (Execute) أكثر؟"},"o":[{"en":"Guessing what others will do","es":"Adivinar qué harán los demás","ru":"Гадать, что сделают другие","tr":"Başkalarının ne yapacağını tahmin etmek","hi":"अनुमान लगाना कि अन्य क्या करेंगे","ar":"تخمين ما سيفعله الآخرون"},{"en":"Only watching mirrors","es":"Solo mirar los espejos","ru":"Только смотреть в зеркала","tr":"Yalnızca aynalara bakmak","hi":"केवल शीशे देखना","ar":"مراقبة المرايا فقط"},{"en":"Adjusting speed, position or communicating to carry out your plan","es":"Ajustar velocidad, posición o comunicarse para llevar a cabo su plan","ru":"Регулировать скорость, положение или подавать сигналы, чтобы выполнить план","tr":"Planınızı gerçekleştirmek için hızı, konumu ayarlamak veya iletişim kurmak","hi":"अपनी योजना पूरी करने के लिए गति, स्थिति समायोजित करना या संवाद करना","ar":"ضبط السرعة أو الموضع أو التواصل لتنفيذ خطتك"},{"en":"Turning off the engine","es":"Apagar el motor","ru":"Глушить двигатель","tr":"Motoru kapatmak","hi":"इंजन बंद करना","ar":"إطفاء المحرك"}],"e":{"en":"'Execute' is acting on your plan by adjusting speed, changing lane position, and communicating (signals, horn, brake light) to keep space and stay safe.","es":"'Ejecutar' es actuar según su plan ajustando la velocidad, cambiando de posición y comunicándose (señales, bocina, luz de freno) para mantener espacio y seguridad.","ru":"«Действовать» — реализовать план: менять скорость и положение в полосе, подавать сигналы (поворотники, сигнал, стоп-сигнал), сохраняя запас и безопасность.","tr":"'Uygula', planınıza göre hareket etmektir: hızı ayarlamak, şerit konumunu değiştirmek ve iletişim kurmak (sinyal, korna, fren lambası) ile boşluk ve güvenliği korumak.","hi":"'निष्पादन' अपनी योजना पर अमल करना है: गति समायोजित करना, लेन स्थिति बदलना और संवाद करना (संकेत, हॉर्न, ब्रेक लाइट) ताकि जगह और सुरक्षा बनी रहे।","ar":"'نفّذ' هو العمل وفق خطتك بضبط السرعة وتغيير الموضع والتواصل (الإشارات والبوق وضوء الفرامل) للحفاظ على المسافة والأمان."}},{"cat":"visibility","a":3,"q":{"en":"Before you change lanes, what must you do about your blind spots?","es":"Antes de cambiar de carril, ¿qué debe hacer respecto a sus puntos ciegos?","ru":"Прежде чем менять полосу, что нужно сделать со слепыми зонами?","tr":"Şerit değiştirmeden önce kör noktalarınızla ilgili ne yapmalısınız?","hi":"लेन बदलने से पहले अपने ब्लाइंड स्पॉट के बारे में क्या करना चाहिए?","ar":"قبل تغيير المسار، ماذا يجب أن تفعل بشأن نقاطك العمياء؟"},"o":[{"en":"Trust the mirrors alone","es":"Confiar solo en los espejos","ru":"Полагаться только на зеркала","tr":"Yalnızca aynalara güvenmek","hi":"केवल शीशों पर भरोसा करें","ar":"الاعتماد على المرايا وحدها"},{"en":"Rely on your signal to clear them","es":"Confiar en la señal para librarlos","ru":"Полагаться на поворотник, чтобы их «очистить»","tr":"Onları temizlemek için sinyalinize güvenmek","hi":"उन्हें साफ करने के लिए अपने संकेत पर निर्भर रहें","ar":"الاعتماد على إشارتك لتجاوزها"},{"en":"Assume they are empty at low speed","es":"Suponer que están vacíos a baja velocidad","ru":"Считать их пустыми на малой скорости","tr":"Düşük hızda boş olduklarını varsaymak","hi":"मान लें कि कम गति पर वे खाली हैं","ar":"افتراض أنها فارغة عند السرعة المنخفضة"},{"en":"Turn your head to check them directly","es":"Girar la cabeza para revisarlos directamente","ru":"Повернуть голову и проверить их напрямую","tr":"Başınızı çevirip onları doğrudan kontrol etmek","hi":"उन्हें सीधे जाँचने के लिए सिर घुमाएँ","ar":"إدارة رأسك لفحصها مباشرة"}],"e":{"en":"Mirrors do not show the blind spots beside and slightly behind you, so turn your head to look directly before changing lanes or merging.","es":"Los espejos no muestran los puntos ciegos a los lados y algo atrás, así que gire la cabeza para mirar directamente antes de cambiar de carril o incorporarse.","ru":"Зеркала не показывают слепые зоны сбоку и чуть сзади, поэтому перед сменой полосы или перестроением поверните голову и посмотрите напрямую.","tr":"Aynalar yanınızdaki ve biraz arkanızdaki kör noktaları göstermez; bu yüzden şerit değiştirmeden veya katılmadan önce başınızı çevirip doğrudan bakın.","hi":"शीशे बगल और थोड़ा पीछे के ब्लाइंड स्पॉट नहीं दिखाते, इसलिए लेन बदलने या मिलाने से पहले सिर घुमाकर सीधे देखें।","ar":"لا تُظهر المرايا النقاط العمياء بجانبك وخلفك قليلاً، لذا أدر رأسك لتنظر مباشرة قبل تغيير المسار أو الاندماج."}},{"cat":"visibility","a":0,"q":{"en":"What does the manual advise about riding in another vehicle's blind spot?","es":"¿Qué aconseja el manual sobre circular en el punto ciego de otro vehículo?","ru":"Что советует руководство относительно езды в слепой зоне другой машины?","tr":"Kılavuz, başka bir aracın kör noktasında sürmek konusunda ne önerir?","hi":"किसी अन्य वाहन के ब्लाइंड स्पॉट में चलने के बारे में मैनुअल क्या सलाह देता है?","ar":"بماذا ينصح الدليل بشأن القيادة في النقطة العمياء لمركبة أخرى؟"},"o":[{"en":"Avoid lingering there; ride where you can be seen","es":"Evitar quedarse allí; circular donde pueda ser visto","ru":"Не задерживаться там; ехать там, где вас видно","tr":"Orada oyalanmaktan kaçının; görülebileceğiniz yerde sürün","hi":"वहाँ रुके न रहें; वहाँ चलें जहाँ आप दिख सकें","ar":"تجنّب البقاء هناك؛ اركب حيث يمكن رؤيتك"},{"en":"Stay there so you are out of the way","es":"Quedarse allí para no estorbar","ru":"Оставаться там, чтобы не мешать","tr":"Yoldan çekilmek için orada kalın","hi":"वहाँ रहें ताकि रास्ते से हटे रहें","ar":"ابقَ هناك كي تكون بعيداً عن الطريق"},{"en":"Ride there only on highways","es":"Circular allí solo en autopistas","ru":"Ехать там только на автомагистралях","tr":"Orada yalnızca otoyolda sürün","hi":"वहाँ केवल राजमार्गों पर चलें","ar":"اركب هناك على الطرق السريعة فقط"},{"en":"Match the other vehicle's exact speed there","es":"Igualar allí la velocidad exacta del otro vehículo","ru":"Точно подстраивать там скорость под другую машину","tr":"Orada diğer aracın hızını birebir eşleştirin","hi":"वहाँ अन्य वाहन की सटीक गति से चलें","ar":"طابِق سرعة المركبة الأخرى تماماً هناك"}],"e":{"en":"Riding in another driver's blind spot means they may not know you are there; the manual says to ride where you can be seen and not linger in blind spots.","es":"Circular en el punto ciego de otro conductor significa que quizá no sepa que está allí; el manual dice conducir donde pueda ser visto y no quedarse en puntos ciegos.","ru":"Езда в слепой зоне другого водителя означает, что он может не знать о вас; руководство советует ехать там, где вас видно, и не задерживаться в слепых зонах.","tr":"Başka bir sürücünün kör noktasında sürmek, orada olduğunuzu bilmeyebileceği anlamına gelir; kılavuz görülebileceğiniz yerde sürmeyi ve kör noktalarda oyalanmamayı söyler.","hi":"किसी अन्य चालक के ब्लाइंड स्पॉट में चलने का अर्थ है कि उसे शायद पता न हो कि आप वहाँ हैं; मैनुअल कहता है वहाँ चलें जहाँ आप दिखें और ब्लाइंड स्पॉट में न रुकें।","ar":"القيادة في النقطة العمياء لسائق آخر تعني أنه قد لا يعرف بوجودك؛ يقول الدليل اركب حيث يمكن رؤيتك ولا تبقَ في النقاط العمياء."}},{"cat":"visibility","a":1,"q":{"en":"Why does the manual warn against relying on eye contact with a driver?","es":"¿Por qué advierte el manual contra confiar en el contacto visual con un conductor?","ru":"Почему руководство предостерегает полагаться на зрительный контакт с водителем?","tr":"Kılavuz neden bir sürücüyle göz teması kurmaya güvenmeye karşı uyarır?","hi":"मैनुअल किसी चालक से आँख संपर्क पर भरोसा करने के खिलाफ चेतावनी क्यों देता है?","ar":"لماذا يحذّر الدليل من الاعتماد على التواصل البصري مع السائق؟"},"o":[{"en":"Eye contact guarantees they will yield","es":"El contacto visual garantiza que cederán el paso","ru":"Зрительный контакт гарантирует, что вам уступят","tr":"Göz teması yol vereceklerini garanti eder","hi":"आँख संपर्क गारंटी देता है कि वे रास्ता देंगे","ar":"التواصل البصري يضمن أنهم سيفسحون الطريق"},{"en":"A driver may look at you yet still not truly register you","es":"Un conductor puede mirarlo y aun así no percibirlo realmente","ru":"Водитель может смотреть на вас и всё равно вас не воспринять","tr":"Bir sürücü size bakabilir ama yine de sizi gerçekten algılamayabilir","hi":"चालक आपको देख सकता है फिर भी वास्तव में आपको दर्ज न करे","ar":"قد ينظر إليك السائق ومع ذلك لا يدركك فعلاً"},{"en":"It is illegal to make eye contact","es":"Es ilegal hacer contacto visual","ru":"Зрительный контакт запрещён","tr":"Göz teması kurmak yasa dışıdır","hi":"आँख संपर्क करना अवैध है","ar":"التواصل البصري غير قانوني"},{"en":"Drivers cannot see motorcycles at all","es":"Los conductores no pueden ver motos en absoluto","ru":"Водители вообще не видят мотоциклы","tr":"Sürücüler motosikletleri hiç göremez","hi":"चालक मोटरसाइकिल बिल्कुल नहीं देख सकते","ar":"لا يستطيع السائقون رؤية الدراجات إطلاقاً"}],"e":{"en":"Even if a driver appears to look right at you, they may not actually see or register a motorcycle, so never assume eye contact means they will yield.","es":"Aunque un conductor parezca mirarlo directamente, quizá no vea ni registre una moto, así que nunca suponga que el contacto visual significa que cederá.","ru":"Даже если водитель словно смотрит прямо на вас, он может не увидеть и не осознать мотоцикл, поэтому не считайте зрительный контакт гарантией уступки.","tr":"Bir sürücü tam size bakıyor gibi görünse bile motosikleti gerçekten görmeyebilir veya algılamayabilir; bu yüzden göz temasını yol verecekleri anlamına asla saymayın.","hi":"भले ही कोई चालक सीधे आपकी ओर देखता प्रतीत हो, वह वास्तव में मोटरसाइकिल न देखे या दर्ज न करे, इसलिए आँख संपर्क को कभी यह न मानें कि वे रास्ता देंगे।","ar":"حتى لو بدا أن السائق ينظر إليك مباشرة، فقد لا يرى الدراجة أو يدركها فعلاً، لذا لا تفترض أبداً أن التواصل البصري يعني أنه سيفسح الطريق."}},{"cat":"visibility","a":2,"q":{"en":"Where does the manual say the greatest potential for conflict with other traffic occurs?","es":"¿Dónde dice el manual que ocurre el mayor potencial de conflicto con otros vehículos?","ru":"Где, по руководству, наиболее вероятен конфликт с другим транспортом?","tr":"Kılavuz, diğer trafikle çatışma potansiyelinin en yüksek olduğu yeri neresi olarak belirtir?","hi":"मैनुअल के अनुसार अन्य ट्रैफ़िक से टकराव की सबसे बड़ी संभावना कहाँ होती है?","ar":"أين يقول الدليل إن أكبر احتمال للتعارض مع حركة المرور الأخرى يحدث؟"},"o":[{"en":"On empty rural roads","es":"En caminos rurales vacíos","ru":"На пустых сельских дорогах","tr":"Boş kırsal yollarda","hi":"खाली ग्रामीण सड़कों पर","ar":"على الطرق الريفية الفارغة"},{"en":"In your own driveway","es":"En su propia entrada","ru":"На собственном подъезде","tr":"Kendi garaj yolunuzda","hi":"अपने ही ड्राइववे में","ar":"في ممر منزلك"},{"en":"At intersections","es":"En las intersecciones","ru":"На перекрёстках","tr":"Kavşaklarda","hi":"चौराहों पर","ar":"عند التقاطعات"},{"en":"On long bridges","es":"En puentes largos","ru":"На длинных мостах","tr":"Uzun köprülerde","hi":"लंबे पुलों पर","ar":"على الجسور الطويلة"}],"e":{"en":"The manual identifies intersections as where the greatest potential for conflict occurs, often because a driver turns across the motorcyclist's path.","es":"El manual señala las intersecciones como el lugar con mayor potencial de conflicto, a menudo porque un conductor gira cruzando el camino del motociclista.","ru":"Руководство называет перекрёстки местом наибольшего риска конфликта, часто потому что водитель поворачивает поперёк траектории мотоциклиста.","tr":"Kılavuz, çatışma potansiyelinin en yüksek olduğu yer olarak kavşakları belirtir; çoğu zaman bir sürücü motosikletlinin yolunu keserek döndüğü için.","hi":"मैनुअल चौराहों को टकराव की सबसे बड़ी संभावना वाला स्थान बताता है, अक्सर इसलिए कि कोई चालक मोटरसाइकिल के रास्ते को काटते हुए मुड़ता है।","ar":"يحدّد الدليل التقاطعات كأكبر مكان لاحتمال التعارض، غالباً لأن سائقاً ينعطف قاطعاً مسار سائق الدراجة."}},{"cat":"visibility","a":3,"q":{"en":"How does adjusting your lane position help with being seen at an intersection?","es":"¿Cómo ayuda ajustar la posición en el carril a ser visto en una intersección?","ru":"Как корректировка положения в полосе помогает быть замеченным на перекрёстке?","tr":"Şerit konumunuzu ayarlamak kavşakta görülmeye nasıl yardımcı olur?","hi":"लेन स्थिति समायोजित करना चौराहे पर दिखने में कैसे मदद करता है?","ar":"كيف يساعد ضبط وضعك في المسار على أن تُرى عند تقاطع؟"},"o":[{"en":"It hides you from cross traffic","es":"Lo oculta del tráfico transversal","ru":"Оно скрывает вас от поперечного потока","tr":"Sizi çapraz trafikten gizler","hi":"यह आपको क्रॉस ट्रैफ़िक से छुपाता है","ar":"يخفيك عن حركة المرور المتقاطعة"},{"en":"It has no effect at intersections","es":"No tiene efecto en las intersecciones","ru":"Оно не действует на перекрёстках","tr":"Kavşaklarda etkisi yoktur","hi":"चौराहों पर इसका कोई असर नहीं","ar":"لا أثر له عند التقاطعات"},{"en":"It lets you skip stopping","es":"Permite omitir la detención","ru":"Оно позволяет не останавливаться","tr":"Durmayı atlamanızı sağlar","hi":"यह रुकना छोड़ने देता है","ar":"يتيح لك تجاوز التوقف"},{"en":"It can move you out from behind obstructions so drivers can see you","es":"Puede sacarlo de detrás de obstáculos para que los conductores lo vean","ru":"Оно может вывести вас из-за препятствий, чтобы водители вас видели","tr":"Sizi engellerin arkasından çıkararak sürücülerin sizi görmesini sağlayabilir","hi":"यह आपको बाधाओं के पीछे से हटा सकता है ताकि चालक आपको देख सकें","ar":"يمكن أن يُخرجك من خلف العوائق كي يراك السائقون"}],"e":{"en":"Choosing a lane position that keeps you out from behind cars, signs or other obstructions helps drivers at the intersection see you sooner.","es":"Elegir una posición que lo mantenga fuera de detrás de autos, señales u otros obstáculos ayuda a que los conductores en la intersección lo vean antes.","ru":"Выбор положения, при котором вы не скрыты за машинами, знаками и другими препятствиями, помогает водителям на перекрёстке заметить вас раньше.","tr":"Sizi arabaların, tabelaların veya diğer engellerin arkasından çıkaran bir konum seçmek, kavşaktaki sürücülerin sizi daha erken görmesini sağlar.","hi":"ऐसी लेन स्थिति चुनना जो आपको कारों, संकेतों या अन्य बाधाओं के पीछे से बाहर रखे, चौराहे के चालकों को आपको जल्दी देखने में मदद करती है।","ar":"اختيار وضع يبقيك خارج مجال الحجب خلف السيارات أو اللافتات أو العوائق الأخرى يساعد السائقين عند التقاطع على رؤيتك أبكر."}},{"cat":"visibility","a":0,"q":{"en":"When you are being passed by another vehicle, which lane position is usually best?","es":"Cuando otro vehículo lo está rebasando, ¿qué posición de carril suele ser mejor?","ru":"Когда вас обгоняет другая машина, какое положение в полосе обычно лучше?","tr":"Başka bir araç sizi geçerken hangi şerit konumu genellikle en iyisidir?","hi":"जब कोई अन्य वाहन आपको ओवरटेक कर रहा हो, तो कौन सी लेन स्थिति आमतौर पर सर्वोत्तम है?","ar":"عندما تتجاوزك مركبة أخرى، أي وضع في المسار يكون الأفضل عادةً؟"},"o":[{"en":"The center portion of the lane","es":"La parte central del carril","ru":"Центральная часть полосы","tr":"Şeridin orta kısmı","hi":"लेन का केंद्रीय भाग","ar":"الجزء الأوسط من المسار"},{"en":"As close to the passing vehicle as possible","es":"Lo más cerca posible del vehículo que rebasa","ru":"Как можно ближе к обгоняющей машине","tr":"Geçen araca olabildiğince yakın","hi":"ओवरटेक करने वाले वाहन के जितना पास हो सके","ar":"أقرب ما يمكن إلى المركبة المتجاوِزة"},{"en":"On the shoulder","es":"En el arcén","ru":"На обочине","tr":"Banket üzerinde","hi":"कंधे पर","ar":"على الكتف"},{"en":"Straddling the lane line","es":"A caballo sobre la línea del carril","ru":"Верхом на линии полосы","tr":"Şerit çizgisine basarak","hi":"लेन लाइन पर सवार होकर","ar":"فوق خط المسار"}],"e":{"en":"Hold the center portion of your lane while being passed; it keeps you away from the passing vehicle and out of wind blasts and debris on either side.","es":"Mantenga la parte central del carril mientras lo rebasan; lo aleja del vehículo que pasa y de las ráfagas de viento y residuos a los lados.","ru":"Держитесь центральной части полосы при обгоне; это отдаляет вас от обгоняющей машины и от порывов ветра и мусора по краям.","tr":"Sizi geçerken şeridin orta kısmında kalın; bu sizi geçen araçtan ve iki yandaki rüzgâr darbeleri ile döküntüden uzak tutar.","hi":"ओवरटेक होते समय अपनी लेन के केंद्रीय भाग में रहें; यह आपको गुजरते वाहन तथा दोनों ओर की हवा के झोंकों और मलबे से दूर रखता है।","ar":"ابقَ في الجزء الأوسط من مسارك أثناء تجاوزك؛ فهذا يبقيك بعيداً عن المركبة المتجاوِزة وعن هبّات الرياح والحطام على الجانبين."}},{"cat":"visibility","a":1,"q":{"en":"What should you do with your turn signal after you finish a lane change or turn?","es":"¿Qué debe hacer con la señal de giro después de terminar un cambio de carril o giro?","ru":"Что делать с указателем поворота после завершения смены полосы или поворота?","tr":"Şerit değişimini veya dönüşü bitirdikten sonra sinyalinizle ne yapmalısınız?","hi":"लेन बदलने या मुड़ने के बाद अपने टर्न सिग्नल का क्या करना चाहिए?","ar":"ماذا يجب أن تفعل بإشارة الانعطاف بعد إتمام تغيير المسار أو الانعطاف؟"},"o":[{"en":"Leave it on for the next mile","es":"Dejarla encendida el siguiente kilómetro","ru":"Оставить его включённым ещё на километр","tr":"Bir sonraki kilometre boyunca açık bırakmak","hi":"अगले किलोमीटर के लिए जलाए रखें","ar":"تركها مضاءة للمسافة التالية"},{"en":"Turn it off if it did not cancel by itself","es":"Apagarla si no se canceló sola","ru":"Выключить его, если он не отключился сам","tr":"Kendiliğinden iptal olmadıysa kapatmak","hi":"यदि यह स्वयं रद्द न हुआ हो तो इसे बंद करें","ar":"إطفاؤها إن لم تنطفئ من تلقاء نفسها"},{"en":"Switch on the other signal","es":"Encender la otra señal","ru":"Включить другой поворотник","tr":"Diğer sinyali açmak","hi":"दूसरा सिग्नल चालू करें","ar":"تشغيل الإشارة الأخرى"},{"en":"Flash the high beam instead","es":"Encender la luz alta en su lugar","ru":"Вместо этого мигнуть дальним светом","tr":"Bunun yerine uzun farı çakmak","hi":"इसके बजाय हाई बीम फ्लैश करें","ar":"وميض الضوء العالي بدلاً من ذلك"}],"e":{"en":"Many motorcycle signals do not self-cancel; after the maneuver, make sure to turn the signal off so you do not mislead other drivers.","es":"Muchas señales de moto no se cancelan solas; tras la maniobra, asegúrese de apagarla para no confundir a otros conductores.","ru":"Многие мотосигналы не отключаются автоматически; после манёвра обязательно выключите поворотник, чтобы не вводить в заблуждение других.","tr":"Birçok motosiklet sinyali kendiliğinden iptal olmaz; manevradan sonra diğer sürücüleri yanıltmamak için sinyali kapattığınızdan emin olun.","hi":"कई मोटरसाइकिल सिग्नल स्वयं रद्द नहीं होते; युद्धाभ्यास के बाद सुनिश्चित करें कि सिग्नल बंद कर दें ताकि अन्य चालकों को भ्रमित न करें।","ar":"كثير من إشارات الدراجات لا تنطفئ ذاتياً؛ بعد المناورة، تأكد من إطفاء الإشارة كي لا تُضلّل السائقين الآخرين."}},{"cat":"visibility","a":2,"q":{"en":"Why does the manual say a motorcycle is often 'not seen' even when in plain view?","es":"¿Por qué dice el manual que a menudo una moto 'no es vista' aun estando a plena vista?","ru":"Почему руководство говорит, что мотоцикл часто «не замечают», даже когда он на виду?","tr":"Kılavuz neden bir motosikletin açıkça görünürken bile sıklıkla 'görülmediğini' söyler?","hi":"मैनुअल क्यों कहता है कि साफ दिखने पर भी मोटरसाइकिल अक्सर 'नहीं दिखती'?","ar":"لماذا يقول الدليل إن الدراجة غالباً 'لا تُرى' حتى وهي ظاهرة بوضوح؟"},"o":[{"en":"Because motorcycles are invisible in daylight","es":"Porque las motos son invisibles de día","ru":"Потому что мотоциклы невидимы днём","tr":"Çünkü motosikletler gündüz görünmezdir","hi":"क्योंकि मोटरसाइकिल दिन में अदृश्य होती हैं","ar":"لأن الدراجات غير مرئية نهاراً"},{"en":"Because headlights never help","es":"Porque los faros nunca ayudan","ru":"Потому что фары никогда не помогают","tr":"Çünkü farlar asla yardımcı olmaz","hi":"क्योंकि हेडलाइट कभी मदद नहीं करती","ar":"لأن المصابيح لا تفيد أبداً"},{"en":"Its small profile is easy to overlook and drivers look for cars","es":"Su perfil pequeño se pasa por alto y los conductores buscan autos","ru":"Его малый силуэт легко упустить, а водители ищут автомобили","tr":"Küçük görüntüsü kolayca gözden kaçar ve sürücüler araba arar","hi":"इसका छोटा आकार आसानी से नजरअंदाज होता है और चालक कारों को खोजते हैं","ar":"مظهرها الصغير يسهل إغفاله والسائقون يبحثون عن السيارات"},{"en":"Because mirrors distort motorcycles","es":"Porque los espejos distorsionan las motos","ru":"Потому что зеркала искажают мотоциклы","tr":"Çünkü aynalar motosikletleri çarpıtır","hi":"क्योंकि शीशे मोटरसाइकिल को विकृत करते हैं","ar":"لأن المرايا تشوّه الدراجات"}],"e":{"en":"A motorcycle presents a narrow profile that is easy to miss, and drivers scanning for cars may not register it, so make yourself as visible as possible.","es":"Una moto presenta un perfil estrecho fácil de pasar por alto, y los conductores que buscan autos pueden no registrarla, así que hágase lo más visible posible.","ru":"Мотоцикл имеет узкий силуэт, который легко пропустить, а водители, высматривающие автомобили, могут его не заметить, поэтому будьте максимально заметны.","tr":"Motosiklet, kolayca gözden kaçan dar bir görüntü sunar ve araba arayan sürücüler onu algılamayabilir; bu yüzden mümkün olduğunca görünür olun.","hi":"मोटरसाइकिल का पतला आकार आसानी से चूक जाता है, और कारों को खोज रहे चालक इसे दर्ज न करें, इसलिए स्वयं को यथासंभव दृश्य बनाएँ।","ar":"تُظهر الدراجة مظهراً ضيقاً يسهل إغفاله، وقد لا يدركها السائقون الباحثون عن سيارات، لذا اجعل نفسك مرئياً قدر الإمكان."}},{"cat":"visibility","a":3,"q":{"en":"When is it appropriate to use your horn according to the manual?","es":"¿Cuándo es apropiado usar la bocina según el manual?","ru":"Когда, по руководству, уместно использовать сигнал?","tr":"Kılavuza göre korna ne zaman uygun kullanılır?","hi":"मैनुअल के अनुसार अपना हॉर्न कब उपयोग करना उचित है?","ar":"متى يكون استخدام البوق مناسباً وفقاً للدليل؟"},"o":[{"en":"To greet other riders","es":"Para saludar a otros motociclistas","ru":"Чтобы приветствовать других мотоциклистов","tr":"Diğer sürücüleri selamlamak için","hi":"अन्य राइडर्स का अभिवादन करने के लिए","ar":"لتحية السائقين الآخرين"},{"en":"To urge slow traffic along","es":"Para apurar al tráfico lento","ru":"Чтобы подгонять медленный поток","tr":"Yavaş trafiği hızlandırmak için","hi":"धीमे ट्रैफ़िक को हड़काने के लिए","ar":"لحثّ حركة المرور البطيئة"},{"en":"Constantly in heavy traffic","es":"Constantemente en tráfico denso","ru":"Постоянно в плотном потоке","tr":"Yoğun trafikte sürekli","hi":"घने ट्रैफ़िक में लगातार","ar":"باستمرار في الزحام الكثيف"},{"en":"To warn someone who may create a hazard, such as a driver drifting into your lane","es":"Para advertir a alguien que pueda crear un peligro, como un conductor que invade su carril","ru":"Чтобы предупредить того, кто может создать опасность, например водителя, въезжающего в вашу полосу","tr":"Tehlike yaratabilecek birini, örneğin şeridinize kayan bir sürücüyü uyarmak için","hi":"किसी को चेतावनी देने के लिए जो खतरा पैदा कर सकता है, जैसे आपकी लेन में आ रहा चालक","ar":"لتحذير شخص قد يخلق خطراً، مثل سائق ينحرف إلى مسارك"}],"e":{"en":"Use the horn to warn others of a developing hazard - for example, a driver starting to drift into your lane or pull out - rather than as a greeting.","es":"Use la bocina para advertir de un peligro que surge - por ejemplo, un conductor que empieza a invadir su carril o a salir - no como saludo.","ru":"Используйте сигнал, чтобы предупредить о назревающей опасности — например, о водителе, начинающем въезжать в вашу полосу или выезжать, — а не как приветствие.","tr":"Kornayı bir selam olarak değil, gelişen bir tehlikeyi - örneğin şeridinize kaymaya veya çıkmaya başlayan bir sürücüyü - uyarmak için kullanın.","hi":"हॉर्न का उपयोग उभरते खतरे की चेतावनी के लिए करें - जैसे कोई चालक आपकी लेन में आने या निकलने लगे - न कि अभिवादन के रूप में।","ar":"استخدم البوق لتحذير الآخرين من خطر ناشئ - مثل سائق يبدأ بالانحراف إلى مسارك أو الخروج - لا كتحية."}},{"cat":"visibility","a":0,"q":{"en":"Why should you keep a cushion of space on all sides of your motorcycle?","es":"¿Por qué debe mantener un colchón de espacio en todos los lados de su moto?","ru":"Почему важно сохранять запас пространства со всех сторон мотоцикла?","tr":"Motosikletinizin her yönünde neden bir boşluk tamponu bırakmalısınız?","hi":"अपनी मोटरसाइकिल के चारों ओर स्थान का कुशन क्यों बनाए रखना चाहिए?","ar":"لماذا يجب أن تحافظ على مساحة أمان من جميع جوانب دراجتك؟"},"o":[{"en":"It gives you room and time to react to hazards","es":"Le da espacio y tiempo para reaccionar ante peligros","ru":"Он даёт место и время, чтобы среагировать на опасности","tr":"Tehlikelere tepki vermek için yer ve zaman kazandırır","hi":"यह खतरों पर प्रतिक्रिया करने के लिए जगह और समय देता है","ar":"يمنحك مساحة ووقتاً للتفاعل مع المخاطر"},{"en":"It saves fuel","es":"Ahorra combustible","ru":"Он экономит топливо","tr":"Yakıt tasarrufu sağlar","hi":"यह ईंधन बचाता है","ar":"يوفّر الوقود"},{"en":"It keeps the engine cool","es":"Mantiene el motor frío","ru":"Он охлаждает двигатель","tr":"Motoru serin tutar","hi":"यह इंजन को ठंडा रखता है","ar":"يبقي المحرك بارداً"},{"en":"It is required only on highways","es":"Solo se exige en autopistas","ru":"Он нужен только на автомагистралях","tr":"Yalnızca otoyollarda gereklidir","hi":"यह केवल राजमार्गों पर आवश्यक है","ar":"مطلوب على الطرق السريعة فقط"}],"e":{"en":"A space cushion around you gives room to swerve or brake and the time to see and respond to hazards before they become emergencies.","es":"Un colchón de espacio a su alrededor da margen para esquivar o frenar y tiempo para ver y responder a los peligros antes de que sean emergencias.","ru":"Запас пространства вокруг даёт место для манёвра или торможения и время заметить опасность и отреагировать до того, как она станет аварией.","tr":"Çevrenizdeki boşluk tamponu, kaçmak veya frenlemek için yer ve tehlikeleri acil duruma dönüşmeden görüp yanıt vermek için zaman verir.","hi":"आपके चारों ओर स्थान का कुशन मुड़ने या ब्रेक लगाने की जगह और खतरों के आपात बनने से पहले उन्हें देखने-प्रतिक्रिया देने का समय देता है।","ar":"مساحة الأمان حولك تمنحك مجالاً للمناورة أو الكبح، ووقتاً لرؤية المخاطر والاستجابة لها قبل أن تصبح طوارئ."}},{"cat":"visibility","a":1,"q":{"en":"How does the manual describe the value of wearing bright clothing at night?","es":"¿Cómo describe el manual el valor de usar ropa brillante de noche?","ru":"Как руководство описывает пользу яркой одежды ночью?","tr":"Kılavuz, gece parlak giysi giymenin değerini nasıl tanımlar?","hi":"रात में चमकीले कपड़े पहनने के महत्व को मैनुअल कैसे वर्णित करता है?","ar":"كيف يصف الدليل قيمة ارتداء ملابس زاهية ليلاً؟"},"o":[{"en":"It is unnecessary once your headlight is on","es":"Es innecesario una vez encendido el faro","ru":"Она не нужна, если включена фара","tr":"Far açıkken gereksizdir","hi":"हेडलाइट जलने पर यह अनावश्यक है","ar":"غير ضرورية بمجرد تشغيل المصباح"},{"en":"Bright and reflective gear still helps others detect you sooner","es":"El equipo brillante y reflectante aún ayuda a que otros lo detecten antes","ru":"Яркая и светоотражающая экипировка всё равно помогает заметить вас раньше","tr":"Parlak ve yansıtıcı ekipman yine de başkalarının sizi daha erken fark etmesine yardımcı olur","hi":"चमकीला और परावर्तक गियर फिर भी दूसरों को आपको जल्दी पहचानने में मदद करता है","ar":"المعدات الزاهية والعاكسة تساعد الآخرين على اكتشافك أبكر"},{"en":"Dark clothing is better at night","es":"La ropa oscura es mejor de noche","ru":"Тёмная одежда лучше ночью","tr":"Gece koyu giysi daha iyidir","hi":"रात में गहरे कपड़े बेहतर हैं","ar":"الملابس الداكنة أفضل ليلاً"},{"en":"Color makes no difference to drivers","es":"El color no cambia nada para los conductores","ru":"Цвет не влияет на восприятие водителями","tr":"Renk sürücüler için fark yaratmaz","hi":"रंग से चालकों को कोई फर्क नहीं पड़ता","ar":"اللون لا يُحدث فرقاً للسائقين"}],"e":{"en":"Even with your headlight on, bright and reflective clothing at night gives drivers extra cues to detect and locate you sooner.","es":"Aun con el faro encendido, la ropa brillante y reflectante de noche da a los conductores señales extra para detectarlo y ubicarlo antes.","ru":"Даже с включённой фарой яркая и светоотражающая одежда ночью даёт водителям дополнительные подсказки, чтобы заметить и определить вас раньше.","tr":"Farınız açık olsa bile, gece parlak ve yansıtıcı giysi sürücülere sizi daha erken fark edip konumlandırmaları için ek ipuçları verir.","hi":"हेडलाइट जलने पर भी रात में चमकीले और परावर्तक कपड़े चालकों को आपको जल्दी पहचानने और स्थान लगाने के अतिरिक्त संकेत देते हैं।","ar":"حتى مع تشغيل مصباحك، تمنح الملابس الزاهية والعاكسة ليلاً السائقين إشارات إضافية لاكتشافك وتحديد موقعك أبكر."}},{"cat":"visibility","a":2,"q":{"en":"What is the safest way to ride when a line of cars is stopped and one driver waves you through?","es":"¿Cuál es la forma más segura de conducir cuando una fila de autos está detenida y un conductor le hace señas para que pase?","ru":"Как безопаснее всего действовать, когда ряд машин стоит и один водитель жестом пропускает вас?","tr":"Bir sıra araç durmuşken bir sürücü sizi geçmeniz için el salladığında en güvenli sürüş nedir?","hi":"जब कारों की कतार रुकी हो और एक चालक आपको जाने का इशारा करे, तो सबसे सुरक्षित तरीका क्या है?","ar":"ما الطريقة الأكثر أماناً للقيادة عندما يتوقف صف من السيارات ويلوّح لك أحد السائقين بالمرور؟"},"o":[{"en":"Accelerate through quickly, trusting the wave","es":"Acelerar y pasar rápido, confiando en la señal","ru":"Быстро проехать, полагаясь на жест","tr":"El işaretine güvenip hızla geçmek","hi":"इशारे पर भरोसा कर तेजी से निकल जाएँ","ar":"التسارع والمرور بسرعة، واثقاً من الإشارة"},{"en":"Close your eyes to the cross traffic","es":"Ignorar el tráfico transversal","ru":"Не обращать внимания на поперечный поток","tr":"Çapraz trafiği görmezden gelmek","hi":"क्रॉस ट्रैफ़िक को नजरअंदाज करें","ar":"تجاهل حركة المرور المتقاطعة"},{"en":"Proceed slowly and check for yourself that the way is truly clear","es":"Avanzar despacio y verificar usted mismo que la vía esté realmente libre","ru":"Двигаться медленно и самому убедиться, что путь действительно свободен","tr":"Yavaş ilerleyip yolun gerçekten açık olduğunu kendiniz kontrol etmek","hi":"धीरे बढ़ें और स्वयं जाँचें कि रास्ता वास्तव में साफ है","ar":"التقدّم ببطء والتأكد بنفسك أن الطريق خالٍ فعلاً"},{"en":"Follow the car ahead closely","es":"Seguir de cerca al auto de adelante","ru":"Ехать вплотную за передней машиной","tr":"Öndeki aracı yakından takip etmek","hi":"आगे वाली कार के करीब चलें","ar":"اتّباع السيارة الأمامية عن قرب"}],"e":{"en":"A wave-through does not guarantee that other lanes or cross traffic are clear; proceed slowly and confirm the path yourself before crossing.","es":"Una señal para pasar no garantiza que otros carriles o el tráfico transversal estén libres; avance despacio y confirme usted mismo antes de cruzar.","ru":"Приглашающий жест не гарантирует, что другие полосы или поперечный поток свободны; двигайтесь медленно и убедитесь сами, прежде чем пересекать.","tr":"Geç işareti, diğer şeritlerin veya çapraz trafiğin açık olduğunu garanti etmez; geçmeden önce yavaş ilerleyin ve yolu kendiniz doğrulayın.","hi":"जाने का इशारा यह गारंटी नहीं देता कि अन्य लेन या क्रॉस ट्रैफ़िक साफ है; पार करने से पहले धीरे बढ़ें और स्वयं रास्ता सुनिश्चित करें।","ar":"التلويح بالمرور لا يضمن أن المسارات الأخرى أو حركة المرور المتقاطعة خالية؛ تقدّم ببطء وتأكد من الطريق بنفسك قبل العبور."}},{"cat":"hazards","a":3,"q":{"en":"When crossing railroad tracks that run across your lane, what is the safest approach?","es":"Al cruzar vías de tren que atraviesan su carril, ¿cuál es el enfoque más seguro?","ru":"При пересечении ж/д путей, идущих поперёк полосы, как безопаснее всего действовать?","tr":"Şeridinizi enine kesen tren raylarını geçerken en güvenli yaklaşım nedir?","hi":"अपनी लेन के आर-पार जाने वाली रेल पटरियों को पार करते समय सबसे सुरक्षित तरीका क्या है?","ar":"عند عبور قضبان سكة حديد تمتد عبر مسارك، ما النهج الأكثر أماناً؟"},"o":[{"en":"Stop on the tracks and look both ways","es":"Detenerse sobre las vías y mirar a ambos lados","ru":"Остановиться на путях и посмотреть по сторонам","tr":"Rayların üzerinde durup iki yana bakmak","hi":"पटरियों पर रुककर दोनों ओर देखें","ar":"التوقف على القضبان والنظر في الاتجاهين"},{"en":"Cross at a sharp angle to the rails","es":"Cruzar en ángulo agudo respecto a los rieles","ru":"Пересекать под острым углом к рельсам","tr":"Raylara keskin açıyla geçmek","hi":"पटरियों से तीखे कोण पर पार करें","ar":"العبور بزاوية حادة على القضبان"},{"en":"Speed up sharply just before them","es":"Acelerar bruscamente justo antes","ru":"Резко ускориться прямо перед ними","tr":"Hemen öncesinde sertçe hızlanmak","hi":"ठीक पहले तेजी से गति बढ़ाएँ","ar":"التسارع بشدة قبلها مباشرة"},{"en":"Ride straight across, staying in your lane","es":"Cruzar recto, permaneciendo en su carril","ru":"Ехать прямо через них, оставаясь в своей полосе","tr":"Şeridinizde kalarak düz karşıya geçmek","hi":"अपनी लेन में रहते हुए सीधे पार करें","ar":"العبور مستقيماً مع البقاء في مسارك"}],"e":{"en":"For tracks that cross your path, it is usually safest to ride straight across within your lane; you rarely need to change direction to take them at 90 degrees.","es":"Para vías que cruzan su camino, suele ser más seguro cruzar recto dentro de su carril; rara vez hace falta cambiar de dirección para tomarlas a 90 grados.","ru":"Для путей, пересекающих ваш путь, обычно безопаснее ехать прямо в пределах полосы; редко нужно менять направление, чтобы пересечь их под 90 градусами.","tr":"Yolunuzu kesen raylarda genellikle şeridiniz içinde düz geçmek en güvenlidir; onları 90 derecede almak için nadiren yön değiştirmeniz gerekir.","hi":"आपके रास्ते को काटने वाली पटरियों के लिए आम तौर पर अपनी लेन में सीधे पार करना सबसे सुरक्षित है; उन्हें 90 डिग्री पर लेने के लिए शायद ही दिशा बदलनी पड़े।","ar":"للقضبان التي تعبر طريقك، عادةً يكون الأأمن العبور مستقيماً ضمن مسارك؛ ونادراً ما تحتاج لتغيير الاتجاه لعبورها بزاوية 90 درجة."}},{"cat":"hazards","a":0,"q":{"en":"If tracks or pavement seams run in the same direction as your travel, how should you cross them?","es":"Si las vías o juntas del pavimento van en la misma dirección de su marcha, ¿cómo debe cruzarlas?","ru":"Если пути или швы покрытия идут в том же направлении, что и вы, как их пересекать?","tr":"Raylar veya asfalt dikişleri gidiş yönünüzle aynı yöndeyse, onları nasıl geçmelisiniz?","hi":"यदि पटरियाँ या फुटपाथ की जोड़ें आपकी यात्रा की दिशा में हों, तो उन्हें कैसे पार करें?","ar":"إذا كانت القضبان أو فواصل الرصيف تمتد في نفس اتجاه سيرك، فكيف تعبرها؟"},"o":[{"en":"Move over enough to cross them at a distinct angle","es":"Desplazarse lo suficiente para cruzarlas en un ángulo claro","ru":"Сместиться достаточно, чтобы пересечь их под заметным углом","tr":"Onları belirgin bir açıyla geçecek kadar yana kaymak","hi":"उन्हें स्पष्ट कोण पर पार करने के लिए पर्याप्त रूप से हट जाएँ","ar":"الانتقال بما يكفي لعبورها بزاوية واضحة"},{"en":"Ride right along the groove","es":"Circular justo por la ranura","ru":"Ехать прямо вдоль борозды","tr":"Tam oluğun üzerinde sürmek","hi":"नाली के ठीक साथ चलें","ar":"القيادة تماماً على طول الأخدود"},{"en":"Speed up and lean hard","es":"Acelerar e inclinarse fuerte","ru":"Ускориться и сильно наклониться","tr":"Hızlanıp sert yatmak","hi":"तेज हों और जोर से झुकें","ar":"التسارع والميل بقوة"},{"en":"Brake heavily while on them","es":"Frenar fuerte mientras las cruza","ru":"Сильно тормозить, находясь на них","tr":"Üzerlerindeyken sert frenlemek","hi":"उन पर रहते हुए जोर से ब्रेक लगाएँ","ar":"الكبح بقوة أثناء وجودك عليها"}],"e":{"en":"Tracks or seams parallel to your path can trap your tire, so move over far enough to cross them at an angle rather than riding along them.","es":"Las vías o juntas paralelas a su camino pueden atrapar la llanta, así que desplácese lo suficiente para cruzarlas en ángulo en vez de ir sobre ellas.","ru":"Пути или швы, идущие параллельно вашему пути, могут «поймать» колесо, поэтому сместитесь настолько, чтобы пересечь их под углом, а не ехать вдоль.","tr":"Yolunuza paralel raylar veya dikişler lastiğinizi kapabilir; bu yüzden onlar boyunca gitmek yerine açıyla geçecek kadar yana kayın.","hi":"आपके रास्ते के समानांतर पटरियाँ या जोड़ें टायर को फँसा सकती हैं, इसलिए उनके साथ चलने के बजाय उन्हें कोण पर पार करने के लिए पर्याप्त रूप से हटें।","ar":"القضبان أو الفواصل الموازية لطريقك قد تحبس إطارك، لذا انتقل بما يكفي لعبورها بزاوية بدلاً من السير عليها."}},{"cat":"hazards","a":1,"q":{"en":"How should you handle riding over a metal bridge grating or rain grooves?","es":"¿Cómo debe manejar circular sobre una rejilla metálica de puente o ranuras antilluvia?","ru":"Как вести себя при проезде по металлической решётке моста или дождевым канавкам?","tr":"Metal köprü ızgarası veya yağmur oluklarının üzerinden geçerken nasıl davranmalısınız?","hi":"धातु के पुल की जाली या रेन ग्रूव्स पर चलने को कैसे संभालना चाहिए?","ar":"كيف تتعامل مع القيادة فوق شبكة جسر معدنية أو أخاديد المطر؟"},"o":[{"en":"Grip the bars tightly and fight every wobble","es":"Agarrar fuerte el manillar y luchar contra cada bamboleo","ru":"Крепко сжать руль и бороться с каждым вилянием","tr":"Gidonu sıkıca kavrayıp her sallantıyla mücadele etmek","hi":"हैंडलबार कसकर पकड़ें और हर डगमगाहट से लड़ें","ar":"الإمساك بالمقود بإحكام ومقاومة كل اهتزاز"},{"en":"Relax, keep a steady speed, and ride straight across","es":"Relajarse, mantener velocidad constante y cruzar recto","ru":"Расслабиться, держать ровную скорость и ехать прямо","tr":"Gevşemek, sabit hız tutmak ve düz karşıya geçmek","hi":"शांत रहें, स्थिर गति रखें और सीधे पार करें","ar":"الاسترخاء والحفاظ على سرعة ثابتة والعبور مستقيماً"},{"en":"Brake hard in the middle","es":"Frenar fuerte en el medio","ru":"Сильно тормозить посередине","tr":"Ortada sert frenlemek","hi":"बीच में जोर से ब्रेक लगाएँ","ar":"الكبح بقوة في المنتصف"},{"en":"Zig-zag to keep balance","es":"Zigzaguear para mantener el equilibrio","ru":"Ехать зигзагом для равновесия","tr":"Denge için zikzak yapmak","hi":"संतुलन के लिए ज़िग-ज़ैग करें","ar":"التعرّج للحفاظ على التوازن"}],"e":{"en":"Metal gratings make the bike feel like it is wandering; stay relaxed on the bars, hold a steady speed and go straight across, and it will track through fine.","es":"Las rejillas metálicas hacen que la moto parezca divagar; mantenga los brazos relajados, velocidad constante y cruce recto, y pasará bien.","ru":"На металлических решётках мотоцикл будто «плавает»; держите руки расслабленными, ровную скорость и езжайте прямо — и вы спокойно проедете.","tr":"Metal ızgaralar motosikleti gezinir gibi hissettirir; gidonda gevşek kalın, sabit hız tutun ve düz karşıya geçin, sorunsuz geçersiniz.","hi":"धातु की जाली से बाइक भटकती-सी लगती है; हैंडलबार पर शांत रहें, स्थिर गति रखें और सीधे पार करें, यह ठीक से निकल जाएगी।","ar":"الشبكات المعدنية تجعل الدراجة تبدو وكأنها تتمايل؛ ابقَ مسترخياً على المقود واحفظ سرعة ثابتة واعبر مستقيماً، وستمرّ بسلاسة."}},{"cat":"hazards","a":2,"q":{"en":"When you must ride over an obstacle you cannot avoid, what should you do just before impact?","es":"Cuando deba pasar sobre un obstáculo que no puede evitar, ¿qué debe hacer justo antes del impacto?","ru":"Когда приходится переезжать неизбежное препятствие, что сделать прямо перед контактом?","tr":"Kaçınamayacağınız bir engelin üzerinden geçmek zorundaysanız, çarpmadan hemen önce ne yapmalısınız?","hi":"जब आपको किसी अपरिहार्य बाधा पर से गुजरना पड़े, तो टकराव से ठीक पहले क्या करना चाहिए?","ar":"عندما يجب أن تعبر عائقاً لا يمكنك تجنّبه، ماذا تفعل قبل الاصطدام مباشرة؟"},"o":[{"en":"Brake hard on the obstacle","es":"Frenar fuerte sobre el obstáculo","ru":"Резко тормозить на препятствии","tr":"Engelin üzerinde sert frenlemek","hi":"बाधा पर जोर से ब्रेक लगाएँ","ar":"الكبح بقوة على العائق"},{"en":"Grip the bars and lean back only","es":"Agarrar el manillar e inclinarse solo hacia atrás","ru":"Только схватить руль и откинуться назад","tr":"Yalnızca gidonu kavrayıp geriye yaslanmak","hi":"केवल हैंडलबार पकड़ें और पीछे झुकें","ar":"الإمساك بالمقود والميل للخلف فقط"},{"en":"Rise slightly off the seat, keep the bike straight, and roll on a little throttle","es":"Levantarse un poco del asiento, mantener la moto recta y dar un poco de acelerador","ru":"Слегка приподняться над сиденьем, держать мотоцикл прямо и чуть прибавить газ","tr":"Selden biraz kalkıp motosikleti düz tutmak ve biraz gaz vermek","hi":"सीट से थोड़ा ऊपर उठें, बाइक को सीधा रखें और थोड़ा थ्रॉटल दें","ar":"الارتفاع قليلاً عن المقعد وإبقاء الدراجة مستقيمة وإعطاء قليل من الخانق"},{"en":"Turn the bars sharply at contact","es":"Girar el manillar bruscamente al contacto","ru":"Резко повернуть руль в момент контакта","tr":"Temas anında gidonu sertçe çevirmek","hi":"संपर्क पर हैंडलबार तेजी से घुमाएँ","ar":"تدوير المقود بحدة عند التلامس"}],"e":{"en":"Approach as square as possible, slow down, then just before the obstacle rise slightly off the seat and give a little throttle so the suspension absorbs the shock.","es":"Acérquese lo más de frente posible, reduzca y, justo antes del obstáculo, levántese un poco del asiento y dé algo de acelerador para que la suspensión absorba el golpe.","ru":"Подъезжайте как можно перпендикулярнее, снизьте скорость, а прямо перед препятствием слегка приподнимитесь над сиденьем и чуть добавьте газ, чтобы подвеска смягчила удар.","tr":"Mümkün olduğunca dik yaklaşın, yavaşlayın, sonra engelden hemen önce selden biraz kalkın ve biraz gaz verin ki süspansiyon darbeyi emsin.","hi":"जितना संभव हो सीधा पहुँचें, धीमे हों, फिर बाधा से ठीक पहले सीट से थोड़ा ऊपर उठें और थोड़ा थ्रॉटल दें ताकि सस्पेंशन झटका सोख ले।","ar":"اقترب بأكثر ما يمكن من الزاوية القائمة، وأبطئ، ثم قبل العائق مباشرة ارتفع قليلاً عن المقعد وأعطِ قليلاً من الخانق كي يمتص نظام التعليق الصدمة."}},{"cat":"hazards","a":3,"q":{"en":"A small animal runs into your path. What is generally the safest response?","es":"Un animal pequeño se cruza en su camino. ¿Cuál suele ser la respuesta más segura?","ru":"Мелкое животное выбегает вам на путь. Какая реакция обычно самая безопасная?","tr":"Küçük bir hayvan yolunuza çıkıyor. Genellikle en güvenli tepki nedir?","hi":"एक छोटा जानवर आपके रास्ते में आ जाता है। आमतौर पर सबसे सुरक्षित प्रतिक्रिया क्या है?","ar":"يركض حيوان صغير أمامك في طريقك. ما الاستجابة الأكثر أماناً عادةً؟"},"o":[{"en":"Swerve sharply across the lane to miss it","es":"Esquivar bruscamente por el carril para evitarlo","ru":"Резко вильнуть через полосу, чтобы объехать","tr":"Kaçırmak için şeritte sertçe kırmak","hi":"बचने के लिए लेन में तेजी से मुड़ें","ar":"الانحراف بحدة عبر المسار لتفاديه"},{"en":"Speed up to jump past it","es":"Acelerar para pasarlo de un salto","ru":"Ускориться, чтобы проскочить","tr":"Sıçrayıp geçmek için hızlanmak","hi":"इसे लाँघने के लिए तेज हों","ar":"التسارع للقفز أمامه"},{"en":"Close your eyes and hope","es":"Cerrar los ojos y esperar","ru":"Закрыть глаза и надеяться","tr":"Gözleri kapatıp ummak","hi":"आँखें बंद करें और उम्मीद करें","ar":"إغلاق عينيك والأمل"},{"en":"Brake if safe and hold your lane rather than risk a dangerous swerve","es":"Frenar si es seguro y mantener el carril en vez de arriesgar un giro peligroso","ru":"Тормозить, если безопасно, и держать полосу, а не рисковать опасным манёвром","tr":"Güvenliyse frenlemek ve tehlikeli bir manevra yerine şeridinizde kalmak","hi":"यदि सुरक्षित हो तो ब्रेक लगाएँ और खतरनाक स्विर्व के बजाय अपनी लेन बनाए रखें","ar":"الكبح إن كان آمناً والبقاء في مسارك بدلاً من المخاطرة بانحراف خطير"}],"e":{"en":"For small animals, the manual advises braking if it is safe and staying in your lane; a sudden swerve risks a crash that is usually worse than hitting the animal.","es":"Para animales pequeños, el manual aconseja frenar si es seguro y permanecer en su carril; un giro brusco arriesga un choque normalmente peor que atropellar al animal.","ru":"Для мелких животных руководство советует тормозить, если безопасно, и оставаться в полосе; резкий манёвр грозит аварией, обычно худшей, чем наезд на животное.","tr":"Küçük hayvanlar için kılavuz, güvenliyse frenlemeyi ve şeridinizde kalmayı önerir; ani bir manevra, hayvana çarpmaktan genellikle daha kötü bir kazaya yol açar.","hi":"छोटे जानवरों के लिए मैनुअल सुरक्षित होने पर ब्रेक लगाने और अपनी लेन में रहने की सलाह देता है; अचानक स्विर्व से ऐसी दुर्घटना का जोखिम है जो आम तौर पर जानवर से टकराने से बदतर होती है।","ar":"للحيوانات الصغيرة، ينصح الدليل بالكبح إن كان آمناً والبقاء في مسارك؛ فالانحراف المفاجئ يخاطر بحادث عادةً أسوأ من الاصطدام بالحيوان."}},{"cat":"hazards","a":0,"q":{"en":"How should you respond to a strong side wind that pushes you toward the edge of your lane?","es":"¿Cómo debe responder a un fuerte viento lateral que lo empuja hacia el borde del carril?","ru":"Как реагировать на сильный боковой ветер, толкающий вас к краю полосы?","tr":"Sizi şeridin kenarına doğru iten güçlü bir yan rüzgâra nasıl tepki vermelisiniz?","hi":"तेज़ बगली हवा जो आपको लेन के किनारे की ओर धकेलती है, उस पर कैसे प्रतिक्रिया दें?","ar":"كيف تستجيب لرياح جانبية قوية تدفعك نحو حافة مسارك؟"},"o":[{"en":"Lean slightly into the wind and adjust to hold your line","es":"Inclinarse un poco hacia el viento y ajustar para mantener su línea","ru":"Слегка наклониться навстречу ветру и подкорректировать курс","tr":"Rüzgâra doğru biraz yatıp çizginizi korumak için ayar yapmak","hi":"हवा की ओर थोड़ा झुकें और अपनी लाइन बनाए रखने के लिए समायोजित करें","ar":"الميل قليلاً نحو الريح والتعديل للحفاظ على مسارك"},{"en":"Grab the front brake hard","es":"Apretar fuerte el freno delantero","ru":"Резко схватить передний тормоз","tr":"Ön frene sertçe asılmak","hi":"फ्रंट ब्रेक जोर से पकड़ें","ar":"الإمساك بقوة بالفرامل الأمامية"},{"en":"Let go of the bars","es":"Soltar el manillar","ru":"Отпустить руль","tr":"Gidonu bırakmak","hi":"हैंडलबार छोड़ दें","ar":"ترك المقود"},{"en":"Stand up on the pegs","es":"Ponerse de pie sobre los estribos","ru":"Встать на подножки","tr":"Basamaklarda ayağa kalkmak","hi":"पेग पर खड़े हो जाएँ","ar":"الوقوف على المسندين"}],"e":{"en":"In a steady side wind, lean slightly into it and keep a firm but relaxed grip, adjusting your steering to stay in your intended path.","es":"Con viento lateral constante, inclínese ligeramente hacia él y mantenga un agarre firme pero relajado, ajustando la dirección para mantener su trayectoria.","ru":"При устойчивом боковом ветре слегка наклонитесь навстречу и держите руль твёрдо, но расслабленно, подруливая, чтобы оставаться на нужной траектории.","tr":"Sabit yan rüzgârda ona doğru hafifçe yatın ve sağlam ama gevşek bir kavrayışla, çizginizde kalmak için direksiyonu ayarlayın.","hi":"स्थिर बगली हवा में इसकी ओर थोड़ा झुकें और दृढ़ पर शांत पकड़ बनाए रखें, अपनी इच्छित पथ में रहने के लिए स्टीयरिंग समायोजित करें।","ar":"في رياح جانبية ثابتة، مِل قليلاً نحوها واحتفظ بقبضة ثابتة لكن مسترخية، معدّلاً توجيهك للبقاء في مسارك المقصود."}},{"cat":"hazards","a":1,"q":{"en":"What should you expect as a large truck or bus passes you at speed?","es":"¿Qué debe esperar cuando un camión o autobús grande lo rebasa a velocidad?","ru":"Чего ожидать, когда большой грузовик или автобус обгоняет вас на скорости?","tr":"Büyük bir kamyon veya otobüs sizi hızla geçerken ne beklemelisiniz?","hi":"जब कोई बड़ा ट्रक या बस आपको तेज़ी से ओवरटेक करे तो क्या अपेक्षा करनी चाहिए?","ar":"ماذا يجب أن تتوقّع عندما تتجاوزك شاحنة أو حافلة كبيرة بسرعة؟"},"o":[{"en":"Your engine will stall","es":"Su motor se calará","ru":"Ваш двигатель заглохнет","tr":"Motorunuz stop edecek","hi":"आपका इंजन बंद हो जाएगा","ar":"سينطفئ محركك"},{"en":"A gust or air turbulence that can push you around","es":"Una ráfaga o turbulencia de aire que puede empujarlo","ru":"Порыв или турбулентность воздуха, которые могут вас качнуть","tr":"Sizi savurabilecek bir hava akımı veya türbülans","hi":"हवा का झोंका या अशांति जो आपको धकेल सकती है","ar":"هبّة أو اضطراب هوائي قد يدفعك"},{"en":"Your headlight will dim","es":"Su faro se atenuará","ru":"Ваша фара потускнеет","tr":"Farınız kısılacak","hi":"आपकी हेडलाइट मंद हो जाएगी","ar":"سيخفت مصباحك"},{"en":"Nothing at all","es":"Nada en absoluto","ru":"Совсем ничего","tr":"Hiçbir şey","hi":"कुछ भी नहीं","ar":"لا شيء إطلاقاً"}],"e":{"en":"Large vehicles create air turbulence and gusts as they pass; expect the push, keep a firm relaxed grip, and if possible move to the lane portion farthest from them.","es":"Los vehículos grandes crean turbulencia y ráfagas al pasar; anticipe el empuje, mantenga un agarre firme y relajado y, si puede, muévase a la parte del carril más alejada de ellos.","ru":"Крупные машины при обгоне создают турбулентность и порывы; будьте готовы к толчку, держите руль твёрдо и расслабленно и по возможности сместитесь в дальнюю от них часть полосы.","tr":"Büyük araçlar geçerken hava türbülansı ve rüzgâr oluşturur; itmeyi bekleyin, sağlam ve gevşek tutun ve mümkünse şeridin onlardan en uzak kısmına geçin.","hi":"बड़े वाहन गुजरते समय हवा की अशांति और झोंके पैदा करते हैं; धक्के की अपेक्षा करें, दृढ़-शांत पकड़ रखें और यदि संभव हो तो उनसे सबसे दूर लेन भाग में जाएँ।","ar":"المركبات الكبيرة تُحدث اضطراباً هوائياً وهبّات عند مرورها؛ توقّع الدفع، واحتفظ بقبضة ثابتة مسترخية، وإن أمكن انتقل إلى جزء المسار الأبعد عنها."}},{"cat":"hazards","a":2,"q":{"en":"When carrying a load on your motorcycle, where should most of the weight be placed?","es":"Al llevar carga en la moto, ¿dónde debe colocarse la mayor parte del peso?","ru":"При перевозке груза на мотоцикле где размещать основную часть веса?","tr":"Motosikletinizde yük taşırken ağırlığın çoğu nereye yerleştirilmeli?","hi":"मोटरसाइकिल पर भार ले जाते समय अधिकांश वजन कहाँ रखा जाना चाहिए?","ar":"عند حمل حمولة على دراجتك، أين يجب وضع معظم الوزن؟"},"o":[{"en":"As high as possible","es":"Lo más alto posible","ru":"Как можно выше","tr":"Olabildiğince yüksek","hi":"जितना ऊँचा हो सके","ar":"بأعلى ما يمكن"},{"en":"Behind the rear axle","es":"Detrás del eje trasero","ru":"За задней осью","tr":"Arka aksın arkasında","hi":"रियर एक्सल के पीछे","ar":"خلف المحور الخلفي"},{"en":"Low and over or ahead of the rear axle","es":"Bajo y sobre o delante del eje trasero","ru":"Низко и над задней осью или перед ней","tr":"Alçak ve arka aksın üzerinde ya da önünde","hi":"नीचे और रियर एक्सल के ऊपर या आगे","ar":"منخفضاً وفوق المحور الخلفي أو أمامه"},{"en":"On the handlebars","es":"En el manillar","ru":"На руле","tr":"Gidonun üzerinde","hi":"हैंडलबार पर","ar":"على المقود"}],"e":{"en":"Keep loads low and positioned over or in front of the rear axle; weight mounted high or behind the axle raises the center of gravity and can make the bike unstable.","es":"Mantenga la carga baja y sobre o delante del eje trasero; el peso alto o detrás del eje eleva el centro de gravedad y puede desestabilizar la moto.","ru":"Держите груз низко и над задней осью или перед ней; вес, размещённый высоко или за осью, поднимает центр тяжести и может сделать мотоцикл неустойчивым.","tr":"Yükü alçak ve arka aksın üzerinde ya da önünde tutun; yüksekte veya aksın arkasında taşınan ağırlık ağırlık merkezini yükseltir ve motosikleti dengesizleştirebilir.","hi":"भार को नीचे और रियर एक्सल के ऊपर या आगे रखें; ऊँचा या एक्सल के पीछे लगा वजन गुरुत्व केंद्र बढ़ाकर बाइक को अस्थिर कर सकता है।","ar":"أبقِ الحمولة منخفضة وفوق المحور الخلفي أو أمامه؛ فالوزن المرتفع أو خلف المحور يرفع مركز الثقل وقد يجعل الدراجة غير مستقرة."}},{"cat":"hazards","a":3,"q":{"en":"Why is it important to distribute cargo evenly in saddlebags on both sides?","es":"¿Por qué es importante distribuir la carga por igual en alforjas a ambos lados?","ru":"Почему важно равномерно распределять груз в кофрах с обеих сторон?","tr":"Yükü her iki taraftaki heybelerde eşit dağıtmak neden önemlidir?","hi":"दोनों ओर सैडलबैग में सामान समान रूप से वितरित करना क्यों महत्वपूर्ण है?","ar":"لماذا من المهم توزيع الحمولة بالتساوي في الحقائب الجانبية على الجهتين؟"},"o":[{"en":"It looks more balanced","es":"Se ve más equilibrado","ru":"Так выглядит аккуратнее","tr":"Daha dengeli görünür","hi":"यह अधिक संतुलित दिखता है","ar":"يبدو أكثر توازناً"},{"en":"It saves fuel","es":"Ahorra combustible","ru":"Это экономит топливо","tr":"Yakıt tasarrufu sağlar","hi":"यह ईंधन बचाता है","ar":"يوفّر الوقود"},{"en":"It keeps the bags cleaner","es":"Mantiene las alforjas más limpias","ru":"Так сумки чище","tr":"Çantaları daha temiz tutar","hi":"यह बैग साफ रखता है","ar":"يبقي الحقائب أنظف"},{"en":"Uneven loads can pull the bike to one side and hurt handling","es":"Las cargas desiguales pueden jalar la moto hacia un lado y afectar el manejo","ru":"Неравномерная загрузка может уводить мотоцикл в сторону и ухудшать управляемость","tr":"Dengesiz yük motosikleti bir tarafa çekip yol tutuşunu bozabilir","hi":"असमान भार बाइक को एक ओर खींचकर हैंडलिंग बिगाड़ सकता है","ar":"الحمولة غير المتوازنة قد تسحب الدراجة إلى جانب وتضر بالتحكم"}],"e":{"en":"Loading one side heavier than the other pulls the motorcycle toward that side and degrades handling, so balance the weight in both saddlebags.","es":"Cargar un lado más que el otro jala la moto hacia ese lado y empeora el manejo, así que equilibre el peso en ambas alforjas.","ru":"Перегруз одной стороны уводит мотоцикл в её сторону и ухудшает управляемость, поэтому уравновешивайте вес в обоих кофрах.","tr":"Bir tarafı diğerinden ağır yüklemek motosikleti o tarafa çeker ve yol tutuşunu bozar; bu yüzden iki heybede ağırlığı dengeleyin.","hi":"एक ओर दूसरे से भारी लोड करना बाइक को उस ओर खींचता है और हैंडलिंग बिगाड़ता है, इसलिए दोनों सैडलबैग में वजन संतुलित करें।","ar":"تحميل جانب أثقل من الآخر يسحب الدراجة نحو ذلك الجانب ويُضعف التحكم، لذا وازِن الوزن في الحقيبتين."}},{"cat":"hazards","a":0,"q":{"en":"Why can wet leaves, gravel or sand on the road be especially dangerous?","es":"¿Por qué las hojas mojadas, la grava o la arena en la vía pueden ser especialmente peligrosas?","ru":"Почему мокрые листья, гравий или песок на дороге особенно опасны?","tr":"Yoldaki ıslak yapraklar, çakıl veya kum neden özellikle tehlikeli olabilir?","hi":"सड़क पर गीली पत्तियाँ, बजरी या रेत विशेष रूप से खतरनाक क्यों हो सकती हैं?","ar":"لماذا قد تكون الأوراق المبللة أو الحصى أو الرمل على الطريق خطيرة بشكل خاص؟"},"o":[{"en":"They sharply reduce traction and can cause a slide","es":"Reducen mucho la tracción y pueden causar un deslizamiento","ru":"Они резко снижают сцепление и могут вызвать скольжение","tr":"Tutuşu keskin biçimde azaltır ve kaymaya neden olabilir","hi":"वे ट्रैक्शन तेजी से घटाकर फिसलन ला सकती हैं","ar":"تقلّل التماسك بشدة وقد تسبّب انزلاقاً"},{"en":"They increase your tire grip","es":"Aumentan el agarre de las llantas","ru":"Они увеличивают сцепление шин","tr":"Lastik tutuşunu artırır","hi":"वे टायर की पकड़ बढ़ाती हैं","ar":"تزيد قبضة الإطار"},{"en":"They improve braking","es":"Mejoran el frenado","ru":"Они улучшают торможение","tr":"Frenlemeyi iyileştirir","hi":"वे ब्रेकिंग बेहतर करती हैं","ar":"تحسّن الكبح"},{"en":"They only matter to cars","es":"Solo importan para los autos","ru":"Они важны только для машин","tr":"Yalnızca arabalar için önemlidir","hi":"वे केवल कारों के लिए मायने रखती हैं","ar":"تهمّ السيارات فقط"}],"e":{"en":"Loose or slick surfaces like wet leaves, gravel and sand greatly cut the traction your two tires rely on, so slow down and cross them upright and smoothly.","es":"Superficies sueltas o resbaladizas como hojas mojadas, grava y arena reducen mucho la tracción de sus dos neumáticos, así que reduzca y crúcelas erguido y con suavidad.","ru":"Сыпучие или скользкие поверхности — мокрые листья, гравий, песок — сильно снижают сцепление ваших двух шин, поэтому сбросьте скорость и проезжайте их вертикально и плавно.","tr":"Islak yaprak, çakıl ve kum gibi gevşek veya kaygan yüzeyler iki lastiğinizin dayandığı tutuşu büyük ölçüde azaltır; bu yüzden yavaşlayın ve dik, yumuşak geçin.","hi":"गीली पत्तियों, बजरी और रेत जैसी ढीली या फिसलन भरी सतहें आपके दो टायरों की ट्रैक्शन बहुत घटा देती हैं, इसलिए धीमे हों और उन्हें सीधे व सहजता से पार करें।","ar":"الأسطح المفككة أو الزلقة كالأوراق المبللة والحصى والرمل تقلّل كثيراً التماسك الذي يعتمد عليه إطاراك، لذا أبطئ واعبرها منتصباً وبسلاسة."}},{"cat":"hazards","a":1,"q":{"en":"How should you adjust your riding at night compared with daytime?","es":"¿Cómo debe ajustar su conducción de noche en comparación con el día?","ru":"Как корректировать езду ночью по сравнению с днём?","tr":"Geceleyin sürüşünüzü gündüze göre nasıl ayarlamalısınız?","hi":"दिन की तुलना में रात में अपनी राइडिंग कैसे समायोजित करें?","ar":"كيف تعدّل قيادتك ليلاً مقارنة بالنهار؟"},"o":[{"en":"Ride faster since roads are emptier","es":"Conducir más rápido porque hay menos tráfico","ru":"Ехать быстрее, ведь дороги пустее","tr":"Yollar daha boş olduğu için daha hızlı sürmek","hi":"सड़कें खाली होने से तेज चलें","ar":"القيادة أسرع لأن الطرق أخلى"},{"en":"Slow down and increase following distance","es":"Reducir la velocidad y aumentar la distancia de seguimiento","ru":"Снизить скорость и увеличить дистанцию","tr":"Yavaşlamak ve takip mesafesini artırmak","hi":"धीमे चलें और फॉलोइंग दूरी बढ़ाएँ","ar":"الإبطاء وزيادة مسافة الاتّباع"},{"en":"Turn off the headlight to reduce glare","es":"Apagar el faro para reducir el deslumbramiento","ru":"Выключить фару, чтобы снизить блики","tr":"Parlamayı azaltmak için farı kapatmak","hi":"चकाचौंध घटाने के लिए हेडलाइट बंद करें","ar":"إطفاء المصباح لتقليل الوهج"},{"en":"Follow closely to use others' lights","es":"Seguir de cerca para usar las luces de otros","ru":"Ехать вплотную, чтобы пользоваться чужим светом","tr":"Başkalarının ışığını kullanmak için yakın takip etmek","hi":"दूसरों की लाइट इस्तेमाल के लिए करीब चलें","ar":"الاتّباع عن قرب لاستخدام أضواء الآخرين"}],"e":{"en":"At night you can see less far, so reduce speed and allow a larger following distance so you can react within the range your headlight lights up.","es":"De noche ve menos lejos, así que reduzca la velocidad y deje más distancia para poder reaccionar dentro del alcance que ilumina su faro.","ru":"Ночью видно меньше, поэтому снизьте скорость и увеличьте дистанцию, чтобы успевать реагировать в пределах освещённого фарой участка.","tr":"Geceleyin daha az uzağı görürsünüz; bu yüzden hızı azaltın ve farınızın aydınlattığı mesafede tepki verebilmek için daha büyük takip mesafesi bırakın.","hi":"रात में कम दूर दिखता है, इसलिए गति घटाएँ और अधिक फॉलोइंग दूरी रखें ताकि आप हेडलाइट द्वारा प्रकाशित सीमा के भीतर प्रतिक्रिया दे सकें।","ar":"ليلاً ترى مسافة أقل، لذا خفّف السرعة واترك مسافة اتّباع أكبر كي تتمكن من التفاعل ضمن المدى الذي يضيئه مصباحك."}},{"cat":"hazards","a":2,"q":{"en":"How can the vehicle ahead of you help you spot road hazards at night?","es":"¿Cómo puede el vehículo de adelante ayudarlo a detectar peligros de noche?","ru":"Как машина впереди помогает замечать дорожные опасности ночью?","tr":"Önünüzdeki araç geceleyin yol tehlikelerini fark etmenize nasıl yardımcı olabilir?","hi":"रात में आगे वाला वाहन आपको सड़क के खतरों को पहचानने में कैसे मदद कर सकता है?","ar":"كيف يمكن للمركبة التي أمامك أن تساعدك على رصد مخاطر الطريق ليلاً؟"},"o":[{"en":"Its exhaust warms the road","es":"Su escape calienta la vía","ru":"Его выхлоп прогревает дорогу","tr":"Egzozu yolu ısıtır","hi":"इसका एग्जॉस्ट सड़क गर्म करता है","ar":"عادمها يُدفئ الطريق"},{"en":"It blocks the wind for you","es":"Le bloquea el viento","ru":"Оно закрывает вас от ветра","tr":"Rüzgârı sizin için keser","hi":"यह आपके लिए हवा रोकता है","ar":"يحجب الرياح عنك"},{"en":"Its tail lights and movements can reveal bumps, dips or hazards","es":"Sus luces traseras y movimientos pueden revelar baches, hondonadas o peligros","ru":"Его задние огни и движения могут выдавать ямы, впадины или опасности","tr":"Arka lambaları ve hareketleri tümsekleri, çukurları veya tehlikeleri ele verebilir","hi":"इसकी टेल लाइट और हरकतें उभार, गड्ढे या खतरे प्रकट कर सकती हैं","ar":"أضواؤها الخلفية وحركاتها قد تكشف المطبّات أو المنخفضات أو المخاطر"},{"en":"It doubles your headlight range","es":"Duplica el alcance de su faro","ru":"Оно удваивает дальность вашей фары","tr":"Farınızın menzilini ikiye katlar","hi":"यह आपकी हेडलाइट रेंज दोगुनी करता है","ar":"يضاعف مدى مصباحك"}],"e":{"en":"Watching the tail lights and motions of the vehicle ahead can warn you of bumps, dips, potholes or hazards before your own headlight reaches them.","es":"Observar las luces traseras y los movimientos del vehículo de adelante puede avisarle de baches, hondonadas o peligros antes de que su faro los alcance.","ru":"Наблюдение за задними огнями и движением машины впереди может предупредить о неровностях, впадинах, ямах или опасностях до того, как их осветит ваша фара.","tr":"Öndeki aracın arka lambalarını ve hareketlerini izlemek, kendi farınız onlara ulaşmadan tümsek, çukur veya tehlikeler konusunda sizi uyarabilir.","hi":"आगे वाले वाहन की टेल लाइट और हरकतें देखना आपकी अपनी हेडलाइट के पहुँचने से पहले उभार, गड्ढे या खतरों की चेतावनी दे सकता है।","ar":"مراقبة الأضواء الخلفية وحركات المركبة التي أمامك قد تحذّرك من المطبّات أو المنخفضات أو الحفر أو المخاطر قبل أن يصل إليها مصباحك."}},{"cat":"hazards","a":3,"q":{"en":"What should you do if a dog runs out to chase your motorcycle?","es":"¿Qué debe hacer si un perro sale a perseguir su moto?","ru":"Что делать, если собака выбегает и гонится за мотоциклом?","tr":"Bir köpek motosikletinizi kovalamak için fırlarsa ne yapmalısınız?","hi":"यदि कोई कुत्ता आपकी मोटरसाइकिल का पीछा करने दौड़े तो क्या करें?","ar":"ماذا تفعل إذا اندفع كلب لمطاردة دراجتك؟"},"o":[{"en":"Kick at the dog","es":"Patear al perro","ru":"Пнуть собаку","tr":"Köpeğe tekme atmak","hi":"कुत्ते को लात मारें","ar":"ركل الكلب"},{"en":"Swerve wildly to lose it","es":"Esquivar bruscamente para perderlo","ru":"Резко вилять, чтобы оторваться","tr":"Ondan kurtulmak için sertçe kırmak","hi":"इससे बचने के लिए बेतहाशा स्विर्व करें","ar":"الانحراف بعنف للتخلّص منه"},{"en":"Stop and wait for it to leave","es":"Detenerse y esperar a que se vaya","ru":"Остановиться и ждать, пока уйдёт","tr":"Durup gitmesini beklemek","hi":"रुकें और उसके जाने का इंतजार करें","ar":"التوقف وانتظار رحيله"},{"en":"Downshift, approach at a steady speed, then accelerate away as you reach it","es":"Reducir de marcha, acercarse a velocidad constante y luego acelerar al llegar a él","ru":"Понизить передачу, подъезжать с ровной скоростью, а поравнявшись — ускориться и уйти","tr":"Vites küçültmek, sabit hızla yaklaşmak, sonra ona ulaşınca hızlanıp uzaklaşmak","hi":"गियर कम करें, स्थिर गति से पास आएँ, फिर उसके पास पहुँचते ही तेज होकर निकल जाएँ","ar":"تخفيض السرعة والاقتراب بسرعة ثابتة، ثم التسارع بعيداً عند الوصول إليه"}],"e":{"en":"The manual suggests downshifting and approaching at a steady speed, then accelerating away just as you reach the dog, rather than swerving or kicking at it.","es":"El manual sugiere reducir de marcha y acercarse a velocidad constante, y luego acelerar justo al llegar al perro, en vez de esquivar o patear.","ru":"Руководство советует понизить передачу и подъезжать с ровной скоростью, а затем ускориться, поравнявшись с собакой, вместо резких манёвров или ударов.","tr":"Kılavuz, kırmak veya tekme atmak yerine vites küçültüp sabit hızla yaklaşmayı, sonra köpeğe ulaştığınız anda hızlanıp uzaklaşmayı önerir.","hi":"मैनुअल स्विर्व करने या लात मारने के बजाय गियर कम कर स्थिर गति से पास आने और फिर कुत्ते के पास पहुँचते ही तेज होकर निकलने का सुझाव देता है।","ar":"يقترح الدليل تخفيض السرعة والاقتراب بسرعة ثابتة، ثم التسارع بعيداً في اللحظة التي تصل فيها إلى الكلب، بدلاً من الانحراف أو ركله."}},{"cat":"hazards","a":0,"q":{"en":"When approaching a large animal such as a deer near the road, what is a sound practice?","es":"Al acercarse a un animal grande como un venado cerca de la vía, ¿cuál es una buena práctica?","ru":"При приближении к крупному животному, например оленю, у дороги — какая практика разумна?","tr":"Yol yakınında geyik gibi büyük bir hayvana yaklaşırken doğru uygulama nedir?","hi":"सड़क के पास हिरन जैसे बड़े जानवर के पास आते समय एक उचित अभ्यास क्या है?","ar":"عند الاقتراب من حيوان كبير مثل الغزال قرب الطريق، ما الممارسة السليمة؟"},"o":[{"en":"Slow down, be ready to stop, and do not assume it will stay put","es":"Reducir, estar listo para detenerse y no suponer que se quedará quieto","ru":"Снизить скорость, быть готовым остановиться и не рассчитывать, что оно останется на месте","tr":"Yavaşlamak, durmaya hazır olmak ve yerinde kalacağını varsaymamak","hi":"धीमे हों, रुकने को तैयार रहें और यह न मानें कि वह वहीं रहेगा","ar":"الإبطاء والاستعداد للتوقف وعدم افتراض أنه سيبقى مكانه"},{"en":"Speed up to pass it before it moves","es":"Acelerar para pasarlo antes de que se mueva","ru":"Ускориться, чтобы проехать до того, как оно двинется","tr":"Hareket etmeden geçmek için hızlanmak","hi":"इसके हिलने से पहले निकलने के लिए तेज हों","ar":"التسارع لتجاوزه قبل أن يتحرك"},{"en":"Flash your high beam to scare it","es":"Encender la luz alta para asustarlo","ru":"Мигать дальним светом, чтобы спугнуть","tr":"Korkutmak için uzun farı çakmak","hi":"इसे डराने के लिए हाई बीम फ्लैश करें","ar":"وميض الضوء العالي لإخافته"},{"en":"Sound the horn continuously","es":"Tocar la bocina sin parar","ru":"Непрерывно сигналить","tr":"Kornayı sürekli çalmak","hi":"लगातार हॉर्न बजाएँ","ar":"إطلاق البوق باستمرار"}],"e":{"en":"Large animals are unpredictable and may bolt into your path, so slow down, cover the brakes, and be ready to stop rather than gambling that it will stay still.","es":"Los animales grandes son impredecibles y pueden lanzarse a su camino, así que reduzca, cubra los frenos y esté listo para detenerse en vez de apostar a que se quede quieto.","ru":"Крупные животные непредсказуемы и могут броситься вам под колёса, поэтому снизьте скорость, держите пальцы над тормозами и будьте готовы остановиться, а не надеяться, что оно застынет.","tr":"Büyük hayvanlar öngörülemez ve yolunuza fırlayabilir; bu yüzden yavaşlayın, frenleri kaplayın ve yerinde kalacağına bel bağlamak yerine durmaya hazır olun.","hi":"बड़े जानवर अप्रत्याशित होते हैं और आपके रास्ते में झपट सकते हैं, इसलिए धीमे हों, ब्रेक कवर करें और यह दाँव लगाने के बजाय कि वह स्थिर रहेगा, रुकने को तैयार रहें।","ar":"الحيوانات الكبيرة غير متوقّعة وقد تندفع إلى طريقك، لذا أبطئ وضع أصابعك على الفرامل وكن مستعداً للتوقف بدلاً من المراهنة على بقائه ساكناً."}},{"cat":"hazards","a":1,"q":{"en":"Why should you avoid riding directly on painted lane markings when it rains?","es":"¿Por qué debe evitar circular directamente sobre las marcas pintadas del carril cuando llueve?","ru":"Почему в дождь не стоит ехать прямо по нанесённой краской разметке?","tr":"Yağmur yağarken neden doğrudan boyalı şerit çizgilerinin üzerinde sürmekten kaçınmalısınız?","hi":"बारिश में सीधे रंगे हुए लेन चिह्नों पर चलने से क्यों बचना चाहिए?","ar":"لماذا يجب تجنّب القيادة مباشرة فوق خطوط المسار المطلية عند هطول المطر؟"},"o":[{"en":"They damage the tires","es":"Dañan las llantas","ru":"Они повреждают шины","tr":"Lastikleri bozar","hi":"वे टायर को नुकसान पहुँचाते हैं","ar":"تتلف الإطارات"},{"en":"Paint and sealant become slippery when wet","es":"La pintura y el sellador se vuelven resbaladizos al mojarse","ru":"Краска и герметик становятся скользкими при намокании","tr":"Boya ve dolgu maddesi ıslanınca kaygan olur","hi":"गीले होने पर पेंट और सीलेंट फिसलन भरे हो जाते हैं","ar":"يصبح الطلاء ومادة السد زلقين عند البلل"},{"en":"They confuse your GPS","es":"Confunden su GPS","ru":"Они сбивают ваш GPS","tr":"GPS'inizi şaşırtır","hi":"वे आपके GPS को भ्रमित करते हैं","ar":"تُربك نظام تحديد المواقع"},{"en":"They are always higher than the road","es":"Siempre están más altas que la vía","ru":"Они всегда выше дороги","tr":"Her zaman yoldan yüksektir","hi":"वे हमेशा सड़क से ऊँचे होते हैं","ar":"دائماً أعلى من الطريق"}],"e":{"en":"Painted lines, tar snakes and steel plates get very slick when wet, offering much less grip, so avoid braking or turning while your tires are on them.","es":"Las líneas pintadas, las juntas de alquitrán y las placas de acero se vuelven muy resbaladizas al mojarse y dan mucho menos agarre, así que evite frenar o girar sobre ellas.","ru":"Крашеная разметка, битумные швы и стальные плиты в дождь становятся очень скользкими и дают гораздо меньше сцепления, поэтому не тормозите и не поворачивайте, находясь на них.","tr":"Boyalı çizgiler, katran dikişleri ve çelik plakalar ıslakken çok kayganlaşır ve çok daha az tutuş verir; bu yüzden lastikleriniz üzerlerindeyken frenlemekten veya dönmekten kaçının.","hi":"रंगी लाइनें, तार-स्नेक और स्टील प्लेटें गीले में बहुत फिसलन भरी हो जाती हैं और बहुत कम पकड़ देती हैं, इसलिए जब आपके टायर उन पर हों तो ब्रेक या मोड़ से बचें।","ar":"الخطوط المطلية وفواصل القار والألواح الفولاذية تصبح زلقة جداً عند البلل وتوفّر تماسكاً أقل بكثير، لذا تجنّب الكبح أو الانعطاف بينما إطاراك عليها."}},{"cat":"hazards","a":2,"q":{"en":"What can happen if a piece of cargo or a strap works loose while you ride?","es":"¿Qué puede pasar si una parte de la carga o una correa se suelta mientras conduce?","ru":"Что может произойти, если часть груза или ремень ослабнет во время езды?","tr":"Sürerken bir yük parçası veya kayış gevşerse ne olabilir?","hi":"चलते समय यदि सामान का कोई टुकड़ा या पट्टा ढीला हो जाए तो क्या हो सकता है?","ar":"ماذا قد يحدث إذا ارتخت قطعة من الحمولة أو حزام أثناء القيادة؟"},"o":[{"en":"Nothing, loose cargo is harmless","es":"Nada, la carga suelta es inofensiva","ru":"Ничего, свободный груз безвреден","tr":"Hiçbir şey, gevşek yük zararsızdır","hi":"कुछ नहीं, ढीला सामान हानिरहित है","ar":"لا شيء، فالحمولة المرتخية غير مؤذية"},{"en":"The bike will speed up","es":"La moto acelerará","ru":"Мотоцикл ускорится","tr":"Motosiklet hızlanır","hi":"बाइक तेज हो जाएगी","ar":"ستتسارع الدراجة"},{"en":"It can catch in the wheel or chain and cause a crash","es":"Puede engancharse en la rueda o cadena y causar un choque","ru":"Он может попасть в колесо или цепь и вызвать аварию","tr":"Tekerleğe veya zincire takılıp kazaya yol açabilir","hi":"यह पहिये या चेन में फँसकर दुर्घटना का कारण बन सकता है","ar":"قد يعلق في العجلة أو السلسلة ويسبّب حادثاً"},{"en":"The horn will sound","es":"Sonará la bocina","ru":"Сработает сигнал","tr":"Korna çalar","hi":"हॉर्न बजेगा","ar":"سيعمل البوق"}],"e":{"en":"A loose strap or item can drop into the wheel spokes or drive chain and lock the wheel, causing a sudden crash, so secure and check all cargo before and during a trip.","es":"Una correa o un objeto suelto puede caer en los rayos o la cadena y bloquear la rueda, causando un choque repentino, así que asegure y revise toda la carga antes y durante el viaje.","ru":"Свободный ремень или предмет может попасть в спицы или приводную цепь и заблокировать колесо, вызвав внезапную аварию, поэтому закрепляйте и проверяйте весь груз до и во время поездки.","tr":"Gevşek bir kayış veya eşya tekerlek jantına ya da tahrik zincirine düşüp tekerleği kilitleyebilir ve ani bir kazaya yol açabilir; bu yüzden tüm yükü yolculuktan önce ve sırasında sabitleyip kontrol edin.","hi":"ढीला पट्टा या वस्तु पहिये की तीलियों या ड्राइव चेन में गिरकर पहिये को लॉक कर सकती है, जिससे अचानक दुर्घटना हो सकती है, इसलिए यात्रा से पहले और दौरान सारा सामान बाँधें और जाँचें।","ar":"قد يسقط حزام أو غرض مرتخٍ في أسلاك العجلة أو سلسلة الدفع ويقفل العجلة مسبّباً حادثاً مفاجئاً، لذا ثبّت وافحص كل الحمولة قبل الرحلة وأثناءها."}},{"cat":"hazards","a":3,"q":{"en":"When you spot a slippery surface ahead that you cannot avoid, what is the best approach?","es":"Cuando ve adelante una superficie resbaladiza que no puede evitar, ¿cuál es el mejor enfoque?","ru":"Когда впереди неизбежный скользкий участок, как лучше действовать?","tr":"Kaçınamayacağınız kaygan bir yüzeyi ileride görürseniz en iyi yaklaşım nedir?","hi":"जब आगे कोई अपरिहार्य फिसलन भरी सतह दिखे, तो सबसे अच्छा तरीका क्या है?","ar":"عندما ترصد سطحاً زلقاً أمامك لا يمكنك تجنّبه، ما النهج الأفضل؟"},"o":[{"en":"Brake hard right on it","es":"Frenar fuerte justo sobre ella","ru":"Резко тормозить прямо на нём","tr":"Tam üzerinde sert frenlemek","hi":"ठीक उस पर जोर से ब्रेक लगाएँ","ar":"الكبح بقوة عليه مباشرة"},{"en":"Accelerate hard across it","es":"Acelerar fuerte al cruzarla","ru":"Резко ускоряться на нём","tr":"Üzerinden sertçe hızlanmak","hi":"इसके पार जोर से तेज हों","ar":"التسارع بقوة عبره"},{"en":"Turn sharply on it","es":"Girar bruscamente sobre ella","ru":"Резко поворачивать на нём","tr":"Üzerinde sertçe dönmek","hi":"इस पर तेजी से मुड़ें","ar":"الانعطاف بحدة عليه"},{"en":"Slow down beforehand, then cross it upright with steady speed and no sudden inputs","es":"Reducir antes, luego cruzarla erguido a velocidad constante y sin movimientos bruscos","ru":"Заранее сбросить скорость, затем проехать его вертикально с ровной скоростью и без резких действий","tr":"Önceden yavaşlamak, sonra dik, sabit hızla ve ani hareketler olmadan geçmek","hi":"पहले धीमे हों, फिर इसे सीधे, स्थिर गति और बिना अचानक इनपुट के पार करें","ar":"الإبطاء مسبقاً، ثم عبوره منتصباً بسرعة ثابتة ودون حركات مفاجئة"}],"e":{"en":"Do your slowing before the slick patch, then cross it with the bike upright, a steady throttle and no braking, turning or sudden throttle changes that could break traction.","es":"Reduzca antes del tramo resbaladizo y luego crúcelo con la moto erguida, acelerador constante y sin frenar, girar ni acelerar de golpe, para no perder tracción.","ru":"Тормозите до скользкого участка, а затем проезжайте его вертикально, с ровным газом, без торможения, поворотов и резких изменений газа, которые могут сорвать сцепление.","tr":"Yavaşlamayı kaygan bölümden önce yapın, sonra motosikleti dik, gazı sabit tutarak; tutuşu bozabilecek frenleme, dönme veya ani gaz değişimi olmadan geçin.","hi":"फिसलन भरे हिस्से से पहले धीमे हों, फिर बाइक सीधी, स्थिर थ्रॉटल के साथ पार करें, बिना ब्रेक, मोड़ या अचानक थ्रॉटल बदलाव के जो ट्रैक्शन तोड़ सकते हैं।","ar":"أبطئ قبل البقعة الزلقة، ثم اعبرها والدراجة منتصبة بخانق ثابت ودون كبح أو انعطاف أو تغيّر مفاجئ في الخانق قد يكسر التماسك."}},{"cat":"hazards","a":2,"q":{"en":"When it first starts to rain, why is the road often most slippery?","es":"Cuando empieza a llover, ¿por qué la vía suele estar más resbaladiza?","ru":"Когда только начинается дождь, почему дорога часто наиболее скользкая?","tr":"Yağmur ilk başladığında yol neden çoğu zaman en kaygan haldedir?","hi":"जब बारिश शुरू ही होती है, तब सड़क अक्सर सबसे अधिक फिसलन भरी क्यों होती है?","ar":"عندما يبدأ المطر للتو، لماذا يكون الطريق غالباً أكثر زلقاً؟"},"o":[{"en":"The road is coldest then","es":"La vía está más fría entonces","ru":"Дорога тогда самая холодная","tr":"Yol o an en soğuktur","hi":"तब सड़क सबसे ठंडी होती है","ar":"يكون الطريق أبرد حينها"},{"en":"Tires always grip worse in humidity","es":"Las llantas siempre agarran peor con humedad","ru":"Шины всегда хуже держат при влажности","tr":"Lastikler nemde her zaman daha kötü tutar","hi":"नमी में टायर हमेशा कम पकड़ते हैं","ar":"الإطارات دائماً أقل تماسكاً في الرطوبة"},{"en":"Early rain lifts oil and dust, making a slick film before it washes away","es":"La lluvia inicial levanta aceite y polvo, formando una película resbaladiza antes de lavarse","ru":"Первый дождь поднимает масло и пыль, образуя скользкую плёнку до того, как всё смоется","tr":"İlk yağmur yağ ve tozu kaldırıp yıkanıp gitmeden önce kaygan bir film oluşturur","hi":"शुरुआती बारिश तेल और धूल उठाकर, बहने से पहले एक फिसलन भरी परत बनाती है","ar":"المطر المبكر يرفع الزيت والغبار مكوّناً طبقة زلقة قبل أن تُغسل"},{"en":"Rain removes all traction permanently","es":"La lluvia elimina toda la tracción de forma permanente","ru":"Дождь навсегда убирает всё сцепление","tr":"Yağmur tüm tutuşu kalıcı olarak yok eder","hi":"बारिश स्थायी रूप से सारी ट्रैक्शन हटा देती है","ar":"المطر يزيل كل التماسك بشكل دائم"}],"e":{"en":"When rain begins, water mixes with oil and dust on the road to form a slippery film; traction improves after a harder rain washes the surface clean.","es":"Cuando empieza a llover, el agua se mezcla con aceite y polvo formando una película resbaladiza; la tracción mejora tras una lluvia más fuerte que limpia la superficie.","ru":"В начале дождя вода смешивается с маслом и пылью на дороге, образуя скользкую плёнку; сцепление улучшается, когда более сильный дождь смывает поверхность.","tr":"Yağmur başlayınca su, yoldaki yağ ve tozla karışarak kaygan bir film oluşturur; daha kuvvetli yağmur yüzeyi temizledikten sonra tutuş iyileşir.","hi":"बारिश शुरू होने पर पानी सड़क के तेल और धूल से मिलकर फिसलन भरी परत बनाता है; तेज बारिश सतह साफ कर देने के बाद ट्रैक्शन बेहतर होती है।","ar":"عند بدء المطر يختلط الماء بالزيت والغبار على الطريق مكوّناً طبقة زلقة؛ ويتحسّن التماسك بعد أن يغسل مطر أغزر السطح."}},{"cat":"passenger","a":0,"q":{"en":"How does adding a passenger change the way your motorcycle handles?","es":"¿Cómo cambia el manejo de su moto al llevar un pasajero?","ru":"Как пассажир меняет управляемость мотоцикла?","tr":"Bir yolcu eklemek motosikletinizin yol tutuşunu nasıl değiştirir?","hi":"सवारी जोड़ने से आपकी मोटरसाइकिल की हैंडलिंग कैसे बदलती है?","ar":"كيف يغيّر إضافة راكب طريقة تحكّم دراجتك؟"},"o":[{"en":"It adds weight, so it accelerates slower and takes longer to stop","es":"Añade peso, por lo que acelera más lento y tarda más en frenar","ru":"Он добавляет вес, поэтому разгон медленнее, а тормозной путь длиннее","tr":"Ağırlık ekler; bu yüzden daha yavaş hızlanır ve durması daha uzun sürer","hi":"यह वजन जोड़ता है, इसलिए यह धीमे तेज होती है और रुकने में अधिक समय लेती है","ar":"يضيف وزناً، فتتسارع أبطأ وتستغرق وقتاً أطول للتوقف"},{"en":"It makes the bike faster","es":"Hace la moto más rápida","ru":"Он делает мотоцикл быстрее","tr":"Motosikleti hızlandırır","hi":"यह बाइक को तेज बनाता है","ar":"يجعل الدراجة أسرع"},{"en":"It has no effect on handling","es":"No afecta el manejo","ru":"Он не влияет на управляемость","tr":"Yol tutuşuna etkisi yoktur","hi":"हैंडलिंग पर कोई असर नहीं","ar":"لا يؤثر على التحكم"},{"en":"It shortens stopping distance","es":"Acorta la distancia de frenado","ru":"Он сокращает тормозной путь","tr":"Durma mesafesini kısaltır","hi":"यह रुकने की दूरी घटाता है","ar":"يقصّر مسافة التوقف"}],"e":{"en":"A passenger's added weight means the motorcycle accelerates more slowly, needs more distance to stop, and responds differently, so ride with extra caution and space.","es":"El peso extra del pasajero hace que la moto acelere más despacio, necesite más distancia para frenar y responda distinto, así que conduzca con más precaución y espacio.","ru":"Дополнительный вес пассажира означает, что мотоцикл медленнее разгоняется, требует большего пути торможения и иначе реагирует, поэтому едьте осторожнее и с большим запасом.","tr":"Yolcunun ek ağırlığı, motosikletin daha yavaş hızlanması, durmak için daha fazla mesafe gerektirmesi ve farklı tepki vermesi demektir; bu yüzden daha dikkatli ve boşlukla sürün.","hi":"सवारी का अतिरिक्त वजन बाइक को धीमे तेज करता है, रुकने के लिए अधिक दूरी चाहिए और यह अलग प्रतिक्रिया देती है, इसलिए अतिरिक्त सावधानी और जगह के साथ चलाएँ।","ar":"وزن الراكب الإضافي يعني أن الدراجة تتسارع أبطأ وتحتاج مسافة أكبر للتوقف وتستجيب بشكل مختلف، لذا اركب بحذر ومسافة إضافية."}},{"cat":"passenger","a":1,"q":{"en":"What should you tell a passenger to do with their feet while riding?","es":"¿Qué debe indicar al pasajero que haga con los pies mientras conduce?","ru":"Что нужно велеть пассажиру делать с ногами во время движения?","tr":"Sürüş sırasında yolcuya ayaklarıyla ne yapmasını söylemelisiniz?","hi":"चलाते समय सवारी को अपने पैरों के साथ क्या करने को कहना चाहिए?","ar":"بماذا يجب أن تُخبر الراكب أن يفعل بقدميه أثناء القيادة؟"},"o":[{"en":"Dangle them for balance","es":"Dejarlos colgando para equilibrarse","ru":"Свесить их для равновесия","tr":"Denge için sallandırmak","hi":"संतुलन के लिए उन्हें लटकाए रखें","ar":"تركهما متدليتين للتوازن"},{"en":"Keep them on the footrests at all times, even when stopped","es":"Mantenerlos en los estribos en todo momento, incluso detenido","ru":"Держать их на подножках всё время, даже на остановке","tr":"Dururken bile her zaman basamaklarda tutmak","hi":"हर समय, रुकने पर भी, उन्हें फुटरेस्ट पर रखें","ar":"إبقاؤهما على المسندين طوال الوقت، حتى عند التوقف"},{"en":"Rest them on the exhaust pipes","es":"Apoyarlos en los tubos de escape","ru":"Ставить их на выхлопные трубы","tr":"Egzoz borularına dayamak","hi":"उन्हें एग्जॉस्ट पाइप पर टिकाएँ","ar":"إسنادهما على أنابيب العادم"},{"en":"Put them down at every stop","es":"Bajarlos en cada parada","ru":"Опускать их на каждой остановке","tr":"Her duruşta yere indirmek","hi":"हर रुकावट पर उन्हें नीचे रखें","ar":"إنزالهما عند كل توقف"}],"e":{"en":"The passenger should keep both feet on the footrests the whole time, even at stops, so they do not lose balance or get a foot caught.","es":"El pasajero debe mantener ambos pies en los estribos todo el tiempo, incluso en las paradas, para no perder el equilibrio ni atrapar un pie.","ru":"Пассажир должен держать обе ноги на подножках всё время, даже на остановках, чтобы не потерять равновесие и не зацепиться ногой.","tr":"Yolcu, dengesini kaybetmemek veya ayağını sıkıştırmamak için duruşlarda bile her zaman iki ayağını da basamaklarda tutmalıdır.","hi":"सवारी को हर समय, रुकने पर भी, दोनों पैर फुटरेस्ट पर रखने चाहिए ताकि संतुलन न खोए या पैर न फँसे।","ar":"يجب أن يُبقي الراكب كلتا قدميه على المسندين طوال الوقت، حتى عند التوقف، كي لا يفقد توازنه أو تعلق قدمه."}},{"cat":"passenger","a":2,"q":{"en":"How should a passenger move as you go through a turn?","es":"¿Cómo debe moverse el pasajero al tomar una curva?","ru":"Как пассажир должен двигаться при прохождении поворота?","tr":"Bir dönüşe girerken yolcu nasıl hareket etmelidir?","hi":"मोड़ से गुजरते समय सवारी को कैसे हिलना-डुलना चाहिए?","ar":"كيف يجب أن يتحرك الراكب عند مرورك في منعطف؟"},"o":[{"en":"Lean the opposite way to balance the bike","es":"Inclinarse al lado contrario para equilibrar","ru":"Наклоняться в противоположную сторону, чтобы уравновесить","tr":"Motosikleti dengelemek için ters yöne yatmak","hi":"बाइक संतुलित करने के लिए विपरीत ओर झुकें","ar":"الميل عكس الاتجاه لموازنة الدراجة"},{"en":"Sit upright and rigid","es":"Sentarse erguido y rígido","ru":"Сидеть прямо и неподвижно","tr":"Dik ve katı oturmak","hi":"सीधे और कठोर बैठें","ar":"الجلوس منتصباً وجامداً"},{"en":"Lean with the rider and the motorcycle as a unit","es":"Inclinarse junto con el conductor y la moto como una unidad","ru":"Наклоняться вместе с водителем и мотоциклом как единое целое","tr":"Sürücü ve motosikletle birlikte tek bir bütün gibi yatmak","hi":"चालक और मोटरसाइकिल के साथ एक इकाई की तरह झुकें","ar":"الميل مع السائق والدراجة كوحدة واحدة"},{"en":"Shift far to the inside of the turn","es":"Desplazarse mucho hacia el interior de la curva","ru":"Сильно смещаться внутрь поворота","tr":"Dönüşün iç tarafına iyice kaymak","hi":"मोड़ के अंदर की ओर बहुत खिसकें","ar":"الانتقال بعيداً إلى داخل المنعطف"}],"e":{"en":"The passenger should lean with the rider and bike as a single unit, looking over the rider's shoulder toward the turn, and avoid making their own separate movements.","es":"El pasajero debe inclinarse con el conductor y la moto como una sola unidad, mirando por encima del hombro del conductor hacia la curva, sin hacer movimientos propios.","ru":"Пассажир должен наклоняться вместе с водителем и мотоциклом как единое целое, глядя через плечо водителя в сторону поворота, и не делать собственных отдельных движений.","tr":"Yolcu, sürücü ve motosikletle tek bir bütün gibi yatmalı, sürücünün omzunun üzerinden dönüşe doğru bakmalı ve kendi ayrı hareketlerini yapmamalıdır.","hi":"सवारी को चालक और बाइक के साथ एक इकाई की तरह झुकना चाहिए, चालक के कंधे के ऊपर से मोड़ की ओर देखते हुए, और अपनी अलग हरकतें नहीं करनी चाहिए।","ar":"يجب أن يميل الراكب مع السائق والدراجة كوحدة واحدة، ناظراً فوق كتف السائق نحو المنعطف، وأن يتجنّب حركاته المنفصلة."}},{"cat":"passenger","a":3,"q":{"en":"Before your passenger gets on, what should you do?","es":"Antes de que suba su pasajero, ¿qué debe hacer?","ru":"Прежде чем пассажир сядет, что нужно сделать?","tr":"Yolcunuz binmeden önce ne yapmalısınız?","hi":"आपकी सवारी के बैठने से पहले आपको क्या करना चाहिए?","ar":"قبل أن يركب راكبك، ماذا يجب أن تفعل؟"},"o":[{"en":"Rev the engine loudly","es":"Acelerar el motor con fuerza","ru":"Громко газовать","tr":"Motoru yüksek sesle gazlamak","hi":"इंजन को जोर से रेव करें","ar":"تدوير المحرك بصوت عالٍ"},{"en":"Put the bike in gear","es":"Poner la moto en marcha","ru":"Включить передачу","tr":"Motosikleti vitese takmak","hi":"बाइक को गियर में डालें","ar":"وضع الدراجة في وضع التعشيق"},{"en":"Fold up the footrests","es":"Plegar los estribos","ru":"Сложить подножки","tr":"Basamakları katlamak","hi":"फुटरेस्ट मोड़ दें","ar":"طيّ المسندين"},{"en":"Start the engine and have the bike stable with both feet down","es":"Arrancar el motor y tener la moto estable con ambos pies en el suelo","ru":"Завести двигатель и удерживать мотоцикл устойчиво, упершись обеими ногами","tr":"Motoru çalıştırmak ve iki ayak yerde motosikleti sabit tutmak","hi":"इंजन शुरू करें और दोनों पैर नीचे रखकर बाइक स्थिर रखें","ar":"تشغيل المحرك وإبقاء الدراجة ثابتة مع وضع كلتا القدمين على الأرض"}],"e":{"en":"Start the engine and hold the motorcycle steady and upright with both feet down before the passenger mounts, so it does not tip while they climb on.","es":"Arranque el motor y mantenga la moto firme y erguida con ambos pies en el suelo antes de que suba el pasajero, para que no se incline al montar.","ru":"Заведите двигатель и держите мотоцикл устойчиво и вертикально, упершись обеими ногами, прежде чем пассажир сядет, чтобы он не завалился при посадке.","tr":"Yolcu binmeden önce motoru çalıştırın ve iki ayağınız yerdeyken motosikleti sabit ve dik tutun ki binerken devrilmesin.","hi":"सवारी के चढ़ने से पहले इंजन शुरू करें और दोनों पैर नीचे रखकर बाइक को स्थिर व सीधा रखें ताकि चढ़ते समय वह न झुके।","ar":"شغّل المحرك وأبقِ الدراجة ثابتة ومنتصبة مع وضع كلتا قدميك على الأرض قبل أن يركب الراكب، كي لا تميل أثناء صعوده."}},{"cat":"passenger","a":0,"q":{"en":"What is the recommended way for a passenger to hold on?","es":"¿Cuál es la forma recomendada de sujetarse para un pasajero?","ru":"Как пассажиру рекомендуется держаться?","tr":"Bir yolcunun tutunması için önerilen yol nedir?","hi":"सवारी के पकड़ने का अनुशंसित तरीका क्या है?","ar":"ما الطريقة الموصى بها لتمسّك الراكب؟"},"o":[{"en":"Hold the rider's waist or hips, or the passenger handholds","es":"Sujetar la cintura o caderas del conductor, o los asideros","ru":"Держаться за талию или бёдра водителя либо за поручни для пассажира","tr":"Sürücünün belini veya kalçalarını ya da yolcu tutamaklarını tutmak","hi":"चालक की कमर या कूल्हों, या सवारी के हैंडहोल्ड को पकड़ें","ar":"الإمساك بخصر السائق أو وركيه، أو بمقابض الراكب"},{"en":"Hold the rider's shoulders and lean on them","es":"Sujetar los hombros del conductor y apoyarse","ru":"Держаться за плечи водителя и опираться на него","tr":"Sürücünün omuzlarını tutup ona yaslanmak","hi":"चालक के कंधे पकड़कर उन पर टिकें","ar":"الإمساك بكتفي السائق والاتّكاء عليهما"},{"en":"Hold nothing and balance freely","es":"No sujetarse y equilibrarse libremente","ru":"Ни за что не держаться и балансировать свободно","tr":"Hiçbir şey tutmadan serbestçe dengede durmak","hi":"कुछ न पकड़ें और स्वतंत्र रूप से संतुलन बनाएँ","ar":"عدم الإمساك بشيء والتوازن بحرية"},{"en":"Grip the rear fender","es":"Agarrar el guardabarros trasero","ru":"Держаться за задний брызговик","tr":"Arka çamurluğu tutmak","hi":"रियर फेंडर पकड़ें","ar":"الإمساك بالرفرف الخلفي"}],"e":{"en":"A passenger should hold firmly to the rider's waist or hips, or to the passenger handholds, so they stay secure during acceleration and braking.","es":"El pasajero debe sujetarse con firmeza a la cintura o caderas del conductor, o a los asideros, para mantenerse seguro al acelerar y frenar.","ru":"Пассажиру следует крепко держаться за талию или бёдра водителя либо за поручни, чтобы оставаться в безопасности при разгоне и торможении.","tr":"Yolcu, hızlanma ve frenlemede güvende kalmak için sürücünün beline ya da kalçalarına veya yolcu tutamaklarına sıkıca tutunmalıdır.","hi":"सवारी को चालक की कमर या कूल्हों, या सवारी के हैंडहोल्ड को मजबूती से पकड़ना चाहिए ताकि तेज होने और ब्रेक लगाने के दौरान सुरक्षित रहे।","ar":"يجب أن يتمسّك الراكب بإحكام بخصر السائق أو وركيه، أو بمقابض الراكب، كي يبقى ثابتاً أثناء التسارع والكبح."}},{"cat":"passenger","a":1,"q":{"en":"Which equipment does the manual say a motorcycle needs before it can safely carry a passenger?","es":"¿Qué equipo dice el manual que necesita una moto para llevar un pasajero con seguridad?","ru":"Какое оборудование, по руководству, нужно мотоциклу, чтобы безопасно везти пассажира?","tr":"Kılavuz, bir motosikletin yolcu taşıyabilmesi için hangi donanıma ihtiyaç duyduğunu söyler?","hi":"मैनुअल के अनुसार सवारी को सुरक्षित रूप से ले जाने से पहले मोटरसाइकिल को किस उपकरण की जरूरत है?","ar":"ما المعدات التي يقول الدليل إن الدراجة تحتاجها قبل أن تحمل راكباً بأمان؟"},"o":[{"en":"A luggage rack","es":"Un portaequipajes","ru":"Багажник","tr":"Bir bagaj taşıyıcısı","hi":"एक लगेज रैक","ar":"حامل أمتعة"},{"en":"A proper passenger seat and footrests","es":"Un asiento para pasajero y estribos adecuados","ru":"Надлежащее пассажирское сиденье и подножки","tr":"Uygun bir yolcu koltuğu ve basamaklar","hi":"एक उचित सवारी सीट और फुटरेस्ट","ar":"مقعد راكب مناسب ومسندان للقدمين"},{"en":"A second headlight","es":"Un segundo faro","ru":"Второй фонарь","tr":"İkinci bir far","hi":"एक दूसरी हेडलाइट","ar":"مصباح أمامي ثانٍ"},{"en":"Wider handlebars","es":"Manillar más ancho","ru":"Более широкий руль","tr":"Daha geniş gidon","hi":"चौड़े हैंडलबार","ar":"مقود أعرض"}],"e":{"en":"To carry a passenger safely, the motorcycle must have a seat large enough for two and a set of footrests for the passenger to use.","es":"Para llevar un pasajero con seguridad, la moto debe tener un asiento suficientemente grande para dos y estribos para que el pasajero los use.","ru":"Чтобы безопасно везти пассажира, у мотоцикла должно быть сиденье, достаточное для двоих, и комплект подножек для пассажира.","tr":"Bir yolcuyu güvenle taşımak için motosiklette iki kişiye yetecek büyüklükte bir koltuk ve yolcunun kullanacağı bir çift basamak bulunmalıdır.","hi":"सवारी को सुरक्षित रूप से ले जाने के लिए मोटरसाइकिल में दो के लिए पर्याप्त बड़ी सीट और सवारी के उपयोग हेतु फुटरेस्ट होने चाहिए।","ar":"لحمل راكب بأمان، يجب أن يكون في الدراجة مقعد كبير بما يكفي لشخصين ومجموعة مسندين ليستخدمها الراكب."}},{"cat":"passenger","a":2,"q":{"en":"When riding with a passenger, how should you approach stops and starts?","es":"Al conducir con un pasajero, ¿cómo debe abordar las paradas y arranques?","ru":"С пассажиром как выполнять остановки и трогания?","tr":"Yolcuyla sürerken duruş ve kalkışlara nasıl yaklaşmalısınız?","hi":"सवारी के साथ चलाते समय रुकावट और शुरुआत को कैसे संभालें?","ar":"عند القيادة مع راكب، كيف تتعامل مع التوقف والانطلاق؟"},"o":[{"en":"Brake and accelerate harder than usual","es":"Frenar y acelerar más fuerte que de costumbre","ru":"Тормозить и разгоняться резче обычного","tr":"Normalden daha sert frenlemek ve hızlanmak","hi":"सामान्य से अधिक जोर से ब्रेक और तेज हों","ar":"الكبح والتسارع أقوى من المعتاد"},{"en":"Ignore the extra weight","es":"Ignorar el peso adicional","ru":"Игнорировать лишний вес","tr":"Ek ağırlığı görmezden gelmek","hi":"अतिरिक्त वजन को अनदेखा करें","ar":"تجاهل الوزن الإضافي"},{"en":"Start and stop more gradually to account for the added weight","es":"Arrancar y detenerse de forma más gradual por el peso extra","ru":"Трогаться и останавливаться плавнее с учётом добавленного веса","tr":"Ek ağırlığı hesaba katarak daha kademeli kalkıp durmak","hi":"अतिरिक्त वजन के कारण अधिक क्रमिक रूप से शुरू और रुकें","ar":"الانطلاق والتوقف بتدرّج أكبر مراعاةً للوزن الإضافي"},{"en":"Only use the rear brake","es":"Usar solo el freno trasero","ru":"Использовать только задний тормоз","tr":"Yalnızca arka freni kullanmak","hi":"केवल रियर ब्रेक इस्तेमाल करें","ar":"استخدام الفرامل الخلفية فقط"}],"e":{"en":"Because the extra weight lengthens stopping and slows acceleration, start and stop more gradually and leave more distance than you would riding alone.","es":"Como el peso extra alarga el frenado y ralentiza la aceleración, arranque y frene de forma más gradual y deje más distancia que si fuera solo.","ru":"Поскольку лишний вес удлиняет остановку и замедляет разгон, трогайтесь и тормозите плавнее и оставляйте больше дистанции, чем в одиночку.","tr":"Ek ağırlık durmayı uzattığı ve hızlanmayı yavaşlattığı için, tek başınıza sürerkenden daha kademeli kalkıp durun ve daha fazla mesafe bırakın.","hi":"चूँकि अतिरिक्त वजन रुकावट बढ़ाता और तेज होना धीमा करता है, अधिक क्रमिक रूप से शुरू-रुकें और अकेले चलाने से अधिक दूरी रखें।","ar":"لأن الوزن الإضافي يطيل التوقف ويبطئ التسارع، انطلق وتوقف بتدرّج أكبر واترك مسافة أكبر مما تفعل عند القيادة منفرداً."}},{"cat":"passenger","a":3,"q":{"en":"What instructions should you give a first-time passenger before riding?","es":"¿Qué instrucciones debe dar a un pasajero primerizo antes de conducir?","ru":"Какие инструкции дать пассажиру-новичку перед поездкой?","tr":"Sürmeden önce ilk kez binen bir yolcuya hangi talimatları vermelisiniz?","hi":"चलाने से पहले पहली बार बैठने वाली सवारी को क्या निर्देश देने चाहिए?","ar":"ما التعليمات التي يجب أن تعطيها لراكب لأول مرة قبل القيادة؟"},"o":[{"en":"None; they will figure it out","es":"Ninguna; ya lo descubrirá","ru":"Никаких; сам разберётся","tr":"Hiçbiri; kendisi çözer","hi":"कोई नहीं; वे खुद समझ लेंगे","ar":"لا شيء؛ سيكتشف بنفسه"},{"en":"Only how to get off","es":"Solo cómo bajarse","ru":"Только как слезать","tr":"Yalnızca nasıl inileceğini","hi":"केवल कैसे उतरना है","ar":"فقط كيفية النزول"},{"en":"Only where to look","es":"Solo hacia dónde mirar","ru":"Только куда смотреть","tr":"Yalnızca nereye bakılacağını","hi":"केवल कहाँ देखना है","ar":"فقط إلى أين ينظر"},{"en":"How to hold on, where to put their feet, and to lean with you in turns","es":"Cómo sujetarse, dónde poner los pies y a inclinarse con usted en las curvas","ru":"Как держаться, куда ставить ноги и наклоняться вместе с вами в поворотах","tr":"Nasıl tutunacağı, ayaklarını nereye koyacağı ve dönüşlerde sizinle birlikte yatacağı","hi":"कैसे पकड़ना है, पैर कहाँ रखने हैं, और मोड़ों में आपके साथ झुकना है","ar":"كيف يتمسّك وأين يضع قدميه وأن يميل معك في المنعطفات"}],"e":{"en":"Brief a new passenger to hold on firmly, keep feet on the footrests, lean with you in turns, and avoid sudden moves, so they do not upset the bike's balance.","es":"Instruya al pasajero nuevo a sujetarse con firmeza, mantener los pies en los estribos, inclinarse con usted en las curvas y evitar movimientos bruscos, para no desestabilizar la moto.","ru":"Проинструктируйте нового пассажира крепко держаться, держать ноги на подножках, наклоняться с вами в поворотах и избегать резких движений, чтобы не нарушать баланс мотоцикла.","tr":"Yeni yolcuya sıkıca tutunmasını, ayaklarını basamaklarda tutmasını, dönüşlerde sizinle yatmasını ve ani hareketlerden kaçınmasını anlatın ki motosikletin dengesini bozmasın.","hi":"नई सवारी को मजबूती से पकड़ने, पैर फुटरेस्ट पर रखने, मोड़ों में आपके साथ झुकने और अचानक हरकतों से बचने का निर्देश दें ताकि वे बाइक का संतुलन न बिगाड़ें।","ar":"وجّه الراكب الجديد بأن يتمسّك بإحكام ويُبقي قدميه على المسندين ويميل معك في المنعطفات ويتجنّب الحركات المفاجئة كي لا يخل بتوازن الدراجة."}},{"cat":"passenger","a":0,"q":{"en":"In a group ride, what is the recommended formation on an open road?","es":"En una conducción en grupo, ¿cuál es la formación recomendada en carretera abierta?","ru":"В групповой поездке какое построение рекомендуется на открытой дороге?","tr":"Grup sürüşünde açık yolda önerilen düzen nedir?","hi":"समूह राइड में खुली सड़क पर अनुशंसित संरचना क्या है?","ar":"في القيادة الجماعية، ما التشكيل الموصى به على طريق مفتوح؟"},"o":[{"en":"A staggered formation","es":"Una formación escalonada","ru":"Ступенчатое построение","tr":"Kaydırılmış (zikzak) düzen","hi":"एक स्टैगर्ड संरचना","ar":"تشكيل متعرّج (متداخل)"},{"en":"Side by side in pairs","es":"Lado a lado en parejas","ru":"Парами бок о бок","tr":"İkişerli yan yana","hi":"जोड़ियों में अगल-बगल","ar":"جنباً إلى جنب في أزواج"},{"en":"Bunched tightly together","es":"Apiñados muy juntos","ru":"Плотной кучей","tr":"Sıkışık şekilde bir arada","hi":"कसकर एक साथ गुच्छित","ar":"متجمّعين بإحكام معاً"},{"en":"In a single tight circle","es":"En un solo círculo cerrado","ru":"В одном тесном кругу","tr":"Tek bir sıkı daire hâlinde","hi":"एक तंग वृत्त में","ar":"في دائرة ضيقة واحدة"}],"e":{"en":"A staggered formation keeps the group close while giving each rider enough space ahead and to the side to maneuver safely.","es":"Una formación escalonada mantiene al grupo unido y da a cada conductor suficiente espacio adelante y al lado para maniobrar con seguridad.","ru":"Ступенчатое построение держит группу вместе, оставляя каждому мотоциклисту достаточно места впереди и сбоку для безопасного манёвра.","tr":"Kaydırılmış düzen, grubu bir arada tutarken her sürücüye güvenli manevra için önde ve yanda yeterli boşluk bırakır.","hi":"स्टैगर्ड संरचना समूह को पास रखती है और प्रत्येक चालक को सुरक्षित युद्धाभ्यास के लिए आगे और बगल में पर्याप्त जगह देती है।","ar":"التشكيل المتعرّج يُبقي المجموعة متقاربة مع منح كل سائق مساحة كافية أمامه وإلى جانبه للمناورة بأمان."}},{"cat":"passenger","a":1,"q":{"en":"When should a group of riders switch from a staggered formation to single file?","es":"¿Cuándo debe un grupo pasar de formación escalonada a fila india?","ru":"Когда группе мотоциклистов переходить со ступенчатого построения в один ряд?","tr":"Bir sürücü grubu kaydırılmış düzenden tek sıraya ne zaman geçmelidir?","hi":"राइडर समूह को स्टैगर्ड संरचना से एकल कतार में कब बदलना चाहिए?","ar":"متى يجب أن تنتقل مجموعة السائقين من التشكيل المتعرّج إلى صف واحد؟"},"o":[{"en":"Only on wide, empty highways","es":"Solo en autopistas anchas y vacías","ru":"Только на широких пустых шоссе","tr":"Yalnızca geniş, boş otoyollarda","hi":"केवल चौड़े, खाली राजमार्गों पर","ar":"على الطرق السريعة الواسعة والفارغة فقط"},{"en":"In curves, narrow roads, or poor conditions","es":"En curvas, caminos estrechos o malas condiciones","ru":"На поворотах, узких дорогах или в плохих условиях","tr":"Virajlarda, dar yollarda veya kötü koşullarda","hi":"मोड़ों, संकरी सड़कों या खराब परिस्थितियों में","ar":"في المنعطفات أو الطرق الضيّقة أو الظروف السيئة"},{"en":"Never, single file is unsafe","es":"Nunca, la fila india es insegura","ru":"Никогда, один ряд опасен","tr":"Asla, tek sıra güvensizdir","hi":"कभी नहीं, एकल कतार असुरक्षित है","ar":"أبداً، الصف الواحد غير آمن"},{"en":"Only at night","es":"Solo de noche","ru":"Только ночью","tr":"Yalnızca geceleyin","hi":"केवल रात में","ar":"ليلاً فقط"}],"e":{"en":"Switch to single file for curves, turns, narrow or bumpy roads, and poor visibility, where each rider needs the full width of the lane and more space.","es":"Pase a fila india en curvas, giros, caminos estrechos o con baches y mala visibilidad, donde cada conductor necesita todo el ancho del carril y más espacio.","ru":"Переходите в один ряд на поворотах, узких или неровных дорогах и при плохой видимости, где каждому мотоциклисту нужна вся ширина полосы и больше места.","tr":"Virajlarda, dönüşlerde, dar veya engebeli yollarda ve kötü görüşte tek sıraya geçin; buralarda her sürücü şeridin tamamına ve daha fazla boşluğa ihtiyaç duyar.","hi":"मोड़ों, टर्न, संकरी या ऊबड़-खाबड़ सड़कों और खराब दृश्यता में एकल कतार में बदलें, जहाँ प्रत्येक चालक को लेन की पूरी चौड़ाई और अधिक जगह चाहिए।","ar":"انتقل إلى صف واحد في المنعطفات والانعطافات والطرق الضيّقة أو الوعرة والرؤية السيئة، حيث يحتاج كل سائق إلى عرض المسار كاملاً ومساحة أكبر."}},{"cat":"passenger","a":2,"q":{"en":"In a group, where should the least experienced riders usually be placed?","es":"En un grupo, ¿dónde deben ubicarse normalmente los conductores menos experimentados?","ru":"В группе где обычно размещать наименее опытных мотоциклистов?","tr":"Bir grupta en az deneyimli sürücüler genellikle nereye yerleştirilmelidir?","hi":"समूह में सबसे कम अनुभवी राइडर्स को आमतौर पर कहाँ रखा जाना चाहिए?","ar":"في المجموعة، أين يجب وضع أقل السائقين خبرة عادةً؟"},"o":[{"en":"At the very back alone","es":"Al final, solos","ru":"В самом хвосте, отдельно","tr":"En arkada tek başına","hi":"बिल्कुल पीछे अकेले","ar":"في المؤخرة تماماً وحدهم"},{"en":"At the front as leader","es":"Al frente como líder","ru":"Впереди как ведущие","tr":"En önde lider olarak","hi":"आगे नेता के रूप में","ar":"في المقدمة كقائد"},{"en":"Near the front, just behind the leader","es":"Cerca del frente, justo detrás del líder","ru":"Ближе к началу, сразу за ведущим","tr":"Önlere yakın, liderin hemen arkasında","hi":"आगे के पास, नेता के ठीक पीछे","ar":"قرب المقدمة، خلف القائد مباشرة"},{"en":"Spread randomly through the group","es":"Repartidos al azar por el grupo","ru":"Разбросаны случайно по группе","tr":"Grup içinde rastgele dağıtılmış","hi":"समूह में बेतरतीब फैलाए हुए","ar":"موزّعين عشوائياً في المجموعة"}],"e":{"en":"Inexperienced riders should ride near the front, just behind the leader, so more experienced riders can watch them and they are not left to keep up from the back.","es":"Los conductores sin experiencia deben ir cerca del frente, justo detrás del líder, para que los más experimentados los vigilen y no queden atrás intentando seguir el ritmo.","ru":"Неопытных мотоциклистов ставят ближе к началу, сразу за ведущим, чтобы более опытные могли за ними следить и им не пришлось догонять сзади.","tr":"Deneyimsiz sürücüler önlere yakın, liderin hemen arkasında sürmeli; böylece deneyimliler onları gözleyebilir ve arkadan yetişmeye çalışmak zorunda kalmazlar.","hi":"अनुभवहीन राइडर्स को आगे के पास, नेता के ठीक पीछे चलना चाहिए ताकि अधिक अनुभवी उन पर नजर रख सकें और उन्हें पीछे से गति बनाए रखने के लिए न छोड़ा जाए।","ar":"يجب أن يركب السائقون قليلو الخبرة قرب المقدمة، خلف القائد مباشرة، كي يراقبهم الأكثر خبرة ولا يُتركوا للّحاق من الخلف."}},{"cat":"passenger","a":3,"q":{"en":"What is the role of the 'sweep' or last rider in a group ride?","es":"¿Cuál es la función del conductor de cierre o último en una conducción en grupo?","ru":"Какова роль замыкающего (sweep) в групповой поездке?","tr":"Grup sürüşünde 'süpürücü' veya son sürücünün rolü nedir?","hi":"समूह राइड में 'स्वीप' या अंतिम राइडर की भूमिका क्या है?","ar":"ما دور 'المُغلِق' أو السائق الأخير في القيادة الجماعية؟"},"o":[{"en":"To ride fastest and set the pace","es":"Conducir más rápido y marcar el ritmo","ru":"Ехать быстрее всех и задавать темп","tr":"En hızlı sürüp tempoyu belirlemek","hi":"सबसे तेज चलना और गति तय करना","ar":"القيادة الأسرع وتحديد الإيقاع"},{"en":"To ride ahead and scout","es":"Ir adelante y explorar","ru":"Ехать впереди и разведывать","tr":"Önden gidip keşif yapmak","hi":"आगे चलना और टोह लेना","ar":"القيادة في المقدمة والاستطلاع"},{"en":"To weave through the group","es":"Zigzaguear entre el grupo","ru":"Петлять внутри группы","tr":"Grubun arasında dolaşmak","hi":"समूह के बीच से बुनना","ar":"التعرّج بين المجموعة"},{"en":"To ride last and help keep the group together","es":"Ir último y ayudar a mantener unido al grupo","ru":"Ехать последним и помогать держать группу вместе","tr":"En arkada gidip grubu bir arada tutmaya yardım etmek","hi":"अंत में चलना और समूह को साथ रखने में मदद करना","ar":"القيادة أخيراً والمساعدة في إبقاء المجموعة متماسكة"}],"e":{"en":"The sweep rider is an experienced rider at the back who helps keep the group together and watches for anyone who falls behind or has trouble.","es":"El conductor de cierre es un motociclista experimentado al final que ayuda a mantener unido al grupo y vigila a quien se rezague o tenga problemas.","ru":"Замыкающий — опытный мотоциклист в хвосте, который помогает держать группу вместе и следит за отстающими или теми, у кого проблемы.","tr":"Süpürücü, arkada bulunan deneyimli bir sürücüdür; grubu bir arada tutmaya yardım eder ve geride kalan ya da sorun yaşayan olursa gözetir.","hi":"स्वीप राइडर पीछे एक अनुभवी राइडर होता है जो समूह को साथ रखने में मदद करता है और पीछे रह जाने या परेशानी में पड़ने वाले पर नजर रखता है।","ar":"المُغلِق سائق ذو خبرة في المؤخرة يساعد على إبقاء المجموعة متماسكة ويراقب من يتخلّف أو يواجه مشكلة."}},{"cat":"passenger","a":0,"q":{"en":"Why should a group of motorcyclists avoid riding two abreast in the same lane?","es":"¿Por qué un grupo de motociclistas debe evitar circular de dos en fondo en el mismo carril?","ru":"Почему группе мотоциклистов не стоит ехать по двое в одной полосе?","tr":"Bir motosikletli grubu neden aynı şeritte ikişerli sürmekten kaçınmalıdır?","hi":"मोटरसाइकिल चालकों के समूह को एक ही लेन में दो-दो साथ चलने से क्यों बचना चाहिए?","ar":"لماذا يجب أن تتجنّب مجموعة من سائقي الدراجات القيادة اثنين جنباً إلى جنب في نفس المسار؟"},"o":[{"en":"It leaves each rider too little room to maneuver or brake","es":"Deja a cada conductor muy poco espacio para maniobrar o frenar","ru":"Это оставляет каждому слишком мало места для манёвра или торможения","tr":"Her sürücüye manevra veya frenleme için çok az yer bırakır","hi":"यह प्रत्येक चालक को युद्धाभ्यास या ब्रेक के लिए बहुत कम जगह देता है","ar":"يترك لكل سائق مساحة قليلة جداً للمناورة أو الكبح"},{"en":"It is faster but noisier","es":"Es más rápido pero más ruidoso","ru":"Это быстрее, но шумнее","tr":"Daha hızlı ama daha gürültülüdür","hi":"यह तेज है पर अधिक शोरगुल वाला","ar":"أسرع لكنه أكثر ضجيجاً"},{"en":"It saves fuel","es":"Ahorra combustible","ru":"Это экономит топливо","tr":"Yakıt tasarrufu sağlar","hi":"यह ईंधन बचाता है","ar":"يوفّر الوقود"},{"en":"It improves visibility to the front","es":"Mejora la visibilidad hacia adelante","ru":"Это улучшает обзор вперёд","tr":"Öne doğru görüşü artırır","hi":"यह आगे की दृश्यता बेहतर करता है","ar":"يحسّن الرؤية للأمام"}],"e":{"en":"Riding side by side in one lane leaves no room to swerve or brake if a rider needs to react, so the manual advises against two motorcycles sharing a lane abreast.","es":"Circular lado a lado en un carril no deja espacio para esquivar o frenar si un conductor debe reaccionar, por eso el manual desaconseja que dos motos compartan un carril en paralelo.","ru":"Езда бок о бок в одной полосе не оставляет места для манёвра или торможения, если нужно среагировать, поэтому руководство не советует двум мотоциклам делить полосу в ряд.","tr":"Aynı şeritte yan yana sürmek, bir sürücünün tepki vermesi gerektiğinde kaçmaya veya frenlemeye yer bırakmaz; bu yüzden kılavuz iki motosikletin şeridi yan yana paylaşmasını önermez.","hi":"एक लेन में अगल-बगल चलना प्रतिक्रिया की जरूरत पड़ने पर मुड़ने या ब्रेक की जगह नहीं छोड़ता, इसलिए मैनुअल दो मोटरसाइकिलों के एक लेन को साथ-साथ साझा करने की सलाह नहीं देता।","ar":"القيادة جنباً إلى جنب في مسار واحد لا تترك مجالاً للمناورة أو الكبح إذا احتاج سائق للتفاعل، لذا ينصح الدليل بعدم مشاركة دراجتين المسار جنباً إلى جنب."}},{"cat":"passenger","a":1,"q":{"en":"How does the manual suggest handling gaps in traffic when riding in a group?","es":"¿Cómo sugiere el manual manejar los huecos en el tráfico al conducir en grupo?","ru":"Как руководство советует использовать промежутки в потоке при езде в группе?","tr":"Kılavuz, grup hâlinde sürerken trafikteki boşlukların nasıl ele alınmasını önerir?","hi":"समूह में चलाते समय ट्रैफ़िक के अंतरालों को संभालने का मैनुअल क्या सुझाव देता है?","ar":"كيف يقترح الدليل التعامل مع الفجوات في حركة المرور عند القيادة ضمن مجموعة؟"},"o":[{"en":"Everyone squeezes through on a single gap together","es":"Todos pasan juntos por un solo hueco","ru":"Все вместе протискиваются в один промежуток","tr":"Herkes tek bir boşluktan birlikte sıkışıp geçer","hi":"सभी एक ही अंतराल से एक साथ निकलते हैं","ar":"يمرّ الجميع معاً عبر فجوة واحدة"},{"en":"Each rider waits for a safe gap and crosses individually","es":"Cada conductor espera un hueco seguro y cruza individualmente","ru":"Каждый ждёт безопасный промежуток и переезжает по отдельности","tr":"Her sürücü güvenli bir boşluğu bekler ve tek tek geçer","hi":"प्रत्येक चालक सुरक्षित अंतराल की प्रतीक्षा कर अलग-अलग पार करता है","ar":"ينتظر كل سائق فجوة آمنة ويعبر بشكل فردي"},{"en":"Follow the leader through any gap regardless of size","es":"Seguir al líder por cualquier hueco sin importar el tamaño","ru":"Следовать за ведущим в любой промежуток независимо от размера","tr":"Boyutu ne olursa olsun lideri her boşlukta takip etmek","hi":"आकार की परवाह किए बिना किसी भी अंतराल से नेता का अनुसरण करें","ar":"اتّباع القائد عبر أي فجوة بغض النظر عن حجمها"},{"en":"Speed up to close all gaps","es":"Acelerar para cerrar todos los huecos","ru":"Ускоряться, чтобы закрыть все промежутки","tr":"Tüm boşlukları kapatmak için hızlanmak","hi":"सभी अंतराल बंद करने के लिए तेज हों","ar":"التسارع لإغلاق كل الفجوات"}],"e":{"en":"When crossing or merging, each rider should wait for and judge a safe gap individually rather than blindly following the rider ahead into traffic.","es":"Al cruzar o incorporarse, cada conductor debe esperar y juzgar un hueco seguro por sí mismo en vez de seguir a ciegas al de adelante hacia el tráfico.","ru":"При пересечении или перестроении каждый мотоциклист должен сам дождаться и оценить безопасный промежуток, а не слепо следовать за впередиидущим в поток.","tr":"Geçerken veya katılırken her sürücü, önündekini körü körüne takip etmek yerine güvenli bir boşluğu tek tek beklemeli ve değerlendirmelidir.","hi":"पार करते या मिलते समय प्रत्येक चालक को आगे वाले का आँख मूँदकर अनुसरण करने के बजाय स्वयं सुरक्षित अंतराल की प्रतीक्षा और आकलन करना चाहिए।","ar":"عند العبور أو الاندماج، يجب أن ينتظر كل سائق ويقدّر فجوة آمنة بنفسه بدلاً من اتّباع من أمامه بشكل أعمى في حركة المرور."}},{"cat":"passenger","a":2,"q":{"en":"How should you fasten cargo to your motorcycle?","es":"¿Cómo debe sujetar la carga a su motocicleta?","ru":"Как крепить груз к мотоциклу?","tr":"Yükü motosikletinize nasıl sabitlemelisiniz?","hi":"अपनी मोटरसाइकिल पर सामान कैसे बाँधना चाहिए?","ar":"كيف يجب أن تثبّت الحمولة على دراجتك؟"},"o":[{"en":"With a single strap over the top","es":"Con una sola correa por encima","ru":"Одним ремнём сверху","tr":"Üstten tek bir kayışla","hi":"ऊपर से एक ही पट्टे से","ar":"بحزام واحد من الأعلى"},{"en":"Loosely so it can shift","es":"De forma holgada para que pueda moverse","ru":"Свободно, чтобы он мог смещаться","tr":"Kayabilecek şekilde gevşek","hi":"ढीले ढंग से ताकि यह खिसक सके","ar":"بشكل مرتخٍ كي يتمكن من التحرك"},{"en":"Firmly with several straps or a cargo net so it cannot shift","es":"Con firmeza con varias correas o una red para que no se mueva","ru":"Надёжно, несколькими ремнями или грузовой сеткой, чтобы он не смещался","tr":"Kaymaması için birkaç kayış veya yük filesiyle sıkıca","hi":"कई पट्टों या कार्गो नेट से मजबूती से ताकि यह खिसक न सके","ar":"بإحكام بعدة أحزمة أو شبكة حمولة كي لا يتحرك"},{"en":"Only by resting it on the seat","es":"Solo apoyándola en el asiento","ru":"Просто положив его на сиденье","tr":"Yalnızca koltuğun üzerine koyarak","hi":"केवल इसे सीट पर रखकर","ar":"بمجرد وضعها على المقعد"}],"e":{"en":"Secure cargo firmly with several tie-downs or a cargo net so nothing can shift or come loose and fall into the wheels or chain while you ride.","es":"Asegure la carga con firmeza con varias amarras o una red para que nada se mueva ni se suelte y caiga en las ruedas o la cadena al conducir.","ru":"Надёжно крепите груз несколькими стяжками или грузовой сеткой, чтобы ничего не сместилось и не попало в колёса или цепь во время езды.","tr":"Yükü birkaç bağlama kayışı veya yük filesiyle sıkıca sabitleyin ki sürerken hiçbir şey kayıp gevşemesin ve tekerleklere ya da zincire düşmesin.","hi":"सामान को कई टाई-डाउन या कार्गो नेट से मजबूती से बाँधें ताकि चलते समय कुछ भी खिसके या ढीला होकर पहियों या चेन में न गिरे।","ar":"ثبّت الحمولة بإحكام بعدة أربطة أو شبكة حمولة كي لا يتحرك شيء أو يرتخي ويسقط في العجلات أو السلسلة أثناء القيادة."}},{"cat":"passenger","a":3,"q":{"en":"When following another rider in a staggered group, how much distance should you keep from the rider directly ahead in your track?","es":"Al seguir a otro conductor en un grupo escalonado, ¿cuánta distancia debe mantener del que va justo delante en su misma huella?","ru":"Следуя за другим в ступенчатой группе, какую дистанцию держать до того, кто прямо впереди в вашей колее?","tr":"Kaydırılmış bir grupta başka bir sürücüyü takip ederken, kendi izinizde tam önünüzdeki sürücüden ne kadar mesafe bırakmalısınız?","hi":"स्टैगर्ड समूह में किसी अन्य चालक का अनुसरण करते समय, अपनी ट्रैक में ठीक आगे वाले चालक से कितनी दूरी रखनी चाहिए?","ar":"عند اتّباع سائق آخر في مجموعة متعرّجة، كم مسافة يجب أن تُبقيها عن السائق الذي أمامك مباشرة في مسارك؟"},"o":[{"en":"About half a second","es":"Cerca de medio segundo","ru":"Около полусекунды","tr":"Yaklaşık yarım saniye","hi":"लगभग आधा सेकंड","ar":"نحو نصف ثانية"},{"en":"Exactly one bike length","es":"Exactamente el largo de una moto","ru":"Ровно длину одного мотоцикла","tr":"Tam bir motosiklet boyu","hi":"ठीक एक बाइक की लंबाई","ar":"طول دراجة واحدة بالضبط"},{"en":"No gap; ride close","es":"Sin espacio; ir pegado","ru":"Без зазора; ехать вплотную","tr":"Boşluk yok; yakın sürmek","hi":"कोई अंतराल नहीं; करीब चलें","ar":"بلا فجوة؛ القيادة قريباً"},{"en":"About two seconds","es":"Cerca de dos segundos","ru":"Около двух секунд","tr":"Yaklaşık iki saniye","hi":"लगभग दो सेकंड","ar":"نحو ثانيتين"}],"e":{"en":"In a staggered formation you normally keep about a two-second gap behind the rider directly ahead in your track, with roughly a one-second gap to the staggered rider beside you.","es":"En formación escalonada normalmente mantiene unos dos segundos tras el conductor justo delante en su huella, y cerca de un segundo respecto al conductor escalonado a su lado.","ru":"В ступенчатом построении обычно держат около двух секунд до того, кто прямо впереди в вашей колее, и примерно секунду до соседнего мотоциклиста в шахматном порядке.","tr":"Kaydırılmış düzende, kendi izinizde tam önünüzdeki sürücünün arkasında normalde yaklaşık iki saniyelik, yanınızdaki kaydırılmış sürücüyle ise yaklaşık bir saniyelik boşluk bırakırsınız.","hi":"स्टैगर्ड संरचना में आप सामान्यतः अपनी ट्रैक में ठीक आगे वाले चालक से लगभग दो सेकंड और बगल के स्टैगर्ड चालक से लगभग एक सेकंड का अंतराल रखते हैं।","ar":"في التشكيل المتعرّج تُبقي عادةً نحو ثانيتين خلف السائق الذي أمامك مباشرة في مسارك، ونحو ثانية واحدة عن السائق المتعرّج بجانبك."}},{"cat":"passenger","a":0,"q":{"en":"Why should you tell your passenger to look over your shoulder in the direction of a turn?","es":"¿Por qué debe indicar a su pasajero que mire por encima de su hombro en la dirección del giro?","ru":"Почему стоит велеть пассажиру смотреть через ваше плечо в сторону поворота?","tr":"Yolcunuza dönüş yönünde omzunuzun üzerinden bakmasını neden söylemelisiniz?","hi":"आपको अपनी सवारी को मोड़ की दिशा में अपने कंधे के ऊपर से देखने को क्यों कहना चाहिए?","ar":"لماذا يجب أن تُخبر راكبك أن ينظر فوق كتفك في اتجاه الانعطاف؟"},"o":[{"en":"It helps them lean naturally with the bike instead of against it","es":"Les ayuda a inclinarse naturalmente con la moto en vez de contra ella","ru":"Это помогает ему естественно наклоняться вместе с мотоциклом, а не против него","tr":"Motosikletle ona karşı değil, doğal biçimde birlikte yatmalarına yardımcı olur","hi":"यह उन्हें बाइक के विरुद्ध नहीं बल्कि उसके साथ स्वाभाविक रूप से झुकने में मदद करता है","ar":"يساعدهم على الميل طبيعياً مع الدراجة بدلاً من عكسها"},{"en":"It lets them see the speedometer","es":"Les permite ver el velocímetro","ru":"Это позволяет ему видеть спидометр","tr":"Hız göstergesini görmelerini sağlar","hi":"यह उन्हें स्पीडोमीटर देखने देता है","ar":"يتيح لهم رؤية عداد السرعة"},{"en":"It keeps their weight off the seat","es":"Mantiene su peso fuera del asiento","ru":"Это снимает его вес с сиденья","tr":"Ağırlıklarını koltuktan alır","hi":"यह उनका वजन सीट से हटाता है","ar":"يُبعد وزنهم عن المقعد"},{"en":"It is required by law","es":"Lo exige la ley","ru":"Этого требует закон","tr":"Yasa gereğidir","hi":"यह कानून द्वारा आवश्यक है","ar":"مطلوب بموجب القانون"}],"e":{"en":"Having the passenger look over your shoulder into the turn naturally leans them with you and the bike as one unit, keeping the motorcycle balanced.","es":"Que el pasajero mire por encima de su hombro hacia la curva lo inclina naturalmente con usted y la moto como una unidad, manteniéndola equilibrada.","ru":"Когда пассажир смотрит через ваше плечо в поворот, он естественно наклоняется вместе с вами и мотоциклом как единое целое, сохраняя баланс.","tr":"Yolcunun omzunuzun üzerinden dönüşe bakması, onları sizinle ve motosikletle tek bir bütün gibi doğal biçimde yatırır ve motosikleti dengede tutar.","hi":"सवारी का आपके कंधे के ऊपर से मोड़ में देखना उन्हें आपके और बाइक के साथ एक इकाई की तरह स्वाभाविक रूप से झुकाता है, जिससे मोटरसाइकिल संतुलित रहती है।","ar":"جعل الراكب ينظر فوق كتفك نحو المنعطف يجعله يميل طبيعياً معك ومع الدراجة كوحدة واحدة، مما يبقي الدراجة متوازنة."}},{"cat":"passenger","a":1,"q":{"en":"How should the rider adjust the motorcycle's suspension or tire pressure when carrying a passenger?","es":"¿Cómo debe ajustar el conductor la suspensión o la presión de las llantas al llevar un pasajero?","ru":"Как мотоциклисту отрегулировать подвеску или давление в шинах при перевозке пассажира?","tr":"Bir yolcu taşırken sürücü motosikletin süspansiyonunu veya lastik basıncını nasıl ayarlamalıdır?","hi":"सवारी ले जाते समय चालक को मोटरसाइकिल के सस्पेंशन या टायर दबाव को कैसे समायोजित करना चाहिए?","ar":"كيف يجب أن يعدّل السائق نظام تعليق الدراجة أو ضغط الإطارات عند حمل راكب؟"},"o":[{"en":"Lower the tire pressure to soften the ride","es":"Bajar la presión de las llantas para suavizar la marcha","ru":"Снизить давление в шинах, чтобы смягчить ход","tr":"Sürüşü yumuşatmak için lastik basıncını düşürmek","hi":"राइड नरम करने के लिए टायर दबाव घटाना","ar":"خفض ضغط الإطارات لتنعيم القيادة"},{"en":"Follow the owner's manual, often adding suspension preload and tire pressure for the extra load","es":"Seguir el manual del propietario, a menudo añadiendo precarga de suspensión y presión por el peso extra","ru":"Следовать руководству по эксплуатации, часто увеличивая преднатяг подвески и давление в шинах под дополнительный вес","tr":"Kullanım kılavuzunu izlemek; ek yük için genellikle süspansiyon ön yükünü ve lastik basıncını artırmak","hi":"मालिक मैनुअल का पालन करें, अक्सर अतिरिक्त भार के लिए सस्पेंशन प्रीलोड और टायर दबाव बढ़ाना","ar":"اتّباع دليل المالك، وغالباً زيادة الحمل المسبق للتعليق وضغط الإطارات للحمولة الإضافية"},{"en":"Remove the rear shock spring","es":"Quitar el resorte del amortiguador trasero","ru":"Снять пружину заднего амортизатора","tr":"Arka amortisör yayını çıkarmak","hi":"रियर शॉक स्प्रिंग हटाना","ar":"إزالة نابض الممتص الخلفي"},{"en":"No adjustment is ever needed","es":"Nunca se necesita ningún ajuste","ru":"Никакая регулировка не нужна","tr":"Hiçbir ayar asla gerekmez","hi":"कभी कोई समायोजन जरूरी नहीं","ar":"لا حاجة لأي تعديل إطلاقاً"}],"e":{"en":"The added weight of a passenger usually calls for more suspension preload and higher tire pressure; check the owner's manual for the recommended settings before the trip.","es":"El peso extra de un pasajero suele requerir más precarga de suspensión y mayor presión de llantas; consulte el manual del propietario para los ajustes recomendados antes del viaje.","ru":"Дополнительный вес пассажира обычно требует большего преднатяга подвески и более высокого давления в шинах; перед поездкой сверьтесь с руководством по эксплуатации.","tr":"Yolcunun ek ağırlığı genellikle daha fazla süspansiyon ön yükü ve daha yüksek lastik basıncı gerektirir; yolculuktan önce önerilen ayarlar için kullanım kılavuzuna bakın.","hi":"सवारी का अतिरिक्त वजन आम तौर पर अधिक सस्पेंशन प्रीलोड और उच्च टायर दबाव माँगता है; यात्रा से पहले अनुशंसित सेटिंग्स के लिए मालिक मैनुअल देखें।","ar":"وزن الراكب الإضافي يستلزم عادةً حملاً مسبقاً أكبر للتعليق وضغط إطارات أعلى؛ راجع دليل المالك للإعدادات الموصى بها قبل الرحلة."}},{"cat":"impairment","a":0,"q":{"en":"Which mental ability does alcohol impair first, even at low blood alcohol levels?","es":"¿Qué capacidad mental afecta primero el alcohol, incluso con niveles bajos en sangre?","ru":"Какую умственную способность алкоголь ухудшает первой, даже при низком уровне в крови?","tr":"Alkol, düşük kan alkol düzeylerinde bile hangi zihinsel yeteneği ilk bozar?","hi":"रक्त में कम अल्कोहल स्तर पर भी शराब सबसे पहले किस मानसिक क्षमता को क्षीण करती है?","ar":"أي قدرة ذهنية يضعفها الكحول أولاً، حتى عند مستويات منخفضة في الدم؟"},"o":[{"en":"Judgment and good sense","es":"El juicio y el buen sentido","ru":"Рассудительность и здравый смысл","tr":"Muhakeme ve sağduyu","hi":"निर्णय और विवेक","ar":"الحكم والتقدير السليم"},{"en":"Sense of smell","es":"El sentido del olfato","ru":"Обоняние","tr":"Koku duyusu","hi":"सूँघने की क्षमता","ar":"حاسة الشم"},{"en":"Hearing","es":"El oído","ru":"Слух","tr":"İşitme","hi":"श्रवण","ar":"السمع"},{"en":"Sense of taste","es":"El sentido del gusto","ru":"Вкус","tr":"Tat alma","hi":"स्वाद","ar":"حاسة التذوق"}],"e":{"en":"Alcohol affects judgment and good sense first, so a rider may not realize how impaired they are; this makes even 'a couple of drinks' dangerous before riding.","es":"El alcohol afecta primero el juicio y el buen sentido, por lo que un conductor puede no darse cuenta de cuán afectado está; por eso 'un par de tragos' ya es peligroso antes de conducir.","ru":"Алкоголь в первую очередь бьёт по рассудительности и здравому смыслу, поэтому мотоциклист может не осознавать степень опьянения; даже «пара напитков» опасна перед ездой.","tr":"Alkol önce muhakemeyi ve sağduyuyu etkiler; bu yüzden sürücü ne kadar etkilendiğini fark etmeyebilir; bu, sürmeden önce 'birkaç kadeh'i bile tehlikeli kılar.","hi":"शराब सबसे पहले निर्णय और विवेक को प्रभावित करती है, इसलिए चालक को यह पता न चले कि वह कितना प्रभावित है; इससे चलाने से पहले 'दो-चार पेग' भी खतरनाक हो जाते हैं।","ar":"يؤثّر الكحول أولاً على الحكم والتقدير السليم، فقد لا يدرك السائق مدى تأثّره؛ وهذا يجعل حتى 'بضعة مشروبات' خطيرة قبل القيادة."}},{"cat":"impairment","a":1,"q":{"en":"What is the only thing that will actually reduce a person's blood alcohol level?","es":"¿Qué es lo único que realmente reduce el nivel de alcohol en sangre?","ru":"Что единственно реально снижает уровень алкоголя в крови?","tr":"Bir kişinin kan alkol düzeyini gerçekten düşürecek tek şey nedir?","hi":"वह एकमात्र चीज क्या है जो वास्तव में किसी के रक्त अल्कोहल स्तर को घटाएगी?","ar":"ما الشيء الوحيد الذي يخفّض فعلاً مستوى الكحول في دم الشخص؟"},"o":[{"en":"Coffee","es":"El café","ru":"Кофе","tr":"Kahve","hi":"कॉफ़ी","ar":"القهوة"},{"en":"Time","es":"El tiempo","ru":"Время","tr":"Zaman","hi":"समय","ar":"الوقت"},{"en":"A cold shower","es":"Una ducha fría","ru":"Холодный душ","tr":"Soğuk bir duş","hi":"ठंडा स्नान","ar":"دُش بارد"},{"en":"Fresh air","es":"El aire fresco","ru":"Свежий воздух","tr":"Temiz hava","hi":"ताज़ी हवा","ar":"الهواء النقي"}],"e":{"en":"Only time lets the body eliminate alcohol; coffee, cold showers and fresh air may make you feel more awake but do not lower your blood alcohol level.","es":"Solo el tiempo permite al cuerpo eliminar el alcohol; el café, las duchas frías y el aire fresco pueden despertarlo pero no bajan el nivel de alcohol en sangre.","ru":"Только время позволяет организму вывести алкоголь; кофе, холодный душ и свежий воздух могут взбодрить, но не снижают уровень алкоголя в крови.","tr":"Alkolü vücuttan yalnızca zaman atar; kahve, soğuk duş ve temiz hava sizi daha uyanık hissettirebilir ama kan alkol düzeyinizi düşürmez.","hi":"केवल समय ही शरीर को शराब बाहर निकालने देता है; कॉफ़ी, ठंडा स्नान और ताज़ी हवा आपको अधिक जगा हुआ महसूस करा सकते हैं पर रक्त अल्कोहल स्तर नहीं घटाते।","ar":"الوقت وحده يتيح للجسم التخلّص من الكحول؛ فالقهوة والدُش البارد والهواء النقي قد تجعلك تشعر بمزيد من اليقظة لكنها لا تخفّض مستوى الكحول في دمك."}},{"cat":"impairment","a":2,"q":{"en":"About how long does the body take to eliminate the alcohol in one standard drink?","es":"¿Cuánto tarda el cuerpo aproximadamente en eliminar el alcohol de una bebida estándar?","ru":"Примерно сколько времени организму нужно, чтобы вывести алкоголь одной стандартной порции?","tr":"Vücut, bir standart içkideki alkolü atmak için yaklaşık ne kadar süre alır?","hi":"शरीर को एक मानक ड्रिंक की शराब बाहर निकालने में लगभग कितना समय लगता है?","ar":"كم يستغرق الجسم تقريباً للتخلّص من الكحول في مشروب قياسي واحد؟"},"o":[{"en":"A few seconds","es":"Unos segundos","ru":"Несколько секунд","tr":"Birkaç saniye","hi":"कुछ सेकंड","ar":"بضع ثوانٍ"},{"en":"Around 5 minutes","es":"Alrededor de 5 minutos","ru":"Около 5 минут","tr":"Yaklaşık 5 dakika","hi":"लगभग 5 मिनट","ar":"نحو 5 دقائق"},{"en":"About one hour","es":"Cerca de una hora","ru":"Около одного часа","tr":"Yaklaşık bir saat","hi":"लगभग एक घंटा","ar":"نحو ساعة واحدة"},{"en":"About 15 minutes","es":"Cerca de 15 minutos","ru":"Около 15 минут","tr":"Yaklaşık 15 dakika","hi":"लगभग 15 मिनट","ar":"نحو 15 دقيقة"}],"e":{"en":"The body eliminates alcohol slowly - roughly one standard drink per hour - so having several drinks means it takes several hours to become sober.","es":"El cuerpo elimina el alcohol lentamente - más o menos una bebida estándar por hora - así que varias bebidas tardan varias horas en eliminarse.","ru":"Организм выводит алкоголь медленно — примерно одну стандартную порцию в час, поэтому после нескольких порций трезвость наступает лишь через несколько часов.","tr":"Vücut alkolü yavaş atar - kabaca saatte bir standart içki - bu yüzden birkaç içki, ayılmanın birkaç saat sürmesi demektir.","hi":"शरीर शराब धीरे-धीरे बाहर निकालता है - लगभग एक मानक ड्रिंक प्रति घंटा - इसलिए कई ड्रिंक लेने पर होश में आने में कई घंटे लगते हैं।","ar":"يتخلّص الجسم من الكحول ببطء - نحو مشروب قياسي واحد في الساعة - لذا فإن تناول عدة مشروبات يعني ساعات عدة حتى تصحو."}},{"cat":"impairment","a":3,"q":{"en":"Besides judgment, which riding skills does alcohol most directly impair?","es":"Además del juicio, ¿qué habilidades de conducción afecta más directamente el alcohol?","ru":"Помимо рассудительности, какие навыки езды алкоголь ухудшает наиболее прямо?","tr":"Muhakemenin yanı sıra alkol en doğrudan hangi sürüş becerilerini bozar?","hi":"निर्णय के अलावा, शराब किन राइडिंग कौशलों को सबसे सीधे क्षीण करती है?","ar":"إلى جانب الحكم، أي مهارات القيادة يضعفها الكحول بشكل مباشر أكثر؟"},"o":[{"en":"Only fuel economy","es":"Solo el consumo de combustible","ru":"Только экономичность","tr":"Yalnızca yakıt ekonomisi","hi":"केवल ईंधन दक्षता","ar":"استهلاك الوقود فقط"},{"en":"Only how loud the engine runs","es":"Solo qué tan fuerte suena el motor","ru":"Только громкость двигателя","tr":"Yalnızca motorun sesi","hi":"केवल इंजन कितना जोर से चलता है","ar":"فقط مدى ضجيج المحرك"},{"en":"Tire pressure","es":"La presión de las llantas","ru":"Давление в шинах","tr":"Lastik basıncı","hi":"टायर का दबाव","ar":"ضغط الإطارات"},{"en":"Balance, coordination, and reaction time","es":"El equilibrio, la coordinación y el tiempo de reacción","ru":"Равновесие, координацию и время реакции","tr":"Denge, koordinasyon ve tepki süresi","hi":"संतुलन, समन्वय और प्रतिक्रिया समय","ar":"التوازن والتناسق وزمن رد الفعل"}],"e":{"en":"Alcohol impairs balance, coordination and reaction time - all essential for riding a motorcycle, which demands more of these skills than driving a car.","es":"El alcohol afecta el equilibrio, la coordinación y el tiempo de reacción - esenciales para conducir una moto, que exige más de estas habilidades que un auto.","ru":"Алкоголь ухудшает равновесие, координацию и время реакции — всё это критично для мотоцикла, который требует их больше, чем автомобиль.","tr":"Alkol dengeyi, koordinasyonu ve tepki süresini bozar - hepsi motosiklet sürmek için gereklidir ve bu beceriler araba sürmekten daha fazla gerekir.","hi":"शराब संतुलन, समन्वय और प्रतिक्रिया समय को क्षीण करती है - ये सभी मोटरसाइकिल चलाने के लिए आवश्यक हैं, जिसमें कार से अधिक इन कौशलों की जरूरत होती है।","ar":"يضعف الكحول التوازن والتناسق وزمن رد الفعل - وكلها أساسية لقيادة الدراجة التي تتطلّب هذه المهارات أكثر من قيادة السيارة."}},{"cat":"impairment","a":0,"q":{"en":"How does riding a motorcycle while fatigued affect you?","es":"¿Cómo le afecta conducir una moto estando fatigado?","ru":"Как усталость влияет на управление мотоциклом?","tr":"Yorgunken motosiklet sürmek sizi nasıl etkiler?","hi":"थके होने पर मोटरसाइकिल चलाना आप पर कैसे असर डालता है?","ar":"كيف يؤثّر عليك قيادة الدراجة وأنت مُتعب؟"},"o":[{"en":"It slows reactions and dulls attention much like alcohol","es":"Ralentiza las reacciones y embota la atención, como el alcohol","ru":"Она замедляет реакции и притупляет внимание — как алкоголь","tr":"Tepkileri yavaşlatır ve dikkati alkol gibi köreltir","hi":"यह प्रतिक्रियाएँ धीमी करता और ध्यान शराब की तरह कुंद करता है","ar":"يبطئ ردود الفعل ويُضعف الانتباه مثل الكحول تماماً"},{"en":"It improves focus over time","es":"Mejora la concentración con el tiempo","ru":"Со временем она улучшает концентрацию","tr":"Zamanla odaklanmayı artırır","hi":"यह समय के साथ फोकस बेहतर करता है","ar":"يحسّن التركيز مع الوقت"},{"en":"It only affects long-distance vision","es":"Solo afecta la visión de larga distancia","ru":"Она влияет только на дальнее зрение","tr":"Yalnızca uzak görüşü etkiler","hi":"यह केवल दूर की दृष्टि को प्रभावित करता है","ar":"يؤثّر فقط على الرؤية البعيدة"},{"en":"It has no effect if you drink coffee","es":"No tiene efecto si toma café","ru":"Она не влияет, если пить кофе","tr":"Kahve içerseniz etkisi olmaz","hi":"कॉफ़ी पीने पर इसका कोई असर नहीं","ar":"لا أثر له إذا شربت القهوة"}],"e":{"en":"Fatigue slows your reactions, weakens concentration and impairs judgment much like alcohol, so protect against it before it becomes dangerous.","es":"La fatiga ralentiza las reacciones, debilita la concentración y afecta el juicio como el alcohol, así que protéjase antes de que sea peligroso.","ru":"Усталость замедляет реакции, ослабляет концентрацию и ухудшает рассудительность подобно алкоголю, поэтому боритесь с ней до того, как станет опасно.","tr":"Yorgunluk tepkilerinizi yavaşlatır, konsantrasyonu zayıflatır ve muhakemeyi alkol gibi bozar; bu yüzden tehlikeli hale gelmeden önce önlem alın.","hi":"थकान प्रतिक्रियाएँ धीमी करती, एकाग्रता कमजोर करती और निर्णय को शराब की तरह क्षीण करती है, इसलिए खतरनाक बनने से पहले इससे बचाव करें।","ar":"يبطئ الإرهاق ردود فعلك ويُضعف تركيزك وحكمك مثل الكحول، لذا احمِ نفسك منه قبل أن يصبح خطيراً."}},{"cat":"impairment","a":1,"q":{"en":"How does drinking on an empty stomach affect alcohol's impact on a rider?","es":"¿Cómo afecta beber con el estómago vacío el impacto del alcohol en un conductor?","ru":"Как выпивка на пустой желудок влияет на действие алкоголя на мотоциклиста?","tr":"Aç karnına içmek, alkolün bir sürücü üzerindeki etkisini nasıl değiştirir?","hi":"खाली पेट पीना किसी चालक पर शराब के प्रभाव को कैसे बदलता है?","ar":"كيف يؤثّر الشرب على معدة فارغة في تأثير الكحول على السائق؟"},"o":[{"en":"It cancels the alcohol's effect","es":"Anula el efecto del alcohol","ru":"Это отменяет действие алкоголя","tr":"Alkolün etkisini ortadan kaldırır","hi":"यह शराब का असर रद्द कर देता है","ar":"يُلغي تأثير الكحول"},{"en":"It lets alcohol reach the bloodstream faster, increasing impairment","es":"Permite que el alcohol llegue antes a la sangre, aumentando el deterioro","ru":"Это ускоряет попадание алкоголя в кровь, усиливая опьянение","tr":"Alkolün kana daha hızlı ulaşmasını sağlar ve bozulmayı artırır","hi":"यह शराब को रक्त में तेजी से पहुँचने देता है, जिससे हानि बढ़ती है","ar":"يجعل الكحول يصل إلى الدم أسرع، مما يزيد التأثّر"},{"en":"It slows alcohol down completely","es":"Ralentiza el alcohol por completo","ru":"Это полностью замедляет алкоголь","tr":"Alkolü tamamen yavaşlatır","hi":"यह शराब को पूरी तरह धीमा कर देता है","ar":"يبطئ الكحول تماماً"},{"en":"It only matters for tall riders","es":"Solo importa para conductores altos","ru":"Это важно только для высоких людей","tr":"Yalnızca uzun boylu sürücüler için önemlidir","hi":"यह केवल लंबे चालकों के लिए मायने रखता है","ar":"يهمّ فقط السائقين طوال القامة"}],"e":{"en":"With little food in the stomach, alcohol passes into the bloodstream faster, so it impairs a rider more quickly; food only slows this slightly and cannot prevent impairment.","es":"Con poca comida en el estómago, el alcohol pasa antes a la sangre y deteriora al conductor más rápido; la comida solo lo retrasa un poco y no evita el deterioro.","ru":"При пустом желудке алкоголь быстрее попадает в кровь и сильнее влияет на мотоциклиста; еда лишь немного это замедляет и не предотвращает опьянение.","tr":"Midede az yiyecek varken alkol kana daha hızlı geçer ve sürücüyü daha çabuk bozar; yiyecek bunu yalnızca biraz yavaşlatır, bozulmayı önleyemez.","hi":"पेट में कम भोजन होने पर शराब तेजी से रक्त में जाती है और चालक को जल्दी क्षीण करती है; भोजन इसे केवल थोड़ा धीमा करता है, हानि रोक नहीं सकता।","ar":"مع قلّة الطعام في المعدة، يمرّ الكحول إلى الدم أسرع فيُضعف السائق بسرعة أكبر؛ والطعام يبطئ ذلك قليلاً فقط ولا يمنع التأثّر."}},{"cat":"impairment","a":2,"q":{"en":"Roughly what share of riders killed in motorcycle crashes had been drinking, per the manual?","es":"Según el manual, ¿aproximadamente qué proporción de motociclistas muertos en accidentes había estado bebiendo?","ru":"По руководству, примерно какая доля погибших в мотоавариях употребляла алкоголь?","tr":"Kılavuza göre, motosiklet kazalarında ölen sürücülerin kabaca ne kadarı içki içmişti?","hi":"मैनुअल के अनुसार, मोटरसाइकिल दुर्घटनाओं में मारे गए राइडर्स में लगभग कितने हिस्से ने शराब पी थी?","ar":"وفقاً للدليل، ما النسبة التقريبية للسائقين الذين قُتلوا في حوادث الدراجات وكانوا قد شربوا؟"},"o":[{"en":"Almost none","es":"Casi ninguno","ru":"Почти никто","tr":"Neredeyse hiçbiri","hi":"लगभग कोई नहीं","ar":"لا أحد تقريباً"},{"en":"About one in twenty","es":"Cerca de uno de cada veinte","ru":"Примерно один из двадцати","tr":"Yaklaşık yirmide biri","hi":"लगभग बीस में से एक","ar":"نحو واحد من عشرين"},{"en":"Roughly 40 to 50 percent","es":"Aproximadamente el 40 al 50 por ciento","ru":"Примерно 40–50 процентов","tr":"Kabaca yüzde 40 ila 50","hi":"लगभग 40 से 50 प्रतिशत","ar":"نحو 40 إلى 50 بالمئة"},{"en":"Exactly 10 percent","es":"Exactamente el 10 por ciento","ru":"Ровно 10 процентов","tr":"Tam olarak yüzde 10","hi":"ठीक 10 प्रतिशत","ar":"عشرة بالمئة بالضبط"}],"e":{"en":"Studies cited in the manual show a large share - roughly 40 to 50 percent - of riders killed in crashes had been drinking, underscoring alcohol's danger.","es":"Los estudios citados en el manual muestran que una gran parte - cerca del 40 al 50 por ciento - de los motociclistas muertos había estado bebiendo, lo que resalta el peligro del alcohol.","ru":"Приведённые в руководстве исследования показывают, что значительная доля — примерно 40–50 процентов — погибших мотоциклистов употребляла алкоголь, что подчёркивает его опасность.","tr":"Kılavuzda alıntılanan çalışmalar, kazalarda ölen sürücülerin büyük bir kısmının - kabaca yüzde 40 ila 50 - içki içmiş olduğunu gösterir; bu alkolün tehlikesini vurgular.","hi":"मैनुअल में उद्धृत अध्ययन दिखाते हैं कि दुर्घटनाओं में मारे गए राइडर्स का बड़ा हिस्सा - लगभग 40 से 50 प्रतिशत - शराब पिए हुए था, जो शराब के खतरे को रेखांकित करता है।","ar":"تُظهر الدراسات المذكورة في الدليل أن نسبة كبيرة - نحو 40 إلى 50 بالمئة - من السائقين الذين قُتلوا في الحوادث كانوا قد شربوا، مما يؤكّد خطر الكحول."}},{"cat":"impairment","a":3,"q":{"en":"A friend has had several drinks and wants to ride home. What is the best thing to do?","es":"Un amigo ha bebido varias copas y quiere volver en moto a casa. ¿Qué es lo mejor?","ru":"Друг выпил несколько порций и хочет ехать домой на мотоцикле. Как лучше поступить?","tr":"Bir arkadaşınız birkaç kadeh içti ve motosikletle eve gitmek istiyor. En doğru şey nedir?","hi":"एक दोस्त कई पेग पी चुका है और मोटरसाइकिल से घर जाना चाहता है। सबसे अच्छा क्या करना है?","ar":"صديق شرب عدة مشروبات ويريد القيادة إلى المنزل. ما أفضل تصرّف؟"},"o":[{"en":"Let him go if he seems fine","es":"Dejarlo ir si parece estar bien","ru":"Отпустить, если выглядит нормально","tr":"İyi görünüyorsa gitmesine izin vermek","hi":"यदि वह ठीक लगे तो जाने दें","ar":"تركه يذهب إن بدا بخير"},{"en":"Give him strong coffee first","es":"Darle café fuerte primero","ru":"Сначала дать крепкий кофе","tr":"Önce ona sert kahve vermek","hi":"पहले उसे कड़क कॉफ़ी दें","ar":"إعطاؤه قهوة قوية أولاً"},{"en":"Have him ride slowly behind you","es":"Que conduzca despacio detrás de usted","ru":"Пусть едет медленно за вами","tr":"Arkanızdan yavaş sürmesini istemek","hi":"उसे आपके पीछे धीरे चलने दें","ar":"جعله يقود ببطء خلفك"},{"en":"Intervene: arrange a ride, take his keys, or delay him until sober","es":"Intervenir: conseguirle transporte, quitarle las llaves o retrasarlo hasta que esté sobrio","ru":"Вмешаться: организовать другой транспорт, забрать ключи или задержать до отрезвления","tr":"Müdahale etmek: ona ulaşım ayarlamak, anahtarlarını almak veya ayılana dek geciktirmek","hi":"हस्तक्षेप करें: सवारी की व्यवस्था करें, उसकी चाबियाँ लें, या होश में आने तक रोकें","ar":"التدخّل: تدبير وسيلة نقل، أخذ مفاتيحه، أو تأخيره حتى يصحو"}],"e":{"en":"The manual urges you to intervene with an impaired friend - arrange another way home, take the keys, or slow them down - since even a little alcohol makes riding unsafe.","es":"El manual insta a intervenir con un amigo afectado - conseguirle otro medio, quitarle las llaves o retrasarlo - ya que hasta un poco de alcohol hace insegura la conducción.","ru":"Руководство призывает вмешаться, если друг пьян: организовать иной способ добраться, забрать ключи или задержать его, ведь даже немного алкоголя делает езду опасной.","tr":"Kılavuz, sarhoş bir arkadaşa müdahale etmenizi ister - başka bir dönüş yolu ayarlamak, anahtarları almak ya da onu oyalamak - çünkü az miktarda alkol bile sürüşü güvensiz kılar.","hi":"मैनुअल आग्रह करता है कि प्रभावित दोस्त के साथ हस्तक्षेप करें - घर जाने का दूसरा साधन जुटाएँ, चाबियाँ लें, या उसे रोकें - क्योंकि थोड़ी शराब भी राइडिंग को असुरक्षित बनाती है।","ar":"يحثّك الدليل على التدخّل مع صديق ثمل - تدبير وسيلة أخرى للعودة، أخذ المفاتيح، أو تأخيره - لأن حتى القليل من الكحول يجعل القيادة غير آمنة."}},{"cat":"impairment","a":0,"q":{"en":"How can over-the-counter or prescription medicines affect your riding?","es":"¿Cómo pueden afectar su conducción los medicamentos de venta libre o con receta?","ru":"Как безрецептурные или рецептурные лекарства могут повлиять на вашу езду?","tr":"Reçetesiz veya reçeteli ilaçlar sürüşünüzü nasıl etkileyebilir?","hi":"बिना पर्ची या पर्ची वाली दवाएँ आपकी राइडिंग को कैसे प्रभावित कर सकती हैं?","ar":"كيف يمكن للأدوية التي تُصرف بوصفة أو بدونها أن تؤثّر على قيادتك؟"},"o":[{"en":"They can cause drowsiness or impair skills, like alcohol can","es":"Pueden causar somnolencia o afectar habilidades, como el alcohol","ru":"Они могут вызывать сонливость или ухудшать навыки, как алкоголь","tr":"Alkol gibi uyku hâline veya beceri kaybına yol açabilirler","hi":"वे शराब की तरह उनींदापन या कौशल क्षीणता ला सकती हैं","ar":"قد تسبّب النعاس أو تُضعف المهارات، مثل الكحول"},{"en":"They always improve alertness","es":"Siempre mejoran el estado de alerta","ru":"Они всегда повышают бдительность","tr":"Her zaman uyanıklığı artırırlar","hi":"वे हमेशा सतर्कता बढ़ाती हैं","ar":"تحسّن اليقظة دائماً"},{"en":"They only matter for car drivers","es":"Solo importan para conductores de auto","ru":"Они важны только для водителей машин","tr":"Yalnızca araba sürücüleri için önemlidir","hi":"वे केवल कार चालकों के लिए मायने रखती हैं","ar":"تهمّ سائقي السيارات فقط"},{"en":"They have no effect on riding","es":"No afectan la conducción","ru":"Они не влияют на езду","tr":"Sürüşe etkisi yoktur","hi":"वे राइडिंग को प्रभावित नहीं करतीं","ar":"لا أثر لها على القيادة"}],"e":{"en":"Many medicines can cause drowsiness or slow reactions, and their effects can be worse when combined with alcohol; check labels and how a drug affects you before riding.","es":"Muchos medicamentos causan somnolencia o ralentizan reacciones, y sus efectos empeoran con alcohol; revise las etiquetas y cómo le afecta un fármaco antes de conducir.","ru":"Многие лекарства вызывают сонливость или замедляют реакции, а в сочетании с алкоголем эффект усиливается; читайте инструкции и проверяйте влияние препарата до поездки.","tr":"Birçok ilaç uyku hâline veya yavaş tepkilere yol açabilir; alkolle birleşince etkileri daha kötü olabilir; sürmeden önce etiketleri ve ilacın sizi nasıl etkilediğini kontrol edin.","hi":"कई दवाएँ उनींदापन या धीमी प्रतिक्रियाएँ ला सकती हैं, और शराब के साथ इनका असर बदतर हो सकता है; चलाने से पहले लेबल और दवा का असर जाँचें।","ar":"كثير من الأدوية قد تسبّب النعاس أو تبطئ ردود الفعل، وقد تسوء آثارها مع الكحول؛ افحص النشرات وكيف يؤثّر الدواء عليك قبل القيادة."}},{"cat":"impairment","a":1,"q":{"en":"Why is combining even a small amount of alcohol with riding especially risky on a motorcycle?","es":"¿Por qué combinar aun poca cantidad de alcohol con la conducción es especialmente arriesgado en moto?","ru":"Почему сочетание даже небольшого количества алкоголя с ездой особенно рискованно на мотоцикле?","tr":"Az miktarda alkolü sürüşle birleştirmek motosiklette neden özellikle risklidir?","hi":"थोड़ी सी भी शराब को राइडिंग के साथ मिलाना मोटरसाइकिल पर विशेष रूप से जोखिमपूर्ण क्यों है?","ar":"لماذا يكون خلط حتى كمية صغيرة من الكحول مع القيادة خطيراً بشكل خاص على الدراجة؟"},"o":[{"en":"Motorcycles use more fuel when you drink","es":"Las motos consumen más combustible si bebe","ru":"Мотоциклы больше тратят топлива, когда вы пьёте","tr":"İçtiğinizde motosikletler daha çok yakıt yakar","hi":"पीने पर मोटरसाइकिल अधिक ईंधन खर्च करती हैं","ar":"الدراجات تستهلك وقوداً أكثر عندما تشرب"},{"en":"Riding demands balance and coordination that alcohol quickly degrades","es":"Conducir exige equilibrio y coordinación que el alcohol degrada rápido","ru":"Езда требует равновесия и координации, которые алкоголь быстро ухудшает","tr":"Sürüş, alkolün hızla bozduğu denge ve koordinasyon gerektirir","hi":"राइडिंग को संतुलन और समन्वय चाहिए जिसे शराब जल्दी बिगाड़ती है","ar":"القيادة تتطلّب توازناً وتناسقاً يُضعفهما الكحول بسرعة"},{"en":"Alcohol improves cornering","es":"El alcohol mejora las curvas","ru":"Алкоголь улучшает прохождение поворотов","tr":"Alkol viraj almayı iyileştirir","hi":"शराब कॉर्नरिंग बेहतर करती है","ar":"الكحول يحسّن المنعطفات"},{"en":"It only affects passengers","es":"Solo afecta a los pasajeros","ru":"Он влияет только на пассажиров","tr":"Yalnızca yolcuları etkiler","hi":"यह केवल सवारियों को प्रभावित करता है","ar":"يؤثّر على الركاب فقط"}],"e":{"en":"A motorcycle requires more balance, coordination and quick judgment than a car, and alcohol degrades exactly those abilities, so even a little is especially dangerous.","es":"Una moto exige más equilibrio, coordinación y juicio rápido que un auto, y el alcohol degrada justamente esas capacidades, por eso hasta poco es especialmente peligroso.","ru":"Мотоцикл требует больше равновесия, координации и быстрой оценки, чем автомобиль, а алкоголь ухудшает именно эти способности, поэтому даже немного особенно опасно.","tr":"Motosiklet arabadan daha fazla denge, koordinasyon ve hızlı muhakeme gerektirir; alkol tam da bu yetenekleri bozar, bu yüzden az miktarı bile özellikle tehlikelidir.","hi":"मोटरसाइकिल को कार से अधिक संतुलन, समन्वय और त्वरित निर्णय चाहिए, और शराब ठीक इन्हीं क्षमताओं को बिगाड़ती है, इसलिए थोड़ी भी विशेष रूप से खतरनाक है।","ar":"تتطلّب الدراجة توازناً وتناسقاً وحكماً سريعاً أكثر من السيارة، والكحول يُضعف تحديداً هذه القدرات، لذا حتى القليل خطير بشكل خاص."}},{"cat":"impairment","a":2,"q":{"en":"What is one legal consequence a rider can face for operating under the influence?","es":"¿Cuál es una consecuencia legal que puede enfrentar un conductor por manejar bajo los efectos?","ru":"Каково одно из юридических последствий для мотоциклиста за управление в нетрезвом виде?","tr":"Bir sürücünün alkollü/uyuşturucu etkisi altında sürmekten karşılaşabileceği yasal bir sonuç nedir?","hi":"नशे में वाहन चलाने के लिए राइडर को किस एक कानूनी परिणाम का सामना करना पड़ सकता है?","ar":"ما إحدى العواقب القانونية التي قد يواجهها السائق للقيادة تحت التأثير؟"},"o":[{"en":"A small parking fine only","es":"Solo una pequeña multa de estacionamiento","ru":"Только небольшой штраф за парковку","tr":"Yalnızca küçük bir park cezası","hi":"केवल एक छोटा पार्किंग जुर्माना","ar":"غرامة وقوف صغيرة فقط"},{"en":"A warning with no record","es":"Una advertencia sin antecedente","ru":"Предупреждение без записи","tr":"Kayıtsız bir uyarı","hi":"बिना रिकॉर्ड की चेतावनी","ar":"تحذير دون سجل"},{"en":"License suspension, fines, or jail","es":"Suspensión de licencia, multas o cárcel","ru":"Лишение прав, штрафы или тюрьма","tr":"Ehliyet askıya alınması, para cezaları veya hapis","hi":"लाइसेंस निलंबन, जुर्माना या जेल","ar":"سحب الرخصة أو غرامات أو السجن"},{"en":"Nothing, if no crash occurs","es":"Nada, si no hay choque","ru":"Ничего, если нет аварии","tr":"Kaza olmazsa hiçbir şey","hi":"यदि दुर्घटना न हो तो कुछ नहीं","ar":"لا شيء إن لم يقع حادث"}],"e":{"en":"Riding under the influence can bring serious penalties - license suspension, heavy fines, and even jail - on top of the greatly increased crash risk.","es":"Conducir bajo los efectos puede acarrear sanciones graves - suspensión de licencia, multas cuantiosas e incluso cárcel - además del riesgo de choque muy elevado.","ru":"Управление в нетрезвом виде грозит серьёзными санкциями — лишением прав, крупными штрафами и даже тюрьмой — вдобавок к резко возросшему риску аварии.","tr":"Alkollü/uyuşturucu etkisi altında sürmek, büyük ölçüde artan kaza riskine ek olarak ciddi cezalar getirebilir - ehliyetin askıya alınması, ağır para cezaları ve hatta hapis.","hi":"नशे में चलाना गंभीर दंड ला सकता है - लाइसेंस निलंबन, भारी जुर्माना और यहाँ तक कि जेल - बहुत बढ़े हुए दुर्घटना जोखिम के अलावा।","ar":"القيادة تحت التأثير قد تجلب عقوبات خطيرة - سحب الرخصة وغرامات باهظة وحتى السجن - إضافة إلى ارتفاع خطر الحادث بشكل كبير."}},{"cat":"impairment","a":3,"q":{"en":"At a gathering, which group strategy can help keep a friend from drinking too much to ride?","es":"En una reunión, ¿qué estrategia de grupo ayuda a evitar que un amigo beba demasiado para conducir?","ru":"На встрече какая групповая стратегия поможет не дать другу перебрать перед ездой?","tr":"Bir toplantıda, bir arkadaşın sürmeyecek kadar çok içmesini önlemeye hangi grup stratejisi yardımcı olabilir?","hi":"किसी समागम में, कौन सी समूह रणनीति किसी दोस्त को चलाने के लिए बहुत अधिक पीने से रोकने में मदद कर सकती है?","ar":"في تجمّع، أي استراتيجية جماعية قد تساعد على منع صديق من الإفراط في الشرب بحيث لا يقود؟"},"o":[{"en":"Encourage friendly drinking contests","es":"Fomentar concursos amistosos de bebida","ru":"Поощрять дружеские состязания в выпивке","tr":"Dostça içki yarışlarını teşvik etmek","hi":"मैत्रीपूर्ण पीने की प्रतियोगिताएँ प्रोत्साहित करें","ar":"تشجيع مسابقات الشرب الودّية"},{"en":"Let everyone manage themselves","es":"Dejar que cada uno se controle solo","ru":"Пусть каждый следит за собой сам","tr":"Herkesin kendini yönetmesine izin vermek","hi":"सबको खुद संभालने दें","ar":"ترك كل شخص يدبّر نفسه"},{"en":"Serve drinks faster to finish early","es":"Servir bebidas más rápido para terminar antes","ru":"Наливать быстрее, чтобы раньше закончить","tr":"Erken bitirmek için içkileri daha hızlı sunmak","hi":"जल्दी खत्म करने के लिए जल्दी पेय परोसें","ar":"تقديم المشروبات أسرع للانتهاء مبكراً"},{"en":"Arrange things in advance, such as a designated rider or limiting drinks","es":"Planear con antelación, como un conductor designado o limitar las bebidas","ru":"Договориться заранее — назначить трезвого водителя или ограничить порции","tr":"Önceden düzenleme yapmak, örneğin belirlenmiş bir sürücü veya içkileri sınırlamak","hi":"पहले से व्यवस्था करें, जैसे नामित चालक या पेय सीमित करना","ar":"الترتيب مسبقاً، مثل تعيين سائق غير شارب أو تحديد المشروبات"}],"e":{"en":"Planning ahead - agreeing on a designated rider, limiting drinks, or providing food and other activities - helps a friend avoid drinking too much to ride safely.","es":"Planear con antelación - acordar un conductor designado, limitar las bebidas o ofrecer comida y otras actividades - ayuda a que un amigo no beba demasiado para conducir con seguridad.","ru":"Планирование заранее — назначить трезвого водителя, ограничить порции или предложить еду и другие занятия — помогает другу не перебрать перед безопасной ездой.","tr":"Önceden planlamak - belirlenmiş bir sürücüde anlaşmak, içkileri sınırlamak ya da yemek ve başka etkinlikler sunmak - bir arkadaşın güvenle sürecek kadar az içmesine yardımcı olur.","hi":"पहले से योजना बनाना - नामित चालक पर सहमत होना, पेय सीमित करना, या भोजन व अन्य गतिविधियाँ देना - किसी दोस्त को सुरक्षित रूप से चलाने के लिए बहुत अधिक पीने से बचने में मदद करता है।","ar":"التخطيط المسبق - الاتفاق على سائق غير شارب أو تحديد المشروبات أو توفير طعام وأنشطة أخرى - يساعد الصديق على تجنّب الإفراط في الشرب كي يقود بأمان."}},{"cat":"impairment","a":0,"q":{"en":"If you cannot stop an impaired friend from leaving right away, what is a reasonable step?","es":"Si no puede impedir de inmediato que un amigo afectado se vaya, ¿cuál es un paso razonable?","ru":"Если сразу остановить пьяного друга нельзя, какой шаг разумен?","tr":"Sarhoş bir arkadaşın hemen gitmesini engelleyemiyorsanız, makul bir adım nedir?","hi":"यदि आप प्रभावित दोस्त को तुरंत जाने से नहीं रोक सकते, तो एक उचित कदम क्या है?","ar":"إذا لم تستطع منع صديق ثمل من المغادرة فوراً، فما الخطوة المعقولة؟"},"o":[{"en":"Slow him down - delay his departure to give the alcohol time to wear off","es":"Retrasarlo - demorar su salida para dar tiempo a que el alcohol se elimine","ru":"Задержать его — оттянуть отъезд, чтобы алкоголь успел выветриться","tr":"Onu oyalamak - alkolün etkisinin geçmesi için gidişini geciktirmek","hi":"उसे धीमा करें - उसके प्रस्थान में देरी करें ताकि शराब का असर उतरने का समय मिले","ar":"تأخيره - تأجيل مغادرته لإعطاء الكحول وقتاً كي يزول أثره"},{"en":"Wave goodbye and hope for the best","es":"Despedirse y esperar lo mejor","ru":"Помахать на прощание и надеяться на лучшее","tr":"El sallayıp en iyisini ummak","hi":"अलविदा कहें और अच्छे की उम्मीद करें","ar":"التلويح بالوداع والأمل في الأفضل"},{"en":"Race him home to keep an eye on him","es":"Competir con él hasta casa para vigilarlo","ru":"Гнать с ним наперегонки, чтобы приглядывать","tr":"Ona göz kulak olmak için eve yarışmak","hi":"उस पर नजर रखने के लिए घर तक दौड़ लगाएँ","ar":"سباقه إلى المنزل لمراقبته"},{"en":"Give him a stronger drink to relax","es":"Darle un trago más fuerte para relajarlo","ru":"Дать ему напиток покрепче, чтобы расслабить","tr":"Rahatlaması için daha sert bir içki vermek","hi":"आराम के लिए उसे और तेज पेय दें","ar":"إعطاؤه مشروباً أقوى ليسترخي"}],"e":{"en":"If you cannot keep an impaired rider from leaving, try to delay their departure - more time is the only thing that reduces their impairment before they ride.","es":"Si no puede evitar que un conductor afectado se vaya, intente retrasar su salida - más tiempo es lo único que reduce su deterioro antes de conducir.","ru":"Если удержать пьяного мотоциклиста нельзя, постарайтесь оттянуть его отъезд — только время снижает опьянение перед ездой.","tr":"Sarhoş bir sürücünün gitmesini engelleyemiyorsanız, gidişini geciktirmeye çalışın - sürmeden önce etkisini azaltan tek şey daha fazla zamandır.","hi":"यदि आप प्रभावित राइडर को जाने से नहीं रोक सकते, तो उसके प्रस्थान में देरी करने की कोशिश करें - चलाने से पहले उसका नशा घटाने वाली एकमात्र चीज अधिक समय है।","ar":"إذا لم تستطع منع سائق ثمل من المغادرة، فحاول تأخير رحيله - فالوقت الإضافي هو الشيء الوحيد الذي يقلّل تأثّره قبل أن يقود."}},{"cat":"impairment","a":1,"q":{"en":"How does alcohol affect a rider's ability to judge their own impairment?","es":"¿Cómo afecta el alcohol la capacidad de un conductor para juzgar su propio deterioro?","ru":"Как алкоголь влияет на способность оценивать собственное опьянение?","tr":"Alkol, bir sürücünün kendi bozulmasını değerlendirme yeteneğini nasıl etkiler?","hi":"शराब किसी चालक की अपनी हानि आँकने की क्षमता को कैसे प्रभावित करती है?","ar":"كيف يؤثّر الكحول على قدرة السائق على تقدير مدى تأثّره؟"},"o":[{"en":"It sharpens self-awareness","es":"Agudiza la autoconciencia","ru":"Он обостряет самооценку","tr":"Öz farkındalığı keskinleştirir","hi":"यह आत्म-जागरूकता तेज करता है","ar":"يشحذ الوعي الذاتي"},{"en":"It makes riders overestimate their impairment","es":"Hace que sobrestimen su deterioro","ru":"Он заставляет переоценивать своё опьянение","tr":"Sürücülerin bozulmalarını abartmasına yol açar","hi":"यह चालकों को अपनी हानि बढ़ा-चढ़ाकर आँकने पर मजबूर करता है","ar":"يجعل السائقين يبالغون في تقدير تأثّرهم"},{"en":"It leaves riders unaware of how impaired they really are","es":"Deja a los conductores sin darse cuenta de cuán afectados están","ru":"Он оставляет мотоциклистов в неведении о реальной степени опьянения","tr":"Sürücüleri gerçekte ne kadar etkilendiklerinden habersiz bırakır","hi":"यह चालकों को यह अहसास नहीं होने देता कि वे वास्तव में कितने प्रभावित हैं","ar":"يترك السائقين غير مدركين لمدى تأثّرهم الحقيقي"},{"en":"It has no effect on self-judgment","es":"No afecta el autojuicio","ru":"Он не влияет на самооценку","tr":"Öz değerlendirmeye etkisi yoktur","hi":"यह आत्म-निर्णय को प्रभावित नहीं करता","ar":"لا أثر له على تقدير الذات"}],"e":{"en":"Because alcohol dulls judgment early, impaired riders often believe they are fine when they are not, which is why you cannot rely on self-assessment.","es":"Como el alcohol embota pronto el juicio, los conductores afectados suelen creer que están bien cuando no lo están, por eso no se puede confiar en la autoevaluación.","ru":"Поскольку алкоголь рано притупляет рассудительность, опьяневшие часто считают себя в порядке, хотя это не так, — поэтому нельзя полагаться на самооценку.","tr":"Alkol muhakemeyi erkenden körelttiği için, etkilenmiş sürücüler çoğu zaman iyi olmadıkları halde iyi olduklarını sanır; bu yüzden öz değerlendirmeye güvenemezsiniz.","hi":"चूँकि शराब निर्णय को जल्दी कुंद करती है, प्रभावित चालक अक्सर मानते हैं कि वे ठीक हैं जबकि नहीं होते, इसीलिए आत्म-आकलन पर भरोसा नहीं किया जा सकता।","ar":"لأن الكحول يُضعف الحكم مبكراً، غالباً ما يظن السائقون المتأثّرون أنهم بخير وهم ليسوا كذلك، ولهذا لا يمكن الاعتماد على التقييم الذاتي."}},{"cat":"impairment","a":2,"q":{"en":"Which of these counts as roughly one standard drink when estimating impairment?","es":"¿Cuál de estos cuenta como aproximadamente una bebida estándar al estimar el deterioro?","ru":"Что из перечисленного считается примерно одной стандартной порцией при оценке опьянения?","tr":"Bozulmayı tahmin ederken bunlardan hangisi kabaca bir standart içki sayılır?","hi":"हानि आँकते समय इनमें से कौन लगभग एक मानक ड्रिंक गिना जाता है?","ar":"أيٌّ من هذه يُعدّ تقريباً مشروباً قياسياً واحداً عند تقدير التأثّر؟"},"o":[{"en":"A full bottle of spirits","es":"Una botella entera de licor","ru":"Целая бутылка крепкого алкоголя","tr":"Bir şişe sert içki","hi":"स्पिरिट्स की पूरी बोतल","ar":"زجاجة كاملة من المشروبات الروحية"},{"en":"A pitcher of beer","es":"Una jarra de cerveza","ru":"Кувшин пива","tr":"Bir sürahi bira","hi":"बीयर का एक जग","ar":"إبريق من البيرة"},{"en":"A 12-ounce glass of beer","es":"Un vaso de 12 onzas de cerveza","ru":"Стакан пива около 350 мл (12 унций)","tr":"350 ml'lik (12 ons) bir bardak bira","hi":"12-औंस बीयर का एक गिलास","ar":"كوب بيرة سعة 12 أونصة"},{"en":"Three shots of liquor","es":"Tres tragos de licor","ru":"Три рюмки крепкого","tr":"Üç kadeh sert içki","hi":"लिकर के तीन शॉट","ar":"ثلاث جرعات من المشروبات الروحية"}],"e":{"en":"One standard drink is roughly a 12-ounce beer, a 5-ounce glass of wine, or a 1.5-ounce shot of liquor - each contains about the same amount of alcohol.","es":"Una bebida estándar es aproximadamente una cerveza de 12 onzas, una copa de vino de 5 onzas o un trago de 1.5 onzas de licor - cada uno contiene casi la misma cantidad de alcohol.","ru":"Одна стандартная порция — это примерно 350 мл пива, 150 мл вина или 45 мл крепкого напитка — в каждом почти одинаковое количество алкоголя.","tr":"Bir standart içki kabaca 350 ml bira, 150 ml şarap ya da 45 ml sert içkidir - her biri yaklaşık aynı miktarda alkol içerir.","hi":"एक मानक ड्रिंक लगभग 12-औंस बीयर, 5-औंस वाइन का गिलास, या 1.5-औंस लिकर का शॉट है - प्रत्येक में लगभग समान मात्रा में शराब होती है।","ar":"المشروب القياسي الواحد هو تقريباً بيرة 12 أونصة أو كأس نبيذ 5 أونصات أو جرعة مشروب روحي 1.5 أونصة - وكلٌّ منها يحتوي على القدر نفسه تقريباً من الكحول."}},{"cat":"impairment","a":3,"q":{"en":"Why does the manual say group pressure can be used positively regarding drinking and riding?","es":"¿Por qué dice el manual que la presión del grupo puede usarse de forma positiva ante beber y conducir?","ru":"Почему руководство говорит, что групповое давление можно использовать во благо в вопросе выпивки и езды?","tr":"Kılavuz, içki ve sürüş konusunda grup baskısının olumlu kullanılabileceğini neden söyler?","hi":"मैनुअल क्यों कहता है कि पीने और चलाने के मामले में समूह दबाव का सकारात्मक उपयोग किया जा सकता है?","ar":"لماذا يقول الدليل إن ضغط المجموعة يمكن استخدامه إيجابياً فيما يخص الشرب والقيادة؟"},"o":[{"en":"To pressure friends into riding home fast","es":"Para presionar a los amigos a volver rápido en moto","ru":"Чтобы заставлять друзей быстрее ехать домой","tr":"Arkadaşları hızlı eve gitmeye zorlamak için","hi":"दोस्तों को तेजी से घर जाने के लिए दबाव डालने हेतु","ar":"للضغط على الأصدقاء للعودة بسرعة"},{"en":"To dare each other to drink more","es":"Para retarse a beber más","ru":"Чтобы подначивать друг друга пить больше","tr":"Birbirini daha çok içmeye kışkırtmak için","hi":"एक-दूसरे को अधिक पीने की चुनौती देने हेतु","ar":"لتحدّي بعضهم على الشرب أكثر"},{"en":"To keep silent about a friend's drinking","es":"Para callar sobre la bebida de un amigo","ru":"Чтобы молчать о том, что друг пьёт","tr":"Bir arkadaşın içkisi hakkında susmak için","hi":"किसी दोस्त के पीने पर चुप रहने हेतु","ar":"للصمت عن شرب صديق"},{"en":"Friends can collectively discourage an impaired rider and offer safe alternatives","es":"Los amigos pueden disuadir en conjunto a un conductor afectado y ofrecer alternativas seguras","ru":"Друзья могут сообща отговорить пьяного мотоциклиста и предложить безопасные варианты","tr":"Arkadaşlar, sarhoş bir sürücüyü toplu olarak caydırıp güvenli alternatifler sunabilir","hi":"दोस्त सामूहिक रूप से प्रभावित राइडर को हतोत्साहित कर सुरक्षित विकल्प दे सकते हैं","ar":"يمكن للأصدقاء جماعياً ثني السائق المتأثّر وتقديم بدائل آمنة"}],"e":{"en":"The same group influence that can push someone to drink can instead be used to discourage an impaired friend from riding and to arrange a safe way home.","es":"La misma influencia de grupo que puede empujar a beber puede usarse en cambio para disuadir a un amigo afectado de conducir y arreglar un regreso seguro.","ru":"То же групповое влияние, что может подталкивать к выпивке, можно направить на то, чтобы отговорить пьяного друга ехать и организовать безопасный путь домой.","tr":"Birini içmeye itebilen aynı grup etkisi, bunun yerine sarhoş bir arkadaşı sürmekten caydırmak ve güvenli bir dönüş ayarlamak için kullanılabilir.","hi":"वही समूह प्रभाव जो किसी को पीने के लिए धकेल सकता है, इसके बजाय प्रभावित दोस्त को चलाने से हतोत्साहित करने और सुरक्षित घर वापसी की व्यवस्था करने में इस्तेमाल किया जा सकता है।","ar":"نفس تأثير المجموعة الذي قد يدفع شخصاً للشرب يمكن استخدامه بدلاً من ذلك لثني صديق متأثّر عن القيادة وترتيب عودة آمنة إلى المنزل."}},{"cat":"impairment","a":2,"q":{"en":"What does the manual say about the level of alcohol at which riding becomes unsafe?","es":"¿Qué dice el manual sobre el nivel de alcohol a partir del cual conducir se vuelve inseguro?","ru":"Что руководство говорит об уровне алкоголя, при котором езда становится небезопасной?","tr":"Kılavuz, sürüşün güvensiz hâle geldiği alkol düzeyi hakkında ne der?","hi":"किस अल्कोहल स्तर पर राइडिंग असुरक्षित हो जाती है, इस बारे में मैनुअल क्या कहता है?","ar":"ماذا يقول الدليل عن مستوى الكحول الذي تصبح عنده القيادة غير آمنة؟"},"o":[{"en":"Only the legal limit matters; below it you are safe","es":"Solo importa el límite legal; por debajo está seguro","ru":"Важен только легальный предел; ниже него вы в безопасности","tr":"Yalnızca yasal sınır önemlidir; altında güvendesiniz","hi":"केवल कानूनी सीमा मायने रखती है; उसके नीचे आप सुरक्षित हैं","ar":"يهمّ الحد القانوني فقط؛ وتحته تكون آمناً"},{"en":"Alcohol has no effect until you feel drunk","es":"El alcohol no afecta hasta que se siente ebrio","ru":"Алкоголь не действует, пока вы не почувствуете опьянение","tr":"Sarhoş hissedene dek alkolün etkisi yoktur","hi":"जब तक आप नशा महसूस न करें, शराब का असर नहीं होता","ar":"لا أثر للكحول حتى تشعر بالسُّكر"},{"en":"Impairment begins well below the legal limit, so any drinking before riding is risky","es":"El deterioro comienza mucho antes del límite legal, así que beber antes de conducir es arriesgado","ru":"Ухудшение начинается задолго до легального предела, поэтому любое питьё перед ездой рискованно","tr":"Bozulma yasal sınırın çok altında başlar; bu yüzden sürmeden önce herhangi bir içki risklidir","hi":"हानि कानूनी सीमा से काफी नीचे शुरू होती है, इसलिए चलाने से पहले कोई भी शराब जोखिमपूर्ण है","ar":"يبدأ التأثّر أقل بكثير من الحد القانوني، لذا أي شرب قبل القيادة محفوف بالمخاطر"},{"en":"You can ride safely up to twice the legal limit","es":"Puede conducir con seguridad hasta el doble del límite legal","ru":"Можно безопасно ехать вплоть до двойного предела","tr":"Yasal sınırın iki katına kadar güvenle sürebilirsiniz","hi":"आप कानूनी सीमा के दोगुने तक सुरक्षित चला सकते हैं","ar":"يمكنك القيادة بأمان حتى ضعف الحد القانوني"}],"e":{"en":"The manual stresses that alcohol impairs skills and judgment well below the legal blood alcohol limit, so any amount before riding increases your crash risk.","es":"El manual subraya que el alcohol afecta las habilidades y el juicio muy por debajo del límite legal, así que cualquier cantidad antes de conducir aumenta el riesgo de choque.","ru":"Руководство подчёркивает, что алкоголь ухудшает навыки и рассудительность задолго до легального предела, поэтому любое его количество перед ездой повышает риск аварии.","tr":"Kılavuz, alkolün becerileri ve muhakemeyi yasal kan alkol sınırının çok altında bozduğunu vurgular; bu yüzden sürmeden önce herhangi bir miktar kaza riskinizi artırır.","hi":"मैनुअल जोर देता है कि शराब कानूनी रक्त-अल्कोहल सीमा से काफी नीचे कौशल और निर्णय को क्षीण करती है, इसलिए चलाने से पहले कोई भी मात्रा दुर्घटना जोखिम बढ़ाती है।","ar":"يؤكّد الدليل أن الكحول يُضعف المهارات والحكم أقل بكثير من الحد القانوني للكحول في الدم، لذا أي كمية قبل القيادة تزيد خطر الحادث."}},{"cat":"impairment","a":3,"q":{"en":"What is the safest personal rule about drinking and riding?","es":"¿Cuál es la regla personal más segura sobre beber y conducir?","ru":"Какое личное правило о выпивке и езде самое безопасное?","tr":"İçki ve sürüş konusunda en güvenli kişisel kural nedir?","hi":"पीने और चलाने के बारे में सबसे सुरक्षित व्यक्तिगत नियम क्या है?","ar":"ما القاعدة الشخصية الأكثر أماناً بشأن الشرب والقيادة؟"},"o":[{"en":"One drink per hour is always fine","es":"Una bebida por hora siempre está bien","ru":"Одна порция в час всегда допустима","tr":"Saatte bir içki her zaman uygundur","hi":"प्रति घंटा एक ड्रिंक हमेशा ठीक है","ar":"مشروب واحد كل ساعة مقبول دائماً"},{"en":"Only spirits are a problem, not beer","es":"Solo los licores son problema, no la cerveza","ru":"Проблема только в крепком, не в пиве","tr":"Yalnızca sert içkiler sorundur, bira değil","hi":"केवल स्पिरिट्स समस्या हैं, बीयर नहीं","ar":"المشروبات الروحية فقط مشكلة، لا البيرة"},{"en":"You can drink if you ride slowly","es":"Puede beber si conduce despacio","ru":"Можно пить, если ехать медленно","tr":"Yavaş sürerseniz içebilirsiniz","hi":"धीरे चलाएँ तो पी सकते हैं","ar":"يمكنك الشرب إذا قدت ببطء"},{"en":"Do not drink at all if you plan to ride","es":"No beber nada si planea conducir","ru":"Совсем не пить, если собираетесь ехать","tr":"Sürmeyi planlıyorsanız hiç içmemek","hi":"यदि चलाना है तो बिल्कुल न पिएँ","ar":"عدم الشرب إطلاقاً إذا كنت تنوي القيادة"}],"e":{"en":"Because alcohol impairs the skills riding demands even in small amounts, the safest rule is simple: if you are going to ride, do not drink at all.","es":"Como el alcohol afecta las habilidades necesarias para conducir incluso en pequeñas cantidades, la regla más segura es simple: si va a conducir, no beba nada.","ru":"Поскольку даже малое количество алкоголя ухудшает нужные для езды навыки, самое безопасное правило простое: собираетесь ехать — не пейте вовсе.","tr":"Alkol, sürüşün gerektirdiği becerileri az miktarda bile bozduğu için en güvenli kural basittir: süreceksen hiç içme.","hi":"चूँकि शराब थोड़ी मात्रा में भी राइडिंग के लिए जरूरी कौशल क्षीण करती है, सबसे सुरक्षित नियम सरल है: यदि चलाना है तो बिल्कुल न पिएँ।","ar":"لأن الكحول يُضعف المهارات التي تتطلّبها القيادة حتى بكميات صغيرة، فإن القاعدة الأكثر أماناً بسيطة: إذا كنت ستقود، فلا تشرب إطلاقاً."}}]};
